const LEVEL_ONE = [{ meta: "Latin to English", stem: "Choose the best translation for <b>via</b>.", options: ["man", "road", "wine", "life"], i: 1, explanation: "The correct answer is <b>B</b>. <b>via</b> means 'road, way, street'. Distractors are translations of visually similar words: <b>A</b> is 'man' (from <b>vir</b>), <b>C</b> is 'wine' (from <b>vīnum</b>), and <b>D</b> is 'life' (from <b>vīta</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>sum</b>.", options: ["they are", "I may be", "I am", "thus"], i: 2, explanation: "The correct answer is <b>C</b>. <b>sum</b> is the first person singular of the verb 'to be', meaning 'I am'. Distractors are translations of visually or morphologically similar words: <b>A</b> is 'they are' (from <b>sunt</b>), <b>B</b> is 'I may be' (from <b>sim</b>), and <b>D</b> is 'thus' (from <b>sīc</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>puer</b>.", options: ["girl", "pure", "boy", "fight"], i: 2, explanation: "The correct answer is <b>C</b>. <b>puer</b> means 'boy'. Distractors are translations of visually similar words: <b>A</b> is 'girl' (from <b>puella</b>), <b>B</b> is 'pure' (from <b>pūrus</b>), and <b>D</b> is 'fight' (from <b>pugna</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>agō</b>.", options: ["sick", "do, drive", "love", "hear"], i: 1, explanation: "The correct answer is <b>B</b>. <b>agō</b> means 'do, drive, lead'. Distractors are translations of visually similar words: <b>A</b> is 'sick' (from <b>aegrōtus</b>), <b>C</b> is 'love' (from <b>amō</b>), and <b>D</b> is 'hear' (from <b>audiō</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>dō</b>.", options: ["lead", "say", "give", "god"], i: 2, explanation: "The correct answer is <b>C</b>. <b>dō</b> means 'give'. Distractors are translations of visually similar words: <b>A</b> is 'lead' (from <b>dūcō</b>), <b>B</b> is 'say' (from <b>dicō</b>), and <b>D</b> is 'god' (from <b>deus</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>longus, -a, -um</b>.", options: ["place", "light", "long", "happy"], i: 2, explanation: "The correct answer is <b>C</b>. <b>longus, -a, -um</b> means 'long'. Distractors are translations of visually similar words: <b>A</b> is 'place' (from <b>locus</b>), <b>B</b> is 'light' (from <b>lūx</b>), and <b>D</b> is 'happy' (from <b>laetus</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>magnus, -a, -um</b>.", options: ["much", "great, large", "bad", "sea"], i: 1, explanation: "The correct answer is <b>B</b>. <b>magnus, -a, -um</b> means 'great, large'. Distractors are translations of visually similar words: <b>A</b> is 'much' (from <b>multus</b>), <b>C</b> is 'bad' (from <b>malus</b>), and <b>D</b> is 'sea' (from <b>mare</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>nōn</b>.", options: ["now", "not", "new", "name"], i: 1, explanation: "The correct answer is <b>B</b>. <b>nōn</b> means 'not'. Distractors are translations of visually similar words: <b>A</b> is 'now' (from <b>nunc</b>), <b>C</b> is 'new' (from <b>novus</b>), and <b>D</b> is 'name' (from <b>nōmen</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>et</b>.", options: ["is", "and", "to him", "out of"], i: 1, explanation: "The correct answer is <b>B</b>. <b>et</b> means 'and'. Distractors are translations of visually or morphologically similar words: <b>A</b> is 'is' (from <b>est</b>), <b>C</b> is 'to him' (from <b>eī</b>), and <b>D</b> is 'out of' (from <b>ex</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>habeō</b>.", options: ["live", "here", "have, hold", "man"], i: 2, explanation: "The correct answer is <b>C</b>. <b>habeō</b> means 'have, hold'. Distractors are translations of visually similar words: <b>A</b> is 'live' (from <b>habitō</b>), <b>B</b> is 'here' (from <b>hīc</b>), and <b>D</b> is 'man' (from <b>homō</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>terra</b>.", options: ["fear", "land, earth", "temple", "crowd"], i: 1, explanation: "The correct answer is <b>B</b>. <b>terra</b> means 'land, earth, ground'. Distractors are translations of visually similar words: <b>A</b> is 'fear' (from <b>timeō</b>), <b>C</b> is 'temple' (from <b>templum</b>), and <b>D</b> is 'crowd' (from <b>turba</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>veniō</b>.", options: ["see", "conquer", "come", "voice"], i: 2, explanation: "The correct answer is <b>C</b>. <b>veniō</b> means 'come'. Distractors are translations of visually similar words: <b>A</b> is 'see' (from <b>videō</b>), <b>B</b> is 'conquer' (from <b>vincō</b>), and <b>D</b> is 'voice' (from <b>vōx</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>pōnō</b>.", options: ["carry", "put, place", "be able", "punishment"], i: 1, explanation: "The correct answer is <b>B</b>. <b>pōnō</b> means 'put, place'. Distractors are translations of visually similar words: <b>A</b> is 'carry' (from <b>portō</b>), <b>C</b> is 'be able' (from <b>possum</b>), and <b>D</b> is 'punishment' (from <b>poena</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>fīlia</b>.", options: ["son", "daughter", "story", "bear, carry"], i: 1, explanation: "The correct answer is <b>B</b>. <b>fīlia</b> means 'daughter'. Distractors are translations of visually similar words: <b>A</b> is 'son' (from <b>fīlius</b>), <b>C</b> is 'story' (from <b>fābula</b>), and <b>D</b> is 'bear, carry' (from <b>ferō</b>)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>bellum</b>.", options: ["well", "good", "war", "drink"], i: 2, explanation: "The correct answer is <b>C</b>. <b>bellum</b> means 'war'. Distractors are translations of visually similar words: <b>A</b> is 'well' (from <b>bene</b>), <b>B</b> is 'good' (from <b>bonus</b>), and <b>D</b> is 'drink' (from <b>bibō</b>)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>girl</b>", options: ["<i>fēmina, -ae</i> f.", "<i>puella, -ae</i> f.", "<i>puer, puerī</i> m.", "<i>vir, virī</i> m."], i: 1, explanation: "The best Latin translation for 'girl' is <i>puella, -ae</i> f. While <i>fēmina, -ae</i> f. means 'woman', it refers to an adult female. <i>Puer, puerī</i> m. means 'boy', and <i>vir, virī</i> m. means 'man'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to carry</b>", options: ["<i>vocō, vocāre, vocāvī, vocātus</i>", "<i>ambulō, ambulāre, ambulāvī, ambulātus</i>", "<i>portō, portāre, portāvī, portātus</i>", "<i>dō, dare, dedī, datus</i>"], i: 2, explanation: "The correct translation for 'to carry' is <i>portō, portāre, portāvī, portātus</i>. The other options are: <i>vocō</i> ('to call'), <i>ambulō</i> ('to walk'), and <i>dō</i> ('to give')." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>water</b>", options: ["<i>terra, -ae</i> f.", "<i>silva, -ae</i> f.", "<i>aqua, -ae</i> f.", "<i>via, -ae</i> f."], i: 2, explanation: "The Latin word for 'water' is <i>aqua, -ae</i> f. The other options are <i>terra, -ae</i> f. ('land' or 'earth'), <i>silva, -ae</i> f. ('forest' or 'wood'), and <i>via, -ae</i> f. ('road' or 'way')." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>good</b>", options: ["<i>magnus, magna, magnum</i>", "<i>bonus, bona, bonum</i>", "<i>malus, mala, malum</i>", "<i>lātus, lāta, lātum</i>"], i: 1, explanation: "The Latin word for 'good' is <i>bonus, bona, bonum</i>. <i>Magnus, magna, magnum</i> means 'large' or 'great'. <i>Malus, mala, malum</i> means 'bad'. <i>Lātus, lāta, lātum</i> means 'wide'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to see</b>", options: ["<i>teneō, tenēre, tenuī, tentus</i>", "<i>habeō, habēre, habuī, habitus</i>", "<i>videō, vidēre, vīdī, vīsus</i>", "<i>moveō, movēre, mōvī, mōtus</i>"], i: 2, explanation: "The correct translation for 'to see' is <i>videō, vidēre, vīdī, vīsus</i>. The other options are <i>teneō</i> ('to hold'), <i>habeō</i> ('to have'), and <i>moveō</i> ('to move'). All are 2nd conjugation verbs but have distinct meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>friend</b> (masculine)", options: ["<i>amīca, -ae</i> f.", "<i>servus, -ī</i> m.", "<i>amicus, -ī</i> m.", "<i>dominus, -ī</i> m."], i: 2, explanation: "The Latin word for a masculine 'friend' is <i>amicus, -ī</i> m. <i>Amīca, -ae</i> f. is a 'female friend'. <i>Servus, -ī</i> m. means 'slave', and <i>dominus, -ī</i> m. means 'master' or 'lord'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to be</b>", options: ["<i>possum, posse, potuī, —</i>", "<i>sum, esse, fuī, futūrus</i>", "<i>eō, īre, iī (īvī), itus</i>", "<i>volō, velle, voluī, —</i>"], i: 1, explanation: "The Latin verb 'to be' is <i>sum, esse, fuī, futūrus</i>. The other verbs are also irregular but have different meanings: <i>possum</i> ('to be able'), <i>eō</i> ('to go'), and <i>volō</i> ('to wish' or 'to be willing')." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>small</b>", options: ["<i>magnus, magna, magnum</i>", "<i>longus, longa, longum</i>", "<i>parvus, parva, parvum</i>", "<i>novus, nova, novum</i>"], i: 2, explanation: "The Latin word for 'small' is <i>parvus, parva, parvum</i>. <i>Magnus, magna, magnum</i> means 'large'. <i>Longus, longa, longum</i> means 'long'. <i>Novus, nova, novum</i> means 'new'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>house</b>", options: ["<i>villa, -ae</i> f.", "<i>oppidum, -ī</i> n.", "<i>casa, -ae</i> f.", "<i>templum, -ī</i> n."], i: 2, explanation: "For a general 'house' or 'cottage', <i>casa, -ae</i> f. is the most appropriate Latin I word. <i>Villa, -ae</i> f. refers to a 'country house' or 'estate'. <i>Oppidum, -ī</i> n. means 'town' or 'fortified town'. <i>Templum, -ī</i> n. means 'temple'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to call</b>", options: ["<i>dō, dare, dedī, datus</i>", "<i>stō, stāre, stetī, status</i>", "<i>vocō, vocāre, vocāvī, vocātus</i>", "<i>amō, amāre, amāvī, amātus</i>"], i: 2, explanation: "The correct translation for 'to call' is <i>vocō, vocāre, vocāvī, vocātus</i>. The other options are <i>dō</i> ('to give'), <i>stō</i> ('to stand'), and <i>amō</i> ('to love'). All are 1st conjugation verbs." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>boy</b>", options: ["<i>vir, virī</i> m.", "<i>servus, -ī</i> m.", "<i>puer, puerī</i> m.", "<i>fīlius, -ī</i> m."], i: 2, explanation: "The Latin word for 'boy' is <i>puer, puerī</i> m. <i>Vir, virī</i> m. means 'man'. <i>Servus, -ī</i> m. means 'slave'. <i>Fīlius, -ī</i> m. means 'son'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to have</b>", options: ["<i>videō, vidēre, vīdī, vīsus</i>", "<i>teneō, tenēre, tenuī, tentus</i>", "<i>habeō, habēre, habuī, habitus</i>", "<i>moveō, movēre, mōvī, mōtus</i>"], i: 2, explanation: "The correct translation for 'to have' is <i>habeō, habēre, habuī, habitus</i>. The other options are <i>videō</i> ('to see'), <i>teneō</i> ('to hold'), and <i>moveō</i> ('to move'). All are 2nd conjugation verbs." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>beautiful</b>", options: ["<i>bonus, bona, bonum</i>", "<i>magnus, magna, magnum</i>", "<i>pulcher, pulchra, pulchrum</i>", "<i>longus, longa, longum</i>"], i: 2, explanation: "The Latin word for 'beautiful' is <i>pulcher, pulchra, pulchrum</i>. This is an adjective of the 1st/2nd declension type with an -er ending in the masculine nominative singular. <i>Bonus</i> means 'good', <i>magnus</i> means 'large', and <i>longus</i> means 'long'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>city</b>", options: ["<i>villa, -ae</i> f.", "<i>ager, agrī</i> m.", "<i>oppidum, -ī</i> n.", "<i>via, -ae</i> f."], i: 2, explanation: "For 'city' or 'town', <i>oppidum, -ī</i> n. is a common Latin I vocabulary word. <i>Urbs, urbis</i> f. (3rd declension) also means 'city' but is often introduced later. <i>Villa, -ae</i> f. means 'country house'. <i>Ager, agrī</i> m. means 'field'. <i>Via, -ae</i> f. means 'road'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to give</b>", options: ["<i>dō, dare, dedī, datus</i>", "<i>stō, stāre, stetī, status</i>", "<i>vocō, vocāre, vocāvī, vocātus</i>", "<i>portō, portāre, portāvī, portātus</i>"], i: 0, explanation: "The correct translation for 'to give' is <i>dō, dare, dedī, datus</i>. The other options are <i>stō</i> ('to stand'), <i>vocō</i> ('to call'), and <i>portō</i> ('to carry'). All are 1st conjugation verbs, but <i>dō</i> is irregular in some of its principal parts." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>terrae</b>?", options: ["aquae", "agrō", "caelō", "silvae"], i: 1, explanation: "The word <b>terra</b> means 'earth' or 'land'. Its closest synonym among the options is <b>agrō</b>, which means 'field' or 'land'. Both refer to arable or open ground. The other options, <i>aquae</i> ('water'), <i>caelō</i> ('sky'), and <i>silvae</i> ('forest'), are related to natural environments but have distinct meanings." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>magnō</b>?", options: ["parvō", "longō", "amplō", "lātō"], i: 2, explanation: "The word <b>magnus</b> means 'large' or 'great'. Its closest synonym among the options is <b>amplō</b>, which means 'large', 'spacious', or 'ample'. Both describe significant size. The other options, <i>parvō</i> ('small'), <i>longō</i> ('long'), and <i>lātō</i> ('wide'), are adjectives describing size or dimension but are not direct synonyms for 'large' in the general sense." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>dīcere</b>?", options: ["scrībere", "audīre", "nārrāre", "vidēre"], i: 2, explanation: "The verb <b>dīcere</b> means 'to say' or 'to speak'. Its closest synonym among the options is <b>nārrāre</b>, which means 'to tell' or 'to relate'. Both verbs involve communicating information verbally. The other options, <i>scrībere</i> ('to write'), <i>audīre</i> ('to hear'), and <i>vidēre</i> ('to see'), are related to communication or senses but describe different actions." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>urbī</b>?", options: ["vīllae", "oppidō", "castrīs", "domuī"], i: 1, explanation: "The word <b>urbs</b> means 'city'. Its closest synonym among the options is <b>oppidō</b>, which means 'town' or 'fortified town'. Both refer to a significant settlement larger than a village. The other options, <i>vīllae</i> ('country house'), <i>castrīs</i> ('camp'), and <i>domuī</i> ('house'), are types of dwellings or settlements but are not equivalent to a city or town." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>bellō</b>?", options: ["pācī", "pugnae", "amīcitiae", "victōriae"], i: 1, explanation: "The word <b>bellum</b> means 'war'. Its closest synonym among the options is <b>pugnae</b>, which means 'fight' or 'battle'. Both terms refer to armed conflict. The other options, <i>pācī</i> ('peace'), <i>amīcitiae</i> ('friendship'), and <i>victōriae</i> ('victory'), are related concepts but are not synonyms for 'war'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>viae</b>?", options: ["flūminī", "itinerī", "montī", "silvae"], i: 1, explanation: "The word <b>via</b> means 'road' or 'way'. Its closest synonym among the options is <b>itinerī</b>, which means 'journey', 'path', or 'way'. Both refer to a route or a course of travel. The other options, <i>flūminī</i> ('river'), <i>montī</i> ('mountain'), and <i>silvae</i> ('forest'), are geographical features but not paths or routes." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>habēre</b>?", options: ["dare", "accipere", "tenēre", "emere"], i: 2, explanation: "The verb <b>habēre</b> means 'to have' or 'to hold'. Its closest synonym among the options is <b>tenēre</b>, which means 'to hold' or 'to keep'. Both verbs imply possession or retention. The other options, <i>dare</i> ('to give'), <i>accipere</i> ('to receive'), and <i>emere</i> ('to buy'), are related to the transfer or acquisition of possession but are not synonyms for 'to have'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>laetō</b>?", options: ["trīstī", "fēlīcī", "īrātō", "timidō"], i: 1, explanation: "The adjective <b>laetus</b> means 'happy' or 'joyful'. Its closest synonym among the options is <b>fēlīcī</b>, which means 'lucky', 'fortunate', or 'happy'. Both describe a positive emotional state. The other options, <i>trīstī</i> ('sad'), <i>īrātō</i> ('angry'), and <i>timidō</i> ('fearful'), describe different or opposing emotional states." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>temporī</b>?", options: ["locō", "spatiō", "numerō", "morae"], i: 1, explanation: "The word <b>tempus</b> means 'time' or 'a period of time'. Its closest synonym among the options is <b>spatiō</b>, which can mean 'space' but also 'an interval' or 'period of time'. Both refer to duration. The other options, <i>locō</i> ('place'), <i>numerō</i> ('number'), and <i>morae</i> ('delay'), are related abstract concepts but not direct synonyms for 'time'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>venīre</b>?", options: ["īre", "advenīre", "fugāre", "currere"], i: 1, explanation: "The verb <b>venīre</b> means 'to come'. Its closest synonym among the options is <b>advenīre</b>, which means 'to arrive' or 'to come to'. Both describe the act of approaching a destination. The other options, <i>īre</i> ('to go'), <i>fugāre</i> ('to put to flight'), and <i>currere</i> ('to run'), are verbs of motion but describe different directions or manners of movement." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>patrī</b>?", options: ["mātrī", "fīliō", "genitōrī", "frātrī"], i: 2, explanation: "The word <b>pater</b> means 'father'. Its closest synonym among the options is <b>genitōrī</b>, which also means 'father' or 'begetter'. Both refer to the male parent. The other options, <i>mātrī</i> ('mother'), <i>fīliō</i> ('son'), and <i>frātrī</i> ('brother'), are other family members but not synonyms for 'father'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>dare</b>?", options: ["accipere", "petere", "praebēre", "tenēre"], i: 2, explanation: "The verb <b>dare</b> means 'to give'. Its closest synonym among the options is <b>praebēre</b>, which means 'to offer', 'to provide', or 'to furnish'. Both verbs involve making something available to another. The other options, <i>accipere</i> ('to receive'), <i>petere</i> ('to seek, ask for'), and <i>tenēre</i> ('to hold'), are related to transfer or possession but are not synonyms for 'to give'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>bonō</b>?", options: ["malō", "magnō", "probō", "pulchrō"], i: 2, explanation: "The adjective <b>bonus</b> means 'good'. Its closest synonym among the options is <b>probō</b>, which means 'good', 'upright', or 'honest', often implying moral goodness. Both describe positive qualities. The other options, <i>malō</i> ('bad'), <i>magnō</i> ('great, large'), and <i>pulchrō</i> ('beautiful'), are adjectives but have different meanings." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>nōn</b>?", options: ["ita", "semper", "minimē", "numquam"], i: 2, explanation: "The adverb <b>nōn</b> means 'not'. Its closest synonym among the options is <b>minimē</b>, which means 'least', 'not at all', or 'by no means', serving as a strong negation. Both express denial or absence. The other options, <i>ita</i> ('thus, yes'), <i>semper</i> ('always'), and <i>numquam</i> ('never'), are adverbs but convey different meanings related to affirmation or time." }, { meta: "Synonyms", stem: "Quod verbum est simillimum <b>vītae</b>?", options: ["mortī", "animae", "corporī", "salūtī"], i: 1, explanation: "The word <b>vīta</b> means 'life'. Its closest synonym among the options is <b>animae</b>, which means 'soul', 'spirit', or 'life-breath'. In many contexts, 'anima' can refer to the principle of life itself. The other options, <i>mortī</i> ('death'), <i>corporī</i> ('body'), and <i>salūtī</i> ('safety, health'), are related concepts but are not synonyms for 'life'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>magnus</b>?", options: ["bonus", "malus", "parvus", "multus"], i: 2, explanation: "The word <b>magnus</b> means 'large' or 'great'. Its direct opposite is <b>parvus</b>, meaning 'small'. Options A (bonus, 'good') and B (malus, 'bad') are opposites of each other, but not of size. Option D (multus, 'much' or 'many') refers to quantity, not size." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>bonus</b>?", options: ["magnus", "malus", "laetus", "trīstis"], i: 1, explanation: "The word <b>bonus</b> means 'good'. Its direct antonym is <b>malus</b>, meaning 'bad' or 'evil'. Options A (magnus, 'large') refers to size. Option C (laetus, 'happy') and D (trīstis, 'sad') are opposites related to emotion, not moral quality." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>laetus</b>?", options: ["pulcher", "fessus", "trīstis", "fortis"], i: 2, explanation: "The word <b>laetus</b> means 'happy' or 'joyful'. Its closest antonym is <b>trīstis</b>, meaning 'sad'. Options A (pulcher, 'beautiful'), B (fessus, 'tired'), and D (fortis, 'brave') are adjectives describing other qualities, not the opposite of happiness." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>stāre</b>?", options: ["currere", "ambulāre", "sedēre", "dormīre"], i: 2, explanation: "The verb <b>stāre</b> means 'to stand'. The most direct opposite action is <b>sedēre</b>, 'to sit'. Options A (currere, 'to run') and B (ambulāre, 'to walk') are forms of movement, not the opposite of standing. Option D (dormīre, 'to sleep') is an unrelated action." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>venīre</b>?", options: ["manēre", "audīre", "vidēre", "discēdere"], i: 3, explanation: "The verb <b>venīre</b> means 'to come'. Its opposite is <b>discēdere</b>, meaning 'to depart' or 'to go away'. Option A (manēre, 'to remain') is related to staying, not the opposite of coming. Options B (audīre, 'to hear') and C (vidēre, 'to see') are unrelated verbs." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>docēre</b>?", options: ["scrībere", "legere", "audīre", "discere"], i: 3, explanation: "The verb <b>docēre</b> means 'to teach'. The direct opposite action is <b>discere</b>, 'to learn'. Options A (scrībere, 'to write'), B (legere, 'to read'), and C (audīre, 'to hear') are related to academic activities but are not antonyms of teaching." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>aperīre</b>?", options: ["pōnere", "tollere", "dūcere", "claudere"], i: 3, explanation: "The verb <b>aperīre</b> means 'to open'. Its direct opposite is <b>claudere</b>, meaning 'to close'. Options A (pōnere, 'to put'), B (tollere, 'to lift'), and C (dūcere, 'to lead') are unrelated verbs." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>plēnus</b>?", options: ["magnus", "parvus", "multus", "vacuus"], i: 3, explanation: "The adjective <b>plēnus</b> means 'full'. Its direct antonym is <b>vacuus</b>, meaning 'empty'. Options A (magnus, 'large') and B (parvus, 'small') refer to size. Option C (multus, 'much' or 'many') refers to quantity." }, { meta: "Antonyms", stem: "Quod verbum est contrārium nōminī <b>nox</b>?", options: ["hōra", "lūx", "umbra", "diēs"], i: 3, explanation: "The noun <b>nox</b> means 'night'. Its direct opposite is <b>diēs</b>, meaning 'day'. Option A (hōra, 'hour') is a unit of time. Option B (lūx, 'light') is a related concept but not the direct opposite of 'night'. Option C (umbra, 'shadow') is also a related concept but not the antonym." }, { meta: "Antonyms", stem: "Quod verbum est contrārium nōminī <b>bellum</b>?", options: ["arma", "hostis", "pāx", "amīcitia"], i: 2, explanation: "The noun <b>bellum</b> means 'war'. Its direct opposite is <b>pāx</b>, meaning 'peace'. Option A (arma, 'arms' or 'weapons') and B (hostis, 'enemy') are related to war but are not its antonym. Option D (amīcitia, 'friendship') is the opposite of enmity, not war itself." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>dūrus</b>?", options: ["gravis", "levis", "mollis", "lātus"], i: 2, explanation: "The adjective <b>dūrus</b> means 'hard' or 'tough'. Its direct antonym is <b>mollis</b>, meaning 'soft'. Option A (gravis, 'heavy') and B (levis, 'light') are opposites related to weight. Option D (lātus, 'wide') refers to dimension." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>altus</b>?", options: ["lātus", "longus", "brevis", "humilis"], i: 3, explanation: "The adjective <b>altus</b> can mean 'high' or 'deep'. Its opposite, referring to 'low', is <b>humilis</b>. Options A (lātus, 'wide'), B (longus, 'long'), and C (brevis, 'short') refer to other dimensions." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adverbō <b>saepe</b>?", options: ["semper", "nunc", "rārō", "tum"], i: 2, explanation: "The adverb <b>saepe</b> means 'often'. Its direct antonym is <b>rārō</b>, meaning 'rarely' or 'seldom'. Option A (semper, 'always') is a stronger degree of frequency, not an antonym. Options B (nunc, 'now') and D (tum, 'then') are adverbs of specific time, not frequency." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adverbō <b>ante</b>?", options: ["prope", "sub", "post", "super"], i: 2, explanation: "The adverb <b>ante</b> means 'before' (in time or place). Its direct antonym is <b>post</b>, meaning 'after' (in time or place). Options A (prope, 'near'), B (sub, 'under'), and D (super, 'over') are adverbs or prepositions of place, not antonyms of 'before'/'after'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium adiectīvō <b>multus</b>?", options: ["magnus", "parvus", "omnis", "paucus"], i: 3, explanation: "The adjective <b>multus</b> means 'much' or 'many'. Its direct antonym is <b>paucus</b>, meaning 'few' or 'little'. Options A (magnus, 'large') and B (parvus, 'small') refer to size, not quantity. Option C (omnis, 'all') refers to totality, not the opposite of 'many'." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["puella, puellae, f.", "puer, puerī, m.", "agricola, agricolae, m.", "terra, terrae, f."], i: 3, explanation: "The words <b>puella</b> (girl), <b>puer</b> (boy), and <b>agricola</b> (farmer) all refer to people. <b>Terra</b> (land, earth) refers to a place or substance and therefore does not belong to the semantic group of 'people'." }, { meta: "Odd One Out", stem: "Which of the following Latin verbs does NOT belong?", options: ["amō, amāre", "laudō, laudāre", "videō, vidēre", "portō, portāre"], i: 2, explanation: "The verbs <b>amō</b> (to love), <b>laudō</b> (to praise), and <b>portō</b> (to carry) are all first conjugation verbs, identifiable by their <i>-āre</i> infinitive ending. <b>Videō</b> (to see) is a second conjugation verb, identifiable by its <i>-ēre</i> infinitive ending, and thus does not belong morphologically." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["villa, villae, f.", "casa, casae, f.", "forum, forī, n.", "aqua, aquae, f."], i: 3, explanation: "The words <b>villa</b> (country house), <b>casa</b> (house, hut), and <b>forum</b> (forum, marketplace) all refer to types of buildings or places. <b>Aqua</b> (water) refers to a substance and therefore does not belong to the semantic group of 'places/buildings'." }, { meta: "Odd One Out", stem: "Which of the following Latin nouns does NOT belong?", options: ["servus, servī, m.", "amicus, amicī, m.", "lupus, lupī, m.", "fīlia, fīliae, f."], i: 3, explanation: "The nouns <b>servus</b> (slave), <b>amicus</b> (friend), and <b>lupus</b> (wolf) are all second declension nouns, typically ending in <i>-us</i> in the nominative singular and <i>-ī</i> in the genitive singular. <b>Fīlia</b> (daughter) is a first declension noun, ending in <i>-a</i> in the nominative singular and <i>-ae</i> in the genitive singular, and thus does not belong morphologically." }, { meta: "Odd One Out", stem: "Which of the following Latin adjectives does NOT belong?", options: ["magnus, magna, magnum", "parvus, parva, parvum", "multus, multa, multum", "bonus, bona, bonum"], i: 3, explanation: "The adjectives <b>magnus</b> (large), <b>parvus</b> (small), and <b>multus</b> (much, many) all describe quantity or size. <b>Bonus</b> (good) describes quality and therefore does not belong to the semantic group of 'size/quantity'." }, { meta: "Odd One Out", stem: "Which of the following Latin verb forms does NOT belong?", options: ["amat", "laudant", "videt", "audit"], i: 1, explanation: "The verb forms <b>amat</b> (he/she/it loves), <b>videt</b> (he/she/it sees), and <b>audit</b> (he/she/it hears) are all third person singular present active indicative forms. <b>Laudant</b> (they praise) is a third person plural present active indicative form, and thus does not belong morphologically due to its number." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["oculus, oculī, m.", "bracchium, bracchiī, n.", "pēs, pedis, m.", "cibus, cibī, m."], i: 3, explanation: "The words <b>oculus</b> (eye), <b>bracchium</b> (arm), and <b>pēs</b> (foot) all refer to parts of the body. <b>Cibus</b> (food) refers to sustenance and therefore does not belong to the semantic group of 'body parts'." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["bene", "male", "saepe", "pulcher, pulchra, pulchrum"], i: 3, explanation: "The words <b>bene</b> (well), <b>male</b> (badly), and <b>saepe</b> (often) are all adverbs. <b>Pulcher</b> (beautiful) is an adjective and therefore does not belong morphologically to the group of adverbs." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["hodiē", "heri", "nunc", "lūx, lūcis, f."], i: 3, explanation: "The words <b>hodiē</b> (today), <b>heri</b> (yesterday), and <b>nunc</b> (now) are all adverbs of time. <b>Lūx</b> (light, daylight) is a third declension noun and therefore does not belong morphologically to the group of adverbs of time." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong?", options: ["in", "ad", "cum", "et"], i: 3, explanation: "The words <b>in</b> (in, on, into), <b>ad</b> (to, towards), and <b>cum</b> (with) are all prepositions. <b>Et</b> (and) is a conjunction and therefore does not belong morphologically to the group of prepositions." }, { meta: "Analogies", stem: "<b>servus</b> : <b>servī</b> :: <b>puella</b> : X", options: ["puellae", "puellam", "puellās", "puellā"], i: 0, explanation: "The relationship is singular nominative noun to plural nominative noun. <b>servus</b> (singular) becomes <b>servī</b> (plural). Similarly, <b>puella</b> (singular) becomes <b>puellae</b> (plural). Options B, C, and D are other case forms (accusative singular, accusative plural, ablative singular, respectively) and do not fit the pattern." }, { meta: "Analogies", stem: "<b>laudō</b> : <b>laudāre</b> :: <b>ambulō</b> : X", options: ["ambulō", "ambulāre", "ambulās", "ambulāmus"], i: 1, explanation: "The relationship is the first person singular present active indicative form of a verb to its present active infinitive form. <b>laudō</b> (I praise) corresponds to <b>laudāre</b> (to praise). Following this pattern, <b>ambulō</b> (I walk) corresponds to <b>ambulāre</b> (to walk). The other options are different conjugated forms of the verb." }, { meta: "Analogies", stem: "<b>via</b> : road :: <b>terra</b> : X", options: ["water", "earth", "sky", "tree"], i: 1, explanation: "The relationship is a Latin noun to its English meaning. <b>via</b> means 'road'. Therefore, <b>terra</b> means 'earth' or 'land'. The other options are meanings of different Latin nouns (e.g., aqua, caelum, arbor)." }, { meta: "Analogies", stem: "<b>digitus</b> : <b>manus</b> :: <b>caput</b> : X", options: ["pēs", "oculus", "corpus", "bracchium"], i: 2, explanation: "The relationship is 'part : whole'. A <b>digitus</b> (finger) is a part of a <b>manus</b> (hand). Similarly, a <b>caput</b> (head) is a part of the <b>corpus</b> (body). Options A, B, and D are other body parts, but not the 'whole' to which the head belongs in the same way a finger belongs to a hand." }, { meta: "Analogies", stem: "<b>pugnāre</b> : <b>mīles</b> :: <b>docēre</b> : X", options: ["servus", "agricola", "magister", "poēta"], i: 2, explanation: "The relationship is 'action : agent'. <b>pugnāre</b> (to fight) is the action performed by a <b>mīles</b> (soldier). Similarly, <b>docēre</b> (to teach) is the action performed by a <b>magister</b> (teacher). The other options are different types of people who do not typically perform the action of teaching." }, { meta: "Analogies", stem: "<b>bonus</b> : <b>malus</b> :: <b>magnus</b> : X", options: ["longus", "parvus", "altus", "novus"], i: 1, explanation: "The relationship is 'adjective : antonym'. <b>bonus</b> (good) is the opposite of <b>malus</b> (bad). Following this pattern, <b>magnus</b> (large/great) is the opposite of <b>parvus</b> (small). The other options are other common adjectives but not the antonym of <b>magnus</b>." }, { meta: "Analogies", stem: "<b>dō</b> : <b>dedit</b> :: <b>vocō</b> : X", options: ["vocat", "vocāre", "vocāvit", "vocābō"], i: 2, explanation: "The relationship is 'present active indicative, 1st person singular : perfect active indicative, 3rd person singular'. <b>dō</b> (I give) has the perfect form <b>dedit</b> (he/she/it gave). Similarly, <b>vocō</b> (I call) has the perfect form <b>vocāvit</b> (he/she/it called). The other options are different verb forms (present, infinitive, future)." }, { meta: "Analogies", stem: "<b>rēgīna</b> : <b>rēgīnārum</b> :: <b>fīlia</b> : X", options: ["fīliam", "fīliīs", "fīliārum", "fīliae"], i: 2, explanation: "The relationship is 'nominative singular noun : genitive plural noun'. <b>rēgīna</b> (queen) becomes <b>rēgīnārum</b> (of the queens). Following this pattern, <b>fīlia</b> (daughter) becomes <b>fīliārum</b> (of the daughters). The other options are different case forms (accusative singular, dative/ablative plural, genitive singular/nominative plural)." }, { meta: "Analogies", stem: "<b>cum</b> : ablative :: <b>ad</b> : X", options: ["nominative", "genitive", "dative", "accusative"], i: 3, explanation: "The relationship is 'preposition : case it takes'. The preposition <b>cum</b> (with) takes the ablative case. Similarly, the preposition <b>ad</b> (to, toward) takes the <b>accusative</b> case. The other options are other Latin cases that <b>ad</b> does not typically govern." }, { meta: "Analogies", stem: "<b>nauta</b> : <b>nāvis</b> :: <b>agricola</b> : X", options: ["aqua", "silva", "ager", "via"], i: 2, explanation: "The relationship is 'person : associated place/object'. A <b>nauta</b> (sailor) is associated with a <b>nāvis</b> (ship). Similarly, an <b>agricola</b> (farmer) is associated with an <b>ager</b> (field). The other options are other common nouns for places or objects that are not as directly associated with a farmer." }, { meta: "Fill-in-the-Blank", stem: "Agricola in agrō _____.<br><i>The farmer in the field _____</i>.", options: ["labōrat", "dormit", "currit", "habitat"], i: 0, explanation: "The correct answer is <b>A. labōrat</b>. The verb <i>labōrat</i> means 'works', which is the most logical activity for a farmer (<i>agricola</i>) to be doing in a field (<i>in agrō</i>).<br><b>B. dormit</b> means 'sleeps'. While one might sleep in a field, it's not the primary activity of a farmer.<br><b>C. currit</b> means 'runs'. Farmers might run, but 'working' is more characteristic.<br><b>D. habitat</b> means 'lives'. Farmers live, but typically not 'in the field' itself." }, { meta: "Fill-in-the-Blank", stem: "Puella aquam ad casam _____.<br><i>The girl water to the house _____</i>.", options: ["videt", "portat", "audit", "vocat"], i: 1, explanation: "The correct answer is <b>B. portat</b>. The verb <i>portat</i> means 'carries', which is the most appropriate action for a girl (<i>puella</i>) to do with water (<i>aquam</i>) to a house (<i>ad casam</i>).<br><b>A. videt</b> means 'sees'. One might see water, but not 'see water to the house'.<br><b>C. audit</b> means 'hears'. Water doesn't typically make a sound that is 'heard to the house'.<br><b>D. vocat</b> means 'calls'. One does not 'call water to the house'." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī multās ____ habēbant.<br><i>The Romans many _____ had</i>.", options: ["silvās", "aquās", "viās", "fēminās"], i: 2, explanation: "The correct answer is <b>C. viās</b>. The noun <i>viās</i> (accusative plural of <i>via, viae</i>) means 'roads'. The Romans were famous for building many roads, making this the most fitting choice.<br><b>A. silvās</b> means 'forests'. While Romans had forests, they are not as famously associated with 'many forests' as they are with roads.<br><b>B. aquās</b> means 'waters'. This doesn't make as much sense in the context of 'having many'.<br><b>D. fēminās</b> means 'women'. While Romans certainly had many women, the sentence structure implies something they possessed or built, making 'roads' a better fit for a common historical fact." }, { meta: "Fill-in-the-Blank", stem: "Puer librum _____.<br><i>The boy a book _____</i>.", options: ["scrībit", "audit", "legit", "timet"], i: 2, explanation: "The correct answer is <b>C. legit</b>. The verb <i>legit</i> means 'reads', which is the most common and direct action one performs with a book (<i>librum</i>).<br><b>A. scrībit</b> means 'writes'. One writes <i>in</i> a book or <i>a</i> book, but not typically 'a book' as a direct object in this context.<br><b>B. audit</b> means 'hears'. One does not hear a book.<br><b>D. timet</b> means 'fears'. While one might fear a book (e.g., a difficult one), 'reads' is the most primary and logical action." }, { meta: "Fill-in-the-Blank", stem: "In silvā multae ____ sunt.<br><i>In the forest many _____ are</i>.", options: ["viae", "bēstiae", "casae", "fēminae"], i: 1, explanation: "The correct answer is <b>B. bēstiae</b>. The noun <i>bēstiae</i> (nominative plural of <i>bēstia, bēstiae</i>) means 'wild animals' or 'beasts'. It is very common to find many wild animals in a forest (<i>in silvā</i>).<br><b>A. viae</b> means 'roads'. While some roads might pass through a forest, 'many roads' are not typically characteristic of a forest itself.<br><b>C. casae</b> means 'houses'. Forests are generally wild places, not typically filled with 'many houses'.<br><b>D. fēminae</b> means 'women'. While women might be in a forest, 'many women' is not a defining characteristic of a forest's inhabitants." }, { meta: "Fill-in-the-Blank", stem: "Cīvēs Rōmānī in ____ vīvēbant.<br><i>Roman citizens lived in _____</i>.", options: ["agrīs", "silvīs", "Rōmā", "īnsulīs"], i: 2, explanation: "The correct answer is <b>C. Rōmā</b>. The noun <i>Rōmā</i> (ablative singular of <i>Rōma, Rōmae</i>) means 'Rome'. Roman citizens (<i>Cīvēs Rōmānī</i>) most famously lived in Rome.<br><b>A. agrīs</b> means 'fields'. While some Romans lived in the countryside, 'Roman citizens' generally refers to those in the city, especially Rome.<br><b>B. silvīs</b> means 'forests'. It's unlikely that Roman citizens would live 'in forests'.<br><b>D. īnsulīs</b> means 'islands'. While the Roman Empire included islands, 'Rome' is the most direct and common answer for where 'Roman citizens' lived." }, { meta: "Fill-in-the-Blank", stem: "Lēgātus mīlitēs ad proelium _____.<br><i>The legate the soldiers to battle _____</i>.", options: ["videt", "audit", "dūcit", "vocat"], i: 2, explanation: "The correct answer is <b>C. dūcit</b>. The verb <i>dūcit</i> means 'leads'. A legate (<i>lēgātus</i>) is a military commander, and their primary role with soldiers (<i>mīlitēs</i>) before a battle (<i>ad proelium</i>) is to lead them.<br><b>A. videt</b> means 'sees'. While a legate sees soldiers, 'sees to battle' is not idiomatic.<br><b>B. audit</b> means 'hears'. A legate might hear soldiers, but not 'hears to battle'.<br><b>D. vocat</b> means 'calls'. While a legate might call soldiers, 'leads' is a more direct and significant action in the context of going 'to battle'." }, { meta: "Fill-in-the-Blank", stem: "Nautae in ____ navigant.<br><i>Sailors in the _____ sail</i>.", options: ["agrō", "silvā", "aquā", "casā"], i: 2, explanation: "The correct answer is <b>C. aquā</b>. The noun <i>aquā</i> (ablative singular of <i>aqua, aquae</i>) means 'water'. Sailors (<i>nautae</i>) sail (<i>navigant</i>) in water.<br><b>A. agrō</b> means 'field'. Sailors do not sail in a field.<br><b>B. silvā</b> means 'forest'. Sailors do not sail in a forest.<br><b>D. casā</b> means 'house'. Sailors do not sail in a house." }, { meta: "Fill-in-the-Blank", stem: "Puerī et puellae in ____ lūdunt.<br><i>Boys and girls in the _____ play</i>.", options: ["casā", "agrō", "silvā", "viā"], i: 3, explanation: "The correct answer is <b>D. viā</b>. The noun <i>viā</i> (ablative singular of <i>via, viae</i>) means 'street' or 'road'. It is common for children (<i>puerī et puellae</i>) to play (<i>lūdunt</i>) in the street or on a road.<br><b>A. casā</b> means 'house'. While children play in a house, 'in the street' is a common outdoor playing location.<br><b>B. agrō</b> means 'field'. Children can play in a field, but 'street' is also a very common and basic place for play.<br><b>C. silvā</b> means 'forest'. While children might play in a forest, it's less universally common for casual play than a street or field." }, { meta: "Circumlocution", stem: "Quid significat: <b>Hīc est parvus homō quī nōn est fēmina.</b>", options: ["puer", "puella", "vir", "fēmina"], i: 0, explanation: 'The Latin phrase <i>Hīc est parvus homō quī nōn est fēmina</i> translates to "This is a small human who is not a woman." This description accurately defines a <b>puer</b>, meaning "boy." Options B (<i>puella</i>, "girl"), C (<i>vir</i>, "man"), and D (<i>fēmina</i>, "woman") do not fit the description of a "small human who is not a woman" as precisely as <i>puer</i>.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Magnus locus ubi multī hominēs habitant et multa aedificia sunt.</b>", options: ["villa", "ager", "urbs", "via"], i: 2, explanation: 'The Latin phrase <i>Magnus locus ubi multī hominēs habitant et multa aedificia sunt</i> translates to "A large place where many people live and many buildings are." This describes an <b>urbs</b>, meaning "city." Option A (<i>villa</i>, "country house") is too small. Option B (<i>ager</i>, "field") is an open area, not typically with many buildings. Option D (<i>via</i>, "road") is a path, not a populated place.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Magnam benevolentiam erga aliquem vel aliquid sentiō.</b>", options: ["laudō", "amō", "dō", "habeō"], i: 1, explanation: 'The Latin phrase <i>Magnam benevolentiam erga aliquem vel aliquid sentiō</i> translates to "I feel great goodwill towards someone or something." This describes the act of loving, which is <b>amō</b>, meaning "I love." Option A (<i>laudō</i>, "I praise"), C (<i>dō</i>, "I give"), and D (<i>habeō</i>, "I have") do not convey the specific emotion of goodwill or affection.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Locus per quem hominēs ambulant vel equī currunt.</b>", options: ["ager", "aqua", "silva", "via"], i: 3, explanation: 'The Latin phrase <i>Locus per quem hominēs ambulant vel equī currunt</i> translates to "A place through which people walk or horses run." This describes a <b>via</b>, meaning "road" or "way." Option A (<i>ager</i>, "field"), B (<i>aqua</i>, "water"), and C (<i>silva</i>, "forest") are places, but not specifically designated paths for travel in this manner.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Liquor clārus et frīgidus quem bibimus.</b>", options: ["vīnum", "aqua", "pānis", "terra"], i: 1, explanation: 'The Latin phrase <i>Liquor clārus et frīgidus quem bibimus</i> translates to "A clear and cold liquid which we drink." This describes <b>aqua</b>, meaning "water." Option A (<i>vīnum</i>, "wine") is a liquid but not necessarily always clear and cold, and <i>aqua</i> is the most fundamental drink. Option C (<i>pānis</i>, "bread") is a solid food. Option D (<i>terra</i>, "earth") is land.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Rem alterī trādō.</b>", options: ["dō", "teneō", "vocō", "portō"], i: 0, explanation: 'The Latin phrase <i>Rem alterī trādō</i> translates to "I hand over a thing to another." This describes the act of giving, which is <b>dō</b>, meaning "I give." Option B (<i>teneō</i>, "I hold"), C (<i>vocō</i>, "I call"), and D (<i>portō</i>, "I carry") are actions, but they do not involve transferring ownership or possession to another person.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Pars mundī quae nōn est mare vel caelum.</b>", options: ["caelum", "mare", "terra", "silva"], i: 2, explanation: 'The Latin phrase <i>Pars mundī quae nōn est mare vel caelum</i> translates to "Part of the world which is not sea or sky." This describes <b>terra</b>, meaning "land" or "earth." Option A (<i>caelum</i>, "sky") and B (<i>mare</i>, "sea") are explicitly excluded by the definition. Option D (<i>silva</i>, "forest") is a specific type of land, not the general concept.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Rem ab ūnō locō ad alium ferō.</b>", options: ["ambulō", "teneō", "portō", "vocō"], i: 2, explanation: 'The Latin phrase <i>Rem ab ūnō locō ad alium ferō</i> translates to "I bear a thing from one place to another." This describes the act of carrying, which is <b>portō</b>, meaning "I carry." Option A (<i>ambulō</i>, "I walk") is moving oneself. Option B (<i>teneō</i>, "I hold") is holding something in place. Option D (<i>vocō</i>, "I call") is an act of speaking, not moving an object.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Nōn parvus.</b>", options: ["parvus", "magnus", "bonus", "malus"], i: 1, explanation: 'The Latin phrase <i>Nōn parvus</i> translates to "Not small." This directly defines <b>magnus</b>, meaning "large" or "great." Option A (<i>parvus</i>, "small") is the opposite. Option C (<i>bonus</i>, "good") and D (<i>malus</i>, "bad") describe quality, not size.' }, { meta: "Circumlocution", stem: "Quid significat: <b>Homō quem bene nōvī et cui crēdō.</b>", options: ["inimīcus", "servus", "amīcus", "dominus"], i: 2, explanation: 'The Latin phrase <i>Homō quem bene nōvī et cui crēdō</i> translates to "A person whom I know well and whom I trust." This describes an <b>amīcus</b>, meaning "friend." Option A (<i>inimīcus</i>, "enemy") is the opposite. Option B (<i>servus</i>, "slave") and D (<i>dominus</i>, "master") describe social roles, not necessarily a relationship of trust and familiarity.' }, { meta: "Latin to English", stem: "What is the best translation of via?", options: ["road", "life", "wine", "man"], i: 0, explanation: "The Latin word <b>via</b> means 'road' or 'way'. Option B, 'life', is the translation of <b>vīta</b>. Option C, 'wine', is the translation of <b>vīnum</b>. Option D, 'man', is the translation of <b>vir</b>." }, { meta: "Latin to English", stem: "What is the best translation of vīta?", options: ["road", "life", "wine", "man"], i: 1, explanation: "The Latin word <b>vīta</b> means 'life'. Option A, 'road', is the translation of <b>via</b>. Option C, 'wine', is the translation of <b>vīnum</b>. Option D, 'man', is the translation of <b>vir</b>." }, { meta: "Latin to English", stem: "What is the best translation of puer?", options: ["boy", "beautiful", "foot", "war"], i: 0, explanation: "The Latin word <b>puer</b> means 'boy'. Option B, 'beautiful', is the translation of <b>pulcher</b>. Option C, 'foot', is the translation of <b>pēs</b>. Option D, 'war', is the translation of <b>bellum</b>." }, { meta: "Latin to English", stem: "What is the best translation of pulcher?", options: ["boy", "beautiful", "foot", "dust"], i: 1, explanation: "The Latin word <b>pulcher</b> means 'beautiful'. Option A, 'boy', is the translation of <b>puer</b>. Option C, 'foot', is the translation of <b>pēs</b>. Option D, 'dust', is the translation of <b>pulvis</b>." }, { meta: "Latin to English", stem: "What is the best translation of dūcō?", options: ["I lead", "I say", "I give", "I learn"], i: 0, explanation: "The Latin verb <b>dūcō</b> means 'I lead'. Option B, 'I say', is the translation of <b>dicō</b>. Option C, 'I give', is the translation of <b>dō</b>. Option D, 'I learn', is the translation of <b>discō</b>." }, { meta: "Latin to English", stem: "What is the best translation of dicō?", options: ["I lead", "I say", "I give", "I learn"], i: 1, explanation: "The Latin verb <b>dicō</b> means 'I say' or 'I tell'. Option A, 'I lead', is the translation of <b>dūcō</b>. Option C, 'I give', is the translation of <b>dō</b>. Option D, 'I learn', is the translation of <b>discō</b>." }, { meta: "Latin to English", stem: "What is the best translation of sedeō?", options: ["I sit", "I see", "I stand", "I fall"], i: 0, explanation: "The Latin verb <b>sedeō</b> means 'I sit'. Option B, 'I see', is the translation of <b>videō</b>. Option C, 'I stand', is the translation of <b>stō</b>. Option D, 'I fall', is the translation of <b>cadō</b>." }, { meta: "Latin to English", stem: "What is the best translation of videō?", options: ["I sit", "I see", "I come", "I conquer"], i: 1, explanation: "The Latin verb <b>videō</b> means 'I see'. Option A, 'I sit', is the translation of <b>sedeō</b>. Option C, 'I come', is the translation of <b>veniō</b>. Option D, 'I conquer', is the translation of <b>vincō</b>." }, { meta: "Latin to English", stem: "What is the best translation of veniō?", options: ["I come", "I see", "I conquer", "I wish"], i: 0, explanation: "The Latin verb <b>veniō</b> means 'I come'. Option B, 'I see', is the translation of <b>videō</b>. Option C, 'I conquer', is the translation of <b>vincō</b>. Option D, 'I wish', is the translation of <b>volō</b>." }, { meta: "Latin to English", stem: "What is the best translation of vincō?", options: ["I come", "I conquer", "I live", "I wish"], i: 1, explanation: "The Latin verb <b>vincō</b> means 'I conquer'. Option A, 'I come', is the translation of <b>veniō</b>. Option C, 'I live', is the translation of <b>vīvō</b>. Option D, 'I wish', is the translation of <b>volō</b>." }, { meta: "Latin to English", stem: "What is the best translation of nōs?", options: ["we", "name", "night", "new"], i: 0, explanation: "The Latin pronoun <b>nōs</b> means 'we' or 'us'. Option B, 'name', is the translation of <b>nōmen</b>. Option C, 'night', is the translation of <b>nox</b>. Option D, 'new', is the translation of the adjective <b>novus</b>." }, { meta: "Latin to English", stem: "What is the best translation of nōmen?", options: ["we", "name", "night", "divine power"], i: 1, explanation: "The Latin noun <b>nōmen</b> means 'name'. Option A, 'we', is the translation of <b>nōs</b>. Option C, 'night', is the translation of <b>nox</b>. Option D, 'divine power', is the translation of <b>nūmen</b>." }, { meta: "Latin to English", stem: "What is the best translation of manus?", options: ["hand", "mother", "sea", "wall"], i: 0, explanation: "The Latin noun <b>manus</b> (fourth declension) means 'hand'. Option B, 'mother', is the translation of <b>māter</b>. Option C, 'sea', is the translation of <b>mare</b>. Option D, 'wall', is the translation of <b>mūrus</b>." }, { meta: "Latin to English", stem: "What is the best translation of māter?", options: ["hand", "mother", "sea", "wall"], i: 1, explanation: "The Latin noun <b>māter</b> (third declension) means 'mother'. Option A, 'hand', is the translation of <b>manus</b>. Option C, 'sea', is the translation of <b>mare</b>. Option D, 'wall', is the translation of <b>mūrus</b>." }, { meta: "Latin to English", stem: "What is the best translation of liber?", options: ["book", "free", "children", "light"], i: 0, explanation: "The Latin noun <b>liber</b> (second declension) means 'book'. Option B, 'free', is the translation of the adjective <b>līber</b>. Option C, 'children', is the translation of the plural noun <b>līberī</b>. Option D, 'light', is the translation of <b>lūx</b>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>to carry</b>.", options: ["portō", "volō", "vocō", "stō"], i: 0, explanation: "The correct Latin verb for <b>to carry</b> is <i>portō, portāre</i>. Option B, <i>volō, volāre</i>, means <b>to fly</b>. Option C, <i>vocō, vocāre</i>, means <b>to call</b>. Option D, <i>stō, stāre</i>, means <b>to stand</b>. All are first conjugation verbs, but with distinct meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>girl</b>.", options: ["puella", "puer", "serva", "fīlia"], i: 0, explanation: "The correct Latin noun for <b>girl</b> is <i>puella, puellae</i> (f.). Option B, <i>puer, puerī</i> (m.), means <b>boy</b>. Option C, <i>serva, servae</i> (f.), means <b>female slave</b>. Option D, <i>fīlia, fīliae</i> (f.), means <b>daughter</b>. While <i>serva</i> and <i>fīlia</i> refer to females, <i>puella</i> is the general term for 'girl'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>large</b>.", options: ["magnus", "multus", "bonus", "longus"], i: 0, explanation: "The correct Latin adjective for <b>large</b> is <i>magnus, magna, magnum</i>. Option B, <i>multus, multa, multum</i>, means <b>much</b> or <b>many</b>. Option C, <i>bonus, bona, bonum</i>, means <b>good</b>. Option D, <i>longus, longa, longum</i>, means <b>long</b>. All are first/second declension adjectives, but with different meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>to see</b>.", options: ["videō", "veniō", "vincō", "habeō"], i: 0, explanation: "The correct Latin verb for <b>to see</b> is <i>videō, vidēre</i> (2nd conjugation). Option B, <i>veniō, venīre</i> (4th conjugation), means <b>to come</b>. Option C, <i>vincō, vincere</i> (3rd conjugation), means <b>to conquer</b>. Option D, <i>habeō, habēre</i> (2nd conjugation), means <b>to have</b>. Options B and C are morphological false friends due to the initial 'v-' sound, but have distinct meanings and conjugations." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>city</b>.", options: ["urbs", "pāx", "rēx", "nox"], i: 0, explanation: "The correct Latin noun for <b>city</b> is <i>urbs, urbis</i> (f.). All options are third declension nouns ending in -x in the nominative. Option B, <i>pāx, pācis</i> (f.), means <b>peace</b>. Option C, <i>rēx, rēgis</i> (m.), means <b>king</b>. Option D, <i>nox, noctis</i> (f.), means <b>night</b>. These are all distinct in meaning." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>water</b>.", options: ["aqua", "terra", "silva", "unda"], i: 0, explanation: "The correct Latin noun for <b>water</b> is <i>aqua, aquae</i> (f.). All options are first declension nouns. Option B, <i>terra, terrae</i> (f.), means <b>land</b> or <b>earth</b>. Option C, <i>silva, silvae</i> (f.), means <b>forest</b> or <b>wood</b>. Option D, <i>unda, undae</i> (f.), means <b>wave</b>. While <i>unda</i> is related to water, it is not the general term for 'water'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>to love</b>.", options: ["amō", "laudō", "dō", "habeō"], i: 0, explanation: "The correct Latin verb for <b>to love</b> is <i>amō, amāre</i> (1st conjugation). Option B, <i>laudō, laudāre</i>, means <b>to praise</b>. Option C, <i>dō, dare</i>, means <b>to give</b>. Option D, <i>habeō, habēre</i> (2nd conjugation), means <b>to have</b>. Options B and C are also first conjugation verbs but have different meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>house</b>.", options: ["casa", "via", "taberna", "mensa"], i: 0, explanation: "The correct Latin noun for <b>house</b> (especially a simple dwelling) is <i>casa, casae</i> (f.). All options are first declension nouns. Option B, <i>via, viae</i> (f.), means <b>road</b> or <b>way</b>. Option C, <i>taberna, tabernae</i> (f.), means <b>shop</b> or <b>inn</b>. Option D, <i>mensa, mensae</i> (f.), means <b>table</b>. While <i>taberna</i> is a type of building, it is not a general 'house'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>good</b>.", options: ["bonus", "malus", "magnus", "novus"], i: 0, explanation: "The correct Latin adjective for <b>good</b> is <i>bonus, bona, bonum</i>. All options are first/second declension adjectives. Option B, <i>malus, mala, malum</i>, means <b>bad</b> (it is an antonym). Option C, <i>magnus, magna, magnum</i>, means <b>large</b>. Option D, <i>novus, nova, novum</i>, means <b>new</b>. These are all distinct in meaning." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>to say</b>.", options: ["dīcō", "dūcō", "scrībō", "legō"], i: 0, explanation: "The correct Latin verb for <b>to say</b> is <i>dīcō, dīcere</i> (3rd conjugation). Option B, <i>dūcō, dūcere</i> (3rd conjugation), means <b>to lead</b>; this is a common morphological false friend. Option C, <i>scrībō, scrībere</i>, means <b>to write</b>. Option D, <i>legō, legere</i>, means <b>to read</b>. Both C and D are related to communication but have different meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>peace</b>.", options: ["pāx", "lūx", "rēx", "vōx"], i: 0, explanation: "The correct Latin noun for <b>peace</b> is <i>pāx, pācis</i> (f.). All options are third declension nouns ending in -x in the nominative. Option B, <i>lūx, lūcis</i> (f.), means <b>light</b>. Option C, <i>rēx, rēgis</i> (m.), means <b>king</b>. Option D, <i>vōx, vōcis</i> (f.), means <b>voice</b>. These are all distinct in meaning and are common morphological false friends." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>friend</b>.", options: ["amīcus", "inimīcus", "servus", "puer"], i: 0, explanation: "The correct Latin noun for <b>friend</b> (masculine) is <i>amīcus, amīcī</i> (m.). All options are second declension masculine nouns. Option B, <i>inimīcus, inimīcī</i> (m.), means <b>enemy</b> (it is an antonym). Option C, <i>servus, servī</i> (m.), means <b>slave</b>. Option D, <i>puer, puerī</i> (m.), means <b>boy</b>. These are all distinct in meaning." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>to come</b>.", options: ["veniō", "videō", "vincō", "currō"], i: 0, explanation: "The correct Latin verb for <b>to come</b> is <i>veniō, venīre</i> (4th conjugation). Option B, <i>videō, vidēre</i> (2nd conjugation), means <b>to see</b>. Option C, <i>vincō, vincere</i> (3rd conjugation), means <b>to conquer</b>. Options B and C are morphological false friends due to the initial 'v-' sound, but have distinct meanings and conjugations. Option D, <i>currō, currere</i> (3rd conjugation), means <b>to run</b>, which is a related action but distinct from 'to come'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>war</b>.", options: ["bellum", "pāx", "arma", "perīculum"], i: 0, explanation: "The correct Latin noun for <b>war</b> is <i>bellum, bellī</i> (n.). Options A and D are second declension neuter nouns, while B is third declension feminine and C is a second declension neuter plural. Option B, <i>pāx, pācis</i> (f.), means <b>peace</b> (it is an antonym). Option C, <i>arma, armōrum</i> (n. pl.), means <b>arms</b> or <b>weapons</b>, which are used in war but are not 'war' itself. Option D, <i>perīculum, perīculī</i> (n.), means <b>danger</b>, which is often associated with war but is a distinct concept." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word <b>field</b>.", options: ["ager", "aqua", "silva", "via"], i: 0, explanation: "The correct Latin noun for <b>field</b> is <i>ager, agrī</i> (m.). All options are nouns referring to places or natural features. Option B, <i>aqua, aquae</i> (f.), means <b>water</b>. Option C, <i>silva, silvae</i> (f.), means <b>forest</b> or <b>wood</b>. Option D, <i>via, viae</i> (f.), means <b>road</b> or <b>way</b>. All distractors are first declension nouns, while <i>ager</i> is a second declension noun with an irregular nominative form." }, { meta: "Synonyms", stem: "dōnum", options: ["mūnus", "opus", "tempus", "nōmen"], i: 0, explanation: "The word <b>dōnum</b> means 'gift' or 'present'. Its closest synonym among the options is <b>mūnus</b>, which also means 'gift', 'present', or 'duty'. All options are 3rd declension neuter nouns. <b>Opus</b> means 'work' or 'task'. <b>Tempus</b> means 'time'. <b>Nōmen</b> means 'name'." }, { meta: "Synonyms", stem: "pugna", options: ["proelium", "bellum", "perīculum", "cōnsilium"], i: 0, explanation: "The word <b>pugna</b> means 'battle' or 'fight'. Its closest synonym is <b>proelium</b>, which also means 'battle' or 'engagement'. All options are 2nd declension neuter nouns. <b>Bellum</b> means 'war' (a broader conflict than a single battle). <b>Perīculum</b> means 'danger'. <b>Cōnsilium</b> means 'plan' or 'counsel'." }, { meta: "Synonyms", stem: "magnus", options: ["ingēns", "gravis", "celer", "fortis"], i: 0, explanation: "The word <b>magnus</b> means 'large', 'great', or 'important'. Its closest synonym among the options is <b>ingēns</b>, meaning 'huge', 'vast', or 'enormous'. All options are 3rd declension adjectives. <b>Gravis</b> means 'heavy' or 'serious'. <b>Celer</b> means 'swift' or 'quick'. <b>Fortis</b> means 'brave' or 'strong'." }, { meta: "Synonyms", stem: "ferō", options: ["portō", "vocō", "amō", "laudō"], i: 0, explanation: "The verb <b>ferō</b> means 'to carry', 'bear', or 'bring'. Its closest synonym is <b>portō</b>, which specifically means 'to carry'. All options are 1st conjugation verbs. <b>Vocō</b> means 'to call'. <b>Amō</b> means 'to love'. <b>Laudō</b> means 'to praise'." }, { meta: "Synonyms", stem: "veniō", options: ["appropinquō", "ambulō", "nāvigō", "parō"], i: 0, explanation: "The verb <b>veniō</b> means 'to come'. Its closest synonym among the options is <b>appropinquō</b>, meaning 'to approach' or 'to come near'. All options are 1st conjugation verbs. <b>Ambulō</b> means 'to walk'. <b>Nāvigō</b> means 'to sail'. <b>Parō</b> means 'to prepare'." }, { meta: "Synonyms", stem: "dīcō", options: ["nārrō", "rogō", "cōgitō", "stō"], i: 0, explanation: "The verb <b>dīcō</b> means 'to say' or 'to tell'. Its closest synonym is <b>nārrō</b>, meaning 'to tell' or 'to relate'. All options are 1st conjugation verbs. <b>Rogō</b> means 'to ask'. <b>Cōgitō</b> means 'to think'. <b>Stō</b> means 'to stand'." }, { meta: "Synonyms", stem: "oppidum", options: ["castrum", "templum", "forum", "perīculum"], i: 0, explanation: "The word <b>oppidum</b> means 'town' or 'fortified town/stronghold'. Its closest synonym among the options is <b>castrum</b>, which means 'fort' or 'fortress' (often plural <b>castra</b> for 'camp'). All options are 2nd declension neuter nouns. <b>Templum</b> means 'temple'. <b>Forum</b> means 'forum' or 'marketplace'. <b>Perīculum</b> means 'danger'." }, { meta: "Synonyms", stem: "timor", options: ["pavor", "honor", "labor", "dolor"], i: 0, explanation: "The word <b>timor</b> means 'fear' or 'dread'. Its closest synonym is <b>pavor</b>, meaning 'panic', 'terror', or 'dread'. All options are 3rd declension masculine nouns. <b>Honor</b> means 'honor'. <b>Labor</b> means 'labor' or 'toil'. <b>Dolor</b> means 'pain' or 'grief'." }, { meta: "Synonyms", stem: "inimīcus", options: ["hostis", "cīvis", "dux", "mīles"], i: 0, explanation: "The word <b>inimīcus</b> means 'personal enemy' or 'foe'. Its closest synonym is <b>hostis</b>, meaning 'public enemy' or 'foe'. Both refer to an adversary. All options are 3rd declension nouns. <b>Cīvis</b> means 'citizen'. <b>Dux</b> means 'leader'. <b>Mīles</b> means 'soldier'." }, { meta: "Synonyms", stem: "laetus", options: ["fēlīx", "fortis", "humilis", "omnis"], i: 0, explanation: "The adjective <b>laetus</b> means 'happy', 'joyful', or 'glad'. Its closest synonym among the options is <b>fēlīx</b>, meaning 'lucky', 'fortunate', or 'happy'. All options are 3rd declension adjectives. <b>Fortis</b> means 'brave' or 'strong'. <b>Humilis</b> means 'humble' or 'low'. <b>Omnis</b> means 'all' or 'every'." }, { meta: "Synonyms", stem: "currō", options: ["celerō", "ambulō", "stō", "nāvigō"], i: 0, explanation: "The verb <b>currō</b> means 'to run'. Its closest synonym among the options is <b>celerō</b>, meaning 'to hasten' or 'to speed up'. All options are 1st conjugation verbs. <b>Ambulō</b> means 'to walk'. <b>Stō</b> means 'to stand'. <b>Nāvigō</b> means 'to sail'." }, { meta: "Synonyms", stem: "pāx", options: ["tranquillitās", "virtūs", "salūs", "lūx"], i: 0, explanation: "The word <b>pāx</b> means 'peace'. Its closest synonym is <b>tranquillitās</b>, meaning 'tranquility' or 'calmness'. All options are 3rd declension feminine nouns. <b>Virtūs</b> means 'virtue' or 'courage'. <b>Salūs</b> means 'safety' or 'health'. <b>Lūx</b> means 'light'." }, { meta: "Synonyms", stem: "parvus", options: ["exiguus", "bonus", "longus", "lātus"], i: 0, explanation: "The adjective <b>parvus</b> means 'small' or 'little'. Its closest synonym is <b>exiguus</b>, meaning 'small', 'scanty', or 'meager'. All options are 1st/2nd declension adjectives. <b>Bonus</b> means 'good'. <b>Longus</b> means 'long'. <b>Lātus</b> means 'wide'." }, { meta: "Synonyms", stem: "semper", options: ["aeternē", "saepe", "nunc", "tum"], i: 0, explanation: "The adverb <b>semper</b> means 'always'. Its closest synonym is <b>aeternē</b>, meaning 'eternally' or 'forever'. All options are adverbs. <b>Saepe</b> means 'often'. <b>Nunc</b> means 'now'. <b>Tum</b> means 'then'." }, { meta: "Synonyms", stem: "habeō", options: ["teneō", "videō", "moveō", "moneō"], i: 0, explanation: "The verb <b>habeō</b> means 'to have' or 'to hold'. Its closest synonym is <b>teneō</b>, meaning 'to hold', 'to keep', or 'to grasp'. All options are 2nd conjugation verbs. <b>Videō</b> means 'to see'. <b>Moveō</b> means 'to move'. <b>Moneō</b> means 'to warn'." }, { meta: "Antonyms", stem: "bonus", options: ["magnus", "malus", "parvus", "multus"], i: 1, explanation: "The Latin adjective <i>bonus</i> means 'good'. Its direct antonym is <i>malus</i>, meaning 'bad'. <i>Magnus</i> means 'large', <i>parvus</i> means 'small', and <i>multus</i> means 'much' or 'many'; these are not antonyms of 'good'." }, { meta: "Antonyms", stem: "veniō", options: ["currō", "sedeō", "discēdō", "stō"], i: 2, explanation: "The Latin verb <i>veniō</i> means 'to come'. Its closest antonym, meaning 'to go away' or 'to depart', is <i>discēdō</i>. <i>Currō</i> means 'to run', <i>sedeō</i> means 'to sit', and <i>stō</i> means 'to stand'; none of these are direct antonyms of 'to come'." }, { meta: "Antonyms", stem: "longus", options: ["lātus", "altus", "brevis", "gravis"], i: 2, explanation: "The Latin adjective <i>longus</i> means 'long'. Its direct antonym is <i>brevis</i>, meaning 'short'. <i>Lātus</i> means 'wide', <i>altus</i> means 'high' or 'deep', and <i>gravis</i> means 'heavy' or 'serious'; these are not antonyms of 'long'." }, { meta: "Antonyms", stem: "nox", options: ["lūx", "sōl", "diēs", "aether"], i: 2, explanation: "The Latin noun <i>nox</i> means 'night'. Its direct antonym, meaning 'day', is <i>diēs</i>. <i>Lūx</i> means 'light', <i>sōl</i> means 'sun', and <i>aether</i> means 'upper air' or 'sky'; while related to the concept of day and night, they are not the direct opposite of 'night' in the same way 'day' is." }, { meta: "Antonyms", stem: "magnus", options: ["longus", "lātus", "parvus", "altus"], i: 2, explanation: "The Latin adjective <i>magnus</i> means 'large' or 'great'. Its direct antonym is <i>parvus</i>, meaning 'small'. <i>Longus</i> means 'long', <i>lātus</i> means 'wide', and <i>altus</i> means 'high' or 'deep'; these are not antonyms of 'large'." }, { meta: "Antonyms", stem: "rīdeō", options: ["cantō", "fleō", "dormiō", "scrībō"], i: 1, explanation: "The Latin verb <i>rīdeō</i> means 'to laugh'. Its direct antonym is <i>fleō</i>, meaning 'to weep' or 'to cry'. <i>Cantō</i> means 'to sing', <i>dormiō</i> means 'to sleep', and <i>scrībō</i> means 'to write'; these are not antonyms of 'to laugh'." }, { meta: "Antonyms", stem: "laetus", options: ["pulcher", "aeger", "trīstis", "fessus"], i: 2, explanation: "The Latin adjective <i>laetus</i> means 'happy' or 'joyful'. Its direct antonym is <i>trīstis</i>, meaning 'sad'. <i>Pulcher</i> means 'beautiful', <i>aeger</i> means 'sick', and <i>fessus</i> means 'tired'; these are not antonyms of 'happy'." }, { meta: "Antonyms", stem: "surgō", options: ["currō", "sedeō", "ambulō", "stō"], i: 1, explanation: "The Latin verb <i>surgō</i> means 'to rise' or 'to get up'. Its direct antonym is <i>sedeō</i>, meaning 'to sit'. <i>Currō</i> means 'to run', <i>ambulō</i> means 'to walk', and <i>stō</i> means 'to stand'; these are not antonyms of 'to rise'." }, { meta: "Antonyms", stem: "plēnus", options: ["magnus", "vacuus", "longus", "lātus"], i: 1, explanation: "The Latin adjective <i>plēnus</i> means 'full'. Its direct antonym is <i>vacuus</i>, meaning 'empty'. <i>Magnus</i> means 'large', <i>longus</i> means 'long', and <i>lātus</i> means 'wide'; these are not antonyms of 'full'." }, { meta: "Antonyms", stem: "bellum", options: ["hostis", "pāx", "perīculum", "fāma"], i: 1, explanation: "The Latin noun <i>bellum</i> means 'war'. Its direct antonym is <i>pāx</i>, meaning 'peace'. <i>Hostis</i> means 'enemy', <i>perīculum</i> means 'danger', and <i>fāma</i> means 'fame' or 'rumor'; these are not antonyms of 'war'." }, { meta: "Antonyms", stem: "fortis", options: ["gravis", "celer", "dēbilis", "trīstis"], i: 2, explanation: "The Latin adjective <i>fortis</i> means 'brave' or 'strong'. Its direct antonym is <i>dēbilis</i>, meaning 'weak'. <i>Gravis</i> means 'heavy' or 'serious', <i>celer</i> means 'swift', and <i>trīstis</i> means 'sad'; these are not antonyms of 'strong' or 'brave'." }, { meta: "Antonyms", stem: "doceō", options: ["scrībō", "discō", "legō", "audiō"], i: 1, explanation: "The Latin verb <i>doceō</i> means 'to teach'. Its direct antonym is <i>discō</i>, meaning 'to learn'. <i>Scrībō</i> means 'to write', <i>legō</i> means 'to read', and <i>audiō</i> means 'to hear'; these are not antonyms of 'to teach'." }, { meta: "Antonyms", stem: "prope", options: ["ibi", "nunc", "procul", "saepe"], i: 2, explanation: "The Latin adverb <i>prope</i> means 'near'. Its direct antonym is <i>procul</i>, meaning 'far away'. <i>Ibi</i> means 'there', <i>nunc</i> means 'now', and <i>saepe</i> means 'often'; these are not antonyms of 'near'." }, { meta: "Antonyms", stem: "semper", options: ["nunc", "numquam", "saepe", "tum"], i: 1, explanation: "The Latin adverb <i>semper</i> means 'always'. Its direct antonym is <i>numquam</i>, meaning 'never'. <i>Nunc</i> means 'now', <i>saepe</i> means 'often', and <i>tum</i> means 'then'; these are not antonyms of 'always'." }, { meta: "Antonyms", stem: "dīves", options: ["fēlīx", "gravis", "pauper", "senex"], i: 2, explanation: "The Latin adjective <i>dīves</i> means 'rich'. Its direct antonym is <i>pauper</i>, meaning 'poor'. <i>Fēlīx</i> means 'lucky' or 'happy', <i>gravis</i> means 'heavy' or 'serious', and <i>senex</i> means 'old'; these are not antonyms of 'rich'." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["servus", "equus", "dominus", "manus"], i: 3, explanation: "All four words end in '-us' in the nominative singular. However, <b>servus</b> (slave), <b>equus</b> (horse), and <b>dominus</b> (master) are all 2nd declension masculine nouns. <b>Manus</b> (hand) is a 4th declension feminine noun, making it the one that morphologically does not belong." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["aqua", "terra", "caelum", "via"], i: 3, explanation: "<b>Aqua</b> (water), <b>terra</b> (earth, land), and <b>caelum</b> (sky, heaven) are all fundamental natural elements or parts of the natural world. <b>Via</b> (road, way, street) refers to a man-made path or route, and thus does not fit the same semantic category as the others." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["puella", "terra", "nauta", "silva"], i: 2, explanation: "All four words are 1st declension nouns ending in '-a'. However, <b>puella</b> (girl), <b>terra</b> (earth, land), and <b>silva</b> (forest, woods) are all feminine nouns. <b>Nauta</b> (sailor) is a masculine noun, despite its 1st declension ending, making it the one that morphologically does not belong." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["magnus", "longus", "lātus", "bonus"], i: 3, explanation: "<b>Magnus</b> (large, great), <b>longus</b> (long), and <b>lātus</b> (wide, broad) are all adjectives that describe physical dimensions or size. <b>Bonus</b> (good) describes a general quality or moral attribute, making it semantically different from the others." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["amō", "parō", "portō", "videō"], i: 3, explanation: "All four words are verbs. <b>Amō</b> (to love), <b>parō</b> (to prepare), and <b>portō</b> (to carry) are all 1st conjugation verbs. <b>Videō</b> (to see) is a 2nd conjugation verb, making it the one that morphologically does not belong due to its different conjugation pattern." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["puer", "vir", "fīlius", "servus"], i: 3, explanation: "<b>Puer</b> (boy), <b>vir</b> (man), and <b>fīlius</b> (son) all refer to free male individuals, often in terms of age or familial relationship. <b>Servus</b> (slave) refers to a person's social status, which is distinct from the age or familial categories of the other words." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["puer", "ager", "vir", "bellum"], i: 3, explanation: "All four words are 2nd declension nouns. However, <b>puer</b> (boy), <b>ager</b> (field), and <b>vir</b> (man) are all masculine nouns. <b>Bellum</b> (war) is a neuter noun, making it the one that morphologically does not belong due to its gender." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["eō", "veniō", "currō", "sedeō"], i: 3, explanation: "<b>Eō</b> (to go), <b>veniō</b> (to come), and <b>currō</b> (to run) are all verbs of motion, indicating movement from one place to another. <b>Sedeō</b> (to sit) describes a state of being or position rather than active movement, making it semantically distinct." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["ad", "in", "dē", "cum"], i: 0, explanation: "All four words are common Latin prepositions. However, <b>ad</b> (to, toward) exclusively takes the accusative case. <b>In</b> (in, on, into, onto) can take either the accusative (with verbs of motion) or the ablative (with verbs of rest). <b>Dē</b> (down from, concerning) and <b>cum</b> (with) both exclusively take the ablative case. Therefore, <b>ad</b> is the only preposition that only governs the accusative case among these options, making it morphologically distinct in its case governance." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["nunc", "semper", "heri", "ibi"], i: 3, explanation: "<b>Nunc</b> (now), <b>semper</b> (always), and <b>heri</b> (yesterday) are all adverbs of time, indicating when an action occurs. <b>Ibi</b> (there) is an adverb of place, indicating where an action occurs, making it semantically different from the others." }, { meta: "Analogies", stem: "oculus : caput :: manus : X", options: ["dōnum", "membrum", "verbum", "bellum"], i: 1, explanation: "The relationship is 'part to whole'. An <i>oculus</i> (eye) is a part of the <i>caput</i> (head). A <i>manus</i> (hand) is a part of the <i>membrum</i> (limb). All options are neuter nouns of the second declension in the nominative singular, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "puer : īnfāns :: femina : X", options: ["cīvis", "mīles", "mulier", "pāstor"], i: 2, explanation: "The relationship is 'synonym'. <i>Puer</i> (boy) is a synonym for <i>īnfāns</i> (child). Similarly, <i>femina</i> (woman) is a synonym for <i>mulier</i> (woman). All options are nouns of the third declension in the nominative singular, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "eō : īre :: volō : X", options: ["posse", "nōlle", "velle", "ferre"], i: 2, explanation: "The relationship is 'first person singular present active indicative to present active infinitive' for irregular verbs. <i>Eō</i> (I go) corresponds to <i>īre</i> (to go). Thus, <i>volō</i> (I wish) corresponds to <i>velle</i> (to wish). All options are irregular present active infinitives, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "gladius : pugnō :: arātrum : X", options: ["labōrō", "portō", "arō", "vocō"], i: 2, explanation: "The relationship is 'tool to action'. A <i>gladius</i> (sword) is used to <i>pugnō</i> (fight). An <i>arātrum</i> (plow) is used to <i>arō</i> (plow). All options are first person singular present active indicative verbs of the first conjugation, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "magnus : parvus :: bonus : X", options: ["pulcher", "malus", "altus", "lātus"], i: 1, explanation: "The relationship is 'antonym'. <i>Magnus</i> (large) is the opposite of <i>parvus</i> (small). Similarly, <i>bonus</i> (good) is the opposite of <i>malus</i> (bad). All options are 2-1-2 declension adjectives in the nominative singular masculine, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "agricola : colō :: nauta : X", options: ["ambulō", "dō", "nāvigō", "stō"], i: 2, explanation: "The relationship is 'agent to action'. An <i>agricola</i> (farmer) <i>colit</i> (cultivates). A <i>nauta</i> (sailor) <i>nāvigat</i> (sails). All options are first person singular present active indicative verbs of the first conjugation, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "ager : agricola :: urbs : X", options: ["mīles", "cīvis", "pāstor", "dux"], i: 1, explanation: "The relationship is 'place to inhabitant'. An <i>ager</i> (field) is where an <i>agricola</i> (farmer) lives/works. An <i>urbs</i> (city) is where a <i>cīvis</i> (citizen) lives. All options are nouns of the third declension in the nominative singular, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "corpus : caput :: arbor : X", options: ["flōs", "frūx", "radīx", "vōx"], i: 2, explanation: "The relationship is 'whole to part'. A <i>caput</i> (head) is a part of the <i>corpus</i> (body). A <i>radīx</i> (root) is a part of an <i>arbor</i> (tree). All options are nouns of the third declension in the nominative singular, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "lūx : clārus :: nox : X", options: ["līber", "aeger", "obscūrus", "pulcher"], i: 2, explanation: "The relationship is 'noun to descriptive adjective'. <i>Lūx</i> (light) is <i>clārus</i> (bright). <i>Nox</i> (night) is <i>obscūrus</i> (dark). All options are 2-1-2 declension adjectives in the nominative singular masculine, matching the grammatical category of the correct answer." }, { meta: "Analogies", stem: "dīcō : dīcere :: faciō : X", options: ["capere", "fugere", "iacere", "facere"], i: 3, explanation: "The relationship is 'first person singular present active indicative to present active infinitive'. <i>Dīcō</i> (I say) corresponds to <i>dīcere</i> (to say). Thus, <i>faciō</i> (I make) corresponds to <i>facere</i> (to make). All options are present active infinitives of the third (-io) conjugation, matching the grammatical category of the correct answer." }, { meta: "Fill-in-the-Blank", stem: "Quod pedēs fessī erant, puer domum lentē ___ poterat.", options: ["scrībere", "ambulāre", "cantāre", "dormīre"], i: 1, explanation: "The sentence states that the boy's feet were tired (<i>pedēs fessī erant</i>). This context strongly implies difficulty in walking. Therefore, <i>ambulāre</i> (to walk) is the only logical choice. The distractors <i>scrībere</i> (to write), <i>cantāre</i> (to sing), and <i>dormīre</i> (to sleep) are all infinitives but make no semantic sense in the context of tired feet preventing movement." }, { meta: "Fill-in-the-Blank", stem: "Cum leōnem magnum in silvā vīdisset, puer valdē ___ coepit.", options: ["amāre", "rīdēre", "audīre", "timēre"], i: 3, explanation: "The clause 'When he had seen a large lion in the forest' (<i>Cum leōnem magnum in silvā vīdisset</i>) sets a context of danger or fright. Therefore, the boy would logically begin 'to fear' (<i>timēre</i>). The distractors <i>amāre</i> (to love), <i>rīdēre</i> (to laugh), and <i>audīre</i> (to hear) are all infinitives but are semantically absurd in this alarming situation." }, { meta: "Fill-in-the-Blank", stem: "Nāvis, quae mercātōribus et mercibus ___ erat, ad portum vēnit.", options: ["vacua", "plēna", "aegra", "parva"], i: 1, explanation: "The sentence describes a ship arriving at a harbor 'with merchants and goods' (<i>mercātōribus et mercibus</i>). A ship carrying such cargo would logically be 'full' (<i>plēna</i>). All options are nominative singular feminine adjectives, but <i>vacua</i> (empty), <i>aegra</i> (sick), and <i>parva</i> (small) are semantically illogical for a ship described as carrying merchants and goods." }, { meta: "Fill-in-the-Blank", stem: "In tenebrīs nūllum ___ vidēre poterāmus.", options: ["flūmen", "nōmen", "lūmen", "iter"], i: 2, explanation: "The phrase 'In the darkness' (<i>In tenebrīs</i>) provides the crucial context. In darkness, one cannot see 'light' (<i>lūmen</i>). All options are accusative singular neuter nouns of the third declension. However, one might see a <i>flūmen</i> (river), a <i>nōmen</i> (name), or perceive an <i>iter</i> (journey) if there were light, but the inability to see 'no light' is the direct consequence of darkness." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs, quod hostēs appropinquābant, ad castra ___ cucurrērunt.", options: ["lentē", "laetē", "celeriter", "saepe"], i: 2, explanation: "The clause 'because the enemies were approaching' (<i>quod hostēs appropinquābant</i>) indicates an urgent situation. Soldiers would therefore run 'quickly' (<i>celeriter</i>) to the camp. All options are adverbs, but <i>lentē</i> (slowly), <i>laetē</i> (happily), and <i>saepe</i> (often) are semantically inappropriate for an urgent retreat from approaching enemies." }, { meta: "Fill-in-the-Blank", stem: "Pāstor ovēs suās per silvam ad oppidum ___ volēbat.", options: ["vidēre", "audīre", "dūcere", "scrībere"], i: 2, explanation: "A shepherd's primary role with sheep, especially 'through the forest to the town' (<i>per silvam ad oppidum</i>), is 'to lead' them (<i>dūcere</i>). All options are present active infinitives. <i>Vidēre</i> (to see), <i>audīre</i> (to hear), and <i>scrībere</i> (to write) are illogical actions for a shepherd guiding his flock in this context." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī, ut novam vīllam in agrīs possent, multōs servōs labōrāre iussērunt.", options: ["dēstruere", "aedificāre", "vendere", "colere"], i: 1, explanation: "The purpose clause 'so that they could ___ a new villa in the fields' (<i>ut novam vīllam in agrīs possent</i>) clearly indicates the Romans' intention. To have a new villa, one must 'build' it (<i>aedificāre</i>). All options are present active infinitives. <i>Dēstruere</i> (to destroy), <i>vendere</i> (to sell), and <i>colere</i> (to cultivate/worship) are contrary to the goal of acquiring a new villa." }, { meta: "Fill-in-the-Blank", stem: "Hieme, quod nix in montibus erat, aqua in flūmine ___ semper erat.", options: ["calida", "alta", "frigida", "clāra"], i: 2, explanation: "The sentence establishes a winter setting where 'there was snow in the mountains' (<i>nix in montibus erat</i>). This context logically means the water in the river would always be 'cold' (<i>frigida</i>). All options are nominative singular feminine adjectives, agreeing with <i>aqua</i>. <i>Calida</i> (warm) is contradictory, while <i>alta</i> (deep) and <i>clāra</i> (clear) are not necessarily implied by the presence of snow." }, { meta: "Fill-in-the-Blank", stem: "Magister multōs ___ docēbat, ut Latīnam discere possent.", options: ["librōs", "equōs", "puerōs", "mūrōs"], i: 2, explanation: "The purpose clause 'so that they could learn Latin' (<i>ut Latīnam discere possent</i>) indicates that the teacher was instructing students. Therefore, the teacher was teaching 'boys' (<i>puerōs</i>). All options are accusative plural masculine nouns of the second declension. A teacher teaches people, not <i>librōs</i> (books), <i>equōs</i> (horses), or <i>mūrōs</i> (walls) in the context of learning Latin." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs Rōmānī parātī erant contra hostēs ferōcēs.", options: ["labōrāre", "dormīre", "cēnāre", "pugnāre"], i: 3, explanation: "The phrase 'ready against fierce enemies' (<i>parātī erant contra hostēs ferōcēs</i>) clearly indicates a military confrontation. Soldiers in this situation would be ready 'to fight' (<i>pugnāre</i>). All options are present active infinitives. <i>Labōrāre</i> (to work), <i>dormīre</i> (to sleep), and <i>cēnāre</i> (to dine) are semantically absurd actions for soldiers facing fierce enemies." }, { meta: "Circumlocution", stem: "Fēmina parva quae nōn est māter.", options: ["puella", "fēmina", "domina", "dea"], i: 0, explanation: "The Latin definition describes <b>puella</b>, meaning 'girl,' as a 'small woman who is not a mother.' <b>Fēmina</b> means 'woman' generally, <b>domina</b> means 'mistress' or 'lady,' and <b>dea</b> means 'goddess.' All options are 1st declension nouns, requiring semantic knowledge to distinguish." }, { meta: "Circumlocution", stem: "Magnō affectū aliquem tenēre.", options: ["amō", "laudō", "vocō", "dō"], i: 0, explanation: "The phrase 'Magnō affectū aliquem tenēre' translates to 'to hold someone with great affection,' which is the definition of <b>amō</b>, 'to love.' <b>Laudō</b> means 'to praise,' <b>vocō</b> means 'to call,' and <b>dō</b> means 'to give.' All are 1st conjugation verbs." }, { meta: "Circumlocution", stem: "Liquor clārus et frīgidus quem bibimus.", options: ["aqua", "terra", "silva", "via"], i: 0, explanation: "The definition 'A clear and cold liquid which we drink' perfectly describes <b>aqua</b>, meaning 'water.' <b>Terra</b> means 'land,' <b>silva</b> means 'forest,' and <b>via</b> means 'road.' All options are 1st declension nouns, but only 'aqua' fits the description of a drinkable liquid." }, { meta: "Circumlocution", stem: "Nōn parvus; multum spatium habēns.", options: ["magnus", "bonus", "malus", "parvus"], i: 0, explanation: "The description 'Not small; having much space' defines <b>magnus</b>, meaning 'large' or 'great.' <b>Bonus</b> means 'good,' <b>malus</b> means 'bad,' and <b>parvus</b> means 'small,' which is the antonym of the correct answer. All options are 1st/2nd declension adjectives." }, { meta: "Circumlocution", stem: "Locus ubi multī hominēs habitant et multa aedificia sunt.", options: ["urbs", "mōns", "flūmen", "nāvis"], i: 0, explanation: "The definition 'A place where many people live and there are many buildings' refers to an <b>urbs</b>, meaning 'city.' <b>Mōns</b> means 'mountain,' <b>flūmen</b> means 'river,' and <b>nāvis</b> means 'ship.' All options are 3rd declension nouns, requiring the student to understand the meaning of each to select the correct answer." }, { meta: "Circumlocution", stem: "Exsistere; vītam habēre.", options: ["sum", "stō", "sedeō", "veniō"], i: 0, explanation: "The definition 'To exist; to have life' is the core meaning of <b>sum</b>, 'to be.' <b>Stō</b> means 'to stand,' <b>sedeō</b> means 'to sit,' and <b>veniō</b> means 'to come.' All are common, basic verbs, but only 'sum' conveys existence." }, { meta: "Circumlocution", stem: "Vir parvus quī nōn est pater.", options: ["puer", "vir", "fīlius", "servus"], i: 0, explanation: "The definition 'A small man who is not a father' describes a <b>puer</b>, meaning 'boy.' <b>Vir</b> means 'man' (generally an adult), <b>fīlius</b> means 'son' (which a boy can be, but 'puer' focuses on age), and <b>servus</b> means 'slave.' All options are 2nd declension nouns referring to males." }, { meta: "Circumlocution", stem: "Litterās in tabulā vel librō facere.", options: ["scrībō", "legō", "dīcō", "audiō"], i: 0, explanation: "The phrase 'To make letters on a tablet or in a book' describes the act of <b>scrībō</b>, 'to write.' <b>Legō</b> means 'to read,' <b>dīcō</b> means 'to say' or 'to speak,' and <b>audiō</b> means 'to hear.' All are common verbs related to communication, but only 'scrībō' involves forming letters." }, { meta: "Circumlocution", stem: "Spatium diērum, mēnsium, annōrum.", options: ["tempus", "corpus", "nōmen", "iter"], i: 0, explanation: "The definition 'The space of days, months, years' refers to <b>tempus</b>, meaning 'time.' <b>Corpus</b> means 'body,' <b>nōmen</b> means 'name,' and <b>iter</b> means 'journey' or 'path.' All options are 3rd declension neuter nouns, ensuring a rigorous choice based on meaning." }, { meta: "Circumlocution", stem: "Ad locum ubi nunc sumus mōtū īre.", options: ["veniō", "eō", "currō", "stō"], i: 0, explanation: "The definition 'To go by movement to the place where we are now' specifically describes <b>veniō</b>, 'to come' (i.e., to the speaker's location). <b>Eō</b> means 'to go' (generally away from the speaker), <b>currō</b> means 'to run,' and <b>stō</b> means 'to stand.' All are basic verbs of motion or position." }];

const LEVEL_TWO = [{ meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>agō, agere, ēgī, āctus</b>", options: ["to drive, do, act", "to be sick", "to plow a field", "to be eager"], i: 0, explanation: "The verb <b>agō</b> means 'to drive, do, act'. Option B is related to <b>aeger</b> (sick) or <b>aegrōtō</b> (to be sick). Option C relates to <b>ager</b> (field). Option D is a distractor based on sound." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>arbitror, arbitrārī, arbitrātus sum</b>", options: ["to judge, think", "to plant a tree", "to decide a case", "to be an arbiter"], i: 0, explanation: "The deponent verb <b>arbitror</b> means 'to judge, think'. Option B relates to <b>arbor</b> (tree). Option C refers to a related noun <b>arbitrium</b> (judgment, decision). Option D is for <b>arbitrātor</b> (umpire, judge)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>cōnor, cōnārī, cōnātus sum</b>", options: ["to try, attempt", "to plan, advise", "to sound a horn", "to consult"], i: 0, explanation: "The deponent verb <b>cōnor</b> means 'to try, attempt'. Option B relates to <b>cōnsilium</b> (plan, counsel). Option C relates to <b>cornū</b> (horn). Option D relates to <b>cōnsulō</b> (to consult)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>dēbeō, dēbēre, dēbuī, dēbitus</b>", options: ["to owe, ought", "to destroy", "to send down", "to defend"], i: 0, explanation: "The verb <b>dēbeō</b> means 'to owe, ought'. Option B is <b>dēleō</b>. Option C is <b>dēmittō</b>. Option D is <b>dēfendō</b>. These are visually similar verbs." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>discēdō, discēdere, discessī, discessūrus</b>", options: ["to depart, go away", "to learn", "to say, speak", "to descend"], i: 0, explanation: "The verb <b>discēdō</b> means 'to depart, go away'. Option B is <b>discō</b>. Option C is <b>dīcō</b>. Option D is <b>dēscendō</b>. These are common verbs with similar prefixes or roots." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>ferō, ferre, tulī, lātus</b>", options: ["to bear, carry, bring, endure", "to be wild", "to strike with iron", "to finish"], i: 0, explanation: "The irregular verb <b>ferō</b> means 'to bear, carry, bring, endure'. Option B relates to <b>ferus</b> (wild). Option C relates to <b>ferrum</b> (iron). Option D relates to <b>fīniō</b> (to finish) or <b>fīnis</b> (end)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>hortor, hortārī, hortātus sum</b>", options: ["to urge, encourage", "to cultivate a garden", "to shudder, dread", "to begin"], i: 0, explanation: "The deponent verb <b>hortor</b> means 'to urge, encourage'. Option B relates to <b>hortus</b> (garden). Option C relates to <b>horror</b> (shudder, dread). Option D is <b>ordior</b>, another deponent verb." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>iter, itineris</b> n.", options: ["journey, march, route", "the same", "to go", "between"], i: 0, explanation: "The irregular noun <b>iter</b> means 'journey, march, route'. Option B is the pronoun <b>īdem</b>. Option C is the infinitive <b>īre</b> (from <b>eō</b>). Option D is the preposition <b>inter</b>. All are visually similar." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>loquor, loquī, locūtus sum</b>", options: ["to speak, talk", "to place, locate", "to flow, be liquid", "to shine"], i: 0, explanation: "The deponent verb <b>loquor</b> means 'to speak, talk'. Option B relates to <b>locus</b> (place) or <b>locō</b> (to place). Option C relates to <b>liquor</b> (liquid) or <b>liqueō</b> (to be liquid). Option D relates to <b>lūceō</b> (to shine) or <b>lūx</b> (light)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>mīror, mīrārī, mīrātus sum</b>", options: ["to wonder at, admire", "to be wonderful", "to be a soldier", "to delay"], i: 0, explanation: "The deponent verb <b>mīror</b> means 'to wonder at, admire'. Option B relates to <b>mīrus</b> (wonderful). Option C relates to <b>mīles</b> (soldier). Option D is <b>moror</b>, another deponent verb." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>moror, morārī, morātus sum</b>", options: ["to delay", "to die", "to establish a custom", "to wonder at"], i: 0, explanation: "The deponent verb <b>moror</b> means 'to delay'. Option B relates to <b>mors</b> (death) or <b>morior</b> (to die). Option C relates to <b>mōs</b> (custom). Option D is <b>mīror</b>, another deponent verb." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>patior, patī, passus sum</b>", options: ["to suffer, endure, allow", "to be a father", "to prepare", "to obey"], i: 0, explanation: "The deponent verb <b>patior</b> means 'to suffer, endure, allow'. Option B relates to <b>pater</b> (father). Option C is <b>parō</b>. Option D is <b>pāreō</b>. These are visually similar verbs or nouns." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>proficīscor, proficīscī, profectus sum</b>", options: ["to set out, depart", "to advance, accomplish", "to be deep, profound", "to promise"], i: 0, explanation: "The deponent verb <b>proficīscor</b> means 'to set out, depart'. Option B is <b>proficiō</b>. Option C relates to <b>profundus</b> (deep, profound). Option D is <b>prōmittō</b>. These are verbs with similar prefixes or roots." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>sequor, sequī, secūtus sum</b>", options: ["to follow", "to be six", "to be second, favorable", "to be thus"], i: 0, explanation: "The deponent verb <b>sequor</b> means 'to follow'. Option B relates to <b>sex</b> (six). Option C relates to <b>secundus</b> (second, favorable). Option D relates to <b>sīc</b> (thus, so). These are visually similar words." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>ūtor, ūtī, ūsus sum</b> (+ abl.)", options: ["to use, employ", "to be one", "to come from all sides", "to be any"], i: 0, explanation: "The deponent verb <b>ūtor</b> means 'to use, employ' and takes the ablative case. Option B relates to <b>ūnus</b> (one). Option C relates to <b>ūndique</b> (from all sides). Option D relates to <b>ūllus</b> (any). These are visually similar words." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To use</b>", options: ["ūtī, ūtor, ūsus sum", "ūtor, ūterī, ūtus sum", "habēre, habeō, habuī, habitum", "fungor, fungī, fūnctus sum"], i: 0, explanation: "The correct answer is <b>A. ūtī, ūtor, ūsus sum</b>. This is a deponent verb meaning 'to use' and it typically takes the ablative case. Option B has incorrect principal parts. Option C, <i>habēre</i>, means 'to have' or 'to hold'. Option D, <i>fungor</i>, also means 'to perform' or 'to discharge' and takes the ablative, but <i>ūtī</i> is the more general and common translation for 'to use'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To seem</b>", options: ["vidēre, videō, vīdī, vīsum", "appārēre, appāreō, appāruī, appāritum", "vidērī, videor, vīsus sum", "simulāre, simulō, simulāvī, simulātum"], i: 2, explanation: "The correct answer is <b>C. vidērī, videor, vīsus sum</b>. This is the passive form of <i>videō</i> ('to see') and is commonly used impersonally to mean 'to seem' or 'it seems', often with a dative of person and an infinitive. Option A, <i>vidēre</i>, means 'to see'. Option B, <i>appārēre</i>, means 'to appear' or 'to be visible'. Option D, <i>simulāre</i>, means 'to pretend' or 'to feign'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Courage</b>", options: ["fortitūdō, fortitūdinis, f.", "animus, animī, m.", "virtūs, virtūtis, f.", "audācia, audāciae, f."], i: 2, explanation: "The correct answer is <b>C. virtūs, virtūtis, f.</b> While <i>fortitūdō</i> (Option A) specifically means 'bravery' or 'fortitude' (often physical), and <i>animus</i> (Option B) can mean 'spirit' or 'courage', <i>virtūs</i> (manliness, excellence, virtue) is a broader term that frequently encompasses 'courage' in a general sense, especially moral courage or excellence. Option D, <i>audācia</i>, means 'boldness' or 'daring', often with a negative connotation." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Journey / March</b>", options: ["via, viae, f.", "iter, itineris, n.", "cursus, cursūs, m.", "profectiō, profectiōnis, f."], i: 1, explanation: "The correct answer is <b>B. iter, itineris, n.</b> This is an irregular third declension noun specifically meaning 'a journey' or 'a march'. Option A, <i>via</i>, means 'road' or 'way'. Option C, <i>cursus</i>, means 'running' or 'course'. Option D, <i>profectiō</i>, means 'departure'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To suffer / endure</b>", options: ["ferō, ferre, tulī, lātum", "sustineō, sustinēre, sustinuī, sustentum", "doleō, dolēre, doluī, dolitūrum", "patior, patī, passus sum"], i: 3, explanation: "The correct answer is <b>D. patior, patī, passus sum</b>. This is a deponent verb meaning 'to suffer' or 'to endure' in a passive sense. Option A, <i>ferō</i>, is an irregular verb meaning 'to bear', 'to carry', or 'to endure' (often implying carrying a burden). Option B, <i>sustineō</i>, means 'to hold up', 'to sustain', or 'to endure' (implying active support). Option C, <i>doleō</i>, means 'to grieve' or 'to suffer pain'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To remember</b>", options: ["recordor, recordārī, recordātus sum", "cōgitō, cōgitāre, cōgitāvī, cōgitātum", "meminī, meminisse", "retineō, retinēre, retinuī, retentum"], i: 2, explanation: "The correct answer is <b>C. meminī, meminisse</b>. This is a defective verb, meaning it only exists in the perfect system but has a present meaning ('I remember'). It can take either the genitive or accusative case. Option A, <i>recordor</i>, is a deponent verb meaning 'to recall' or 'to recollect'. Option B, <i>cōgitō</i>, means 'to think' or 'to consider'. Option D, <i>retineō</i>, means 'to hold back' or 'to retain'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To besiege</b>", options: ["oppugnō, oppugnāre, oppugnāvī, oppugnātum", "circumdō, circumdare, circumdedī, circumdatum", "obsīdeō, obsidēre, obsēdī, obsessum", "expugnō, expugnāre, expugnāvī, expugnātum"], i: 2, explanation: "The correct answer is <b>C. obsīdeō, obsidēre, obsēdī, obsessum</b>. This verb specifically means 'to besiege' or 'to blockade'. Option A, <i>oppugnō</i>, means 'to attack' or 'to assault'. Option B, <i>circumdō</i>, means 'to surround' or 'to encircle'. Option D, <i>expugnō</i>, means 'to take by storm' or 'to capture'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Bridge</b>", options: ["pōns, pontis, m.", "arcus, arcūs, m.", "via, viae, f.", "agger, aggeris, m."], i: 0, explanation: "The correct answer is <b>A. pōns, pontis, m.</b> This is a third declension noun meaning 'bridge'. It is masculine, which can be tricky for some learners. Option B, <i>arcus</i>, means 'arch' or 'bow'. Option C, <i>via</i>, means 'road' or 'way'. Option D, <i>agger</i>, means 'mound' or 'rampart', often used in military contexts." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To try / attempt</b>", options: ["temptō, temptāre, temptāvī, temptātum", "experior, experīrī, expertus sum", "cōnor, cōnārī, cōnātus sum", "studeō, studēre, studuī"], i: 2, explanation: "The correct answer is <b>C. cōnor, cōnārī, cōnātus sum</b>. This is a deponent verb commonly used to mean 'to try' or 'to attempt' (to make an effort). Option A, <i>temptō</i>, means 'to test' or 'to try', often with a sense of 'testing the waters' or 'tempting'. Option B, <i>experior</i>, is a deponent verb meaning 'to test', 'to try', or 'to experience'. Option D, <i>studeō</i>, means 'to be eager', 'to strive for', or 'to study' and takes the dative case." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Each / Every</b>", options: ["omnis, omne", "ūnusquisque, ūnaquaeque, ūnumquodque", "quisque, quaeque, quodque", "singulī, -ae, -a"], i: 2, explanation: "The correct answer is <b>C. quisque, quaeque, quodque</b>. This indefinite adjective/pronoun means 'each' or 'every' and is often used with superlatives or ordinals, typically placed after the word it modifies. Option A, <i>omnis</i>, means 'all' or 'every', but usually in the plural for 'every'. Option B, <i>ūnusquisque</i>, is a more emphatic form meaning 'each one'. Option D, <i>singulī</i>, is a distributive numeral meaning 'one by one' or 'individual'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To trust / rely on</b>", options: ["crēdō, crēdere, crēdidī, crēditum", "fīdō, fīdere, fīsus sum", "cōnfīdō, cōnfīdere, cōnfīsus sum", "nītī, nītor, nīxus sum / nīsus sum"], i: 2, explanation: "The correct answer is <b>C. cōnfīdō, cōnfīdere, cōnfīsus sum</b>. This is a semi-deponent verb meaning 'to trust' or 'to rely on', and it takes the dative or ablative case. Option A, <i>crēdō</i>, means 'to believe' or 'to trust' (in someone's word), and takes the dative. Option B, <i>fīdō</i>, is also semi-deponent and means 'to trust' or 'to rely on', but <i>cōnfīdō</i> is often stronger for 'rely on'. Option D, <i>nītī</i>, is a deponent verb meaning 'to lean on', 'to strive', or 'to rely on', and takes the ablative, but <i>cōnfīdō</i> is more direct for 'trust/rely on' in a personal sense." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Wall (of a city)</b>", options: ["moenia, moenium, n. pl.", "pariēs, parietis, m.", "mūrus, mūrī, m.", "vallum, vallī, n."], i: 2, explanation: "The correct answer is <b>C. mūrus, mūrī, m.</b> This refers to a single wall, often specifically a city wall. Option A, <i>moenia</i>, is a plural-only noun referring to 'city walls' or 'fortifications' in general. Option B, <i>pariēs</i>, refers to the 'wall of a house' or a room. Option D, <i>vallum</i>, means 'rampart' or 'palisade', typically part of a military camp's defenses." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To set out / depart</b>", options: ["discēdō, discēdere, discessī, discessum", "eō, īre, iī/īvī, itum", "proficīscor, proficīscī, profectus sum", "abeō, abīre, abiī/abīvī, abitum"], i: 2, explanation: "The correct answer is <b>C. proficīscor, proficīscī, profectus sum</b>. This is a deponent verb specifically meaning 'to set out' or 'to depart' on a journey or march, and is very common in Caesar. Option A, <i>discēdō</i>, means 'to depart' or 'to go away' in a more general sense. Option B, <i>eō</i>, is the irregular verb 'to go'. Option D, <i>abeō</i>, means 'to go away' or 'to depart', similar to <i>discēdō</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>Dignity / Prestige</b>", options: ["honōs, honōris, m.", "auctōritās, auctōritātis, f.", "glōria, glōriae, f.", "dignitās, dignitātis, f."], i: 3, explanation: "The correct answer is <b>D. dignitās, dignitātis, f.</b> This noun refers to 'dignity', 'rank', or 'prestige' based on inherent worth or position. Option A, <i>honōs</i>, means 'honor' or 'public office'. Option B, <i>auctōritās</i>, means 'authority', 'influence', or 'prestige' derived from one's position or reputation. Option C, <i>glōria</i>, means 'glory' or 'fame'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>To obtain / acquire</b>", options: ["consequor, consequī, consecūtus sum", "potior, potīrī, potītus sum", "comparō, comparāre, comparāvī, comparātum", "adipīscor, adipīscī, adeptus sum"], i: 3, explanation: "The correct answer is <b>D. adipīscor, adipīscī, adeptus sum</b>. This deponent verb means 'to reach', 'to attain', or 'to obtain' something. Option A, <i>consequor</i>, is a deponent verb meaning 'to follow up', 'to overtake', or 'to obtain' (often implying following to get). Option B, <i>potior</i>, is a deponent verb meaning 'to get possession of' or 'to obtain', and it takes the ablative or genitive case. Option C, <i>comparō</i>, means 'to prepare', 'to acquire', or 'to procure', often implying effort in getting." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>iter</b>?", options: ["spatium", "via", "profectiō", "cursus"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Iter</i> et <i>via</i> ambo significant 'iter' vel 'viam.' Quamquam <i>spatium</i> 'spatium' vel 'distantiam' significat, et <i>profectiō</i> 'discessum,' et <i>cursus</i> 'cursum' vel 'cursum,' <i>via</i> est proximum synonymum pro itinere vel via physicā." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cōnor</b>?", options: ["labōrō", "temptō", "studeō", "petō"], i: 1, explanation: "Responsum rectum est <b>B</b>. Verbum dēpōnēns <i>cōnor</i> significat 'cōnārī' vel 'temptāre.' <i>Temptō</i> est directum synonymum. <i>Labōrō</i> significat 'labōrāre,' <i>studeō</i> 'studēre' vel 'cupere,' et <i>petō</i> 'petere' vel 'quaerere,' quae sunt affinia sed nōn eadem." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>proficīscor</b>?", options: ["veniō", "discedō", "aggredior", "perveniō"], i: 1, explanation: "Responsum rectum est <b>B</b>. Verbum dēpōnēns <i>proficīscor</i> significat 'profectīscī' vel 'discedere.' <i>Discedō</i> est proximum synonymum. <i>Veniō</i> significat 'venīre,' <i>aggredior</i> 'aggredī,' et <i>perveniō</i> 'pervenīre,' quae contrāria vel aliās actionēs significant." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>hortor</b>?", options: ["vetō", "incitō", "moneō", "iubeō"], i: 1, explanation: "Responsum rectum est <b>B</b>. Verbum dēpōnēns <i>hortor</i> significat 'hortārī' vel 'incitāre.' <i>Incitō</i> est proximum synonymum. <i>Vetō</i> significat 'vetāre' (contrārium), <i>moneō</i> 'monēre' (minus urgēns), et <i>iubeō</i> 'iubēre' (cum auctōritāte)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>pauper</b>?", options: ["dīves", "egēns", "miser", "humilis"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Pauper</i> significat 'pauper' vel 'egēns.' <i>Egēns</i> est proximum synonymum, significāns 'egēns' vel 'indigens.' <i>Dīves</i> est contrārium ('dīves'), <i>miser</i> 'miser' vel 'īnfēlīx,' et <i>humilis</i> 'humilis' vel 'īnfīmus,' quae aliās qualitates significant." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>proelium</b>?", options: ["bellum", "pugna", "cōnsilium", "victōria"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Proelium</i> significat 'proelium' vel 'pugnam.' <i>Pugna</i> est proximum synonymum. <i>Bellum</i> est conceptus lātior ('bellum'), <i>cōnsilium</i> 'cōnsilium' vel 'stratēgia,' et <i>victōria</i> 'victōria' (exitus proeliī)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>timor</b>?", options: ["audācia", "metus", "spēs", "gaudium"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Timor</i> significat 'timor' vel 'metus.' <i>Metus</i> est proximum synonymum. <i>Audācia</i> est contrārium ('audācia'), <i>spēs</i> 'spēs,' et <i>gaudium</i> 'gaudium,' quae aliōs affectūs significant." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>vīcīnus</b>?", options: ["longē", "propinquus", "extrāneus", "medius"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Vīcīnus</i> significat 'vīcīnus' vel 'propinquus.' <i>Propinquus</i> est proximum synonymum. <i>Longē</i> est adverbium contrārium ('procul'), <i>extrāneus</i> 'extrāneus' vel 'aliēnus,' et <i>medius</i> 'medius' vel 'in mediō,' quae aliās ratiōnēs spatiālēs significant." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>oppugnō</b>?", options: ["dēfendō", "adorior", "cēdō", "expugnō"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Oppugnō</i> significat 'oppugnāre' vel 'adorīrī.' Verbum dēpōnēns <i>adorior</i> est proximum synonymum. <i>Dēfendō</i> est contrārium ('dēfendere'), <i>cēdō</i> 'cēdere' vel 'recēdere,' et <i>expugnō</i> 'expugnāre' (quod successum implicat, nōn sōlum actum oppugnandī)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cōgō</b>?", options: ["solvō", "compellō", "hortor", "permittō"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Cōgō</i> significat 'cōgere' vel 'compellere.' <i>Compellō</i> est proximum synonymum. <i>Solvō</i> est contrārium ('solvere' vel 'laxāre'), <i>hortor</i> 'hortārī' (minus coactīvum), et <i>permittō</i> 'permittere' (contrārium cōgendi)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>fīnis</b>?", options: ["initium", "terminus", "spatium", "locus"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Fīnis</i> (masc.) significat 'fīnis' vel 'terminus.' <i>Terminus</i> est proximum synonymum. <i>Initium</i> est contrārium ('initium'), <i>spatium</i> 'spatium' vel 'intervallum,' et <i>locus</i> 'locus' vel 'situs,' quae sunt affinia sed nōn eadem." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>mīles</b>?", options: ["cīvis", "bellātor", "hostis", "dux"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Mīles</i> significat 'mīles' vel 'bellātor.' <i>Bellātor</i> est proximum synonymum. <i>Cīvis</i> est 'cīvis,' <i>hostis</i> 'hostis' (contrārium), et <i>dux</i> 'dux' vel 'imperātor' (genus mīlitis specificum)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>virtūs</b>?", options: ["ignāvia", "fortitūdō", "prūdentia", "dēfēnsiō"], i: 1, explanation: "Responsum rectum est <b>B</b>. <i>Virtūs</i>, praesertim in contextū mīlitārī, significat 'virtūs' vel 'fortitūdō.' <i>Fortitūdō</i> est proximum synonymum. <i>Ignāvia</i> est contrārium ('ignāvia'), <i>prūdentia</i> 'prūdentia' (alia virtūs), et <i>dēfēnsiō</i> 'dēfēnsiō' (actio, nōn qualitas)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>sequor</b>?", options: ["praecēdō", "īnsector", "fugō", "stō"], i: 1, explanation: "Responsum rectum est <b>B</b>. Verbum dēpōnēns <i>sequor</i> significat 'sequī' vel 'īnsectārī.' Verbum dēpōnēns <i>īnsector</i> est proximum synonymum, praesertim cum significat 'persequī.' <i>Praecēdō</i> est contrārium ('praecēdere'), <i>fugō</i> 'fugāre' (agere ut fugiant), et <i>stō</i> 'stāre' (contrārium movendī)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>loquor</b>?", options: ["taceō", "fābulor", "audiō", "scrībō"], i: 1, explanation: "Responsum rectum est <b>B</b>. Verbum dēpōnēns <i>loquor</i> significat 'loquī' vel 'fābulārī.' Verbum dēpōnēns <i>fābulor</i> est proximum synonymum, praesertim significāns 'sermōnem habēre.' <i>Taceō</i> est contrārium ('tacēre'), <i>audiō</i> 'audīre,' et <i>scrībō</i> 'scrībere' (alius modus communicandī)." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>hostī</b>?", options: ["cīvis", "socius", "amīcus", "servus"], i: 2, explanation: "The correct answer is C. <b>Amīcus</b> (friend) is the direct opposite of <b>hostis</b> (enemy). A. <b>Cīvis</b> means 'citizen', which describes a person's legal status, not their relationship as an adversary. B. <b>Socius</b> means 'ally' or 'companion', which is a close relationship, but <b>amīcus</b> is the more fundamental antonym for <b>hostis</b>. D. <b>Servus</b> means 'slave', which denotes a social status and is not an antonym for 'enemy'." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbio <b>prope</b>?", options: ["longē", "ubīque", "procul", "hīc"], i: 2, explanation: "The correct answer is C. <b>Procul</b> means 'far off' or 'at a distance', which is the direct antonym of <b>prope</b> (near). A. <b>Longē</b> also means 'far', and is a close synonym of <b>procul</b>, but <b>procul</b> is often specifically paired with <b>prope</b> in Latin. B. <b>Ubīque</b> means 'everywhere'. D. <b>Hīc</b> means 'here'. Neither B nor D convey the opposite sense of proximity." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbio <b>celeriter</b>?", options: ["saepe", "lentē", "facile", "difficiliter"], i: 1, explanation: "The correct answer is B. <b>Lentē</b> means 'slowly', which is the direct opposite of <b>celeriter</b> (quickly). A. <b>Saepe</b> means 'often', referring to frequency, not speed. C. <b>Facile</b> means 'easily'. D. <b>Difficiliter</b> means 'with difficulty'. Both C and D refer to the manner of an action, not its speed." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbio <b>saepe</b>?", options: ["semper", "numquam", "rārō", "cotīdiē"], i: 2, explanation: "The correct answer is C. <b>Rārō</b> means 'rarely' or 'seldom', which is the direct antonym of <b>saepe</b> (often). A. <b>Semper</b> means 'always', and B. <b>Numquam</b> means 'never'; these are extremes of frequency, but <b>rārō</b> is the most appropriate opposite for 'often'. D. <b>Cotīdiē</b> means 'daily', referring to a specific regular frequency." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>incipiō</b>?", options: ["perficiō", "dēsinō", "continuō", "sequor"], i: 1, explanation: "The correct answer is B. <b>Dēsinō</b> means 'to cease' or 'to stop', which is the direct antonym of <b>incipiō</b> (to begin). A. <b>Perficiō</b> means 'to complete' or 'to finish', which is related to stopping but <b>dēsinō</b> more directly conveys the cessation of an action. C. <b>Continuō</b> means 'to continue'. D. <b>Sequor</b> means 'to follow'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>vīvō</b>?", options: ["dormiō", "morior", "aegrōtō", "labōrō"], i: 1, explanation: "The correct answer is B. <b>Morior</b> (to die) is the direct antonym of <b>vīvō</b> (to live). A. <b>Dormiō</b> means 'to sleep', which is a state of rest, not death. C. <b>Aegrōtō</b> means 'to be sick'. D. <b>Labōrō</b> means 'to work'. None of these are direct opposites of 'to live'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>summō</b>?", options: ["medius", "īmus", "magnus", "parvus"], i: 1, explanation: "The correct answer is B. <b>Īmus</b> (lowest, bottom-most) is the direct antonym of <b>summus</b> (highest, top-most). A. <b>Medius</b> means 'middle'. C. <b>Magnus</b> means 'great' or 'large'. D. <b>Parvus</b> means 'small'. These describe size or position, but not the extreme opposite of 'highest'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>accipiō</b>?", options: ["capiō", "dō", "retineō", "petō"], i: 1, explanation: "The correct answer is B. <b>Dō</b> (to give) is the direct antonym of <b>accipiō</b> (to receive). A. <b>Capiō</b> means 'to take' or 'to seize', which is related to receiving but not its opposite. C. <b>Retineō</b> means 'to hold back' or 'to keep'. D. <b>Petō</b> means 'to seek' or 'to ask for'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>fortī</b>?", options: ["debilis", "audāx", "timidus", "sapiēns"], i: 2, explanation: "The correct answer is C. <b>Timidus</b> (fearful, timid) is the direct antonym of <b>fortis</b> (brave, strong). A. <b>Debilis</b> means 'weak', which is an antonym for 'strong' but <b>fortis</b> also carries the meaning of 'brave'. B. <b>Audāx</b> means 'bold' or 'daring', which is a near synonym for 'brave'. D. <b>Sapiēns</b> means 'wise', which is unrelated." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbio <b>ante</b>?", options: ["prīmum", "nunc", "post", "tum"], i: 2, explanation: "The correct answer is C. <b>Post</b> (after) is the direct antonym of <b>ante</b> (before). A. <b>Prīmum</b> means 'first'. B. <b>Nunc</b> means 'now'. D. <b>Tum</b> means 'then'. These are temporal adverbs but not direct opposites of 'before'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>paucīs</b>?", options: ["omnēs", "singulī", "multī", "nūllī"], i: 2, explanation: "The correct answer is C. <b>Multī</b> (many) is the direct antonym of <b>paucī</b> (few). A. <b>Omnēs</b> means 'all', which is an extreme, but <b>multī</b> is a more direct opposite of 'few'. B. <b>Singulī</b> means 'one by one' or 'individual'. D. <b>Nūllī</b> means 'no' or 'none', which is an absolute negation." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>veniō</b>?", options: ["maneō", "discēdō", "redeō", "currō"], i: 1, explanation: "The correct answer is B. <b>Discēdō</b> (to depart, go away) is the direct antonym of <b>veniō</b> (to come). A. <b>Maneō</b> means 'to remain' or 'to stay', which is the opposite of going, but <b>discēdō</b> is a more active opposite of 'coming'. C. <b>Redeō</b> means 'to return', which implies both coming and going. D. <b>Currō</b> means 'to run', which describes a manner of movement, not its direction relative to a point." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>laudō</b>?", options: ["accusō", "vituperō", "dēfendō", "hortor"], i: 1, explanation: "The correct answer is B. <b>Vituperō</b> (to blame, to censure) is the direct antonym of <b>laudō</b> (to praise). A. <b>Accusō</b> means 'to accuse', which is related to blaming but <b>vituperō</b> more directly expresses the opposite of praise. C. <b>Dēfendō</b> means 'to defend', which is the opposite of accusing. D. <b>Hortor</b> means 'to encourage'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>surgō</b>?", options: ["dormiō", "stō", "sedeō", "iaceō"], i: 2, explanation: "The correct answer is C. <b>Sedeō</b> (to sit) is the direct antonym of <b>surgō</b> (to rise, to get up). A. <b>Dormiō</b> means 'to sleep'. B. <b>Stō</b> means 'to stand', which is a posture, not the opposite action of rising. D. <b>Iaceō</b> means 'to lie down', which is an opposite posture, but <b>sedeō</b> is the most common and direct opposite action to 'getting up'." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>lūcī</b>?", options: ["umbra", "sōl", "tenebrae", "ignis"], i: 2, explanation: "The correct answer is C. <b>Tenebrae</b> (darkness, shadows, gloom - plural) is the direct antonym of <b>lūx</b> (light). A. <b>Umbra</b> means 'shade' or 'shadow', which is a reduction of light, but not its complete absence. B. <b>Sōl</b> means 'sun', which is a source of light. D. <b>Ignis</b> means 'fire', also a source of light." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>ūtor</b>", "<b>sequor</b>", "<b>loquor</b>", "<b>petō</b>"], i: 3, explanation: "The correct answer is <b>D. petō</b>. <b>ūtor</b> (to use), <b>sequor</b> (to follow), and <b>loquor</b> (to speak) are all deponent verbs, meaning they have passive forms but active meanings. <b>petō</b> (to seek, ask for) is an active verb with regular active and passive forms." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>castra</b>", "<b>bellum</b>", "<b>oppidum</b>", "<b>agmen</b>"], i: 0, explanation: "The correct answer is <b>A. castra</b>. <b>castra</b> (camp) is a <i>plūrālia tantum</i> noun, meaning it appears only in the plural form but often has a singular meaning. <b>bellum</b> (war), <b>oppidum</b> (town), and <b>agmen</b> (column of marching men) are all regular nouns that have distinct singular and plural forms." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>proficīscor</b>", "<b>eō</b>", "<b>maneō</b>", "<b>gradior</b>"], i: 2, explanation: "The correct answer is <b>C. maneō</b>. <b>maneō</b> (to remain, stay) is a verb indicating stasis or rest. <b>proficīscor</b> (to set out, depart), <b>eō</b> (to go), and <b>gradior</b> (to step, walk) are all verbs of motion or movement." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>ā/ab</b>", "<b>dē</b>", "<b>sine</b>", "<b>propter</b>"], i: 3, explanation: "The correct answer is <b>D. propter</b>. <b>propter</b> (on account of, because of) is a preposition that always takes the accusative case. <b>ā/ab</b> (from, by), <b>dē</b> (down from, concerning), and <b>sine</b> (without) are all prepositions that take the ablative case." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>celer</b>", "<b>facilis</b>", "<b>fortis</b>", "<b>plūrimus</b>"], i: 3, explanation: "The correct answer is <b>D. plūrimus</b>. <b>plūrimus</b> (most, very many) is an adjective in the superlative degree. <b>celer</b> (swift), <b>facilis</b> (easy), and <b>fortis</b> (brave, strong) are all adjectives in the positive degree." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>virtūs</b>", "<b>homō</b>", "<b>equus</b>", "<b>arma</b>"], i: 0, explanation: "The correct answer is <b>A. virtūs</b>. <b>virtūs</b> (courage, virtue) is an abstract noun. <b>homō</b> (man, human being), <b>equus</b> (horse), and <b>arma</b> (arms, weapons) are all concrete nouns, referring to tangible entities." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>pāreō</b>", "<b>regō</b>", "<b>gerō</b>", "<b>mittō</b>"], i: 0, explanation: "The correct answer is <b>A. pāreō</b>. <b>pāreō</b> (to obey) is an intransitive verb that typically takes an object in the dative case. <b>regō</b> (to rule, guide), <b>gerō</b> (to carry, wage), and <b>mittō</b> (to send) are all transitive verbs that typically take a direct object in the accusative case." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>dum</b>", "<b>postquam</b>", "<b>ubi</b>", "<b>quia</b>"], i: 3, explanation: "The correct answer is <b>D. quia</b>. <b>quia</b> (because) is a causal conjunction, introducing a reason. <b>dum</b> (while, until), <b>postquam</b> (after), and <b>ubi</b> (when, where) are all temporal conjunctions or adverbs, indicating time." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>sē</b>", "<b>nōs</b>", "<b>vōs</b>", "<b>hic</b>"], i: 3, explanation: "The correct answer is <b>D. hic</b>. <b>hic</b> (this, he) is a demonstrative pronoun or adjective. <b>sē</b> (himself, herself, itself, themselves), <b>nōs</b> (we, us), and <b>vōs</b> (you plural) are all personal or reflexive pronouns." }, { meta: "Odd One Out", stem: "Which Latin word does NOT belong with the others?", options: ["<b>ūnus</b>", "<b>duo</b>", "<b>tertius</b>", "<b>trēs</b>"], i: 2, explanation: "The correct answer is <b>C. tertius</b>. <b>tertius</b> (third) is an ordinal number, indicating order or position. <b>ūnus</b> (one), <b>duo</b> (two), and <b>trēs</b> (three) are all cardinal numbers, indicating quantity." }, { meta: "Analogies", stem: "sequor : secūtus sum :: loquor : <b>X</b>", options: ["locūtus sum", "loquī", "locūtus", "loquēns"], i: 0, explanation: "The relationship is a deponent verb's first principal part (present active indicative) to its third principal part (perfect active participle + sum). <i>Sequor</i> (to follow) has <i>secūtus sum</i> as its perfect. Similarly, <i>loquor</i> (to speak) has <i>locūtus sum</i> as its perfect. Option B is the second principal part (present active infinitive). Options C and D are forms of the participle without the auxiliary verb or the present participle, respectively." }, { meta: "Analogies", stem: "iter : itineris :: opus : <b>X</b>", options: ["operis", "opus", "operī", "operum"], i: 0, explanation: "The relationship is an irregular noun's nominative singular form to its genitive singular form. <i>Iter, itineris</i> (n.) means 'journey'. The corresponding genitive singular for <i>opus</i> (n.) 'work, task' is <i>operis</i>. Option B is the nominative/accusative singular. Option C is the dative singular. Option D is the genitive plural." }, { meta: "Analogies", stem: "pugnāre : pugna :: dūcere : <b>X</b>", options: ["dux", "ductus", "dūctus", "dūctiō"], i: 2, explanation: "The relationship is a verb's infinitive form to a related noun denoting the action or result. <i>Pugnāre</i> (to fight) relates to <i>pugna, -ae</i> (f.) 'a battle, fight'. For <i>dūcere</i> (to lead), the most common noun denoting 'a leading, command' is <i>dūctus, -ūs</i> (m.), a fourth declension noun of action. Option A, <i>dux</i>, means 'leader', which is the agent, not the action. Option B is the perfect passive participle (<i>ductus, -a, -um</i>). Option D, <i>dūctiō</i>, is a less common noun for 'a leading'." }, { meta: "Analogies", stem: "fortis : fortiter :: celer : <b>X</b>", options: ["celeriter", "celerē", "celerius", "celeritās"], i: 0, explanation: "The relationship is an adjective to its corresponding adverb. Adjectives of the third declension, like <i>fortis</i> (brave) and <i>celer</i> (swift), typically form their adverbs by adding <i>-iter</i> to the stem. Thus, <i>fortis</i> becomes <i>fortiter</i> (bravely), and <i>celer</i> becomes <i>celeriter</i> (swiftly). Option B, <i>celerē</i>, would be the adverbial form for a second declension adjective ending in <i>-er</i> (e.g., <i>pulcher</i> &gt; <i>pulchrē</i>). Option C is the comparative adverb. Option D is a noun." }, { meta: "Analogies", stem: "mīles : legiō :: nāvis : <b>X</b>", options: ["classis", "nāvigium", "portus", "rēmus"], i: 0, explanation: "The relationship is an individual unit to a collective group. A <i>mīles</i> (soldier) is part of a <i>legiō</i> (legion). Similarly, a <i>nāvis</i> (ship) is part of a <i>classis</i> (fleet). Option B, <i>nāvigium</i>, means 'boat' or 'vessel' and refers to an individual craft. Option C, <i>portus</i>, means 'harbor'. Option D, <i>rēmus</i>, means 'oar'." }, { meta: "Analogies", stem: "agricola : colere :: mīles : <b>X</b>", options: ["pugnāre", "labōrāre", "dēfendere", "gerere"], i: 0, explanation: "The relationship is an agent (person) to their characteristic or primary action. An <i>agricola</i> (farmer) characteristically practices <i>colere</i> (to cultivate). A <i>mīles</i> (soldier) characteristically practices <i>pugnāre</i> (to fight). While soldiers also <i>labōrāre</i> (work), <i>dēfendere</i> (defend), and <i>gerere</i> (wage, carry), <i>pugnāre</i> is their most direct and defining action." }, { meta: "Analogies", stem: "timor : metus :: virtūs : <b>X</b>", options: ["fortitūdō", "audācia", "probitās", "cōnsilium"], i: 0, explanation: "The relationship is synonymy. <i>Timor</i> and <i>metus</i> both mean 'fear'. <i>Virtūs</i>, while broadly meaning 'excellence' or 'virtue', often specifically refers to 'courage' or 'bravery' in a military context, especially in prose authors like Caesar. Its closest synonym in this sense is <i>fortitūdō</i> (courage, bravery). Option B, <i>audācia</i>, means 'boldness' or 'daring', which can be positive but often carries a negative connotation of 'rashness'. Options C and D are other virtues or qualities (integrity and prudence/plan, respectively)." }, { meta: "Analogies", stem: "posse : potentia :: valēre : <b>X</b>", options: ["valētūdō", "valor", "virtūs", "validitās"], i: 0, explanation: "The relationship is a verb's infinitive form to a related abstract noun denoting a quality or state. <i>Posse</i> (to be able) relates to <i>potentia, -ae</i> (f.) 'power, ability'. Similarly, <i>valēre</i> (to be strong, to be well) relates to <i>valētūdō, -inis</i> (f.) 'health, soundness'. Option B, <i>valor</i>, means 'value' or 'worth'. Option C, <i>virtūs</i>, means 'virtue' or 'courage'. Option D, <i>validitās</i>, is a less common noun for 'strength' or 'validity'." }, { meta: "Analogies", stem: "amāre : amārī :: monēre : <b>X</b>", options: ["monērī", "monēre", "monitus esse", "monēns"], i: 0, explanation: "The relationship is an active present infinitive to its corresponding passive present infinitive. <i>Amāre</i> (to love) becomes <i>amārī</i> (to be loved). For a second conjugation verb like <i>monēre</i> (to warn), the passive present infinitive is formed by changing the final <i>-e</i> to <i>-ī</i>, resulting in <i>monērī</i> (to be warned). Option B is the active infinitive. Option C is the perfect passive infinitive. Option D is the present participle." }, { meta: "Analogies", stem: "ūtor : ūsus sum :: fruor : <b>X</b>", options: ["frūctus sum", "fruī", "fruitus sum", "frūctus"], i: 0, explanation: "The relationship is a deponent verb's first principal part (present active indicative) to its third principal part (perfect active participle + sum). <i>Ūtor</i> (to use) has <i>ūsus sum</i> as its perfect. Similarly, <i>fruor</i> (to enjoy) has <i>frūctus sum</i> as its perfect. Option B is the second principal part (present active infinitive). Option C is an incorrect formation. Option D is the participle without the auxiliary verb." }, { meta: "Fill-in-the-Blank", stem: "Caesar cum omnibus cōpiīs māne ___________.<br><i>Caesar with all his troops early ___________.</i>", options: ["proficīscitur", "revertitur", "sequitur", "patitur"], i: 0, explanation: "The correct answer is <b>A. proficīscitur</b> (sets out, departs). The sentence describes Caesar's action of moving his army early in the morning, which aligns perfectly with 'setting out' or 'departing'.<br><br><b>B. revertitur</b> means 'returns', which contradicts the idea of setting out.<br><b>C. sequitur</b> means 'follows', which doesn't fit the context of Caesar initiating movement with his troops.<br><b>D. patitur</b> means 'suffers' or 'endures', which is semantically incorrect for the action described." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī urbe hostium ___________.<br><i>The Romans __________ the enemy's city.</i>", options: ["potīrī", "capere", "vincere", "dēlēre"], i: 0, explanation: "The correct answer is <b>A. potīrī</b> (to get possession of, obtain). The verb <i>potior</i> is a deponent verb that commonly takes the ablative case (<i>urbe</i>) to mean 'to get possession of the city'. The infinitive form is required to complete the sentence, implying an action the Romans were about to do or attempting to do (e.g., 'The Romans were eager to get possession of the enemy's city' or 'The Romans tried to get possession of the enemy's city').<br><br><b>B. capere</b> (to take), <b>C. vincere</b> (to conquer), and <b>D. dēlēre</b> (to destroy) are all transitive verbs that would take the accusative case (<i>urbem</i>), not the ablative <i>urbe</i>, making them grammatically incorrect in this context." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs scūtīs et gladiīs ___________.<br><i>The soldiers __________ shields and swords.</i>", options: ["ūtuntur", "habent", "gerunt", "tenent"], i: 0, explanation: "The correct answer is <b>A. ūtuntur</b> (use, employ). The deponent verb <i>ūtor</i> takes the ablative case (<i>scūtīs et gladiīs</i>) to express the instrument being used. This perfectly fits the meaning 'The soldiers use shields and swords'.<br><br><b>B. habent</b> (have), <b>C. gerunt</b> (carry, wage), and <b>D. tenent</b> (hold) are all transitive verbs that would take the accusative case (<i>scūta et gladiōs</i>), not the ablative, making them grammatically incorrect for this sentence structure." }, { meta: "Fill-in-the-Blank", stem: "Imperātor mīlitēs ad pugnam ___________.<br><i>The general __________ the soldiers to battle.</i>", options: ["hortātur", "iubet", "vetat", "timet"], i: 0, explanation: "The correct answer is <b>A. hortātur</b> (encourages, urges). This deponent verb fits the context of a general motivating his soldiers for battle.<br><br><b>B. iubet</b> means 'orders', which is possible but <i>hortātur</i> implies encouragement rather than a direct command, fitting the nuance better.<br><b>C. vetat</b> means 'forbids', which is the opposite of what a general would do to his soldiers before battle.<br><b>D. timet</b> means 'fears', which makes no sense in this context." }, { meta: "Fill-in-the-Blank", stem: "Nē __________, sed statim venīte!<br><i>Do not __________, but come at once!</i>", options: ["morēminī", "currātis", "festīnētis", "stētis"], i: 0, explanation: "The correct answer is <b>A. morēminī</b> (delay, linger). The sentence uses a negative command (<i>nē</i> + subjunctive) and then a positive command (<i>venīte</i>). 'Do not delay' fits perfectly with 'but come at once'.<br><br><b>B. currātis</b> (run), <b>C. festīnētis</b> (hurry), and <b>D. stētis</b> (stand) do not fit the contrasting meaning of 'come at once' as well as 'delay' does. 'Do not hurry' or 'Do not run' would contradict 'come at once'." }, { meta: "Fill-in-the-Blank", stem: "Nōs hostēs nōn __________, sed deōs timēmus.<br><i>We do not __________ the enemy, but we fear the gods.</i>", options: ["verēmur", "laudāmus", "odimus", "amāmus"], i: 0, explanation: "The correct answer is <b>A. verēmur</b> (fear, revere). The sentence sets up a contrast: 'We do not fear the enemy, but we fear the gods.' The verb <i>vereor</i> means 'to fear' or 'to revere', and its use here creates a strong parallel with <i>timēmus</i>.<br><br><b>B. laudāmus</b> (praise), <b>C. odimus</b> (hate), and <b>D. amāmus</b> (love) do not provide the necessary semantic contrast with 'fear the gods'." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs mūrum ascendere ___________.<br><i>The soldiers __________ to climb the wall.</i>", options: ["cōnantur", "possunt", "volunt", "dēsinunt"], i: 0, explanation: "The correct answer is <b>A. cōnantur</b> (try, attempt). This deponent verb perfectly describes the action of soldiers making an effort to climb a wall.<br><br><b>B. possunt</b> (are able) and <b>C. volunt</b> (wish, want) are grammatically possible but less specific than 'try' in describing the active effort. 'They are able to climb' or 'They want to climb' doesn't convey the same sense of active endeavor as 'they try to climb'.<br><b>D. dēsinunt</b> (cease, stop) is the opposite of what one would expect soldiers to do when facing a wall they need to ascend." }, { meta: "Fill-in-the-Blank", stem: "Dux mīlitēs per silvam ___________.<br><i>The leader __________ the soldiers through the forest.</i>", options: ["sequitur", "praecēdit", "fugat", "mittit"], i: 0, explanation: "The correct answer is <b>A. sequitur</b> (follows). The deponent verb <i>sequor</i> means 'to follow', which makes perfect sense for a leader moving behind or with his soldiers through a forest.<br><br><b>B. praecēdit</b> means 'goes before, precedes', which is the opposite of 'follows'.<br><b>C. fugat</b> means 'puts to flight, chases away', which is not the typical action of a leader with his own soldiers.<br><b>D. mittit</b> means 'sends', which implies sending the soldiers away, not following them." }, { meta: "Fill-in-the-Blank", stem: "Cicerō ōrātiōnem longam ___________.<br><i>Cicero __________ a long speech.</i>", options: ["loquitur", "audit", "scrībit", "legit"], i: 0, explanation: "The correct answer is <b>A. loquitur</b> (speaks, talks). Cicero was famous for his oratory, so 'speaking a long speech' is the most fitting action.<br><br><b>B. audit</b> means 'hears', which doesn't fit with 'a speech' as the direct object.<br><b>C. scrībit</b> means 'writes', and while Cicero wrote speeches, the primary action associated with delivering an <i>ōrātiō</i> is speaking it.<br><b>D. legit</b> means 'reads', which again is less direct than speaking when referring to the delivery of an oration." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī multōs labōrēs ___________.<br><i>The Romans __________ many labors.</i>", options: ["patiuntur", "gaudent", "vītant", "fugiunt"], i: 0, explanation: "The correct answer is <b>A. patiuntur</b> (suffer, endure). The deponent verb <i>patior</i> is perfectly suited for expressing the idea that the Romans 'endured many labors', a common theme in Roman history and literature.<br><br><b>B. gaudent</b> means 'rejoice', which is the opposite of enduring labors.<br><b>C. vītant</b> means 'avoid', which contradicts the idea of experiencing or enduring labors.<br><b>D. fugiunt</b> means 'flee', which also implies avoiding or escaping, not enduring." }, { meta: "Circumlocution", stem: "Ab ūno locō ad alium locum iter facere, praesertim cum certā causā.", options: ["revertor", "moror", "proficīscor", "perveniō"], i: 2, explanation: "The Latin description, 'Ab ūno locō ad alium locum iter facere, praesertim cum certā causā,' means 'To make a journey from one place to another, especially with a certain reason.' This accurately defines the deponent verb <b>proficīscor, proficīscī, profectus sum</b>, meaning 'to set out, depart.' Option A, <b>revertor</b>, means 'to turn back, return,' which is the opposite action. Option B, <b>moror</b>, means 'to delay, linger,' which is contrary to setting out. Option D, <b>perveniō</b>, means 'to arrive,' which is the conclusion of a journey, not the act of beginning it." }, { meta: "Circumlocution", stem: "Sententiam habēre dē rē aliquā, vel iūdicium facere.", options: ["arbitror", "dubito", "cōnfiteor", "negō"], i: 0, explanation: "The Latin description, 'Sententiam habēre dē rē aliquā, vel iūdicium facere,' translates to 'To have an opinion about something, or to make a judgment.' This precisely describes the deponent verb <b>arbitror, arbitrārī, arbitrātus sum</b>, meaning 'to think, judge, consider.' Option B, <b>dubito</b>, means 'to doubt, hesitate,' which is the opposite of forming a judgment. Option C, <b>cōnfiteor</b>, means 'to confess, admit,' which involves stating a fact rather than forming an opinion. Option D, <b>negō</b>, means 'to deny,' which is contrary to affirming a judgment." }, { meta: "Circumlocution", stem: "Operam dare ut aliquid agātur, sed nōn semper perficere.", options: ["perficiō", "cōnor", "dēsinō", "patior"], i: 1, explanation: "The Latin description, 'Operam dare ut aliquid agātur, sed nōn semper perficere,' means 'To give effort so that something may be done, but not always to accomplish it.' This accurately defines the deponent verb <b>cōnor, cōnārī, cōnātus sum</b>, meaning 'to try, attempt.' Option A, <b>perficiō</b>, means 'to accomplish, complete,' which is the successful outcome of trying, not the act of trying itself. Option C, <b>dēsinō</b>, means 'to cease, stop,' which is the opposite of attempting to do something. Option D, <b>patior</b>, means 'to suffer, endure' or 'to allow,' which is a different kind of action." }, { meta: "Circumlocution", stem: "Verbīs aliōs ad rem faciendam incitāre vel spem dare.", options: ["deterreō", "hortor", "moneō", "vetō"], i: 1, explanation: "The Latin description, 'Verbīs aliōs ad rem faciendam incitāre vel spem dare,' translates to 'To incite others to do something with words or to give hope.' This accurately describes the deponent verb <b>hortor, hortārī, hortātus sum</b>, meaning 'to encourage, urge, exhort.' Option A, <b>deterreō</b>, means 'to deter, frighten off,' which is the opposite of encouraging. Option C, <b>moneō</b>, means 'to warn, advise,' which is similar but generally less forceful or direct encouragement. Option D, <b>vetō</b>, means 'to forbid,' which is the opposite of urging someone to act." }, { meta: "Circumlocution", stem: "Post aliquem īre vel eum comitārī.", options: ["praecēdō", "fugō", "sequor", "stō"], i: 2, explanation: "The Latin description, 'Post aliquem īre vel eum comitārī,' means 'To go after someone or to accompany him.' This accurately defines the deponent verb <b>sequor, sequī, secūtus sum</b>, meaning 'to follow.' Option A, <b>praecēdō</b>, means 'to go before, precede,' which is the opposite of following. Option B, <b>fugō</b>, means 'to put to flight, rout,' which causes someone to flee, not to follow. Option D, <b>stō</b>, means 'to stand,' which implies being static rather than moving after someone." }, { meta: "Circumlocution", stem: "Rē aliquā prodest, vel eā ad suum fīnem adhibēre.", options: ["careō", "ūtor", "fruor", "fungor"], i: 1, explanation: "The Latin description, 'Rē aliquā prodest, vel eā ad suum fīnem adhibēre,' translates to 'To profit from something, or to apply it to one's own purpose.' This accurately defines the deponent verb <b>ūtor, ūtī, ūsus sum</b>, meaning 'to use, employ, make use of' (which takes the ablative case). Option A, <b>careō</b>, means 'to lack, be without,' which is the opposite of using something. Option C, <b>fruor</b>, means 'to enjoy,' which is similar in taking advantage of something but focuses on pleasure rather than utility. Option D, <b>fungor</b>, means 'to perform, execute' (a duty or function), which is a different kind of action." }, { meta: "Circumlocution", stem: "Dominium vel potestātem rērum capere.", options: ["āmittō", "potior", "dēserō", "parō"], i: 1, explanation: "The Latin description, 'Dominium vel potestātem rērum capere,' means 'To seize dominion or power over things.' This accurately defines the deponent verb <b>potior, potīrī, potītus sum</b>, meaning 'to get possession of, obtain' (which often takes the ablative case). Option A, <b>āmittō</b>, means 'to lose,' which is the opposite of obtaining possession. Option C, <b>dēserō</b>, means 'to abandon, desert,' which is contrary to taking possession. Option D, <b>parō</b>, means 'to prepare,' which is a preparatory action, not the act of obtaining itself." }, { meta: "Circumlocution", stem: "Vir armātus quī pro patriā pugnat.", options: ["cīvis", "hostis", "dux", "mīles"], i: 3, explanation: "The Latin description, 'Vir armātus quī pro patriā pugnat,' translates to 'An armed man who fights for his country.' This accurately defines the noun <b>mīles, mīlitis, m.</b>, meaning 'soldier.' Option A, <b>cīvis</b>, means 'citizen,' which is a broader term and does not necessarily imply being armed or fighting. Option B, <b>hostis</b>, means 'enemy,' which is the opposite role of one fighting for their country. Option C, <b>dux</b>, means 'leader, general,' which is a specific rank, not a generic soldier." }, { meta: "Circumlocution", stem: "Via per quam hominēs vel animālia moventur, vel actus eundī.", options: ["pons", "flūmen", "iter", "mūrus"], i: 2, explanation: "The Latin description, 'Via per quam hominēs vel animālia moventur, vel actus eundī,' means 'A way through which people or animals move, or the act of going.' This accurately defines the irregular noun <b>iter, itineris, n.</b>, meaning 'journey, march, road.' Option A, <b>pons</b>, means 'bridge,' which is a specific type of structure on a path. Option B, <b>flūmen</b>, means 'river,' which is a natural feature, not necessarily a designated path. Option D, <b>mūrus</b>, means 'wall,' which is a barrier, the opposite of a path." }, { meta: "Circumlocution", stem: "Magna potentia vel energīa quae ad rem faciendam adhibētur, saepe cum violentia.", options: ["pax", "consilium", "vis", "voluntās"], i: 2, explanation: "The Latin description, 'Magna potentia vel energīa quae ad rem faciendam adhibētur, saepe cum violentia,' translates to 'Great power or energy which is applied to do something, often with violence.' This accurately defines the irregular noun <b>vis, vis, f.</b>, meaning 'force, power, violence.' Option A, <b>pax</b>, means 'peace,' which is the opposite of violence. Option B, <b>consilium</b>, means 'plan, advice,' which is an intellectual concept, not physical force. Option D, <b>voluntās</b>, means 'will, desire,' which is an internal motivation, not an external force." }, { meta: "Latin to English", stem: "What is the best English translation of <b>proficīscor</b>?", options: ["to set out", "to make progress", "to complete", "to pour forth"], i: 0, explanation: "<b>proficīscor</b> is a deponent verb meaning 'to set out' or 'depart'. Option B is the translation of <b>proficiō</b>, 'to make progress'. Option C is the translation of <b>perficiō</b>, 'to complete'. Option D is the translation of <b>profundō</b>, 'to pour forth'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>sequor</b>?", options: ["to follow", "to cut", "to be safe", "to speak"], i: 0, explanation: "<b>sequor</b> is a deponent verb meaning 'to follow'. Option B is the translation of <b>secō</b>, 'to cut'. Option C is derived from <b>sēcūrus</b>, an adjective meaning 'secure' or 'safe'. Option D is the translation of <b>loquor</b>, 'to speak'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>arbitror</b>?", options: ["to think", "tree", "judgment", "judge"], i: 0, explanation: "<b>arbitror</b> is a deponent verb meaning 'to think' or 'judge'. Option B is the translation of the noun <b>arbor</b>, 'tree'. Option C is the translation of the noun <b>arbitrium</b>, 'judgment' or 'decision'. Option D is the translation of the noun <b>arbitrātor</b>, 'judge'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>ūtor</b>?", options: ["to use", "use", "one", "eleven"], i: 0, explanation: "<b>ūtor</b> is a deponent verb meaning 'to use' or 'employ', and it takes the ablative case. Option B is the translation of the noun <b>ūsus</b>, 'use' or 'experience'. Option C is the translation of the adjective <b>ūnus</b>, 'one'. Option D is the translation of the number <b>ūndecim</b>, 'eleven'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>hortor</b>?", options: ["to urge", "garden", "to shudder", "to beg"], i: 0, explanation: "<b>hortor</b> is a deponent verb meaning 'to urge' or 'encourage'. Option B is the translation of the noun <b>hortus</b>, 'garden'. Option C is the translation of the verb <b>horreō</b>, 'to shudder'. Option D is the translation of the verb <b>ōrō</b>, 'to beg'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>moror</b>?", options: ["to delay", "death", "to die", "custom"], i: 0, explanation: "<b>moror</b> is a deponent verb meaning 'to delay'. Option B is the translation of the noun <b>mors</b>, 'death'. Option C is the translation of the deponent verb <b>morior</b>, 'to die'. Option D is the translation of the noun <b>mōs</b>, 'custom'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>potior</b>?", options: ["to get possession of", "to be able", "powerful", "drunk"], i: 0, explanation: "<b>potior</b> is a deponent verb meaning 'to get possession of' or 'obtain', and it often takes the ablative case. Option B is the translation of the irregular verb <b>possum</b>, 'to be able'. Option C is the translation of the adjective <b>potēns</b>, 'powerful'. Option D is the translation of the adjective <b>potus</b>, 'drunk' or 'having drunk'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>vereor</b>?", options: ["to fear", "true", "to turn", "man"], i: 0, explanation: "<b>vereor</b> is a deponent verb meaning 'to fear' or 'revere'. Option B is the translation of the adjective <b>vērus</b>, 'true'. Option C is the translation of the verb <b>vertō</b>, 'to turn'. Option D is the translation of the noun <b>vir</b>, 'man'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>patior</b>?", options: ["to suffer", "father", "fatherland", "to obey"], i: 0, explanation: "<b>patior</b> is a deponent verb meaning 'to suffer', 'endure', or 'allow'. Option B is the translation of the noun <b>pater</b>, 'father'. Option C is the translation of the noun <b>patria</b>, 'fatherland'. Option D is the translation of the verb <b>pāreō</b>, 'to obey'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>cōnor</b>?", options: ["to try", "to consult", "to stand still", "to complete"], i: 0, explanation: "<b>cōnor</b> is a deponent verb meaning 'to try' or 'attempt'. Option B is the translation of <b>cōnsulō</b>, 'to consult'. Option C is the translation of <b>cōnsistō</b>, 'to stand still' or 'halt'. Option D is the translation of <b>cōnficiō</b>, 'to complete' or 'accomplish'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>loquor</b>?", options: ["to speak", "place", "talkative", "light"], i: 0, explanation: "<b>loquor</b> is a deponent verb meaning 'to speak'. Option B is the translation of the noun <b>locus</b>, 'place'. Option C is the translation of the adjective <b>loquāx</b>, 'talkative'. Option D is the translation of the noun <b>lūx</b>, 'light'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>gradior</b>?", options: ["to step", "step", "heavy", "pleasing"], i: 0, explanation: "<b>gradior</b> is a deponent verb meaning 'to step' or 'walk'. Option B is the translation of the noun <b>gradus</b>, 'step' or 'pace'. Option C is the translation of the adjective <b>gravis</b>, 'heavy' or 'serious'. Option D is the translation of the adjective <b>grātus</b>, 'pleasing' or 'grateful'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>vīs</b> (nominative singular)?", options: ["force", "man", "wine", "road"], i: 0, explanation: "The irregular noun <b>vīs</b> (gen. <b>vīs</b>, f.) means 'force' or 'power' in the singular. Its plural, <b>vīrēs, vīrium</b>, means 'strength'. Option B is the translation of the noun <b>vir</b>, 'man'. Option C is the translation of the noun <b>vīnum</b>, 'wine'. Option D is the translation of the noun <b>via</b>, 'road'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>iter</b>?", options: ["journey", "between", "the same", "anger"], i: 0, explanation: "The irregular noun <b>iter, itineris</b> (n.) means 'journey', 'route', or 'march'. Option B is the translation of the preposition <b>inter</b>, 'between' or 'among'. Option C is the translation of the pronoun/adjective <b>īdem</b>, 'the same'. Option D is the translation of the noun <b>īra</b>, 'anger'." }, { meta: "Latin to English", stem: "What is the best English translation of <b>cōnsulō</b>?", options: ["to consult", "plan", "consul", "to stand still"], i: 0, explanation: "The verb <b>cōnsulō, cōnsulere, cōnsuluī, cōnsultus</b> means 'to consult', 'deliberate', or 'consider'. When followed by the dative, it can mean 'to look out for'. Option B is the translation of the noun <b>cōnsilium</b>, 'plan' or 'advice'. Option C is the translation of the noun <b>cōnsul</b>, 'consul'. Option D is the translation of the verb <b>cōnsistō</b>, 'to stand still' or 'halt'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to use</b>", options: ["ūtor, ūtī, ūsus sum", "ūtor, ūtī, ūtus sum", "ūtor, ūtī, ūxī", "ūtor, ūtāre, ūtāvī, ūtātum"], i: 0, explanation: "The verb 'to use' is the deponent verb <b>ūtor, ūtī, ūsus sum</b>, which takes the ablative case. Option A provides the correct principal parts. Option B has an incorrect perfect participle. Option C has incorrect principal parts, possibly confused with a verb like <i>ūrō</i>. Option D presents an incorrect conjugation and principal parts." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to set out, depart</b>", options: ["proficīscor, proficīscī, profectus sum", "proficiō, proficere, profēcī, profectum", "prōcēdō, prōcēdere, prōcessī, prōcessum", "proficior, proficīrī, profectus sum"], i: 0, explanation: "The most common Latin verb for 'to set out' or 'depart' is the deponent verb <b>proficīscor, proficīscī, profectus sum</b>. Option B, <i>proficiō</i>, means 'to accomplish' or 'to advance'. Option C, <i>prōcēdō</i>, means 'to advance' or 'to proceed'. Option D has incorrect principal parts for a deponent verb." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>force, strength</b> (singular)", options: ["vīs, vīs (f.)", "rōbur, rōboris (n.)", "potentia, potentiae (f.)", "vīrēs, vīrium (f. pl.)"], i: 0, explanation: "The irregular noun for 'force' in the singular is <b>vīs, vīs (f.)</b>. It is an i-stem noun with an irregular declension (nom. <i>vīs</i>, acc. <i>vim</i>, abl. <i>vī</i>). Option B, <i>rōbur</i>, means 'strength' or 'firmness', often metaphorical. Option C, <i>potentia</i>, refers to 'power' or 'influence', especially political. Option D, <i>vīrēs</i>, is the plural form of <i>vīs</i> and means 'strength' or 'military forces'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>sea</b>", options: ["mare, maris (n.)", "pontus, pontī (m.)", "aequor, aequoris (n.)", "pelagus, pelagī (n.)"], i: 0, explanation: "The most common and general Latin word for 'sea' is the i-stem neuter noun <b>mare, maris (n.)</b>. Options B, C, and D (<i>pontus</i>, <i>aequor</i>, <i>pelagus</i>) are all poetic or less common synonyms for 'sea', with <i>pelagus</i> being a Greek loanword. For general prose, <i>mare</i> is the best choice." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>each (one)</b>", options: ["quisque, quaeque, quidque", "ūnusquisque, ūnaquaeque, ūnumquidque", "uterque, utraque, utrumque", "omnis, omne"], i: 0, explanation: "The pronoun for 'each (one)' is <b>quisque, quaeque, quidque</b> (or <i>quodque</i> as an adjective). Option B, <i>ūnusquisque</i>, means 'every single one' and is more emphatic. Option C, <i>uterque</i>, means 'each of two'. Option D, <i>omnis</i>, means 'all' or 'every', but not specifically 'each one'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to persuade</b>", options: ["persuādeō, persuādēre, persuāsī, persuāsum (+ dat.)", "convincō, convincere, convīcī, convictum", "cōgō, cōgere, coēgī, coāctum", "persuādō, persuādere, persuāsī, persuāsum"], i: 0, explanation: "The verb 'to persuade' is <b>persuādeō, persuādēre, persuāsī, persuāsum</b>, and it typically takes the dative case for the person being persuaded. Option B, <i>convincō</i>, means 'to convict' or 'to prove wrong'. Option C, <i>cōgō</i>, means 'to compel' or 'to force'. Option D has an incorrect first principal part (should be <i>persuādeō</i>, not <i>persuādō</i>)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to wage war</b>", options: ["bellum gerere", "bellum facere", "bellum agere", "bellum portare"], i: 0, explanation: "The standard Latin idiom for 'to wage war' is <b>bellum gerere</b>, literally 'to carry on war'. Option B, <i>bellum facere</i>, is less common and can mean 'to make war' in the sense of 'to cause war'. Options C and D are not idiomatic expressions for 'to wage war'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to dismiss, send away</b>", options: ["dīmittō, dīmittere, dīmīsī, dīmissum", "mittō, mittere, mīsī, missum", "remittō, remittere, remīsī, remissum", "ēmittō, ēmittere, ēmīsī, ēmissum"], i: 0, explanation: "The verb 'to dismiss' or 'send away' is best translated by <b>dīmittō, dīmittere, dīmīsī, dīmissum</b>. Option B, <i>mittō</i>, means 'to send' generally. Option C, <i>remittō</i>, means 'to send back' or 'to relax'. Option D, <i>ēmittō</i>, means 'to send out' or 'to let go'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>city</b>", options: ["urbs, urbis (f.)", "cīvitās, cīvitātis (f.)", "oppidum, oppidī (n.)", "cīvitās, cīvitātis (m.)"], i: 0, explanation: "The most general and common Latin word for a large, important 'city' (especially Rome) is <b>urbs, urbis (f.)</b>. Option B, <i>cīvitās</i>, refers more to the 'body of citizens', 'state', or 'city-state' as a political entity. Option C, <i>oppidum</i>, refers to a 'town' or 'fortified town', typically smaller than an <i>urbs</i>. Option D is incorrect due to the gender (<i>cīvitās</i> is feminine)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>hand</b>", options: ["manus, manūs (f.)", "palma, palmae (f.)", "dīgitus, dīgitī (m.)", "manus, manūs (m.)"], i: 0, explanation: "The Latin word for 'hand' is the 4th declension feminine noun <b>manus, manūs (f.)</b>. Option B, <i>palma</i>, means 'palm of the hand'. Option C, <i>dīgitus</i>, means 'finger'. Option D is incorrect because <i>manus</i> is feminine, not masculine." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to suffer, endure</b>", options: ["patior, patī, passus sum", "ferō, ferre, tulī, lātum", "tolerō, tolerāre, tolerāvī, tolerātum", "labōrō, labōrāre, labōrāvī, labōrātum"], i: 0, explanation: "The deponent verb <b>patior, patī, passus sum</b> is the most direct translation for 'to suffer' or 'to endure'. Option B, <i>ferō</i>, can mean 'to bear' or 'to endure', but it is a highly irregular non-deponent verb. Option C, <i>tolerō</i>, means 'to tolerate' or 'to endure', but is a regular 1st conjugation verb. Option D, <i>labōrō</i>, means 'to work', 'to toil', or 'to be in distress', which can imply suffering but is less direct." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to think, believe</b> (often implying judgment or consideration)", options: ["arbitror, arbitrārī, arbitrātus sum", "putō, putāre, putāvī, putātum", "crēdō, crēdere, crēdidī, crēditum", "exīstimō, exīstimāre, exīstimāvī, exīstimātum"], i: 0, explanation: "While several verbs can mean 'to think' or 'to believe', <b>arbitror, arbitrārī, arbitrātus sum</b>, a deponent verb, often carries the nuance of 'to judge', 'to consider', or 'to be of the opinion'. Option B, <i>putō</i>, is a general verb for 'to think' or 'to suppose'. Option C, <i>crēdō</i>, means 'to believe' or 'to trust', often taking the dative for the person believed. Option D, <i>exīstimō</i>, is very similar to <i>putō</i>, meaning 'to judge', 'to think', or 'to estimate'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>army</b>", options: ["exercitus, exercitūs (m.)", "agmen, agminis (n.)", "aciēs, aciēī (f.)", "legiō, legiōnis (f.)"], i: 0, explanation: "The most general and common Latin word for a trained 'army' is <b>exercitus, exercitūs (m.)</b>. Option B, <i>agmen</i>, refers specifically to an 'army on the march' or a 'marching column'. Option C, <i>aciēs</i>, refers to a 'battle line' or 'line of sight'. Option D, <i>legiō</i>, is a specific unit of the Roman army, a 'legion', not the general term for 'army'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to return</b> (intransitive)", options: ["redeō, redīre, rediī/redīvī, reditum", "revertor, revertī, reversus sum", "regredior, regredī, regressus sum", "referō, referre, rettulī, relātum"], i: 0, explanation: "The most common intransitive verb for 'to return' is <b>redeō, redīre, rediī/redīvī, reditum</b>, a compound of <i>eō</i>. Option B, <i>revertor</i>, is a deponent verb also meaning 'to return', often used for persons. Option C, <i>regredior</i>, is a deponent verb meaning 'to go back' or 'to retreat'. Option D, <i>referō</i>, is a transitive verb meaning 'to bring back' or 'to report'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to be accustomed</b>", options: ["soleō, solēre, solitus sum", "cōnsuēscō, cōnsuēscere, cōnsuēvī, cōnsuētum", "assuēscō, assuēscere, assuēvī, assuētum", "habitō, habitāre, habitāvī, habitātum"], i: 0, explanation: "The semi-deponent verb <b>soleō, solēre, solitus sum</b> is the primary translation for 'to be accustomed'. Options B and C, <i>cōnsuēscō</i> and <i>assuēscō</i>, mean 'to become accustomed' (in the present system) or 'to be accustomed' (in the perfect system, e.g., <i>cōnsuēvī</i> = 'I am accustomed'). Option D, <i>habitō</i>, means 'to dwell' or 'to inhabit', which is incorrect." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>iter</b> simillimum?", options: ["via", "proelium", "castra", "flūmen"], i: 0, explanation: "Verbum <b>iter</b> (iter, itineris, n.) significat 'iter, via, cursus'. Verbum <b>via</b> (via, viae, f.) quoque significat 'via, iter'. Haec duo verba sunt inter sē simillima. <b>Proelium</b> significat 'pugnam', <b>castra</b> 'castra militāria', et <b>flūmen</b> 'flūmen'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>cōnor</b> simillimum?", options: ["patior", "temptō", "sequor", "proficīscor"], i: 1, explanation: "Verbum dēpōnēns <b>cōnor</b> (cōnārī, cōnātus sum) significat 'cōnārī, temptāre'. Verbum <b>temptō</b> (temptāre, temptāvī, temptātus) quoque significat 'temptāre, cōnārī'. <b>Patior</b> significat 'patī, ferre', <b>sequor</b> 'sequī', et <b>proficīscor</b> 'proficīscī, exīre'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>hortor</b> simillimum?", options: ["retineō", "dēterreō", "incitō", "laudō"], i: 2, explanation: "Verbum dēpōnēns <b>hortor</b> (hortārī, hortātus sum) significat 'hortārī, incitāre, adhortārī'. Verbum <b>incitō</b> (incitāre, incitāvī, incitātus) significat 'incitāre, excitāre, urgēre'. <b>Retineō</b> significat 'retinēre, cohibēre', <b>dēterreō</b> 'dēterrēre', et <b>laudō</b> 'laudāre'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>mīles</b> simillimum?", options: ["cīvis", "armātus", "hostis", "dux"], i: 1, explanation: "Nōmen <b>mīles</b> (mīlitis, m.) significat 'mīlitem, virum mīlitārem'. <b>Armātus</b> (armātī, m.) est 'vir armātus, mīles'. <b>Cīvis</b> significat 'cīvem', <b>hostis</b> 'hostem', et <b>dux</b> 'ducem, imperātōrem'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>vīcīnus</b> simillimum?", options: ["longinquus", "propinquus", "aliēnus", "medius"], i: 1, explanation: "Adiectīvum <b>vīcīnus</b> (-a, -um) significat 'vīcīnum, prope positum'. Adiectīvum <b>propinquus</b> (-a, -um) quoque significat 'propinquum, vīcīnum'. <b>Longinquus</b> significat 'longinquum, remōtum', <b>aliēnus</b> 'aliēnum, externum', et <b>medius</b> 'medium'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proelium</b> simillimum?", options: ["pāx", "pugna", "bellum", "arma"], i: 1, explanation: "Nōmen <b>proelium</b> (proeliī, n.) significat 'proelium, pugnam'. Nōmen <b>pugna</b> (pugnae, f.) quoque significat 'pugnam, proelium'. <b>Pāx</b> significat 'pācem', <b>bellum</b> 'bellum' (quod est conceptus lātior quam 'pugna'), et <b>arma</b> 'arma'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>imperium</b> simillimum?", options: ["servitūs", "lībertās", "potestās", "amīcitia"], i: 2, explanation: "Nōmen <b>imperium</b> (imperiī, n.) significat 'imperium, potestātem, iūrisdictiōnem'. Nōmen <b>potestās</b> (potestātis, f.) quoque significat 'potestātem, auctōritātem'. <b>Servitūs</b> significat 'servitūtem', <b>lībertās</b> 'lībertātem', et <b>amīcitia</b> 'amīcitiam'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>magnus</b> simillimum?", options: ["parvus", "celer", "ingēns", "gravis"], i: 2, explanation: "Adiectīvum <b>magnus</b> (-a, -um) significat 'magnus, grandis'. Adiectīvum <b>ingēns</b> (ingentis) significat 'ingēns, vāstus, permagnus'. <b>Parvus</b> significat 'parvus', <b>celer</b> 'celer', et <b>gravis</b> 'gravis'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>timor</b> simillimum?", options: ["spēs", "metus", "gaudium", "īra"], i: 1, explanation: "Nōmen <b>timor</b> (timōris, m.) significat 'timōrem, metum'. Nōmen <b>metus</b> (metūs, m.) quoque significat 'metum, timōrem'. <b>Spēs</b> significat 'spem', <b>gaudium</b> 'gaudium', et <b>īra</b> 'īram'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>oppugnō</b> simillimum?", options: ["dēfendō", "adorior", "fugiō", "cōnsistō"], i: 1, explanation: "Verbum <b>oppugnō</b> (oppugnāre, oppugnāvī, oppugnātus) significat 'oppugnāre, bellum inferre'. Verbum <b>adorior</b> (adorīrī, adortus sum) quoque significat 'adorīrī, impetum facere'. <b>Dēfendō</b> significat 'dēfendere', <b>fugiō</b> 'fugere', et <b>cōnsistō</b> 'cōnsistere, subsistere'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>vīrēs</b> simillimum?", options: ["corpus", "potentia", "animus", "ōtium"], i: 1, explanation: "Nōmen <b>vīrēs</b> (vīrium, f. pl.) significat 'vīrēs, rōbur, potentiam'. Nōmen <b>potentia</b> (potentiae, f.) quoque significat 'potentiam, potestātem, vīrēs'. <b>Corpus</b> significat 'corpus', <b>animus</b> 'animum', et <b>ōtium</b> 'ōtium'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>profectiō</b> simillimum?", options: ["adventus", "discessus", "reditus", "mora"], i: 1, explanation: "Nōmen <b>profectiō</b> (profectiōnis, f.) significat 'profectiōnem, ēgressum'. Nōmen <b>discessus</b> (discessūs, m.) quoque significat 'discessum, profectiōnem'. <b>Adventus</b> significat 'adventum', <b>reditus</b> 'reditum', et <b>mora</b> 'moram'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>cōnsilium</b> simillimum?", options: ["fāma", "ratiō", "fortūna", "voluntās"], i: 1, explanation: "Nōmen <b>cōnsilium</b> (cōnsiliī, n.) significat 'cōnsilium, sententiam, ratiōnem'. Nōmen <b>ratiō</b> (ratiōnis, f.) quoque significat 'ratiōnem, modum, cōnsilium'. <b>Fāma</b> significat 'fāmam', <b>fortūna</b> 'fortūnam', et <b>voluntās</b> 'voluntātem'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>paene</b> simillimum?", options: ["semper", "numquam", "ferē", "saepe"], i: 2, explanation: "Adverbium <b>paene</b> significat 'paene, prope'. Adverbium <b>ferē</b> quoque significat 'ferē, paene, prope'. <b>Semper</b> significat 'semper', <b>numquam</b> 'numquam', et <b>saepe</b> 'saepe'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>loquor</b> simillimum?", options: ["audiō", "scrībō", "colloquor", "tacēō"], i: 2, explanation: "Verbum dēpōnēns <b>loquor</b> (loquī, locūtus sum) significat 'loquī, dīcere'. Verbum dēpōnēns <b>colloquor</b> (colloquī, collocūtus sum) significat 'colloquī, sermōnem habēre'. <b>Audiō</b> significat 'audīre', <b>scrībō</b> 'scrībere', et <b>tacēō</b> 'tacēre'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>prope</b>?", options: ["longē", "celeriter", "lentē", "saepe"], i: 0, explanation: "Verbum <b>prope</b> significat 'prope' vel 'iuxtā'. Eius contrārium est <b>longē</b>, quod significat 'procul' vel 'longē'. Optiōnēs B, C, D sunt adverbia temporis vel modī, nōn locī." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>incipiō</b>?", options: ["perficiō", "dēsinō", "labōrō", "veniō"], i: 1, explanation: "Verbum <b>incipiō</b> significat 'incipere' vel 'incohāre'. Eius contrārium directissimum est <b>dēsinō</b>, quod significat 'dēsinere' vel 'intermittere'. Quamquam <i>perficiō</i> (perficiō, perficere, perfēcī, perfectum) significat 'complēre', <i>dēsinō</i> (dēsinō, dēsinere, dēsiī, dēsitum) est magis directē contrārium 'incipiō' quoad actiōnis initium et fīnem." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>saepe</b>?", options: ["semper", "numquam", "rārō", "nunc"], i: 2, explanation: "Verbum <b>saepe</b> significat 'saepe' vel 'multīs temporibus'. Eius contrārium est <b>rārō</b>, quod significat 'rārō' vel 'paucīs temporibus'. <i>Semper</i> significat 'semper' et <i>numquam</i> significat 'numquam', quae sunt extrēma, nōn contrāria directē ad frequentiam mediam 'saepe'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>hostis</b>?", options: ["cīvis", "amīcus", "servus", "dux"], i: 1, explanation: "Nōmen <b>hostis</b> significat 'inimīcum' vel 'adversārium bellī'. Eius contrārium est <b>amīcus</b>, quod significat 'socium' vel 'sodālem'. Cēterae optiōnēs sunt rōlēs sociāles, nōn necessāriō contrāriae hostī." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>laetus</b>?", options: ["īrātus", "fessus", "trīstis", "fortis"], i: 2, explanation: "Adiectīvum <b>laetus</b> significat 'laetus' vel 'gaudēns'. Eius contrārium est <b>trīstis</b>, quod significat 'trīstis' vel 'dolēns'. Cēterae optiōnēs sunt aliī statūs animī vel corporāles." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>pauper</b>?", options: ["fēlīx", "miser", "dīves", "validus"], i: 2, explanation: "Adiectīvum <b>pauper</b> significat 'pauper' vel 'ēgens'. Eius contrārium est <b>dīves</b>, quod significat 'dīves' vel 'opulentus'. Cēterae optiōnēs describunt fortūnam, statum, vel vīrēs, nōn dīvitiās." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>anteā</b>?", options: ["nunc", "semper", "posteā", "tum"], i: 2, explanation: "Adverbium <b>anteā</b> significat 'antehac' vel 'prius'. Eius contrārium est <b>posteā</b>, quod significat 'posthac' vel 'deinde'. Cēterae optiōnēs sunt adverbia temporis, sed nōn directē contrāria 'anteā'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>accipiō</b>?", options: ["capiō", "mittō", "dō", "emō"], i: 2, explanation: "Verbum <b>accipiō</b> significat 'accipere' vel 'sūmere'. Eius contrārium est <b>dō</b>, quod significat 'dare' vel 'trādere'. <i>Capiō</i> (capiō, capere, cēpī, captum) est similis sed significat 'capere' vel 'prehendere', nōn 'dare'. Cēterae optiōnēs sunt aliī actūs." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>lūx</b>?", options: ["umbra", "ignis", "tenebrāe", "sōl"], i: 2, explanation: "Nōmen <b>lūx</b> significat 'lūmen' vel 'clāritās'. Eius contrārium est <b>tenebrāe</b> (plūrāle tantum), quod significat 'obscūritās' vel 'calīgō'. <i>Umbra</i> (umbra, umbrae, f.) significat 'umbram', quae est absentia lūcis, sed <i>tenebrāe</i> est contrārium directius." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>audāx</b>?", options: ["stultus", "timidus", "fortis", "prūdēns"], i: 1, explanation: "Adiectīvum <b>audāx</b> significat 'audāx' vel 'temerārius'. Eius contrārium est <b>timidus</b>, quod significat 'timidus' vel 'pavidus'. Quamquam <i>fortis</i> (fortis, forte) significat 'fortis', <i>audāx</i> saepe implicat temerāritātem, contrāriam timōrī." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>vīvō</b>?", options: ["dormiō", "moriōr", "labōrō", "ambulō"], i: 1, explanation: "Verbum <b>vīvō</b> significat 'vīvere' vel 'spīrāre'. Eius contrārium est <b>moriōr</b> (depōnēns), quod significat 'morī' vel 'dēfūnctus esse'. Cēterae optiōnēs sunt aliī actūs vītae." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>superus</b>?", options: ["medius", "īnferus", "extrēmus", "prīmus"], i: 1, explanation: "Adiectīvum <b>superus</b> significat 'superiōr' vel 'altior'. Eius contrārium est <b>īnferus</b>, quod significat 'īnferiōr' vel 'īmus'. Cēterae optiōnēs describunt aliās positiōnēs vel ordōnem." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>plēnus</b>?", options: ["magnus", "parvus", "vacuus", "sēcūrus"], i: 2, explanation: "Adiectīvum <b>plēnus</b> significat 'plēnus' vel 'repertus'. Eius contrārium est <b>vacuus</b>, quod significat 'vacuus' vel 'inānis'. Cēterae optiōnēs describunt magnitudinem vel statum mentis." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>cōnfiteor</b>?", options: ["laudō", "negō", "crēdō", "sciō"], i: 1, explanation: "Verbum <b>cōnfiteor</b> (depōnēns) significat 'cōnfitērī' vel 'fateri'. Eius contrārium est <b>negō</b>, quod significat 'negāre' vel 'dēmentīrī'. Cēterae optiōnēs sunt aliī actūs mentis vel vocis." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbī <b>fortiter</b>?", options: ["celeriter", "lentē", "graviter", "timidē"], i: 3, explanation: "Adverbium <b>fortiter</b> significat 'fortiter' vel 'audācter'. Eius contrārium est <b>timidē</b>, quod significat 'timidē' vel 'pavidē'. Cēterae optiōnēs sunt adverbia modī, sed nōn contrāria 'fortiter'." }, { meta: "Odd One Out", stem: "Which of the following verbs does NOT belong with the others?", options: ["proficīscor", "gradior", "sedeō", "contendō"], i: 2, explanation: "The correct answer is <b>sedeō</b>. <i>Proficīscor</i> (to set out), <i>gradior</i> (to step, walk), and <i>contendō</i> (to hasten, strive) are all verbs indicating motion. <i>Sedeō</i> (to sit) indicates a state of rest or stasis." }, { meta: "Odd One Out", stem: "Which of the following nouns does NOT belong with the others?", options: ["centuriō", "lēgātus", "eques", "cīvis"], i: 3, explanation: "The correct answer is <b>cīvis</b>. <i>Centuriō</i> (centurion), <i>lēgātus</i> (lieutenant, envoy), and <i>eques</i> (horseman, knight, cavalryman) are all terms related to military ranks or specific military roles/social classes with military implications. <i>Cīvis</i> (citizen) is a general term for an inhabitant of a city or state, not specifically a military role." }, { meta: "Odd One Out", stem: "Which of the following verbs does NOT belong with the others?", options: ["sequor", "loquor", "patior", "petō"], i: 3, explanation: "The correct answer is <b>petō</b>. <i>Sequor</i> (to follow), <i>loquor</i> (to speak), and <i>patior</i> (to suffer, endure) are all deponent verbs, meaning they have passive forms but active meanings. <i>Petō</i> (to seek, ask, attack) is an active verb." }, { meta: "Odd One Out", stem: "Which of the following nouns does NOT belong with the others?", options: ["virtūs", "clementia", "fīdēs", "superbia"], i: 3, explanation: "The correct answer is <b>superbia</b>. <i>Virtūs</i> (courage, excellence), <i>clementia</i> (clemency, mercy), and <i>fīdēs</i> (faith, loyalty) are all considered virtues or positive qualities. <i>Superbia</i> (pride, arrogance) is generally considered a vice or negative quality." }, { meta: "Odd One Out", stem: "Which of the following nouns does NOT belong with the others?", options: ["iter", "vīs", "urbs", "bōs"], i: 2, explanation: "The correct answer is <b>urbs</b>. <i>Iter, itineris</i> (journey), <i>vīs, (vīs)</i> (force), and <i>bōs, bovis</i> (ox, cow) are all irregular third declension nouns. <i>Urbs, urbis</i> (city) is a regular third declension noun." }, { meta: "Odd One Out", stem: "Which of the following adverbs does NOT belong with the others?", options: ["hīc", "nunc", "tum", "semper"], i: 0, explanation: "The correct answer is <b>hīc</b>. <i>Nunc</i> (now), <i>tum</i> (then), and <i>semper</i> (always) are all adverbs of time. <i>Hīc</i> (here) is an adverb of place." }, { meta: "Odd One Out", stem: "Which of the following words does NOT belong with the others?", options: ["autem", "nam", "ob", "igitur"], i: 2, explanation: "The correct answer is <b>ob</b>. <i>Autem</i> (however), <i>nam</i> (for), and <i>igitur</i> (therefore) are all conjunctions. <i>Ob</i> (on account of, because of) is a preposition that takes the accusative case." }, { meta: "Odd One Out", stem: "Which of the following nouns does NOT belong with the others?", options: ["caput", "manus", "arma", "pēs"], i: 2, explanation: "The correct answer is <b>arma</b>. <i>Caput</i> (head), <i>manus</i> (hand), and <i>pēs</i> (foot) are all terms for parts of the human body. <i>Arma</i> (arms, weapons) refers to implements for fighting, not anatomical limbs." }, { meta: "Odd One Out", stem: "Which of the following verbs does NOT belong with the others?", options: ["dīcō", "loquor", "audiō", "nārrō"], i: 2, explanation: "The correct answer is <b>audiō</b>. <i>Dīcō</i> (to say, speak), <i>loquor</i> (to speak), and <i>nārrō</i> (to tell, relate) are all verbs of speaking or communicating verbally. <i>Audiō</i> (to hear, listen) is a verb of perception." }, { meta: "Odd One Out", stem: "Which of the following nouns does NOT belong with the others?", options: ["ager", "rūs", "colōnus", "forum"], i: 3, explanation: "The correct answer is <b>forum</b>. <i>Ager</i> (field, land), <i>rūs</i> (countryside), and <i>colōnus</i> (farmer) are all terms associated with rural life, agriculture, or the countryside. <i>Forum</i> (forum, marketplace) is a term associated with urban life and public spaces within a city." }, { meta: "Analogies", stem: "<b>proficīscor</b> : <b>profectiō</b> :: <b>sequor</b> : X", options: ["<b>secūtiō</b>", "<b>sequēns</b>", "<b>secūtus</b>", "<b>sequor</b>"], i: 0, explanation: "The relationship is Verb : Noun of Action. <i>Proficīscor</i> (to set out, depart) relates to <i>profectiō</i> (a setting out, departure). Similarly, <i>sequor</i> (to follow) relates to <i>secūtiō</i> (a following, pursuit). Options B and C are participles, and D is the verb itself, not the noun of action." }, { meta: "Analogies", stem: "<b>impedīmenta</b> : <b>sarcina</b> :: <b>castra</b> : X", options: ["<b>tentōrium</b>", "<b>vallum</b>", "<b>agmen</b>", "<b>legiō</b>"], i: 0, explanation: "The relationship is Collective Noun (plural for 'baggage') : Individual Item within the collective. <i>Impedīmenta</i> (baggage, plural) refers to the collective items carried, and <i>sarcina</i> is an individual pack or burden. Similarly, <i>castra</i> (camp, plural in form but singular in meaning for 'a camp') is a collective structure, and <i>tentōrium</i> (tent) is an individual component of a camp. <i>Vallum</i> is a part of the fortification, <i>agmen</i> is a marching column, and <i>legiō</i> is a unit of soldiers, not a physical part of the camp structure." }, { meta: "Analogies", stem: "<b>fugiō</b> : <b>fugāx</b> :: <b>loquor</b> : X", options: ["<b>loquāx</b>", "<b>locūtus</b>", "<b>loquēns</b>", "<b>locūtiō</b>"], i: 0, explanation: "The relationship is Verb : Adjective describing a tendency or characteristic. <i>Fugiō</i> (to flee) relates to <i>fugāx</i> (fleeting, prone to fleeing). Similarly, <i>loquor</i> (to speak) relates to <i>loquāx</i> (talkative, prone to speaking). Options B and C are participles, and D is a noun." }, { meta: "Analogies", stem: "<b>rēgnum</b> : <b>rēx</b> :: <b>imperium</b> : X", options: ["<b>imperātor</b>", "<b>imperium</b>", "<b>imperō</b>", "<b>imperiōsē</b>"], i: 0, explanation: "The relationship is Office/Power : Holder of the Office/Power. <i>Rēgnum</i> (kingship, royal power) relates to <i>rēx</i> (king). Similarly, <i>imperium</i> (command, supreme power) relates to <i>imperātor</i> (commander, emperor). Option B is the same word as <i>word3</i>, C is a verb, and D is an adverb." }, { meta: "Analogies", stem: "<b>multus</b> : <b>multum</b> :: <b>magnus</b> : X", options: ["<b>magnopere</b>", "<b>magnē</b>", "<b>magnitūdō</b>", "<b>maximē</b>"], i: 0, explanation: "The relationship is Adjective : Adverb. <i>Multus</i> (much, many - adjective) relates to <i>multum</i> (much, a lot - adverb). Similarly, <i>magnus</i> (great, large - adjective) relates to <i>magnopere</i> (greatly, exceedingly - adverb). <i>Magnē</i> is not the standard adverbial form for <i>magnus</i>. <i>Magnitūdō</i> is a noun, and <i>maximē</i> is the superlative adverb." }, { meta: "Analogies", stem: "<b>hortor</b> : <b>hortātiō</b> :: <b>cohortor</b> : X", options: ["<b>cohortātiō</b>", "<b>cohortāns</b>", "<b>cohortātus</b>", "<b>cohortātor</b>"], i: 0, explanation: "The relationship is Verb : Noun of Action. <i>Hortor</i> (to urge) relates to <i>hortātiō</i> (exhortation). Similarly, <i>cohortor</i> (to encourage) relates to <i>cohortātiō</i> (encouragement). Options B and C are participles. Option D, <i>cohortātor</i>, is a noun for the agent (the one who encourages), not the act of encouraging." }, { meta: "Analogies", stem: "<b>pāx</b> : <b>pācātus</b> :: <b>iter</b> : X", options: ["<b>itinerārius</b>", "<b>iterum</b>", "<b>iterō</b>", "<b>itinere</b>"], i: 0, explanation: "The relationship is Noun : Adjective derived from or describing the noun. <i>Pāx</i> (peace) relates to <i>pācātus</i> (peaceful, pacified - adjective). Similarly, <i>iter</i> (journey) relates to <i>itinerārius</i> (relating to a journey, itinerary - adjective). <i>Iterum</i> is an adverb, <i>iterō</i> is a verb, and <i>itinere</i> is an ablative form of the noun <i>iter</i>." }, { meta: "Analogies", stem: "<b>Rōmānus</b> (adj.) : <b>Rōmānus</b> (noun) :: <b>vīcīnus</b> (adj.) : X", options: ["<b>vīcīnus</b> (noun)", "<b>vīcīnitās</b>", "<b>vīcus</b>", "<b>vīcīne</b>"], i: 0, explanation: "The relationship is Adjective : Noun (referring to a person described by the adjective). <i>Rōmānus</i> (Roman - adjective) relates to <i>Rōmānus</i> (a Roman - noun, referring to a person). Similarly, <i>vīcīnus</i> (neighboring - adjective) relates to <i>vīcīnus</i> (a neighbor - noun, referring to a person). <i>Vīcīnitās</i> is the noun for 'neighborhood', <i>vīcus</i> is 'village', and <i>vīcīne</i> is an adverb." }, { meta: "Analogies", stem: "<b>cōnsilium</b> : <b>cōnsulō</b> :: <b>cōnsuētūdō</b> : X", options: ["<b>cōnsuēscō</b>", "<b>cōnsuētus</b>", "<b>cōnsuētē</b>", "<b>cōnsuēdī</b>"], i: 0, explanation: "The relationship is Noun : Verb (action associated with the noun). <i>Cōnsilium</i> (plan, counsel) relates to <i>cōnsulō</i> (to consult, plan, deliberate). Similarly, <i>cōnsuētūdō</i> (custom, habit) relates to <i>cōnsuēscō</i> (to accustom oneself, become accustomed). <i>Cōnsuētus</i> is a participle/adjective, <i>cōnsuētē</i> is an adverb, and <i>cōnsuēdī</i> is a perfect tense form of the verb, not the infinitive or present stem." }, { meta: "Analogies", stem: "<b>philosophia</b> : <b>philosophus</b> :: <b>mīlitia</b> : X", options: ["<b>mīles</b>", "<b>mīlitāris</b>", "<b>mīlitō</b>", "<b>castra</b>"], i: 0, explanation: "The relationship is Noun (abstract concept/field) : Noun (person associated with that concept/field). <i>Philosophia</i> (philosophy) relates to <i>philosophus</i> (philosopher). Similarly, <i>mīlitia</i> (military service, warfare) relates to <i>mīles</i> (soldier). <i>Mīlitāris</i> is an adjective, <i>mīlitō</i> is a verb, and <i>castra</i> is a noun for 'camp', not a person." }, { meta: "Fill-in-the-Blank", stem: "Caesar cum legiōnibus ad Rhēnum _________, ut Germānōs prohibēret.", options: ["profectus est", "proficīscētur", "proficīscī", "profuit"], i: 0, explanation: "The sentence describes a completed past action by Caesar: 'Caesar, with his legions, _____ to the Rhine, so that he might keep back the Germans.' The verb 'proficīscor' (to set out, depart) is deponent. Option A, <b>profectus est</b>, is the perfect active indicative, third person singular, meaning 'he set out,' which fits the context perfectly. Option B, <b>proficīscētur</b>, is future tense ('he will set out'). Option C, <b>proficīscī</b>, is the present infinitive ('to set out') and cannot serve as the main verb of the sentence. Option D, <b>profuit</b>, comes from 'prōsum' (to be useful, benefit) and means 'he benefited,' which is semantically incorrect." }, { meta: "Fill-in-the-Blank", stem: "Longum _________ per Alpēs fēcērunt.", options: ["itineris", "iter", "itinere", "itinera"], i: 1, explanation: "The sentence means 'They made a long _____ through the Alps.' The verb 'fēcērunt' (they made) requires a direct object in the accusative case. The noun 'iter, itineris' (journey, route) is an irregular neuter noun of the third declension. Option B, <b>iter</b>, is the nominative/accusative singular form, fitting the role of the direct object 'a long journey.' Option A, <b>itineris</b>, is genitive singular ('of a journey'). Option C, <b>itinere</b>, is ablative singular ('by/from/with a journey'). Option D, <b>itinera</b>, is nominative/accusative plural ('journeys'), but the adjective 'longum' (long) is singular." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs gravia _________ trāns flūmen portāvērunt.", options: ["arma", "impedīmenta", "castra", "praesidia"], i: 1, explanation: "The sentence means 'The soldiers carried heavy _____ across the river.' The adjective 'gravia' (heavy) strongly suggests baggage. Option B, <b>impedīmenta</b> (baggage, equipment), is a neuter plural noun often used in military contexts and fits perfectly with 'gravia' and 'portāvērunt' (carried). Option A, <b>arma</b> (arms, weapons), could be carried, but 'gravia' is a more natural fit for baggage. Option C, <b>castra</b> (camp), is plural but not something one 'carries' across a river in this sense. Option D, <b>praesidia</b> (guards, garrisons), does not fit the context of being 'heavy' or 'carried' in this manner." }, { meta: "Fill-in-the-Blank", stem: "Hostēs mūrum ascendere _________, sed ā Rōmānīs repulsī sunt.", options: ["cōnābantur", "cōnātī sunt", "cōnantur", "cōnantēs"], i: 1, explanation: "The sentence means 'The enemy _____ to climb the wall, but were repulsed by the Romans.' This describes a completed past attempt that was met with failure. The verb 'cōnor' (to try, attempt) is deponent. Option B, <b>cōnātī sunt</b>, is the perfect active indicative, third person plural, meaning 'they tried/attempted,' which perfectly matches the plural subject 'Hostēs' and the past context established by 'repulsī sunt.' Option A, <b>cōnābantur</b>, is the imperfect tense ('they were trying'), which could imply an ongoing attempt, but the perfect tense often provides a more direct narrative of a completed action leading to a result. Option C, <b>cōnantur</b>, is present tense ('they try'). Option D, <b>cōnantēs</b>, is a present participle ('trying') and cannot serve as the main verb." }, { meta: "Fill-in-the-Blank", stem: "Dux signum dedit et mīlitēs _________ parātī erant.", options: ["proelium committere", "proeliō committendō", "proeliī commissiōnis", "proeliīs committere"], i: 0, explanation: "The sentence means 'The leader gave the signal and the soldiers were ready _____.' The phrase 'parātī erant' (they were ready) typically takes an infinitive to express what they were ready to do. The idiomatic expression for 'to join battle' is 'proelium committere.' Option A, <b>proelium committere</b>, is the correct infinitive phrase. Option B, <b>proeliō committendō</b>, is a gerundive in the ablative case, which does not fit the grammatical construction here. Option C, <b>proeliī commissiōnis</b>, uses a less common noun 'commissiō' and is in the genitive case, which is grammatically incorrect. Option D, <b>proeliīs committere</b>, uses the plural 'proeliīs' (battles) which doesn't fit the singular context of 'joining battle' in this idiom." }, { meta: "Fill-in-the-Blank", stem: "Magna _________ hostium urbem oppugnāvit.", options: ["vīribus", "vī", "vīs", "vim"], i: 2, explanation: "The sentence means 'A great _____ of the enemy attacked the city.' The verb 'oppugnāvit' (attacked) is singular, requiring a singular subject. The noun 'vīs, vīs' (force, strength) is an irregular third declension noun. Option C, <b>vīs</b>, is the nominative singular form, meaning 'force' or 'strength,' and correctly serves as the subject of the sentence. Option A, <b>vīribus</b>, is dative/ablative plural ('to/by/with forces'). Option B, <b>vī</b>, is ablative singular ('by/with force'). Option D, <b>vim</b>, is accusative singular ('force'), used as a direct object." }, { meta: "Fill-in-the-Blank", stem: "Lēgātus imperātōrem _________ per silvam.", options: ["sequēbātur", "secūtus est", "sequī", "secūtus"], i: 0, explanation: "The sentence means 'The legate _____ the general through the forest.' The verb 'sequor' (to follow) is deponent. The phrase 'per silvam' (through the forest) suggests an ongoing or continuous action in the past. Option A, <b>sequēbātur</b>, is the imperfect active indicative, third person singular, meaning 'he was following,' which perfectly captures this continuous past action. Option B, <b>secūtus est</b>, is the perfect active indicative ('he followed'), which would imply a completed action. While grammatically possible, the imperfect fits the nuance of 'through the forest' better. Option C, <b>sequī</b>, is the present infinitive ('to follow'). Option D, <b>secūtus</b>, is a perfect participle ('having followed') and cannot serve as the main verb." }, { meta: "Fill-in-the-Blank", stem: "Post bellum, cīvēs _________ dēsīderābant.", options: ["bellum", "pācem", "victōriam", "glōriam"], i: 1, explanation: "The sentence means 'After the war, the citizens desired _____.' The verb 'dēsīderābant' (they desired) requires a direct object in the accusative case. The most logical desire 'after war' is peace. Option B, <b>pācem</b>, is the accusative singular of 'pāx, pācis' (peace), fitting the context perfectly. Option A, <b>bellum</b> (war), is the opposite of what would be desired after a war. Option C, <b>victōriam</b> (victory), might be desired during or immediately after a war, but 'peace' is the more encompassing desire for the aftermath. Option D, <b>glōriam</b> (glory), is less directly related to the immediate aftermath of war than peace." }, { meta: "Fill-in-the-Blank", stem: "Imperātor mīlitēs fortiter pugnāre _________.", options: ["hortātus est", "hortātur", "hortārī", "hortābātur"], i: 0, explanation: "The sentence means 'The general _____ the soldiers to fight bravely.' The verb 'hortor' (to encourage, urge) is deponent and often takes an infinitive (or ut/nē clause) to express the action being urged. The context implies a completed action of encouragement in the past. Option A, <b>hortātus est</b>, is the perfect active indicative, third person singular, meaning 'he encouraged/urged,' which is the most appropriate tense for a narrative statement of the general's action. Option B, <b>hortātur</b>, is present tense ('he encourages'). Option C, <b>hortārī</b>, is the present infinitive ('to encourage') and cannot be the main verb. Option D, <b>hortābātur</b>, is imperfect tense ('he was encouraging'), which is plausible but the perfect tense often provides a more direct statement of a completed command or encouragement." }, { meta: "Fill-in-the-Blank", stem: "Nōn _________ diērum ad iter nōbīs dabitur.", options: ["plūrēs", "plūs", "multa", "plūra"], i: 1, explanation: "The sentence means 'Not _____ days will be given to us for the journey.' The phrase 'nōn plūs' (not more) is a common construction in Latin, where 'plūs' (more) is an irregular neuter noun/adjective that often takes a partitive genitive. Here, 'diērum' (of days) is a partitive genitive. Option B, <b>plūs</b>, is the correct form to mean 'more' when followed by a genitive plural. Option A, <b>plūrēs</b>, is the nominative/accusative plural (masculine/feminine) of the adjective 'plūris' and would not be used with a partitive genitive 'diērum.' Option C, <b>multa</b>, means 'many' or 'much' but not 'more.' Option D, <b>plūra</b>, is the nominative/accusative plural (neuter) of 'plūris,' but 'plūs' is the standard for 'more of X' with a partitive genitive." }, { meta: "Circumlocution", stem: 'Quod verbum significat: "Post alium ambulāre aut eum cōnsequī"?', options: ["<b>sequor, sequī, secūtus sum</b>", "<b>loquor, loquī, locūtus sum</b>", "<b>gradior, gradī, gressus sum</b>", "<b>patior, patī, passus sum</b>"], i: 0, explanation: 'The Latin description "Post alium ambulāre aut eum cōnsequī" means "to walk after another or to overtake him," which perfectly defines the deponent verb <b>sequor, sequī, secūtus sum</b>, meaning "to follow, pursue."<br><br>Option B, <b>loquor</b>, means "to speak."<br>Option C, <b>gradior</b>, means "to step, walk," which is related but does not include the idea of following someone.<br>Option D, <b>patior</b>, means "to suffer, endure."' }, { meta: "Circumlocution", stem: 'Quod nōmen significat: "Locus mūnītus ubi mīlitēs habitant"?', options: ["<b>castra, castrōrum</b> n. pl.", "<b>urbs, urbis</b> f.", "<b>vīcus, vīcī</b> m.", "<b>praesidium, praesidiī</b> n."], i: 0, explanation: 'The description "Locus mūnītus ubi mīlitēs habitant" refers to a "fortified place where soldiers live," which is the definition of a military camp, known in Latin as <b>castra, castrōrum</b> (a plural-only noun).<br><br>Option B, <b>urbs</b>, means "city."<br>Option C, <b>vīcus</b>, means "village" or "street."<br>Option D, <b>praesidium</b>, means "garrison, protection," which can be related but does not specifically mean the camp itself.' }, { meta: "Circumlocution", stem: 'Quod verbum significat: "Dolōrem aut labōrem ferre"?', options: ["<b>patior, patī, passus sum</b>", "<b>morior, morī, mortuus sum</b>", "<b>orior, orīrī, ortus sum</b>", "<b>gaudeō, gaudēre, gāvīsus sum</b>"], i: 0, explanation: 'The phrase "Dolōrem aut labōrem ferre" translates to "to bear pain or toil," which is the core meaning of the deponent verb <b>patior, patī, passus sum</b>, "to suffer, endure."<br><br>Option B, <b>morior</b>, means "to die."<br>Option C, <b>orior</b>, means "to rise, arise."<br>Option D, <b>gaudeō</b>, a semi-deponent verb, means "to rejoice," which is the opposite of suffering.' }, { meta: "Circumlocution", stem: 'Quod nōmen significat: "Structūra quae super flūmen aut fossam trānsitum praebet"?', options: ["<b>pōns, pontis</b> m.", "<b>mūrus, mūrī</b> m.", "<b>agger, aggeris</b> m.", "<b>fossa, fossae</b> f."], i: 0, explanation: 'The description "Structūra quae super flūmen aut fossam trānsitum praebet" means "a structure which provides passage over a river or ditch." This accurately describes a <b>pōns, pontis</b>, or "bridge."<br><br>Option B, <b>mūrus</b>, means "wall."<br>Option C, <b>agger</b>, means "mound, rampart."<br>Option D, <b>fossa</b>, means "ditch," which is something a bridge might cross, but not the bridge itself.' }, { meta: "Circumlocution", stem: 'Quod verbum significat: "Alīquid agere temptāre aut studēre"?', options: ["<b>cōnor, cōnārī, cōnātus sum</b>", "<b>hortor, hortārī, hortātus sum</b>", "<b>moror, morārī, morātus sum</b>", "<b>arbitror, arbitrārī, arbitrātus sum</b>"], i: 0, explanation: 'The phrase "Alīquid agere temptāre aut studēre" means "to try to do something or to be eager for it," which is the definition of the deponent verb <b>cōnor, cōnārī, cōnātus sum</b>, "to try, attempt."<br><br>Option B, <b>hortor</b>, means "to encourage."<br>Option C, <b>moror</b>, means "to delay."<br>Option D, <b>arbitror</b>, means "to think, judge." These are all first conjugation deponents, making them plausible distractors based on form.' }, { meta: "Circumlocution", stem: 'Quod nōmen significat: "Anima fīrma et intrēpida in perīculō"?', options: ["<b>fortitūdō, fortitūdinis</b> f.", "<b>virtūs, virtūtis</b> f.", "<b>timor, timōris</b> m.", "<b>audācia, audāciae</b> f."], i: 0, explanation: 'The description "Anima fīrma et intrēpida in perīculō" means "a firm and fearless spirit in danger," which is the precise definition of <b>fortitūdō, fortitūdinis</b>, "courage, bravery."<br><br>Option B, <b>virtūs</b>, can mean "courage," but its primary meaning is "virtue, excellence," and <b>fortitūdō</b> is more specific to bravery in the face of danger.<br>Option C, <b>timor</b>, means "fear," which is the opposite of courage.<br>Option D, <b>audācia</b>, means "boldness, daring," which can sometimes be positive but often carries a negative connotation of recklessness.' }, { meta: "Circumlocution", stem: 'Quod verbum significat: "Alīquid in servitūtem adhibēre aut ad rem faciendam adhibēre"?', options: ["<b>ūtor, ūtī, ūsus sum</b>", "<b>fruor, fruī, frūctus sum</b>", "<b>potior, potīrī, potītus sum</b>", "<b>fungor, fungī, fūnctus sum</b>"], i: 0, explanation: 'The description "Alīquid in servitūtem adhibēre aut ad rem faciendam adhibēre" means "to apply something to service or to apply it for doing a thing," which is the definition of the deponent verb <b>ūtor, ūtī, ūsus sum</b>, "to use, employ." This verb commonly takes the ablative case.<br><br>Options B, C, and D are all deponent verbs that also take the ablative case, making them strong distractors:<br><b>fruor</b> means "to enjoy."<br><b>potior</b> means "to get possession of, obtain."<br><b>fungor</b> means "to perform, discharge (a duty)."' }, { meta: "Circumlocution", stem: 'Quod prōnōmen significat: "Omnis singulāris numerō"?', options: ["<b>quisque, quaeque, quodque</b>", "<b>quīdam, quaedam, quoddam</b>", "<b>alius, alia, aliud</b>", "<b>ūnus, ūna, ūnum</b>"], i: 0, explanation: 'The phrase "Omnis singulāris numerō" means "every one in singular number," which accurately describes the indefinite pronoun <b>quisque, quaeque, quodque</b>, meaning "each, every (one)."<br><br>Option B, <b>quīdam</b>, means "a certain (one)."<br>Option C, <b>alius</b>, means "another, other."<br>Option D, <b>ūnus</b>, means "one."' }, { meta: "Circumlocution", stem: 'Quod verbum significat: "Ex locō movērī aut iter incipere"?', options: ["<b>proficīscor, proficīscī, profectus sum</b>", "<b>revertor, revertī, reversus sum</b>", "<b>progredior, progredī, progressus sum</b>", "<b>ingredior, ingredī, ingressus sum</b>"], i: 0, explanation: 'The description "Ex locō movērī aut iter incipere" means "to be moved from a place or to begin a journey," which is the definition of the deponent verb <b>proficīscor, proficīscī, profectus sum</b>, "to set out, depart."<br><br>Option B, <b>revertor</b>, means "to return," which is the opposite.<br>Option C, <b>progredior</b>, means "to go forward, advance," which is a more specific type of movement.<br>Option D, <b>ingredior</b>, means "to enter," which implies moving into a place rather than setting out from one.' }, { meta: "Circumlocution", stem: 'Quod nōmen significat: "Agger aut mūnīmentum ex terrā factum ad castra dēfendenda"?', options: ["<b>vallum, vallī</b> n.", "<b>mūrus, mūrī</b> m.", "<b>turris, turris</b> f.", "<b>fossa, fossae</b> f."], i: 0, explanation: 'The description "Agger aut mūnīmentum ex terrā factum ad castra dēfendenda" means "a mound or fortification made from earth for defending a camp." This precisely defines a <b>vallum, vallī</b>, or "rampart," which was typically an earthen wall often topped with a palisade.<br><br>Option B, <b>mūrus</b>, means "wall," usually implying stone.<br>Option C, <b>turris</b>, means "tower."<br>Option D, <b>fossa</b>, means "ditch," which often accompanied a rampart but is not the rampart itself.' }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>agō, agere, ēgī, āctus</b>", options: ["to do, drive", "to be sick", "to plow a field", "to act with difficulty"], i: 0, explanation: "The verb <b>agō</b> means 'to do, drive, lead, act'. Option B is related to <b>aeger</b> (sick). Option C relates to <b>ager</b> (field). Option D relates to <b>aegrē</b> (with difficulty)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>arbitror, arbitrārī, arbitrātus sum</b>", options: ["to judge, think", "to plant a tree", "to make a decision", "having judged"], i: 0, explanation: "The deponent verb <b>arbitror</b> means 'to judge, think, consider'. Option B relates to <b>arbor</b> (tree). Option C refers to the noun <b>arbitrium</b> (judgment, decision). Option D is the translation of the perfect passive participle <b>arbitrātus</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>cōnor, cōnārī, cōnātus sum</b>", options: ["to try, attempt", "to blow a horn", "to plan, devise", "to consult"], i: 0, explanation: "The deponent verb <b>cōnor</b> means 'to try, attempt'. Option B relates to <b>cornū</b> (horn). Option C refers to the noun <b>cōnsilium</b> (plan, counsel). Option D relates to <b>cōnsulō</b> (to consult)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>dēbeō, dēbēre, dēbuī, dēbitus</b>", options: ["to owe, ought", "to destroy", "to be lacking", "a debt"], i: 0, explanation: "The verb <b>dēbeō</b> means 'to owe, ought'. Option B is the translation of <b>dēleō</b> (to destroy). Option C is the translation of <b>dēsum</b> (to be lacking). Option D is the translation of the noun <b>dēbitum</b> (debt)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>discēdō, discēdere, discessī, discessūrus</b>", options: ["to depart, go away", "to learn", "to say, speak", "to disagree"], i: 0, explanation: "The verb <b>discēdō</b> means 'to depart, go away'. Option B is the translation of <b>discō</b> (to learn). Option C is the translation of <b>dīcō</b> (to say, speak). Option D relates to <b>discōrdia</b> (discord)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>ferō, ferre, tulī, lātum</b>", options: ["to bear, carry, bring", "to be wild", "to forge iron", "almost, nearly"], i: 0, explanation: "The irregular verb <b>ferō</b> means 'to bear, carry, bring, endure'. Option B relates to <b>ferus</b> (wild, savage). Option C relates to <b>ferrum</b> (iron, sword). Option D is the translation of the adverb <b>fere</b> (almost, nearly)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>hortor, hortārī, hortātus sum</b>", options: ["to urge, encourage", "to cultivate a garden", "to feel dread", "to begin"], i: 0, explanation: "The deponent verb <b>hortor</b> means 'to urge, encourage'. Option B relates to <b>hortus</b> (garden). Option C relates to <b>horror</b> (horror, dread). Option D is the translation of <b>ōrdior</b> (to begin), which has a similar ending." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>loquor, loquī, locūtus sum</b>", options: ["to speak, say", "to find a place", "to flow like liquid", "to be talkative"], i: 0, explanation: "The deponent verb <b>loquor</b> means 'to speak, say'. Option B relates to <b>locus</b> (place). Option C relates to <b>liquor</b> (liquid). Option D relates to the adjective <b>loquāx</b> (talkative)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>moror, morārī, morātus sum</b>", options: ["to delay", "to follow a custom", "to die", "to suffer death"], i: 0, explanation: "The deponent verb <b>moror</b> means 'to delay'. Option B relates to <b>mōs</b> (custom, manner). Option C is the translation of <b>mōrior</b> (to die). Option D relates to <b>mors</b> (death)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>patior, patī, passus sum</b>", options: ["to suffer, endure, allow", "to be a father", "to love one's homeland", "to get possession of"], i: 0, explanation: "The deponent verb <b>patior</b> means 'to suffer, endure, allow'. Option B relates to <b>pater</b> (father). Option C relates to <b>patria</b> (homeland). Option D is the translation of another deponent verb, <b>potior</b> (to get possession of)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>sequor, sequī, secūtus sum</b>", options: ["to follow", "thus, so", "often", "to be second"], i: 0, explanation: "The deponent verb <b>sequor</b> means 'to follow'. Option B is the translation of the adverb <b>sīc</b> (thus, so). Option C is the translation of the adverb <b>saepe</b> (often). Option D relates to the adjective <b>secundus</b> (second, favorable)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>ūtor, ūtī, ūsus sum</b>", options: ["to use, employ (with ablative)", "to be one", "to have experience", "to be useful"], i: 0, explanation: "The deponent verb <b>ūtor</b> means 'to use, employ' and takes the ablative case. Option B relates to <b>ūnus</b> (one). Option C relates to the noun <b>ūsus</b> (use, experience). Option D relates to the adjective <b>ūtilis</b> (useful)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>vereor, verērī, veritus sum</b>", options: ["to fear, respect", "to be true", "to speak a word", "to turn"], i: 0, explanation: "The deponent verb <b>vereor</b> means 'to fear, respect'. Option B relates to <b>vērus</b> (true). Option C relates to <b>verbum</b> (word). Option D is the translation of <b>vertō</b> (to turn)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>volō, velle, voluī</b>", options: ["to wish, want, be willing", "to fly", "to feel pleasure", "to roll a book"], i: 0, explanation: "The irregular verb <b>volō</b> means 'to wish, want, be willing'. Option B is the translation of the first conjugation verb <b>volō, volāre</b> (to fly). Option C relates to <b>voluptās</b> (pleasure). Option D relates to <b>volūmen</b> (roll, book)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>vīvō, vīvere, vīxī, vīctūrus</b>", options: ["to live, be alive", "to conquer", "to travel a road", "to drink wine"], i: 0, explanation: "The verb <b>vīvō</b> means 'to live, be alive'. Option B is the translation of <b>vincō</b> (to conquer). Option C relates to <b>via</b> (road, way). Option D relates to <b>vīnum</b> (wine)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to use</b>", options: ["ūtor, ūtī, ūsus sum", "adhibeō, adhibēre, adhibuī, adhibitum", "ūtilis, ūtile", "ūtere, ūtī, ūsus est"], i: 0, explanation: "The verb <b>ūtor, ūtī, ūsus sum</b> is a deponent verb meaning 'to use' and regularly takes the ablative case. Option B, <b>adhibeō</b>, means 'to apply, employ,' which is a synonym but less direct for 'to use' in the sense of employing something. Option C is an adjective meaning 'useful.' Option D has incorrect principal parts." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to seem</b>", options: ["videor, vidērī, vīsus sum", "appāreō, appārēre, appāruī, appāritum", "similis, simile", "putō, putāre, putāvī, putātum"], i: 0, explanation: "The deponent verb <b>videor, vidērī, vīsus sum</b> is the passive of <b>videō</b> ('to see') and means 'to seem' or 'to be seen.' Option B, <b>appāreō</b>, means 'to appear, to be visible,' which is close but doesn't quite capture the nuance of 'to seem' in the sense of 'to appear to be' or 'to be thought.' Option C is an adjective meaning 'similar.' Option D, <b>putō</b>, means 'to think, to suppose.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to suffer, to allow</b>", options: ["patior, patī, passus sum", "ferō, ferre, tulī, lātum", "sinō, sinere, sīvī, situm", "doleō, dolēre, doluī, dolitum"], i: 0, explanation: "The deponent verb <b>patior, patī, passus sum</b> means both 'to suffer, endure' and 'to allow, permit.' Option B, <b>ferō</b>, can mean 'to bear, endure,' but <b>patior</b> is more encompassing for 'to suffer' in the sense of experiencing pain or hardship, and explicitly includes 'to allow.' Option C, <b>sinō</b>, means 'to allow, permit,' but does not include 'to suffer.' Option D, <b>doleō</b>, means 'to grieve, to feel pain,' focusing only on the emotional aspect of suffering." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to follow</b>", options: ["sequor, sequī, secūtus sum", "insequor, insequī, insecūtus sum", "subsequor, subsequī, subsecūtus sum", "comitor, comitārī, comitātus sum"], i: 0, explanation: "The deponent verb <b>sequor, sequī, secūtus sum</b> is the general term for 'to follow.' Options B and C are compounds of <b>sequor</b>: <b>insequor</b> means 'to pursue, to follow up,' implying a more aggressive or immediate following, and <b>subsequor</b> means 'to follow closely behind.' Option D, <b>comitor</b>, means 'to accompany,' which implies being with someone, but not necessarily following in their footsteps or direction." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to set out, to depart</b>", options: ["proficīscor, proficīscī, profectus sum", "discēdō, discēdere, discessī, discessum", "abeō, abīre, abiī, abitum", "ēgredior, ēgredī, ēgressus sum"], i: 0, explanation: "The deponent verb <b>proficīscor, proficīscī, profectus sum</b> is commonly used in military contexts (e.g., in Caesar) for 'to set out, to depart' on a journey or expedition. Option B, <b>discēdō</b>, means 'to depart, go away,' and is a good synonym but less specific to setting out for a purpose. Option C, <b>abeō</b>, means 'to go away,' a general term. Option D, <b>ēgredior</b>, means 'to go out, to march out,' which is more specific to exiting a place." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to try, to attempt</b>", options: ["cōnor, cōnārī, cōnātus sum", "temptō, temptāre, temptāvī, temptātum", "experior, experīrī, expertus sum", "studeō, studēre, studuī"], i: 0, explanation: "The deponent verb <b>cōnor, cōnārī, cōnātus sum</b> is the most common and direct translation for 'to try, to attempt,' especially when referring to an undertaking or effort. Option B, <b>temptō</b>, also means 'to try, to test, to attempt,' but can sometimes imply a more tentative or exploratory attempt. Option C, <b>experior</b>, means 'to try, to test, to experience,' often with the nuance of putting something to the test. Option D, <b>studeō</b>, means 'to be eager, to strive for,' implying desire rather than an active attempt." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to fear, to be afraid</b>", options: ["vereor, verērī, veritus sum", "timeō, timēre, timuī", "metuō, metuere, metuī, metūtum", "terreō, terrēre, terruī, territum"], i: 0, explanation: "The deponent verb <b>vereor, verērī, veritus sum</b> means 'to fear,' often with a nuance of respect or reverence, or a cautious apprehension. Option B, <b>timeō</b>, is a general verb for 'to fear.' Option C, <b>metuō</b>, implies a more intense, anxious, or dread-filled fear. Option D, <b>terreō</b>, is transitive and means 'to frighten, to terrify' someone else." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to obtain, to get possession of</b>", options: ["potior, potīrī, potītus sum", "obtineō, obtinēre, obtinuī, obtentum", "acquīrō, acquīrere, acquīsīvī, acquīsītum", "capiō, capere, cēpī, captum"], i: 0, explanation: "The deponent verb <b>potior, potīrī, potītus sum</b> specifically means 'to get possession of, to obtain,' and is notable for taking the ablative or genitive case. Option B, <b>obtineō</b>, means 'to hold, to maintain, to obtain,' but <b>potior</b> is more precise for gaining possession. Option C, <b>acquīrō</b>, means 'to acquire, to gain,' a more general term for acquisition. Option D, <b>capiō</b>, means 'to take, to seize,' implying an active taking rather than necessarily obtaining lasting possession." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to urge, to exhort</b>", options: ["hortor, hortārī, hortātus sum", "moneō, monēre, monuī, monitum", "impellō, impellere, impulī, impulsum", "suādeō, suādēre, suāsī, suāsum"], i: 0, explanation: "The deponent verb <b>hortor, hortārī, hortātus sum</b> is the most direct and common translation for 'to urge, to exhort.' Option B, <b>moneō</b>, means 'to advise, to warn,' which is a softer form of encouragement. Option C, <b>impellō</b>, means 'to drive, to urge on,' often with a stronger, more forceful connotation. Option D, <b>suādeō</b>, means 'to advise, to persuade,' focusing on the act of convincing rather than simply urging." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to speak, to say</b>", options: ["loquor, loquī, locūtus sum", "dīcō, dīcere, dīxī, dictum", "for, fārī, fātus sum", "nārrō, nārrāre, nārrāvī, nārrātum"], i: 0, explanation: "The deponent verb <b>loquor, loquī, locūtus sum</b> is the general term for 'to speak' or 'to talk.' Option B, <b>dīcō</b>, means 'to say, to tell,' often referring to specific utterances or statements. Option C, <b>for</b>, is an archaic and poetic deponent verb for 'to speak, to say,' often used for divine pronouncements. Option D, <b>nārrō</b>, means 'to tell, to relate,' implying a story or account." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>journey, march</b>", options: ["iter, itineris, n.", "via, viae, f.", "cursus, cursūs, m.", "profectiō, profectiōnis, f."], i: 0, explanation: "The irregular noun <b>iter, itineris, n.</b> means 'journey' or 'march,' referring to the act of traveling or the route taken. It is very common in Caesar. Option B, <b>via</b>, refers to the 'road' or 'way' itself, not the act of traveling. Option C, <b>cursus</b>, means 'running, course,' implying speed or a specific route. Option D, <b>profectiō</b>, means 'a setting out, departure,' referring to the act of beginning a journey, not the journey itself." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>force, strength</b>", options: ["vīs, (gen. vīs), f.", "rōbur, rōboris, n.", "potentia, potentiae, f.", "fortitūdō, fortitūdinis, f."], i: 0, explanation: "The irregular noun <b>vīs, (gen. vīs), f.</b> means 'force, power, violence.' Its plural, <b>vīrēs, vīrium</b>, means 'strength, forces.' This noun is particularly tricky due to its irregular singular genitive and its distinct plural meaning. Option B, <b>rōbur</b>, means 'oak, strength, hard wood,' implying inherent, natural strength. Option C, <b>potentia</b>, refers to 'power, political power, influence.' Option D, <b>fortitūdō</b>, means 'bravery, courage,' referring to moral strength." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>courage, valor</b>", options: ["virtūs, virtūtis, f.", "fortitūdō, fortitūdinis, f.", "animus, animī, m.", "audācia, audāciae, f."], i: 0, explanation: "The noun <b>virtūs, virtūtis, f.</b>, while broadly meaning 'manliness, excellence, virtue,' is frequently used to denote 'courage' or 'valor,' especially in a military context, reflecting the Roman ideal of manly excellence. Option B, <b>fortitūdō</b>, means 'bravery, fortitude,' which is a direct synonym for courage but lacks the broader cultural implications of <b>virtūs</b>. Option C, <b>animus</b>, can mean 'spirit, mind, courage,' but <b>virtūs</b> is more formal for valor. Option D, <b>audācia</b>, means 'boldness, daring,' which can be positive but often carries a negative connotation of recklessness." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to gather, to collect</b>", options: ["cōgō, cōgere, coēgī, coāctum", "colligō, colligere, collēgī, collēctum", "congerō, congerere, congessī, congestum", "convocō, convocāre, convocāvī, convocātum"], i: 0, explanation: "The verb <b>cōgō, cōgere, coēgī, coāctum</b> means 'to collect, to compel,' and is very commonly used in military contexts (e.g., in Caesar) for gathering troops or forces. Option B, <b>colligō</b>, means 'to collect, to gather,' and is a general synonym, but <b>cōgō</b> often implies a more forceful or organized collection. Option C, <b>congerō</b>, means 'to heap up, to collect,' implying piling things. Option D, <b>convocō</b>, means 'to call together, to summon,' specifically for people." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to prefer</b>", options: ["mālō, mālle, māluī", "praeferō, praeferre, praetulī, praelātum", "antepōnō, antepōnere, anteposuī, antepositum", "cupiō, cupere, cupīvī, cupītum"], i: 0, explanation: "The irregular verb <b>mālō, mālle, māluī</b> is the most direct and common translation for 'to prefer.' Options B, <b>praeferō</b>, and C, <b>antepōnō</b>, both mean 'to place before, to prefer,' and are good synonyms, but <b>mālō</b> is a distinct irregular verb often tested for its unique conjugation. Option D, <b>cupiō</b>, means 'to desire, to wish for,' which implies a strong wish but not necessarily a preference over alternatives." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>iter</b>?", options: ["via", "tempus", "bellum", "castra"], i: 0, explanation: "Verbum <b>iter</b> significat 'iter, via, cursus'. Verbum <b>via</b> est proximum synonymum, significāns 'via, iter, modus'. Optiō B, <b>tempus</b>, significat 'tempus'. Optiō C, <b>bellum</b>, significat 'bellum'. Optiō D, <b>castra</b>, significat 'castra'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>cōnor</b>?", options: ["sequor", "temptō", "patior", "loquor"], i: 1, explanation: "Verbum dēpōnēns <b>cōnor</b> significat 'cōnārī, temptāre'. Verbum <b>temptō</b> est proximum synonymum, significāns 'temptāre, cōnārī'. Optiō A, <b>sequor</b>, significat 'sequī'. Optiō C, <b>patior</b>, significat 'patī, ferre'. Optiō D, <b>loquor</b>, significat 'loquī'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>proelium</b>?", options: ["pāx", "victōria", "pugna", "arma"], i: 2, explanation: "Verbum <b>proelium</b> significat 'proelium, pugna'. Verbum <b>pugna</b> est proximum synonymum, significāns 'pugna, certāmen'. Optiō A, <b>pāx</b>, significat 'pāx'. Optiō B, <b>victōria</b>, significat 'victōria'. Optiō D, <b>arma</b>, significat 'arma'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>magnus</b>?", options: ["parvus", "celer", "ingēns", "gravis"], i: 2, explanation: "Adiectīvum <b>magnus</b> significat 'magnus, grandis'. Adiectīvum <b>ingēns</b> est proximum synonymum, significāns 'ingēns, immēnsus'. Optiō A, <b>parvus</b>, significat 'parvus' (antonymum). Optiō B, <b>celer</b>, significat 'celer'. Optiō D, <b>gravis</b>, significat 'gravis, ponderōsus'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>hostis</b>?", options: ["amīcus", "cīvis", "inimīcus", "dux"], i: 2, explanation: "Verbum <b>hostis</b> significat 'hostis (publicus), inimīcus'. Verbum <b>inimīcus</b> est proximum synonymum, significāns 'inimīcus (personālis)'. Optiō A, <b>amīcus</b>, significat 'amīcus' (antonymum). Optiō B, <b>cīvis</b>, significat 'cīvis'. Optiō D, <b>dux</b>, significat 'dux, imperātor'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>mīles</b>?", options: ["agricola", "bellātor", "mercātor", "poēta"], i: 1, explanation: "Verbum <b>mīles</b> significat 'mīles, sōldātus'. Verbum <b>bellātor</b> est proximum synonymum, significāns 'bellātor, vir bellī'. Optiō A, <b>agricola</b>, significat 'agricola'. Optiō C, <b>mercātor</b>, significat 'mercātor'. Optiō D, <b>poēta</b>, significat 'poēta'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>urbs</b>?", options: ["vīlla", "cīvitās", "castellum", "pagus"], i: 1, explanation: "Verbum <b>urbs</b> significat 'urbs, cīvitās'. Verbum <b>cīvitās</b> est proximum synonymum, praesertim in contextū Rōmānō, significāns 'cīvitās, status, urbs'. Optiō A, <b>vīlla</b>, significat 'vīlla, domus rūstica'. Optiō C, <b>castellum</b>, significat 'castellum, fortificātiō'. Optiō D, <b>pagus</b>, significat 'pagus, districtus'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>vīnum</b>?", options: ["aqua", "merum", "pānis", "cibus"], i: 1, explanation: "Verbum <b>vīnum</b> significat 'vīnum'. Verbum <b>merum</b> est proximum synonymum, significāns 'vīnum pūrum, vīnum nōn mixtum'. Optiō A, <b>aqua</b>, significat 'aqua'. Optiō C, <b>pānis</b>, significat 'pānis'. Optiō D, <b>cibus</b>, significat 'cibus'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>dōnum</b>?", options: ["praemium", "mūnus", "poena", "pecūnia"], i: 1, explanation: "Verbum <b>dōnum</b> significat 'dōnum, dōnātiō'. Verbum <b>mūnus</b> est proximum synonymum, significāns 'mūnus, dōnum, officium'. Optiō A, <b>praemium</b>, significat 'praemium, recompēnsātiō'. Optiō C, <b>poena</b>, significat 'poena, sānctiō'. Optiō D, <b>pecūnia</b>, significat 'pecūnia'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>loquor</b>?", options: ["audiō", "dīcō", "scrībō", "legō"], i: 1, explanation: "Verbum dēpōnēns <b>loquor</b> significat 'loquī, fārī'. Verbum <b>dīcō</b> est proximum synonymum, significāns 'dīcere, fārī'. Optiō A, <b>audiō</b>, significat 'audīre'. Optiō C, <b>scrībō</b>, significat 'scrībere'. Optiō D, <b>legō</b>, significat 'legere'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>flūmen</b>?", options: ["mare", "amnis", "lacus", "rīpa"], i: 1, explanation: "Verbum <b>flūmen</b> significat 'flūmen, rīvus'. Verbum <b>amnis</b> est proximum synonymum, significāns 'amnis, flūmen'. Optiō A, <b>mare</b>, significat 'mare'. Optiō C, <b>lacus</b>, significat 'lacus'. Optiō D, <b>rīpa</b>, significat 'rīpa, lītus'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>vīs</b>?", options: ["virtūs", "potentia", "fortūna", "voluntās"], i: 1, explanation: "Nōmen irregulāre <b>vīs</b> significat 'vīs, potentia, rōbur'. Verbum <b>potentia</b> est proximum synonymum, significāns 'potentia, facultās'. Optiō A, <b>virtūs</b>, significat 'virtūs, fortitūdō'. Optiō C, <b>fortūna</b>, significat 'fortūna, cāsus'. Optiō D, <b>voluntās</b>, significat 'voluntās, arbitrium'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>timor</b>?", options: ["spēs", "gaudium", "metus", "īra"], i: 2, explanation: "Verbum <b>timor</b> significat 'timor, pavor'. Verbum <b>metus</b> est proximum synonymum, significāns 'metus, timor'. Optiō A, <b>spēs</b>, significat 'spēs' (antonymum). Optiō B, <b>gaudium</b>, significat 'gaudium'. Optiō D, <b>īra</b>, significat 'īra'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>cōnsilium</b>?", options: ["perīculum", "ratiō", "beneficium", "ōrdō"], i: 1, explanation: "Verbum <b>cōnsilium</b> significat 'cōnsilium, plānum, dēlīberātiō'. Verbum <b>ratiō</b> est proximum synonymum, praesertim in contextū 'plānī' vel 'methodī', significāns 'ratiō, modus, cōnsilium'. Optiō A, <b>perīculum</b>, significat 'perīculum'. Optiō C, <b>beneficium</b>, significat 'beneficium, grātia'. Optiō D, <b>ōrdō</b>, significat 'ōrdō, series'." }, { meta: "Synonyms", stem: "Quod verbum est simillimum verbō <b>proficīscor</b>?", options: ["veniō", "maneō", "discēdō", "redeō"], i: 2, explanation: "Verbum dēpōnēns <b>proficīscor</b> significat 'proficīscī, iter facere, abīre'. Verbum <b>discēdō</b> est proximum synonymum, significāns 'discēdere, abīre'. Optiō A, <b>veniō</b>, significat 'venīre'. Optiō B, <b>maneō</b>, significat 'manēre' (antonymum). Optiō D, <b>redeō</b>, significat 'redīre'." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbiō <b>prōpe</b>?", options: ["longe", "circum", "intrā", "trāns"], i: 0, explanation: "<i>Prōpe</i> significat 'prope' vel 'non procul'. Eius contrārium est <i>longe</i>, quod significat 'procul' vel 'longē'. <i>Circum</i> significat 'circum' vel 'undique'; <i>intrā</i> significat 'intrā' vel 'intus'; <i>trāns</i> significat 'trāns' vel 'per'. Haec verba locum indicant, sed nūllum eōrum est contrārium <i>prōpe</i>." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>incipiō</b>?", options: ["dēsinō", "perveniō", "petō", "agō"], i: 0, explanation: "<i>Incipiō</i> significat 'incipere' vel 'initiāre'. Eius contrārium est <i>dēsinō</i>, quod significat 'dēsinere' vel 'fīnem facere'. <i>Perveniō</i> significat 'pervenīre' vel 'advenīre'; <i>petō</i> significat 'petere' vel 'quaerere'; <i>agō</i> significat 'agere' vel 'facere'. Nūllum eōrum est contrārium <i>incipiō</i>." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>surgō</b>?", options: ["cadō", "sedeō", "stō", "iaceō"], i: 0, explanation: "<i>Surgō</i> significat 'surgere' vel 'ad caelum ferre'. Eius contrārium est <i>cadō</i>, quod significat 'cadere' vel 'ad terram dēscendere'. <i>Sedeō</i> significat 'sedēre'; <i>stō</i> significat 'stāre'; <i>iaceō</i> significat 'iacēre'. Haec verba statum corporis indicant, sed <i>cadō</i> sōlum est contrārium actiōnī <i>surgō</i>." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>fortis</b>?", options: ["ignāvus", "dūrus", "laetus", "lentus"], i: 0, explanation: "<i>Fortis</i> significat 'fortis' vel 'audāx'. Eius contrārium est <i>ignāvus</i>, quod significat 'ignāvus' vel 'timidus'. <i>Dūrus</i> significat 'dūrus' vel 'difficilis'; <i>laetus</i> significat 'laetus' vel 'gāvisus'; <i>lentus</i> significat 'lentus' vel 'tardus'. Nūllum eōrum est contrārium <i>fortis</i>." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>pāx</b>?", options: ["bellum", "concordia", "trānquillitās", "amīcitia"], i: 0, explanation: "<i>Pāx</i> significat 'pāx' vel 'absentia bellī'. Eius contrārium est <i>bellum</i>, quod significat 'bellum' vel 'pugna'. <i>Concordia</i> significat 'concordia' vel 'consensus'; <i>trānquillitās</i> significat 'trānquillitās' vel 'quietūdō'; <i>amīcitia</i> significat 'amīcitia' vel 'benevolentia'. Haec verba sunt prope <i>pāx</i> in sēnsū, sed <i>bellum</i> sōlum est eius contrārium directum." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>hostis</b>?", options: ["amīcus", "cīvis", "socius", "servus"], i: 0, explanation: "<i>Hostis</i> significat 'hostis' vel 'inimīcus pūblicus'. Eius contrārium est <i>amīcus</i>, quod significat 'amīcus' vel 'sodālis'. <i>Cīvis</i> significat 'cīvis' vel 'incola urbis'; <i>socius</i> significat 'socius' vel 'coniūnctus'; <i>servus</i> significat 'servus' vel 'captīvus'. Quamquam <i>socius</i> est propinquus in contextū bellī, <i>amīcus</i> est contrārium generāle <i>hostis</i>." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbiō <b>saepe</b>?", options: ["rārō", "semper", "umquam", "nunc"], i: 0, explanation: "<i>Saepe</i> significat 'saepe' vel 'multīs temporibus'. Eius contrārium est <i>rārō</i>, quod significat 'rārō' vel 'paucīs temporibus'. <i>Semper</i> significat 'semper' vel 'omnī tempore'; <i>umquam</i> significat 'umquam' vel 'aliquandō'; <i>nunc</i> significat 'nunc' vel 'hōc tempore'. <i>Semper</i> est contrārium <i>numquam</i>, nōn <i>saepe</i>." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>magnus</b>?", options: ["parvus", "lātus", "altus", "longus"], i: 0, explanation: "<i>Magnus</i> significat 'magnus' vel 'grandis'. Eius contrārium est <i>parvus</i>, quod significat 'parvus' vel 'minūtus'. <i>Lātus</i> significat 'lātus'; <i>altus</i> significat 'altus' vel 'prōfundus'; <i>longus</i> significat 'longus'. Haec verba magnitudinem vel dimensiōnem dēscrībunt, sed <i>parvus</i> sōlum est contrārium generāle <i>magnus</i>." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>laetus</b>?", options: ["trīstis", "īrātus", "aeger", "fessus"], i: 0, explanation: "<i>Laetus</i> significat 'laetus' vel 'gāvisus'. Eius contrārium est <i>trīstis</i>, quod significat 'trīstis' vel 'dolēns'. <i>Īrātus</i> significat 'īrātus' vel 'īrā commōtus'; <i>aeger</i> significat 'aeger' vel 'male habēns'; <i>fessus</i> significat 'fessus' vel 'dēfessus'. Haec verba affectūs vel statūs corporis indicant, sed <i>trīstis</i> sōlum est contrārium directum <i>laetus</i>." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbiō <b>anteā</b>?", options: ["posteā", "nunc", "semper", "umquam"], i: 0, explanation: "<i>Anteā</i> significat 'anteā' vel 'prius'. Eius contrārium est <i>posteā</i>, quod significat 'posteā' vel 'post id tempus'. <i>Nunc</i> significat 'nunc' vel 'hōc tempore'; <i>semper</i> significat 'semper' vel 'omnī tempore'; <i>umquam</i> significat 'umquam' vel 'aliquandō'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>accipiō</b>?", options: ["dō", "capiō", "mittō", "teneō"], i: 0, explanation: "<i>Accipiō</i> significat 'accipere' vel 'sūmere'. Eius contrārium est <i>dō</i>, quod significat 'dare' vel 'trādere'. <i>Capiō</i> significat 'capere' vel 'sūmere'; <i>mittō</i> significat 'mittere' vel 'dīmittere'; <i>teneō</i> significat 'tenēre' vel 'retinēre'. Quamquam <i>mittō</i> est actiō dīmittendī, <i>dō</i> est actiō trādendī, quae est contrāria accipiendī." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>veniō</b>?", options: ["abeō", "redeō", "maneō", "stō"], i: 0, explanation: "<i>Veniō</i> significat 'venīre' vel 'advenīre'. Eius contrārium est <i>abeō</i>, quod significat 'abīre' vel 'discedere'. <i>Redeō</i> significat 'redīre' vel 'revertī'; <i>maneō</i> significat 'manēre' vel 'remanēre'; <i>stō</i> significat 'stāre' vel 'cōnsistere'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>vīvō</b>?", options: ["morior", "dormiō", "sedeō", "labōrō"], i: 0, explanation: "<i>Vīvō</i> significat 'vīvere' vel 'spīrāre'. Eius contrārium est <i>morior</i>, quod significat 'morī' vel 'vītam fīnīre'. <i>Dormiō</i> significat 'dormīre'; <i>sedeō</i> significat 'sedēre'; <i>labōrō</i> significat 'labōrāre'. Haec sunt actiōnēs vītae, sed <i>morior</i> est fīnis vītae." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>plēnus</b>?", options: ["vacuus", "lātus", "dēnsus", "gravis"], i: 0, explanation: "<i>Plēnus</i> significat 'plēnus' vel 'repletus'. Eius contrārium est <i>vacuus</i>, quod significat 'vacuus' vel 'inānis'. <i>Lātus</i> significat 'lātus'; <i>dēnsus</i> significat 'dēnsus' vel 'crassus'; <i>gravis</i> significat 'gravis' vel 'pondere plēnus'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>celer</b>?", options: ["tardus", "levis", "brevis", "facilis"], i: 0, explanation: "<i>Celer</i> significat 'celer' vel 'vēlōx'. Eius contrārium est <i>tardus</i>, quod significat 'tardus' vel 'lentus'. <i>Levis</i> significat 'levis' vel 'pondere levis'; <i>brevis</i> significat 'brevis' vel 'nōn longus'; <i>facilis</i> significat 'facilis' vel 'nōn difficilis'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["proficīscor", "sequor", "petō", "loquor"], i: 2, explanation: "The words <b>proficīscor</b> (to set out, depart), <b>sequor</b> (to follow), and <b>loquor</b> (to speak) are all deponent verbs, meaning they have passive forms but active meanings. <b>Petō</b> (to seek, ask, attack) is an active verb of the third conjugation." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vallum", "fossa", "agmen", "mūnītiō"], i: 2, explanation: "The words <b>vallum</b> (rampart, wall), <b>fossa</b> (ditch), and <b>mūnītiō</b> (fortification, defense) all refer to military structures or defenses. <b>Agmen</b>, however, refers to a marching column or line of march, not a stationary structure." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["iter", "vīs", "manus", "bōs"], i: 2, explanation: "The words <b>iter</b> (journey, route), <b>vīs</b> (force, power), and <b>bōs</b> (ox, cow) are all irregular or heteroclite nouns of the third declension, exhibiting unusual stem changes or defective forms. <b>Manus</b> (hand, band of men) is a regular noun of the fourth declension." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["veniō", "eō", "gerō", "proficīscor"], i: 2, explanation: "The verbs <b>veniō</b> (to come), <b>eō</b> (to go), and <b>proficīscor</b> (to set out, depart) are all verbs of motion. <b>Gerō</b> (to carry, wage, manage) does not belong to this semantic group." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["sine", "prō", "apud", "cum"], i: 2, explanation: "The prepositions <b>sine</b> (without), <b>prō</b> (for, on behalf of), and <b>cum</b> (with) all exclusively take the ablative case. <b>Apud</b> (among, at the house of, near) always takes the accusative case." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["virtūs", "fortitūdō", "cīvitās", "fidēs"], i: 2, explanation: "The words <b>virtūs</b> (courage, excellence), <b>fortitūdō</b> (bravery, fortitude), and <b>fidēs</b> (faith, trust, loyalty) are all abstract nouns denoting personal qualities or virtues. <b>Cīvitās</b> (state, citizenship, body of citizens) refers to a political entity or status, not an inherent personal quality." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["loquor", "arbitror", "dīcō", "sequor"], i: 2, explanation: "The verbs <b>loquor</b> (to speak), <b>arbitror</b> (to think, judge), and <b>sequor</b> (to follow) are all deponent verbs, meaning they have passive forms but active meanings. <b>Dīcō</b> (to say, tell) is an active verb of the third conjugation." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["magnus", "parvus", "multus", "omnis"], i: 3, explanation: "The adjectives <b>magnus</b> (great, large), <b>parvus</b> (small), and <b>multus</b> (much, many) are all first/second declension adjectives describing size or quantity. <b>Omnis</b> (all, every) is a third declension adjective." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["caput", "manus", "oculus", "pēs"], i: 2, explanation: "The words <b>caput</b> (head, 3rd declension), <b>manus</b> (hand, 4th declension), and <b>pēs</b> (foot, 3rd declension) are all nouns belonging to either the third or fourth declension. <b>Oculus</b> (eye) is a noun of the second declension." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["persuādeō", "imperō", "iubeō", "crēdō"], i: 2, explanation: "The verbs <b>persuādeō</b> (to persuade), <b>imperō</b> (to command), and <b>crēdō</b> (to believe, trust) all typically take a dative object (the person persuaded/commanded/believed) and often an indirect command clause (dative + ut/nē + subjunctive). <b>Iubeō</b> (to order, command) takes an accusative object (the person ordered) and an infinitive (what is ordered), functioning as a direct command." }, { meta: "Analogies", stem: "<b>mīles</b> : <b>legiō</b> :: <b>nāvis</b> : X", options: ["portus", "classis", "rēmus", "fluctus"], i: 1, explanation: "The relationship is Part:Whole. A <i>mīles</i> (soldier) is a part of a <i>legiō</i> (legion). Similarly, a <i>nāvis</i> (ship) is a part of a <i>classis</i> (fleet). Option A, <i>portus</i>, means 'harbor'. Option C, <i>rēmus</i>, means 'oar'. Option D, <i>fluctus</i>, means 'wave'. None of these represent a whole unit composed of ships." }, { meta: "Analogies", stem: "<b>imperātor</b> : <b>imperium</b> :: <b>lēgātus</b> : X", options: ["lēgātiō", "lēx", "mandātum", "cōnsilium"], i: 0, explanation: "The relationship is Agent:Sphere of Authority/Function. An <i>imperātor</i> (commander) holds <i>imperium</i> (command, power). A <i>lēgātus</i> (envoy, legate) is associated with a <i>lēgātiō</i> (embassy, legation, commission). Option B, <i>lēx</i>, means 'law'. Option C, <i>mandātum</i>, means 'order, commission' (often given to a legate, but <i>lēgātiō</i> is the office/function itself). Option D, <i>cōnsilium</i>, means 'plan, counsel'." }, { meta: "Analogies", stem: "<b>sequor</b> : <b>secūtus</b> :: <b>proficīscor</b> : X", options: ["profectus", "profectiō", "proficīscēns", "profectūrus"], i: 0, explanation: "The relationship is Verb:Perfect Participle. <i>sequor</i> (to follow) is a deponent verb, and its perfect participle is <i>secūtus</i> (having followed). Similarly, <i>proficīscor</i> (to set out) is a deponent verb, and its perfect participle is <i>profectus</i> (having set out). Option B, <i>profectiō</i>, is a noun meaning 'departure'. Option C, <i>proficīscēns</i>, is the present participle. Option D, <i>profectūrus</i>, is the future active participle." }, { meta: "Analogies", stem: "<b>celeritās</b> : <b>tarditās</b> :: <b>virtūs</b> : X", options: ["timor", "ignāvia", "fortitūdō", "dēfectiō"], i: 1, explanation: "The relationship is Antonym. <i>celeritās</i> (swiftness, speed) is the opposite of <i>tarditās</i> (slowness). Similarly, <i>virtūs</i> (courage, virtue) is the opposite of <i>ignāvia</i> (cowardice, idleness). Option A, <i>timor</i>, means 'fear' but is not as direct an antonym for 'courage' as 'cowardice'. Option C, <i>fortitūdō</i>, is a synonym for courage. Option D, <i>dēfectiō</i>, means 'defection' or 'revolt'." }, { meta: "Analogies", stem: "<b>vīs</b> : <b>vīrēs</b> :: <b>iter</b> : X", options: ["itineris", "itinera", "itinere", "iterum"], i: 1, explanation: "The relationship is Singular Nominative:Plural Nominative. <i>vīs</i> (force, strength) is an irregular noun whose plural nominative is <i>vīrēs</i> (forces, strengths). Similarly, <i>iter</i> (journey, march) is an irregular noun (neuter 3rd declension) whose plural nominative is <i>itinera</i> (journeys, marches). Option A, <i>itineris</i>, is the genitive singular. Option C, <i>itinere</i>, is the ablative singular. Option D, <i>iterum</i>, is an adverb meaning 'again'." }, { meta: "Analogies", stem: "<b>aedificō</b> : <b>mūrus</b> :: <b>cōnficiō</b> : X", options: ["proelium", "hostis", "arma", "praesidium"], i: 0, explanation: "The relationship is Verb:Typical Direct Object. One <i>aedificat</i> (builds) a <i>mūrus</i> (wall). Similarly, one <i>cōnficit</i> (finishes, accomplishes) a <i>proelium</i> (battle), often implying winning or completing it. While one might 'finish' other things, <i>cōnficiō proelium</i> is a common idiom in Caesar. Option B, <i>hostis</i>, means 'enemy'. Option C, <i>arma</i>, means 'arms'. Option D, <i>praesidium</i>, means 'guard, garrison'." }, { meta: "Analogies", stem: "<b>caput</b> : <b>corpus</b> :: <b>prīncipium</b> : X", options: ["fīnis", "ōrdō", "opus", "pars"], i: 2, explanation: "The relationship is Part:Whole. The <i>caput</i> (head) is a part of the <i>corpus</i> (body). Similarly, the <i>prīncipium</i> (beginning) is a part of an <i>opus</i> (work, undertaking). The beginning is integral to the whole work. Option A, <i>fīnis</i>, is the opposite (end). Option B, <i>ōrdō</i>, means 'order, sequence'. Option D, <i>pars</i>, means 'part' but is too general; <i>opus</i> provides the specific context for a 'beginning'." }, { meta: "Analogies", stem: "<b>agricola</b> : <b>arātrum</b> :: <b>mīles</b> : X", options: ["gladius", "castra", "scūtum", "pīlum"], i: 0, explanation: "The relationship is Agent:Primary Tool. An <i>agricola</i> (farmer) uses an <i>arātrum</i> (plow) as a primary tool for their work. A <i>mīles</i> (soldier) primarily uses a <i>gladius</i> (sword) for combat. While <i>scūtum</i> (shield) and <i>pīlum</i> (javelin) are also soldier's equipment, the <i>gladius</i> is the quintessential close-combat weapon. Option B, <i>castra</i>, means 'camp'." }, { meta: "Analogies", stem: "<b>hortor</b> : <b>incitō</b> :: <b>vereor</b> : X", options: ["timeō", "dēfendō", "cōnfīdō", "spērō"], i: 0, explanation: "The relationship is Synonym. <i>hortor</i> (to encourage, exhort) is synonymous with <i>incitō</i> (to incite, urge on). Similarly, <i>vereor</i> (to fear, respect) is synonymous with <i>timeō</i> (to fear). Both <i>hortor</i> and <i>vereor</i> are deponent verbs. Option B, <i>dēfendō</i>, means 'to defend'. Option C, <i>cōnfīdō</i>, means 'to trust' (an antonym of fear). Option D, <i>spērō</i>, means 'to hope'." }, { meta: "Analogies", stem: "<b>impedīmenta</b> : <b>exercitus</b> :: <b>commeātus</b> : X", options: ["cīvitās", "nāvis", "frūmentum", "iter"], i: 2, explanation: "The relationship is Part:Whole or Category:Specific Item. <i>impedīmenta</i> (baggage) are a part of an <i>exercitus</i> (army). Similarly, <i>commeātus</i> (provisions, supplies) is a general category that includes <i>frūmentum</i> (grain), which was a crucial type of provision for Roman armies, especially in Caesar's campaigns. Option A, <i>cīvitās</i>, means 'state, citizenship'. Option B, <i>nāvis</i>, means 'ship'. Option D, <i>iter</i>, means 'journey, march'." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs Rōmānī hostēs fortiter ____.", options: ["petēbant", "fugābant", "<b>sequēbantur</b>", "agēbant"], i: 2, explanation: "The sentence describes Roman soldiers actively engaging with enemies. The deponent verb <b>sequor, sequī, secūtus sum</b> means 'to follow' or 'to pursue,' which fits the context of soldiers pursuing enemies in battle. Options A (petēbant - 'were seeking/attacking'), B (fugābant - 'were putting to flight'), and D (agēbant - 'were driving/doing') are less precise for the action of following or pursuing the enemy." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs longum ____ per silvās fēcērunt.", options: ["viam", "cursum", "spatium", "<b>iter</b>"], i: 3, explanation: "The phrase 'longum ____ per silvās fēcērunt' means 'they made a long ____ through the woods.' The noun <b>iter, itineris</b> (n.) means 'journey' or 'march,' and <i>iter facere</i> is a common idiom for 'to make a journey/march.' Option A (viam - 'road') refers to the path itself, not the act of traveling. Option B (cursum - 'course' or 'running') is less appropriate for a journey through woods. Option C (spatium - 'space' or 'interval') does not fit the context of making a journey." }, { meta: "Fill-in-the-Blank", stem: "Lēgātus cīvēs ad pācem ____.", options: ["iubēbat", "monēbat", "rogābat", "<b>hortābātur</b>"], i: 3, explanation: "The sentence states that 'The legate ____ the citizens to peace.' The deponent verb <b>hortor, hortārī, hortātus sum</b> means 'to urge,' 'to encourage,' or 'to exhort,' which perfectly fits the context of a legate encouraging citizens towards peace. Option A (iubēbat - 'was ordering') implies a command, which might be too strong. Option B (monēbat - 'was advising' or 'warning') is less about strong encouragement. Option C (rogābat - 'was asking') suggests a question rather than an urging." }, { meta: "Fill-in-the-Blank", stem: "Hostēs nostrōs impetū ____ superāvērunt.", options: ["celeriter", "fortiter", "difficulter", "<b>facile</b>"], i: 3, explanation: "The sentence means 'The enemies overcame our men by attack ____.' The adverb <b>facile</b> means 'easily,' which logically describes how an attack might lead to overcoming an opponent, especially if the attackers were superior. Option A (celeriter - 'quickly') describes speed, not ease. Option B (fortiter - 'bravely') describes manner, but 'easily' is a more direct consequence of 'overcame.' Option C (difficulter - 'with difficulty') is the opposite of what the context implies if they 'overcame' them." }, { meta: "Fill-in-the-Blank", stem: "Caesar castra in locō ____ pōnī iussit.", options: ["altō", "lātō", "vacuō", "<b>opportūnō</b>"], i: 3, explanation: "The sentence states 'Caesar ordered the camp to be placed in a ____ place.' When establishing a military camp (castra), the location is chosen for strategic advantage. The adjective <b>opportūnus, -a, -um</b> means 'suitable,' 'advantageous,' or 'opportune,' which is the most fitting description for a strategic camp location. Option A (altō - 'high' or 'deep') could be a characteristic but not necessarily the primary reason. Option B (lātō - 'wide') is too general. Option C (vacuō - 'empty') doesn't convey strategic suitability." }, { meta: "Fill-in-the-Blank", stem: "Omnēs cīvēs lībertātem ____.", options: ["cēpērunt", "petīvērunt", "quaesīvērunt", "<b>adeptī sunt</b>"], i: 3, explanation: "The sentence means 'All citizens ____ liberty.' The deponent verb <b>adipīscor, adipīscī, adeptus sum</b> means 'to obtain' or 'to acquire,' which is an excellent fit for gaining an abstract concept like liberty. Option A (cēpērunt - 'seized' or 'took') implies a more forceful or physical action. Option B (petīvērunt - 'sought' or 'asked for') indicates an attempt, not necessarily success. Option C (quaesīvērunt - 'sought' or 'inquired') is similar to B and doesn't imply successful acquisition." }, { meta: "Fill-in-the-Blank", stem: "Magnā ____ rēs pūblica servāta est.", options: ["potentiā", "fortūnā", "sapientiā", "<b>virtūte</b>"], i: 3, explanation: "The sentence means 'The republic was saved by great ____.' The noun <b>virtūs, virtūtis</b> (f.) means 'courage,' 'valor,' or 'excellence,' which is a common and fitting quality by which a republic might be saved, especially in a military or political crisis. Option A (potentiā - 'power') could be a means, but <i>virtūs</i> is more specific to the quality of the people. Option B (fortūnā - 'fortune' or 'luck') implies chance, not effort. Option C (sapientiā - 'wisdom') is also a virtue, but 'courage' is often more directly associated with saving a state from peril." }, { meta: "Fill-in-the-Blank", stem: "Imperātor mīlitēs arma ____ iussit.", options: ["ferre", "habēre", "dūcere", "<b>sūmere</b>"], i: 3, explanation: "The sentence means 'The general ordered the soldiers ____ arms.' The idiom 'arma <b>sūmere</b>' means 'to take up arms,' which is the standard phrase for preparing for battle. Option A (ferre - 'to carry') is too general. Option B (habēre - 'to have') implies possession, not the action of taking them up. Option C (dūcere - 'to lead') does not fit the context of arms." }, { meta: "Fill-in-the-Blank", stem: "Multī Gallī arma ____ ad proelium parāvērunt.", options: ["magna", "nova", "gravia", "<b>varia</b>"], i: 3, explanation: "The sentence means 'Many Gauls prepared ____ arms for battle.' Given that 'Multī Gallī' (many Gauls) are involved, it is highly probable that they would possess different kinds of weapons. The adjective <b>varius, -a, -um</b> means 'various' or 'diverse,' which fits this context well. Option A (magna - 'great') is possible but less specific to diversity. Option B (nova - 'new') is a possibility but not implied by 'many Gauls.' Option C (gravia - 'heavy') describes a characteristic, not the variety." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī hostium numerum magnum ____.", options: ["timuērunt", "metuērunt", "horrēbant", "<b>veritī sunt</b>"], i: 3, explanation: "The sentence means 'The Romans ____ the great number of enemies.' The deponent verb <b>vereor, verērī, veritus sum</b> means 'to fear' or 'to dread,' and often implies a respectful or apprehensive fear, which is appropriate when facing a large enemy force. While options A (timuērunt - 'feared') and B (metuērunt - 'feared') are also verbs meaning 'to fear,' they are active verbs. Option C (horrēbant - 'were shuddering/dreading') is also active. The question aims for nuanced vocabulary and deponent verbs, making <b>veritī sunt</b> the best fit among the choices for a Level 2 question focusing on deponents." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>locum relinquere et iter incipere</b>?", options: ["proficīscor", "pugnō", "aedificō", "maneō"], i: 0, explanation: "The question asks for the verb meaning 'to leave a place and begin a journey'.<br><b>A. proficīscor</b> (to set out, depart) perfectly matches this definition. It is a common deponent verb in Caesar.<br>B. <b>pugnō</b> means 'to fight'.<br>C. <b>aedificō</b> means 'to build'.<br>D. <b>maneō</b> means 'to remain, stay', which is the opposite of setting out." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>verbīs animōs excitāre et ad rem agendam impellere</b>?", options: ["cohortor", "dissuādeō", "impediō", "contemnō"], i: 0, explanation: "The question asks for the verb meaning 'to stir up spirits with words and drive them to do something'.<br><b>A. cohortor</b> (to encourage, incite, exhort) accurately describes this action, often used in military contexts by commanders. It is a deponent verb.<br>B. <b>dissuādeō</b> means 'to dissuade, advise against'.<br>C. <b>impediō</b> means 'to hinder, impede'.<br>D. <b>contemnō</b> means 'to despise, scorn'." }, { meta: "Circumlocution", stem: "Quod nōmen significat <b>viam per quam hominēs aut exercitūs ad locum novum moventur</b>?", options: ["iter", "flūmen", "mūrus", "pons"], i: 0, explanation: "The question asks for the noun meaning 'a way by which people or armies move to a new place'.<br><b>A. iter</b> (journey, route, march) is the correct term for this, and it is an irregular noun (gen. <i>itineris</i>).<br>B. <b>flūmen</b> means 'river'.<br>C. <b>mūrus</b> means 'wall'.<br>D. <b>pons</b> means 'bridge'." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>operam dare ut aliquid fiat, sed nōn semper succēdit</b>?", options: ["cōnor", "perficiō", "dēsinō", "neglegō"], i: 0, explanation: "The question asks for the verb meaning 'to give effort so that something happens, but it doesn't always succeed'.<br><b>A. cōnor</b> (to try, attempt) perfectly fits this description, implying effort without guaranteed success. It is a deponent verb.<br>B. <b>perficiō</b> means 'to accomplish, complete', implying success.<br>C. <b>dēsinō</b> means 'to stop, cease'.<br>D. <b>neglegō</b> means 'to neglect, disregard'." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>re aliquā ad rem aliam agendam adhibēre</b>?", options: ["ūtor", "fruor", "fungor", "potior"], i: 0, explanation: "The question asks for the verb meaning 'to apply something for doing another thing'.<br><b>A. ūtor</b> (to use, employ) is the correct verb, and it takes the ablative case, as do the distractors, making them plausible but incorrect choices.<br>B. <b>fruor</b> means 'to enjoy'.<br>C. <b>fungor</b> means 'to perform, discharge'.<br>D. <b>potior</b> means 'to get possession of, obtain'." }, { meta: "Circumlocution", stem: "Quod adiectīvum aut nōmen significat <b>quī prope alterum habitat aut situs est</b>?", options: ["vīcīnus", "longinquus", "extrāneus", "hostis"], i: 0, explanation: "The question asks for the adjective or noun meaning 'who lives or is situated near another'.<br><b>A. vīcīnus</b> (neighboring, near; as a noun, neighbor) accurately describes this.<br>B. <b>longinquus</b> means 'distant, far off'.<br>C. <b>extrāneus</b> means 'foreign, stranger'.<br>D. <b>hostis</b> means 'enemy'." }, { meta: "Circumlocution", stem: "Quod adverbium aut nōmen significat <b>nōn multum, sed aliquid ex parvā parte</b>?", options: ["paulum", "multum", "omnīnō", "nihil"], i: 0, explanation: "The question asks for the adverb or noun meaning 'not much, but something from a small part'.<br><b>A. paulum</b> (a little, a small amount) is the correct term.<br>B. <b>multum</b> means 'much, a great deal', which is the opposite.<br>C. <b>omnīnō</b> means 'entirely, altogether'.<br>D. <b>nihil</b> means 'nothing'." }, { meta: "Circumlocution", stem: "Quod nōmen plūrāle significat <b>rēs quae ab exercitū portantur et motum tardant</b>?", options: ["impedīmenta", "arma", "cibāria", "castra"], i: 0, explanation: "The question asks for the plural noun meaning 'things which are carried by an army and slow movement'.<br><b>A. impedīmenta</b> (baggage, hindrance) is the specific term for an army's baggage train, which impedes movement. This word is very common in Caesar.<br>B. <b>arma</b> means 'arms, weapons'.<br>C. <b>cibāria</b> means 'provisions, food supplies'.<br>D. <b>castra</b> means 'camp'." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>ex ūnā parte ad alteram per aquam aut terram ferre</b>?", options: ["trānsportō", "aedificō", "dēstruō", "revertor"], i: 0, explanation: "The question asks for the verb meaning 'to carry from one side to another across water or land'.<br><b>A. trānsportō</b> (to carry across, transport) accurately conveys this meaning.<br>B. <b>aedificō</b> means 'to build'.<br>C. <b>dēstruō</b> means 'to destroy'.<br>D. <b>revertor</b> (a deponent verb) means 'to return, turn back'." }, { meta: "Circumlocution", stem: "Quod verbum significat <b>vim ab hostibus arcēre et suōs servāre</b>?", options: ["dēfendō", "oppugnō", "dēserō", "prodō"], i: 0, explanation: "The question asks for the verb meaning 'to ward off force from enemies and save one's own'.<br><b>A. dēfendō</b> (to defend, protect) is the precise meaning.<br>B. <b>oppugnō</b> means 'to attack, assault', which is the opposite of defending.<br>C. <b>dēserō</b> means 'to desert, abandon'.<br>D. <b>prodō</b> means 'to betray, hand over'." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>proficīscor, proficīscī, profectus sum</b>.", options: ["to make progress", "to set out, depart", "to complete, finish", "to be useful, profit"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Proficīscor, proficīscī, profectus sum</b> is a deponent verb meaning 'to set out, depart'. Option <b>A</b>, 'to make progress', translates <b>proficiō, proficere, profēcī, profectum</b>. Option <b>C</b>, 'to complete, finish', translates <b>perficiō, perficere, perfēcī, perfectum</b>. Option <b>D</b>, 'to be useful, profit', translates <b>prōsum, prōdesse, prōfuī</b>. These verbs are often confused due to similar prefixes or roots." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>moror, morārī, morātus sum</b>.", options: ["to die", "to bite", "to delay, linger", "to remember, relate"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Moror, morārī, morātus sum</b> is a deponent verb meaning 'to delay, linger'. Option <b>A</b>, 'to die', translates the visually similar deponent verb <b>morior, morī, mortuus sum</b>. Option <b>B</b>, 'to bite', translates <b>mordeō, mordēre, momordī, morsum</b>. Option <b>D</b>, 'to remember, relate', translates <b>memorō, memorāre, memorāvī, memorātum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>sequor, sequī, secūtus sum</b>.", options: ["to cut", "to follow", "father-in-law", "thus, so"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Sequor, sequī, secūtus sum</b> is a deponent verb meaning 'to follow'. Option <b>A</b>, 'to cut', translates <b>secō, secāre, secuī, sectum</b>, which has a similar perfect passive participle stem. Option <b>C</b>, 'father-in-law', translates the noun <b>socer, socerī</b>, which is visually similar. Option <b>D</b>, 'thus, so', translates the adverb <b>sīc</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>hortor, hortārī, hortātus sum</b>.", options: ["to shudder, dread", "garden", "to urge, encourage", "to beg, pray"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Hortor, hortārī, hortātus sum</b> is a deponent verb meaning 'to urge, encourage'. Option <b>A</b>, 'to shudder, dread', translates <b>horreō, horrēre, horruī</b>, which is visually similar. Option <b>B</b>, 'garden', translates the noun <b>hortus, hortī</b>. Option <b>D</b>, 'to beg, pray', translates <b>ōrō, ōrāre, ōrāvī, ōrātum</b>, which shares a similar sound." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>loquor, loquī, locūtus sum</b>.", options: ["to place, locate", "to shine", "to speak, talk", "to read, gather"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Loquor, loquī, locūtus sum</b> is a deponent verb meaning 'to speak, talk'. Option <b>A</b>, 'to place, locate', translates <b>locō, locāre, locāvī, locātum</b>, which has a similar root. Option <b>B</b>, 'to shine', translates <b>lūceō, lūcēre, lūxī</b>. Option <b>D</b>, 'to read, gather', translates <b>legō, legere, lēgī, lēctum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>ūtor, ūtī, ūsus sum</b>.", options: ["one", "to use, employ", "eleven", "from all sides"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Ūtor, ūtī, ūsus sum</b> is a deponent verb meaning 'to use, employ', and it takes the ablative case. Option <b>A</b>, 'one', translates the adjective <b>ūnus, ūna, ūnum</b>, which is visually similar. Option <b>C</b>, 'eleven', translates the numeral <b>ūndecim</b>. Option <b>D</b>, 'from all sides', translates the adverb <b>ūndique</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>potior, potīrī, potītus sum</b>.", options: ["powerful, able", "to be able", "to get possession of, obtain", "rather, preferably"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Potior, potīrī, potītus sum</b> is a deponent verb meaning 'to get possession of, obtain', and it typically takes the ablative or genitive case. Option <b>A</b>, 'powerful, able', translates the adjective <b>potēns, potentis</b>. Option <b>B</b>, 'to be able', translates the irregular verb <b>possum, posse, potuī</b>. Option <b>D</b>, 'rather, preferably', translates the adverb <b>potius</b>. All these words are related to the concept of power or ability." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>patior, patī, passus sum</b>.", options: ["to lie open, extend", "to suffer, endure, allow", "father", "to seek, ask"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Patior, patī, passus sum</b> is a deponent verb meaning 'to suffer, endure, allow'. Option <b>A</b>, 'to lie open, extend', translates <b>pateō, patēre, patuī</b>, which is visually very similar. Option <b>C</b>, 'father', translates the noun <b>pater, patris</b>. Option <b>D</b>, 'to seek, ask', translates <b>petō, petere, petīvī, petītum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>cōnor, cōnārī, cōnātus sum</b>.", options: ["consul", "to sit down, encamp", "to try, attempt", "to consult, consider"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Cōnor, cōnārī, cōnātus sum</b> is a deponent verb meaning 'to try, attempt'. Option <b>A</b>, 'consul', translates the noun <b>cōnsul, cōnsulis</b>, which is visually similar. Option <b>B</b>, 'to sit down, encamp', translates <b>cōnsīdō, cōnsīdere, cōnsēdī, cōnsessum</b>. Option <b>D</b>, 'to consult, consider', translates <b>cōnsulō, cōnsulere, cōnsuluī, cōnsultum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>vereor, verērī, veritus sum</b>.", options: ["true", "to turn", "to fear, be afraid of, revere", "word"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Vereor, verērī, veritus sum</b> is a deponent verb meaning 'to fear, be afraid of, revere'. Option <b>A</b>, 'true', translates the adjective <b>vērus, vēra, vērum</b>, which is visually similar. Option <b>B</b>, 'to turn', translates <b>vertō, vertere, vertī, versum</b>. Option <b>D</b>, 'word', translates the noun <b>verbum, verbī</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>audeō, audēre, ausus sum</b>.", options: ["to hear, listen", "to dare, venture", "to increase, enlarge", "gold"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Audeō, audēre, ausus sum</b> is a semi-deponent verb meaning 'to dare, venture'. Option <b>A</b>, 'to hear, listen', translates <b>audiō, audīre, audīvī, audītum</b>, which is very similar in form. Option <b>C</b>, 'to increase, enlarge', translates <b>augeō, augēre, auxī, auctum</b>. Option <b>D</b>, 'gold', translates the noun <b>aurum, aurī</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>fidō, fīdere, fīsus sum</b>.", options: ["faith, loyalty, trust", "to trust, rely on", "end, boundary", "to fix, fasten"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Fidō, fīdere, fīsus sum</b> is a semi-deponent verb meaning 'to trust, rely on', and it often takes the dative or ablative case. Option <b>A</b>, 'faith, loyalty, trust', translates the noun <b>fīdēs, fideī</b>, which is from the same root and often confused. Option <b>C</b>, 'end, boundary', translates the noun <b>fīnis, fīnis</b>. Option <b>D</b>, 'to fix, fasten', translates <b>fīgō, fīgere, fīxī, fīxum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>revertor, revertī, reversus sum</b>.", options: ["to turn", "to turn back, return", "to bring back, report", "to find, discover"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Revertor, revertī, reversus sum</b> is a deponent verb (though sometimes active in the perfect system for authors like Caesar) meaning 'to turn back, return'. Option <b>A</b>, 'to turn', translates <b>vertō, vertere, vertī, versum</b>, which is the root verb. Option <b>C</b>, 'to bring back, report', translates <b>referō, referre, rettulī, relātum</b>. Option <b>D</b>, 'to find, discover', translates <b>reperiō, reperīre, repperī, repertum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>arbitror, arbitrārī, arbitrātus sum</b>.", options: ["tree", "to think, judge, consider", "judgment, decision", "to build"], i: 1, explanation: "The correct answer is <b>B</b>. <b>Arbitror, arbitrārī, arbitrātus sum</b> is a deponent verb meaning 'to think, judge, consider'. Option <b>A</b>, 'tree', translates the noun <b>arbor, arboris</b>, which is visually similar. Option <b>C</b>, 'judgment, decision', translates the noun <b>arbitrium, arbitriī</b>, which is related but a noun. Option <b>D</b>, 'to build', translates <b>aedificō, aedificāre, aedificāvī, aedificātum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for <b>progredior, progredī, progressus sum</b>.", options: ["to step, walk", "to enter, step into", "to go forward, advance, proceed", "to go back, retreat"], i: 2, explanation: "The correct answer is <b>C</b>. <b>Progredior, progredī, progressus sum</b> is a deponent verb meaning 'to go forward, advance, proceed'. Option <b>A</b>, 'to step, walk', translates <b>gradior, gradī, gressus sum</b>, which is the simple verb from which <b>progredior</b> is compounded. Option <b>B</b>, 'to enter, step into', translates <b>ingredior, ingredī, ingressus sum</b>. Option <b>D</b>, 'to go back, retreat', translates <b>regredior, regredī, regressus sum</b>. These are all compounds of <b>gradior</b> and are often confused." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to use</b>?", options: ["ūtī", "ūtor", "adhibēre", "gerere"], i: 0, explanation: "The correct answer is <b>A. ūtī</b>. This is the present active infinitive of the deponent verb <i>ūtor, ūtī, ūsus sum</i>, meaning 'to use' and typically taking the ablative case. Option <b>B. ūtor</b> is the 1st person singular present indicative. Option <b>C. adhibēre</b> means 'to apply, employ, bring in' and has a slightly different nuance, often implying a specific application or bringing something into play. Option <b>D. gerere</b> means 'to carry, wage, manage' and is too broad in meaning." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>courage</b>?", options: ["virtūs, virtūtis, f.", "fortitūdō, fortitūdinis, f.", "animus, animī, m.", "audācia, audāciae, f."], i: 0, explanation: "The correct answer is <b>A. virtūs, virtūtis, f.</b> While often translated as 'virtue' or 'excellence,' <i>virtūs</i> is a very common and appropriate word for 'courage' or 'valor' in a general sense, especially in military and civic contexts. Option <b>B. fortitūdō, fortitūdinis, f.</b> means 'bravery, fortitude,' which is very close, but <i>virtūs</i> often encompasses a broader sense of moral excellence including courage. Option <b>C. animus, animī, m.</b> can mean 'spirit' or 'mind,' and sometimes 'courage,' but it's less specific than <i>virtūs</i> for 'courage' itself. Option <b>D. audācia, audāciae, f.</b> means 'boldness, daring,' but often carries a negative connotation of 'rashness' or 'presumption.'" }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to suffer, endure</b>?", options: ["patī", "ferre", "dolēre", "labōrāre"], i: 0, explanation: "The correct answer is <b>A. patī</b>. This is the present active infinitive of the deponent verb <i>patior, patī, passus sum</i>, meaning 'to suffer, endure' hardships or pain. Option <b>B. ferre</b>, an irregular verb, means 'to bear, carry, bring,' and can also mean 'to endure,' but <i>patī</i> is more direct for 'to suffer.' Option <b>C. dolēre</b> means 'to feel pain, grieve,' focusing more on the internal sensation of pain. Option <b>D. labōrāre</b> means 'to work, toil,' or 'to suffer from illness,' which is a more specific kind of suffering." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to warn</b>?", options: ["monēre", "admonēre", "praecipere", "cavēre"], i: 0, explanation: "The correct answer is <b>A. monēre</b>. This verb (<i>moneō, monēre, monuī, monitum</i>) directly means 'to warn, advise.' Option <b>B. admonēre</b> is very similar and can also mean 'to warn' or 'to advise,' but it often carries the nuance of 'to remind' or 'to urge strongly.' In many contexts, they are interchangeable, but <i>monēre</i> is the more fundamental verb for 'to warn.' Option <b>C. praecipere</b> means 'to instruct, order, enjoin,' which is a stronger command than a warning. Option <b>D. cavēre</b> means 'to beware, take precautions, guard against,' and is often used intransitively or with <i>ut/nē</i> clauses." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>debt</b>?", options: ["aes aliēnum, aeris aliēnī, n.", "dēbitum, dēbitī, n.", "pecūnia, pecūniae, f.", "mūnus, mūneris, n."], i: 0, explanation: "The correct answer is <b>A. aes aliēnum, aeris aliēnī, n.</b> This is the standard idiom in Latin for 'debt,' literally meaning 'another's bronze/money.' It is an irregular noun phrase. Option <b>B. dēbitum, dēbitī, n.</b> does mean 'a debt' or 'what is owed,' but it is less common for general financial debt in classical prose than <i>aes aliēnum</i>. Option <b>C. pecūnia, pecūniae, f.</b> means 'money' and is too general. Option <b>D. mūnus, mūneris, n.</b> means 'duty, gift, service' and is unrelated to 'debt.'" }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to remember</b>?", options: ["meminisse", "recordārī", "cōgitāre", "retinēre"], i: 0, explanation: "The correct answer is <b>A. meminisse</b>. This is a defective verb (only perfect system forms exist, but they have present meaning), meaning 'to remember.' It typically takes the genitive case or an accusative object. Option <b>B. recordārī</b> is a deponent verb meaning 'to recall, call to mind, remember,' often implying an active process of bringing something back to memory. While close, <i>meminisse</i> is the primary verb for the state of remembering. Option <b>C. cōgitāre</b> means 'to think, consider.' Option <b>D. retinēre</b> means 'to hold back, retain,' not 'to remember.'" }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>army</b>?", options: ["exercitus, exercitūs, m.", "agmen, agminis, n.", "legiō, legiōnis, f.", "cōpiae, cōpiārum, f. pl."], i: 0, explanation: "The correct answer is <b>A. exercitus, exercitūs, m.</b> This is the general term for an 'army' in Latin, a 4th declension noun. Option <b>B. agmen, agminis, n.</b> refers to a 'marching column' or 'line of march,' which is a part of an army's formation, not the entire army. Option <b>C. legiō, legiōnis, f.</b> means 'legion,' a specific unit within an army, typically comprising several thousand men. Option <b>D. cōpiae, cōpiārum, f. pl.</b> means 'troops, forces,' and can also mean 'resources' or 'supplies.' While it refers to military personnel, <i>exercitus</i> is the singular noun for the collective 'army.'" }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to speak</b>?", options: ["loquī", "dīcere", "fārī", "ōrāre"], i: 0, explanation: "The correct answer is <b>A. loquī</b>. This is the present active infinitive of the deponent verb <i>loquor, loquī, locūtus sum</i>, meaning 'to speak, talk' in a general sense. Option <b>B. dīcere</b> means 'to say, tell,' often implying the content of speech or a message. Option <b>C. fārī</b> is an archaic and poetic deponent verb meaning 'to speak, utter.' Option <b>D. ōrāre</b> means 'to plead, pray,' or 'to speak formally' (like an orator), which is a more specific type of speaking." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>wall (of a city)</b>?", options: ["moenia, moenium, n. pl.", "mūrus, mūrī, m.", "paries, parietis, m.", "vallum, vallī, n."], i: 0, explanation: "The correct answer is <b>A. moenia, moenium, n. pl.</b> This noun is always plural and specifically refers to the 'walls or fortifications of a city.' Option <b>B. mūrus, mūrī, m.</b> means 'wall' in a general sense, such as a garden wall or a single defensive wall, but not typically the collective city fortifications. Option <b>C. paries, parietis, m.</b> refers to the 'wall of a house or room.' Option <b>D. vallum, vallī, n.</b> means 'rampart, palisade,' referring to an earthwork or defensive barrier, not a stone wall." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to follow</b>?", options: ["sequī", "īre", "comitārī", "persequī"], i: 0, explanation: "The correct answer is <b>A. sequī</b>. This is the present active infinitive of the deponent verb <i>sequor, sequī, secūtus sum</i>, meaning 'to follow' in a general sense, and it takes the accusative case. Option <b>B. īre</b> means 'to go' and is too general. Option <b>C. comitārī</b> is a deponent verb meaning 'to accompany,' implying going along with someone. Option <b>D. persequī</b> is a deponent verb meaning 'to pursue, follow up, avenge,' which is a stronger and more aggressive form of following." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>power, authority</b>?", options: ["potestās, potestātis, f.", "imperium, imperiī, n.", "vīs, (gen. vīs), f.", "rēgnum, rēgnī, n."], i: 0, explanation: "The correct answer is <b>A. potestās, potestātis, f.</b> This noun refers to 'power, ability, authority,' often in a civil or legal sense, or the power held by a magistrate. Option <b>B. imperium, imperiī, n.</b> means 'command, supreme power, empire,' often with a military or sovereign connotation. While related, <i>imperium</i> suggests a higher, more absolute form of power. Option <b>C. vīs, (gen. vīs), f.</b> is an irregular noun meaning 'force, strength, violence,' usually physical. Option <b>D. rēgnum, rēgnī, n.</b> means 'royal power, kingdom,' referring to a specific type of power or dominion." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to try, attempt</b>?", options: ["cōnārī", "temptāre", "petere", "studēre"], i: 0, explanation: "The correct answer is <b>A. cōnārī</b>. This is the present active infinitive of the deponent verb <i>cōnor, cōnārī, cōnātus sum</i>, which is the most common and direct translation for 'to try, attempt.' Option <b>B. temptāre</b> also means 'to try, attempt,' but often carries the nuance of 'to test, prove, or provoke.' Option <b>C. petere</b> means 'to seek, ask, attack,' and is too general. Option <b>D. studēre</b> means 'to be eager, study, strive for,' which is a different meaning." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>journey, march</b>?", options: ["iter, itineris, n.", "via, viae, f.", "cursus, cursūs, m.", "profectiō, profectiōnis, f."], i: 0, explanation: "The correct answer is <b>A. iter, itineris, n.</b> This is an irregular 3rd declension noun meaning 'journey, march, road.' It specifically refers to the act of traveling or the route taken. Option <b>B. via, viae, f.</b> means 'road, way, street,' referring to the physical path itself, not necessarily the act of traveling. Option <b>C. cursus, cursūs, m.</b> means 'running, course, race,' implying speed or a specific path, but not a general journey. Option <b>D. profectiō, profectiōnis, f.</b> means 'departure, setting out,' referring to the beginning of a journey, not the journey itself." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>to seem</b>?", options: ["vidērī", "appārēre", "putāre", "crēdere"], i: 0, explanation: "The correct answer is <b>A. vidērī</b>. This is the present active infinitive of the deponent verb <i>videor, vidērī, vīsus sum</i>, meaning 'to seem, appear' (passive of <i>vidēre</i> 'to see'). It is often used impersonally with a dative of person (e.g., <i>mihi vidētur</i>, 'it seems to me'). Option <b>B. appārēre</b> means 'to appear, be visible,' often referring to a physical manifestation. Option <b>C. putāre</b> means 'to think, suppose,' referring to a subjective opinion. Option <b>D. crēdere</b> means 'to believe, trust,' which is a different concept." }, { meta: "English to Latin", stem: "Which is the best Latin translation for <b>each, every</b>?", options: ["quisque, quaeque, quodque", "ūnusquisque", "omnis, omne", "singulī, -ae, -a"], i: 0, explanation: "The correct answer is <b>A. quisque, quaeque, quodque</b>. This indefinite pronoun/adjective means 'each, every (single one)' and is used to refer to individuals within a group. Option <b>B. ūnusquisque</b> means 'each one' (literally 'one each') and is more emphatic, often used substantively. Option <b>C. omnis, omne</b> means 'all, every,' and while it can mean 'every' in the singular, <i>quisque</i> is more precise for 'each individual.' Option <b>D. singulī, -ae, -a</b> is a distributive numeral meaning 'one by one, individual,' and is used to indicate distribution rather than 'each' in a general sense." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>iter</b>?", options: ["via", "tempus", "bellum", "flūmen"], i: 0, explanation: "Verbum <b>iter</b> (neut. 3rd decl.) significat 'iter, via, cursus'. Inter optiōnēs datās, <b>via</b> (fem. 1st decl.) est proximē simillimum, significāns 'via, iter, modus'. Amba verba ad trānsitum vel cursum pertinent. <b>Tempus</b> significat 'tempus', <b>bellum</b> 'bellum', et <b>flūmen</b> 'flūmen'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>cōnor</b>?", options: ["proficīscor", "temptō", "loquor", "sequor"], i: 1, explanation: "Verbum <b>cōnor, cōnārī, cōnātus sum</b> (deponent) significat 'cōnārī, temptāre'. <b>Temptō, temptāre, temptāvī, temptātus</b> est verbum activum quod eandem ferē rem significat, scīlicet 'temptāre, cōnārī'. <b>Proficīscor</b> significat 'profectus sum, proficīscī', <b>loquor</b> 'loquī, dīcere', et <b>sequor</b> 'sequī, secūtus sum'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>mīles</b>?", options: ["cīvis", "hostis", "bellātor", "dux"], i: 2, explanation: "Verbum <b>mīles, mīlitis</b> (masc. 3rd decl.) significat 'mīles, socius militāris'. <b>Bellātor, bellātōris</b> (masc. 3rd decl.) est proximē simillimum, significāns 'bellātor, vir militāris'. <b>Cīvis</b> significat 'cīvis', <b>hostis</b> 'hostis', et <b>dux</b> 'dux, imperātor'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>castra</b>?", options: ["urbs", "statīva", "pagus", "forum"], i: 1, explanation: "Verbum <b>castra, castrōrum</b> (neut. pl. tantum) significat 'castra militāria'. <b>Statīva, statīvōrum</b> (neut. pl. tantum) significat 'castra statīva, hiberna', quod est genus castrōrum. <b>Urbs</b> significat 'urbs', <b>pagus</b> 'pagus, vīcus', et <b>forum</b> 'forum'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>proelium</b>?", options: ["pāx", "victōria", "pugna", "perīculum"], i: 2, explanation: "Verbum <b>proelium, proeliī</b> (neut. 2nd decl.) significat 'proelium, certāmen'. <b>Pugna, pugnae</b> (fem. 1st decl.) est proximē simillimum, significāns 'pugna, certāmen, proelium'. <b>Pāx</b> significat 'pāx', <b>victōria</b> 'victōria', et <b>perīculum</b> 'perīculum'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>hortor</b>?", options: ["retineō", "prohibeō", "incitō", "dēterreō"], i: 2, explanation: "Verbum <b>hortor, hortārī, hortātus sum</b> (deponent) significat 'hortārī, incitāre, monēre'. <b>Incitō, incitāre, incitāvī, incitātus</b> est proximē simillimum, significāns 'incitāre, excitāre, urgēre'. <b>Retineō</b> significat 'retinēre', <b>prohibeō</b> 'prohibēre', et <b>dēterreō</b> 'dēterrēre', quae sunt contrāria vel similia in sensū impedientī." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>ferō</b>?", options: ["veniō", "portō", "eō", "dūcō"], i: 1, explanation: "Verbum <b>ferō, ferre, tulī, lātus</b> (irreg.) significat 'ferre, portāre, gerere'. <b>Portō, portāre, portāvī, portātus</b> est proximē simillimum, significāns 'portāre, vehere'. <b>Veniō</b> significat 'venīre', <b>eō</b> 'īre', et <b>dūcō</b> 'dūcere'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>magnus</b>?", options: ["parvus", "ingēns", "celer", "gravis"], i: 1, explanation: "Adiectīvum <b>magnus, -a, -um</b> significat 'magnus, grandis'. <b>Ingēns, ingentis</b> (3rd decl. adiectīvum) est proximē simillimum, significāns 'ingēns, vastus, permagnus'. <b>Parvus</b> significat 'parvus' (contrārium), <b>celer</b> 'celer', et <b>gravis</b> 'gravis, ponderōsus'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>virtūs</b>?", options: ["timor", "ignāvia", "fortitūdō", "sapientia"], i: 2, explanation: "Nōmen <b>virtūs, virtūtis</b> (fem. 3rd decl.) significat 'virtūs, fortitūdō, excellentia'. <b>Fortitūdō, fortitūdinis</b> (fem. 3rd decl.) est proximē simillimum, significāns 'fortitūdō, animus'. <b>Timor</b> significat 'timor', <b>ignāvia</b> 'ignāvia, dēsidia' (contrārium), et <b>sapientia</b> 'sapientia'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>loquor</b>?", options: ["audiō", "scrībō", "dīcō", "legō"], i: 2, explanation: "Verbum <b>loquor, loquī, locūtus sum</b> (deponent) significat 'loquī, dīcere'. <b>Dīcō, dīcere, dīxī, dictus</b> est proximē simillimum, significāns 'dīcere, nārrāre'. <b>Audiō</b> significat 'audīre', <b>scrībō</b> 'scrībere', et <b>legō</b> 'legere'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>flūmen</b>?", options: ["lacus", "mare", "amnis", "fōns"], i: 2, explanation: "Nōmen <b>flūmen, flūminis</b> (neut. 3rd decl.) significat 'flūmen, rīvus magnus'. <b>Amnis, amnis</b> (masc. 3rd decl.) est proximē simillimum, significāns 'amnis, flūmen'. <b>Lacus</b> significat 'lacus', <b>mare</b> 'mare', et <b>fōns</b> 'fōns, scatebra'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>initium</b>?", options: ["fīnis", "ōrīgō", "medium", "exitus"], i: 1, explanation: "Nōmen <b>initium, initiī</b> (neut. 2nd decl.) significat 'initium, prīncipium, orīgō'. <b>Ōrīgō, ōrīginis</b> (fem. 3rd decl.) est proximē simillimum, significāns 'ōrīgō, fōns, prīncipium'. <b>Fīnis</b> significat 'fīnis' (contrārium), <b>medium</b> 'medium', et <b>exitus</b> 'exitus, fīnis, ēventus'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>oppugnō</b>?", options: ["dēfendō", "adorior", "fugō", "cēdō"], i: 1, explanation: "Verbum <b>oppugnō, oppugnāre, oppugnāvī, oppugnātus</b> significat 'oppugnāre, bellum inferre'. <b>Adorior, adorīrī, adortus sum</b> (deponent) est proximē simillimum, significāns 'adorīrī, aggredī, oppugnāre'. <b>Dēfendō</b> significat 'dēfendere' (contrārium), <b>fugō</b> 'fugāre', et <b>cēdō</b> 'cēdere, recēdere'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>cōnsilium</b>?", options: ["fortūna", "fātum", "ratiō", "voluntās"], i: 2, explanation: "Nōmen <b>cōnsilium, cōnsiliī</b> (neut. 2nd decl.) significat 'cōnsilium, dēlīberātiō, ratiō'. <b>Ratiō, ratiōnis</b> (fem. 3rd decl.) est proximē simillimum, significāns 'ratiō, modus, cōnsilium'. <b>Fortūna</b> significat 'fortūna', <b>fātum</b> 'fātum', et <b>voluntās</b> 'voluntās'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est simillimum verbō <b>moror</b>?", options: ["accelerō", "contendō", "tardō", "properō"], i: 2, explanation: "Verbum <b>moror, morārī, morātus sum</b> (deponent) significat 'morārī, dēmorārī, tardāre'. <b>Tardō, tardāre, tardāvī, tardātus</b> est proximē simillimum, significāns 'tardāre, morārī, impedīre'. <b>Accelerō</b> significat 'accelerāre' (contrārium), <b>contendō</b> 'contendere, festīnāre', et <b>properō</b> 'properāre' (contrāria)." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>hostis</b>?", options: ["Cīvis", "Amīcus", "Socius", "Servus"], i: 1, explanation: "Verbum <b>hostis</b> significat 'inimīcus'. Antonymum directum est <b>amīcus</b>, quod 'amīcum' significat. <b>Cīvis</b> est 'cīvis', <b>socius</b> est 'socius' (quī et amīcus et hostis esse potest), et <b>servus</b> est 'servus'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>proficīscī</b>?", options: ["Manēre", "Venīre", "Fugere", "Sequī"], i: 0, explanation: "Verbum <b>proficīscī</b> (deponens) significat 'proficīscī, abīre'. Antonymum est <b>manēre</b>, quod 'manēre, cōnsistere' significat. <b>Venīre</b> est 'venīre', <b>fugere</b> est 'fugere', et <b>sequī</b> est 'sequī'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>accipere</b>?", options: ["Capere", "Dare", "Reddere", "Petere"], i: 1, explanation: "Verbum <b>accipere</b> significat 'accipere, recipere'. Antonymum directum est <b>dare</b>, quod 'dare' significat. <b>Capere</b> est 'capere' (quod interdum similis est accipere, sed non est antonymum dare), <b>reddere</b> est 'reddere, reportāre', et <b>petere</b> est 'petere, quaerere'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>magnus</b>?", options: ["Longus", "Gravis", "Parvus", "Lātus"], i: 2, explanation: "Adiectīvum <b>magnus</b> significat 'magnus, grandis'. Antonymum est <b>parvus</b>, quod 'parvus' significat. <b>Longus</b> est 'longus', <b>gravis</b> est 'gravis', et <b>lātus</b> est 'lātus'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>fortis</b>?", options: ["Debilis", "Igāvus", "Lentus", "Stultus"], i: 1, explanation: "Adiectīvum <b>fortis</b> significat 'fortis, audāx'. Antonymum est <b>igāvus</b>, quod 'igāvus, timidus' significat. <b>Debilis</b> est 'dēbilis' (quod ad vīrēs, nōn ad audāciam, pertinet), <b>lentus</b> est 'lentus', et <b>stultus</b> est 'stultus'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>saepe</b>?", options: ["Semper", "Numquam", "Rārō", "Breviter"], i: 2, explanation: "Adverbium <b>saepe</b> significat 'saepe, crebrō'. Antonymum est <b>rārō</b>, quod 'rārō, nōn saepe' significat. <b>Semper</b> est 'semper' (frequentia extrēma), <b>numquam</b> est 'numquam' (altera frequentia extrēma), et <b>breviter</b> est 'breviter' (ad tempus, nōn ad frequentiam, pertinēns)." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>surgere</b>?", options: ["Sedēre", "Cadere", "Iacēre", "Stāre"], i: 1, explanation: "Verbum <b>surgere</b> significat 'surgere, cōnsurgere'. Antonymum directum est <b>cadere</b>, quod 'cadere, dēcidere' significat. <b>Sedēre</b> est 'sedēre', <b>iacēre</b> est 'iacēre', et <b>stāre</b> est 'stāre'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>vīvere</b>?", options: ["Dormīre", "Morī", "Aegrōtāre", "Perīre"], i: 1, explanation: "Verbum <b>vīvere</b> significat 'vīvere'. Antonymum est <b>morī</b> (deponens), quod 'morī' significat. <b>Dormīre</b> est 'dormīre', <b>aegrōtāre</b> est 'aegrōtāre', et <b>perīre</b> est 'perīre' (quod est simillimum, sed <b>morī</b> est antonymum fundamentāle vīvere)." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>lūx</b>?", options: ["Umbra", "Nox", "Tenebrae", "Ignis"], i: 2, explanation: "Nōmen <b>lūx</b> significat 'lūx'. Antonymum est <b>tenebrae</b> (plūrāle), quod 'tenebrās, obscūritātem' significat. <b>Umbra</b> est 'umbra', <b>nox</b> est 'nox' (tempus, nōn ipsam absentiam lūcis), et <b>ignis</b> est 'ignis' (fōns lūcis)." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>celeriter</b>?", options: ["Facile", "Lentē", "Difficile", "Breviter"], i: 1, explanation: "Adverbium <b>celeriter</b> significat 'celeriter, rapidē'. Antonymum est <b>lentē</b>, quod 'lentē, tardē' significat. <b>Facile</b> est 'facile', <b>difficile</b> est 'difficile', et <b>breviter</b> est 'breviter'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>superus</b>?", options: ["Dexter", "Sinister", "Īnferus", "Medius"], i: 2, explanation: "Adiectīvum <b>superus</b> significat 'superus, superior'. Antonymum est <b>īnferus</b>, quod 'īnferus, īnfimus' significat. <b>Dexter</b> est 'dexter', <b>sinister</b> est 'sinister', et <b>medius</b> est 'medius'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>plēnus</b>?", options: ["Magnus", "Parvus", "Vacuus", "Rarus"], i: 2, explanation: "Adiectīvum <b>plēnus</b> significat 'plēnus'. Antonymum est <b>vacuus</b>, quod 'vacuus, inānis' significat. <b>Magnus</b> est 'magnus', <b>parvus</b> est 'parvus', et <b>rarus</b> est 'rarus' (ad densitātem vel frequentiam pertinēns, nōn ad plēnitūdinem)." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>incipere</b>?", options: ["Perficere", "Dēsinere", "Continuāre", "Reperīre"], i: 1, explanation: "Verbum <b>incipere</b> significat 'incipere, incohāre'. Antonymum est <b>dēsinere</b>, quod 'dēsinere, cessāre' significat. <b>Perficere</b> est 'perfīcere, complēre' (quod finem, nōn tantum cessātiōnem, implicat), <b>continuāre</b> est 'continuāre', et <b>reperīre</b> est 'reperīre'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>verus</b>?", options: ["Certus", "Falsus", "Dubius", "Malus"], i: 1, explanation: "Adiectīvum <b>verus</b> significat 'verus, vēridicus'. Antonymum est <b>falsus</b>, quod 'falsus, mendāx' significat. <b>Certus</b> est 'certus', <b>dubius</b> est 'dubius' (ambō ad vēritātem pertinent, sed nōn sunt antonyma directa), et <b>malus</b> est 'malus'." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>dūrus</b>?", options: ["Facilis", "Mollis", "Lēnis", "Gravis"], i: 1, explanation: "Adiectīvum <b>dūrus</b> significat 'dūrus, asper, difficilis'. Antonymum est <b>mollis</b>, quod 'mollis, lēnis' significat. <b>Facilis</b> est 'facilis' (antonymum 'difficilis', unius significātiōnis dūrī, sed <b>mollis</b> est magis directum ad dūritātem physicam), <b>lēnis</b> est 'lēnis' (similis mollis, sed <b>mollis</b> est latius), et <b>gravis</b> est 'gravis'." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>dīcō</i>", "<i>loquor</i>", "<i>for</i>", "<i>videō</i>"], i: 3, explanation: "The words <i>dīcō</i>, <i>loquor</i> (a deponent verb), and <i>for</i> (a deponent verb) all mean 'to speak' or 'to say'. <b><i>videō</i></b>, however, means 'to see', making it the outlier in this group of verbs related to communication." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>bellum</i>", "<i>proelium</i>", "<i>pāx</i>", "<i>pugna</i>"], i: 2, explanation: "<i>bellum</i> means 'war', <i>proelium</i> means 'battle', and <i>pugna</i> means 'fight' or 'battle'. All three are related to conflict and warfare. <b><i>pāx</i></b>, on the other hand, means 'peace', which is the opposite concept." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>timor</i>", "<i>metus</i>", "<i>pavor</i>", "<i>virtūs</i>"], i: 3, explanation: "<i>timor</i>, <i>metus</i>, and <i>pavor</i> all convey the meaning of 'fear' or 'dread', with varying degrees of intensity. <b><i>virtūs</i></b> means 'courage', 'excellence', or 'manliness', which is a quality often contrasted with fear." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>dūcō</i>", "<i>imperō</i>", "<i>praesum</i>", "<i>sequor</i>"], i: 3, explanation: "<i>dūcō</i> means 'to lead', <i>imperō</i> means 'to command' or 'to order', and <i>praesum</i> (with dative) means 'to be in charge of' or 'to command'. These verbs all relate to leadership or giving orders. <b><i>sequor</i></b> (a deponent verb) means 'to follow', which is the opposite action of leading." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>urbs</i>", "<i>oppidum</i>", "<i>rūs</i>", "<i>mūrus</i>"], i: 2, explanation: "<i>urbs</i> means 'city', <i>oppidum</i> means 'town', and <i>mūrus</i> means 'wall', which is a common feature of cities and towns. These words are all associated with urban or fortified settlements. <b><i>rūs</i></b> (an irregular noun, often used in the ablative <i>rūrī</i> for 'in the country') means 'the countryside' or 'rural area', which is distinct from a city or town." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>iter</i>", "<i>via</i>", "<i>cursus</i>", "<i>nāvis</i>"], i: 3, explanation: "<i>iter</i> means 'journey' or 'route', <i>via</i> means 'road' or 'way', and <i>cursus</i> means 'course' or 'journey'. These words are all related to travel or a path taken. <b><i>nāvis</i></b> means 'ship', which is a means of transport but not a journey or a path itself in the same conceptual group." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>vīs</i>", "<i>potentia</i>", "<i>rōbur</i>", "<i>infirmitās</i>"], i: 3, explanation: "<i>vīs</i> (an irregular noun) means 'force' or 'power', <i>potentia</i> means 'power' or 'ability', and <i>rōbur</i> means 'strength' or 'hard wood'. These words all denote strength, power, or robustness. <b><i>infirmitās</i></b> means 'weakness' or 'frailty', which is the opposite of strength." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>multitūdō</i>", "<i>turba</i>", "<i>cōpia</i>", "<i>paucī</i>"], i: 3, explanation: "<i>multitūdō</i> means 'multitude' or 'large number', <i>turba</i> means 'crowd' or 'throng', and <i>cōpia</i> means 'abundance' or 'supply' (often implying a large quantity, especially in the plural 'troops'). These words all refer to a large number or quantity. <b><i>paucī</i></b> (an adjective, often used substantively) means 'few' or 'a small number', which is the contrasting concept." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>dō</i>", "<i>praebeō</i>", "<i>offerō</i>", "<i>capiō</i>"], i: 3, explanation: "<i>dō</i> means 'to give', <i>praebeō</i> means 'to offer' or 'to provide', and <i>offerō</i> means 'to offer' or 'to present'. These verbs all describe the act of giving or presenting something. <b><i>capiō</i></b> means 'to take' or 'to seize', which is the opposite action of giving." }, { meta: "Odd One Out", stem: "Which word does NOT belong based on meaning?", options: ["<i>mōs</i>", "<i>cōnsuētūdō</i>", "<i>institūtum</i>", "<i>lēx</i>"], i: 3, explanation: "<i>mōs</i> means 'custom' or 'habit', <i>cōnsuētūdō</i> means 'custom' or 'habit', and <i>institūtum</i> means 'custom', 'institution', or 'principle'. These words all relate to established practices, traditions, or unwritten rules within a society. <b><i>lēx</i></b> means 'law' or 'statute', referring to formal, enacted legislation, which is distinct from custom or tradition." }, { meta: "Analogies", stem: "<b>proficīscor</b> : <b>profectiō</b> :: <b>sequor</b> : X", options: ["<b>secūtiō</b>", "<b>sequēla</b>", "<b>secūtor</b>", "<b>sequī</b>"], i: 0, explanation: "The relationship is a deponent verb to its corresponding verbal noun denoting the action or result. <b>proficīscor</b> (to set out) relates to <b>profectiō</b> (a setting out, departure). Similarly, <b>sequor</b> (to follow) relates to <b>secūtiō</b> (a following, pursuit). Option B, <b>sequēla</b>, means 'consequence' or 'sequel', which is related but not the direct action noun. Option C, <b>secūtor</b>, means 'follower' (an agent noun). Option D, <b>sequī</b>, is the infinitive form of the verb." }, { meta: "Analogies", stem: "<b>iter</b> : <b>itineris</b> :: <b>vīs</b> : X", options: ["<b>vīrium</b>", "<b>virī</b>", "<b>vīribus</b>", "<b>vīs</b>"], i: 3, explanation: "The relationship is an irregular noun in the nominative singular to its genitive singular form. <b>iter</b> (journey) has the genitive <b>itineris</b>. The irregular noun <b>vīs</b> (force, strength) has the genitive singular <b>vīs</b>. Option A, <b>vīrium</b>, is the genitive plural. Option B, <b>virī</b>, is the genitive singular of <b>vir</b> (man), a different word entirely. Option C, <b>vīribus</b>, is the dative/ablative plural." }, { meta: "Analogies", stem: "<b>castra</b> : <b>castrōrum</b> :: <b>arma</b> : X", options: ["<b>armī</b>", "<b>armārum</b>", "<b>armis</b>", "<b>armōrum</b>"], i: 3, explanation: "The relationship is a <i>plūrālia tantum</i> noun (plural in form but often singular in meaning) in the nominative plural to its genitive plural form. <b>castra</b> (camp) has the genitive plural <b>castrōrum</b>. Similarly, <b>arma</b> (arms, weapons) has the genitive plural <b>armōrum</b>. Option A, <b>armī</b>, is the genitive singular of <b>armus</b> (shoulder/foreleg), a different word. Option B, <b>armārum</b>, is an incorrect declensional ending for <b>arma</b> (which is 2nd declension neuter plural). Option C, <b>armis</b>, is the dative/ablative plural." }, { meta: "Analogies", stem: "<b>loquor</b> : <b>locūtus sum</b> :: <b>patior</b> : X", options: ["<b>patī</b>", "<b>passus est</b>", "<b>patēbam</b>", "<b>passus sum</b>"], i: 3, explanation: "The relationship is a deponent verb in the present tense (1st person singular) to its perfect tense (1st person singular). <b>loquor</b> (I speak) becomes <b>locūtus sum</b> (I spoke). Similarly, <b>patior</b> (I suffer) becomes <b>passus sum</b> (I suffered). Option A, <b>patī</b>, is the present infinitive. Option B, <b>passus est</b>, is the perfect tense but in the 3rd person singular. Option C, <b>patēbam</b>, is the imperfect tense." }, { meta: "Analogies", stem: "<b>mīles</b> : <b>mīlitāris</b> :: <b>cīvis</b> : X", options: ["<b>cīvitās</b>", "<b>cīvīcō</b>", "<b>cīvīnum</b>", "<b>cīvīlis</b>"], i: 3, explanation: "The relationship is a noun denoting a person to an adjective derived from it, meaning 'pertaining to' that person or group. <b>mīles</b> (soldier) relates to <b>mīlitāris</b> (military, pertaining to a soldier). Similarly, <b>cīvis</b> (citizen) relates to <b>cīvīlis</b> (civil, pertaining to a citizen). Option A, <b>cīvitās</b>, is a noun meaning 'citizenship' or 'state'. Options B and C are not standard Latin adjective forms." }, { meta: "Analogies", stem: "<b>aedificō</b> : <b>aedificium</b> :: <b>mūniō</b> : X", options: ["<b>mūrus</b>", "<b>mūnīmentum</b>", "<b>mūnīre</b>", "<b>mūnītiō</b>"], i: 3, explanation: "The relationship is a verb (action) to a noun representing the product or result of that action. <b>aedificō</b> (to build) relates to <b>aedificium</b> (a building). Similarly, <b>mūniō</b> (to fortify) relates to <b>mūnītiō</b> (a fortification). Option A, <b>mūrus</b>, means 'wall', which is related but not the direct product noun from the verb <b>mūniō</b>. Option B, <b>mūnīmentum</b>, also means 'fortification' or 'defense', but <b>mūnītiō</b> is a more direct and common verbal noun from <b>mūniō</b>. Option C, <b>mūnīre</b>, is the present infinitive of the verb." }, { meta: "Analogies", stem: "<b>magnus</b> : <b>magnitūdō</b> :: <b>altus</b> : X", options: ["<b>altum</b>", "<b>altē</b>", "<b>altior</b>", "<b>altitūdō</b>"], i: 3, explanation: "The relationship is an adjective to its corresponding abstract noun, denoting the quality or state. <b>magnus</b> (large, great) relates to <b>magnitūdō</b> (greatness, size). Similarly, <b>altus</b> (high, deep) relates to <b>altitūdō</b> (height, depth). Option A, <b>altum</b>, is a neuter noun meaning 'the deep sea' or 'a deep place'. Option B, <b>altē</b>, is an adverb meaning 'deeply' or 'highly'. Option C, <b>altior</b>, is the comparative form of the adjective, meaning 'higher' or 'deeper'." }, { meta: "Analogies", stem: "<b>sum</b> : <b>possum</b> :: <b>eō</b> : X", options: ["<b>ferō</b>", "<b>īre</b>", "<b>īvī</b>", "<b>redeō</b>"], i: 3, explanation: "The relationship is an irregular verb to a common irregular compound verb that builds upon its meaning or structure. <b>sum</b> (to be) relates to <b>possum</b> (to be able, literally 'to be powerful'). Similarly, <b>eō</b> (to go) relates to <b>redeō</b> (to return, literally 'to go back'). Option A, <b>ferō</b>, is another irregular verb but not a compound of <b>eō</b>. Option B, <b>īre</b>, is the present infinitive of <b>eō</b>. Option C, <b>īvī</b>, is the perfect tense (1st person singular) of <b>eō</b>." }, { meta: "Analogies", stem: "<b>urbs</b> : <b>Rōma</b> :: <b>flūmen</b> : X", options: ["<b>mōns</b>", "<b>mare</b>", "<b>pontus</b>", "<b>Rhēnus</b>"], i: 3, explanation: "The relationship is a general category noun to a specific, well-known example of that category. <b>urbs</b> (city) relates to <b>Rōma</b> (Rome). Similarly, <b>flūmen</b> (river) relates to <b>Rhēnus</b> (the Rhine River), a prominent river in Caesar's Gallic Wars. Options A, B, and C (<b>mōns</b>, <b>mare</b>, <b>pontus</b>) are general nouns for 'mountain' and 'sea', which are different geographical categories." }, { meta: "Analogies", stem: "<b>hortor</b> : <b>hortātus</b> :: <b>moror</b> : X", options: ["<b>morātus est</b>", "<b>moritūrus</b>", "<b>mora</b>", "<b>morātus</b>"], i: 3, explanation: "The relationship is a deponent verb in the present tense (1st person singular) to its perfect participle (which has an active meaning for deponent verbs). <b>hortor</b> (to urge) relates to <b>hortātus</b> (having urged). Similarly, <b>moror</b> (to delay) relates to <b>morātus</b> (having delayed). Option A, <b>morātus est</b>, is the full perfect tense verb ('he delayed'), not just the participle. Option B, <b>moritūrus</b>, is the future active participle ('about to delay'). Option C, <b>mora</b>, is a noun meaning 'delay'." }, { meta: "Fill-in-the-Blank", stem: "Caesar mīlitēs iussit prīmā lūce _________ ad hostem.", options: ["pugnāre", "proficīscī", "manēre", "venīre"], i: 1, explanation: "The sentence means 'Caesar ordered the soldiers at first light _________ towards the enemy.' The verb <b>proficīscī</b> means 'to set out, depart,' which fits the context of moving towards an enemy at dawn. <br>A) <b>pugnāre</b> ('to fight') is plausible but less direct for the initial action. <br>C) <b>manēre</b> ('to remain') is the opposite of what would be ordered when moving 'ad hostem.' <br>D) <b>venīre</b> ('to come') implies movement towards the speaker, not necessarily 'towards the enemy' in this context of setting out." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs urbem expugnāre _________, sed frūstrā.", options: ["timēbant", "cōnābantur", "dormiēbant", "laudābant"], i: 1, explanation: "The sentence means 'The soldiers _________ to capture the city, but in vain.' The deponent verb <b>cōnābantur</b> (from <b>cōnor</b>) means 'they were trying' or 'they were attempting,' which perfectly fits the context of an unsuccessful effort ('sed frūstrā'). <br>A) <b>timēbant</b> ('they were fearing') does not fit the idea of attempting to capture. <br>C) <b>dormiēbant</b> ('they were sleeping') is illogical. <br>D) <b>laudābant</b> ('they were praising') makes no sense in this context." }, { meta: "Fill-in-the-Blank", stem: "Ego vōs esse fortissimōs _________.", options: ["dīcō", "sciō", "arbitror", "sentiō"], i: 2, explanation: "The sentence means 'I _________ that you are the bravest.' The deponent verb <b>arbitror</b> means 'to think, judge, consider,' which is very appropriate for expressing an opinion or judgment about someone's qualities. <br>A) <b>dīcō</b> ('I say') is possible but less nuanced for an internal thought or judgment. <br>B) <b>sciō</b> ('I know') implies certainty, which might be too strong if it's an opinion. <br>D) <b>sentiō</b> ('I feel, perceive') can work for opinions but <b>arbitror</b> often specifically implies a judgment or estimation, making it a stronger fit here." }, { meta: "Fill-in-the-Blank", stem: "Dux suōs mīlitēs ad virtūtem _________.", options: ["vetuit", "hortātus est", "timuit", "fugit"], i: 1, explanation: "The sentence means 'The leader _________ his soldiers to valor.' The deponent verb <b>hortātus est</b> (from <b>hortor</b>) means 'he encouraged, urged,' which is the natural action of a leader inspiring his troops to valor. <br>A) <b>vetuit</b> ('he forbade') is the opposite meaning. <br>C) <b>timuit</b> ('he feared') is illogical for a leader encouraging valor. <br>D) <b>fugit</b> ('he fled') is also contrary to the context." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī gladiīs et scūtīs _________ in proeliō.", options: ["habuērunt", "ūsī sunt", "fēcērunt", "vīdērunt"], i: 1, explanation: "The sentence means 'The Romans _________ swords and shields in battle.' The deponent verb <b>ūsī sunt</b> (from <b>ūtor</b>) means 'they used' and correctly takes the ablative case (<b>gladiīs et scūtīs</b>). <br>A) <b>habuērunt</b> ('they had') means possession, not usage. <br>C) <b>fēcērunt</b> ('they made') is incorrect; they used them, not made them in battle. <br>D) <b>vīdērunt</b> ('they saw') is irrelevant to the action of employing weapons." }, { meta: "Fill-in-the-Blank", stem: "Lēgātus ducem per silvam _________.", options: ["praecēdit", "sequēbātur", "fugit", "oppugnat"], i: 1, explanation: "The sentence means 'The legate _________ the leader through the forest.' The deponent verb <b>sequēbātur</b> (from <b>sequor</b>) means 'he was following,' which is a natural action for a legate in relation to a leader. <br>A) <b>praecēdit</b> ('he goes before, precedes') is the opposite action. <br>C) <b>fugit</b> ('he fled') is contrary to the idea of accompanying a leader. <br>D) <b>oppugnat</b> ('he attacks') is illogical in this context." }, { meta: "Fill-in-the-Blank", stem: "Nōn licet nōbīs hīc diūtius _________.", options: ["currere", "morārī", "dormīre", "labōrāre"], i: 1, explanation: "The sentence means 'It is not permitted for us to _________ here any longer.' The deponent verb <b>morārī</b> (from <b>moror</b>) means 'to delay, linger,' which fits the context of not being allowed to stay longer. <br>A) <b>currere</b> ('to run') is not the primary meaning implied by 'diūtius.' <br>C) <b>dormīre</b> ('to sleep') is too specific and not the general sense of 'delaying.' <br>D) <b>labōrāre</b> ('to work') is also too specific and doesn't fit the 'not allowed to stay longer' nuance as well as 'delay.'" }, { meta: "Fill-in-the-Blank", stem: "Hostēs nōn _________ Rōmānōs trānsīre flūmen.", options: ["iussērunt", "voluērunt", "passī sunt", "vetuērunt"], i: 2, explanation: "The sentence means 'The enemies did not _________ the Romans to cross the river.' The deponent verb <b>passī sunt</b> (from <b>patior</b>) means 'they allowed' or 'they suffered/endured.' In this context, 'did not allow' makes perfect sense. <br>A) <b>iussērunt</b> ('they ordered') implies a command, not permission. <br>B) <b>voluērunt</b> ('they wished') is a possibility but <b>patior</b> is specifically 'to allow.' <br>D) <b>vetuērunt</b> ('they forbade') is the opposite of 'allowed' and would mean 'The enemies forbade the Romans to cross,' which is grammatically correct but semantically distinct from 'did not allow' when the blank is for 'allow.'" }, { meta: "Fill-in-the-Blank", stem: "Cicerō in forō cum amīcīs _________.", options: ["scrīpsit", "lēgit", "loquēbātur", "audīvit"], i: 2, explanation: "The sentence means 'Cicero in the forum with friends _________.' The deponent verb <b>loquēbātur</b> (from <b>loquor</b>) means 'he was speaking' or 'he was talking,' which is a very common activity for Cicero in the forum with friends. <br>A) <b>scrīpsit</b> ('he wrote') is possible but less direct for interaction 'cum amīcīs' in the forum. <br>B) <b>lēgit</b> ('he read') is also possible but less common for a general interaction. <br>D) <b>audīvit</b> ('he heard') implies listening, not actively engaging in conversation." }, { meta: "Fill-in-the-Blank", stem: "Subitō Gallī castra Rōmāna _________.", options: ["dēfendērunt", "relīquērunt", "aggredī sunt", "aedificāvērunt"], i: 2, explanation: "The sentence means 'Suddenly the Gauls _________ the Roman camp.' The deponent verb <b>aggredī sunt</b> (from <b>aggredior</b>) means 'they attacked' or 'they approached aggressively,' which is a sudden action against an enemy camp. Note that the perfect tense of <b>aggredior</b> is <b>aggressus sum</b>, so <b>aggredī sunt</b> is an incorrect form; it should be <b>aggressī sunt</b>. However, assuming the intent was the correct verb, it is the best fit. Let's correct the option to <b>aggressī sunt</b>. <br>A) <b>dēfendērunt</b> ('they defended') is the opposite action. <br>B) <b>relīquērunt</b> ('they abandoned') is also contrary to a sudden move against a camp. <br>D) <b>aedificāvērunt</b> ('they built') makes no sense for an action against an enemy camp." }, { meta: "Circumlocution", stem: "Quid significat: <b>Ab locō ūno ad locum alium īre, praesertim cum itineris causā.</b>", options: ["manēre", "redīre", "proficīscī", "cōnsistere"], i: 2, explanation: "The Latin definition describes the act of setting out or departing from one place to another, especially for a journey. This perfectly matches the meaning of <b>proficīscī</b>, a deponent verb meaning 'to set out, depart'. Option A, <b>manēre</b>, means 'to remain'. Option B, <b>redīre</b>, means 'to return'. Option D, <b>cōnsistere</b>, means 'to halt, stand still'. All distractors represent actions opposite or different from setting out." }, { meta: "Circumlocution", stem: "Quid significat: <b>Rēs gravēs et onera quae mīlitēs in itinere sēcum ferunt, quae eōs tardant.</b>", options: ["arma", "commeātus", "impedīmenta", "cōpia"], i: 2, explanation: "The definition describes heavy things and burdens that soldiers carry with them on a march, which slow them down. This is the precise meaning of <b>impedīmenta, -ōrum</b> n. pl., 'baggage, impediments'. Option A, <b>arma</b>, means 'weapons'. Option B, <b>commeātus</b>, means 'provisions, supplies'. Option D, <b>cōpia</b>, means 'abundance, supply', or in the plural, 'troops'. While related to military context, none of the distractors accurately capture the specific concept of hindering baggage." }, { meta: "Circumlocution", stem: "Quid significat: <b>Sententia aut ratiō quaedam dē rē gerendā, saepe ā plūribus hominibus capta.</b>", options: ["factum", "cōnsilium", "fortūna", "bellum"], i: 1, explanation: "The Latin phrase defines an opinion or a certain reasoning about a thing to be done, often taken by several people. This corresponds to <b>cōnsilium, -ī</b> n., meaning 'plan, counsel, advice'. Option A, <b>factum</b>, means 'deed, act', which is the execution of a plan, not the plan itself. Option C, <b>fortūna</b>, means 'fortune, luck', which is distinct from deliberate planning. Option D, <b>bellum</b>, means 'war', a context in which plans are made, but not the plan itself." }, { meta: "Circumlocution", stem: "Quid significat: <b>Rē quādam ad fīnem aliquem adhibēre.</b>", options: ["ūtī", "habēre", "dare", "capere"], i: 0, explanation: "The definition means 'to apply a certain thing for some purpose', which is the core meaning of the deponent verb <b>ūtor, ūtī, ūsus sum</b>, 'to use, employ'. This verb famously takes the ablative case. Option B, <b>habēre</b>, means 'to have'. Option C, <b>dare</b>, means 'to give'. Option D, <b>capere</b>, means 'to take, seize'. While related to possession or action, none of these precisely convey the idea of 'using' something for a purpose." }, { meta: "Circumlocution", stem: "Quid significat: <b>Mōtus ab ūno locō ad alium, praesertim longus et difficilis.</b>", options: ["via", "cursus", "iter", "proelium"], i: 2, explanation: "The description refers to movement from one place to another, especially if it is long and difficult. This is the definition of <b>iter, itineris</b> n., 'journey, march'. Option A, <b>via</b>, means 'road, way', which is the path, not the act of moving. Option B, <b>cursus</b>, means 'running, course', a more specific type of movement. Option D, <b>proelium</b>, means 'battle', which is unrelated to the concept of movement between places." }, { meta: "Circumlocution", stem: "Quid significat: <b>Opus factum ad locum dēfendendum, ut vallum aut fossa.</b>", options: ["castra", "mūnītiō", "aedificium", "oppidum"], i: 1, explanation: "The definition describes a work made for defending a place, such as a rampart or ditch. This is the meaning of <b>mūnītiō, mūnītiōnis</b> f., 'fortification'. Option A, <b>castra</b>, means 'camp', which is a place that *has* fortifications, but is not the fortification itself. Option C, <b>aedificium</b>, means 'building', which is too general. Option D, <b>oppidum</b>, means 'town', which also *has* fortifications but is not the fortification itself." }, { meta: "Circumlocution", stem: "Quid significat: <b>Multitūdō mīlitum quae in itinere ordinātē prōcēdit.</b>", options: ["aciēs", "exercitus", "agmen", "turba"], i: 2, explanation: "The definition refers to a multitude of soldiers proceeding in an orderly fashion on a march. This is the specific meaning of <b>agmen, agminis</b> n., 'a column of men, an army on the march'. Option A, <b>aciēs</b>, means 'battle line', referring to a formation for fighting, not marching. Option B, <b>exercitus</b>, means 'army' in a general sense, not specifically the marching formation. Option D, <b>turba</b>, means 'crowd, mob', which implies disorder, the opposite of 'ordinātē'." }, { meta: "Circumlocution", stem: "Quid significat: <b>Metū afficī aut magnō honōre aliquem habēre.</b>", options: ["amāre", "timēre", "verērī", "laudāre"], i: 2, explanation: "The definition describes being affected by fear OR holding someone in great honor. This dual meaning ('to fear' and 'to revere') is characteristic of the deponent verb <b>vereor, verērī, veritus sum</b>. Option A, <b>amāre</b>, means 'to love'. Option B, <b>timēre</b>, means 'to fear', but lacks the 'revere' aspect. Option D, <b>laudāre</b>, means 'to praise', which is related to reverence but not the full scope of the verb." }, { meta: "Circumlocution", stem: "Quid significat: <b>Terminus cuiusdam reī aut extrēma pars terrae.</b>", options: ["initium", "locus", "fīnis", "spatium"], i: 2, explanation: "The definition describes the limit of a certain thing or the outermost part of a land. This matches <b>fīnis, fīnis</b> m., meaning 'end, boundary', and in the plural, 'territory'. Option A, <b>initium</b>, means 'beginning', the opposite of 'end'. Option B, <b>locus</b>, means 'place', which is too general. Option D, <b>spatium</b>, means 'space, interval', which is related but does not precisely mean 'end' or 'boundary'." }, { meta: "Circumlocution", stem: "Quid significat: <b>Operam dare ut aliquid fiat, etsī fortasse difficile est.</b>", options: ["facere", "cōnārī", "dēsinere", "perfīcere"], i: 1, explanation: "The definition means 'to give effort so that something may happen, even if perhaps it is difficult'. This accurately describes the deponent verb <b>cōnor, cōnārī, cōnātus sum</b>, 'to try, attempt'. Option A, <b>facere</b>, means 'to do, make', implying completion rather than just the effort of trying. Option C, <b>dēsinere</b>, means 'to cease, stop', which is the opposite of trying. Option D, <b>perfīcere</b>, means 'to accomplish, complete', implying success, not merely the attempt." }, { meta: "Latin to English", stem: "What is the best translation of <b>moror, morārī, morātus sum</b>?", options: ["to die", "to delay, linger", "to bite", "to remember"], i: 1, explanation: "The deponent verb <b>moror, morārī, morātus sum</b> means 'to delay' or 'to linger'. Option A, 'to die', is the translation of <b>morior, morī, mortuus sum</b>, a commonly confused deponent verb. Option C, 'to bite', is <b>mordeō, mordēre, momordī, morsum</b>. Option D, 'to remember', is <b>meminī</b> (defective verb)." }, { meta: "Latin to English", stem: "What is the best translation of <b>proficīscor, proficīscī, profectus sum</b>?", options: ["to make progress", "to accomplish", "to set out, depart", "to pour forth"], i: 2, explanation: "The deponent verb <b>proficīscor, proficīscī, profectus sum</b> means 'to set out' or 'to depart'. Option A, 'to make progress', is <b>proficiō, proficere, profēcī, profectum</b>. Option B, 'to accomplish', is <b>perficiō, perficere, perfēcī, perfectum</b>. Option D, 'to pour forth', is <b>profundō, profundere, profūdī, profūsum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>iter, itineris, n.</b>?", options: ["anger", "the same", "journey, route, march", "between"], i: 2, explanation: "The irregular noun <b>iter, itineris, n.</b> means 'journey', 'route', or 'march'. Option A, 'anger', is <b>īra, -ae, f.</b>. Option B, 'the same', is <b>īdem, eadem, idem</b>. Option D, 'between', is the preposition <b>inter</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>cōnor, cōnārī, cōnātus sum</b>?", options: ["to think", "to try, attempt", "to compel, collect", "to advise"], i: 1, explanation: "The deponent verb <b>cōnor, cōnārī, cōnātus sum</b> means 'to try' or 'to attempt'. Option A, 'to think', is <b>cōgitō, cōgitāre, cōgitāvī, cōgitātum</b>. Option C, 'to compel, collect', is <b>cōgō, cōgere, coēgī, coāctum</b>. Option D, 'to advise', is <b>moneō, monēre, monuī, monitum</b> (or <b>suādeō</b>)." }, { meta: "Latin to English", stem: "What is the best translation of <b>paene</b>?", options: ["punishment", "bread", "almost, nearly", "few"], i: 2, explanation: "The adverb <b>paene</b> means 'almost' or 'nearly'. Option A, 'punishment', is <b>poena, -ae, f.</b>. Option B, 'bread', is <b>pānis, pānis, m.</b>. Option D, 'few', is <b>paucī, -ae, -a</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>vīs, vīs, f.</b> (singular)?", options: ["wine", "man", "force, power, violence", "road"], i: 2, explanation: "The irregular noun <b>vīs, vīs, f.</b> means 'force', 'power', or 'violence' in the singular. Its plural, <b>vīrēs, vīrium</b>, means 'strength'. Option A, 'wine', is <b>vīnum, -ī, n.</b>. Option B, 'man', is <b>vir, virī, m.</b>. Option D, 'road', is <b>via, -ae, f.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>sōl, sōlis, m.</b>?", options: ["alone", "sun", "salt", "soil"], i: 1, explanation: "The noun <b>sōl, sōlis, m.</b> means 'sun'. Option A, 'alone', is the adjective <b>sōlus, -a, -um</b>. Option C, 'salt', is <b>sal, salis, m./n.</b>. Option D, 'soil', is <b>solum, -ī, n.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>hortor, hortārī, hortātus sum</b>?", options: ["to shudder", "to encourage, urge", "to carry", "to hide"], i: 1, explanation: "The deponent verb <b>hortor, hortārī, hortātus sum</b> means 'to encourage' or 'to urge'. Option A, 'to shudder', is <b>horreō, horrēre, horruī</b>. Option C, 'to carry', is <b>portō, portāre, portāvī, portātum</b>. Option D, 'to hide', is <b>cēlō, cēlāre, cēlāvī, cēlātum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>aequus, -a, -um</b>?", options: ["water", "sea, level surface", "equal, fair, level, calm", "temple, house"], i: 2, explanation: "The adjective <b>aequus, -a, -um</b> means 'equal', 'fair', 'level', or 'calm'. Option A, 'water', is <b>aqua, -ae, f.</b>. Option B, 'sea, level surface', is <b>aequor, aequoris, n.</b>. Option D, 'temple' (singular) or 'house' (plural) is <b>aedēs, aedis, f.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>patior, patī, passus sum</b>?", options: ["to obey", "father", "to suffer, endure, allow", "fatherland"], i: 2, explanation: "The deponent verb <b>patior, patī, passus sum</b> means 'to suffer', 'to endure', or 'to allow'. Option A, 'to obey', is <b>pāreō, pārēre, pāruī, pāritum</b>. Option B, 'father', is <b>pater, patris, m.</b>. Option D, 'fatherland', is <b>patria, -ae, f.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>cēdō, cēdere, cessī, cessum</b>?", options: ["to fall", "to cut, kill", "to yield, go, withdraw", "to close"], i: 2, explanation: "The verb <b>cēdō, cēdere, cessī, cessum</b> means 'to yield', 'to go', or 'to withdraw'. Option A, 'to fall', is <b>cadō, cadere, cecidī, cāsum</b>. Option B, 'to cut, kill', is <b>caedō, caedere, cecīdī, caesum</b>. Option D, 'to close', is <b>claudō, claudere, clausī, clausum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>mīror, mīrārī, mīrātus sum</b>?", options: ["soldier", "to wonder at, admire", "thousand", "wall"], i: 1, explanation: "The deponent verb <b>mīror, mīrārī, mīrātus sum</b> means 'to wonder at' or 'to admire'. Option A, 'soldier', is <b>mīles, mīlitis, m.</b>. Option C, 'thousand', is the adjective <b>mīlle</b> (or noun <b>mīlia, mīlium, n. pl.</b>). Option D, 'wall', is <b>mūrus, -ī, m.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>opus est</b>?", options: ["work, task", "there is need of, it is necessary", "effort, work", "shore"], i: 1, explanation: "The impersonal expression <b>opus est</b> means 'there is need of' or 'it is necessary' (often taking a dative of person and an ablative of the thing needed). Option A, 'work, task', is the noun <b>opus, operis, n.</b>. Option C, 'effort, work', is <b>opera, -ae, f.</b>. Option D, 'shore', is <b>ōra, -ae, f.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>ferō, ferre, tulī, lātum</b>?", options: ["wild, savage", "to bear, carry, bring, endure", "to become, happen", "iron, sword"], i: 1, explanation: "The irregular verb <b>ferō, ferre, tulī, lātum</b> means 'to bear', 'to carry', 'to bring', or 'to endure'. Option A, 'wild, savage', is the adjective <b>ferus, -a, -um</b>. Option C, 'to become, happen', is <b>fīō, fierī, factus sum</b>. Option D, 'iron, sword', is <b>ferrum, -ī, n.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>vīdeor, vidērī, vīsus sum</b>?", options: ["to see", "to conquer", "to seem, appear", "to live"], i: 2, explanation: "The deponent verb <b>vīdeor, vidērī, vīsus sum</b> is the passive of <b>videō</b> and means 'to seem' or 'to appear'. Option A, 'to see', is <b>videō, vidēre, vīdī, vīsum</b>. Option B, 'to conquer', is <b>vincō, vincere, vīcī, victum</b>. Option D, 'to live', is <b>vīvō, vīvere, vīxī, vīctum</b>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to use</b>", options: ["ūtor, ūtī, ūsus sum", "fruor, fruī, frūctus sum", "fungor, fungī, fūnctus sum", "potior, potīrī, potītus sum"], i: 0, explanation: "All options are deponent verbs that take the ablative case. However, <i>ūtor</i> is the most direct and general translation for 'to use.' <i>Fruor</i> means 'to enjoy,' <i>fungor</i> means 'to perform' or 'to execute,' and <i>potior</i> means 'to get possession of' or 'to obtain.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>army (on the march)</b>", options: ["exercitus, -ūs, m.", "agmen, agminis, n.", "aciēs, aciēī, f.", "legiō, legiōnis, f."], i: 1, explanation: "While <i>exercitus</i> is the general term for 'army,' <i>agmen</i> specifically refers to an army on the march, in a column, or in a procession. <i>Aciēs</i> refers to a battle line or the keen edge of a weapon. <i>Legiō</i> means 'legion.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to try</b>", options: ["cōnor, cōnārī, cōnātus sum", "temptō, temptāre, temptāvī, temptātus", "studeō, studēre, studuī", "labōrō, labōrāre, labōrāvī, labōrātus"], i: 0, explanation: "<i>Cōnor</i> is the most common deponent verb for 'to try' or 'to attempt.' <i>Temptō</i> also means 'to try' or 'to test,' but can also mean 'to attack' or 'to tempt.' <i>Studeō</i> means 'to be eager for,' 'to strive for,' or 'to study,' and takes the dative. <i>Labōrō</i> means 'to work' or 'to toil.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>sea</b>", options: ["mare, maris, n.", "pelagus, -ī, n.", "aequor, aequoris, n.", "pontus, -ī, m."], i: 0, explanation: "<i>Mare</i> is the most common and general Latin word for 'sea,' a 3rd declension neuter noun. <i>Pelagus</i> is a Greek loanword, often used poetically. <i>Aequor</i> literally means 'a level surface' and is often used poetically for the sea. <i>Pontus</i> is also a poetic word for the sea, derived from Greek." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>to fear (reverently or respectfully)</b>", options: ["timeō, timēre, timuī", "metuō, metuere, metuī", "vereor, verērī, veritus sum", "horreō, horrēre, horruī"], i: 2, explanation: "<i>Vereor</i> is a deponent verb that often implies a respectful or reverential fear, or a fear of shame. <i>Timeō</i> is the general word for 'to fear.' <i>Metuō</i> often implies a more anxious or apprehensive fear of danger. <i>Horreō</i> means 'to shudder' or 'to dread.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>journey / march</b>", options: ["via, viae, f.", "iter, itineris, n.", "cursus, cursūs, m.", "trānsitus, trānsitūs, m."], i: 1, explanation: "<i>Iter</i> is the irregular 3rd declension neuter noun for 'journey,' 'march,' or 'route.' <i>Via</i> is a 'road' or 'way.' <i>Cursus</i> is a 'course' or 'running.' <i>Trānsitus</i> is a 'passage' or 'crossing.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to persuade</b>", options: ["persuādeō, persuādēre, persuāsī, persuāsum", "hortor, hortārī, hortātus sum", "moneō, monēre, monuī, monitum", "cōgō, cōgere, coēgī, coāctus"], i: 0, explanation: "<i>Persuādeō</i> specifically means 'to persuade' and is one of the verbs that takes the dative case for the person persuaded. <i>Hortor</i> means 'to urge' or 'to encourage.' <i>Moneō</i> means 'to warn' or 'to advise.' <i>Cōgō</i> means 'to compel' or 'to collect.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>brave / courageous</b>", options: ["fortis, forte", "audāx, audācis", "acer, acris, acre", "strenuus, -a, -um"], i: 0, explanation: "<i>Fortis</i> is the most common and generally positive word for 'brave' or 'courageous.' <i>Audāx</i> means 'bold' or 'daring,' which can sometimes carry a negative connotation of recklessness. <i>Acer</i> means 'sharp,' 'keen,' or 'fierce.' <i>Strenuus</i> means 'energetic,' 'vigorous,' or 'strenuous.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>to set out / depart</b>", options: ["proficīscor, proficīscī, profectus sum", "discēdō, discēdere, discessī, discessum", "exeō, exīre, exiī (or exīvī), exitum", "abeō, abīre, abiī (or abīvī), abitum"], i: 0, explanation: "<i>Proficīscor</i> is a common deponent verb meaning 'to set out' or 'to depart,' especially for a journey or military expedition. While <i>discēdō</i>, <i>exeō</i>, and <i>abeō</i> also mean 'to depart' or 'to go away,' <i>proficīscor</i> carries the specific nuance of initiating a journey or campaign." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>hand</b>", options: ["manus, manūs, f.", "dextra, dextrae, f.", "palma, palmae, f.", "digitus, digitī, m."], i: 0, explanation: "<i>Manus</i> is the general word for 'hand' and is a 4th declension noun, but notably feminine (a tricky gender/declension pairing). <i>Dextra</i> refers specifically to the 'right hand' (or 'right' as a noun). <i>Palma</i> is the 'palm' of the hand. <i>Digitus</i> is a 'finger.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>to know (a fact or skill)</b>", options: ["sciō, scīre, scīvī, scītus", "nōscō, nōscere, nōvī, nōtus", "cognōscō, cognōscere, cognōvī, cognitus", "intellegō, intellegere, intellēxī, intellēctus"], i: 0, explanation: "<i>Sciō</i> means 'to know' a fact, a skill, or information. <i>Nōscō</i> means 'to get to know' or 'to learn,' and in the perfect tense, 'to know' (having learned). <i>Cognōscō</i> is similar, meaning 'to learn,' 'to recognize,' or in the perfect, 'to know.' <i>Intellegō</i> means 'to understand' or 'to comprehend.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: <b>state / commonwealth</b>", options: ["cīvitās, cīvitātis, f.", "rēs pūblica, reī pūblicae, f.", "imperium, imperiī, n.", "regnum, regnī, n."], i: 1, explanation: "<i>Rēs pūblica</i> (literally 'public thing') is the specific term for a 'republic,' 'commonwealth,' or 'state' in the sense of a political entity governing itself. <i>Cīvitās</i> means 'citizenship' or 'state' in the sense of the body of citizens. <i>Imperium</i> means 'command,' 'power,' or 'empire.' <i>Regnum</i> means 'kingdom' or 'royal power.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>each (one)</b>", options: ["quisque, quaeque, quidque (or quodque)", "ūnusquisque, ūnaquaeque, ūnumquidque (or ūnumquodque)", "omnis, omne", "uterque, utraque, utrumque"], i: 1, explanation: "<i>Ūnusquisque</i> explicitly means 'each one' or 'every single one,' emphasizing individuality. <i>Quisque</i> means 'each' or 'every,' but is often used with superlatives or reflexives. <i>Omnis</i> means 'all' or 'every' (plural or collective singular). <i>Uterque</i> means 'each of two' or 'both.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>at last / finally (after a long delay)</b>", options: ["tandem", "dēnique", "postrēmō", "aliquandō"], i: 0, explanation: "<i>Tandem</i> specifically conveys 'at last' or 'finally' after a long expectation or delay, often with a sense of relief or impatience. <i>Dēnique</i> means 'finally' in a summing-up sense, or 'in short.' <i>Postrēmō</i> means 'lastly' or 'finally' in a sequence. <i>Aliquandō</i> means 'at some time,' 'once,' or 'finally' in a general sense, but lacks the specific nuance of delay/expectation of <i>tandem</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English phrase: <b>to kill (by striking down)</b>", options: ["necō, necāre, necāvī, necātus", "interficiō, interficere, interfēcī, interfectus", "occīdō, occīdere, occīdī, occīsus", "caedō, caedere, cecīdī, caesus"], i: 2, explanation: "<i>Occīdō</i> (from <i>ob</i> + <i>caedō</i>) means 'to cut down,' 'to strike down,' and thus 'to kill,' especially in battle or by violence. <i>Necō</i> is the general word for 'to kill.' <i>Interficiō</i> means 'to kill' or 'to destroy,' often used for killing people. <i>Caedō</i> means 'to cut,' 'to strike,' or 'to fell,' and can mean 'to kill' but is more general and less specific to the act of killing a person by striking down." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>cōnor</b> simillimum?", options: ["studeō", "temptō", "incipiō", "dēsinō"], i: 1, explanation: "Verbum <b>cōnor</b> significat 'cōnārī, temptāre, sē ad aliquid applicāre'. Optiō <b>B) temptō</b> est synōnymum directum, significāns 'cōnārī, experīrī'. Optiō A) studeō significat 'cupere, studēre, dīligenter operam dare', quod est affīne sed nōn idem. Optiō C) incipiō significat 'initiāre, committere', quod est actiōnem incohāre, nōn necessariō cōnārī. Optiō D) dēsinō significat 'dēsistere, finem facere', quod est contrārium." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proficīscor</b> simillimum?", options: ["discēdō", "veniō", "maneō", "perveniō"], i: 0, explanation: "Verbum <b>proficīscor</b>, verbum dēpōnēns, significat 'proficīscī, abīre, iter facere'. Optiō <b>A) discēdō</b> est synōnymum proximum, significāns 'abīre, discedere, sē movēre'. Optiō B) veniō significat 'venīre, adesse', quod est contrārium. Optiō C) maneō significat 'manēre, remanēre', quod est etiam contrārium. Optiō D) perveniō significat 'pervenīre, advenīre', quod est ad fīnem itineris pervenīre, nōn initium." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>iter</b> simillimum?", options: ["pons", "via", "mūrus", "porta"], i: 1, explanation: "Nōmen <b>iter</b> (n., itineris) significat 'iter, via, cursus'. Optiō <b>B) via</b> est synōnymum directum, significāns 'via, trāmes, iter'. Optiō A) pons significat 'pons'. Optiō C) mūrus significat 'mūrus'. Optiō D) porta significat 'porta'. Haec verba sunt ad iter pertinentia, sed nōn ipsum iter dēsignant." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>pauper</b> simillimum?", options: ["dīves", "egēns", "fēlīx", "validus"], i: 1, explanation: "Adiectīvum <b>pauper</b> significat 'pauper, inops, nōn dīves'. Optiō <b>B) egēns</b> est synōnymum proximum, significāns 'egēns, inops, dēstitūtus'. Optiō A) dīves significat 'dīves, opulentus', quod est contrārium. Optiō C) fēlīx significat 'fēlīx, fortūnātus'. Optiō D) validus significat 'validus, fortis'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>hortor</b> simillimum?", options: ["vetō", "terreō", "incitō", "retineō"], i: 2, explanation: "Verbum <b>hortor</b>, verbum dēpōnēns, significat 'hortārī, incitāre, monēre'. Optiō <b>C) incitō</b> est synōnymum directum, significāns 'incitāre, excitāre, urgēre'. Optiō A) vetō significat 'vetāre, prohibēre', quod est contrārium. Optiō B) terreō significat 'terrēre, perterrēre'. Optiō D) retineō significat 'retinēre, cohibēre', quod est etiam contrārium." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proelium</b> simillimum?", options: ["pāx", "pugna", "castra", "arma"], i: 1, explanation: "Nōmen <b>proelium</b> (n., -ī) significat 'proelium, pugna, certāmen'. Optiō <b>B) pugna</b> est synōnymum directum, significāns 'pugna, certāmen, dīmicātiō'. Optiō A) pāx significat 'pāx', quod est contrārium. Optiō C) castra significat 'castra, tentōria'. Optiō D) arma significat 'arma, tēla', quae ad proelium pertinent sed nōn ipsum proelium sunt." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>arbitror</b> simillimum?", options: ["sciō", "ignōrō", "putō", "dubitō"], i: 2, explanation: "Verbum <b>arbitror</b>, verbum dēpōnēns, significat 'arbitrārī, putāre, iūdicāre'. Optiō <b>C) putō</b> est synōnymum proximum, significāns 'putāre, cēnsēre, exīstimāre'. Optiō A) sciō significat 'scīre, cognōscere', quod est certius quam arbitrārī. Optiō B) ignōrō significat 'ignōrāre, nōn scīre', quod est contrārium. Optiō D) dubitō significat 'dubitāre, haesitāre', quod est incertitūdinem implicat." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>cōnsilium</b> simillimum?", options: ["fortūna", "ratiō", "cāsus", "fātum"], i: 1, explanation: "Nōmen <b>cōnsilium</b> (n., -ī) significat 'cōnsilium, plānum, dēlīberātiō'. Optiō <b>B) ratiō</b> potest significāre 'ratiō, ratiōnālitās, methodus, plānum', et in contextū 'plānī' est synōnymum idōneum. Optiō A) fortūna significat 'fortūna, cāsus'. Optiō C) cāsus significat 'cāsus, fortūna, accidēns'. Optiō D) fātum significat 'fātum, dēstinātiō'. Haec verba sunt ad eventūs pertinentia, nōn ad plāna ab hominibus facta." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>timor</b> simillimum?", options: ["audācia", "spēs", "metus", "gaudium"], i: 2, explanation: "Nōmen <b>timor</b> (m., -ōris) significat 'timor, pavor, formīdō'. Optiō <b>C) metus</b> est synōnymum directum, significāns 'metus, timor, formīdō'. Optiō A) audācia significat 'audācia, fortitūdō', quod est contrārium. Optiō B) spēs significat 'spēs, exspectātiō'. Optiō D) gaudium significat 'gaudium, laetitia'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>ūtī</b> simillimum?", options: ["neglegere", "adhibēre", "omitō", "dēserere"], i: 1, explanation: "Verbum <b>ūtī</b> (verbum dēpōnēns, cum ablātīvō) significat 'ūtī, adhibēre, fruī'. Optiō <b>B) adhibēre</b> est synōnymum proximum, significāns 'adhibēre, applicāre, ūsum facere'. Optiō A) neglegere significat 'neglegere, omittere', quod est contrārium. Optiō C) omitō (vel omittō) significat 'omittere, praetermittere'. Optiō D) dēserere significat 'dēserere, relinquere'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>mīles</b> simillimum?", options: ["cīvis", "hostis", "bellātor", "dux"], i: 2, explanation: "Nōmen <b>mīles</b> (m., mīlitis) significat 'mīles, armātus'. Optiō <b>C) bellātor</b> est synōnymum proximum, significāns 'bellātor, vir bellicōsus, mīles'. Optiō A) cīvis significat 'cīvis, incolā'. Optiō B) hostis significat 'hostis, inimīcus'. Optiō D) dux significat 'dux, imperātor', quod est gradus superiōris mīlitis." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>virtūs</b> simillimum?", options: ["ignāvia", "fortitūdō", "dolor", "ōtium"], i: 1, explanation: "Nōmen <b>virtūs</b> (f., virtūtis) significat 'virtūs, fortitūdō, excellentia'. Optiō <b>B) fortitūdō</b> est synōnymum directum, praesertim quoad 'cōnsilium et animī robur in perīculīs'. Optiō A) ignāvia significat 'ignāvia, timiditās', quod est contrārium. Optiō C) dolor significat 'dolor, maeror'. Optiō D) ōtium significat 'ōtium, quiēs'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>magnitūdō</b> simillimum?", options: ["parvitās", "celeritās", "amplitūdō", "altitūdō"], i: 2, explanation: "Nōmen <b>magnitūdō</b> (f., magnitūdinis) significat 'magnitūdō, amplitūdō, granditās'. Optiō <b>C) amplitūdō</b> est synōnymum directum, significāns 'amplitūdō, magnitūdō, spatium'. Optiō A) parvitās significat 'parvitās', quod est contrārium. Optiō B) celeritās significat 'celeritās, vēlōcitās'. Optiō D) altitūdō significat 'altitūdō, profunditās', quod est speciēs magnitūdinis, nōn generalis magnitūdō." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>oppugnō</b> simillimum?", options: ["dēfendō", "cēdō", "adorior", "fugiō"], i: 2, explanation: "Verbum <b>oppugnō</b> significat 'oppugnāre, bellō petere, impetere'. Optiō <b>C) adorior</b> est synōnymum proximum, significāns 'adorīrī, impetere, aggredī'. Optiō A) dēfendō significat 'dēfendere, tūtārī', quod est contrārium. Optiō B) cēdō significat 'cēdere, recēdere', quod est contrārium. Optiō D) fugiō significat 'fugere, effugere', quod est etiam contrārium." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>difficultās</b> simillimum?", options: ["commodum", "facultās", "incommodum", "ōtium"], i: 2, explanation: "Nōmen <b>difficultās</b> (f., difficultātis) significat 'difficultās, molestia, labōr'. Optiō <b>C) incommodum</b> est synōnymum proximum, significāns 'incommodum, dētrīmentum, molestia', saepe ad difficultātēs vel obstācula referēns. Optiō A) commodum significat 'commodum, beneficium', quod est contrārium. Optiō B) facultās significat 'facultās, potestās, opportunitās'. Optiō D) ōtium significat 'ōtium, quiēs, pāx'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>hostis, hostis, m./f.</b>?", options: ["amīcus, -ī, m.", "cīvis, cīvis, m./f.", "socius, -ī, m.", "comes, comitis, m./f."], i: 0, explanation: "Antonymum vocābulī 'hostis' (enemy) est 'amīcus' (friend). 'Cīvis' significat 'citizen', 'socius' significat 'ally', et 'comes' significat 'companion'. Haec verba sunt ad hostem vel amīcum pertinentia, sed sōlum 'amīcus' est directum antonymum." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>incipiō, incipere, incēpī, inceptum</b>?", options: ["perficiō, perficere, perfēcī, perfectum", "dēsinō, dēsinere, dēsiī, dēsitum", "finiō, finīre, finīvī, finītum", "intermittō, intermittere, intermīsī, intermissum"], i: 1, explanation: "Antonymum vocābulī 'incipiō' (to begin) est 'dēsinō' (to cease, stop). Quamquam 'perficiō' (to complete) et 'finiō' (to finish) ad finem actionis pertinent, 'dēsinō' est directum antonymum 'incipiō' quod ad cessationem actionis spectat. 'Intermittō' significat 'to interrupt'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>surgō, surgere, surrēxī, surrēctum</b>?", options: ["sedeō, sedēre, sēdī, sessum", "iaceō, iacēre, iacuī", "cadō, cadere, cecidī, cāsum", "dēscendō, dēscendere, dēscendī, dēscēnsum"], i: 2, explanation: "Antonymum vocābulī 'surgō' (to rise) est 'cadō' (to fall). 'Sedeō' significat 'to sit' et 'iaceō' significat 'to lie down', quae sunt status contrāriī stantī, sed 'cadō' est actiō contrāria surgendī. 'Dēscendō' significat 'to descend', quod est actiō contrāria ascendendī, sed 'cadō' est directius antonymum 'surgō'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>prope</b>?", options: ["longē", "procul", "ultrā", "extrā"], i: 1, explanation: "Antonymum vocābulī 'prope' (near) est 'procul' (far, at a distance). 'Longē' quoque significat 'far', sed 'procul' est directius antonymum 'prope'. 'Ultrā' significat 'beyond' et 'extrā' significat 'outside'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>lentē</b>?", options: ["subitō", "prīmō", "celeriter", "statim"], i: 2, explanation: "Antonymum vocābulī 'lentē' (slowly) est 'celeriter' (quickly). 'Subitō' significat 'suddenly', 'prīmō' significat 'at first', et 'statim' significat 'immediately'. Haec ad tempus vel celeritātem pertinent, sed 'celeriter' est directum antonymum 'lentē'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>semper</b>?", options: ["rārō", "nōnnumquam", "numquam", "aliquandō"], i: 2, explanation: "Antonymum vocābulī 'semper' (always) est 'numquam' (never). 'Rārō' significat 'rarely', 'nōnnumquam' significat 'sometimes', et 'aliquandō' significat 'at some time'. Haec ad frequentiam pertinent, sed 'numquam' est directum antonymum 'semper'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>vetus, veteris</b>?", options: ["iuvenis, iuvenis, m./f.", "recēns, recentis", "novus, -a, -um", "prīmus, -a, -um"], i: 2, explanation: "Antonymum vocābulī 'vetus' (old) est 'novus' (new). 'Iuvenis' significat 'young' (referring to a person), 'recēns' significat 'recent', et 'prīmus' significat 'first'. Quamquam haec ad aetātem vel novitātem pertinent, 'novus' est directum antonymum 'vetus'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>plēnus, -a, -um</b>?", options: ["inānis, ināne", "apertus, -a, -um", "vacuus, -a, -um", "rārus, -a, -um"], i: 2, explanation: "Antonymum vocābulī 'plēnus' (full) est 'vacuus' (empty). 'Inānis' quoque significat 'empty' vel 'vain', sed 'vacuus' est communius et directius antonymum 'plēnus'. 'Apertus' significat 'open' et 'rārus' significat 'sparse' vel 'rare'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>fortis, forte</b>?", options: ["dēbilis, dēbile", "mollis, molle", "timidus, -a, -um", "inermis, inerme"], i: 2, explanation: "Antonymum vocābulī 'fortis' (brave, strong) est 'timidus' (fearful, timid). 'Dēbilis' significat 'weak', 'mollis' significat 'soft' vel 'effeminate', et 'inermis' significat 'unarmed'. Haec ad fortitūdinem vel virēs pertinent, sed 'timidus' est directum antonymum 'fortis' quoad animum." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>laetus, -a, -um</b>?", options: ["miser, misera, miserum", "maestus, -a, -um", "trīstis, trīste", "sollicitus, -a, -um"], i: 2, explanation: "Antonymum vocābulī 'laetus' (happy) est 'trīstis' (sad). 'Miser' significat 'wretched', 'maestus' significat 'sad' vel 'mournful' (quod est valde propinquum), et 'sollicitus' significat 'anxious'. 'Trīstis' est communissimum et directissimum antonymum 'laetus'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>pāx, pācis, f.</b>?", options: ["tumultus, -ūs, m.", "seditiō, seditiōnis, f.", "bellum, -ī, n.", "discordia, -ae, f."], i: 2, explanation: "Antonymum vocābulī 'pāx' (peace) est 'bellum' (war). 'Tumultus' significat 'uproar' vel 'disorder', 'seditiō' significat 'rebellion', et 'discordia' significat 'discord'. Haec ad perturbationem vel conflictum pertinent, sed 'bellum' est directum antonymum 'pāx'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>veniō, venīre, vēnī, ventum</b>?", options: ["discēdō, discēdere, discessī, discessum", "abeō, abīre, abiī/abīvī, abitum", "eō, īre, iī/īvī, itum", "fugiō, fugere, fūgī, fugitum"], i: 2, explanation: "Antonymum vocābulī 'veniō' (to come) est 'eō' (to go). Quamquam 'discēdō' (to depart), 'abeō' (to go away), et 'fugiō' (to flee) omnia significant 'to go away', 'eō' est verbum generale et directum antonymum 'veniō'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>doceō, docēre, docuī, doctum</b>?", options: ["audiō, audīre, audīvī, audītum", "oblīvīscor, oblīvīscī, oblītus sum", "discō, discere, didicī", "errō, errāre, errāvī, errātum"], i: 2, explanation: "Antonymum vocābulī 'doceō' (to teach) est 'discō' (to learn). Docēre est actiō dandi scientiam, discere est actiō accipiendī scientiam. 'Audiō' significat 'to hear', 'oblīvīscor' significat 'to forget', et 'errō' significat 'to wander' vel 'to be mistaken'." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>vīvō, vīvere, vīxī, vīctum</b>?", options: ["pereō, perīre, periī/perīvī, peritum", "moriōr, morī, mortuus sum", "occīdō, occīdere, occīdī, occīsum", "interficiō, interficere, interfēcī, interfectum"], i: 1, explanation: "Antonymum vocābulī 'vīvō' (to live) est 'moriōr' (to die). 'Pereō' significat 'to perish' vel 'to die', quod est valde propinquum, sed 'moriōr' est directum antonymum 'vīvō'. 'Occīdō' et 'interficiō' significant 'to kill', quae sunt causae mortis, nōn actiō ipsa moriendī." }, { meta: "Antonyms", stem: "Quod verbum est antonymum vocābulī <b>multus, -a, -um</b>?", options: ["nūllus, -a, -um", "singulī, -ae, -a", "paucus, -a, -um", "parvus, -a, -um"], i: 2, explanation: "Antonymum vocābulī 'multus' (much, many) est 'paucus' (few, little). 'Nūllus' significat 'no' vel 'none', 'singulī' significat 'one by one', et 'parvus' significat 'small' (referring to size, not quantity). 'Paucus' est directum antonymum 'multus' quoad quantitātem." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>dīcō</b>", "<b>loquor</b>", "<b>nārrō</b>", "<b>faciō</b>"], i: 3, explanation: 'The verbs <b>dīcō</b>, <b>loquor</b> (a deponent verb), and <b>nārrō</b> all pertain to the act of speaking or telling. <b>faciō</b>, however, means "to make" or "to do."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>mīles</b>", "<b>exercitus</b>", "<b>cīvis</b>", "<b>legiō</b>"], i: 2, explanation: "<b>mīles</b> (soldier), <b>exercitus</b> (army), and <b>legiō</b> (legion) are all terms related to the military. <b>cīvis</b> refers to a citizen." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>perīculum</b>", "<b>timor</b>", "<b>metus</b>", "<b>salūs</b>"], i: 3, explanation: '<b>perīculum</b> (danger), <b>timor</b> (fear), and <b>metus</b> (fear, dread) all denote danger or fear. <b>salūs</b> means "safety" or "welfare," which is the opposite.' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>eō</b>", "<b>ambulō</b>", "<b>maneō</b>", "<b>proficīscor</b>"], i: 2, explanation: '<b>eō</b> (go), <b>ambulō</b> (walk), and <b>proficīscor</b> (a deponent verb meaning "to set out" or "depart") are all verbs indicating movement. <b>maneō</b> means "to remain" or "to stay."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>magnus</b>", "<b>ingēns</b>", "<b>parvus</b>", "<b>amplus</b>"], i: 2, explanation: '<b>magnus</b> (great, large), <b>ingēns</b> (huge, vast), and <b>amplus</b> (large, spacious) all describe something as large or great. <b>parvus</b> means "small" or "little."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>dux</b>", "<b>imperātor</b>", "<b>mīles</b>", "<b>praefectus</b>"], i: 2, explanation: "<b>dux</b> (leader, general), <b>imperātor</b> (commander, general), and <b>praefectus</b> (commander, prefect) all refer to types of leaders or commanders. <b>mīles</b> refers to a soldier, a subordinate." }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>dō</b>", "<b>offerō</b>", "<b>accipiō</b>", "<b>praebeō</b>"], i: 2, explanation: '<b>dō</b> (give), <b>offerō</b> (offer, present), and <b>praebeō</b> (offer, provide) are all verbs meaning "to give" or "to offer." <b>accipiō</b> means "to receive" or "to accept."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>annus</b>", "<b>hōra</b>", "<b>locus</b>", "<b>diēs</b>"], i: 2, explanation: '<b>annus</b> (year), <b>hōra</b> (hour), and <b>diēs</b> (day) are all nouns referring to units of time. <b>locus</b> means "place" or "spot."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>bellum</b>", "<b>pugna</b>", "<b>pāx</b>", "<b>proelium</b>"], i: 2, explanation: '<b>bellum</b> (war), <b>pugna</b> (battle, fight), and <b>proelium</b> (battle, engagement) all refer to conflict, war, or battle. <b>pāx</b> means "peace."' }, { meta: "Odd One Out", stem: "Which of the following Latin words does NOT belong based on meaning?", options: ["<b>bonus</b>", "<b>malus</b>", "<b>probus</b>", "<b>honestus</b>"], i: 1, explanation: '<b>bonus</b> (good), <b>probus</b> (good, upright, honest), and <b>honestus</b> (honorable, respectable) all describe positive moral qualities or goodness. <b>malus</b> means "bad" or "evil."' }, { meta: "Analogies", stem: "<i>dūcō, dūcere, dūxī, ductus</i> : <i>ductus</i> :: <i>proficīscor, proficīscī, profectus sum</i> : <b>X</b>", options: ["<i>proficīscēns</i>", "<i>profectiō</i>", "<i>profectus</i>", "<i>prōficiō</i>"], i: 2, explanation: "The relationship demonstrated is between the present active infinitive (second principal part) and the perfect active participle (derived from the third principal part) of a verb. For the verb <i>dūcō</i>, the infinitive is <i>dūcere</i> and the perfect participle is <i>ductus</i>. Following this pattern, for the deponent verb <i>proficīscor</i> (to set out), the infinitive is <i>proficīscī</i> and the perfect active participle is <b><i>profectus</i></b> (having set out).<br><br>Option A, <i>proficīscēns</i>, is the present active participle. Option B, <i>profectiō</i>, is a noun meaning 'departure'. Option D, <i>prōficiō</i>, is a different verb meaning 'to make progress'." }, { meta: "Analogies", stem: "<i>urbs, urbis</i> f. : <i>urbēs</i> :: <i>iter, itineris</i> n. : <b>X</b>", options: ["<i>itinerum</i>", "<i>iterum</i>", "<i>itinera</i>", "<i>itinere</i>"], i: 2, explanation: "The relationship is between the nominative singular and the nominative plural forms of a noun. For <i>urbs, urbis</i> f. (city), the nominative plural is <i>urbēs</i>. Similarly, for the irregular noun <i>iter, itineris</i> n. (journey, route), the nominative plural is <b><i>itinera</i></b>.<br><br>Option A, <i>itinerum</i>, is the genitive plural. Option B, <i>iterum</i>, is an adverb meaning 'again'. Option D, <i>itinere</i>, is the ablative singular." }, { meta: "Analogies", stem: "<i>pugnō, pugnāre</i> : <i>pugna</i> :: <i>cohortor, cohortārī, cohortātus sum</i> : <b>X</b>", options: ["<i>cohortēs</i>", "<i>hortor</i>", "<i>cohortātiō</i>", "<i>cohortātus</i>"], i: 2, explanation: "The relationship is between a verb and a related noun that describes the action or its result. For <i>pugnō, pugnāre</i> (to fight), the related noun is <i>pugna</i> (battle). Following this pattern, for the deponent verb <i>cohortor, cohortārī, cohortātus sum</i> (to encourage, incite), the related noun describing the action is <b><i>cohortātiō</i></b> (encouragement, exhortation).<br><br>Option A, <i>cohortēs</i>, means 'cohorts' (military units). Option B, <i>hortor</i>, is a similar verb meaning 'to urge' but not the noun form of <i>cohortor</i>. Option D, <i>cohortātus</i>, is the perfect active participle of <i>cohortor</i>." }, { meta: "Analogies", stem: "<i>sequor, sequī, secūtus sum</i> : to follow :: <i>potior, potīrī, potītus sum</i> : <b>X</b>", options: ["to be able", "to get possession of", "to drink", "to rule"], i: 1, explanation: "The relationship is between a deponent verb and its primary English meaning. <i>Sequor, sequī, secūtus sum</i> means 'to follow'. Similarly, the deponent verb <i>potior, potīrī, potītus sum</i> means <b>'to get possession of'</b> or 'to obtain', and it typically takes the ablative case.<br><br>Option A, 'to be able', is associated with <i>possum</i> or <i>potēns</i>. Option C, 'to drink', is associated with <i>pōtō</i>. Option D, 'to rule', is related to <i>potestās</i> (power) or <i>imperō</i>, but not the primary meaning of <i>potior</i>." }, { meta: "Analogies", stem: "<i>mittō, mittere</i> : <i>missus</i> :: <i>loquor, loquī, locūtus sum</i> : <b>X</b>", options: ["<i>loquēns</i>", "<i>locūtiō</i>", "<i>locūtus</i>", "<i>loquēbar</i>"], i: 2, explanation: "The relationship is between the present active infinitive (second principal part) and the perfect active participle (derived from the third principal part) of a verb. For the verb <i>mittō</i>, the infinitive is <i>mittere</i> and the perfect participle is <i>missus</i>. Following this pattern, for the deponent verb <i>loquor</i> (to speak, talk), the infinitive is <i>loquī</i> and the perfect active participle is <b><i>locūtus</i></b> (having spoken).<br><br>Option A, <i>loquēns</i>, is the present active participle. Option B, <i>locūtiō</i>, is a noun meaning 'speech' or 'discourse'. Option D, <i>loquēbar</i>, is the imperfect indicative form of the verb." }, { meta: "Analogies", stem: "<i>bonus</i> : <i>bona</i> :: <i>mīlle</i> : <b>X</b>", options: ["<i>mīlitēs</i>", "<i>mīles</i>", "<i>mīlia</i>", "<i>mīlitāris</i>"], i: 2, explanation: "The relationship is between an adjective (singular) and a plural noun derived from or closely related to that adjective, often representing a collection or quantity. <i>Bonus</i> (good, adjective) can form <i>bona</i> (goods, plural noun). Similarly, <i>mīlle</i> (one thousand, adjective) forms the plural noun <b><i>mīlia</i></b> (thousands, miles). <i>Mīlia</i> is often used with a genitive plural to express 'thousands of' or as a noun meaning 'miles'.<br><br>Option A, <i>mīlitēs</i>, means 'soldiers'. Option B, <i>mīles</i>, means 'soldier'. Option D, <i>mīlitāris</i>, means 'military' (an adjective)." }, { meta: "Analogies", stem: "<i>regō, regere</i> : <i>rēctus</i> :: <i>patior, patī, passus sum</i> : <b>X</b>", options: ["<i>patiēns</i>", "<i>passiō</i>", "<i>passus</i>", "<i>pateō</i>"], i: 2, explanation: "The relationship is between the present active infinitive (second principal part) and the perfect active participle (derived from the third principal part) of a verb. For the verb <i>regō</i>, the infinitive is <i>regere</i> and the perfect participle is <i>rēctus</i>. Following this pattern, for the deponent verb <i>patior</i> (to suffer, endure; allow), the infinitive is <i>patī</i> and the perfect active participle is <b><i>passus</i></b> (having suffered/endured/allowed).<br><br>Option A, <i>patiēns</i>, is the present active participle. Option B, <i>passiō</i>, is a noun meaning 'suffering' or 'passion'. Option D, <i>pateō</i>, is a different verb meaning 'to lie open'." }, { meta: "Analogies", stem: "<i>aedificō, aedificāre</i> : <i>aedificium</i> :: <i>arbitror, arbitrārī, arbitrātus sum</i> : <b>X</b>", options: ["<i>arbitrātor</i>", "<i>arbitrium</i>", "<i>arbitrātus</i>", "<i>arbitrātiō</i>"], i: 1, explanation: "The relationship is between a verb and a related noun that describes the result or concept of the action. For <i>aedificō, aedificāre</i> (to build), the related noun is <i>aedificium</i> (building). Following this pattern, for the deponent verb <i>arbitror, arbitrārī, arbitrātus sum</i> (to think, judge), the related noun for the act of judging or the judgment itself is <b><i>arbitrium</i></b> (judgment, decision, opinion).<br><br>Option A, <i>arbitrātor</i>, is a noun meaning 'judge' or 'arbiter' (the agent). Option C, <i>arbitrātus</i>, is the perfect active participle. Option D, <i>arbitrātiō</i>, is also a noun meaning 'judgment' or 'arbitration', but <i>arbitrium</i> is more common in Caesar for a general 'judgment' or 'opinion'." }, { meta: "Analogies", stem: "<i>hortor, hortārī, hortātus sum</i> : to urge :: <i>ūtor, ūtī, ūsus sum</i> : <b>X</b>", options: ["to burn", "to use", "to be useful", "to be accustomed"], i: 1, explanation: "The relationship is between a deponent verb and its primary English meaning. <i>Hortor, hortārī, hortātus sum</i> means 'to urge'. Similarly, the deponent verb <i>ūtor, ūtī, ūsus sum</i> means <b>'to use'</b> or 'to employ', and it always takes the ablative case.<br><br>Option A, 'to burn', is associated with <i>ūrō</i>. Option C, 'to be useful', is related to the adjective <i>ūtilis</i>, but not the verb <i>ūtor</i> itself. Option D, 'to be accustomed', is the meaning of <i>soleō</i>." }, { meta: "Analogies", stem: "<i>arma, armōrum</i> n. pl. : <i>armōrum</i> :: <i>castra, castrōrum</i> n. pl. : <b>X</b>", options: ["<i>castrum</i>", "<i>castrīs</i>", "<i>castrōrum</i>", "<i>castrī</i>"], i: 2, explanation: "The relationship is between a plural-only noun (nominative form) and its genitive plural form. For <i>arma, armōrum</i> n. pl. (arms, weapons), the genitive plural is <i>armōrum</i>. Similarly, for the plural-only noun <i>castra, castrōrum</i> n. pl. (camp), the genitive plural is <b><i>castrōrum</i></b>.<br><br>Option A, <i>castrum</i>, is a singular noun meaning 'fortress' or 'fort', which is distinct from <i>castra</i> (camp). Option B, <i>castrīs</i>, is the dative or ablative plural. Option D, <i>castrī</i>, is the genitive singular of <i>castrum</i> (fortress), not <i>castra</i> (camp)." }, { meta: "Fill-in-the-Blank", stem: "Caesar exercitum trāns Rhēnum __________.", options: ["trānsīre", "trādūcere", "proficīscī", "sequī"], i: 1, explanation: "The sentence requires a verb meaning 'to lead across' because Caesar is leading an army across the Rhine. <br><b>B. trādūcere</b> (to lead across) is a transitive verb that perfectly fits the context, taking 'exercitum' (army) as its direct object. <br>A. trānsīre (to go across) is typically intransitive or takes a direct object without a preposition, but 'trādūcere' is more specific for leading an army. <br>C. proficīscī (to set out) is intransitive and doesn't convey the idea of crossing with an army. <br>D. sequī (to follow) means 'to follow' and does not fit the action of leading an army across a river." }, { meta: "Fill-in-the-Blank", stem: "Gallī, veritī nōs, arma __________ ut sē dēfenderent.", options: ["posuērunt", "trādiderant", "cēpērunt", "iēcērunt"], i: 2, explanation: "The context 'ut sē dēfenderent' (in order to defend themselves) clearly indicates that the Gauls took up arms. <br><b>C. cēpērunt</b> (they took up) is the correct perfect tense form of 'capiō' used in the idiom 'arma capere' (to take up arms). <br>A. posuērunt (they laid down) would mean they surrendered or gave up fighting, which contradicts the purpose clause. <br>B. trādiderant (they had handed over) implies surrender, which is the opposite of defending themselves. <br>D. iēcērunt (they threw) could mean they threw down their arms in surrender, again contradicting the context." }, { meta: "Fill-in-the-Blank", stem: "Propter tempestātem nāvēs diū in portū __________.", options: ["profectae sunt", "nāvigāvērunt", "morābantur", "appulsae sunt"], i: 2, explanation: "The phrase 'diū in portū' (for a long time in the harbor) implies that the ships were delayed or staying. <br><b>C. morābantur</b> (they were delaying/staying) is the imperfect deponent verb 'moror' which fits this meaning perfectly. <br>A. profectae sunt (they set out) is the opposite of staying in the harbor. <br>B. nāvigāvērunt (they sailed) is also the opposite, as they were prevented from sailing by the storm. <br>D. appulsae sunt (they landed/put in) implies arrival at a port, not an extended stay due to bad weather." }, { meta: "Fill-in-the-Blank", stem: "Caesar hostēs magnā __________ superāvit, quod mīlitēs eius nūllum timōrem habuērunt.", options: ["celeritāte", "virtūte", "fortūnā", "dīligentiā"], i: 1, explanation: "The clause 'quod mīlitēs eius nūllum timōrem habuērunt' (because his soldiers had no fear) provides a strong clue that the victory was due to the soldiers' courage. <br><b>B. virtūte</b> (courage, valor) is an ablative of manner that perfectly aligns with the soldiers' lack of fear. <br>A. celeritāte (speed) is plausible for military victory but not directly supported by the 'no fear' clause. <br>C. fortūnā (fortune, luck) is also a possible factor in victory but doesn't connect to the soldiers' emotional state. <br>D. dīligentiā (diligence, carefulness) is a positive quality but less directly linked to overcoming an enemy due to a lack of fear." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī __________ armīs et equīs captīs.", options: ["frūēbantur", "potībantur", "ūtēbantur", "verēbantur"], i: 2, explanation: "The sentence describes the Romans' action with captured arms and horses. The verb required should mean 'to use' and take an ablative object. <br><b>C. ūtēbantur</b> (they were using) is the imperfect deponent of 'ūtor', which means 'to use' and governs the ablative case ('armīs et equīs captīs'). <br>A. frūēbantur (they were enjoying) also takes the ablative, but 'using' captured equipment is a more direct and common military action than 'enjoying' it. <br>B. potībantur (they were getting possession of/mastering) takes the ablative or genitive, but implies acquiring or controlling, not necessarily the ongoing use. <br>D. verēbantur (they were fearing) takes an object in the accusative or a 'nē' clause and does not fit the context." }, { meta: "Fill-in-the-Blank", stem: "Caesar, __________ cōgnitō, ad urbem contendit ut cīvēs servāret.", options: ["proeliō", "perīculō", "adventū", "cōnsiliō"], i: 2, explanation: "The ablative absolute '__________ cōgnitō' combined with 'ad urbem contendit ut cīvēs servāret' (hastened to the city to save the citizens) suggests that Caesar learned of an event that necessitated his rapid movement to protect the city. An 'arrival' is a common trigger for such a response in Caesar's narratives. <br><b>C. adventū</b> (arrival) fits perfectly, implying the arrival of an enemy or perhaps an ally that Caesar needed to meet. 'Adventus cōgnitō' is a very common phrase in Caesar. <br>A. proeliō (battle) could be known, but 'the battle having been known' doesn't as strongly imply a need to rush to save citizens as an 'arrival' does. <br>B. perīculō (danger) could be known, but 'perīculō cōgnitō' is less idiomatic than 'adventū cōgnitō' for prompting immediate military movement to a city. <br>D. cōnsiliō (plan) could be known, but usually refers to an enemy's plan, and while plausible, 'adventū' is a more direct cause for rushing to defend a city." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs __________ nē hostēs fūgerent.", options: ["cōnfīsī sunt", "cūrāvērunt", "veritī sunt", "arbitrātī sunt"], i: 1, explanation: "The clause 'nē hostēs fūgerent' (that the enemy might not flee) indicates a purpose or precaution taken by the soldiers. <br><b>B. cūrāvērunt</b> (they took care) is the perfect tense of 'cūrō', which commonly takes an 'ut' or 'nē' clause to express taking care that something happens or doesn't happen. This fits the context of soldiers preventing an enemy escape. <br>A. cōnfīsī sunt (they trusted) takes the dative case and does not fit the 'nē' clause construction in this sense. <br>C. veritī sunt (they feared) takes a 'nē' clause, but it means 'they feared that the enemy would flee', which describes their emotion, not an action they took to prevent it. <br>D. arbitrātī sunt (they thought) takes an indirect statement (accusative and infinitive) and does not fit the 'nē' clause." }, { meta: "Fill-in-the-Blank", stem: "__________ dē legiōnibus in Galliā remānsērunt, dum cēterae in Germāniam profectae sunt.", options: ["ūllī", "nūllī", "nōnnullī", "quīdam"], i: 2, explanation: "The sentence states that 'the others' (cēterae) went to Germany, implying that a portion of the legions remained in Gaul. This requires a word meaning 'some' or 'a few'. <br><b>C. nōnnullī</b> (some, quite a few) is the most appropriate choice to indicate a portion of the legions. It literally means 'not none'. <br>A. ūllī (any) is typically used in negative or interrogative contexts. <br>B. nūllī (no, none) is the opposite of what is needed. <br>D. quīdam (certain ones) could also mean 'some', but 'nōnnullī' is often used when referring to a specific, but unspecified, number out of a larger group, fitting the context of legions being divided." }, { meta: "Fill-in-the-Blank", stem: "Caesar mīlitibus __________ ut pontem facerent.", options: ["persuāsit", "iussit", "imperāvit", "monuit"], i: 2, explanation: "The sentence describes Caesar giving an order to his soldiers to build a bridge, requiring a verb of commanding that takes a dative object and an 'ut' clause. <br><b>C. imperāvit</b> (he ordered) is the perfect tense of 'imperō', which means 'to command' and takes a dative object ('mīlitibus') and an 'ut' clause ('ut pontem facerent'). This is a very common construction in Caesar. <br>A. persuāsit (he persuaded) also takes a dative and an 'ut' clause, but it implies convincing rather than a direct command, which is less likely for Caesar instructing his soldiers to build a bridge. <br>B. iussit (he ordered) is the perfect tense of 'iubeō', which means 'to order' but takes an accusative object and an infinitive (e.g., 'Caesar mīlitēs pontem facere iussit'). <br>D. monuit (he warned) takes an accusative object and an 'ut' or 'nē' clause, but the meaning 'warned' does not fit the context of building a bridge." }, { meta: "Fill-in-the-Blank", stem: "Magna __________ frūmentī exercituī dēfuit.", options: ["multitūdō", "cōpia", "penūria", "dīvitiae"], i: 1, explanation: "The sentence states that something 'dēfuit' (was lacking) for the army, specifically related to 'frūmentī' (of grain). This implies a lack of a supply or abundance. <br><b>B. cōpia</b> (abundance, supply) is the correct word. 'Magna cōpia frūmentī' means 'a great supply of grain'. If a great supply was lacking, it means the army needed it. <br>A. multitūdō (multitude, crowd) refers to a large number of people or things, but not typically a 'supply' of a commodity like grain. <br>C. penūria (lack, scarcity) is the opposite of what is needed; if a 'great lack' was lacking, it would be a double negative implying abundance, which is convoluted. The sentence implies a lack of a *positive* quantity. <br>D. dīvitiae (riches, wealth) refers to general wealth, not specifically a supply of grain." }, { meta: "Circumlocution", stem: 'Quid significat: "Ex locō ūno ad alium locum iter facere, praesertim cum magnō cōnsiliō"?', options: ["<u>proficīscī</u>", "<u>revertī</u>", "<u>manēre</u>", "<u>pervenīre</u>"], i: 0, explanation: "The Latin phrase describes the act of setting out or departing from one place to another with a specific intention. Option A, <u>proficīscī</u>, a deponent verb, means 'to set out, depart', which perfectly matches the description. Option B, <u>revertī</u>, means 'to return', the opposite of setting out. Option C, <u>manēre</u>, means 'to remain' or 'stay', also contrary to the description. Option D, <u>pervenīre</u>, means 'to arrive', which is the culmination of a journey, not the act of beginning it." }, { meta: "Circumlocution", stem: 'Quid significat: "Opus difficile aggredī et studēre id perficere"?', options: ["<u>cōnor</u>", "<u>perficiō</u>", "<u>dēsinō</u>", "<u>patior</u>"], i: 0, explanation: "The Latin definition describes undertaking a difficult task and striving to accomplish it, which is the essence of 'to try' or 'to attempt'. Option A, <u>cōnor</u>, is a deponent verb meaning 'to try, attempt'. Option B, <u>perficiō</u>, means 'to accomplish' or 'to complete', which is the result of trying, not the act itself. Option C, <u>dēsinō</u>, means 'to cease' or 'to stop', the opposite of attempting. Option D, <u>patior</u>, means 'to suffer' or 'to allow', which is unrelated to the act of trying." }, { meta: "Circumlocution", stem: 'Quid significat: "Via quam hominēs vel exercitūs peragrāre solent, vel actiō eundī ab ūno locō ad alium"?', options: ["<u>iter</u>", "<u>via</u>", "<u>pōns</u>", "<u>mūrus</u>"], i: 0, explanation: "The description refers to a path traveled by people or armies, or the act of going from one place to another, clearly defining a 'journey' or 'march'. Option A, <u>iter</u> (an irregular noun, <u>itineris</u>, n.), means 'journey', 'road', or 'march', fitting the description perfectly. Option B, <u>via</u>, means 'road' or 'way', but it lacks the sense of the act of traveling. Option C, <u>pōns</u>, means 'bridge', a specific type of structure. Option D, <u>mūrus</u>, means 'wall', which is completely unrelated." }, { meta: "Circumlocution", stem: 'Quid significat: "Verbīs aliōs ad rem faciendam incitāre vel animōs eōrum firmāre"?', options: ["<u>hortor</u>", "<u>vetō</u>", "<u>impediō</u>", "<u>laudō</u>"], i: 0, explanation: "The Latin phrase describes using words to incite others to action or to strengthen their spirits, which is 'to urge' or 'to encourage'. Option A, <u>hortor</u>, a deponent verb, means 'to urge, encourage'. Option B, <u>vetō</u>, means 'to forbid', the opposite of encouraging. Option C, <u>impediō</u>, means 'to hinder' or 'to impede', also contrary to the meaning. Option D, <u>laudō</u>, means 'to praise', which is a positive form of speech but does not necessarily involve urging action." }, { meta: "Circumlocution", stem: 'Quid significat: "Locus mūnītus ubi mīlitēs ad tempus habitant"?', options: ["<u>castra</u>", "<u>urbs</u>", "<u>vīlla</u>", "<u>templum</u>"], i: 0, explanation: "The description refers to a fortified place where soldiers temporarily reside, which is a 'camp'. Option A, <u>castra</u> (a plural noun, <u>castrōrum</u>, n.), means 'camp'. Option B, <u>urbs</u>, means 'city', a permanent civilian settlement. Option C, <u>vīlla</u>, means 'country house' or 'farm', a civilian dwelling. Option D, <u>templum</u>, means 'temple', a religious building." }, { meta: "Circumlocution", stem: 'Quid significat: "Vōcem ēmittere et verbīs sententiam significāre"?', options: ["<u>loquor</u>", "<u>audiō</u>", "<u>tacēre</u>", "<u>scrībō</u>"], i: 0, explanation: "The Latin definition describes emitting a voice and signifying meaning with words, which is 'to speak' or 'to talk'. Option A, <u>loquor</u>, a deponent verb, means 'to speak, talk'. Option B, <u>audiō</u>, means 'to hear', which is the reception of speech, not its production. Option C, <u>tacēre</u>, means 'to be silent', the opposite of speaking. Option D, <u>scrībō</u>, means 'to write', which is a different mode of communication." }, { meta: "Circumlocution", stem: 'Quid significat: "Nōn prōcēdere, sed in eōdem locō vel statū diūtius manēre"?', options: ["<u>moror</u>", "<u>festīnō</u>", "<u>currō</u>", "<u>cōgō</u>"], i: 0, explanation: "The description indicates not proceeding but remaining longer in the same place or state, which means 'to delay' or 'to linger'. Option A, <u>moror</u>, a deponent verb, means 'to delay, linger'. Option B, <u>festīnō</u>, means 'to hurry' or 'to hasten', the opposite of delaying. Option C, <u>currō</u>, means 'to run', implying speed and movement. Option D, <u>cōgō</u>, means 'to compel' or 'to collect', which is unrelated." }, { meta: "Circumlocution", stem: 'Quid significat: "Rē aliquā ad fīnem certum adhibēre"?', options: ["<u>ūtor</u>", "<u>dōnō</u>", "<u>emō</u>", "<u>habeō</u>"], i: 0, explanation: "The Latin phrase describes applying something for a certain purpose, which is 'to use' or 'to employ'. Option A, <u>ūtor</u>, a deponent verb that takes the ablative case, means 'to use, employ'. Option B, <u>dōnō</u>, means 'to give' or 'to present', which is the opposite direction of action. Option C, <u>emō</u>, means 'to buy', which is about acquiring something, not necessarily using it. Option D, <u>habeō</u>, means 'to have' or 'to hold', indicating possession, not necessarily active use." }, { meta: "Circumlocution", stem: 'Quid significat: "Rērum dominus fierī vel rem aliquam in potestātem suam redigere"?', options: ["<u>potior</u>", "<u>perdō</u>", "<u>dēfendō</u>", "<u>petō</u>"], i: 0, explanation: "The description refers to becoming master of things or bringing something into one's power, which is 'to get possession of' or 'to obtain'. Option A, <u>potior</u>, a deponent verb that often takes the ablative case, means 'to get possession of, obtain'. Option B, <u>perdō</u>, means 'to lose' or 'to destroy', the opposite of obtaining. Option C, <u>dēfendō</u>, means 'to defend', which implies protecting something one already possesses. Option D, <u>petō</u>, means 'to seek' or 'to ask for', which is the action taken before potentially obtaining something." }, { meta: "Circumlocution", stem: 'Quid significat: "Impugnātiō urbis vel castrōrum cum vī et armīs, ut capiantur"?', options: ["<u>oppugnātiō</u>", "<u>dēfēnsiō</u>", "<u>pāx</u>", "<u>proelium</u>"], i: 0, explanation: "The Latin phrase describes an attack on a city or camp with force and arms, with the goal of capturing them, which is an 'assault' or 'siege'. Option A, <u>oppugnātiō</u>, means 'assault', 'attack', or 'siege'. Option B, <u>dēfēnsiō</u>, means 'defense', the opposite of an attack. Option C, <u>pāx</u>, means 'peace', which is the absence of conflict. Option D, <u>proelium</u>, means 'battle' or 'engagement', which is a more general term for fighting and doesn't specifically imply the assault of a fortified position to capture it." }, { meta: "Latin to English", stem: "What is the best translation of <b>cōnor, cōnārī, cōnātus sum</b>?", options: ["to strive", "to try", "to bring together", "to consult"], i: 1, explanation: "The deponent verb <b>cōnor, cōnārī, cōnātus sum</b> means 'to try' or 'to attempt'. Option A, 'to strive', is the meaning of <b>contendō</b>. Option C, 'to bring together', is the meaning of <b>conferō</b>. Option D, 'to consult', is the meaning of <b>cōnsulō</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>sequor, sequī, secūtus sum</b>?", options: ["to cut", "to feel", "to follow", "to seek"], i: 2, explanation: "The deponent verb <b>sequor, sequī, secūtus sum</b> means 'to follow'. Option A, 'to cut', is the meaning of <b>secō</b>. Option B, 'to feel', is the meaning of <b>sentiō</b>. Option D, 'to seek', is the meaning of <b>petō</b> or <b>quaerō</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>moror, morārī, morātus sum</b>?", options: ["to die", "to wonder", "to bite", "to delay"], i: 3, explanation: "The deponent verb <b>moror, morārī, morātus sum</b> means 'to delay'. Option A, 'to die', is the meaning of <b>morior</b>. Option B, 'to wonder', is the meaning of <b>mīror</b>. Option C, 'to bite', is the meaning of <b>mordō</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>proficīscor, proficīscī, profectus sum</b>?", options: ["to make progress", "to accomplish", "to set out", "to be useful"], i: 2, explanation: "The deponent verb <b>proficīscor, proficīscī, profectus sum</b> means 'to set out' or 'to depart'. Option A, 'to make progress', is the meaning of <b>proficiō</b>. Option B, 'to accomplish', is the meaning of <b>perficiō</b>. Option D, 'to be useful', is the meaning of <b>prōsum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>hortor, hortārī, hortātus sum</b>?", options: ["to dread", "to encourage", "to beg", "to hide"], i: 1, explanation: "The deponent verb <b>hortor, hortārī, hortātus sum</b> means 'to encourage' or 'to urge'. Option A, 'to dread', is the meaning of <b>horreō</b>. Option C, 'to beg', is the meaning of <b>ōrō</b>. Option D, 'to hide', is the meaning of <b>cēlō</b> or <b>lateō</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>uterque, utraque, utrumque</b>?", options: ["which of two", "to use", "each of two", "everywhere"], i: 2, explanation: "The adjective/pronoun <b>uterque, utraque, utrumque</b> means 'each of two' or 'both'. Option A, 'which of two', is the meaning of <b>uter, utra, utrum</b>. Option B, 'to use', is the meaning of the deponent verb <b>ūtor</b>. Option D, 'everywhere', is the meaning of the adverb <b>ubīque</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>paulum</b>?", options: ["poor", "by a little", "a little", "almost"], i: 2, explanation: "The adverb/noun <b>paulum</b> means 'a little' or 'a small amount'. Option A, 'poor', is the meaning of the adjective <b>pauper</b>. Option B, 'by a little', is the meaning of the ablative of degree of difference, <b>paulō</b>. Option D, 'almost', is the meaning of the adverb <b>paene</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>simul</b>?", options: ["similar", "at the same time", "to pretend", "always"], i: 1, explanation: "The adverb <b>simul</b> means 'at the same time' or 'together'. Option A, 'similar', is the meaning of the adjective <b>similis</b>. Option C, 'to pretend', is the meaning of the verb <b>simulō</b>. Option D, 'always', is the meaning of the adverb <b>semper</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>mīles, mīlitis, m.</b>?", options: ["thousand", "soldier", "thousands", "soft"], i: 1, explanation: "The noun <b>mīles, mīlitis, m.</b> means 'soldier'. Option A, 'thousand', is the meaning of the indeclinable adjective <b>mīlle</b>. Option C, 'thousands', is the meaning of the plural noun <b>mīlia, mīlium, n.</b>. Option D, 'soft', is the meaning of the adjective <b>mollis</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>iter, itineris, n.</b>?", options: ["the same", "journey", "between", "to go"], i: 1, explanation: "The irregular noun <b>iter, itineris, n.</b> means 'journey', 'route', or 'march'. Option A, 'the same', is the meaning of the pronoun/adjective <b>īdem, eadem, idem</b>. Option C, 'between', is the meaning of the preposition <b>inter</b>. Option D, 'to go', is the meaning of the verb <b>eō, īre, iī/īvī, itum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>cīvitās, cīvitātis, f.</b>?", options: ["citizen", "civil", "state", "food"], i: 2, explanation: "The noun <b>cīvitās, cīvitātis, f.</b> means 'state', 'citizenship', or 'tribe'. Option A, 'citizen', is the meaning of the noun <b>cīvis, cīvis, m./f.</b>. Option B, 'civil', is the meaning of the adjective <b>cīvilis, cīvile</b>. Option D, 'food', is the meaning of the noun <b>cībus, cībī, m.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>arbitror, arbitrārī, arbitrātus sum</b>?", options: ["tree", "to think", "judgment", "to consider"], i: 1, explanation: "The deponent verb <b>arbitror, arbitrārī, arbitrātus sum</b> means 'to think', 'to judge', or 'to consider'. Both 'to think' and 'to consider' are correct translations, but 'to think' is often the primary translation. Option A, 'tree', is the meaning of the noun <b>arbor, arboris, f.</b>. Option C, 'judgment', is the meaning of the noun <b>arbitrium, arbitrī, n.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>vereor, verērī, veritus sum</b>?", options: ["true", "to fear", "to turn", "word"], i: 1, explanation: "The deponent verb <b>vereor, verērī, veritus sum</b> means 'to fear' or 'to revere'. Option A, 'true', is the meaning of the adjective <b>verus, vera, verum</b>. Option C, 'to turn', is the meaning of the verb <b>vertō</b>. Option D, 'word', is the meaning of the noun <b>verbum, verbī, n.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>loquor, loquī, locūtus sum</b>?", options: ["place", "talkative", "to speak", "liquid"], i: 2, explanation: "The deponent verb <b>loquor, loquī, locūtus sum</b> means 'to speak' or 'to talk'. Option A, 'place', is the meaning of the noun <b>locus, locī, m.</b>. Option B, 'talkative', is the meaning of the adjective <b>loquāx, loquācis</b>. Option D, 'liquid', is the meaning of the noun <b>liquor, liquōris, m.</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>opus est</b>?", options: ["work", "it is necessary", "effort", "to think"], i: 1, explanation: "The impersonal expression <b>opus est</b> means 'there is need of' or 'it is necessary'. It often takes an ablative of the thing needed. Option A, 'work', is the meaning of the noun <b>opus, operis, n.</b>. Option C, 'effort', is the meaning of the noun <b>opera, operae, f.</b>. Option D, 'to think', is the meaning of the deponent verb <b>opīnor, opīnārī, opīnātus sum</b>." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to use</b>?", options: ["ūtī", "ūtor", "ūtere", "adhibēre"], i: 0, explanation: "The best translation for 'to use' is <b>ūtī</b>, a 3rd conjugation deponent verb. Deponent verbs are passive in form but active in meaning. Options B and C are forms of the verb (1st person singular present indicative and imperative, respectively). Option D, <i>adhibēre</i>, means 'to apply, employ,' which is a synonym but <i>ūtī</i> is more general for 'to use' and often takes the ablative case." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>fear</b> (noun)?", options: ["timor, timōris, m.", "metus, metūs, m.", "pavor, pavōris, m.", "timōrem"], i: 0, explanation: "While all options A, B, and C can mean 'fear,' <b>timor, timōris, m.</b> is the most common and general term for 'fear' or 'dread.' <i>Metus, metūs, m.</i> is a 4th declension noun for 'fear' or 'dread,' often implying anxiety. <i>Pavor, pavōris, m.</i> refers more to 'panic' or 'terror.' Option D, <i>timōrem</i>, is the accusative singular of <i>timor</i>, not the nominative form typically used when asking for a noun's translation." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to try, attempt</b>?", options: ["cōnārī", "temptāre", "cōnō", "cōnātus"], i: 0, explanation: "The most common and direct translation for 'to try' or 'to attempt' is <b>cōnārī</b>, a 1st conjugation deponent verb. <i>Temptāre</i> (Option B) is also 'to try' or 'to test,' but <i>cōnārī</i> is more frequent in the sense of 'to attempt to do something.' Option C, <i>cōnō</i>, is the 1st person singular present indicative form. Option D, <i>cōnātus</i>, is the perfect participle or a noun meaning 'attempt'." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>power, authority</b> (official, political)?", options: ["potestās, potestātis, f.", "imperium, imperiī, n.", "vīs, (gen. vīs), f.", "potentia, potentiae, f."], i: 0, explanation: "For official or political 'power' and 'authority,' <b>potestās, potestātis, f.</b> is the most appropriate term. <i>Imperium, imperiī, n.</i> (Option B) refers to 'command, supreme power, empire.' <i>Vīs, (gen. vīs), f.</i> (Option C) is an irregular 3rd declension noun meaning 'force, violence.' <i>Potentia, potentiae, f.</i> (Option D) denotes 'personal power, influence,' or 'ability,' rather than official authority." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to follow</b>?", options: ["sequī", "sequor", "secūtus", "sectāre"], i: 0, explanation: "The infinitive form for 'to follow' is <b>sequī</b>, a 3rd conjugation deponent verb. Option B, <i>sequor</i>, is the 1st person singular present indicative ('I follow'). Option C, <i>secūtus</i>, is the perfect participle ('having followed'). Option D, <i>sectāre</i>, is an active frequentative verb meaning 'to pursue eagerly' or 'to follow habitually,' but not the primary translation for 'to follow'." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>journey, march</b>?", options: ["iter, itineris, n.", "via, viae, f.", "cursus, cursūs, m.", "itinere"], i: 0, explanation: "The best translation for 'journey' or 'march' is <b>iter, itineris, n.</b>, an irregular 3rd declension neuter noun. <i>Via, viae, f.</i> (Option B) means 'road' or 'way.' <i>Cursus, cursūs, m.</i> (Option C) means 'running' or 'course.' Option D, <i>itinere</i>, is the ablative singular form of <i>iter</i>." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to seem</b>?", options: ["vidērī", "vidēre", "videor", "appārēre"], i: 0, explanation: "The correct translation for 'to seem' is <b>vidērī</b>, a 2nd conjugation deponent verb (passive in form, active in meaning). This is often used impersonally (e.g., <i>vidētur</i>, 'it seems'). Option B, <i>vidēre</i>, is the active infinitive 'to see.' Option C, <i>videor</i>, is the 1st person singular present indicative ('I seem' or 'I am seen'). Option D, <i>appārēre</i>, means 'to appear,' which is a synonym but less common for 'to seem'." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>wall</b> (of a city)?", options: ["mūrus, mūrī, m.", "moenia, moenium, n. pl.", "pariēs, parietis, m.", "vallum, vallī, n."], i: 1, explanation: "For the 'walls of a city' or 'fortifications,' the plural noun <b>moenia, moenium, n. pl.</b> is the most precise. <i>Mūrus, mūrī, m.</i> (Option A) refers to a single 'wall' (e.g., of a house or a city, but <i>moenia</i> is preferred for city walls collectively). <i>Pariēs, parietis, m.</i> (Option C) is the 'wall of a house' or 'room.' <i>Vallum, vallī, n.</i> (Option D) means 'rampart' or 'palisade,' a defensive earthwork." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to suffer, endure</b>?", options: ["patī", "ferre", "patior", "dolēre"], i: 0, explanation: "The best translation for 'to suffer' or 'to endure' is <b>patī</b>, a 3rd conjugation deponent verb. <i>Ferre</i> (Option B) is an irregular verb meaning 'to bear, carry, endure,' but <i>patī</i> is more direct for 'to suffer.' Option C, <i>patior</i>, is the 1st person singular present indicative ('I suffer'). Option D, <i>dolēre</i>, means 'to feel pain' or 'to grieve,' which is related but not a direct synonym for 'to suffer' in all contexts." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>wound</b> (noun)?", options: ["vulnus, vulneris, n.", "plāga, plāgae, f.", "iniūria, iniūriae, f.", "vulnera"], i: 0, explanation: "The most common and direct translation for 'wound' is <b>vulnus, vulneris, n.</b>, a 3rd declension neuter noun. <i>Plāga, plāgae, f.</i> (Option B) means 'blow, strike,' or sometimes 'wound' but is less specific. <i>Iniūria, iniūriae, f.</i> (Option C) means 'injury' in the sense of 'injustice' or 'wrong.' Option D, <i>vulnera</i>, is the nominative/accusative plural of <i>vulnus</i>." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to encourage</b>?", options: ["hortārī", "incitāre", "hortor", "monēre"], i: 0, explanation: "The best translation for 'to encourage' is <b>hortārī</b>, a 1st conjugation deponent verb. <i>Incitāre</i> (Option B) means 'to incite, rouse, urge on,' which can be similar but often implies a more forceful or even negative connotation. Option C, <i>hortor</i>, is the 1st person singular present indicative ('I encourage'). Option D, <i>monēre</i>, means 'to warn' or 'to advise,' not 'to encourage'." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>hand</b>?", options: ["manus, manūs, f.", "bracchium, bracchiī, n.", "manum", "dextra, dextrae, f."], i: 0, explanation: "The correct translation for 'hand' is <b>manus, manūs, f.</b>, which is a 4th declension noun that is feminine. This is a common point of confusion due to its declension and gender. <i>Bracchium, bracchiī, n.</i> (Option B) means 'arm.' Option C, <i>manum</i>, is the accusative singular of <i>manus</i>. <i>Dextra, dextrae, f.</i> (Option D) specifically means 'right hand' or 'right side'." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to speak, say</b>?", options: ["loquī", "dīcere", "fārī", "loquor"], i: 0, explanation: "While <i>dīcere</i> (Option B) is very common for 'to say' or 'to tell,' <b>loquī</b>, a 3rd conjugation deponent verb, is the most direct translation for 'to speak.' <i>Fārī</i> (Option C) is an archaic or poetic deponent verb meaning 'to speak.' Option D, <i>loquor</i>, is the 1st person singular present indicative ('I speak')." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>time</b>?", options: ["tempus, temporis, n.", "hōra, hōrae, f.", "spatium, spatiī, n.", "diēs, diēī, m./f."], i: 0, explanation: "The most general and common translation for 'time' is <b>tempus, temporis, n.</b>, a 3rd declension neuter noun. <i>Hōra, hōrae, f.</i> (Option B) means 'hour.' <i>Spatium, spatiī, n.</i> (Option C) means 'space' or 'interval.' <i>Diēs, diēī, m./f.</i> (Option D) means 'day,' which is a specific unit of time." }, { meta: "English to Latin", stem: "What is the best Latin translation for <b>to go forward, advance</b>?", options: ["prōgredī", "prōcēdere", "prōgredior", "īre"], i: 0, explanation: "The best translation for 'to go forward' or 'to advance' is <b>prōgredī</b>, a 3rd conjugation deponent verb. <i>Prōcēdere</i> (Option B) is an active verb meaning 'to advance' or 'to proceed,' and is a close synonym, but <i>prōgredī</i> specifically emphasizes 'going forward.' Option C, <i>prōgredior</i>, is the 1st person singular present indicative ('I go forward'). Option D, <i>īre</i>, means 'to go' generally, without the specific sense of 'forward' or 'advance'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>proficīscī</b>?", options: ["discēdere", "venīre", "manēre", "pugnāre"], i: 0, explanation: "Verbum <b>proficīscī</b> significat 'proficīscī, exīre, iter facere'. Proximum synonymum est <b>discēdere</b>, quod etiam 'abīre, exīre' significat. Optiōnēs B et C (venīre, manēre) sunt antonyma. Optiō D (pugnāre) est actiō nōn relāta." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cōnor</b>?", options: ["perficiō", "temptāre", "timēre", "dubium esse"], i: 1, explanation: "Verbum <b>cōnor</b> significat 'conārī, experīrī, tentāre'. Proximum synonymum est <b>temptāre</b>, quod 'experīrī, conārī' significat. Optiō A (perficiō) est potius effectus cōnātūs. Optiōnēs C (timēre) et D (dubium esse) nōn sunt synonyma." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>iter</b>?", options: ["bellum", "castra", "via", "proelium"], i: 2, explanation: "Nōmen <b>iter</b> (gen. itineris) significat 'iter, via, cursus'. Proximum synonymum est <b>via</b>, quod 'iter, trāmes, cursus' significat. Optiōnēs A (bellum), B (castra), et D (proelium) sunt conceptūs ad iter fortasse relātī, sed nōn synonyma ipsīus itineris." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>magnitūdō</b>?", options: ["parvitās", "amplitūdō", "celeritās", "altitūdō"], i: 1, explanation: "Nōmen <b>magnitūdō</b> significat 'magnitūdō, amplitūdō, rōbur'. Proximum synonymum est <b>amplitūdō</b>, quod 'magnitūdō, spatium, dīlātātiō' significat. Optiō A (parvitās) est antonymum. Optiōnēs C (celeritās) et D (altitūdō) sunt qualitates diversae, quamquam altitūdō ad dīmēnsiōnem pertinet." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cōnsilium</b>?", options: ["perīculum", "ratiō", "virtūs", "fortūna"], i: 1, explanation: "Nōmen <b>cōnsilium</b> significat 'cōnsilium, sententia, ratiō'. Proximum synonymum est <b>ratiō</b>, quod 'ratiō, mēthodus, cōnsilium' significat. Optiōnēs A (perīculum), C (virtūs), et D (fortūna) sunt conceptūs diversī, quamquam cōnsilium saepe ad perīcula vītanda vel fortūnam regendam adhibētur." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>hostis</b>?", options: ["socius", "inimīcus", "cīvis", "mīles"], i: 1, explanation: "Nōmen <b>hostis</b> significat 'hostis pūblicus, inimīcus'. Proximum synonymum est <b>inimīcus</b>, quod 'inimīcus persōnālis, adversārius' significat. Quamquam <i>hostis</i> saepius ad hostem pūblicum vel bellī refertur, <i>inimīcus</i> est generalior. Optiō A (socius) est antonymum. Optiōnēs C (cīvis) et D (mīles) sunt rōlēs vel status, nōn synonyma." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>paucitās</b>?", options: ["multitūdō", "numerus", "exiguitās", "potentia"], i: 2, explanation: "Nōmen <b>paucitās</b> significat 'paucitās, nūmerus parvus'. Proximum synonymum est <b>exiguitās</b>, quod 'parvitās, paucitas, tenuitās' significat. Optiō A (multitūdō) est antonymum. Optiō B (numerus) est terminus generalis, nōn specificē 'paucitās'. Optiō D (potentia) est conceptus nōn relātus." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>prohibēre</b>?", options: ["adiuvāre", "impedīre", "permittere", "cōnfirmāre"], i: 1, explanation: "Verbum <b>prohibēre</b> significat 'prohibēre, arcēre, vetāre'. Proximum synonymum est <b>impedīre</b>, quod 'impedīre, obstāre, morārī' significat. Optiōnēs A (adiuvāre) et C (permittere) sunt antonyma. Optiō D (cōnfirmāre) est actiō diversae sententiae." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>ūtor</b>?", options: ["neglegere", "adhibēre", "parāre", "petere"], i: 1, explanation: "Verbum deponēns <b>ūtor</b> (cum ablatīvō) significat 'ūtī, adhibēre, fruī'. Proximum synonymum est <b>adhibēre</b>, quod 'adhibēre, ūtī, applicāre' significat. Optiō A (neglegere) est antonymum. Optiōnēs C (parāre) et D (petere) sunt actiōnēs ad ūsum relātae, sed nōn ipsīus ūtendī." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>dēfendere</b>?", options: ["oppugnāre", "tuerī", "fugere", "tradere"], i: 1, explanation: "Verbum <b>dēfendere</b> significat 'dēfendere, tūtārī, prōtegēre'. Proximum synonymum est <b>tuerī</b>, quod 'tuerī, dēfendere, cūstōdīre' significat. Optiōnēs A (oppugnāre) et D (tradere) sunt antonyma. Optiō C (fugere) est rēactiō contrāriī generis." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>prope</b>?", options: ["longe", "paene", "semper", "saepe"], i: 1, explanation: "Adverbium <b>prope</b> significat 'prope, paene, ferē'. Proximum synonymum est <b>paene</b>, quod 'paene, ferē, vix nōn' significat. Optiō A (longe) est antonymum. Optiōnēs C (semper) et D (saepe) sunt adverbia temporis, nōn spatiī vel gradūs." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>vīcīnitās</b>?", options: ["longinquitās", "propinquitās", "urbs", "rūsticus"], i: 1, explanation: "Nōmen <b>vīcīnitās</b> significat 'vīcīnitās, propinquitās, vicīnia'. Proximum synonymum est <b>propinquitās</b>, quod 'propinquitās, vīcīnitās, affīnitās' significat. Optiō A (longinquitās) est antonymum. Optiō C (urbs) est locus, nōn conceptus propinquitātis. Optiō D (rūsticus) est adiectīvum nōn relātum." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>imperium</b>?", options: ["servitūs", "potestās", "lībertās", "pax"], i: 1, explanation: "Nōmen <b>imperium</b> significat 'imperium, potestās, iussum'. Proximum synonymum est <b>potestās</b>, quod 'potestās, auctōritās, facultās' significat. Quamquam <i>imperium</i> saepe ad potestātem mīlitārem vel summam refertur, <i>potestās</i> est terminus generalior et proximus. Optiōnēs A (servitūs) et C (lībertās) sunt antonyma. Optiō D (pax) est condiciō, nōn potestās." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>celeritās</b>?", options: ["tarditās", "magnitūdō", "vēlōcitās", "difficultās"], i: 2, explanation: "Nōmen <b>celeritās</b> significat 'celeritās, vēlōcitās, rapiditās'. Proximum synonymum est <b>vēlōcitās</b>, quod 'vēlōcitās, celeritās, rapiditās' significat. Optiō A (tarditās) est antonymum. Optiōnēs B (magnitūdō) et D (difficultās) sunt qualitates nōn relātae." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>prīstinus</b>?", options: ["novus", "antīquus", "futūrus", "praesēns"], i: 1, explanation: "Adiectīvum <b>prīstinus</b> significat 'prīstinus, vetus, antīquus'. Proximum synonymum est <b>antīquus</b>, quod 'antīquus, vetus, prīscus' significat. Optiō A (novus) est antonymum. Optiōnēs C (futūrus) et D (praesēns) sunt tempora diversa." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>hostis</b>?", options: ["amīcus", "cīvis", "socius", "dux"], i: 0, explanation: "<b>Hostis</b> (<i>enemy</i>) significat 'inimīcum' vel 'adversārium'. Antonymum eius est <b>amīcus</b> (<i>friend</i>), quod significat 'sodālem' vel 'benevolum'. <i>Cīvis</i> est 'incola urbis', <i>socius</i> est 'coniūnctus' vel 'foederātus', et <i>dux</i> est 'prīnceps' vel 'imperātor'; haec verba nūllum contrārium significātum cum <i>hoste</i> habent." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>prope</b>?", options: ["hīc", "longē", "ubīque", "saepe"], i: 1, explanation: "Adverbium <b>prope</b> (<i>near</i>) significat 'nōn longē ā'. Antonymum eius est <b>longē</b> (<i>far</i>), quod significat 'magnō intervāllō'. <i>Hīc</i> significat 'in hoc locō', <i>ubīque</i> significat 'omnibus in locīs', et <i>saepe</i> significat 'multīs temporibus'; haec verba nōn sunt contrāria <i>prope</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>saepe</b>?", options: ["semper", "numquam", "rārō", "tandem"], i: 2, explanation: "Adverbium <b>saepe</b> (<i>often</i>) significat 'multīs temporibus' vel 'frequentius'. Antonymum eius est <b>rārō</b> (<i>rarely</i>), quod significat 'paucīs temporibus' vel 'nōn frequentius'. <i>Semper</i> significat 'omnī tempore', et <i>numquam</i> significat 'nūllō tempore'; haec verba sunt contrāria inter sē, sed nōn sunt antonyma <i>saepe</i>. <i>Tandem</i> significat 'postrēmō'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>incipiō</b>?", options: ["fīniō", "dēsinō", "pōnō", "dīmittō"], i: 1, explanation: "Verbum <b>incipiō</b> (<i>to begin</i>) significat 'opus aggredī' vel 'initium facere'. Antonymum eius est <b>dēsinō</b> (<i>to cease</i>), quod significat 'intermittere' vel 'finem facere'. Quamquam <i>fīniō</i> quoque 'finem facere' significat, <i>dēsinō</i> magis aptum est ad contrārium 'incipiō' quod ad cessationem actiōnis spectat. <i>Pōnō</i> significat 'collocāre', et <i>dīmittō</i> significat 'abīre iubēre'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>summus</b>?", options: ["medius", "parvus", "īmus", "prīmus"], i: 2, explanation: "Adiectīvum <b>summus</b> (<i>highest</i>) significat 'altissimus' vel 'supremus'. Antonymum eius est <b>īmus</b> (<i>lowest</i>), quod significat 'īnfimus' vel 'profundissimus'. <i>Medius</i> significat 'inter duōs posītum', <i>parvus</i> significat 'nōn magnus', et <i>prīmus</i> significat 'ante omnēs alios'; haec verba nōn sunt contrāria <i>summus</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>celer</b>?", options: ["gravis", "lentus", "tardus", "fortis"], i: 2, explanation: "Adiectīvum <b>celer</b> (<i>swift</i>) significat 'vēlōx' vel 'rapidē movēns'. Antonymum eius est <b>tardus</b> (<i>slow</i>), quod significat 'nōn vēlōx' vel 'lentē movēns'. Quamquam <i>lentus</i> quoque 'tardus' significat, <i>tardus</i> est antonymum directius et frequentius ad <i>celer</i>. <i>Gravis</i> significat 'ponderōsus' vel 'serius', et <i>fortis</i> significat 'validus' vel 'audāx'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>ōrdō</b>?", options: ["disciplīna", "cōnsilium", "tumultus", "pugna"], i: 2, explanation: "Nōmen <b>ōrdō</b> (<i>order, rank</i>) significat 'dispositiōnem' vel 'cōnstitūtiōnem rērum'. Antonymum eius est <b>tumultus</b> (<i>uproar, confusion</i>), quod significat 'perturbātiōnem' vel 'cōnfūsiōnem' atque 'strepitum'. <i>Disciplīna</i> est 'īgnōrātiōnis ērudītiō', <i>cōnsilium</i> est 'dēlīberātiō' vel 'sententia', et <i>pugna</i> est 'certāmen armātum'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>sequor</b>?", options: ["fugiō", "stō", "praecēdō", "mittō"], i: 2, explanation: "Verbum dēpōnēns <b>sequor</b> (<i>to follow</i>) significat 'post aliquem īre' vel 'vestīgia premere'. Antonymum eius est <b>praecēdō</b> (<i>to precede</i>), quod significat 'ante aliquem īre' vel 'prīmus esse'. <i>Fugiō</i> significat 'effugere', <i>stō</i> significat 'pedibus cōnsistere', et <i>mittō</i> significat 'aliquem dēstināre'; haec verba nōn sunt contrāria <i>sequor</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>pugnō</b>?", options: ["vincō", "conciliō", "pācō", "currō"], i: 2, explanation: "Verbum <b>pugnō</b> (<i>to fight</i>) significat 'bellum gerere' vel 'manū certāre'. Antonymum eius est <b>pācō</b> (<i>to pacify</i>), quod significat 'pācem facere' vel 'tranquillum reddere'. <i>Vincō</i> significat 'superāre', quod est exitus pugnae, nōn contrārium ipsī actiōnī pugnandī. <i>Conciliō</i> significat 'amīcitiam parāre', et <i>currō</i> significat 'celeriter īre'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>vīvō</b>?", options: ["aegrōtō", "dormiō", "morior", "nāscor"], i: 2, explanation: "Verbum <b>vīvō</b> (<i>to live</i>) significat 'vītam agere' vel 'esse in vītā'. Antonymum eius est <b>morior</b> (<i>to die</i>), quod significat 'vītam dēpōnere' vel 'exspirāre'. <i>Aegrōtō</i> significat 'male valēre', <i>dormiō</i> significat 'somnō capi', et <i>nāscor</i> significat 'in vītam venīre'; haec verba nōn sunt contrāria <i>vīvō</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>laetus</b>?", options: ["īrātus", "timidus", "trīstis", "fēlīx"], i: 2, explanation: "Adiectīvum <b>laetus</b> (<i>happy</i>) significat 'hīlāris' vel 'gaudiō plēnus'. Antonymum eius est <b>trīstis</b> (<i>sad</i>), quod significat 'maestus' vel 'dolōris plēnus'. <i>Īrātus</i> significat 'īrā commōtus', <i>timidus</i> significat 'metū plēnus', et <i>fēlīx</i> significat 'fōrtūnātus'; haec verba nōn sunt contrāria <i>laetus</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>validus</b>?", options: ["aeger", "dēbilis", "īnfirmus", "lentus"], i: 2, explanation: "Adiectīvum <b>validus</b> (<i>strong</i>) significat 'robustus' vel 'potēns'. Antonymum eius est <b>īnfirmus</b> (<i>weak</i>), quod significat 'nōn validus' vel 'imbecillus'. Quamquam <i>dēbilis</i> quoque 'īnfirmus' significat, <i>īnfirmus</i> est antonymum generalius et directius ad <i>validus</i>. <i>Aeger</i> significat 'male valēns', et <i>lentus</i> significat 'tardus'." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>pauper</b>?", options: ["miser", "humilis", "dīves", "avārus"], i: 2, explanation: "Adiectīvum <b>pauper</b> (<i>poor</i>) significat 'nōn dīves' vel 'rēbus carens'. Antonymum eius est <b>dīves</b> (<i>rich</i>), quod significat 'multās opēs habēns' vel 'locuplēs'. <i>Miser</i> significat 'īnfēlīx' vel 'dolōris plēnus', <i>humilis</i> significat 'īnfimī ōrdinis' vel 'modestus', et <i>avārus</i> significat 'pecuniae cupidus'; haec verba nōn sunt contrāria <i>pauper</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>surgō</b>?", options: ["sedeō", "discēdō", "cadō", "iaceō"], i: 2, explanation: "Verbum <b>surgō</b> (<i>to rise</i>) significat 'sē ērigere' vel 'in altum ferre'. Antonymum eius est <b>cadō</b> (<i>to fall</i>), quod significat 'dēscendere' vel 'in terram dēicī'. <i>Sedeō</i> significat 'in sēde esse', <i>discēdō</i> significat 'abīre', et <i>iaceō</i> significat 'humī positus esse'; haec verba nōn sunt contrāria <i>surgō</i>." }, { meta: "Antonyms", stem: "Quod est antonymum verbum pro <b>accipiō</b>?", options: ["petō", "trādō", "dō", "teneō"], i: 2, explanation: "Verbum <b>accipiō</b> (<i>to receive</i>) significat 'sūmere' vel 'sibi habēre'. Antonymum eius est <b>dō</b> (<i>to give</i>), quod significat 'trādere' vel 'alicuī tribuere'. Quamquam <i>trādō</i> quoque 'trādere' significat, <i>dō</i> est verbum generalius et directius contrārium <i>accipiō</i>. <i>Petō</i> significat 'quaerere' vel 'rogāre', et <i>teneō</i> significat 'retinēre'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["proficīscor", "moror", "iter faciō", "contendō"], i: 1, explanation: "The words <b>proficīscor</b> (to set out, depart), <b>iter faciō</b> (to make a journey), and <b>contendō</b> (to hasten, march) all refer to various forms of movement or departure. The word <b>moror</b>, however, means 'to delay' or 'to linger', indicating a cessation or slowing of movement, making it the one that does not belong." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vallum", "fossa", "agger", "impedīmenta"], i: 3, explanation: "The words <b>vallum</b> (rampart), <b>fossa</b> (ditch), and <b>agger</b> (mound, siege-work) are all terms for fortifications or siege constructions, particularly common in military contexts like Caesar's campaigns. <b>Impedīmenta</b>, on the other hand, means 'baggage' or 'heavy equipment', which, while associated with an army, is not a type of fortification." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["centuriō", "lēgātus", "hostis", "tribūnus"], i: 2, explanation: "The words <b>centuriō</b> (centurion), <b>lēgātus</b> (legate), and <b>tribūnus</b> (tribune) all refer to specific ranks or officers within the Roman military structure. <b>Hostis</b> means 'enemy' and refers to an adversary, not a Roman military official." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["virtūs", "fortitūdō", "odium", "constantia"], i: 2, explanation: "The words <b>virtūs</b> (courage, virtue), <b>fortitūdō</b> (bravery, fortitude), and <b>constantia</b> (steadfastness, firmness) are all abstract nouns describing positive qualities or virtues. <b>Odium</b>, however, means 'hatred' and represents a negative emotion, making it the word that does not belong." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["hortor", "moneō", "pūgnō", "persuādeō"], i: 2, explanation: "The verbs <b>hortor</b> (to urge, encourage), <b>moneō</b> (to advise, warn), and <b>persuādeō</b> (to persuade) all describe actions involving communication aimed at influencing someone's thoughts or actions. <b>Pūgnō</b>, meaning 'to fight' or 'to contend', describes a physical conflict, not a communicative act of influence." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["flūmen", "montēs", "pontem", "silva"], i: 2, explanation: "The words <b>flūmen</b> (river), <b>montēs</b> (mountains), and <b>silva</b> (forest) are all terms for natural geographical features. <b>Pontem</b>, meaning 'bridge', refers to a man-made structure built to cross a natural feature, making it the one that does not belong." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["diēs", "nox", "hōra", "aetās"], i: 3, explanation: "The words <b>diēs</b> (day), <b>nox</b> (night), and <b>hōra</b> (hour) are all specific divisions or periods within a daily cycle. <b>Aetās</b>, meaning 'age' or 'lifetime', refers to a much broader span of time, often a person's entire life or a historical epoch, thus it does not belong with the daily time divisions." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["videō", "cernō", "audiō", "conspiciō"], i: 2, explanation: "The verbs <b>videō</b> (to see), <b>cernō</b> (to perceive, discern), and <b>conspiciō</b> (to catch sight of, observe) all relate to the sense of sight or visual perception. <b>Audiō</b>, however, means 'to hear' and relates to the sense of sound, making it the word that does not belong." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["pāx", "foedus", "bellum", "concilium"], i: 2, explanation: "The words <b>pāx</b> (peace), <b>foedus</b> (treaty, alliance), and <b>concilium</b> (assembly, council – often for discussion and agreement) are all associated with states of peace, agreement, or diplomatic resolution. <b>Bellum</b>, meaning 'war', represents a state of conflict and hostility, directly opposite to the other concepts." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["magnus", "multus", "celer", "ingēns"], i: 2, explanation: "The adjectives <b>magnus</b> (great, large), <b>multus</b> (much, many), and <b>ingēns</b> (huge, vast) all describe aspects of size, quantity, or extent. <b>Celer</b>, meaning 'swift' or 'quick', describes speed, which is a different quality entirely, making it the word that does not belong." }, { meta: "Analogies", stem: "<b>proficīscī</b> : <b>iter</b> :: <b>pugnāre</b> : X", options: ["<b>proelium</b>", "<b>victōria</b>", "<b>arma</b>", "<b>hostis</b>"], i: 0, explanation: "The relationship is 'Action : Associated Noun/Result'. <i>proficīscī</i> (to set out, depart) is associated with <i>iter</i> (a journey). Similarly, <i>pugnāre</i> (to fight) is associated with <i>proelium</i> (a battle). Option B, <i>victōria</i> (victory), is a possible outcome of fighting, but <i>proelium</i> is the direct noun for the act itself. Option C, <i>arma</i> (arms), are tools for fighting. Option D, <i>hostis</i> (enemy), is an agent in fighting." }, { meta: "Analogies", stem: "<b>cīvitās</b> : <b>cīvis</b> :: <b>exercitus</b> : X", options: ["<b>mīles</b>", "<b>castra</b>", "<b>imperātor</b>", "<b>bellum</b>"], i: 0, explanation: "The relationship is 'Whole : Part/Member'. A <i>cīvitās</i> (state, citizenship) is composed of <i>cīvēs</i> (citizens). An <i>exercitus</i> (army) is composed of <i>mīlitēs</i> (soldiers). Option B, <i>castra</i> (camp), is where an army stays. Option C, <i>imperātor</i> (commander), is the leader of an army, not a general member. Option D, <i>bellum</i> (war), is what an army does." }, { meta: "Analogies", stem: "<b>potīrī</b> : <b>imperiō</b> :: <b>ūtī</b> : X", options: ["<b>gladiō</b>", "<b>arma</b>", "<b>hostis</b>", "<b>dōnum</b>"], i: 0, explanation: "The relationship is 'Deponent Verb : Noun in the Ablative Case (Object)'. Both <i>potīrī</i> (to get possession of) and <i>ūtī</i> (to use) are deponent verbs that typically take their object in the ablative case. <i>potīrī</i> takes <i>imperiō</i> (command, power) in the ablative. Similarly, <i>ūtī</i> takes <i>gladiō</i> (sword) in the ablative. Option B, <i>arma</i> (arms), is a plausible object for <i>ūtī</i>, but it is in the nominative/accusative plural, not the ablative. Options C and D are not suitable objects for <i>ūtī</i> in this context." }, { meta: "Analogies", stem: "<b>cōnārī</b> : <b>temptāre</b> :: <b>timēre</b> : X", options: ["<b>verērī</b>", "<b>audēre</b>", "<b>fugere</b>", "<b>terrēre</b>"], i: 0, explanation: "The relationship is 'Synonym'. <i>cōnārī</i> (to try, attempt) is synonymous with <i>temptāre</i> (to try, test). Similarly, <i>timēre</i> (to fear) is synonymous with <i>verērī</i> (to fear, revere). Option B, <i>audēre</i> (to dare), is an antonym for fear. Option C, <i>fugere</i> (to flee), is a possible action resulting from fear. Option D, <i>terrēre</i> (to frighten), is a transitive verb meaning to cause fear in someone else." }, { meta: "Analogies", stem: "<b>castra</b> : <b>mīlitēs</b> :: <b>urbs</b> : X", options: ["<b>cīvēs</b>", "<b>aedificia</b>", "<b>forum</b>", "<b>rēx</b>"], i: 0, explanation: "The relationship is 'Location : Inhabitants'. <i>castra</i> (a military camp) is inhabited by <i>mīlitēs</i> (soldiers). An <i>urbs</i> (city) is inhabited by <i>cīvēs</i> (citizens). Option B, <i>aedificia</i> (buildings), are structures within a city. Option C, <i>forum</i> (marketplace), is a specific place within a city. Option D, <i>rēx</i> (king), is a ruler, not the general inhabitants." }, { meta: "Analogies", stem: "<b>loquī</b> : <b>verba</b> :: <b>scrībere</b> : X", options: ["<b>litterae</b>", "<b>liber</b>", "<b>stilus</b>", "<b>lēgere</b>"], i: 0, explanation: "The relationship is 'Action : Product/Result'. <i>loquī</i> (to speak) produces <i>verba</i> (words). <i>scrībere</i> (to write) produces <i>litterae</i> (letters, written documents, literature). While <i>liber</i> (book) is a written product, <i>litterae</i> is a more general and fundamental product of writing. Option C, <i>stilus</i> (stylus), is a tool for writing. Option D, <i>lēgere</i> (to read), is a related action but not the product of writing." }, { meta: "Analogies", stem: "<b>hortārī</b> : <b>mīlitēs</b> :: <b>docēre</b> : X", options: ["<b>discipulī</b>", "<b>litterae</b>", "<b>magister</b>", "<b>discere</b>"], i: 0, explanation: "The relationship is 'Action : Typical Recipient/Object'. <i>hortārī</i> (to urge, encourage) is typically directed at <i>mīlitēs</i> (soldiers). <i>docēre</i> (to teach) is typically directed at <i>discipulī</i> (students). Option B, <i>litterae</i> (literature, learning), is what is taught. Option C, <i>magister</i> (teacher), is the agent of teaching. Option D, <i>discere</i> (to learn), is what students do, not who they are." }, { meta: "Analogies", stem: "<b>iter</b> : <b>via</b> :: <b>corpus</b> : X", options: ["<b>membrum</b>", "<b>anima</b>", "<b>caput</b>", "<b>sanguis</b>"], i: 0, explanation: "The relationship is 'Whole : General Part'. An <i>iter</i> (journey) consists of a <i>via</i> (road, path). A <i>corpus</i> (body) consists of a <i>membrum</i> (limb, member, general part). While <i>caput</i> (head) is a specific part of the body, <i>membrum</i> is a more general term for any constituent part of the body, mirroring the general relationship between <i>iter</i> and <i>via</i>. Option B, <i>anima</i> (soul), is not a physical part. Option D, <i>sanguis</i> (blood), is a substance within the body, not a distinct part." }, { meta: "Analogies", stem: "<b>sequī</b> : <b>fugere</b> :: <b>incipere</b> : X", options: ["<b>fīnīre</b>", "<b>perficere</b>", "<b>continuāre</b>", "<b>morārī</b>"], i: 0, explanation: "The relationship is 'Antonym'. <i>sequī</i> (to follow) is the antonym of <i>fugere</i> (to flee, run away from). <i>incipere</i> (to begin) is the antonym of <i>fīnīre</i> (to finish, end). Option B, <i>perficere</i> (to complete, accomplish), is similar to finishing but implies success or thoroughness, whereas <i>fīnīre</i> is a direct opposite of beginning. Option C, <i>continuāre</i> (to continue), is not an antonym. Option D, <i>morārī</i> (to delay), is unrelated." }, { meta: "Analogies", stem: "<b>aedificāre</b> : <b>domus</b> :: <b>colere</b> : X", options: ["<b>ager</b>", "<b>templum</b>", "<b>cīvitās</b>", "<b>frūctus</b>"], i: 0, explanation: "The relationship is 'Action : Typical Object/Product'. <i>aedificāre</i> (to build) typically results in a <i>domus</i> (house). <i>colere</i> (to cultivate, worship) can have multiple meanings, but in the context of cultivation, it typically applies to an <i>ager</i> (field). Option B, <i>templum</i> (temple), is something that might be built or worshipped, but not cultivated. Option C, <i>cīvitās</i> (state), is too broad. Option D, <i>frūctus</i> (fruit), is a product of cultivation, but <i>ager</i> is the direct object of the action 'to cultivate'." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs scūtīs et gladiīs semper ____ in proeliō.", options: ["ūtēbantur", "ūsī sunt", "ūtentur", "ūtor"], i: 0, explanation: "The correct answer is <b>A. ūtēbantur</b>. The verb <i>ūtor, ūtī, ūsus sum</i> is a deponent verb meaning 'to use,' and it takes the ablative case (<i>scūtīs et gladiīs</i>). The adverb <i>semper</i> ('always') indicates a continuous or repeated action in the past, making the imperfect tense (<i>ūtēbantur</i>, 'they were accustomed to use' or 'they always used') the most appropriate choice. <br><br><b>B. ūsī sunt</b> is the perfect tense, which would imply a completed action, less fitting with <i>semper</i>. <br><b>C. ūtentur</b> is the future tense. <br><b>D. ūtor</b> is the first person singular present tense, incorrect in person and number." }, { meta: "Fill-in-the-Blank", stem: "Magnā ____ hostēs mūrōs urbis oppugnābant.", options: ["vī", "vīrēs", "vīribus", "vīs"], i: 0, explanation: "The correct answer is <b>A. vī</b>. The noun <i>vīs, vīs</i> (feminine) is an irregular noun meaning 'force' or 'strength.' In this sentence, 'with great force' requires the ablative case. The ablative singular of <i>vīs</i> is <i>vī</i>. <br><br><b>B. vīrēs</b> is the nominative plural. <br><b>C. vīribus</b> is the dative/ablative plural. <br><b>D. vīs</b> is the nominative singular." }, { meta: "Fill-in-the-Blank", stem: "Rēx magnās cōpiās colligere ____ ut bellum gereret.", options: ["cōnātus est", "cōnat", "cōnantur", "cōgēbat"], i: 0, explanation: "The correct answer is <b>A. cōnātus est</b>. The verb <i>cōnor, cōnārī, cōnātus sum</i> is a deponent verb meaning 'to try' or 'to attempt,' and it typically takes a complementary infinitive (<i>colligere</i>). The context implies a completed attempt in the past, making the perfect tense (<i>cōnātus est</i>, 'he tried') appropriate for the singular subject <i>Rēx</i>. <br><br><b>B. cōnat</b> is the present tense, which doesn't fit the past context. <br><b>C. cōnantur</b> is the present plural. <br><b>D. cōgēbat</b> means 'he was compelling' or 'he was gathering,' which is a different verb (<i>cōgō, cōgere, coēgī, coāctus</i>) and does not fit the meaning 'tried to gather' as well as <i>cōnor</i>." }, { meta: "Fill-in-the-Blank", stem: "Post paucōs diēs Caesar cum legiōnibus ex urbe ____.", options: ["profectus est", "proficīscētur", "proficīscitur", "profectī sunt"], i: 0, explanation: "The correct answer is <b>A. profectus est</b>. The verb <i>proficīscor, proficīscī, profectus sum</i> is a deponent verb meaning 'to set out' or 'to depart.' The phrase <i>Post paucōs diēs</i> ('After a few days') indicates a past action, making the perfect tense (<i>profectus est</i>, 'he set out') the correct choice for the singular subject <i>Caesar</i>. <br><br><b>B. proficīscētur</b> is the future tense. <br><b>C. proficīscitur</b> is the present tense. <br><b>D. profectī sunt</b> is the perfect plural, incorrect for the singular subject <i>Caesar</i>." }, { meta: "Fill-in-the-Blank", stem: "Rōmānī tandem castrīs hostium ____.", options: ["potītī sunt", "potiuntur", "potuērunt", "potīrī"], i: 0, explanation: "The correct answer is <b>A. potītī sunt</b>. The verb <i>potior, potīrī, potītus sum</i> is a deponent verb meaning 'to get possession of' or 'to obtain,' and it typically takes the ablative case (<i>castrīs hostium</i>, 'of the enemy's camp'). The adverb <i>tandem</i> ('at last') suggests a completed action in the past, making the perfect tense (<i>potītī sunt</i>, 'they got possession of') the appropriate choice for the plural subject <i>Rōmānī</i>. <br><br><b>B. potiuntur</b> is the present tense. <br><b>C. potuērunt</b> is the perfect tense of <i>possum</i> ('to be able'), a different verb. <br><b>D. potīrī</b> is the present infinitive." }, { meta: "Fill-in-the-Blank", stem: "Longum et difficile ____ per montēs fēcimus.", options: ["iter", "itinera", "itinerī", "itineris"], i: 0, explanation: "The correct answer is <b>A. iter</b>. The noun <i>iter, itineris</i> (neuter) is an irregular noun meaning 'journey' or 'route.' In this sentence, 'we made a long and difficult journey,' <i>iter</i> is the direct object of <i>fēcimus</i> ('we made') and thus needs to be in the accusative case. The accusative singular of <i>iter</i> is <i>iter</i>. <br><br><b>B. itinera</b> is the nominative/accusative plural. <br><b>C. itinerī</b> is the dative singular. <br><b>D. itineris</b> is the genitive singular." }, { meta: "Fill-in-the-Blank", stem: "Dux mīlitēs suōs hortātus est ut fortissimē ____.", options: ["sequerentur", "secūtī sunt", "sequuntur", "sequī"], i: 0, explanation: "The correct answer is <b>A. sequerentur</b>. This sentence contains an indirect command, introduced by <i>hortātus est ut</i> ('he urged that'). Indirect commands require the subjunctive mood. The main verb <i>hortātus est</i> is perfect (past tense), so the subjunctive in the subordinate clause must be imperfect (for contemporaneous action) or pluperfect (for prior action). Here, 'to follow' is contemporaneous with 'urged,' so the imperfect subjunctive <i>sequerentur</i> ('they should follow') is correct for the plural subject <i>mīlitēs</i>. The verb <i>sequor, sequī, secūtus sum</i> is deponent. <br><br><b>B. secūtī sunt</b> is the perfect indicative. <br><b>C. sequuntur</b> is the present indicative. <br><b>D. sequī</b> is the present infinitive. None of these are in the correct mood or tense for an indirect command." }, { meta: "Fill-in-the-Blank", stem: "Caesar suōs mīlitēs ad pugnam ____.", options: ["hortātus est", "hortātur", "hortantur", "hortārī"], i: 0, explanation: "The correct answer is <b>A. hortātus est</b>. The verb <i>hortor, hortārī, hortātus sum</i> is a deponent verb meaning 'to urge' or 'to encourage.' The context implies a past action, making the perfect tense (<i>hortātus est</i>, 'he urged') the appropriate choice for the singular subject <i>Caesar</i>. <br><br><b>B. hortātur</b> is the present tense. <br><b>C. hortantur</b> is the present plural. <br><b>D. hortārī</b> is the present infinitive." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs post bellum ad ____ suās rediērunt.", options: ["domōs", "domī", "domibus", "domum"], i: 0, explanation: "The correct answer is <b>A. domōs</b>. The noun <i>domus, domūs</i> (feminine) is an irregular noun meaning 'house' or 'home.' For place to which, <i>domus</i> uses the accusative case without a preposition. Since <i>mīlitēs</i> ('soldiers') implies multiple homes, the accusative plural <i>domōs</i> ('to their homes') is required. <br><br><b>B. domī</b> is the locative singular, meaning 'at home.' <br><b>C. domibus</b> is the dative/ablative plural. <br><b>D. domum</b> is the accusative singular, meaning 'to home' (singular)." }, { meta: "Fill-in-the-Blank", stem: "Nōn ____ hostēs, sed prō patriā pugnābimus.", options: ["verēmur", "veritī sumus", "verēbāmur", "verērī"], i: 0, explanation: "The correct answer is <b>A. verēmur</b>. The verb <i>vereor, verērī, veritus sum</i> is a deponent verb meaning 'to fear' or 'to be afraid.' The second clause, <i>pugnābimus</i> ('we will fight'), is in the future tense, but the first clause expresses a present state of not fearing. Therefore, the present tense, first person plural (to agree with the implied 'we' from <i>pugnābimus</i>), <i>verēmur</i> ('we do not fear'), is correct. <br><br><b>B. veritī sumus</b> is the perfect tense. <br><b>C. verēbāmur</b> is the imperfect tense. <br><b>D. verērī</b> is the present infinitive." }, { meta: "Circumlocution", stem: "Quod verbum significat: <b>Ūnus locō ad alium locum sē movēre, praesertim cum itinerī initium datur.</b>", options: ["ambulāre", "manēre", "proficīscī", "redīre"], i: 2, explanation: "The Latin definition describes the act of setting out or departing from one place to another, especially at the beginning of a journey. <br>Option C, <b>proficīscī</b> (to set out, depart), is the correct deponent verb. <br>Option A, <b>ambulāre</b> (to walk), is too general. <br>Option B, <b>manēre</b> (to remain), is the opposite. <br>Option D, <b>redīre</b> (to return), implies movement in the opposite direction." }, { meta: "Circumlocution", stem: "Quod verbum significat: <b>Aliquid agere velle et id facere incipere, etsī fortasse nōn perficiētur.</b>", options: ["perfīcere", "dēsinere", "cōnārī", "velle"], i: 2, explanation: "The Latin definition describes the action of wishing to do something and beginning to do it, even if it might not be completed. <br>Option C, <b>cōnārī</b> (to try, attempt), accurately captures this meaning. <br>Option A, <b>perfīcere</b> (to complete), is the opposite of the potential outcome mentioned. <br>Option B, <b>dēsinere</b> (to cease), is also an opposite action. <br>Option D, <b>velle</b> (to wish), is only a part of the definition, not the full action of attempting." }, { meta: "Circumlocution", stem: "Quod nōmen significat: <b>Locus mūnītus ubi mīlitēs per noctem aut per longum tempus habitant.</b>", options: ["urbs", "castra", "vīcus", "domus"], i: 1, explanation: "The Latin definition describes a fortified place where soldiers live for a night or a longer period. <br>Option B, <b>castra</b> (camp), specifically refers to a military encampment. <br>Option A, <b>urbs</b> (city), is a general term for a large settlement. <br>Option C, <b>vīcus</b> (village), is too small and not necessarily fortified for military use. <br>Option D, <b>domus</b> (house), refers to an individual dwelling." }, { meta: "Circumlocution", stem: "Quod nōmen significat: <b>Via quam hominēs aut animālia eunt ab ūno locō ad alium, vel ipsa actiō eundī.</b>", options: ["via", "pōns", "iter", "mūrus"], i: 2, explanation: "The Latin definition refers to the path taken by people or animals from one place to another, or the act of going itself. <br>Option C, <b>iter</b> (journey, road, march), perfectly encapsulates both the path and the act of traveling. <br>Option A, <b>via</b> (road, way), is part of the definition but less comprehensive than <i>iter</i>, which emphasizes the journey aspect. <br>Option B, <b>pōns</b> (bridge), is a specific type of structure, not a general path or journey. <br>Option D, <b>mūrus</b> (wall), is entirely unrelated." }, { meta: "Circumlocution", stem: "Quod verbum significat: <b>Aliquid in manūs sūmere et id ad suum fīnem adhibēre.</b>", options: ["habēre", "ūtī", "emere", "dāre"], i: 1, explanation: "The Latin definition describes the action of taking something into one's hands and applying it to one's purpose. <br>Option B, <b>ūtī</b> (to use, employ), correctly translates this concept. <br>Option A, <b>habēre</b> (to have), is too passive and doesn't imply active application. <br>Option C, <b>emere</b> (to buy), refers to acquiring something through purchase. <br>Option D, <b>dāre</b> (to give), is the opposite of taking or using." }, { meta: "Circumlocution", stem: "Quod nōmen significat: <b>Persona quae in potestāte alterīus gentis tenētur ut pacta servētur.</b>", options: ["servus", "cīvis", "obsēs", "captīvus"], i: 2, explanation: "The Latin definition describes a person held by another nation to ensure that agreements are kept. <br>Option C, <b>obsēs</b> (hostage), precisely fits this description. <br>Option A, <b>servus</b> (slave), implies a different form of servitude, not specifically for guaranteeing pacts. <br>Option B, <b>cīvis</b> (citizen), is a general term for a member of a state. <br>Option D, <b>captīvus</b> (captive), is similar but lacks the specific connotation of being a guarantee for an agreement." }, { meta: "Circumlocution", stem: "Quod nōmen significat: <b>Multitūdō mīlitum quae in itinere est, nōn in aciē.</b>", options: ["aciēs", "exercitus", "agmen", "turba"], i: 2, explanation: "The Latin definition refers to a multitude of soldiers that is on the march, not in battle line. <br>Option C, <b>agmen</b> (column of soldiers, army on the march), is the correct term. <br>Option A, <b>aciēs</b> (battle line), is explicitly excluded by the definition. <br>Option B, <b>exercitus</b> (army), is too general and can refer to an army in any state (camp, battle, march). <br>Option D, <b>turba</b> (crowd), is a general term for a crowd and not specific to a military formation." }, { meta: "Circumlocution", stem: "Quod verbum significat: <b>Verba dīcere quibus aliī ad rem faciendam excitentur aut animum sūmant.</b>", options: ["vetāre", "hortārī", "tacēre", "rogāre"], i: 1, explanation: "The Latin definition describes speaking words to stir others to action or to take courage. <br>Option B, <b>hortārī</b> (to urge, encourage), is the correct deponent verb. <br>Option A, <b>vetāre</b> (to forbid), is the opposite of encouraging. <br>Option C, <b>tacēre</b> (to be silent), is the opposite of speaking. <br>Option D, <b>rogāre</b> (to ask), implies a request, not necessarily encouragement or urging." }, { meta: "Circumlocution", stem: "Quod nōmen significat: <b>Certāmen armātum inter duās partēs mīlitum.</b>", options: ["pāx", "bellum", "proelium", "conloquium"], i: 2, explanation: "The Latin definition describes an armed struggle between two sides of soldiers. <br>Option C, <b>proelium</b> (battle, engagement), is the precise term for a single armed conflict. <br>Option A, <b>pāx</b> (peace), is the opposite. <br>Option B, <b>bellum</b> (war), is a broader concept encompassing a series of conflicts over time. <br>Option D, <b>conloquium</b> (conference, discussion), is a peaceful meeting, not an armed struggle." }, { meta: "Circumlocution", stem: "Quod verbum significat: <b>Dolōrem ferre aut rem nōn impedīre, sed eam accipere.</b>", options: ["gaudēre", "resistere", "patī", "fugere"], i: 2, explanation: "The Latin definition describes bearing pain or not hindering something but accepting it. <br>Option C, <b>patī</b> (to suffer, endure, allow), accurately conveys both aspects of the definition. <br>Option A, <b>gaudēre</b> (to rejoice), is the opposite of bearing pain. <br>Option B, <b>resistere</b> (to resist), is the opposite of not hindering or accepting. <br>Option D, <b>fugere</b> (to flee), implies avoiding, rather than enduring or allowing." }];

const LEVEL_THREE = [{ meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>obsequium, -ī</b> n.", options: ["deference", "to obey", "begging", "flattery"], i: 0, explanation: "The correct translation for <b>obsequium, -ī</b> n. is 'deference' or 'compliance'.<br>Option B, 'to obey', translates the verb <b>obsequor</b>.<br>Option C, 'begging', translates the verb <b>obsecrō</b>.<br>Option D, 'flattery', is a possible secondary meaning of <b>obsequēla</b>, which is visually and semantically similar but not the primary meaning of <b>obsequium</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>īnfrāctus, -a, -um</b> (from <b>īnfrangō</b>)", options: ["broken", "unbroken", "shattered", "weakened"], i: 1, explanation: "The correct translation for <b>īnfrāctus, -a, -um</b>, when derived from <b>īnfrangō</b> (to break, crush), is 'unbroken' or 'undiscouraged'. This is a common point of confusion with <b>īnfractus</b> (short 'a'), the perfect passive participle of <b>īnfringō</b> (to break, diminish), which means 'broken' or 'shattered'. The macron on the 'ā' is crucial here. Therefore, 'unbroken' is the best answer.<br>Options A and C, 'broken' and 'shattered', would be correct for <b>īnfractus</b> (from <b>īnfringō</b>).<br>Option D, 'weakened', is a related but less precise meaning." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>sōlācium, -ī</b> n.", options: ["ground", "solace", "sun", "solitude"], i: 1, explanation: "The correct translation for <b>sōlācium, -ī</b> n. is 'comfort' or 'solace'.<br>Option A, 'ground', translates <b>sōlum, -ī</b> n.<br>Option C, 'sun', translates <b>sōl, sōlis</b> m.<br>Option D, 'solitude', translates <b>sōlitūdō, sōlitūdinis</b> f." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>dēfessus, -a, -um</b>", options: ["defended", "weary", "failing", "disappointed"], i: 1, explanation: "The correct translation for <b>dēfessus, -a, -um</b> is 'weary' or 'exhausted'. It is the perfect passive participle of <b>dēfetīscor</b>, meaning 'to become weary'.<br>Option A, 'defended', translates <b>dēfēnsus, -a, -um</b> (from <b>dēfendō</b>).<br>Option C, 'failing', would be a participle of <b>dēficiō</b>, such as <b>dēficiēns</b>.<br>Option D, 'disappointed', is not a direct translation of a visually similar word." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>dēsuper</b> adv.", options: ["from above", "from below", "to cease", "to be lacking"], i: 0, explanation: "The correct translation for the adverb <b>dēsuper</b> is 'from above' or 'from on high'. It is a compound of <b>dē</b> (from) and <b>super</b> (above).<br>Option B, 'from below', would be <b>dēsubter</b> or similar, but not <b>dēsuper</b>.<br>Option C, 'to cease', translates the verb <b>dēsinō</b>.<br>Option D, 'to be lacking', translates the verb <b>dēsum</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>ērudītus, -a, -um</b>", options: ["dug out", "learned", "burst forth", "rough"], i: 1, explanation: "The correct translation for <b>ērudītus, -a, -um</b> is 'learned' or 'educated'. It is the perfect passive participle of <b>ērudiō</b>, meaning 'to educate, instruct'.<br>Option A, 'dug out', translates <b>ērutus, -a, -um</b> (from <b>ēruō</b>).<br>Option C, 'burst forth', translates <b>ēruptus, -a, -um</b> (from <b>ērumpō</b>).<br>Option D, 'rough', translates <b>rūdis, -e</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>fīdūcia, -ae</b> f.", options: ["end", "faith", "trust", "boundary"], i: 2, explanation: "The correct translation for <b>fīdūcia, -ae</b> f. is 'trust' or 'confidence'.<br>Option A, 'end', translates <b>fīnis, fīnis</b> m.<br>Option B, 'faith' or 'loyalty', translates <b>fīdēs, fideī</b> f. While related in meaning, <b>fīdūcia</b> emphasizes confidence, often in oneself or others, whereas <b>fīdēs</b> emphasizes loyalty, good faith, or trustworthiness.<br>Option D, 'boundary', translates <b>fīnis</b> (in the plural, <b>fīnēs</b>, it can mean territory)." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>īgnārus, -a, -um</b>", options: ["fire", "lazy", "ignorant", "unknown"], i: 2, explanation: "The correct translation for <b>īgnārus, -a, -um</b> is 'ignorant', 'unaware', or 'unacquainted with'.<br>Option A, 'fire', translates <b>īgnis, īgnis</b> m.<br>Option B, 'lazy' or 'cowardly', translates <b>īgnāvus, -a, -um</b>.<br>Option D, 'unknown', is a close synonym but 'ignorant' more directly reflects the root meaning of lacking knowledge." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>lūgubris, -e</b>", options: ["light", "shining", "mournful", "lamenting"], i: 2, explanation: "The correct translation for <b>lūgubris, -e</b> is 'mournful', 'dismal', or 'lamentable'. It is derived from the verb <b>lūgeō</b> (to mourn).<br>Option A, 'light', translates <b>lūx, lūcis</b> f.<br>Option B, 'shining', translates <b>lūcidus, -a, -um</b>.<br>Option D, 'lamenting', would be the present participle <b>lūgēns, lūgentis</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>māiōrēs, -um</b> m. pl.", options: ["greater", "majesty", "ancestors", "older people"], i: 2, explanation: "The correct translation for <b>māiōrēs, -um</b> m. pl. is 'ancestors' or 'forefathers'. It is the plural of the comparative adjective <b>māior</b> used substantively.<br>Option A, 'greater', translates the singular adjective <b>māior, māius</b>.<br>Option B, 'majesty', translates <b>māiestās, māiestātis</b> f.<br>Option D, 'older people', is a plausible meaning but 'ancestors' is the more specific and common translation in this context, especially in historical or literary texts." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>nūper</b> adv.", options: ["no one", "recently", "marriage", "never"], i: 1, explanation: "The correct translation for the adverb <b>nūper</b> is 'recently' or 'lately'.<br>Option A, 'no one', translates <b>nūllus, -a, -um</b> (as a pronoun) or <b>nēmō</b>.<br>Option C, 'marriage', translates <b>nūptiae, -ārum</b> f. pl.<br>Option D, 'never', translates <b>numquam</b>." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>obsequor, obsequī, obsecūtus sum</b>", options: ["to beg", "to obey", "to follow", "compliance"], i: 1, explanation: "The correct translation for the deponent verb <b>obsequor, obsequī, obsecūtus sum</b> is 'to obey' or 'to comply with'.<br>Option A, 'to beg', translates the verb <b>obsecrō, obsecrāre, obsecrāvī, obsecrātus</b>.<br>Option C, 'to follow', translates <b>sequor</b>, but <b>obsequor</b> implies following in a sense of obedience or deference.<br>Option D, 'compliance', translates the noun <b>obsequium, -ī</b> n., which is related but a different part of speech." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>paenitet, paenitēre, paenituit</b> (impersonal)", options: ["almost", "it repents", "punishment", "to be sorry"], i: 1, explanation: "The correct translation for the impersonal verb <b>paenitet, paenitēre, paenituit</b> is 'it repents' or 'it causes regret'. When used with an accusative of the person, it means 'one regrets' (e.g., <i>māgnī mē paenitet</i> - 'I greatly regret it').<br>Option A, 'almost', translates the adverb <b>paene</b>.<br>Option C, 'punishment', translates <b>poena, -ae</b> f.<br>Option D, 'to be sorry', captures the meaning but 'it repents' is the most direct and literal translation of the impersonal verb's sense." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>prōpinquus, -a, -um</b>", options: ["to propose", "near", "distant", "relative"], i: 1, explanation: "The correct translation for the adjective <b>prōpinquus, -a, -um</b> is 'near' or 'neighboring'. It can also be used substantively to mean 'a relative'. Since 'near' is a primary adjectival meaning, it is a strong choice. 'Relative' (Option D) is also correct when used as a noun, but 'near' is the adjectival meaning.<br>Option A, 'to propose', translates the verb <b>prōpōnō</b>.<br>Option C, 'distant', is an antonym.<br>Option D, 'relative', is a correct translation when <b>prōpinquus</b> is used as a noun, but 'near' is the primary adjectival meaning." }, { meta: "Latin to English", stem: "Choose the best English translation for the Latin word: <b>sūspīrium, -ī</b> n.", options: ["suspicion", "sigh", "breath", "hope"], i: 1, explanation: "The correct translation for <b>sūspīrium, -ī</b> n. is 'sigh'. It is derived from the verb <b>sūspīrō</b> (to sigh).<br>Option A, 'suspicion', translates <b>sūspīciō, sūspīciōnis</b> f., or the verb <b>sūspicor</b>.<br>Option C, 'breath' or 'spirit', translates <b>spīritus, -ūs</b> m.<br>Option D, 'hope', translates <b>spēs, speī</b> f." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Fear (of the unknown, dread, terror)</b>", options: ["metus, -ūs m.", "formīdō, -inis f.", "timor, -ōris m.", "pavor, -ōris m."], i: 1, explanation: "The English word 'fear' has several Latin synonyms with distinct nuances. <b><i>Formīdō</i></b> (B) specifically refers to dread, terror, or a fear of the unknown, often with a sense of awe or apprehension. <i>Metus</i> (A) is a general term for fear or apprehension. <i>Timor</i> (C) denotes fear, alarm, or anxiety. <i>Pavor</i> (D) refers to panic or sudden fright. For 'fear of the unknown or dread', <i>formīdō</i> is the most precise choice." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>To wander aimlessly, to stray (often poetic, of scattered individuals)</b>", options: ["errō, -āre, -āvī, -ātum", "vagor, -ārī, -ātus sum", "palor, -ārī, -ātus sum", "dēviō, -āre, -āvī, -ātum"], i: 2, explanation: "While all options relate to wandering, <b><i>palor</i></b> (C) specifically implies wandering in a scattered, dispersed, or aimless manner, often used in poetic contexts for individuals or groups separated and straying. <i>Errō</i> (A) is a general verb for wandering, straying, or making a mistake. <i>Vagor</i> (B) means to roam, wander, or stroll. <i>Dēviō</i> (D) means to turn aside or deviate from a path." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>A ship (especially a large vessel or warship, often used poetically for the whole ship by synecdoche)</b>", options: ["nāvis, -is f.", "carīna, -ae f.", "puppis, -is f.", "ratis, -is f."], i: 2, explanation: "<b><i>Puppis</i></b> (C), literally 'stern' or 'poop deck', is frequently used in poetry by synecdoche to refer to the entire ship, especially a large vessel or warship. <i>Nāvis</i> (A) is the general word for 'ship'. <i>Carīna</i> (B), meaning 'keel', can also be used poetically for a ship, but <i>puppis</i> is more common for the 'ship' as a whole. <i>Ratis</i> (D) refers to a raft or a small boat." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>To kill (to slaughter, to cut down, especially in battle or a violent manner)</b>", options: ["interficiō, interficere, interfēcī, interfectum", "necō, necāre, necāvī, necātum", "caedō, caedere, cecīdī, caesum", "occīdō, occīdere, occīdī, occīsum"], i: 2, explanation: "Among the verbs for 'to kill', <b><i>caedō</i></b> (C) specifically implies to cut down, to slaughter, or to fell, often in the context of battle or a violent massacre. <i>Interficiō</i> (A) is a general verb for killing or destroying. <i>Necō</i> (B) is also a general term for killing. <i>Occīdō</i> (D) means to strike down, kill, or slay, often with a sense of dispatching. <i>Caedō</i> best captures the nuance of 'slaughtering' or 'cutting down'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>The sea (the deep, the open sea, often personified in poetry)</b>", options: ["mare, maris n.", "aequor, aequoris n.", "pontus, -ī m.", "fretum, -ī n."], i: 2, explanation: "While all options relate to the sea, <b><i>pontus</i></b> (C) is a common poetic term for the open sea, the deep, or the main, often personified. <i>Mare</i> (A) is the general and most common word for 'sea'. <i>Aequor</i> (B), literally 'a level surface', is frequently used in poetry for the surface of the sea. <i>Fretum</i> (D) refers to a strait, a narrow sea, or a channel." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Journey, march, road (an irregular noun)</b>", options: ["via, -ae f.", "cursus, -ūs m.", "iter, itineris n.", "trānsitus, -ūs m."], i: 2, explanation: "The English word 'journey' or 'march' is best translated by the irregular third declension noun <b><i>iter, itineris n.</i></b> (C). <i>Via</i> (A) means 'road' or 'way'. <i>Cursus</i> (B) means 'course' or 'running'. <i>Trānsitus</i> (D) means 'passage' or 'crossing'. While related, none of these are the specific irregular noun 'iter'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Old age (as a period of life, with its characteristic infirmities)</b>", options: ["vetustās, vetustātis f.", "aetās, aetātis f.", "senectūs, senectūtis f.", "antīquitās, antīquitātis f."], i: 2, explanation: "<b><i>Senectūs, senectūtis f.</i></b> (C) specifically refers to old age as a period of life, often implying its associated weaknesses, wisdom, or infirmities. <i>Vetustās</i> (A) means 'antiquity' or 'oldness' (of things). <i>Aetās</i> (B) is a general term for 'age' or 'time of life'. <i>Antīquitās</i> (D) refers to 'ancient times' or 'antiquity'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>To know (to become acquainted with, to learn, and in the perfect, to have knowledge of)</b>", options: ["sciō, scīre, scīvī, scītum", "nōscō, nōscere, nōvī, nōtum", "cognōscō, cognōscere, cognōvī, cognitum", "intellegō, intellegere, intellēxī, intellēctum"], i: 1, explanation: "The verb <b><i>nōscō, nōscere, nōvī, nōtum</i></b> (B) means 'to get to know', 'to become acquainted with', or 'to learn'. In its perfect tense (<i>nōvī</i>), it means 'I know' (having come to know). <i>Sciō</i> (A) means 'to know' a fact or piece of information. <i>Cognōscō</i> (C) means 'to learn', 'to investigate', or 'to recognize'. <i>Intellegō</i> (D) means 'to understand' or 'to comprehend'. <i>Nōscō</i> best captures the process of acquiring knowledge and the state of knowing as a result." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>A wave (especially a large, surging wave, often used poetically)</b>", options: ["unda, -ae f.", "aestus, -ūs m.", "fluctus, -ūs m.", "gurges, gurgitis m."], i: 2, explanation: "While <i>unda</i> (A) is a general term for 'wave' or 'water', <b><i>fluctus, -ūs m.</i></b> (C) specifically denotes a large, surging wave, billow, or flood, and is very common in poetic descriptions of the sea. <i>Aestus</i> (B) refers to 'tide', 'surge', or 'heat'. <i>Gurges</i> (D) means 'whirlpool' or 'abyss'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Virtue, excellence (moral excellence, manliness, courage)</b>", options: ["bonitās, bonitātis f.", "probitās, probitātis f.", "virtūs, virtūtis f.", "integritās, integritātis f."], i: 2, explanation: "<b><i>Virtūs, virtūtis f.</i></b> (C) encompasses a broad range of meanings including moral excellence, manliness, courage, and general excellence, embodying the ideal qualities of a Roman citizen. <i>Bonitās</i> (A) means 'goodness'. <i>Probitās</i> (B) means 'honesty' or 'uprightness'. <i>Integritās</i> (D) means 'integrity' or 'wholeness'. While related, none fully capture the comprehensive classical meaning of <i>virtūs</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>To speak, to utter, to declare (especially of divine pronouncements or fate, often deponent)</b>", options: ["dīcō, dīcere, dīxī, dictum", "loquor, loquī, locūtus sum", "fātor, fārī, fātus sum", "aīō, aīere (defective)"], i: 2, explanation: "The deponent verb <b><i>fātor, fārī, fātus sum</i></b> (C) is often used for solemn pronouncements, divine utterances, or the decrees of fate, carrying a more formal or sacred connotation than other verbs of speaking. <i>Dīcō</i> (A) is the most common verb for 'to say' or 'to speak'. <i>Loquor</i> (B) means 'to speak' or 'to converse'. <i>Aīō</i> (D) is a defective verb meaning 'to say', typically used for direct speech." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Pleasure, delight (especially sensual or physical pleasure, a key concept in Epicurean philosophy)</b>", options: ["laetitia, -ae f.", "gaudium, -ī n.", "voluptās, voluptātis f.", "dēlectātiō, dēlectātiōnis f."], i: 2, explanation: "<b><i>Voluptās, voluptātis f.</i></b> (C) specifically refers to pleasure, often with a connotation of sensual or physical delight, and is a central term in philosophical discussions, particularly Epicureanism. <i>Laetitia</i> (A) means 'joy' or 'gladness'. <i>Gaudium</i> (B) means 'joy' or 'delight', often more internal. <i>Dēlectātiō</i> (D) means 'delight', 'amusement', or 'pleasure' (often intellectual or aesthetic)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>A citizen (a full member of a state, with rights and duties)</b>", options: ["homō, hominis m./f.", "vir, virī m.", "cīvis, cīvis m./f.", "incola, -ae m./f."], i: 2, explanation: "<b><i>Cīvis, cīvis m./f.</i></b> (C) is the precise term for a citizen, denoting a full member of a state or community with specific rights and duties. <i>Homō</i> (A) is a general term for 'human being' or 'person'. <i>Vir</i> (B) means 'man' (male human being). <i>Incola</i> (D) means 'inhabitant' or 'resident', but does not necessarily imply citizenship." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>To remember, to recall (to bear in mind, to be mindful of; a defective verb)</b>", options: ["recordor, recordārī, recordātus sum", "meminī, meminisse (defective)", "commemorō, commemorāre, commemorāvī, commemorātum", "reminīscor, reminīscī (deponent)"], i: 1, explanation: "The defective verb <b><i>meminī, meminisse</i></b> (B) is the most common and direct translation for 'to remember' or 'to bear in mind'. It is perfect in form but present in meaning. <i>Recordor</i> (A) means 'to recall' or 'to recollect' (often with effort). <i>Commemorō</i> (C) means 'to recount' or 'to mention'. <i>Reminīscor</i> (D) is a deponent verb meaning 'to recollect' or 'to call to mind'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>A boundary, limit (especially a sacred boundary, a landmark, or a boundary god)</b>", options: ["fīnis, fīnis m.", "līmes, līmitis m.", "terminus, -ī m.", "margō, marginis m."], i: 2, explanation: "While all options relate to boundaries, <b><i>terminus, -ī m.</i></b> (C) specifically refers to a boundary stone, a landmark, or a sacred limit, often personified as the god Terminus. <i>Fīnis</i> (A) is a general term for 'end', 'limit', or 'boundary'. <i>Līmes</i> (B) means 'path', 'track', or 'boundary line'. <i>Margō</i> (D) means 'edge', 'border', or 'margin'." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>aevum</i>?", options: ["<i>tempus</i>", "<i>spatium</i>", "<i>diēs</i>", "<i>saeculum</i>"], i: 3, explanation: "Verbum <i>aevum, -ī</i> n. significat 'aetātem, tempus, saeculum, vītam' et saepe in poēsī et philosophīā invenītur. <b><i>Saeculum, -ī</i></b> n. est synōnymum proximē, quod 'aetātem, generātiōnem, saeculum' significat, et similibus contextibus adhibētur. <i>Tempus</i> est nimis generāle, <i>spatium</i> ad intervallum vel locum refertur, et <i>diēs</i> est nimis speciāle." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>lūgubris</i>?", options: ["<i>maestus</i>", "<i>trīstis</i>", "<i>fūnebris</i>", "<i>ater</i>"], i: 2, explanation: "Adiectīvum <i>lūgubris, -e</i> significat 'lūctuōsus, trīstis, fūnebris, miserābilis'. <b><i>Fūnebris, -e</i></b> est synōnymum directum, praesertim cum ad rēs mortis vel exsequiārum spectat. <i>Maestus</i> et <i>trīstis</i> 'trīstem' significant, sed <i>lūgubris</i> saepe speciem exteriōrem vel atmosphaeram maerōris dēnotat. <i>Ater</i> 'nigrum' significat, quod lūgubrem colōrem esse potest, sed nōn est synōnymum directum." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>obsequium</i>?", options: ["<i>imperium</i>", "<i>arbitrium</i>", "<i>obtemperātiō</i>", "<i>licentia</i>"], i: 2, explanation: "Substantīvum <i>obsequium, -ī</i> n. significat 'cōnsēnsus, oboedientia, dēferentia, cōmplecentia'. <b><i>Obtemperātiō, -ōnis</i></b> f. est synōnymum proximē, quod 'oboedientiam, cōnsēnsum' significat. <i>Imperium</i> est contrārium, 'iussum' vel 'potestātem' significāns. <i>Arbitrium</i> 'iūdicium' vel 'dēcīsiōnem' significat. <i>Licentia</i> 'lībertātem' vel 'licentiam' significat, quod est contrārium obsequiō." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>pervicāx</i>?", options: ["<i>audāx</i>", "<i>fortis</i>", "<i>pertināx</i>", "<i>mollis</i>"], i: 2, explanation: "Adiectīvum <i>pervicāx, -ācis</i> significat 'contumāx, pertināx, obstinātus, caput dūrum'. Saepe nēgātīvam cōnnotātiōnem habet. <b><i>Pertināx, -ācis</i></b> est synōnymum validum, quod 'persevērāns, tenāx, obstinātus' significat, et saepe cum <i>pervicāx</i> inter sē mūtārī potest, quamquam <i>pertināx</i> potest esse et positīvum et nēgātīvum. <i>Audāx</i> 'audācem' significat, <i>fortis</i> 'fortem', et <i>mollis</i> 'mollem' vel 'imbecillem', quae omnia sunt aliārum quālitātum." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>sōlācium</i>?", options: ["<i>auxilium</i>", "<i>levāmen</i>", "<i>cōnsōlātiō</i>", "<i>remedium</i>"], i: 2, explanation: "Substantīvum <i>sōlācium, -ī</i> n. significat 'sōlāmen, cōnsōlātiōnem, levāmen'. <b><i>Cōnsōlātiō, -ōnis</i></b> f. est synōnymum directum, quod 'cōnsōlātiōnem, sōlāmen' significat. <i>Auxilium</i> 'adiūtōrium' significat, <i>levāmen</i> 'levātiōnem' vel 'alleviātiōnem' (quod est proximē, sed <i>sōlācium</i> magis ad animum refertur), et <i>remedium</i> 'medicīnam' vel 'cūram' significat, saepe ad morbos physicōs." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>aegritūdō</i>?", options: ["<i>salūs</i>", "<i>gaudium</i>", "<i>dolor</i>", "<i>morbus</i>"], i: 2, explanation: "Substantīvum <i>aegritūdō, -inis</i> f. significat 'aegrōtātiōnem, molestiam, maerōrem, animī angōrem'. Saepe ad statum mentis refertur. <b><i>Dolor, -ōris</i></b> m. est synōnymum proximē, quod 'dolōrem, maerōrem, trīstitiam' significat, et tam physicum quam mentālem labōrem complectitur. <i>Salūs</i> et <i>gaudium</i> sunt contrāria. <i>Morbus</i> 'morbum' vel 'aegrōtātiōnem physicam' significat, quod est minus latum quam <i>aegritūdō</i> quae et mentālem labōrem includit." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>dēprecārī</i>?", options: ["<i>mīnārī</i>", "<i>cohortārī</i>", "<i>ōrāre</i>", "<i>dēterrēre</i>"], i: 2, explanation: "Verbum <i>dēprecārī</i> (depōnēns) significat 'precibus āvertere, dēprecārī, implōrāre, obsecrāre'. Saepe dēprecātiōnem malī vel supplicātiōnem vehementem implicat. <b><i>Ōrāre</i></b> est synōnymum validum, quod 'rogāre, precārī, implōrāre' significat. <i>Mīnārī</i> 'minitārī' significat, <i>cohortārī</i> 'incitāre', et <i>dēterrēre</i> 'dēterrēre', quae omnia sunt actiōnēs diversae." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>oblivīscī</i>?", options: ["<i>meminisse</i>", "<i>recordārī</i>", "<i>memoriā excidere</i>", "<i>discere</i>"], i: 2, explanation: "Verbum <i>oblivīscī</i> (depōnēns) significat 'oblīvīscī, in oblīviōnem venīre'. <b><i>Memoriā excidere</i></b> est locūtiō commūnis quae 'ē memoriā ēlabī, oblīvīscī' significat, et est synōnymum proximē. <i>Meminisse</i> et <i>recordārī</i> sunt contrāria, 'memor esse' vel 'recordārī' significantia. <i>Discere</i> 'discere' significat, quod est aliud." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>dēsinere</i>?", options: ["<i>incipere</i>", "<i>pergere</i>", "<i>intermittere</i>", "<i>cōnārī</i>"], i: 2, explanation: "Verbum <i>dēsinere</i> significat 'dēsinere, cessāre, fīnem facere'. <b><i>Intermittere</i></b> est synōnymum proximē, quod 'interrumpere, cessāre, omītere' significat, implicāns intermissiōnem vel cessātiōnem. <i>Incipere</i> et <i>pergere</i> sunt contrāria, 'incipere' et 'pergere' significantia. <i>Cōnārī</i> 'cōnārī' significat, quod est aliud." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>ēgregius</i>?", options: ["<i>mediocris</i>", "<i>vulgāris</i>", "<i>praeclārus</i>", "<i>ignōbilis</i>"], i: 2, explanation: "Adiectīvum <i>ēgregius, -a, -um</i> significat 'eximius, praestāns, excellēns, rārus'. Līterāliter 'ex grege ēlectus'. <b><i>Praeclārus, -a, -um</i></b> est synōnymum directum, quod 'clārissimus, splendidus, excellēns, nōbilis' significat. <i>Mediocris</i>, <i>vulgāris</i>, et <i>ignōbilis</i> sunt contrāria, 'mediocrem', 'commūnem', et 'ignōbilem' significantia." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>īnsidiae</i>?", options: ["<i>praesidium</i>", "<i>auxilium</i>", "<i>dolus</i>", "<i>pax</i>"], i: 2, explanation: "Substantīvum <i>īnsidiae, -ārum</i> f. pl. significat 'īnsidiās, dolum, fraudem, laqueum'. <b><i>Dolus, -ī</i></b> m. est synōnymum proximē, quod 'dolum, fraudem, stratagēma' significat, et saepe in contextibus dēceptiōnis et perīculī occultī adhibētur. <i>Praesidium</i>, <i>auxilium</i>, et <i>pax</i> sunt contrāria vel ad aliās rēs pertinentia." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>mīrābilis</i>?", options: ["<i>commūnis</i>", "<i>trīviālis</i>", "<i>admirābilis</i>", "<i>sōlitārius</i>"], i: 2, explanation: "Adiectīvum <i>mīrābilis, -e</i> significat 'mīrus, mīrandus, stupēns, singulāris'. <b><i>Admirābilis, -e</i></b> est synōnymum directum, quod 'admirābilis, mīrus, stupēns' significat. <i>Commūnis</i> et <i>trīviālis</i> sunt contrāria, 'commūnem' et 'vulgārem' significantia. <i>Sōlitārius</i> 'sōlitārium' significat, quod nōn est relātum." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>oblivium</i>?", options: ["<i>memoria</i>", "<i>recordātiō</i>", "<i>lēthum</i>", "<i>scientia</i>"], i: 2, explanation: "Substantīvum <i>oblivium, -ī</i> n. significat 'oblīviōnem, immemōriam'. Saepe in poēsī invenītur. <b><i>Lēthum, -ī</i></b> n. est synōnymum proximē, quod 'mortem, interitum, oblīviōnem' significat, praesertim in contextibus poēticīs ubi mors et oblīviō saepe coniunguntur. <i>Memoria</i> et <i>recordātiō</i> sunt contrāria. <i>Scientia</i> 'scientiam' significat, quod nōn est relātum." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>pernicies</i>?", options: ["<i>salūs</i>", "<i>beneficium</i>", "<i>exitium</i>", "<i>fortūna</i>"], i: 2, explanation: "Substantīvum <i>pernicies, -ēī</i> f. significat 'perniciem, interitum, ruīnam, calamitātem'. Fortem sensum damna fātālis habet. <b><i>Exitium, -ī</i></b> n. est synōnymum directum, quod 'interitum, ruīnam, fīnem' significat. <i>Salūs</i> et <i>beneficium</i> sunt contrāria. <i>Fortūna</i> 'fortūnam' vel 'cāsum' significat, quod est nimis generāle." }, { meta: "Synonyms", stem: "Quod verbum Latīnum est <b>proximē</b> synōnymum vocābulō <i>sēgnis</i>?", options: ["<i>ācer</i>", "<i>celer</i>", "<i>iners</i>", "<i>strenuus</i>"], i: 2, explanation: "Adiectīvum <i>sēgnis, -e</i> significat 'lentus, tardus, piger, iners, dēsidiōsus'. <b><i>Iners, inertis</i></b> est synōnymum directum, quod 'iners, piger, dēsidiōsus' significat, saepe ad vīrium dēficientiam refertur. <i>Ācer</i>, <i>celer</i>, et <i>strenuus</i> sunt contrāria, 'ācrem', 'celerem', et 'strenuum' significantia." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>oblivīscor</b>?", options: ["dēserō", "meminī", "ignorō", "neglēgō"], i: 1, explanation: "Verbum <b>oblivīscor</b> significat 'oblīvīscī' vel 'memoriam āmittere'. Eius contrārium est <b>meminī</b>, quod significat 'memoriam tenēre' vel 'recordārī'.<br>A) <b>dēserō</b> significat 'dēserere' vel 'relinquere'.<br>C) <b>ignorō</b> significat 'nescīre' vel 'ignōrāre'.<br>D) <b>neglēgō</b> significat 'neglēgere' vel 'nōn cūrāre'. Haec verba sunt sēmanticē affīnia, sed nōn sunt contrāria directē ad 'oblīvīscī'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>aequus</b>?", options: ["prāvus", "asper", "inīquus", "turbidus"], i: 2, explanation: "Adiectīvum <b>aequus</b> significat 'plānus', 'iūstus', vel 'aequālis'. Eius contrārium est <b>inīquus</b>, quod significat 'nōn plānus', 'nōn iūstus', vel 'ināequālis'.<br>A) <b>prāvus</b> significat 'tortuōsus' vel 'dēpravātus'.<br>B) <b>asper</b> significat 'rūgōsus' vel 'dūrus'.<br>D) <b>turbidus</b> significat 'turbulentus' vel 'cōnfūsus'. Haec verba nōn sunt contrāria directē ad 'aequus'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>profānus</b>?", options: ["vulgāris", "impius", "sacer", "pūrus"], i: 2, explanation: "Adiectīvum <b>profānus</b> significat 'nōn sacrātus', 'commūnis', vel 'impius'. Eius contrārium est <b>sacer</b>, quod significat 'sacrātus', 'dīvīnus', vel 'sānctus'.<br>A) <b>vulgāris</b> significat 'commūnis' vel 'plebēius', quod est sēmanticē affīne sed nōn contrārium. <br>B) <b>impius</b> est propemodum synonymum 'profānī' in aliquibus contextibus, nōn contrārium.<br>D) <b>pūrus</b> significat 'mundus' vel 'sincērus', quod est affīne sed nōn contrārium." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>cōnfiteor</b>?", options: ["dissimulō", "tacēō", "negō", "recūsō"], i: 2, explanation: "Verbum <b>cōnfiteor</b> significat 'fāterī' vel 'agnōscere'. Eius contrārium est <b>negō</b>, quod significat 'nōn fāterī' vel 'recūsāre vērī'.<br>A) <b>dissimulō</b> significat 'cēlāre' vel 'simulāre', quod est affīne sed nōn directum contrārium.<br>B) <b>tacēō</b> significat 'silēre', quod est actiō nōn dīcendī, sed nōn directē negātiō.<br>D) <b>recūsō</b> significat 'nōlō' vel 'abnuō', quod est affīne sed nōn directē contrārium 'cōnfiterī'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>pauper</b>?", options: ["opulentus", "dīves", "locuplēs", "potēns"], i: 1, explanation: "Adiectīvum <b>pauper</b> significat 'nōn dīves' vel 'egēns'. Eius contrārium directissimum est <b>dīves</b>, quod significat 'multās opēs habēns'.<br>A) <b>opulentus</b> et C) <b>locuplēs</b> sunt propemodum synonyma 'dīvitis', sed <b>dīves</b> est contrārium vulgārissimum et directissimum 'pauperī'.<br>D) <b>potēns</b> significat 'validus' vel 'potestātem habēns', quod nōn est contrārium 'pauperī'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>arduus</b>?", options: ["lēnis", "mollis", "facilis", "expeditus"], i: 2, explanation: "Adiectīvum <b>arduus</b> significat 'difficilis', 'altus', vel 'praeceps'. Eius contrārium, praesertim in sēnsū 'difficilis', est <b>facilis</b>, quod significat 'nōn difficilis' vel 'lēvis'.<br>A) <b>lēnis</b> significat 'mītis' vel 'placidus'.<br>B) <b>mollis</b> significat 'tener' vel 'flexibilis'.<br>D) <b>expeditus</b> significat 'expedītus' vel 'parātus'. Haec nōn sunt contrāria directē ad 'arduus'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>obscūrus</b>?", options: ["lūcidus", "apertus", "clārus", "manifestus"], i: 2, explanation: "Adiectīvum <b>obscūrus</b> significat 'tenebrōsus', 'nōn clārus', vel 'ignōtus'. Eius contrārium est <b>clārus</b>, quod significat 'lūcidus', 'perspicuus', vel 'nōtus'.<br>A) <b>lūcidus</b> est synonymum 'clārī' in sēnsū lūcis.<br>B) <b>apertus</b> significat 'patefactus' vel 'sincērus', quod est affīne sed nōn directē contrārium.<br>D) <b>manifestus</b> significat 'patefactus' vel 'evidēns', quod est affīne sed nōn directē contrārium." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>fīdūcia</b>?", options: ["timor", "suspiciō", "diffīdentia", "dubium"], i: 2, explanation: "Nōmen <b>fīdūcia</b> significat 'fidem' vel 'spem'. Eius contrārium est <b>diffīdentia</b>, quod significat 'fideī dēfectum' vel 'spem nūllam'.<br>A) <b>timor</b> significat 'metum'.<br>B) <b>suspiciō</b> significat 'suspīciōnem' vel 'aestimātiōnem malam'.<br>D) <b>dubium</b> significat 'incertitūdinem'. Haec sunt affīnia, sed <b>diffīdentia</b> est directissimum contrārium." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>celer</b>?", options: ["tardus", "lentus", "segnis", "iners"], i: 1, explanation: "Adiectīvum <b>celer</b> significat 'vēlōx' vel 'properāns'. Eius contrārium est <b>lentus</b>, quod significat 'tardus' vel 'mōrāns'. Quamquam <b>tardus</b> (A) est quoque contrārium, <b>lentus</b> saepius in poēsī et prōlātiōne subtīliōre adhibētur ut contrārium directum 'celerī'.<br>C) <b>segnis</b> significat 'piger' vel 'iners'.<br>D) <b>iners</b> significat 'sine vī' vel 'ōtiōsus'. Haec verba sunt affīnia, sed <b>lentus</b> est contrārium directissimum ad 'celer'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>sōbrius</b>?", options: ["luxuriōsus", "ebrius", "dissolūtus", "effrēnātus"], i: 1, explanation: "Adiectīvum <b>sōbrius</b> significat 'nōn ēbrius' vel 'moderātus'. Eius contrārium directissimum est <b>ebrius</b>, quod significat 'vīnō plēnus' vel 'temulentus'.<br>A) <b>luxuriōsus</b> significat 'nimius' vel 'profūsus'.<br>C) <b>dissolūtus</b> significat 'laxus' vel 'licentiōsus'.<br>D) <b>effrēnātus</b> significat 'sine frēnō' vel 'licentiōsus'. Haec verba sunt affīnia in sēnsū immoderātiōnis, sed <b>ebrius</b> est contrārium directum 'sōbriō'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>probus</b>?", options: ["malus", "scelestus", "improbus", "nefārius"], i: 2, explanation: "Adiectīvum <b>probus</b> significat 'honēstus', 'bonus', vel 'integer'. Eius contrārium est <b>improbus</b>, quod significat 'inēgregius', 'malus', vel 'dēpravātus'.<br>A) <b>malus</b> est contrārium generāle 'bonō', sed <b>improbus</b> est contrārium specificum 'probō'.<br>B) <b>scelestus</b> significat 'crīminōsus' vel 'impius'.<br>D) <b>nefārius</b> significat 'impius' vel 'scelestus'. Haec sunt affīnia, sed <b>improbus</b> est contrārium directissimum 'probō'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>vetus</b>?", options: ["recēns", "iuvenis", "novus", "prīmus"], i: 2, explanation: "Adiectīvum <b>vetus</b> significat 'antīquus' vel 'longae aetātis'. Eius contrārium est <b>novus</b>, quod significat 'recēns' vel 'nōn antīquus'.<br>A) <b>recēns</b> est propemodum synonymum 'novī', sed <b>novus</b> est contrārium vulgārissimum et directissimum 'veterī'.<br>B) <b>iuvenis</b> significat 'iūvenis' vel 'aetāte parvus', quod ad hominēs refertur, nōn ad rēs generātim.<br>D) <b>prīmus</b> significat 'prīnceps' vel 'initiālis', quod nōn est contrārium 'veterī'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>sānus</b>?", options: ["aeger", "dēmēns", "īnsānus", "morbidus"], i: 2, explanation: "Adiectīvum <b>sānus</b> significat 'integer', 'validus', vel 'mentis compōs'. Eius contrārium est <b>īnsānus</b>, quod significat 'nōn sānus' vel 'mentis nōn compōs'.<br>A) <b>aeger</b> significat 'morbidus' vel 'dolēns'.<br>B) <b>dēmēns</b> significat 'ā mente dēiectus' vel 'furiōsus'.<br>D) <b>morbidus</b> significat 'aeger' vel 'morbum habēns'. Quamquam haec verba sunt affīnia, <b>īnsānus</b> est contrārium directissimum 'sānō', praesertim in sēnsū mentis." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>plēnus</b>?", options: ["inānis", "dēficiēns", "vacuus", "exhilarātus"], i: 2, explanation: "Adiectīvum <b>plēnus</b> significat 'repletus' vel 'nōn vacuus'. Eius contrārium est <b>vacuus</b>, quod significat 'inānis' vel 'nōn plēnus'.<br>A) <b>inānis</b> est propemodum synonymum 'vacuī', sed <b>vacuus</b> est contrārium vulgārissimum et directissimum 'plēnō'.<br>B) <b>dēficiēns</b> significat 'dēficiēns' vel 'carentem'.<br>D) <b>exhilarātus</b> significat 'exinanītus' vel 'exhilarātus', quod nōn est directē contrārium 'plēnō'." }, { meta: "Antonyms", stem: "Quod verbum Latīnum est contrārium <b>incipiō</b>?", options: ["fīniō", "terminō", "dēsinō", "intermittō"], i: 2, explanation: "Verbum <b>incipiō</b> significat 'initiāre' vel 'prīmum facere'. Eius contrārium est <b>dēsinō</b>, quod significat 'fīnem facere' vel 'intermittere'.<br>A) <b>fīniō</b> significat 'fīnem pōnere' vel 'perfīcere'.<br>B) <b>terminō</b> significat 'fīnem pōnere' vel 'claudere'.<br>D) <b>intermittō</b> significat 'pausam facere' vel 'interrumpere'. Quamquam 'fīniō' et 'terminō' sunt affīnia, <b>dēsinō</b> est contrārium directissimum 'incipiō' in sēnsū 'nōn iam facere' vel 'cessāre'." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["ēlūcūbrō", "ēdō", "prōmulgō", "ēvānēscō"], i: 3, explanation: "Options A (ēlūcūbrō, 'to work by lamplight, compose laboriously'), B (ēdō, 'to put forth, utter, publish'), and C (prōmulgō, 'to make publicly known, publish') are all verbs related to the act of uttering, publishing, or creating and making public. Option D (ēvānēscō) means 'to vanish' or 'to disappear', and is semantically distinct, despite the similar 'ē-' prefix." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["nāvis longa", "linter", "cymbula", "rāmus"], i: 3, explanation: "Options A (nāvis longa, 'warship'), B (linter, 'skiff, dugout canoe'), and C (cymbula, 'small boat, skiff') are all terms for types of boats or vessels. Option D (rāmus) means 'branch' or 'bough', and is a morphological distractor due to its similar appearance to words for small boats." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["prīscus", "vetustus", "antīquus", "vēlōx"], i: 3, explanation: "Options A (prīscus, 'ancient, old-fashioned, venerable'), B (vetustus, 'ancient, old, of long standing'), and C (antīquus, 'ancient, old, former') are all adjectives meaning 'old' or 'ancient', often with connotations of respect or tradition. Option D (vēlōx) means 'swift' or 'quick', and serves as a morphological distractor due to its similarity to 'vetustus'." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["fulgor", "candor", "lūmen", "flūmen"], i: 3, explanation: "Options A (fulgor, 'brightness, gleam, splendor'), B (candor, 'whiteness, radiance, purity'), and C (lūmen, 'light, lamp, eye') are all nouns related to light, brightness, or shining. Option D (flūmen) means 'river' or 'stream', and is a common morphological trap for 'lūmen'." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["pontus", "aequor", "fretum", "fōns"], i: 3, explanation: "Options A (pontus, 'the sea, the deep', often poetic), B (aequor, 'level surface, the sea', common in poetry), and C (fretum, 'strait, sound, sea') are all terms for the sea or a body of water. Option D (fōns) means 'spring' or 'fountain', and is a morphological distractor." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["nectō", "ligō", "vinciō", "vincō"], i: 3, explanation: "Options A (nectō, 'to bind, tie, fasten'), B (ligō, 'to bind, tie, fasten'), and C (vinciō, 'to bind, tie, fetter') are all verbs meaning 'to bind' or 'to tie'. Option D (vincō) means 'to conquer, overcome, defeat', and is a classic morphological trap due to its similarity in form to 'vinciō'." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["nūbēs", "nimbus", "nebula", "nūmen"], i: 3, explanation: "Options A (nūbēs, 'cloud'), B (nimbus, 'rain-cloud, storm-cloud, halo'), and C (nebula, 'mist, fog, cloud') are all nouns related to atmospheric phenomena, specifically clouds or mist. Option D (nūmen) means 'divine will, divine power, divinity', and is a morphological distractor." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["hasta", "tēlum", "cuspis", "scūtum"], i: 3, explanation: "Options A (hasta, 'spear'), B (tēlum, 'missile, weapon, dart'), and C (cuspis, 'point, spear, javelin', often poetic) are all terms for offensive weapons, particularly spears or missiles. Option D (scūtum) means 'shield', which is a piece of defensive armor, not an offensive weapon." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["mūnus", "dōnum", "praemium", "mūrus"], i: 3, explanation: "Options A (mūnus, 'gift, present, service, duty'), B (dōnum, 'gift, present'), and C (praemium, 'reward, prize, bounty') are all nouns related to gifts, rewards, or offerings. Option D (mūrus) means 'wall', and is a morphological distractor for 'mūnus'." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["fātum", "fors", "Parcae", "fāma"], i: 3, explanation: "Options A (fātum, 'fate, destiny, doom'), B (fors, 'chance, luck, fortune'), and C (Parcae, 'the Fates') are all terms directly related to fate, destiny, or chance. Option D (fāma) means 'rumor, report, reputation, fame', and is a morphological distractor that sounds similar to 'fātum'." }, { meta: "Analogies", stem: "<b>aevum</b> : <b>saeculum</b> :: <b>opācus</b> : X", options: ["<b>umbrōsus</b>", "<b>caecus</b>", "<b>lūgubris</b>", "<b>tenebrōsus</b>"], i: 0, explanation: "The relationship is one of close synonymy, particularly in poetic or elevated contexts. <i>Aevum</i> and <i>saeculum</i> both refer to an 'age' or 'time period.' Similarly, <i>opācus</i> (shady, dark, obscure) finds its closest synonym in <i>umbrōsus</i> (shady, full of shade), both often used to describe places or conditions of deep shade.<br><br>Distractors:<br>B) <i>Caecus</i> means 'blind' or 'dark' but doesn't specifically imply 'shady' or 'shadowy.'<br>C) <i>Lūgubris</i> means 'mournful' or 'dismal,' referring to mood or atmosphere rather than physical shade.<br>D) <i>Tenebrōsus</i> means 'dark' or 'gloomy,' which is close, but <i>opācus</i> and <i>umbrōsus</i> specifically denote the quality of being 'shady' or 'shadowy,' a more precise match for the nuance." }, { meta: "Analogies", stem: "<b>vātēs</b> : <b>lyra</b> :: <b>fūnis</b> : X", options: ["<b>nauta</b>", "<b>piscātor</b>", "<b>agricola</b>", "<b>faber</b>"], i: 0, explanation: "The relationship is Agent : Instrument. A <i>vātēs</i> (prophet, poet) is associated with the <i>lyra</i> (lyre) as an instrument of song and prophecy. Similarly, a <i>nauta</i> (sailor) is primarily associated with <i>fūnis</i> (rope, cable) for rigging and managing a ship.<br><br>Distractors:<br>B) A <i>piscātor</i> (fisherman) uses nets, not typically ropes in the same primary sense as a sailor.<br>C) An <i>agricola</i> (farmer) uses tools like plows and hoes.<br>D) A <i>faber</i> (craftsman) is too general; while they might use ropes, it's not their defining instrument." }, { meta: "Analogies", stem: "<b>sōpiō</b> : <b>somnus</b> :: <b>ērudīō</b> : X", options: ["<b>doctrīna</b>", "<b>disciplīna</b>", "<b>sapientia</b>", "<b>ingenium</b>"], i: 0, explanation: "The relationship is Verb : Resulting Noun. <i>Sōpiō</i> (to lull to sleep) results in <i>somnus</i> (sleep). Likewise, <i>ērudīō</i> (to educate, instruct) directly leads to <i>doctrīna</i> (instruction, learning, knowledge).<br><br>Distractors:<br>B) <i>Disciplīna</i> (training, discipline) is the process or system of instruction, rather than the acquired knowledge itself.<br>C) <i>Sapientia</i> (wisdom) is a higher, more profound outcome than the direct knowledge imparted by <i>ērudīō</i>.<br>D) <i>Ingenium</i> (innate talent, genius) is a prerequisite or natural capacity, not the result of education." }, { meta: "Analogies", stem: "<b>digitī</b> : <b>manus</b> :: <b>artūs</b> : X", options: ["<b>corpus</b>", "<b>membra</b>", "<b>caput</b>", "<b>ossa</b>"], i: 0, explanation: "The relationship is Part : Whole. <i>Digitī</i> (fingers/toes) are parts of the <i>manus</i> (hand). Similarly, <i>artūs</i> (limbs, joints, often referring to the major parts or framework of the body) are parts of the entire <i>corpus</i> (body).<br><br>Distractors:<br>B) <i>Membra</i> (limbs, members) can be a synonym for <i>artūs</i> in some contexts, making it a part rather than the whole in this specific analogy.<br>C) <i>Caput</i> (head) is a part of the body, not the whole.<br>D) <i>Ossa</i> (bones) are components of the body, but not the whole body itself." }, { meta: "Analogies", stem: "<b>fēlīcitās</b> : <b>calamitās</b> :: <b>ōtium</b> : X", options: ["<b>labōr</b>", "<b>negotium</b>", "<b>bellum</b>", "<b>sollicitūdō</b>"], i: 0, explanation: "The relationship is Antonymy. <i>Fēlīcitās</i> (happiness, good fortune) is the opposite of <i>calamitās</i> (disaster, misfortune). In a similar vein, <i>ōtium</i> (leisure, peace, quiet, ease) is often contrasted with <i>labōr</i> (toil, effort, hardship). While <i>ōtium</i> is often defined as the absence of <i>negotium</i>, <i>labōr</i> captures the sense of strenuous effort and hardship, which is a stronger antonym to the 'ease' and 'peace' implied by <i>ōtium</i> in philosophical contexts.<br><br>Distractors:<br>B) <i>Negotium</i> (business, occupation) is the absence of <i>ōtium</i>, but <i>labōr</i> emphasizes the toil and hardship, which is a more direct opposite to the 'ease' aspect of <i>ōtium</i>.<br>C) <i>Bellum</i> (war) is an antonym to 'peace,' which is an aspect of <i>ōtium</i>, but not the primary antonym for the broader concept of 'leisure' or 'ease.'<br>D) <i>Sollicitūdō</i> (anxiety, worry) is a potential consequence of a lack of <i>ōtium</i>, but not its direct antonym." }, { meta: "Analogies", stem: "<b>flūmen</b> : <b>liquidus</b> :: <b>caelum</b> : X", options: ["<b>aether</b>", "<b>nūbēs</b>", "<b>sīdus</b>", "<b>serēnus</b>"], i: 0, explanation: "The relationship is Thing : Defining Characteristic/Essence (often poetic). A <i>flūmen</i> (river) is inherently <i>liquidus</i> (flowing, clear, liquid). Similarly, the <i>caelum</i> (sky, heaven), especially its upper, pure regions, is characterized by <i>aether</i> (the pure, bright upper air or 'ether'), which represents its essential quality in poetic and philosophical contexts.<br><br>Distractors:<br>B) <i>Nūbēs</i> (cloud) is a feature of the sky, but not its inherent essence.<br>C) <i>Sīdus</i> (star, constellation) is a celestial body found in the sky, not the sky itself or its defining characteristic.<br>D) <i>Serēnus</i> (clear, calm) is an adjective describing the sky's condition, not a noun representing its essential substance or a specific part like <i>aether</i>." }, { meta: "Analogies", stem: "<b>fremō</b> : <b>leō</b> :: <b>ululō</b> : X", options: ["<b>lupus</b>", "<b>ursa</b>", "<b>cornīx</b>", "<b>serpēns</b>"], i: 0, explanation: "The relationship is Sound : Agent (animal). <i>Fremō</i> (to roar, growl) is the characteristic sound made by a <i>leō</i> (lion). Likewise, <i>ululō</i> (to howl, shriek, wail) is the characteristic sound of a <i>lupus</i> (wolf).<br><br>Distractors:<br>B) An <i>ursa</i> (bear) growls, but does not typically 'howl' in the same manner as a wolf.<br>C) A <i>cornīx</i> (crow) caws or croaks.<br>D) A <i>serpēns</i> (snake) hisses (<i>sībilō</i>)." }, { meta: "Analogies", stem: "<b>cōnfundō</b> : <b>cōnfūsiō</b> :: <b>ēvānēscō</b> : X", options: ["<b>ēvānēscentia</b>", "<b>exitus</b>", "<b>dēfectiō</b>", "<b>interitus</b>"], i: 0, explanation: "The relationship is Verb : Noun of Action/Result. <i>Cōnfundō</i> (to confuse, disturb) yields <i>cōnfūsiō</i> (confusion, disorder). Similarly, <i>ēvānēscō</i> (to vanish, fade away) forms the noun <i>ēvānēscentia</i> (a vanishing, disappearance). This tests knowledge of less common Latin abstract nouns.<br><br>Distractors:<br>B) <i>Exitus</i> (departure, outcome, death) is related to going away, but not the specific act of vanishing or fading.<br>C) <i>Dēfectiō</i> (failing, revolt, desertion) implies a failure or abandonment, not necessarily a vanishing.<br>D) <i>Interitus</i> (ruin, destruction, death) refers to perishing, which is a more definitive end than merely vanishing." }, { meta: "Analogies", stem: "<b>unda</b> : <b>aequor</b> :: <b>cōnfīnis</b> : X", options: ["<b>conterminus</b>", "<b>vīcīnus</b>", "<b>propinquus</b>", "<b>adiacēns</b>"], i: 0, explanation: "The relationship is one of close synonymy, often with poetic or specific usage. <i>Unda</i> (wave, water) and <i>aequor</i> (level surface, sea, plain) are often used poetically as synonyms for 'sea' or 'water.' Likewise, <i>cōnfīnis</i> (bordering, having a common boundary) finds its most precise synonym in <i>conterminus</i> (bordering, contiguous, having a common boundary). Both terms emphasize the sharing of a physical border.<br><br>Distractors:<br>B) <i>Vīcīnus</i> (neighboring, near) implies proximity but not necessarily a shared boundary.<br>C) <i>Propinquus</i> (near, close, related) is a more general term for proximity and can also refer to kinship.<br>D) <i>Adiacēns</i> (lying near, adjacent) is close, but <i>conterminus</i> and <i>cōnfīnis</i> more strongly convey the idea of 'sharing a border' rather than just 'lying next to.'" }, { meta: "Analogies", stem: "<b>sībilō</b> : <b>serpēns</b> :: <b>mugīō</b> : X", options: ["<b>taurus</b>", "<b>bōs</b>", "<b>equus</b>", "<b>aper</b>"], i: 0, explanation: "The relationship is Sound : Agent (animal). <i>Sībilō</i> (to hiss) is the characteristic sound of a <i>serpēns</i> (snake). Similarly, <i>mugīō</i> (to bellow, low) is the characteristic sound of a <i>taurus</i> (bull). While <i>bōs</i> (ox, cow) also lows, <i>taurus</i> is often specifically associated with the powerful 'bellowing' sound, especially in poetic contexts.<br><br>Distractors:<br>B) <i>Bōs</i> (ox, cow) is a general term for bovine animals, but <i>taurus</i> is more specific and often implies the stronger bellowing sound.<br>C) An <i>equus</i> (horse) neighs (<i>hinnīō</i>).<br>D) An <i>aper</i> (wild boar) grunts (<i>grunniō</i>)." }, { meta: "Fill-in-the-Blank", stem: "Cicerō, nōn <u>         </u> adulātorum, sed iūstitiam semper sequēbātur.", options: ["<i>obsequium</i>", "<i>imperium</i>", "<i>odium</i>", "<i>studium</i>"], i: 0, explanation: "The correct answer is <b>A. <i>obsequium</i></b>, meaning 'compliance, deference, servility'. Cicero would not follow the servility of flatterers, but rather justice. Option B, <i>imperium</i> (command, rule), is antithetical to the idea of following flatterers. Option C, <i>odium</i> (hatred), and Option D, <i>studium</i> (eagerness, zeal), do not fit the context of 'adulātorum' (flatterers) as well as <i>obsequium</i>." }, { meta: "Fill-in-the-Blank", stem: "Post clādem ingentem, nūllum <u>         </u> afflictīs animīs reperīrī poterat.", options: ["<i>sōlācium</i>", "<i>perīculum</i>", "<i>flagitium</i>", "<i>praemium</i>"], i: 0, explanation: "The correct answer is <b>A. <i>sōlācium</i></b>, meaning 'comfort, solace, relief'. After a great disaster, no comfort could be found for afflicted souls. Option B, <i>perīculum</i> (danger), is an antonym. Option C, <i>flagitium</i> (disgrace, crime), and Option D, <i>praemium</i> (reward), are semantically irrelevant to the context of 'clādem ingentem' (great disaster) and 'afflictīs animīs' (afflicted souls)." }, { meta: "Fill-in-the-Blank", stem: "Catilīna, plēnē <u>         </u> et sceleris, cōnsulī Rōmānō mortem parābat.", options: ["<i>īnsidiārum</i>", "<i>virtūtum</i>", "<i>beneficiōrum</i>", "<i>cōnsiliōrum</i>"], i: 0, explanation: "The correct answer is <b>A. <i>īnsidiārum</i></b>, the genitive plural of <i>īnsidiae, -ārum</i> f., meaning 'ambush, trap, treachery'. The phrase 'plēnē... et sceleris' (full of... and crime) strongly indicates treachery. Option B, <i>virtūtum</i> (virtues), and Option C, <i>beneficiōrum</i> (favors, benefits), are antonyms. Option D, <i>cōnsiliōrum</i> (plans), is too general and lacks the specific negative connotation of plotting harm." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs, post longum iter et acerrimum proelium, omnīnō <u>         </u> erant.", options: ["<i>dēfessī</i>", "<i>integrī</i>", "<i>alacrēs</i>", "<i>potentēs</i>"], i: 0, explanation: "The correct answer is <b>A. <i>dēfessī</i></b>, meaning 'exhausted, weary'. Soldiers would naturally be exhausted after a long march ('longum iter') and a very fierce battle ('acerrimum proelium'). Option B, <i>integrī</i> (fresh, untouched), Option C, <i>alacrēs</i> (eager, brisk), and Option D, <i>potentēs</i> (powerful), are either antonyms or do not fit the context of extreme exertion." }, { meta: "Fill-in-the-Blank", stem: "Tanta nivis vīs montēs altōs paene <u>         </u> .", options: ["<i>obruit</i>", "<i>aperuit</i>", "<i>sustinuit</i>", "<i>ēvāsit</i>"], i: 0, explanation: "The correct answer is <b>A. <i>obruit</i></b>, the perfect tense of <i>obruō, obruere</i>, meaning 'to overwhelm, bury, cover'. A great force of snow ('tanta nivis vīs') would almost bury high mountains. Option B, <i>aperuit</i> (opened), and Option C, <i>sustinuit</i> (held up, sustained), are antonyms in this context. Option D, <i>ēvāsit</i> (escaped), is semantically illogical for snow acting upon mountains." }, { meta: "Fill-in-the-Blank", stem: "Philosophus docēbat mortem nōn esse malum, sed finem omnium <u>         </u> .", options: ["<i>aegritūdinum</i>", "<i>voluptātum</i>", "<i>glōriārum</i>", "<i>dīvitiārum</i>"], i: 0, explanation: "The correct answer is <b>A. <i>aegritūdinum</i></b>, the genitive plural of <i>aegritūdō, aegritūdinis</i> f., meaning 'sickness, distress, grief, mental anguish'. This fits the philosophical context that death brings an end to suffering. Option B, <i>voluptātum</i> (pleasures), is an antonym. Option C, <i>glōriārum</i> (glories), and Option D, <i>dīvitiārum</i> (riches), are irrelevant to the concept of death as an end to a state of being." }, { meta: "Fill-in-the-Blank", stem: "Vergilius Aenēam dīcit Rōmānae gentis <u>         </u> sequī.", options: ["<i>fātum</i>", "<i>arbitrium</i>", "<i>cōnsilium</i>", "<i>lūdum</i>"], i: 0, explanation: "The correct answer is <b>A. <i>fātum</i></b>, meaning 'fate, destiny'. This is a central theme in Vergil's <i>Aeneid</i>, where Aeneas is constantly guided by destiny to found the Roman race. Option B, <i>arbitrium</i> (judgment, will), and Option C, <i>cōnsilium</i> (plan), imply human agency rather than the divine, predetermined course of events. Option D, <i>lūdum</i> (game, sport), is entirely inappropriate." }, { meta: "Fill-in-the-Blank", stem: "Quamquam multīs monita erat, puella <u>         </u> in sententiā suā manēbat.", options: ["<i>pervicāx</i>", "<i>flexibilis</i>", "<i>modesta</i>", "<i>obsequēns</i>"], i: 0, explanation: "The correct answer is <b>A. <i>pervicāx</i></b>, meaning 'stubborn, obstinate, persistent'. The phrase 'in sententiā suā manēbat' (she remained in her opinion) despite being 'multīs monita' (warned by many) strongly indicates stubbornness. Option B, <i>flexibilis</i> (flexible), and Option D, <i>obsequēns</i> (compliant, obedient), are antonyms. Option C, <i>modesta</i> (modest, moderate), does not fit the context of refusing to change one's mind." }, { meta: "Fill-in-the-Blank", stem: "Agricolae, terrā <u>         </u> frūgēs maximās collēgērunt.", options: ["<i>opīmā</i>", "<i>sterilī</i>", "<i>asperā</i>", "<i>exiguā</i>"], i: 0, explanation: "The correct answer is <b>A. <i>opīmā</i></b>, the ablative feminine singular of <i>opīmus, -a, -um</i>, meaning 'rich, fertile, abundant'. Farmers would collect great harvests ('frūgēs maximās') from fertile land. Option B, <i>sterilī</i> (sterile, barren), Option C, <i>asperā</i> (rough, harsh), and Option D, <i>exiguā</i> (small, scanty), are all antonyms or inappropriate for producing abundant crops." }, { meta: "Fill-in-the-Blank", stem: "Sōl iam in occāsum <u>         </u> , noctem adferēns.", options: ["<i>praecipitābat</i>", "<i>retinēbat</i>", "<i>ascendēbat</i>", "<i>morābātur</i>"], i: 0, explanation: "The correct answer is <b>A. <i>praecipitābat</i></b>, the imperfect active of <i>praecipitō, praecipitāre</i>, meaning 'to throw headlong, rush down, hasten'. This verb is often used poetically to describe the sun 'rushing' towards its setting. Options B, <i>retinēbat</i> (was holding back), Option C, <i>ascendēbat</i> (was ascending), and Option D, <i>morābātur</i> (was delaying), are all antonyms to the idea of the sun setting and bringing night." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Mōrēs servī quī dominō suō semper pāret et eius voluntātī cēdit, aut dēferentia ad superiōrem?</b>", options: ["indulgentia", "obsequium", "contumēlia", "superbia"], i: 1, explanation: "The Latin description, \"Mōrēs servī quī dominō suō semper pāret et eius voluntātī cēdit, aut dēferentia ad superiōrem,\" accurately defines <b>obsequium</b>, which means 'compliance, deference, or obedience,' often with a connotation of servility. Option A, <i>indulgentia</i>, means 'indulgence' or 'kindness.' Option C, <i>contumēlia</i>, means 'insult' or 'affront.' Option D, <i>superbia</i>, means 'pride' or 'arrogance.' None of these alternatives fit the description of yielding to a superior's will as precisely as <b>obsequium</b>." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Spatium temporis quō nihil initium aut fīnem habet, sed semper manet et nūllō modō mūtātur?</b>", options: ["saeculum", "momentum", "aeternum", "intervallum"], i: 2, explanation: "The description, \"Spatium temporis quō nihil initium aut fīnem habet, sed semper manet et nūllō modō mūtātur,\" perfectly defines <b>aeternum</b>, meaning 'eternity' or 'forever,' a state without beginning or end and unchanging. Option A, <i>saeculum</i>, refers to a 'specific age' or 'generation.' Option B, <i>momentum</i>, means a 'moment' or 'instant.' Option D, <i>intervallum</i>, means an 'interval' or 'gap.' All these options imply finite duration, unlike <b>aeternum</b>." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Coetus virōrum quī propter amīcitiam aut rēs commūnēs coniunguntur, saepe ad fīnēs politicōs aut religiōsōs?</b>", options: ["factiō", "sodālitās", "turba", "coniūrātiō"], i: 1, explanation: "The description, \"Coetus virōrum quī propter amīcitiam aut rēs commūnēs coniunguntur, saepe ad fīnēs politicōs aut religiōsōs,\" accurately defines <b>sodālitās</b>, which means 'fellowship, club, or association,' particularly one formed for shared interests, often political or religious. Option A, <i>factiō</i>, implies a 'faction' or 'party,' often with a negative connotation of division. Option C, <i>turba</i>, is a general 'crowd' or 'mob.' Option D, <i>coniūrātiō</i>, signifies a 'conspiracy' or 'secret plot.' <b>Sodālitās</b> best captures the sense of an organized group united by common purpose." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Quod dē corpore animālis dētrahitur, ut pellis serpentis, aut arma hostis occīsī, vel vestēs dēpositae?</b>", options: ["spolia", "exuviae", "praeda", "manubiae"], i: 1, explanation: "The description, \"Quod dē corpore animālis dētrahitur, ut pellis serpentis, aut arma hostis occīsī, vel vestēs dēpositae,\" refers to <b>exuviae</b>, which means 'things stripped off,' such as an animal's sloughed skin, the armor of a fallen enemy, or discarded clothing. This term is often used poetically. Option A, <i>spolia</i>, specifically refers to 'spoils of war' taken from an enemy. Option C, <i>praeda</i>, is general 'booty' or 'plunder.' Option D, <i>manubiae</i>, refers to 'money obtained from spoils.' <b>Exuviae</b> has a broader and more evocative meaning, encompassing both natural and martial 'strippings.'" }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Pars aedificiī quae ad summum cacūmen ēvehitur, vel culmen montis, vel summa dignitās et glōria?</b>", options: ["fundāmentum", "fastīgium", "līmen", "porticus"], i: 1, explanation: "The description, \"Pars aedificiī quae ad summum cacūmen ēvehitur, vel culmen montis, vel summa dignitās et glōria,\" defines <b>fastīgium</b>, meaning 'summit, peak, highest point,' whether literal (of a building or mountain) or metaphorical (of dignity or glory). Option A, <i>fundāmentum</i>, means 'foundation,' which is the opposite. Option C, <i>līmen</i>, means 'threshold' or 'entrance.' Option D, <i>porticus</i>, means 'portico' or 'colonnade.' Only <b>fastīgium</b> captures the essence of the highest point or culmination." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Angusta via per silvās aut agrōs, nōn lāta et pūblica, sed trāmes occultus et minus frequentātus?</b>", options: ["iter", "sēmita", "callis", "strāta"], i: 1, explanation: "The description, \"Angusta via per silvās aut agrōs, nōn lāta et pūblica, sed trāmes occultus et minus frequentātus,\" refers to <b>sēmita</b>, which means 'a narrow path, by-way, or secluded track.' Option A, <i>iter</i>, is a general term for a 'journey' or 'road,' which can be wide. Option C, <i>callis</i>, also means 'path' or 'track,' but often implies a rougher, less defined path, possibly for animals. Option D, <i>strāta</i>, means a 'paved road,' typically wide and public. <b>Sēmita</b> specifically emphasizes the narrow, less frequented, and often hidden nature of the path." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Quod contrā iūs dīvīnum et humānum est, ac pium nōn habētur, sed impium et scelerātum?</b>", options: ["scelus", "nefās", "culpa", "iniūria"], i: 1, explanation: "The description, \"Quod contrā iūs dīvīnum et humānum est, ac pium nōn habētur, sed impium et scelerātum,\" defines <b>nefās</b>, an indeclinable noun meaning 'wrong, impiety, or sacrilege,' specifically an act forbidden by divine law. While Option A, <i>scelus</i>, means 'crime' or 'wickedness,' <b>nefās</b> carries a stronger connotation of religious transgression. Option C, <i>culpa</i>, means 'fault' or 'blame,' which is less severe. Option D, <i>iniūria</i>, means 'injustice' or 'wrong,' often in a legal sense. <b>Nefās</b> uniquely emphasizes the impious and religiously forbidden nature of the act." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Macula quae fāmam hominis dēhonestat, aut ruīna quae rem pūblicam affligit, vel dēfectiō et corruptiō?</b>", options: ["dēdecus", "labēs", "vīcium", "clādēs"], i: 1, explanation: "The description, \"Macula quae fāmam hominis dēhonestat, aut ruīna quae rem pūblicam affligit, vel dēfectiō et corruptiō,\" refers to <b>labēs</b>, a versatile word meaning 'stain, blemish, disgrace,' but also 'a fall, ruin, or corruption.' It encompasses both moral and physical/political decay. Option A, <i>dēdecus</i>, primarily means 'disgrace' or 'dishonor.' Option C, <i>vīcium</i>, refers to a 'vice' or 'fault' in character. Option D, <i>clādēs</i>, means 'disaster' or 'defeat,' often on a large scale. <b>Labēs</b> uniquely covers the broad spectrum of meanings, from a personal stain to the ruin of a state." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Partēs intrā pectus, ubi animus et affectūs resident, et unde cōnsilia et sententiae oriuntur?</b>", options: ["vīscera", "cor", "praecordia", "pulmōnēs"], i: 2, explanation: "The description, \"Partēs intrā pectus, ubi animus et affectūs resident, et unde cōnsilia et sententiae oriuntur,\" defines <b>praecordia</b>. In poetic and elevated language, <b>praecordia</b> refers to the 'breast' or 'diaphragm' as the seat of the mind, emotions, and intellect, encompassing more than just the physical heart. Option A, <i>vīscera</i>, refers to 'internal organs' or 'entrails' generally. Option B, <i>cor</i>, is the specific 'heart' organ. Option D, <i>pulmōnēs</i>, are the 'lungs.' <b>Praecordia</b> best captures the metaphorical sense of the dwelling place of the soul and feelings." }, { meta: "Circumlocution", stem: "Quod verbum dēscrībit: <b>Humor ex corpore propter labōrem aut calōrem ēmissus, aut magnus labōr ipse et dīligentia?</b>", options: ["frīgus", "sūdor", "sitis", "fūmus"], i: 1, explanation: "The description, \"Humor ex corpore propter labōrem aut calōrem ēmissus, aut magnus labōr ipse et dīligentia,\" defines <b>sūdor</b>, which means 'sweat' (the moisture emitted from the body) but also metaphorically refers to 'toil, exertion, or hard work' itself. Option A, <i>frīgus</i>, means 'cold,' which is an opposite concept. Option C, <i>sitis</i>, means 'thirst,' which can be related to exertion but is not the same. Option D, <i>fūmus</i>, means 'smoke,' which is unrelated. <b>Sūdor</b> accurately covers both the physical manifestation and the effort behind it." }, { meta: "Latin to English", stem: "What is the best translation of <b>fīdus, -a, -um</b>?", options: ["faithful, trustworthy", "treaty", "end, boundary", "to pour"], i: 0, explanation: "The adjective <b>fīdus, -a, -um</b> means 'faithful' or 'trustworthy'. Option B, 'treaty', is the translation of the noun <b>foedus, foederis</b>. Option C, 'end, boundary', is the translation of the noun <b>fīnis, fīnis</b>. Option D, 'to pour', is the translation of the verb <b>fūndō, fūndere, fūdī, fūsus</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>polliceor, pollicērī, pollicitus sum</b>?", options: ["to pollute", "to promise", "thumb", "solemn"], i: 1, explanation: "The deponent verb <b>polliceor, pollicērī, pollicitus sum</b> means 'to promise'. Option A, 'to pollute', is the translation of the verb <b>polluō, polluere, polluī, pollūtus</b>. Option C, 'thumb', is the translation of the noun <b>pollex, pollicis</b>. Option D, 'solemn', is the translation of the adjective <b>sollemnis, -e</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>dīrus, -a, -um</b>?", options: ["to give", "rich", "dreadful, ominous", "hard, harsh"], i: 2, explanation: "The adjective <b>dīrus, -a, -um</b> means 'dreadful' or 'ominous'. Option A, 'to give', is the translation of the verb <b>dō, dare, dedī, datus</b>. Option B, 'rich', is the translation of the adjective <b>dīves, dīvitis</b>. Option D, 'hard, harsh', is the translation of the adjective <b>dūrus, -a, -um</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>aevum, -ī</b>?", options: ["age, time, eternity", "upper air, sky", "bronze, money", "egg"], i: 0, explanation: "The noun <b>aevum, -ī</b> means 'age', 'time', or 'eternity'. Option B, 'upper air, sky', is the translation of the noun <b>aether, aetheris</b>. Option C, 'bronze, money', is the translation of the noun <b>aes, aeris</b>. Option D, 'egg', is the translation of the noun <b>ovum, -ī</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>torus, -ī</b>?", options: ["bull", "couch, bed", "whole, entire", "terror"], i: 1, explanation: "The noun <b>torus, -ī</b> means 'couch' or 'bed' (also a 'bulge' or 'swelling'). Option A, 'bull', is the translation of the noun <b>taurus, -ī</b>. Option C, 'whole, entire', is the translation of the adjective <b>tōtus, -a, -um</b>. Option D, 'terror', is the translation of the noun <b>terror, terrōris</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>serō, serere, sēvī, satus</b>?", options: ["to sow, plant", "to join, interweave", "thus, so", "late"], i: 0, explanation: "The verb <b>serō, serere, sēvī, satus</b> means 'to sow' or 'plant'. Note that there is another verb <b>serō, serere, seruī, sertus</b> which means 'to join' or 'interweave', making option B a strong distractor for advanced students who recognize the homograph. Option C, 'thus, so', is the translation of the adverb <b>sīc</b>. Option D, 'late', is the translation of the adjective <b>sērus, -a, -um</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>pateō, patēre, patuī</b>?", options: ["to suffer, endure", "to lie open, be open", "father", "to obey"], i: 1, explanation: "The verb <b>pateō, patēre, patuī</b> means 'to lie open' or 'be open'. Option A, 'to suffer, endure', is the translation of the deponent verb <b>patior, patī, passus sum</b>. Option C, 'father', is the translation of the noun <b>pater, patris</b>. Option D, 'to obey', is the translation of the verb <b>pāreō, parēre, paruī, paritūrus</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>līmen, līminis</b>?", options: ["mud, slime", "threshold, doorway", "boundary, path", "light, lamp"], i: 1, explanation: "The noun <b>līmen, līminis</b> means 'threshold' or 'doorway'. Option A, 'mud, slime', is the translation of the noun <b>līmus, -ī</b>. Option C, 'boundary, path', is the translation of the noun <b>līmes, līmitis</b>. Option D, 'light, lamp', is the translation of the noun <b>lūmen, lūminis</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>obliviscor, oblivīscī, oblītus sum</b>?", options: ["to forget", "slanting, indirect", "to overwhelm, bury", "hostage"], i: 0, explanation: "The deponent verb <b>obliviscor, oblivīscī, oblītus sum</b> means 'to forget'. Option B, 'slanting, indirect', is the translation of the adjective <b>oblīquus, -a, -um</b>. Option C, 'to overwhelm, bury', is the translation of the verb <b>obruō, obruere, obruī, obrutus</b>. Option D, 'hostage', is the translation of the noun <b>obses, obsidis</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>prīstinus, -a, -um</b>?", options: ["ancient, former, original", "to excel, perform", "immediately, forthwith", "beyond, except"], i: 0, explanation: "The adjective <b>prīstinus, -a, -um</b> means 'ancient', 'former', or 'original'. Option B, 'to excel, perform', is the translation of the verb <b>praestō, praestāre, praestitī, praestitus</b>. Option C, 'immediately, forthwith', is the translation of the adverb <b>prōtinus</b>. Option D, 'beyond, except', is the translation of the preposition <b>praeter</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>dēpellō, dēpellere, dēpulī, dēpulsus</b>?", options: ["to lay down, put aside", "to drive away, repel", "to destroy, erase", "to drive to, land"], i: 1, explanation: "The verb <b>dēpellō, dēpellere, dēpulī, dēpulsus</b> means 'to drive away' or 'repel'. Option A, 'to lay down, put aside', is the translation of the verb <b>dēpōnō, dēpōnere, dēposuī, dēpositus</b>. Option C, 'to destroy, erase', is the translation of the verb <b>dēleō, dēlēre, dēlēvī, dēlētus</b>. Option D, 'to drive to, land', is the translation of the verb <b>appellō, appellere, appulī, appulsus</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>exiguus, -a, -um</b>?", options: ["to demand, complete", "small, scanty, meager", "to strip off, divest", "sick, ill"], i: 1, explanation: "The adjective <b>exiguus, -a, -um</b> means 'small', 'scanty', or 'meager'. Option A, 'to demand, complete', is the translation of the verb <b>exigō, exigere, exēgī, exāctus</b>. Option C, 'to strip off, divest', is the translation of the verb <b>exuō, exuere, exuī, exūtus</b>. Option D, 'sick, ill', is the translation of the adjective <b>aeger, aegra, aegrum</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>almus, -a, -um</b>?", options: ["other, another", "nourishing, kindly", "soul, spirit", "high, deep"], i: 1, explanation: "The adjective <b>almus, -a, -um</b> means 'nourishing' or 'kindly' and is often used as an epithet for goddesses (e.g., <i>alma Venus</i>). Option A, 'other, another', is the translation of the adjective <b>alius, -a, -ud</b>. Option C, 'soul, spirit', is the translation of the noun <b>anima, -ae</b>. Option D, 'high, deep', is the translation of the adjective <b>altus, -a, -um</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>mūnīmen, mūnīminis</b>?", options: ["gift, duty", "fortification, defense", "wall", "generosity"], i: 1, explanation: "The noun <b>mūnīmen, mūnīminis</b> means 'fortification' or 'defense' (often poetic or late Latin). Option A, 'gift, duty', is the translation of the noun <b>mūnus, mūneris</b>. Option C, 'wall', is the translation of the noun <b>mūrus, -ī</b>. Option D, 'generosity', is the translation of the noun <b>mūnificentia, -ae</b>, which is related to <b>mūnus</b>." }, { meta: "Latin to English", stem: "What is the best translation of <b>pōne</b>?", options: ["bridge", "behind, after", "punishment", "to put, place"], i: 1, explanation: "The adverb/preposition <b>pōne</b> means 'behind' or 'after'. Option A, 'bridge', is the translation of the noun <b>pōns, pontis</b>. Option C, 'punishment', is the translation of the noun <b>poena, -ae</b>. Option D, 'to put, place', is the translation of the verb <b>pōnō, pōnere, posuī, positus</b>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Fear</b> (specifically, dread or anxiety)", options: ["<i>formīdō, -inis</i> f.", "<i>metus, -ūs</i> m.", "<i>timor, -ōris</i> m.", "<i>pavor, -ōris</i> m."], i: 1, explanation: "The correct answer is <b>B. <i>metus, -ūs</i></b>. While all options relate to 'fear,' <i>metus</i> specifically denotes a dread or anxiety, often a rational or apprehensive fear of impending danger. <i>Formīdō</i> (A) implies terror or awe. <i>Timor</i> (C) is the most general term for fear. <i>Pavor</i> (D) refers to a sudden fright or panic." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: The <b>sea</b> (poetic, referring to the deep sea or ocean)", options: ["<i>mare, maris</i> n.", "<i>pontus, -ī</i> m.", "<i>aequor, -oris</i> n.", "<i>pelagus, -ī</i> n."], i: 1, explanation: "The correct answer is <b>B. <i>pontus, -ī</i></b>. <i>Pontus</i> is a common poetic term, especially in Vergil and Ovid, for the deep sea or ocean. <i>Mare</i> (A) is the general prose term for 'sea.' <i>Aequor</i> (C) refers to any level surface, often used poetically for the sea's surface. <i>Pelagus</i> (D) is also a poetic term for the open sea, derived from Greek, but <i>pontus</i> more strongly emphasizes the 'deep sea' aspect." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: An <b>old woman</b>", options: ["<i>senecta, -ae</i> f.", "<i>anus, -ūs</i> f.", "<i>vetula, -ae</i> f.", "<i>senīlis, -e</i>"], i: 1, explanation: "The correct answer is <b>B. <i>anus, -ūs</i></b>. This noun specifically means 'an old woman' and belongs to the fourth declension, which can be tricky. <i>Senecta</i> (A) is an abstract noun meaning 'old age.' <i>Vetula</i> (C) is a diminutive of <i>vetus</i>, meaning 'a little old woman,' often with a sense of pity or contempt, not just 'an old woman.' <i>Senīlis</i> (D) is an adjective meaning 'old, aged.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>try</b> (in the sense of to test, to attack, or to attempt with difficulty/risk)", options: ["<i>cōnor, cōnārī, cōnātus sum</i>", "<i>temptō, temptāre, temptāvī, temptātus</i>", "<i>experior, experīrī, expertus sum</i>", "<i>probō, probāre, probāvī, probātus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>temptō</i></b>. This verb carries the specific nuances of 'to test,' 'to attack,' or 'to attempt something difficult or dangerous.' <i>Cōnor</i> (A) is the general verb for 'to try' or 'to attempt.' <i>Experior</i> (C) means 'to try, test, or experience' (often implying a personal trial). <i>Probō</i> (D) means 'to approve, test, or prove.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>kill</b> (specifically, to cut down, slaughter, or massacre)", options: ["<i>interficiō, interficere, interfēcī, interfectus</i>", "<i>caedō, caedere, cecīdī, caesum</i>", "<i>occīdō, occīdere, occīdī, occīsum</i>", "<i>necō, necāre, necāvī, necātus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>caedō</i></b>. This verb literally means 'to cut down' and by extension 'to slaughter, massacre,' often implying a violent and indiscriminate killing of many. <i>Interficiō</i> (A) is a general verb for 'to kill' or 'to destroy.' <i>Occīdō</i> (C), derived from <i>ob-caedō</i>, also means 'to cut down, slay,' and is very close in meaning, but <i>caedō</i> more strongly emphasizes the act of 'cutting down' and 'slaughtering' en masse. <i>Necō</i> (D) is another general term for 'to kill.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: The <b>mind</b> (specifically, the intellect, reason, or understanding)", options: ["<i>animus, -ī</i> m.", "<i>mēns, mentis</i> f.", "<i>ingenuum, -ī</i> n.", "<i>intellectus, -ūs</i> m."], i: 1, explanation: "The correct answer is <b>B. <i>mēns, mentis</i></b>. <i>Mēns</i> refers to the intellectual faculty, reason, and understanding. <i>Animus</i> (A) encompasses the mind, spirit, soul, courage, or passion, but is less specific to pure intellect. <i>Ingenuum</i> (C) refers to innate character or genius. <i>Intellectus</i> (D) means 'understanding' or 'comprehension,' which is a function of the mind, but <i>mēns</i> is the broader and more appropriate noun for the intellectual faculty itself." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>use</b> (specifically, to enjoy the use of, to avail oneself of, typically requiring the ablative case)", options: ["<i>ūtilis, -e</i>", "<i>ūtor, ūtī, ūsus sum</i>", "<i>ūsus, -ūs</i> m.", "<i>adhibeō, adhibēre, adhibuī, adhibitus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>ūtor, ūtī, ūsus sum</i></b>. This is a deponent verb that specifically means 'to use, enjoy the use of, or avail oneself of' and famously governs the ablative case. <i>Ūtilis</i> (A) is an adjective meaning 'useful.' <i>Ūsus</i> (C) is a noun meaning 'use' or 'experience.' <i>Adhibeō</i> (D) means 'to apply' or 'to employ,' which is similar but does not inherently carry the ablative requirement or the nuance of 'enjoying the use of' in the same way <i>ūtor</i> does." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: The <b>sky</b> (poetic, referring to the upper air or heaven, often divine)", options: ["<i>caelum, -ī</i> n.", "<i>aethēr, aetheris</i> m.", "<i>polus, -ī</i> m.", "<i>sīdus, sīderis</i> n."], i: 1, explanation: "The correct answer is <b>B. <i>aethēr, aetheris</i></b>. <i>Aethēr</i> is a poetic term for the pure, upper air, often associated with the realm of the gods or heaven itself, frequently used by poets like Vergil and Ovid. <i>Caelum</i> (A) is the general word for 'sky' or 'heaven.' <i>Polus</i> (C) refers to the pole (celestial or terrestrial) and by extension, the sky, but <i>aethēr</i> more strongly evokes the 'upper air' and divine association. <i>Sīdus</i> (D) means 'star' or 'constellation.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>Ship</b> (poetic, referring to the keel or hull, by synecdoche, the whole ship)", options: ["<i>nāvis, nāvis</i> f.", "<i>puppis, puppis</i> f.", "<i>carīna, -ae</i> f.", "<i>ratis, ratis</i> f."], i: 2, explanation: "The correct answer is <b>C. <i>carīna, -ae</i></b>. This word literally means 'keel,' but in poetry, it is frequently used by synecdoche to refer to the entire 'ship.' <i>Nāvis</i> (A) is the standard, general term for 'ship.' <i>Puppis</i> (B) refers specifically to the 'stern' of a ship. <i>Ratis</i> (D) means 'raft' or 'small boat.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>speak</b> (specifically, to utter, to declare solemnly, often archaic or poetic, and a defective verb)", options: ["<i>loquor, loquī, locūtus sum</i>", "<i>dīcō, dīcere, dīxī, dictus</i>", "<i>fārī, fātus sum</i>", "<i>ōrō, ōrāre, ōrāvī, ōrātus</i>"], i: 2, explanation: "The correct answer is <b>C. <i>fārī, fātus sum</i></b>. This is a defective deponent verb, primarily found in its infinitive <i>fārī</i> or perfect participle <i>fātus</i>, and it carries a strong archaic or poetic connotation of uttering or declaring solemnly. <i>Loquor</i> (A) is the general verb 'to speak, converse.' <i>Dīcō</i> (B) means 'to say, tell.' <i>Ōrō</i> (D) means 'to plead, speak formally, or pray.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>enjoy</b> (to delight in, to derive pleasure from, requiring the ablative case)", options: ["<i>gaudeō, gaudēre, gavīsus sum</i>", "<i>dēlectō, dēlectāre, dēlectāvī, dēlectātus</i>", "<i>fruor, fruī, frūctus sum</i>", "<i>voluptās, voluptātis</i> f."], i: 2, explanation: "The correct answer is <b>C. <i>fruor, fruī, frūctus sum</i></b>. This deponent verb specifically means 'to enjoy, to delight in,' and like <i>ūtor</i>, it governs the ablative case. <i>Gaudeō</i> (A) means 'to rejoice' (intransitive), often followed by an ablative of cause or an infinitive. <i>Dēlectō</i> (B) is a transitive verb meaning 'to delight' or 'to please (someone).' <i>Voluptās</i> (D) is a noun meaning 'pleasure.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: The <b>citizenry</b> (the body of citizens, or the state itself as an organized community)", options: ["<i>urbs, urbis</i> f.", "<i>populus, -ī</i> m.", "<i>cīvitās, cīvitātis</i> f.", "<i>rēs pūblica, reī pūblicae</i> f."], i: 2, explanation: "The correct answer is <b>C. <i>cīvitās, cīvitātis</i></b>. This noun refers to the body of citizens, citizenship, or the state as a political entity. <i>Urbs</i> (A) refers to the physical 'city.' <i>Populus</i> (B) means 'the people' or 'a nation,' but <i>cīvitās</i> emphasizes the political organization and rights of citizens. <i>Rēs pūblica</i> (D) means 'the republic,' 'commonwealth,' or 'public affair,' which is related but not synonymous with 'citizenry' itself." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>hide</b> (specifically, to lie hidden, to be concealed, an intransitive action)", options: ["<i>cēlō, cēlāre, cēlāvī, cēlātus</i>", "<i>lateō, latēre, latuī, —</i>", "<i>abdō, abdere, abdidī, abditus</i>", "<i>occultō, occultāre, occultāvī, occultātus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>lateō, latēre, latuī</i></b>. This is an intransitive verb meaning 'to lie hidden' or 'to be concealed.' The other options are transitive verbs: <i>cēlō</i> (A) means 'to hide (something/someone),' <i>abdō</i> (C) means 'to put away, hide (something),' and <i>occultō</i> (D) means 'to hide, conceal (something).' This question tests the crucial distinction between transitive and intransitive verbs for 'to hide.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>advise</b> (specifically, to warn, to admonish, often with a subtle hint of caution or reminder of duty)", options: ["<i>suādeō, suādēre, suāsī, suāsum</i>", "<i>moneō, monēre, monuī, monitus</i>", "<i>cōnsulō, cōnsulere, cōnsuluī, cōnsultus</i>", "<i>praecipiō, praecipere, praecēpī, praeceptus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>moneō, monēre, monuī, monitus</i></b>. This verb means 'to warn, advise, or admonish,' often implying a reminder of duty or a caution. <i>Suādeō</i> (A) means 'to advise, recommend, or persuade,' focusing more on proposing a course of action. <i>Cōnsulō</i> (C) means 'to consult, deliberate, or take counsel for.' <i>Praecipiō</i> (D) means 'to instruct, order, or anticipate.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: To <b>suffer</b> (to endure, to bear, to permit, a common verb in AP texts)", options: ["<i>doleō, dolēre, doluī, dolitūrus</i>", "<i>patior, patī, passus sum</i>", "<i>perferō, perferre, pertulī, perlātus</i>", "<i>labōrō, labōrāre, labōrāvī, labōrātus</i>"], i: 1, explanation: "The correct answer is <b>B. <i>patior, patī, passus sum</i></b>. This is a highly versatile deponent verb meaning 'to suffer, endure, bear, or permit,' and is very common in advanced Latin prose and poetry. <i>Doleō</i> (A) means 'to feel pain' or 'to grieve.' <i>Perferō</i> (C) means 'to bear through' or 'to endure to the end.' <i>Labōrō</i> (D) means 'to toil, labor,' or 'to be in distress.'" }, { meta: "Synonyms", stem: "Quid est simillimum vocī <b><u>ūsus</u></b>?", options: ["cōnsuētūdō", "officium", "fāma", "labor"], i: 0, explanation: '<i>Ūsus</i> significat "ūsūrum, experientiam, cōnsuētūdinem." <i>Cōnsuētūdō</i> est propinquissima, significāns "mōrem, cōnsuētūdinem, habitum." <i>Officium</i> est "officium, dēbitum," <i>fāma</i> est "fāma, rēputātiō," et <i>labor</i> est "labor, cūra," quae omnia ā sentiōne prōmptā differunt.' }, { meta: "Synonyms", stem: "Quod verbum proximum est <b><u>cōnātus</u></b>?", options: ["cōnsilium", "molīmen", "voluntās", "exitus"], i: 1, explanation: '<i>Cōnātus</i> est "temptāmen, studium, cūra." <i>Molīmen</i> significat "magnam cūram, labōrem, nīxum," saepe cum difficultāte coniūnctum, quod est prope <i>cōnātus</i>. <i>Cōnsilium</i> est "cōnsilium, ratiō," <i>voluntās</i> est "voluntās, cupīdō," et <i>exitus</i> est "fīnis, ēventus," quae nōn sunt synonyma.' }, { meta: "Synonyms", stem: "Quid est simile <b><u>obsecrō</u></b>?", options: ["imperō", "ōrō", "negō", "cōnficiō"], i: 1, explanation: '<i>Obsecrō</i> significat "precor, supplicō, dēprecor." <i>Ōrō</i> est "precārī, rogāre, supplicāre," quod est proximum. <i>Imperō</i> est "imperāre, iubēre" (antonymum contextū), <i>negō</i> est "negāre, recūsāre," et <i>cōnficiō</i> est "perficiō, efficiō," quae omnia ā sentiōne prōmptā differunt.' }, { meta: "Synonyms", stem: "Quod verbum simillimum est <b><u>indoles</u></b>?", options: ["forma", "fortūna", "ingenium", "disciplīna"], i: 2, explanation: '<i>Indoles</i> est "nātūra ingeniī, proprietas īnsita, ingenium." <i>Ingenium</i> est "nātūra, ingenium, talentum," quod est propinquissimum. <i>Forma</i> est "figūra, speciēs," <i>fortūna</i> est "fortūna, cāsus," et <i>disciplīna</i> est "disciplīna, ērudītiō," quae nōn sunt synonyma.' }, { meta: "Synonyms", stem: "Quod verbum proximum est <b><u>nūmen</u></b>?", options: ["fātum", "dīvīnitās", "templum", "sacrum"], i: 1, explanation: '<i>Nūmen</i> significat "voluntātem dīvīnam, potestātem dīvīnam, dīvīnitātem ipsam." <i>Dīvīnitās</i> est "dīvīnitās, nātūra dīvīna," quod est proximum. <i>Fātum</i> est "fātum, dēstinātiō," <i>templum</i> est "templum, aedēs sacra," et <i>sacrum</i> est "sacrum, rītus," quae ad rem dīvīnam pertinent sed nōn sunt synonyma ipsius potestātis dīvīnae.' }, { meta: "Synonyms", stem: "Quid est simillimum <b><u>prōlēs</u></b>?", options: ["pārēns", "gēns", "stirps", "familia"], i: 2, explanation: '<i>Prōlēs</i> est "subolēs, posterī, stirps." <i>Stirps</i> est "stirps, rādīx, generātiō, prōlēs," quod est propinquissimum, praesertim in contextū poeticō. <i>Pārēns</i> est "genitor," <i>gēns</i> est "gēns, nātiō," et <i>familia</i> est "familia, domus," quae ad generātiōnem pertinent sed nōn sunt synonyma ipsius subolis.' }, { meta: "Synonyms", stem: "Quod verbum proximum est <b><u>aevum</u></b>?", options: ["annus", "diēs", "saeculum", "mōrs"], i: 2, explanation: '<i>Aevum</i> est "tempus, aevum, aeternitās." <i>Saeculum</i> est "saeculum, aevum, generātiō," quod est proximum. Ambae voces saepe ad longās temporum spatiīs vel ad aeternitātem referuntur. <i>Annus</i> est "annus," <i>diēs</i> est "diēs," et <i>mōrs</i> est "mōrs, fātum," quae aliās temporis vel vītae rēs significant.' }, { meta: "Synonyms", stem: "Quod verbum simillimum est <b><u>cōnsummō</u></b>?", options: ["incipiō", "dēserō", "perficiō", "impediō"], i: 2, explanation: '<i>Cōnsummō</i> significat "perficiō, ad fīnem dēdūcō, complēō." <i>Perficiō</i> est "perficiō, efficiō, ad fīnem perducō," quod est propinquissimum. <i>Incipiō</i> est "incipiō, initiō" (antonymum), <i>dēserō</i> est "dēserō, relinquō," et <i>impediō</i> est "impediō, obstō," quae aliās actiōnēs significant.' }, { meta: "Synonyms", stem: "Quid est simile <b><u>scaevus</u></b>?", options: ["dexter", "sinister", "laetus", "facilis"], i: 1, explanation: '<i>Scaevus</i>, vox praecipuē poētica vel archaica, significat "sinister, malus, infaustus." <i>Sinister</i> est "sinister, malus, infaustus," quod est proximum. <i>Dexter</i> est "dexter, fēlīx" (antonymum), <i>laetus</i> est "laetus, fēlīx," et <i>facilis</i> est "facilis, lēnis," quae aliās qualitates significant.' }, { meta: "Synonyms", stem: "Quod verbum proximum est <b><u>nex</u></b>?", options: ["vīta", "somnus", "caedēs", "vulnus"], i: 2, explanation: '<i>Nex</i> est "nōx, caedēs, occīsiō violenta." <i>Caedēs</i> est "caedēs, occīsiō, strāgēs," quod est propinquissimum. <i>Vīta</i> est "vīta" (antonymum), <i>somnus</i> est "somnus," et <i>vulnus</i> est "vulnus, plāga," quod potest esse causa necis sed nōn ipsa nex.' }, { meta: "Synonyms", stem: "Quod verbum simillimum est <b><u>dēpellō</u></b>?", options: ["appellō", "amoveō", "retineō", "admittō"], i: 1, explanation: '<i>Dēpellō</i> significat "dēmoveō, pellō, amoveō." <i>Amoveō</i> est "amoveō, removēō, dēpellō," quod est propinquissimum. <i>Appellō</i> est "appellō, nōminō," <i>retineō</i> est "retineō, contineō" (antonymum), et <i>admittō</i> est "admittō, recipiō," quae aliās actiōnēs significant.' }, { meta: "Synonyms", stem: "Quid est simile <b><u>pervicāx</u></b>?", options: ["mītis", "facilis", "pertināx", "ignāvus"], i: 2, explanation: '<i>Pervicāx</i> significat "obstinātus, pertināx, contumax." <i>Pertināx</i> est "pertināx, obstinātus, tenāx," quod est proximum. Ambae voces ad tenācitātem vel obstinātiōnem referuntur. <i>Mītis</i> est "mītis, lēnis" (antonymum), <i>facilis</i> est "facilis, flēxibilis," et <i>ignāvus</i> est "ignāvus, piger," quae aliās qualitates significant.' }, { meta: "Synonyms", stem: "Quod verbum proximum est <b><u>īgnārus</u></b>?", options: ["sciēns", "nescius", "prūdēns", "doctus"], i: 1, explanation: '<i>Īgnārus</i> est "nescius, īgnōrāns, incertus." <i>Nescius</i> est "nescius, īgnōrāns," quod est propinquissimum. <i>Sciēns</i> est "sciēns, cognōscēns" (antonymum), <i>prūdēns</i> est "prūdēns, cōnsultus," et <i>doctus</i> est "doctus, ērudītus," quae aliās mōdōs cognitīvōs vel eōrum contrāria significant.' }, { meta: "Synonyms", stem: "Quod verbum simillimum est <b><u>opīmus</u></b>?", options: ["pauper", "macer", "dīves", "humilis"], i: 2, explanation: '<i>Opīmus</i>, saepe in contextū poēticō vel ad "spolia opīma" referēns, significat "dīves, fertilis, glōriōsus." <i>Dīves</i> est "dīves, locuplēs, opulentus," quod est propinquissimum. <i>Pauper</i> est "pauper" (antonymum), <i>macer</i> est "macer, gracilis" (antonymum ad "fat"), et <i>humilis</i> est "humilis, īnfimus," quae aliās quālitātēs significant.' }, { meta: "Synonyms", stem: "Quid est simile <b><u>cōnscrībō</u></b>?", options: ["dēleō", "legō", "perscrībō", "dictō"], i: 2, explanation: '<i>Cōnscrībō</i> significat "perscrībō, ēnumerō, adscrībō, scrībō." In sentiōne "scrībendī," <i>perscrībō</i>, quod significat "omnīnō scrībō, describō," est proximum. <i>Dēleō</i> est "dēleō, ēradō" (antonymum), <i>legō</i> est "legō, perlegō," et <i>dictō</i> est "dictō, praescrībō," quae aliās actiōnēs cum scrīptūrā coniūnctās significant.' }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>absistō</b>?", options: ["īnstō", "persevērō", "incipiō", "cōnsistō"], i: 1, explanation: "Verbum <b>absistō</b> (<i>absistere, abstitī</i>) significat 'dēsistō, ācēdō, mē abstineō ab aliquā rē'. Contrārium est <b>persevērō</b> (<i>persevērāre, persevērāvī, persevērātus</i>), quod significat 'perstō, immūtābilis sum, inceptum peragō'. `īnstō` (persequor) et `cōnsistō` (stō firmiter) affīnitātem habent cum 'stō', sed nōn sunt contrāria. `incipiō` est contrārium 'fīniō', nōn 'absistō' in sensū dēsistentiae." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>obsequium</b>?", options: ["insolentia", "contumācia", "licentia", "seditio"], i: 1, explanation: "Nōmen <b>obsequium</b> (<i>-ī</i>, n.) significat 'cōmpliance, dēferentia, facilitās'. Contrārium est <b>contumācia</b> (<i>-ae</i>, f.), quod significat 'obstinātiō, rebelliō, animus contumēliōsus'. `insolentia` (arrogantia) et `licentia` (libertās nimia) sunt vitia, sed nōn directe contrāria. `seditio` (rebelliō) est actiō potius quam qualitas animī." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>iners</b>?", options: ["dīligēns", "strēnuus", "vigilāns", "promptus"], i: 1, explanation: "Adiectīvum <b>iners</b> (<i>inertis</i>) significat 'ināctīvus, lentus, ignāvus, imprūdens'. Contrārium est <b>strēnuus</b> (<i>-a, -um</i>), quod significat 'āctīvus, vīgorōsus, dīligēns, fortis'. `dīligēns` (cūrōsus) et `vigilāns` (attentus) et `promptus` (parātus) quidem virtūtēs sunt, sed nōn omnīnō contrāria 'inērtī' in omnī eius significātiōne, praesertim in parte 'ināctīvus'." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>probitās</b>?", options: ["fraus", "mālitia", "nequitia", "impudentia"], i: 2, explanation: "Nōmen <b>probitās</b> (<i>-ātis</i>, f.) significat 'honestās, integritās, virtūs'. Contrārium est <b>nequitia</b> (<i>-ae</i>, f.), quod significat 'malitia, scelus, dēpravātiō morum, vīlitās'. `fraus` (dēceptiō) est species inhonestātis. `mālitia` (malus animus) est genus malitiae. `impudentia` (shamelessness) ad audāciam in peccandō pertinet, nōn ad omnem probitātis contrārium." }, { meta: "Antonyms", stem: "Quod adverbium est contrārium adverbiō <b>māne</b>?", options: ["noctū", "merīdiē", "vesperī", "serō"], i: 2, explanation: "Adverbium <b>māne</b> significat 'tempore mātinō, prīmō diēī'. Contrārium est <b>vesperī</b>, quod significat 'tempore vespertīnō, ad sōlis occāsum'. `noctū` est 'per noctem', `merīdiē` est 'mediō diē', `serō` est 'tardē', quae nōn sunt contrāria 'māne' sīcut 'vesperī'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>arduus</b>?", options: ["facilis", "lēvis", "plānus", "dēclīvis"], i: 2, explanation: "Adiectīvum <b>arduus</b> (<i>-a, -um</i>) significat 'steep, difficilis, altus'. Contrārium est <b>plānus</b> (<i>-a, -um</i>), quod significat 'aequus, lēvis, facilis'. `facilis` (easy) est pars significātiōnis metaphoricae, sed `plānus` ambās significātiōnēs (physicam 'steep' et metaphoricam 'difficult') optime contrāstat. `lēvis` (smooth) et `dēclīvis` (sloping downward) nōn sunt tam directe contrāria." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>sordēs</b>?", options: ["nitor", "munditia", "splendor", "pūritās"], i: 3, explanation: "Nōmen <b>sordēs</b> (<i>-is</i>, f.) significat 'lūtum, spurcitia, vīlitās, dēclīnātiō morum'. Contrārium est <b>pūritās</b> (<i>-ātis</i>, f.), quod significat 'munditia, castitās, integritās'. `munditia` (cleanliness) proximum est, sed `pūritās` in ambārum significātiōnum (physicae et morālis) contrāstū validius est. `nitor` (brightness) et `splendor` (brilliance) ad aspectum magis quam ad substantiam pertinent." }, { meta: "Antonyms", stem: "Quod verbum est contrārium verbō <b>obliviscor</b>?", options: ["recordor", "cōgnōscō", "meminī", "teneō"], i: 2, explanation: "Verbum <b>obliviscor</b> (<i>oblivīscī, oblītus sum</i>) significat 'ē memoriā excidō, nōn recordor'. Contrārium est <b>meminī</b> (<i>meminisse</i>), quod significat 'in memoriā teneō, recordor'. `recordor` (to recall) est verbum simile, sed `meminī` est verbum dēfectīvum quod prīmāriō contrārium 'obliviscor' habētur. `cōgnōscō` (to learn) et `teneō` (to hold) nōn sunt tam directe contrāria quam `meminī`." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>profānus</b>?", options: ["pius", "castus", "sacer", "religiōsus"], i: 2, explanation: "Adiectīvum <b>profānus</b> (<i>-a, -um</i>) significat 'nōn sacerdōtālis, commūnis, impius, nōn sānctus'. Contrārium est <b>sacer</b> (<i>sacra, sacrum</i>), quod significat 'sānctus, dīvīnus, dēdicātus'. `pius` (dutiful), `castus` (chaste), et `religiōsus` (devout) virtūtēs vel qualitates ad religiōnem pertinentes sunt, sed nōn directe contrāstant statum 'profānum'." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>lūctus</b>?", options: ["hilaritās", "laetitia", "voluptās", "gaudium"], i: 3, explanation: "Nōmen <b>lūctus</b> (<i>-ūs</i>, m.) significat 'dolor, trīstitia, maeror, fletus'. Contrārium est <b>gaudium</b> (<i>-ī</i>, n.), quod significat 'laetitia, dēlectātiō, exsultātiō'. `hilaritās` (cheerfulness), `laetitia` (gladness), et `voluptās` (pleasure) sunt species laetitiae vel voluptātis, sed `gaudium` est prīmārium contrārium `lūctūs`." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>aequor</b> (poēticē)?", options: ["collis", "vallis", "clīvus", "mōns"], i: 3, explanation: "Nōmen <b>aequor</b> (<i>-oris</i>, n.) poēticē significat 'superficiēs plāna, mare'. Contrārium est <b>mōns</b> (<i>montis</i>, m.), quod significat 'altum, elevātum, nōn plānum'. `collis` (hill) est minor, `vallis` (valley) est depressiō, `clīvus` (slope) est declīvitās; nūllum ex hīs est tam contrārium `aequorī` (flat expanse) quam `mōns` (mountain)." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>sēdulus</b>?", options: ["pigrōsus", "ignāvus", "socors", "neglēns"], i: 3, explanation: "Adiectīvum <b>sēdulus</b> (<i>-a, -um</i>) significat 'dīligēns, assiduus, cūrōsus'. Contrārium est <b>neglēns</b> (<i>neglegentis</i>), quod significat 'incūrōsus, indīligēns, remissus'. `pigrōsus` (lazy) et `ignāvus` (cowardly, lazy) ad inertia pertinent, `socors` (sluggish, careless) ad incuriam, sed `neglēns` optime contrāstat dīligentiam et cūram 'sēdulī'." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>obscūrus</b>?", options: ["clārus", "manifestus", "apertus", "perspicuus"], i: 3, explanation: "Adiectīvum <b>obscūrus</b> (<i>-a, -um</i>) significat 'tenebrōsus, nōn clārus, ignōtus, difficilis intellectū'. Contrārium est <b>perspicuus</b> (<i>-a, -um</i>), quod significat 'clārus, lūcidus, manifestus, facilis intellectū'. `clārus` (bright, clear), `manifestus` (obvious), et `apertus` (open) sunt verba similia, sed `perspicuus` omnēs significātiōnēs 'obscūrī' optime contrāstat, tam in sensū vīsibilī quam intellegibilī." }, { meta: "Antonyms", stem: "Quod adiectīvum est contrārium adiectīvō <b>vetus</b>?", options: ["novus", "iuvenis", "viridis", "recēns"], i: 3, explanation: "Adiectīvum <b>vetus</b> (<i>veteris</i>) significat 'antīquus, annōsus, prīscus'. Contrārium est <b>recēns</b> (<i>recentis</i>), quod significat 'novus, frīscus, modo factus'. `novus` (new) est prōximē, sed `recēns` speciālius ad id quod modo factum est refertur, quod est fortior contrāstus 'veterī'. `iuvenis` (young) ad aetātem hominum vel animālium, `viridis` (green, fresh) ad colōrem vel vīgōrem pertinet." }, { meta: "Antonyms", stem: "Quod nōmen est contrārium nōminī <b>voluptās</b>?", options: ["trīstitia", "aegritūdō", "miseria", "dolor"], i: 3, explanation: "Nōmen <b>voluptās</b> (<i>-ātis</i>, f.) significat 'dēlectātiō, gaudium, laetitia, lūxuria'. Contrārium est <b>dolor</b> (<i>-ōris</i>, m.), quod significat 'cruciātus, maeror, aegritūdō, trīstitia'. `trīstitia` (sadness), `aegritūdō` (sickness, distress), et `miseria` (misery) sunt species dolōris vel miseriae, sed `dolor` est omnīnō contrārius `voluptātī` in omnibus eius significātiōnibus, tam physicīs quam mentālibus." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["lūmen", "candor", "fulgor", "calīgō"], i: 3, explanation: "The words <b>lūmen</b> (light, lamp), <b>candor</b> (whiteness, brightness, purity), and <b>fulgor</b> (brightness, gleam, splendor) all refer to concepts of light or brilliance. <b>Calīgō</b>, however, means 'mist, fog, darkness, gloom', and therefore refers to an absence of light or obscurity." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["maeror", "aegritūdō", "lūctus", "hilaritās"], i: 3, explanation: "<b>Maeror</b> (grief, sorrow), <b>aegritūdō</b> (sickness, distress, grief), and <b>lūctus</b> (grief, sorrow, mourning) are all nouns denoting forms of sadness, distress, or mourning. <b>Hilaritās</b>, in contrast, means 'cheerfulness, merriment' and thus describes a state of joy." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["timor", "metus", "formīdō", "audācia"], i: 3, explanation: "<b>Timor</b>, <b>metus</b>, and <b>formīdō</b> are all synonyms for 'fear' or 'dread', with <b>formīdō</b> often implying terror. <b>Audācia</b>, while sometimes carrying negative connotations, primarily means 'boldness, daring, courage', which is the antithesis of fear." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["loquor", "fāror", "īnfit", "taceō"], i: 3, explanation: "The verbs <b>loquor</b> (to speak, say), <b>fāror</b> (to speak, say, declare – often poetic), and <b>īnfit</b> (he/she/it begins to speak – archaic/poetic) all describe the act of speaking or uttering. <b>Taceō</b>, on the other hand, means 'to be silent' or 'to keep quiet'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["aequor", "pontus", "pelagus", "tellūs"], i: 3, explanation: "<b>Aequor</b> (a level surface, especially of the sea), <b>pontus</b> (the sea, especially the open sea – poetic), and <b>pelagus</b> (the sea, open sea – poetic) are all elevated or poetic terms for the sea. <b>Tellūs</b>, however, is a poetic term for 'earth, land, country'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["tēlum", "ferrum", "ensis", "clipeus"], i: 3, explanation: "<b>Tēlum</b> (a missile, weapon), <b>ferrum</b> (iron, often used by metonymy for 'sword' or 'weapon'), and <b>ensis</b> (a sword – poetic) are all terms for offensive weapons. <b>Clipeus</b>, conversely, refers to a 'round shield', which is a defensive piece of armor." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["amnis", "flūmen", "rīvus", "mōns"], i: 3, explanation: "<b>Amnis</b> (a river, torrent), <b>flūmen</b> (a river, stream), and <b>rīvus</b> (a brook, small stream) all denote bodies of flowing water. <b>Mōns</b>, in contrast, means 'mountain' or 'hill'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vulnus", "plāga", "cruor", "medicīna"], i: 3, explanation: "<b>Vulnus</b> (a wound, injury), <b>plāga</b> (a blow, stroke, wound), and <b>cruor</b> (gore, blood from a wound) are all terms directly associated with injury or the physical results of harm. <b>Medicīna</b>, however, refers to 'medicine, the healing art, or a remedy'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vetus", "antīquus", "priscus", "recēns"], i: 3, explanation: "The adjectives <b>vetus</b> (old, ancient), <b>antīquus</b> (old, ancient, former), and <b>priscus</b> (ancient, old-fashioned, primitive) all describe something as being old or from a former time. <b>Recēns</b>, conversely, means 'fresh, new, recent'." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["ēdō", "profiteor", "prōmō", "audiō"], i: 3, explanation: "The verbs <b>ēdō</b> (to give out, utter, publish), <b>profiteor</b> (to declare, profess, acknowledge), and <b>prōmō</b> (to bring forth, disclose, utter) all describe actions of expressing, speaking, or making something known. <b>Audiō</b>, on the other hand, means 'to hear' or 'to listen', which is a receptive action rather than an expressive one." }, { meta: "Analogies", stem: "<b>cingō</b> : <b>cīnctus</b> :: <b>fateor</b> : X", options: ["fāctus", "fōtus", "fessus", "fīxus"], i: 2, explanation: "The relationship is Verb : Perfect Passive Participle (PPP). <b>cingō, cingere, cīnxī, cīnctus</b> (to gird, surround). The PPP of <b>fateor, fatērī, fassus sum</b> (to confess, admit) is <b>fassus</b>, which is often contracted to <b>fessus</b> in poetic and later Latin, especially when used adjectivally. Option C, <b>fessus</b>, is the correct, albeit irregular, PPP. Options A (<b>fāctus</b> from <b>faciō</b>), B (<b>fōtus</b> from <b>foveō</b>), and D (<b>fīxus</b> from <b>fīgō</b>) are PPPs of other verbs, chosen as distractors due to similar sounds or forms." }, { meta: "Analogies", stem: "<b>aequus</b> : <b>aequitās</b> :: <b>prūdēns</b> : X", options: ["prūna", "prōvideō", "prūdentia", "prōditor"], i: 2, explanation: "The relationship is Adjective : Abstract Noun. <b>aequus</b> (fair, just) forms the abstract noun <b>aequitās</b> (fairness, equity). Similarly, <b>prūdēns</b> (prudent, wise) forms the abstract noun <b>prūdentia</b> (prudence, foresight). Option A, <b>prūna</b>, means 'a live coal'. Option B, <b>prōvideō</b>, is a verb meaning 'to foresee'. Option D, <b>prōditor</b>, means 'traitor'. These are distractors based on sound or related semantic fields but do not fit the grammatical transformation." }, { meta: "Analogies", stem: "<b>regō</b> : <b>rēctor</b> :: <b>ōrō</b> : X", options: ["ōrātiō", "ōrāculum", "ōrātor", "ōrātrix"], i: 2, explanation: "The relationship is Verb : Agent Noun. <b>regō</b> (to rule, guide) forms the agent noun <b>rēctor</b> (ruler, guide). Likewise, <b>ōrō</b> (to plead, pray) forms the agent noun <b>ōrātor</b> (speaker, orator, pleader). Option A, <b>ōrātiō</b>, is an action noun meaning 'speech' or 'prayer'. Option B, <b>ōrāculum</b>, means 'oracle' (a place or divine response). Option D, <b>ōrātrix</b>, is the specific feminine agent noun, whereas <b>ōrātor</b> serves as the general masculine/common agent noun." }, { meta: "Analogies", stem: "<b>falx</b> : <b>īnstrūmentum</b> :: <b>caterva</b> : X", options: ["cohors", "grex", "multitūdō", "contubernium"], i: 2, explanation: "The relationship is Specific Type : General Category. A <b>falx</b> (sickle, scythe, grappling hook) is a specific type of <b>īnstrūmentum</b> (tool, implement). Similarly, a <b>caterva</b> (troop, band, crowd, often disorderly or a mob) is a specific type of <b>multitūdō</b> (multitude, crowd). Options A (<b>cohors</b> - cohort, military unit), B (<b>grex</b> - flock, herd, company), and D (<b>contubernium</b> - mess-unit, tent-companionship) are all specific types of groups, but <b>multitūdō</b> serves as the broader, more general category for <b>caterva</b>." }, { meta: "Analogies", stem: "<b>lūstrum</b> : <b>pūrgō</b> :: <b>augurium</b> : X", options: ["ōrō", "vaticinor", "auguror", "immolō"], i: 2, explanation: "The relationship is Ritual/Object : Associated Action (Verb). A <b>lūstrum</b> (purificatory sacrifice or ceremony) is associated with the verb <b>pūrgō</b> (to cleanse, purify). An <b>augurium</b> (omen, divination) is associated with the verb <b>auguror</b> (to take omens, divine). Option A, <b>ōrō</b>, means 'to pray'. Option B, <b>vaticinor</b>, means 'to prophesy' but is less specific to formal Roman augury. Option D, <b>immolō</b>, means 'to sacrifice', which is a related but different ritual action." }, { meta: "Analogies", stem: "<b>mītis</b> : <b>asper</b> :: <b>pervicāx</b> : X", options: ["lentus", "mōrōsus", "contumax", "obsequēns"], i: 3, explanation: "The relationship is Antonym. <b>mītis</b> (mild, gentle) is an antonym of <b>asper</b> (rough, harsh). Likewise, <b>pervicāx</b> (stubborn, obstinate) is an antonym of <b>obsequēns</b> (compliant, obedient). Option A, <b>lentus</b>, means 'slow' or 'pliant'. Option B, <b>mōrōsus</b>, means 'fretful' or 'peevish'. Option C, <b>contumax</b>, is a near synonym for <b>pervicāx</b>, meaning 'insubordinate' or 'stubborn', making it a strong distractor." }, { meta: "Analogies", stem: "<b>linter</b> : <b>nāvigō</b> :: <b>clipeus</b> : X", options: ["tegō", "ferō", "dēfendō", "ornō"], i: 2, explanation: "The relationship is Object : Primary Function (Verb). A <b>linter</b> (skiff, small boat) is used for <b>nāvigō</b> (to sail, navigate). A <b>clipeus</b> (round shield) is primarily used to <b>dēfendō</b> (to defend). Option A, <b>tegō</b> (to cover, protect), is a very close synonym in some contexts, but <b>dēfendō</b> more directly expresses the active purpose of a shield in combat. Option B, <b>ferō</b>, means 'to carry'. Option D, <b>ornō</b>, means 'to adorn', which shields might be, but it's not their primary function." }, { meta: "Analogies", stem: "<b>sōlus</b> : <b>sōlum</b> :: <b>prīmus</b> : X", options: ["prīmō", "prior", "prīmum", "prīncipium"], i: 2, explanation: "The relationship is Adjective : Corresponding Adverb. <b>sōlus</b> (alone, adj.) has the adverb <b>sōlum</b> (only, merely). Similarly, <b>prīmus</b> (first, adj.) has the adverb <b>prīmum</b> (first, for the first time). Option A, <b>prīmō</b>, also functions as an adverb meaning 'at first' or 'in the beginning', often an ablative of time. However, <b>prīmum</b> is the direct adverbial form corresponding to the adjective <b>prīmus</b> when meaning 'firstly' or 'for the first time'. Option B, <b>prior</b>, is the comparative adjective 'earlier'. Option D, <b>prīncipium</b>, is a noun meaning 'beginning'." }, { meta: "Analogies", stem: "<b>collis</b> : <b>clīvus</b> :: <b>aedificium</b> : X", options: ["pariēs", "fundāmentum", "tēctum", "lapis"], i: 2, explanation: "The relationship is Whole : Part. A <b>clīvus</b> (slope, ascent) is a part of a <b>collis</b> (hill). A <b>tēctum</b> (roof) is a prominent and essential part of an <b>aedificium</b> (building). Options A (<b>pariēs</b> - wall), B (<b>fundāmentum</b> - foundation), and C (<b>columna</b> - column, not listed here but a good example) are also parts of a building. However, <b>tēctum</b> is a distinct and fundamental component. Option D, <b>lapis</b> (stone), is a component material rather than a structural part in the same sense." }, { meta: "Analogies", stem: "<b>caesariēs</b> : <b>coma</b> :: <b>pōcula</b> : X", options: ["merum", "fūndō", "crātēra", "cyathus"], i: 2, explanation: "The relationship is Poetic Synonym / Semantic Field. <b>caesariēs</b> and <b>coma</b> are both poetic terms for 'hair', often long or flowing. <b>pōcula</b> (cups, drinking vessels) and <b>crātēra</b> (mixing bowl, krater, often used poetically for a large drinking vessel or for the wine within it) are both poetic terms for vessels used for drinking. Option A, <b>merum</b>, refers to 'pure wine' (the substance). Option B, <b>fūndō</b>, is a verb meaning 'to pour'. Option D, <b>cyathus</b>, is a specific, smaller type of cup or ladle, making <b>crātēra</b> a better general poetic parallel to <b>pōcula</b>." }, { meta: "Fill-in-the-Blank", stem: "Iuppiter īrā incēnsus __________ ex Olympō dēmīsit, terram et caelum contremefacit.", options: ["fulmen", "ignem", "tēlum", "nūbem"], i: 0, explanation: "The sentence describes Jupiter's anger causing a shaking of earth and sky, which is characteristic of a <b>fulmen</b> (thunderbolt). While 'ignem' (fire) and 'tēlum' (weapon) are related, <b>fulmen</b> is the precise and idiomatic term for Jupiter's divine weapon and its destructive effect. 'Nūbem' (cloud) does not fit the context of being 'sent down' in anger to cause such devastation." }, { meta: "Fill-in-the-Blank", stem: "Tantā erat impietās ut hoc __________ dīvīnārum lēgum putārētur, nōn sōlum scelus hūmānum.", options: ["nefās", "scelus", "culpa", "fraus"], i: 0, explanation: "The context 'dīvīnārum lēgum' (of divine laws) and 'nōn sōlum scelus hūmānum' (not only a human crime) strongly indicates that the missing word should refer to a religious transgression. <b>Nefās</b> (an unholy act, sacrilege) perfectly fits this nuance, specifically denoting something contrary to divine law or religious custom. 'Scelus' (crime) is a general term for a wicked deed, 'culpa' (fault, blame) is too mild, and 'fraus' (deceit, fraud) is semantically incorrect." }, { meta: "Fill-in-the-Blank", stem: "Post longam labōrum seriem, mīles tandem __________ membra in umbrā quiēscēbat, profundō somnō oppressus.", options: ["sōpītus", "fessus", "vigil", "lassus"], i: 0, explanation: "The phrase 'profundō somnō oppressus' (overcome by deep sleep) provides a strong clue. <b>Sōpītus</b> (lulled to sleep, put to rest, dormant) is a poetic and elevated term that perfectly describes limbs heavy with sleep. 'Fessus' (tired) and 'lassus' (weary) are close but less specific to the state of being deeply asleep. 'Vigil' (watchful) is an antonym." }, { meta: "Fill-in-the-Blank", stem: "Nāvibus tempestāte iactātīs, nautae spē dēiectī vastum __________ trānsīre cōgēbantur, sīve morte sīve vītā.", options: ["aequor", "campus", "lītus", "pelagus"], i: 0, explanation: "The context of 'nāvibus tempestāte iactātīs' (ships tossed by a storm) and 'trānsīre' (to cross) points to a body of water. <b>Aequor</b> (level surface, especially the sea) is a common poetic term for the sea, emphasizing its flat expanse. While 'pelagus' (the open sea) is a very close synonym and often interchangeable, <b>aequor</b> is frequently used by poets like Vergil to describe the surface traversed. 'Campus' (plain, field) is incorrect, and 'lītus' (shore) is not something one 'crosses' in a ship in this manner." }, { meta: "Fill-in-the-Blank", stem: "Per silvās obscūrās et montēs altōs, hērōs ignōtās regiōnēs __________ glōriae cupidus.", options: ["lūstrābat", "vīsitābat", "peregrīnābātur", "circumeābat"], i: 0, explanation: "The hero is 'glōriae cupidus' (eager for glory) and moving 'per silvās obscūrās et montēs altōs' (through dark forests and high mountains) to 'ignōtās regiōnēs' (unknown regions). <b>Lūstrō</b> (to survey, traverse, purify) is a strong poetic verb that encompasses the idea of exploring and observing a vast area, fitting the heroic context. 'Vīsitō' (to visit) is too mundane. 'Peregrīnor' (to travel abroad) is more about being a foreigner. 'Circumeō' (to go around) lacks the sense of thorough exploration and observation implied by 'lūstrō'." }, { meta: "Fill-in-the-Blank", stem: "Inter gēns Rōmāna et Sabīna, prīmō __________ nōn erat, unde bellum exortum est ac rapīnae virginum.", options: ["cōnūbium", "pāx", "amīcitia", "foedus"], i: 0, explanation: "The phrase 'unde bellum exortum est ac rapīnae virginum' (whence war arose and the abduction of maidens) directly references the historical cause of the Roman-Sabine conflict. The Romans initially lacked the right of intermarriage with the Sabines. <b>Cōnūbium</b> specifically means 'marriage' or 'the right of marriage'. 'Pāx' (peace) and 'amīcitia' (friendship) are too general. 'Foedus' (treaty, alliance) refers to a broader agreement, but the specific issue leading to the conflict was the lack of marital rights." }, { meta: "Fill-in-the-Blank", stem: "Hērōs, victō hoste, eius __________ dīvīnīs templīs suspendit, grātiam deīs agēns.", options: ["exuviās", "arma", "praedam", "spolia"], i: 0, explanation: "The sentence describes a hero hanging the vanquished enemy's possessions in temples as an offering of gratitude. While 'arma' (weapons), 'praeda' (booty), and 'spolia' (spoils) are related, <b>exuviae</b> (spoils, relics, what is stripped off, especially personal effects or armor of a vanquished foe) is a more specific and poetic term, often used by Vergil, emphasizing the personal nature of what is taken from a defeated opponent. It carries a sense of the opponent's 'skin' or 'garments' being stripped away." }, { meta: "Fill-in-the-Blank", stem: "Post multōs annōs labōrum, hominēs vērē līberī __________ fīērī potuērunt, nōn antea.", options: ["dēmum", "tandem", "denique", "postrēmō"], i: 0, explanation: "The phrase 'nōn antea' (not before) provides a critical clue, emphasizing that freedom was achieved 'only then' or 'not until then'. <b>Dēmum</b> (at length, at last; only then, not until) precisely conveys this nuance, signifying that something happens after a long delay and often under specific conditions. While 'tandem' (at last) is a close synonym, 'dēmum' often implies a stronger emphasis on the preceding condition or the finality of the achievement after a prolonged struggle. 'Denique' and 'postrēmō' are typically used for summing up or listing in sequence." }, { meta: "Fill-in-the-Blank", stem: "Ōrāculum, per __________ obscūrās, fāta futūra nūntiāvit, nēmō nisi sapiēns intellegere poterat.", options: ["ambāgēs", "verba", "mysterīa", "dicta"], i: 0, explanation: "The sentence describes an oracle announcing fates through 'obscūrās' (obscure) means, which 'nēmō nisi sapiēns intellegere poterat' (no one but a wise person could understand). <b>Ambāgēs</b> (winding paths, circumlocutions, ambiguities, riddles) is the perfect term for the often obscure, indirect, and enigmatic pronouncements of an oracle. While 'verba' (words) and 'dicta' (sayings) are too general, and 'mysterīa' (mysteries) is plausible, 'ambāgēs' specifically refers to the convoluted manner of expression typical of oracles." }, { meta: "Fill-in-the-Blank", stem: "Rēgēs, post longum bellum, foedus novum __________ cōnstituērunt, ut pāx dēnique fieret.", options: ["īcere", "facere", "sancīre", "firmāre"], i: 0, explanation: "The phrase 'foedus novum' (a new treaty) combined with the infinitive 'cōnstituērunt' (they decided) requires a verb meaning 'to make' or 'to strike' a treaty. <b>Foedus īcere</b> is the standard, idiomatic Latin expression for 'to make' or 'to strike a treaty', literally meaning 'to strike a treaty', referring to the ancient practice of striking an animal as part of the ritual for ratifying an agreement. While 'facere' (to make) can sometimes be used with 'foedus', 'īcere' is the more formal and classical idiom. 'Sancīre' (to ratify, confirm) implies confirming an existing agreement, and 'firmāre' (to strengthen, confirm) is similar." }, { meta: "Circumlocution", stem: "Quī somnō gravī oppressus est, vel cuius mēns torpet, est:", options: ["oblivīscēns", "āter", "sōpitus", "lassus"], i: 2, explanation: "The correct answer is <b>C. sōpitus</b>. This participle, derived from <i>sōpiō</i>, means 'lulled to sleep, stupefied, put to sleep,' perfectly describing one overcome by heavy sleep or whose mind is sluggish. Option <b>A. oblivīscēns</b> means 'forgetting.' Option <b>B. āter</b> means 'dark, gloomy.' Option <b>D. lassus</b> means 'weary, tired.'" }, { meta: "Circumlocution", stem: "Actiōnem vel rem aliquam ad fīnem dūcere, nōn ultrā prōgredī, significat:", options: ["intermittere", "dēsinere", "prōvehere", "persistere"], i: 1, explanation: "The correct answer is <b>B. dēsinere</b>. <i>Dēsinō</i> means 'to cease, stop, leave off,' which accurately reflects 'to bring an action or thing to an end, not to proceed further.' Option <b>A. intermittere</b> means 'to interrupt, break off,' often implying a temporary cessation. Option <b>C. prōvehere</b> means 'to carry forward, advance.' Option <b>D. persistere</b> means 'to persist, continue,' which is an antonym." }, { meta: "Circumlocution", stem: "Rēs ab hoste victō dētrāctae, vel vestēs corpore dēpositae, vel pellis serpente mūtāta, appellantur:", options: ["spolia", "vestīmenta", "exuviae", "arma"], i: 2, explanation: "The correct answer is <b>C. exuviae</b>. This word refers to 'spoils stripped from an enemy,' 'clothes stripped off,' or 'a snake's slough,' encompassing all aspects of the definition. Option <b>A. spolia</b> specifically means 'spoils of war.' Option <b>B. vestīmenta</b> means 'clothes.' Option <b>D. arma</b> means 'arms, weapons,' a specific type of spoil." }, { meta: "Circumlocution", stem: "Spatium temporis longissimum, vel aetās hominis, vel diēs omnēs quōs vīvit, dīcitur:", options: ["tempus", "saeculum", "aevum", "spatium"], i: 2, explanation: "The correct answer is <b>C. aevum</b>. <i>Aevum</i> means 'age, lifetime, eternity, period of time,' matching 'a very long space of time, or the age of a person, or all the days one lives.' In poetic contexts, it often carries a sense of profound or eternal duration. Option <b>A. tempus</b> is 'time' in a general sense. Option <b>B. saeculum</b> is 'a generation, an age, a century.' Option <b>D. spatium</b> is 'space, interval.'" }, { meta: "Circumlocution", stem: "Signum quod futūra praenūntiat, saepe dīvīnum, est:", options: ["fātum", "cāsus", "ōmen", "vōx"], i: 2, explanation: "The correct answer is <b>C. ōmen</b>. <i>Ōmen</i> means 'an omen, a sign, a portent,' which is a sign that foretells future events, often divine. Option <b>A. fātum</b> means 'fate, destiny,' which is the outcome, not the sign. Option <b>B. cāsus</b> means 'chance, accident, misfortune,' lacking the prophetic element. Option <b>D. vōx</b> means 'voice,' although omens can sometimes be conveyed by voices, it's not the primary meaning." }, { meta: "Circumlocution", stem: "Quī memoriā nūllam rem tenet, vel cuius mēns praeterita nōn recordātur, est:", options: ["memor", "ignārus", "oblitus", "cōgnōscēns"], i: 2, explanation: "The correct answer is <b>C. oblitus</b>. <i>Oblitus</i>, the perfect participle of <i>oblivīscor</i>, means 'forgetful, having forgotten,' accurately describing someone who holds nothing in memory or whose mind does not recall past events. Option <b>A. memor</b> means 'mindful, remembering,' an antonym. Option <b>B. ignārus</b> means 'ignorant, unaware,' which is related but not specifically about forgetting. Option <b>D. cōgnōscēns</b> means 'knowing, recognizing,' an antonym." }, { meta: "Circumlocution", stem: "Magnō negōtiō afficī, vel dolōre premī, vel gravia ferre, est:", options: ["patī", "opus facere", "labōrāre", "gaudēre"], i: 2, explanation: "The correct answer is <b>C. labōrāre</b>. While <i>labōrō</i> can mean 'to work,' in advanced Latin, especially poetic contexts, it frequently means 'to suffer, be in distress, be troubled,' fitting 'to be affected by great trouble, to be pressed by pain, or to bear heavy things.' Option <b>A. patī</b> is a very close synonym for 'to suffer, endure,' but <i>labōrāre</i> often implies a more active struggle or toil. Option <b>B. opus facere</b> means 'to do work.' Option <b>D. gaudēre</b> means 'to rejoice,' an antonym." }, { meta: "Circumlocution", stem: "Quī nūllā vī nūllōve mōtū est, vel cuius animus ad agendum lentus est, est:", options: ["strenuus", "pigra", "fortis", "iners"], i: 3, explanation: "The correct answer is <b>D. iners</b>. <i>Iners</i> means 'inactive, sluggish, inert, without skill or energy, cowardly,' matching the description of someone without strength or movement, or whose spirit is slow to act. Option <b>A. strenuus</b> means 'active, vigorous,' an antonym. Option <b>B. pigra</b> (feminine of <i>piger</i>) means 'lazy, sluggish,' which is close but <i>iners</i> often implies a more fundamental lack of power or spirit. Option <b>C. fortis</b> means 'brave, strong,' an antonym." }, { meta: "Circumlocution", stem: "Ā summō in īmum celeriter dēicere, vel sē ipsum dēorsum ferre, vel sōlem occidere, est:", options: ["ascendere", "prōcurrere", "praecipitāre", "ēripere"], i: 2, explanation: "The correct answer is <b>C. praecipitāre</b>. <i>Praecipitō</i> means 'to throw headlong, to rush down, to set (of the sun),' aligning with 'to throw down quickly from top to bottom, or to carry oneself downwards, or for the sun to set.' This verb is frequently found in Vergil and Ovid. Option <b>A. ascendere</b> means 'to ascend, climb,' an antonym. Option <b>B. prōcurrere</b> means 'to run forward,' implying speed but not necessarily downwards. Option <b>D. ēripere</b> means 'to snatch away, rescue,' which is unrelated." }, { meta: "Circumlocution", stem: "Cēremōnia quā corpus mortuī sepelītur, vel ipsa mors vel cadaver, appellātur:", options: ["vīta", "sepulcrum", "fūnus", "lūctus"], i: 2, explanation: "The correct answer is <b>C. fūnus</b>. <i>Fūnus</i> means 'a funeral, burial; death; a corpse,' covering all aspects of the definition: the ceremony, death itself, or the body. Option <b>A. vīta</b> means 'life,' an antonym. Option <b>B. sepulcrum</b> means 'a tomb, grave,' which is the place, not the event or body. Option <b>D. lūctus</b> means 'grief, mourning,' which is a related emotion, not the event or body itself." }, { meta: "Latin to English", stem: "Choose the best translation for <b>obsequium, -ī</b> (n.).", options: ["funeral rites", "compliance, deference", "pursuit, following", "a siege"], i: 1, explanation: "The correct answer is <b>B. compliance, deference</b>. <b>Obsequium</b> refers to compliance, obedience, or deference. <br>Distractor <b>A</b>, 'funeral rites,' translates <i>exsequiae, -ārum</i> (f. pl.). <br>Distractor <b>C</b>, 'pursuit, following,' is a possible meaning for the verb <i>obsequor</i>, but not the noun <i>obsequium</i> in its primary sense. <br>Distractor <b>D</b>, 'a siege,' translates <i>obsidiō, -ōnis</i> (f.)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>labēs, -is</b> (f.).", options: ["labor, toil", "lip, edge", "stain, disgrace, fall", "to slip, glide"], i: 2, explanation: "The correct answer is <b>C. stain, disgrace, fall</b>. <b>Labēs</b> (with a short 'a') means a fall, a stain, or a disgrace. <br>Distractor <b>A</b>, 'labor, toil,' translates <i>labor, -ōris</i> (m.). <br>Distractor <b>B</b>, 'lip, edge,' translates <i>labrum, -ī</i> (n.). <br>Distractor <b>D</b>, 'to slip, glide,' translates the verb <i>lābor, lābī, lāpsus sum</i> (with a long 'a')." }, { meta: "Latin to English", stem: "Choose the best translation for <b>sēgnis, -e</b>.", options: ["slow, sluggish, inactive", "a sign, standard", "to separate", "to cut"], i: 0, explanation: "The correct answer is <b>A. slow, sluggish, inactive</b>. <b>Sēgnis</b> is an adjective meaning slow, sluggish, or inactive. <br>Distractor <b>B</b>, 'a sign, standard,' translates <i>signum, -ī</i> (n.), which is visually similar. <br>Distractor <b>C</b>, 'to separate,' translates the verb <i>sēgregō, -āre</i>. <br>Distractor <b>D</b>, 'to cut,' translates the verb <i>secō, secāre, secuī, sectus</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>dēsinō, dēsinere, dēsiī, dēsitum</b>.", options: ["to desire, long for", "to sit down, settle", "to stop, cease", "idleness, sloth"], i: 2, explanation: "The correct answer is <b>C. to stop, cease</b>. <b>Dēsinō</b> means to stop or cease. <br>Distractor <b>A</b>, 'to desire, long for,' translates <i>dēsīderō, -āre</i>. <br>Distractor <b>B</b>, 'to sit down, settle,' translates <i>dēsideō, dēsidēre, dēsidī</i>. <br>Distractor <b>D</b>, 'idleness, sloth,' translates the noun <i>dēsidia, -ae</i> (f.)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>cōnfīnis, -e</b>.", options: ["bordering, adjacent", "a boundary, limit", "to trust, rely on", "to finish, complete"], i: 0, explanation: "The correct answer is <b>A. bordering, adjacent</b>. <b>Cōnfīnis</b> is an adjective meaning bordering or adjacent. <br>Distractor <b>B</b>, 'a boundary, limit,' translates the noun <i>cōnfīnium, -ī</i> (n.), which is related but a different part of speech. <br>Distractor <b>C</b>, 'to trust, rely on,' translates the verb <i>cōnfīdō, cōnfīdere, cōnfīsus sum</i>. <br>Distractor <b>D</b>, 'to finish, complete,' translates the verb <i>fīniō, fīnīre</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>ērudītus, -a, -um</b>.", options: ["rough, unrefined", "learned, educated", "to dig out, overthrow", "to instruct, teach"], i: 1, explanation: "The correct answer is <b>B. learned, educated</b>. <b>Ērudītus</b> is the perfect passive participle of <i>ērudiō</i>, meaning 'learned' or 'educated.' <br>Distractor <b>A</b>, 'rough, unrefined,' translates <i>rūdis, -e</i>, which is visually similar to the root. <br>Distractor <b>C</b>, 'to dig out, overthrow,' translates <i>ēruō, ēruere, ēruī, ērutus</i>, a different verb. <br>Distractor <b>D</b>, 'to instruct, teach,' is a meaning of the verb <i>ērudiō</i>, from which <i>ērudītus</i> is derived, but the adjective itself means 'learned' or 'educated,' not 'to instruct.'" }, { meta: "Latin to English", stem: "Choose the best translation for <b>prōdigium, -ī</b> (n.).", options: ["extravagant, wasteful", "omen, prodigy, monster", "to waste, squander", "to bring forth, produce"], i: 1, explanation: "The correct answer is <b>B. omen, prodigy, monster</b>. <b>Prōdigium</b> refers to an omen, a prodigy, or a monster. <br>Distractor <b>A</b>, 'extravagant, wasteful,' translates the adjective <i>prōdigus, -a, -um</i>. <br>Distractor <b>C</b>, 'to waste, squander,' translates the verb <i>prōdigō, prōdigere, prōdēgī, prōdāctus</i>. <br>Distractor <b>D</b>, 'to bring forth, produce,' translates the verb <i>prōdūcō, prōdūcere, prōdūxī, prōductus</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>obliquus, -a, -um</b>.", options: ["to forget", "slanting, indirect", "to bind, obligate", "to block, obstruct"], i: 1, explanation: "The correct answer is <b>B. slanting, indirect</b>. <b>Obliquus</b> is an adjective meaning slanting, indirect, or sideways. <br>Distractor <b>A</b>, 'to forget,' translates the verb <i>oblivīscor, oblivīscī, oblītus sum</i>. <br>Distractor <b>C</b>, 'to bind, obligate,' translates the verb <i>obligō, obligāre</i>. <br>Distractor <b>D</b>, 'to block, obstruct,' translates the verb <i>obstruō, obstruere</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>sōlācium, -ī</b> (n.).", options: ["ground, soil", "alone, only", "comfort, solace", "the sun"], i: 2, explanation: "The correct answer is <b>C. comfort, solace</b>. <b>Sōlācium</b> means comfort, solace, or consolation. <br>Distractor <b>A</b>, 'ground, soil,' translates <i>solum, -ī</i> (n.). <br>Distractor <b>B</b>, 'alone, only,' translates the adjective <i>sōlus, -a, -um</i>. <br>Distractor <b>D</b>, 'the sun,' translates <i>sōl, sōlis</i> (m.)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>īnsidiae, -ārum</b> (f. pl.).", options: ["distinguished, remarkable", "ambush, plot, treachery", "inside, within", "to sit upon, occupy"], i: 1, explanation: "The correct answer is <b>B. ambush, plot, treachery</b>. <b>Īnsidiae</b> (always plural) means an ambush, a plot, or treachery. <br>Distractor <b>A</b>, 'distinguished, remarkable,' translates the adjective <i>īnsignis, -e</i>. <br>Distractor <b>C</b>, 'inside, within,' translates the adverb <i>intus</i>. <br>Distractor <b>D</b>, 'to sit upon, occupy,' translates the verb <i>īnsideō, īnsidēre, īnsēdī</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>dēprecārī</b>.", options: ["to avert by prayer, to beg off", "to catch, seize, detect", "to pray, entreat", "to value, appraise"], i: 0, explanation: "The correct answer is <b>A. to avert by prayer, to beg off</b>. <b>Dēprecārī</b> means to ward off by prayer, to beg off, or to deprecate. <br>Distractor <b>B</b>, 'to catch, seize, detect,' translates the verb <i>dēprehendō, dēprehendere, dēprehendī, dēprehēnsus</i>. <br>Distractor <b>C</b>, 'to pray, entreat,' translates <i>precārī</i>, the root verb. <br>Distractor <b>D</b>, 'to value, appraise,' relates to <i>pretium</i> (price) or <i>pretiōsus</i> (valuable)." }, { meta: "Latin to English", stem: "Choose the best translation for <b>cōnficiō, cōnficere, cōnfēcī, cōnfectus</b>.", options: ["to trust, rely on", "to accomplish, finish, wear out", "to forge, invent", "to confess, acknowledge"], i: 1, explanation: "The correct answer is <b>B. to accomplish, finish, wear out</b>. <b>Cōnficiō</b> is a versatile verb meaning to accomplish, finish, complete, or to wear out/exhaust. <br>Distractor <b>A</b>, 'to trust, rely on,' translates <i>cōnfīdō, cōnfīdere, cōnfīsus sum</i>. <br>Distractor <b>C</b>, 'to forge, invent,' translates <i>fingō, fingere, fīnxī, fictus</i>. <br>Distractor <b>D</b>, 'to confess, acknowledge,' translates <i>cōnfiteor, cōnfitērī, cōnfessus sum</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>obīre</b>.", options: ["circle, world", "to go to meet, to die", "to surround, enclose", "to forget"], i: 1, explanation: "The correct answer is <b>B. to go to meet, to die</b>. <b>Obīre</b> is the present active infinitive of <i>obeō</i>, meaning to go to meet, to encounter, or euphemistically, to die. <br>Distractor <b>A</b>, 'circle, world,' is the accusative singular of <i>orbis, orbis</i> (m.). <br>Distractor <b>C</b>, 'to surround, enclose,' translates <i>obsaepiō, obsaepīre</i>. <br>Distractor <b>D</b>, 'to forget,' translates <i>oblivīscor, oblivīscī, oblītus sum</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>effulgeō, effulgēre, effulsī</b>.", options: ["to flee, escape", "to shine forth, gleam", "to pour out, shed", "to accomplish, effect"], i: 1, explanation: "The correct answer is <b>B. to shine forth, gleam</b>. <b>Effulgeō</b> means to shine forth or gleam. <br>Distractor <b>A</b>, 'to flee, escape,' translates <i>effugiō, effugere, effūgī</i>, which is visually and phonetically similar. <br>Distractor <b>C</b>, 'to pour out, shed,' translates <i>effundō, effundere, effūdī, effūsus</i>. <br>Distractor <b>D</b>, 'to accomplish, effect,' translates <i>efficiō, efficere, effēcī, effectus</i>." }, { meta: "Latin to English", stem: "Choose the best translation for <b>dēlectāre</b>.", options: ["to choose, select", "to delight, charm", "to loosen, untie", "to read, gather"], i: 1, explanation: "The correct answer is <b>B. to delight, charm</b>. <b>Dēlectāre</b> is the present active infinitive of <i>dēlectō</i>, meaning to delight or charm. <br>Distractor <b>A</b>, 'to choose, select,' translates <i>dēligere</i>, the present active infinitive of <i>dēligō, dēligere, dēlēgī, dēlēctus</i>. <br>Distractor <b>C</b>, 'to loosen, untie,' translates <i>dēligāre</i>, the present active infinitive of <i>dēligō, dēligāre, dēligāvī, dēligātus</i> (a different verb with the same root spelling in the infinitive). <br>Distractor <b>D</b>, 'to read, gather,' translates <i>legō, legere, lēgī, lēctus</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to fear</b> (with reverence or awe)", options: ["timēre", "metuere", "verērī", "formīdāre"], i: 2, explanation: "The verb <i>verērī</i> specifically conveys a respectful or reverential fear, often found in poetic or elevated prose contexts, implying awe or veneration. This distinguishes it from <i>timēre</i> (general fear), <i>metuere</i> (apprehension, dread), or <i>formīdāre</i> (terror, dread)." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>the open sea</b> (poetic)", options: ["mare, maris n.", "pontus, -ī m.", "pelagus, -ī n.", "aequor, aequoris n."], i: 2, explanation: "<i>Pelagus</i>, a Greek loanword, specifically denotes the open or high sea and is frequently used in poetry. While <i>pontus</i> (deep sea) and <i>aequor</i> (level surface of the sea) are also poetic terms for the sea, <i>pelagus</i> most precisely captures the nuance of 'open sea.' <i>Mare</i> is the general prose term for 'sea.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>intellect, reason, thought</b>", options: ["animus, -ī m.", "mēns, mentis f.", "cor, cordis n.", "ingenium, -ī n."], i: 1, explanation: "<i>Mēns</i> specifically refers to the intellectual faculty, reason, and thought. <i>Animus</i> is a broader term encompassing soul, spirit, courage, and mind in a more general sense, including emotions. <i>Cor</i> is the heart, sometimes used poetically for the seat of emotions or thought. <i>Ingenium</i> refers to natural disposition or talent." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to slaughter brutally</b>", options: ["necāre", "interficere", "caedere", "trucīdāre"], i: 3, explanation: "<i>Trucīdāre</i> emphasizes brutal, indiscriminate slaughter, often of many victims, conveying a sense of savagery. This is a stronger and more specific term than the more general 'to kill' verbs like <i>necāre</i> or <i>interficere</i>. <i>Caedere</i> means 'to cut down' or 'to slaughter' but lacks the explicit emphasis on brutality inherent in <i>trucīdāre</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>a star, constellation</b> (poetic)", options: ["stella, -ae f.", "sīdus, sīderis n.", "āstrum, -ī n.", "lūx, lūcis f."], i: 1, explanation: "While <i>stella</i> is the common word for 'star,' <i>sīdus</i> is frequently used in poetry to mean a star or, more commonly, a constellation or heavenly body. <i>Āstrum</i> is also a poetic term for 'star' or 'constellation' (a Greek loanword), but <i>sīdus</i> is often preferred for 'constellation' in classical Latin poetry. <i>Lūx</i> means 'light.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to utter, to speak</b> (poetic/archaic)", options: ["loquī", "dīcere", "fārī", "forās"], i: 2, explanation: "<i>Fārī</i> is an archaic and poetic deponent verb meaning 'to speak' or 'to utter,' frequently found in epic poetry (e.g., Vergil). <i>Loquī</i> and <i>dīcere</i> are common prose verbs for 'to speak' or 'to say.' <i>Forās</i> is an adverb meaning 'out of doors' and is a sound-alike distractor." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to be strong, to be well, to be able</b>", options: ["posse", "valēre", "potīrī", "licēre"], i: 1, explanation: "While <i>posse</i> means 'to be able' in terms of capacity, <i>valēre</i> encompasses 'to be strong,' 'to be healthy,' and by extension, 'to be able' or 'to be powerful,' especially in terms of influence or strength. This nuance is crucial for advanced texts. <i>Potīrī</i> means 'to get possession of,' and <i>licēre</i> is an impersonal verb meaning 'it is permitted.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to flash, to glitter, to quiver</b>", options: ["lucēre", "splendēre", "micāre", "fulgēre"], i: 2, explanation: "<i>Micāre</i> specifically conveys a rapid, intermittent flashing or glittering, and can also mean to quiver or tremble. This distinguishes it from the more steady shining of <i>lucēre</i> ('to shine, be light') or <i>splendēre</i> ('to shine, gleam, be bright'), and from the more forceful, often sudden flash of <i>fulgēre</i> ('to flash, gleam, lighten')." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to forget</b> (requiring the genitive case)", options: ["oblīvīscī", "neglegere", "praeterīre", "dēserere"], i: 0, explanation: "<i>Oblīvīscī</i> is a deponent verb meaning 'to forget' that typically takes the genitive case of the thing forgotten (or the accusative of a neuter pronoun). The other verbs listed—<i>neglegere</i> ('to neglect'), <i>praeterīre</i> ('to pass over'), and <i>dēserere</i> ('to abandon')—take the accusative case and have different meanings." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to compel, to force, to gather (by force)</b>", options: ["colligere", "congregāre", "cōgere", "coīre"], i: 2, explanation: "<i>Cōgere</i> has the dual meaning of 'to compel' or 'to force' and 'to gather' or 'to collect,' often with the implication of force or necessity. <i>Colligere</i> and <i>congregāre</i> are more neutral terms for gathering or assembling. <i>Coīre</i> means 'to come together' or 'to assemble' but is intransitive." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>a shade, a ghost, a phantom</b>", options: ["umbra, -ae f.", "tenebrae, -ārum f. pl.", "phāntasma, -atis n.", "lūx, lūcis f."], i: 0, explanation: "While <i>umbra</i> primarily means 'shade' or 'shadow,' it is very commonly used in poetry (e.g., Vergil's <i>Aeneid</i>) to refer to a ghost or the shade of the dead. <i>Tenebrae</i> means 'darkness' or 'gloom.' <i>Phāntasma</i> is a Greek loanword for 'phantom' or 'apparition,' but <i>umbra</i> is more idiomatic for the classical Latin concept of a 'shade' of the dead. <i>Lūx</i> means 'light' and is an antonym." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to command, to order</b> (especially military or official)", options: ["imperāre", "iubēre", "praecipere", "mandāre"], i: 0, explanation: "<i>Imperāre</i> specifically refers to giving commands, especially in a military or official capacity, and often takes the dative of the person commanded. <i>Iubēre</i> is a more general 'to order' or 'to bid.' <i>Praecipere</i> means 'to instruct' or 'to advise,' implying teaching or giving precepts. <i>Mandāre</i> means 'to entrust' or 'to commit,' implying giving a charge or commission." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>an old man</b>", options: ["vetus, veteris", "senex, senis m.", "grandis nātū", "antīquus, -a, -um"], i: 1, explanation: "<i>Senex</i> is the noun for 'an old man' (and can also be used as an adjective). <i>Vetus</i> and <i>antīquus</i> are adjectives meaning 'old' or 'ancient.' <i>Grandis nātū</i> is a descriptive phrase meaning 'advanced in age,' not a single noun for 'an old man.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to lament loudly, to wail</b>", options: ["flēre", "lacrimāre", "plōrāre", "gemere"], i: 2, explanation: "<i>Plōrāre</i> implies a loud, demonstrative lamentation or wailing, often publicly. <i>Flēre</i> is a more general term for weeping, which can be silent. <i>Lacrimāre</i> focuses on the act of shedding tears. <i>Gemere</i> means 'to groan' or 'to sigh,' expressing sorrow but not necessarily tears or loud wailing." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: <b>to seek, to ask, to inquire</b>", options: ["rogāre", "quaerere", "petere", "ōrāre"], i: 1, explanation: "<i>Quaerere</i> encompasses the ideas of seeking, searching for, and inquiring, often with a sense of investigation or pursuit. <i>Rogāre</i> is more about asking a direct question. <i>Petere</i> implies a request or aiming for something. <i>Ōrāre</i> means 'to plead,' 'to beg,' or 'to pray,' implying supplication." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>aequor</b>?", options: ["pelagus", "gurges", "fretum", "vadum"], i: 0, explanation: "Verba <i>aequor</i> et <i>pelagus</i> ambo mare apertum vel vastum significant. <i>Gurges</i> est vorāgō vel gurges aquae; <i>fretum</i> est angustiae maris; <i>vadum</i> est locus maris paucā altitūdine aquae." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>dēfetīscor</b>?", options: ["fatīscor", "labōrō", "langueō", "cōnsumō"], i: 0, explanation: "<i>Dēfetīscor</i> et <i>fatīscor</i> sunt verba paene synonyma, significantia 'fessus fiō' vel 'lābor'. <i>Labōrō</i> significat 'operor' vel 'fessus sum ex labōre'. <i>Langueō</i> significat 'languidus sum' vel 'dēbilitātem sentio'. <i>Cōnsumō</i> significat 'abūtor' vel 'dēleō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>obtestor</b>?", options: ["supplicō", "ōrō", "postulō", "cōnfiteor"], i: 0, explanation: "<i>Obtestor</i> significat 'implōrō' vel 'testem appellō'. <i>Supplicō</i> est 'hūmiter rogō' vel 'implōrō', praesertim ad deōs vel superiōrēs. <i>Ōrō</i> est 'rogō' vel 'precēs faciō', quod est latius. <i>Postulō</i> significat 'exigō' vel 'flagitō'. <i>Cōnfiteor</i> significat 'fateor' vel 'dēclārō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>prīscus</b>?", options: ["antīquus", "vetus", "longaevus", "obsolētus"], i: 0, explanation: "<i>Prīscus</i> et <i>antīquus</i> ambo significant 'vetustus' vel 'ab antīquō tempore oriēns', saepe cum nōtā venerātiōnis. <i>Vetus</i> est generalius 'senex' vel 'vetus'. <i>Longaevus</i> significat 'multōs annōs vīvēns'. <i>Obsolētus</i> significat 'exolētus' vel 'ūsū dēstitūtus'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>opācus</b>?", options: ["umbrōsus", "tenebrōsus", "obscūrus", "lūgubris"], i: 0, explanation: "<i>Opācus</i> et <i>umbrōsus</i> ambo ad umbram pertinent, significantia 'plēnus umbrae' vel 'umbrā tectus'. <i>Tenebrōsus</i> significat 'plēnus tenebrārum' vel 'caligōsus'. <i>Obscūrus</i> significat 'tenebrōsus' vel 'nōn clārus'. <i>Lūgubris</i> significat 'tristis' vel 'maestus'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>īnfestus</b>?", options: ["mināx", "hostīlis", "saevus", "inimīcus"], i: 0, explanation: "<i>Īnfestus</i> dēscribit rem vel personam quae perīculōsa est vel minātur. <i>Mināx</i> dīrēctē significat 'quī minātur'. <i>Hostīlis</i> ad hostem pertinet. <i>Saevus</i> significat 'crūdēlis' vel 'ferus'. <i>Inimīcus</i> significat 'nōn amīcus'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>lūgeō</b>?", options: ["maereō", "fleō", "queror", "dolōrō"], i: 0, explanation: "<i>Lūgeō</i> et <i>maereō</i> sunt synonyma dīrēcta, significantia 'doleō' vel 'tristis sum ob āmissum'. <i>Fleō</i> significat 'lacrimō'. <i>Queror</i> significat 'dēplōrō' vel 'murmurō'. <i>Dolōrō</i> significat 'dolōrem afferō' vel 'cruciō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>aevum</b>?", options: ["saeculum", "tempus", "diēs", "spatium"], i: 0, explanation: "<i>Aevum</i> et <i>saeculum</i> ambo 'aetātem' vel 'longum tempus' significant, saepe cum nōtā ērae vel generātiōnis. <i>Tempus</i> est generalius 'tempus'. <i>Diēs</i> est 'lūx' vel 'spatium vīgintī quattuor hōrārum'. <i>Spatium</i> est 'intervāllum' vel 'locus'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>pālor</b>?", options: ["vagor", "errō", "dēviō", "fluctuō"], i: 0, explanation: "<i>Pālor</i> et <i>vagor</i> sunt verba simillima, significantia 'hūc illūc ambulō' vel 'sine certō itinere eō'. <i>Errō</i> potest significāre 'vagor', sed etiam 'fallor' vel 'dēlinquō'. <i>Dēviō</i> significat 'ā viā recēdō'. <i>Fluctuō</i> significat 'undō' vel 'dubius sum'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cōnscendō</b>?", options: ["ascendō", "ēvehō", "subeō", "dēscendō"], i: 0, explanation: "<i>Cōnscendō</i> et <i>ascendō</i> sunt synonyma dīrēcta, significantia 'suprā eō' vel 'in nāvem eō'. <i>Ēvehō</i> significat 'sursum vehō'. <i>Subeō</i> significat 'subeō' vel 'accēdō'. <i>Dēscendō</i> est contrārium, 'dēorsum eō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>sōpiō</b>?", options: ["mulceō", "lēnīō", "placō", "obdormīscō"], i: 0, explanation: "<i>Sōpiō</i> significat 'in somnum dūcō' vel 'sōpiō'. <i>Mulceō</i> significat 'lēniō' vel 'blandior', et saepe ad somnum inducendum adhibētur. <i>Lēnīō</i> et <i>placō</i> sunt generalius 'mītigō' vel 'tranquillō'. <i>Obdormīscō</i> significat 'in somnum cadō' (intransitivum)." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>sīdō</b>?", options: ["cōnsīdō", "sedeō", "recumbō", "dēmittō"], i: 0, explanation: "<i>Sīdō</i> (poēticum vel archaicum) et <i>cōnsīdō</i> ambo significant 'sēdeō' vel 'cōnsīdō'. <i>Sedeō</i> dēscribit statum 'sedēre', nōn actiōnem 'cōnsīdere'. <i>Recumbō</i> significat 'iaceō' vel 'cubō'. <i>Dēmittō</i> significat 'dēmittō' vel 'dēiciō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>fāma</b>?", options: ["rumor", "glōria", "laus", "nōmen"], i: 0, explanation: "<i>Fāma</i> et <i>rumor</i> sunt synonyma dīrēcta, significantia 'vōx pūblica' vel 'nūntius'. Quamquam <i>fāma</i> etiam 'glōriam' significāre potest, <i>rumor</i> ad aspectum 'nūntiī' vel 'sermōnis pūblicī' propius accēdit. <i>Glōria</i> est 'clāritās' vel 'honōs'. <i>Laus</i> est 'praedicātiō'. <i>Nōmen</i> est 'appūllātiō' vel 'fāma'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>exuō</b>?", options: ["dētrahō", "spoliō", "induō", "vestīō"], i: 0, explanation: "<i>Exuō</i> significat 'dētrahō' vel 'vestem dēpōnō'. <i>Dētrahō</i> est proximum synonymum, significāns 'dētrahō' vel 'tollō'. <i>Spoliō</i> significat 'praedō' vel 'vestem auferō', saepe cum nōtā vīolentiae vel rapinārum. <i>Induō</i> et <i>vestīō</i> sunt antonyma, significantia 'vestem pōnō' vel 'vestem dō'." }, { meta: "Synonyms", stem: "Quod verbum est proximum in sententiā verbō <b>cūnctor</b>?", options: ["moror", "haesitō", "differō", "tardō"], i: 0, explanation: "<i>Cūnctor</i> et <i>moror</i> sunt verba simillima, significantia 'mora facio' vel 'tardō'. <i>Haesitō</i> significat 'dubius sum' vel 'hēsito', quod est mentis actiō. <i>Differō</i> significat 'prōrogō' vel 'distribuō'. <i>Tardō</i> significat 'lentum faciō' vel 'impediō'." }, { meta: "Antonyms", stem: "Quod est contrārium <u>aequāre</u>?", options: ["<b>distinguere</b>", "<b>cōnfirmāre</b>", "<b>temperāre</b>", "<b>comprimere</b>"], i: 0, explanation: "The verb <b>aequāre</b> means 'to make equal, to level'. Its direct antonym is <b>distinguere</b>, which means 'to distinguish, to separate, to make different or unequal'. Options B, C, and D refer to strengthening, regulating, or restraining, which are not direct opposites of making equal." }, { meta: "Antonyms", stem: "Quod est contrārium <u>obsequiō</u>?", options: ["<b>contumēlia</b>", "<b>indulgentia</b>", "<b>cōnsēnsus</b>", "<b>servitūs</b>"], i: 0, explanation: "<b>Obsequium</b> denotes 'compliance, deference, obedience'. The most fitting antonym is <b>contumēlia</b>, meaning 'insult, affront, defiance, humiliation'. While related, <b>indulgentia</b> (indulgence), <b>cōnsēnsus</b> (agreement), and <b>servitūs</b> (slavery) do not capture the direct opposition of respectful deference versus defiant insult." }, { meta: "Antonyms", stem: "Quod est contrārium <u>mētīrī</u>?", options: ["<b>īnfinīre</b>", "<b>cōnstituere</b>", "<b>dēfīnīre</b>", "<b>coercēre</b>"], i: 0, explanation: "<b>Mētīrī</b> means 'to measure, to limit, to traverse' (often implying a boundary or extent). Its antonym, particularly in a poetic or philosophical sense, is <b>īnfinīre</b>, 'to make endless, to leave unbounded'. <b>Dēfīnīre</b> (to define) can imply setting limits, making it a tricky distractor, but it's not the opposite of the act of measuring or limiting. <b>Cōnstituere</b> (to establish) and <b>coercēre</b> (to restrain) are not direct antonyms." }, { meta: "Antonyms", stem: "Quod est contrārium <u>cōnsummāre</u>?", options: ["<b>īnstituere</b>", "<b>dēstituere</b>", "<b>intermittere</b>", "<b>corrumpere</b>"], i: 0, explanation: "<b>Cōnsummāre</b> means 'to complete, to finish, to bring to perfection'. The most direct antonym is <b>īnstituere</b>, 'to begin, to establish, to undertake'. <b>Dēstituere</b> (to abandon) and <b>intermittere</b> (to interrupt) imply stopping, but not the opposite action of initiating. <b>Corrumpere</b> (to corrupt) is unrelated." }, { meta: "Antonyms", stem: "Quod est contrārium <u>fēlīcitātī</u>?", options: ["<b>calamitās</b>", "<b>miseria</b>", "<b>dolor</b>", "<b>trīstitia</b>"], i: 0, explanation: "<b>Fēlīcitās</b> refers to 'happiness, good fortune, success'. Its most comprehensive antonym, especially at an advanced level, is <b>calamitās</b>, meaning 'disaster, misfortune, ruin'. While <b>miseria</b> (misery), <b>dolor</b> (pain), and <b>trīstitia</b> (sadness) describe states of unhappiness, <b>calamitās</b> represents the broader concept of adverse fortune or catastrophic event, directly opposing the idea of good fortune and success." }, { meta: "Antonyms", stem: "Quod est contrārium <u>arduō</u>?", options: ["<b>plānus</b>", "<b>lēnis</b>", "<b>mollis</b>", "<b>humilis</b>"], i: 0, explanation: "The adjective <b>arduus</b> means 'steep, difficult, arduous'. The best antonym is <b>plānus</b>, which means 'flat, level' (opposing 'steep') and also 'easy, clear' (opposing 'difficult'). <b>Lēnis</b> (gentle), <b>mollis</b> (soft), and <b>humilis</b> (lowly) are not direct antonyms for both senses of <b>arduus</b>." }, { meta: "Antonyms", stem: "Quod est contrārium <u>vīlī</u>?", options: ["<b>pretiōsus</b>", "<b>nōbilis</b>", "<b>magnificus</b>", "<b>excellēns</b>"], i: 0, explanation: "<b>Vīlis</b> means 'cheap, worthless, common'. The most direct antonym is <b>pretiōsus</b>, meaning 'precious, valuable, expensive'. While <b>nōbilis</b> (noble), <b>magnificus</b> (magnificent), and <b>excellēns</b> (excellent) describe high quality or status, they do not directly oppose the concept of 'worthless' or 'cheap' in the same way <b>pretiōsus</b> does." }, { meta: "Antonyms", stem: "Quod est contrārium <u>cōnfertō</u>?", options: ["<b>rārēfactus</b>", "<b>vacuus</b>", "<b>solūtus</b>", "<b>apertus</b>"], i: 0, explanation: "<b>Cōnfertus</b> means 'crowded, dense, packed close together'. The precise antonym is <b>rārēfactus</b>, meaning 'thinned out, made rare, scattered'. <b>Vacuus</b> (empty) is too strong, implying a complete absence rather than a thinning. <b>Solūtus</b> (loose) and <b>apertus</b> (open) do not directly relate to density." }, { meta: "Antonyms", stem: "Quod est contrārium <u>obdūcere</u>?", options: ["<b>aperīre</b>", "<b>prōferre</b>", "<b>ēdūcere</b>", "<b>patefacere</b>"], i: 0, explanation: "<b>Obdūcere</b> means 'to draw over, to cover, to obscure'. Its direct antonym is <b>aperīre</b>, 'to open, to uncover, to reveal'. <b>Patefacere</b> (to lay open, reveal) is a strong synonym for <b>aperīre</b> and thus a plausible distractor, but <b>aperīre</b> is more common as a direct opposite of covering. <b>Prōferre</b> (to bring forth) and <b>ēdūcere</b> (to lead out) are not direct antonyms." }, { meta: "Antonyms", stem: "Quod est contrārium <u>cōnfirmāre</u>?", options: ["<b>īnvalidāre</b>", "<b>dēstruere</b>", "<b>dissolvere</b>", "<b>frangere</b>"], i: 0, explanation: "<b>Cōnfirmāre</b> means 'to strengthen, to confirm, to establish'. The most direct antonym is <b>īnvalidāre</b>, 'to weaken, to invalidate, to render powerless'. While <b>dēstruere</b> (to destroy), <b>dissolvere</b> (to dissolve), and <b>frangere</b> (to break) imply destruction or breaking apart, they are stronger and less precise opposites of 'strengthen' or 'confirm' than 'weaken' or 'invalidate'." }, { meta: "Antonyms", stem: "Quod est contrārium <u>pervicācī</u>?", options: ["<b>obsequēns</b>", "<b>mītis</b>", "<b>modestus</b>", "<b>patiēns</b>"], i: 0, explanation: "<b>Pervicāx</b> means 'stubborn, obstinate, persistent (in a negative sense)'. The most fitting antonym is <b>obsequēns</b>, meaning 'compliant, obedient, yielding'. While <b>mītis</b> (mild) and <b>modestus</b> (moderate) describe temperament, and <b>patiēns</b> (patient) can sometimes imply endurance akin to stubbornness, none directly oppose the 'obstinate' aspect of <b>pervicāx</b> as clearly as <b>obsequēns</b>." }, { meta: "Antonyms", stem: "Quod est contrārium <u>effulgēre</u>?", options: ["<b>obscūrāre</b>", "<b>dēficere</b>", "<b>ēvānēscere</b>", "<b>cōnfūndere</b>"], i: 0, explanation: "<b>Effulgēre</b> means 'to shine forth, to gleam, to be brilliant'. Its direct antonym is <b>obscūrāre</b>, 'to darken, to obscure, to dim'. <b>Dēficere</b> (to fail, to cease), <b>ēvānēscere</b> (to vanish), and <b>cōnfūndere</b> (to confuse) are not direct opposites of shining or being brilliant." }, { meta: "Antonyms", stem: "Quod est contrārium <u>saturō</u>?", options: ["<b>ēsurīns</b>", "<b>pauper</b>", "<b>macilentus</b>", "<b>dēficiēns</b>"], i: 0, explanation: "The adjective <b>satur</b> means 'full, sated, rich'. Its specific antonym, especially concerning food or fullness, is <b>ēsurīns</b>, 'hungry'. While <b>pauper</b> (poor) is an antonym for 'rich' in an economic sense, and <b>macilentus</b> (thin) or <b>dēficiēns</b> (lacking) relate to physical state, <b>ēsurīns</b> is the precise opposite of 'sated'." }, { meta: "Antonyms", stem: "Quod est contrārium <u>sūdōrī</u>?", options: ["<b>ōtium</b>", "<b>requiēs</b>", "<b>frīgus</b>", "<b>voluptās</b>"], i: 0, explanation: "<b>Sūdor</b> literally means 'sweat', but often metaphorically signifies 'toil, exertion, hard work'. The classic antonym for 'toil' or 'exertion' is <b>ōtium</b>, which means 'leisure, idleness, ease'. While <b>requiēs</b> (rest) is related, <b>ōtium</b> better captures the broader state of freedom from labor. <b>Frīgus</b> (cold) is a physical opposite of sweat, not toil, and <b>voluptās</b> (pleasure) is not a direct antonym for toil." }, { meta: "Antonyms", stem: "Quod est contrārium <u>perfidiae</u>?", options: ["<b>fidēs</b>", "<b>honōr</b>", "<b>probitās</b>", "<b>cōnstantia</b>"], i: 0, explanation: "<b>Perfidia</b> means 'treachery, perfidy, faithlessness'. Its direct and strongest antonym is <b>fidēs</b>, meaning 'faith, loyalty, trust, trustworthiness'. While <b>honōr</b> (honor), <b>probitās</b> (honesty), and <b>cōnstantia</b> (constancy) are related virtues, <b>fidēs</b> specifically captures the opposite of faithlessness and betrayal." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["doleō", "lūgeō", "queror", "fleō"], i: 0, explanation: "The core group of words <b>lūgeō</b>, <b>queror</b>, and <b>fleō</b> all describe outward expressions of sorrow or lamentation: <b>lūgeō</b> (to mourn, lament, often publicly), <b>queror</b> (to complain, lament, bewail, often with words), and <b>fleō</b> (to weep, cry, expressing sorrow with tears). <b>Doleō</b>, however, means 'to feel pain, suffer, grieve' and primarily refers to the internal sensation of pain or sorrow, not necessarily its outward manifestation. Thus, <b>doleō</b> is the outlier." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vinciō", "ligō", "impediō", "nectō"], i: 2, explanation: "The words <b>vinciō</b>, <b>ligō</b>, and <b>nectō</b> all pertain to the act of binding or tying: <b>vinciō</b> (to bind, tie, fetter, often with chains), <b>ligō</b> (to bind, tie, a general term), and <b>nectō</b> (to bind, tie, interweave, connect, often more intricately). <b>Impediō</b>, on the other hand, means 'to hinder, impede, entangle.' While entanglement can involve binding, its primary meaning is to obstruct or prevent progress, making it distinct from the direct act of tying." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["fulgeō", "micō", "splendeō", "coruscō"], i: 2, explanation: "The words <b>fulgeō</b>, <b>micō</b>, and <b>coruscō</b> often describe a flashing, glittering, or quivering light, typically intermittent or tremulous, and are frequently found in poetic contexts: <b>fulgeō</b> (to flash, gleam, glitter), <b>micō</b> (to flash, glitter, quiver), and <b>coruscō</b> (to flash, glitter, vibrate, wave, implying a shimmering light). <b>Splendeō</b>, however, means 'to shine, be bright, gleam' and usually refers to a steady, brilliant, or magnificent light. The transient nature of the light described by the other three distinguishes them from <b>splendeō</b>." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["saeviō", "īrāscor", "fureō", "bacchor"], i: 1, explanation: "The verbs <b>saeviō</b>, <b>fureō</b>, and <b>bacchor</b> all denote a state of intense, often uncontrolled, rage or frenzy: <b>saeviō</b> (to rage, be fierce, be cruel, often violently), <b>fureō</b> (to rage, be mad, rave, implying mental derangement or uncontrolled passion), and <b>bacchor</b> (to rage, revel like a Bacchante, rave, a poetic term for wild, frenzied behavior). <b>Īrāscor</b>, however, means 'to grow angry, be angry' and describes the onset or state of anger, which is a less intense and less frenzied emotion than the furious rage implied by the other three." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vetus", "antīquus", "senex", "prīscus"], i: 2, explanation: "The adjectives <b>vetus</b>, <b>antīquus</b>, and <b>prīscus</b> all describe something as old or ancient: <b>vetus</b> (old, ancient, of long standing), <b>antīquus</b> (ancient, old-fashioned, venerable), and <b>prīscus</b> (ancient, olden, primitive, often with a sense of venerable antiquity, frequently poetic or archaic). <b>Senex</b>, while it can function as an adjective meaning 'old,' primarily refers to an 'old man' (or woman) as a noun, or describes a person as old. Its focus is on the age of living beings, rather than the general antiquity or age of objects, customs, or eras, which is the broader sense shared by the other three." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["cupiō", "dēsīderō", "appetō", "gestiō"], i: 2, explanation: "The verbs <b>cupiō</b>, <b>dēsīderō</b>, and <b>gestiō</b> all express various forms of desire or longing: <b>cupiō</b> (to desire, long for, wish for), <b>dēsīderō</b> (to long for, miss, regret the absence of, implying yearning), and <b>gestiō</b> (to desire eagerly, be eager, exult, often with outward signs of eagerness). <b>Appetō</b>, however, means 'to strive for, seek, desire (in the sense of reaching out for), or attack.' While it can involve desire, its core meaning often implies an active pursuit or even aggression, which distinguishes it from the more internal or expressive forms of longing represented by the other three." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["moneō", "admoneō", "hortor", "praecipiō"], i: 2, explanation: "The verbs <b>moneō</b>, <b>admoneō</b>, and <b>praecipiō</b> all relate to giving advice, warning, or instruction: <b>moneō</b> (to warn, advise, remind), <b>admoneō</b> (to warn, remind, advise, often with a sense of gentle reproof), and <b>praecipiō</b> (to instruct, order, advise, implying the giving of rules or precepts). <b>Hortor</b>, on the other hand, means 'to urge, encourage, exhort.' While related to influencing someone's actions, <b>hortor</b> emphasizes persuasion and motivation rather than warning or formal instruction." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["vacuus", "inānis", "dēsertus", "cāvus"], i: 2, explanation: "The adjectives <b>vacuus</b>, <b>inānis</b>, and <b>cāvus</b> all describe a state of being empty, void, or lacking contents: <b>vacuus</b> (empty, void, free from), <b>inānis</b> (empty, void, vain, useless, meaningless), and <b>cāvus</b> (hollow, excavated, concave). <b>Dēsertus</b>, however, means 'deserted, desolate, abandoned.' While a deserted place might be empty, <b>dēsertus</b> describes a state resulting from abandonment or desolation, not the inherent quality of being without contents or being hollow. It implies a previous presence that is now gone." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["laudō", "praedicō", "veneror", "extollō"], i: 2, explanation: "The verbs <b>laudō</b>, <b>praedicō</b>, and <b>extollō</b> all refer to various forms of praise or commendation: <b>laudō</b> (to praise, commend), <b>praedicō</b> (to proclaim, declare, praise, boast, often publicly), and <b>extollō</b> (to lift up, raise, extol, praise highly, often with a sense of exaggeration). <b>Veneror</b>, however, means 'to worship, revere, adore, supplicate.' While reverence can be a form of high regard, <b>veneror</b> implies a much deeper, often sacred or profound respect, bordering on religious adoration, which distinguishes it from general praise or commendation." }, { meta: "Odd One Out", stem: "Which word does NOT belong?", options: ["cēlō", "occultō", "lateō", "abdō"], i: 2, explanation: "The verbs <b>cēlō</b>, <b>occultō</b>, and <b>abdō</b> are all transitive verbs meaning 'to hide or conceal something': <b>cēlō</b> (to hide, conceal), <b>occultō</b> (to hide, conceal, keep secret, often implying deliberate secrecy), and <b>abdō</b> (to hide, put away, remove, conceal, often implying putting something in a secret or remote place). <b>Lateō</b>, on the other hand, is an intransitive verb meaning 'to lie hidden, be concealed, escape notice.' It describes the state of being hidden rather than the act of hiding something, making it the outlier." }, { meta: "Analogies", stem: "<i>prōlēs</i> : <i>genus</i> :: <i>sēmen</i> : X", options: ["<i>stirps</i>", "<i>rādīx</i>", "<i>fētus</i>", "<i>frūx</i>"], i: 0, explanation: "The relationship is 'specific instance or product' to 'general category or source'. <i>Prōlēs</i> (offspring) is a specific instance or product of a <i>genus</i> (race, kind). Similarly, <i>sēmen</i> (seed) is the origin or source from which a <i>stirps</i> (stock, lineage, root) grows or is derived. Options B, C, and D are related to plant growth or progeny but do not represent the same logical relationship of general category/source to specific origin as <i>stirps</i> does for <i>sēmen</i>." }, { meta: "Analogies", stem: "<i>aeternum</i> : <i>breviter</i> :: <i>saepe</i> : X", options: ["<i>rārō</i>", "<i>numquam</i>", "<i>nūper</i>", "<i>aliquandō</i>"], i: 0, explanation: "The relationship is 'adverbial antonym' based on duration or frequency. <i>Aeternum</i> (forever) is the opposite of <i>breviter</i> (briefly). Following this pattern, <i>saepe</i> (often) finds its direct opposite in <i>rārō</i> (rarely). Option B, <i>numquam</i> (never), is the opposite of <i>semper</i> (always), which is too absolute for <i>saepe</i>. Option C, <i>nūper</i> (recently), refers to a point in time, not frequency. Option D, <i>aliquandō</i> (sometimes), is a less direct antonym for <i>saepe</i> than <i>rārō</i>, representing a neutral frequency rather than infrequency." }, { meta: "Analogies", stem: "<i>ēbrius</i> : <i>ēbrietās</i> :: <i>sōbrius</i> : X", options: ["<i>sōbrietās</i>", "<i>temperantia</i>", "<i>vīnum</i>", "<i>abstinentia</i>"], i: 0, explanation: "The relationship is 'adjective' to its corresponding 'abstract noun' denoting a state or quality. <i>Ēbrius</i> (drunk) corresponds to <i>ēbrietās</i> (drunkenness). Similarly, <i>sōbrius</i> (sober) corresponds to <i>sōbrietās</i> (sobriety). Options B, C, and D are related concepts but are not the direct noun form representing the state of being <i>sōbrius</i>. <i>Temperantia</i> (self-control) and <i>abstinentia</i> (abstinence) are virtues associated with sobriety, while <i>vīnum</i> (wine) is the cause of drunkenness." }, { meta: "Analogies", stem: "<i>obruō</i> : <i>obrutus</i> :: <i>percellō</i> : X", options: ["<i>perculsus</i>", "<i>percussus</i>", "<i>percellēns</i>", "<i>perculī</i>"], i: 0, explanation: "The relationship is 'verb (infinitive)' to its 'perfect passive participle'. <i>Obruō</i> (to overwhelm, bury) has the perfect passive participle <i>obrutus</i> (overwhelmed, buried). Following this pattern, <i>percellō</i> (to strike down, smite, dismay) has the perfect passive participle <i>perculsus</i> (struck down, dismayed). Option B, <i>percussus</i>, is the perfect passive participle of a different verb, <i>percutiō</i> (to strike, beat). Option C, <i>percellēns</i>, is the present active participle. Option D, <i>perculī</i>, is the first person singular perfect active indicative form of <i>percellō</i>." }, { meta: "Analogies", stem: "<i>aequor</i> : <i>mare</i> :: <i>pontus</i> : X", options: ["<i>mare</i>", "<i>ōceanus</i>", "<i>fluctus</i>", "<i>rādīx</i>"], i: 0, explanation: "The relationship is 'poetic term' to its 'more common synonym'. <i>Aequor</i> (level surface, sea) is a poetic term often used for <i>mare</i> (sea). Similarly, <i>pontus</i> (sea, deep) is another poetic term for <i>mare</i>. Option B, <i>ōceanus</i>, is a broader geographical term. Option C, <i>fluctus</i> (wave), is a part of the sea. Option D, <i>rādīx</i> (root), is unrelated." }, { meta: "Analogies", stem: "<i>cōnsulō</i> : <i>cōnsilium</i> :: <i>praestō</i> : X", options: ["<i>praestantia</i>", "<i>praestīgium</i>", "<i>praestō</i>", "<i>praesidium</i>"], i: 0, explanation: "The relationship is 'verb' to a closely related 'noun' representing an action, result, or quality. <i>Cōnsulō</i> (to consult, deliberate) is related to <i>cōnsilium</i> (plan, counsel, advice). Likewise, <i>praestō</i> (to stand out, excel, furnish) is related to <i>praestantia</i> (excellence, superiority). Option B, <i>praestīgium</i>, means 'trick' or 'illusion'. Option C, <i>praestō</i>, is the verb itself or an adverb meaning 'at hand'. Option D, <i>praesidium</i> (protection, guard), is derived from a different verb, <i>praesum</i>." }, { meta: "Analogies", stem: "<i>obsequor</i> : <i>repugnō</i> :: <i>fastīdiō</i> : X", options: ["<i>appetō</i>", "<i>dēspiciō</i>", "<i>contemnō</i>", "<i>admiror</i>"], i: 0, explanation: "The relationship is 'verb' to its 'antonym verb'. <i>Obsequor</i> (to comply with, obey) is the antonym of <i>repugnō</i> (to resist, oppose). Following this pattern, <i>fastīdiō</i> (to disdain, scorn, be disgusted by) finds its antonym in <i>appetō</i> (to seek, desire, strive after). Options B (<i>dēspiciō</i>) and C (<i>contemnō</i>) are synonyms of <i>fastīdiō</i>. Option D, <i>admiror</i> (to wonder at, admire), is related but <i>appetō</i> provides a more direct opposition to 'disdain' by signifying 'desire' or 'seeking'." }, { meta: "Analogies", stem: "<i>cōnfīnis</i> : <i>fīnis</i> :: <i>sēmivir</i> : X", options: ["<i>vir</i>", "<i>mulier</i>", "<i>homō</i>", "<i>sexus</i>"], i: 0, explanation: "The relationship is 'adjective (derived from or related to)' to its 'base noun'. <i>Cōnfīnis</i> (bordering on, contiguous) is derived from or closely related to <i>fīnis</i> (boundary, end). Similarly, <i>sēmivir</i> (half-man, effeminate) is derived from or related to <i>vir</i> (man). Option B, <i>mulier</i> (woman), refers to the implied 'half' aspect but is not the base noun. Option C, <i>homō</i> (human being), is too general. Option D, <i>sexus</i> (sex, gender), is too abstract." }, { meta: "Analogies", stem: "<i>ēnsis</i> : <i>gladius</i> :: <i>aethēr</i> : X", options: ["<i>caelum</i>", "<i>āēr</i>", "<i>nūbēs</i>", "<i>polus</i>"], i: 0, explanation: "The relationship is 'poetic term' to its 'more common synonym'. <i>Ēnsis</i> (sword) is a poetic synonym for <i>gladius</i> (sword). Likewise, <i>aethēr</i> (upper air, sky, heaven) is a poetic synonym for <i>caelum</i> (sky, heaven). Option B, <i>āēr</i>, refers to the lower atmosphere, not the upper air or heaven. Option C, <i>nūbēs</i> (cloud), is a component of the sky. Option D, <i>polus</i> (pole, sky), is also a poetic term, but <i>caelum</i> is the more common, prosaic equivalent." }, { meta: "Analogies", stem: "<i>cōnsuētūdō</i> : <i>cōnsuēscō</i> :: <i>oblīviō</i> : X", options: ["<i>oblivīscor</i>", "<i>memorō</i>", "<i>memoria</i>", "<i>oblivium</i>"], i: 0, explanation: "The relationship is 'noun (state or habit)' to its 'related verb (to become accustomed to or to perform the action)'. <i>Cōnsuētūdō</i> (custom, habit) is related to <i>cōnsuēscō</i> (to become accustomed, habituated). Similarly, <i>oblīviō</i> (forgetfulness, oblivion) is related to <i>oblivīscor</i> (to forget, be unmindful of). Option B, <i>memorō</i> (to remind, mention), is an antonym verb. Option C, <i>memoria</i> (memory), is an antonym noun. Option D, <i>oblivium</i>, is a noun synonymous with <i>oblīviō</i>, but the pattern requires a verb." }, { meta: "Fill-in-the-Blank", stem: "Rōma, quondam glōriōsa, nunc magnā ____ dēformāta est.", options: ["labē", "lāpsū", "lābōre", "lūstrō"], i: 0, explanation: "The sentence means: \"Rome, once glorious, is now disfigured by a great ____.\" The context \"dēformāta est\" (is disfigured) strongly implies something negative like a stain, disgrace, or ruin. <br>A. <b>labē</b> (ablative of <i>labēs, labis</i> f.) means 'stain, disgrace, ruin, fall'. This fits perfectly with the idea of Rome being disfigured. <br>B. <b>lāpsū</b> (ablative of <i>lāpsus, -ūs</i> m.) means 'a slipping, fall, error'. While related to 'fall', <i>labēs</i> often carries a stronger connotation of moral stain or ruin, which aligns better with 'dēformāta'. <br>C. <b>lābōre</b> (ablative of <i>labor, labōris</i> m.) means 'toil, effort, hardship'. This does not fit the semantic context of being disfigured. <br>D. <b>lūstrō</b> (ablative of <i>lūstrum, -ī</i> n.) means 'a purificatory sacrifice, a period of five years'. This is semantically unrelated to the context." }, { meta: "Fill-in-the-Blank", stem: "Tyrannus nūllum dissentientium verbum tolerābat, sed sōlum ____ ā subditis postulābat.", options: ["obsequium", "arbitrium", "imperium", "fastīgium"], i: 0, explanation: "The sentence means: \"The tyrant tolerated no word of dissent, but demanded only ____ from his subjects.\" The phrase \"nūllum dissentientium verbum tolerābat\" (tolerated no word of dissent) indicates the tyrant desired complete compliance or flattery. <br>A. <b>obsequium</b> (<i>obsequium, -ī</i> n.) means 'compliance, deference, obedience, flattery'. This is the direct opposite of dissent and fits the context perfectly. <br>B. <b>arbitrium</b> (<i>arbitrium, -ī</i> n.) means 'judgment, decision, power'. While a tyrant has power, he is demanding a specific behavior (compliance), not just 'power' in general from his subjects. <br>C. <b>imperium</b> (<i>imperium, -ī</i> n.) means 'command, power, empire'. Similar to 'arbitrium', this is too broad and doesn't capture the specific behavioral demand. <br>D. <b>fastīgium</b> (<i>fastīgium, -ī</i> n.) means 'summit, peak, dignity'. This is semantically unrelated to the context of a tyrant demanding behavior from subjects." }, { meta: "Fill-in-the-Blank", stem: "Hostēs ā nostrīs mīlitibus tam vehementer ____ sunt ut nūllus superfuerit.", options: ["prōflīgātī", "obtruncātī", "dēpellī", "exstirpātī"], i: 0, explanation: "The sentence means: \"The enemies were so vehemently ____ by our soldiers that no one survived.\" The phrase \"ut nūllus superfuerit\" (that no one survived) indicates utter defeat or destruction in battle. <br>A. <b>prōflīgātī</b> (perfect passive participle of <i>prōflīgō, -āre</i>) means 'struck down, overthrown, ruined, utterly defeated'. This precisely conveys the complete destruction of the enemy. <br>B. <b>obtruncātī</b> (perfect passive participle of <i>obtruncō, -āre</i>) means 'cut down, slaughter'. While very close in meaning, <i>prōflīgō</i> often implies a more comprehensive overthrow or ruin, especially in a military context for utter defeat, fitting the 'no one survived' clause more strongly. <br>C. <b>dēpellī</b> (present passive infinitive of <i>dēpellō, dēpellere</i>) means 'to be driven away, repelled'. This is not strong enough to imply that no one survived. <br>D. <b>exstirpātī</b> (perfect passive participle of <i>exstirpō, -āre</i>) means 'uprooted, eradicated'. This term implies a complete removal from existence, often of things like plants or evils, but less specifically about a military defeat of an army than <i>prōflīgō</i>." }, { meta: "Fill-in-the-Blank", stem: "Mīles, post multōs annōs bellōrum, tandem stīpendia ____ domum rediit.", options: ["ēmerita", "functus", "perfēcta", "absolūta"], i: 0, explanation: "The sentence means: \"The soldier, after many years of wars, finally returned home, having ____ his service.\" The context of a soldier returning home after wars implies completing or serving out his military duty. <br>A. <b>ēmerita</b> (neuter plural perfect passive participle of <i>ēmereō, ēmerēre, ēmeruī, ēmeritum</i>) means 'having served out one's time, discharged, veteran'. It specifically refers to completing military service, often used with <i>stīpendia</i> (military pay/service). This is the most precise fit. <br>B. <b>functus</b> (perfect active participle of <i>fungor, fungī</i>) means 'having performed, discharged'. While semantically related, <i>fungor</i> typically takes an ablative object (e.g., <i>mūnere functus</i>, 'having discharged a duty'), and is less idiomatic with <i>stīpendia</i> in this specific sense of 'serving out' military time. <br>C. <b>perfēcta</b> (neuter plural perfect passive participle of <i>perficiō, perficere</i>) means 'completed, finished'. This is a general term for completion and lacks the specific military connotation of <i>ēmeritus</i>. <br>D. <b>absolūta</b> (neuter plural perfect passive participle of <i>absolvō, absolvere</i>) means 'finished, completed, released'. Similar to 'perfēcta', it is too general and does not carry the specific meaning of military discharge." }, { meta: "Fill-in-the-Blank", stem: "Consilium, quamquam bonum, ____ erat; iam enim hostēs urbem cēperant.", options: ["sērum", "lentum", "tardum", "dēfessum"], i: 0, explanation: "The sentence means: \"The plan, although good, was ____; for the enemies had already captured the city.\" The clause \"iam enim hostēs urbem cēperant\" (for the enemies had already captured the city) indicates that the plan was implemented too late. <br>A. <b>sērum</b> (neuter nominative singular of <i>sērus, -a, -um</i>) means 'late, slow, tardy; too late'. This perfectly captures the idea that the plan's goodness was nullified by its tardiness. <br>B. <b>lentum</b> (neuter nominative singular of <i>lentus, -a, -um</i>) means 'slow, sluggish, pliant'. While 'slow' is related, <i>sērus</i> more specifically conveys the nuance of 'too late' in this context. <br>C. <b>tardum</b> (neuter nominative singular of <i>tardus, -a, -um</i>) means 'slow, sluggish, late'. Similar to 'lentum', it describes a characteristic of being slow, but <i>sērus</i> is often preferred to emphasize the consequence of being 'too late'. <br>D. <b>dēfessum</b> (neuter nominative singular of <i>dēfessus, -a, -um</i>) means 'tired, weary'. This is semantically unrelated to the timing of a plan." }, { meta: "Fill-in-the-Blank", stem: "Fūr, timōre perculsus, in spēluncā obscūrā ____ ut poenam effugeret.", options: ["dēlituit", "latuit", "abdidit", "condidit"], i: 0, explanation: "The sentence means: \"The thief, struck by fear, ____ in a dark cave to escape punishment.\" The context of a thief, fear, a dark cave, and escaping punishment strongly suggests the act of going into hiding. <br>A. <b>dēlituit</b> (perfect active indicative of <i>dēlitēscō, dēlitēscere, dēlitī</i>) means 'to hide oneself, lie hidden, lurk'. <i>Dēlitēscō</i> often implies the *act* of going into hiding, especially with a sense of urgency or suddenness, which fits \"timōre perculsus\" (struck by fear). <br>B. <b>latuit</b> (perfect active indicative of <i>lateō, latēre, latuī</i>) means 'to lie hidden'. While very similar, <i>lateō</i> emphasizes the state of being hidden, whereas <i>dēlitēscō</i> emphasizes the action of getting into hiding. The context of the thief *going* into the cave to escape punishment makes <i>dēlituit</i> a slightly better fit. <br>C. <b>abdidit</b> (perfect active indicative of <i>abdō, abdere, abdidī, abditum</i>) means 'to hide, put away'. This verb is transitive and would require an object (e.g., <i>sē abdidit</i>, 'he hid himself'). Without 'sē', it is grammatically incorrect here. <br>D. <b>condidit</b> (perfect active indicative of <i>condō, condere, condidī, conditum</i>) means 'to found, build; to hide, store'. This verb is also transitive and would require an object, making it grammatically unsuitable in this context without a reflexive pronoun." }, { meta: "Fill-in-the-Blank", stem: "Hic morbus, quamquam initiō levis vidēbātur, mox ____ factus est.", options: ["exitiābilis", "pernīciōsus", "pestifer", "noxius"], i: 0, explanation: "The sentence means: \"This disease, although it seemed slight at first, soon became ____.\" The progression from \"levis\" (slight) to something severe implies a fatal or deadly outcome. <br>A. <b>exitiābilis</b> (<i>exitiābilis, -e</i>) means 'destructive, fatal, deadly'. This accurately describes a disease that becomes severe and life-threatening. <br>B. <b>pernīciōsus</b> (<i>pernīciōsus, -a, -um</i>) means 'destructive, ruinous, fatal'. This is very close, but <i>exitiābilis</i> often emphasizes the *fatal* aspect more directly and strongly, which fits the escalation from 'slight' to a severe disease. <br>C. <b>pestifer</b> (<i>pestifer, pestifera, pestiferum</i>) means 'plague-bearing, noxious, destructive'. This implies carrying disease or being harmful, but not necessarily that the disease itself is fatal in the same direct way as <i>exitiābilis</i>. <br>D. <b>noxius</b> (<i>noxius, -a, -um</i>) means 'harmful, injurious'. This is too general and does not convey the strong sense of 'fatal' or 'deadly' implied by the context." }, { meta: "Fill-in-the-Blank", stem: "Spēs eius, cum omnia adversa essent, paulatim ____.", options: ["dēfēcit", "interiit", "ēvānuit", "concidit"], i: 0, explanation: "The sentence means: \"His hope, when all things were adverse, gradually ____.\" The context \"omnia adversa essent\" (all things were adverse) implies that hope would diminish, fail, or give out. <br>A. <b>dēfēcit</b> (perfect active indicative of <i>dēficiō, dēficere, dēfēcī, dēfectum</i>) means 'to fail, desert, revolt, be wanting, give out'. This is a perfect fit for hope gradually diminishing or failing. <br>B. <b>interiit</b> (perfect active indicative of <i>intereō, interīre, interiī, interitum</i>) means 'to perish, die, be destroyed'. This is too strong for 'hope'; hope typically fails or fades, rather than 'dies' in a literal sense. <br>C. <b>ēvānuit</b> (perfect active indicative of <i>ēvānēscō, ēvānēscere, ēvānuī</i>) means 'to vanish, disappear, fade away'. While similar, <i>dēficiō</i> implies a more active failing or giving out due to exhaustion or lack, which fits the 'adverse circumstances' better than simply 'vanishing'. <br>D. <b>concidit</b> (perfect active indicative of <i>concido, concidere, concidī</i>) means 'to fall down, collapse, perish'. This verb is more often used for physical collapse or literal perishing, less so for abstract concepts like hope." }, { meta: "Fill-in-the-Blank", stem: "Tanta nivis vīs montem ____ ut vīcīna oppida paene dēlēta sint.", options: ["obruit", "oppressit", "submersit", "contexit"], i: 0, explanation: "The sentence means: \"Such a force of snow ____ the mountain that neighboring towns were almost destroyed.\" The context of a 'force of snow' and 'almost destroyed' implies an overwhelming, burying, or crushing action. <br>A. <b>obruit</b> (perfect active indicative of <i>obruō, obruere, obruī, obrutum</i>) means 'to overwhelm, bury, cover, suppress'. This is a precise fit for a large amount of snow covering and overwhelming a mountain to the point of destruction. <br>B. <b>oppressit</b> (perfect active indicative of <i>opprimō, opprimere, oppressī, oppressum</i>) means 'to press down, overwhelm, suppress'. While similar to 'overwhelm', <i>obruō</i> often specifically implies covering or burying, which is more apt for snow. <br>C. <b>submersit</b> (perfect active indicative of <i>submergō, submergere, submersī, submersum</i>) means 'to submerge, sink'. This verb is typically used with water, not snow. <br>D. <b>contexit</b> (perfect active indicative of <i>contegō, contegere, contēxī, contēctum</i>) means 'to cover, conceal'. This is too mild; it implies simple covering, not the destructive, overwhelming force suggested by \"paene dēlēta sint\" (almost destroyed)." }, { meta: "Fill-in-the-Blank", stem: "Ōrāculum, ut saepe, responsa per ____ obscūra dedit.", options: ["ambāgēs", "aenigmata", "fallāciās", "perplexitātēs"], i: 0, explanation: "The sentence means: \"The oracle, as often, gave answers through obscure ____.\" The context of an 'oracle' giving 'obscure answers' strongly points to ambiguity, circumlocution, or indirect speech. <br>A. <b>ambāgēs</b> (accusative plural of <i>ambāgēs, ambāgum</i> f. pl.) means 'winding, circuitous path; circumlocution, ambiguity'. This is a classic term for the obscure and indirect pronouncements of oracles. <br>B. <b>aenigmata</b> (accusative plural of <i>aenigma, -atis</i> n.) means 'riddles, enigmas'. While oracles often speak in riddles, <i>ambāgēs</i> specifically refers to the winding, indirect, and often deceptive nature of their speech, which is a more nuanced fit for 'obscūra'. <br>C. <b>fallāciās</b> (accusative plural of <i>fallācia, -ae</i> f.) means 'deceptions, tricks, sophistries'. While oracles could be seen as deceptive, <i>ambāgēs</i> focuses more on the indirectness and ambiguity rather than outright trickery. <br>D. <b>perplexitātēs</b> (accusative plural of <i>perplexitās, -ātis</i> f.) means 'perplexities, complications'. This refers to the state of being perplexed or confused, not the manner in which the answers are given." }, { meta: "Circumlocution", stem: "Quod est <b>gravis miseria</b> aut <b>calamitās</b> quae animum et corpus affligit?", options: ["aerumna", "mūnus", "cōnsilium", "ōtium"], i: 0, explanation: "The correct answer is <b>A. aerumna</b>, meaning 'toil, hardship, tribulation, distress, suffering'. This word, often found in poetic and elevated prose, perfectly matches the description of 'heavy misery or calamity which afflicts the mind and body'. <b>B. mūnus</b> refers to a 'duty, gift, or service', which, while sometimes burdensome, does not primarily denote suffering. <b>C. cōnsilium</b> means 'plan, counsel, or advice', entirely unrelated to the concept. <b>D. ōtium</b> signifies 'leisure, peace, or idleness', serving as a clear antonym to the described state of affliction." }, { meta: "Circumlocution", stem: "Quod <b>nōn abundat</b>, sed paucum est aut parvum?", options: ["exiguus", "procerus", "vastus", "opīmus"], i: 0, explanation: "The correct answer is <b>A. exiguus</b>, meaning 'small, scanty, meager, short'. This adjective accurately describes something that 'does not abound, but is little or small'. <b>B. procerus</b> means 'tall, slender', referring to height rather than quantity or general smallness. <b>C. vastus</b> means 'vast, enormous, immense', which is an antonym. <b>D. opīmus</b> means 'rich, fertile, fat, splendid', also an antonym, suggesting abundance and richness." }, { meta: "Circumlocution", stem: "Quae est <b>pars nāvis</b> quae prīma undās scindit?", options: ["prōra", "puppis", "mālus", "rūder"], i: 0, explanation: "The correct answer is <b>A. prōra</b>, which means 'prow' or 'the front part of a ship'. This term, frequently found in Vergil and other poets, precisely fits the description of 'the part of a ship which first cuts the waves'. <b>B. puppis</b> refers to the 'stern' or 'rear part of a ship'. <b>C. mālus</b> means 'mast', the vertical pole supporting sails. <b>D. rūder</b> refers to the 'rudder', used for steering. All distractors are parts of a ship, making them plausible but incorrect choices." }, { meta: "Circumlocution", stem: "Quid est <b>in somnum inducere</b> aut quiētem dare?", options: ["sōpīre", "expergīscī", "ērigere", "turbāre"], i: 0, explanation: "The correct answer is <b>A. sōpīre</b>, meaning 'to put to sleep, lull, quiet, deaden'. This verb, common in poetic contexts, perfectly matches the definition 'to lead into sleep or give rest'. <b>B. expergīscī</b> means 'to wake up or awaken', a direct antonym. <b>C. ērigere</b> means 'to raise, erect, or rouse', implying an increase in activity or position. <b>D. turbāre</b> means 'to disturb, confuse, or agitate', which is the opposite of giving rest or quiet." }, { meta: "Circumlocution", stem: "Quid est <b>sermō vel iter tortuōsum</b>, plēnum cōnfūsiōnis aut dēviātiōnum?", options: ["ambāgēs", "directiō", "brevitas", "cōnsilium"], i: 0, explanation: "The correct answer is <b>A. ambāgēs</b> (plural), meaning 'circuitous paths, windings, circumlocutions, or obscure details'. This term, often used in Vergil, accurately describes 'winding speech or path, full of confusion or deviations'. <b>B. directiō</b> refers to 'a straight direction or course', which is an antonym. <b>C. brevitas</b> means 'brevity or conciseness', the opposite of circumlocution. <b>D. cōnsilium</b> means 'plan, counsel, or wisdom', unrelated to the winding or confusing nature described." }, { meta: "Circumlocution", stem: "Quid est <b>ignis caelestis</b> qui cum magnō sonitū et lūmine cadit?", options: ["fulmen", "tonitrus", "grando", "nimbus"], i: 0, explanation: "The correct answer is <b>A. fulmen</b>, meaning 'lightning, thunderbolt'. This noun, frequently found in epic poetry and descriptions of divine power, perfectly matches the definition 'heavenly fire which falls with great sound and light'. <b>B. tonitrus</b> refers to 'thunder', the sound associated with lightning, but not the 'fire' itself. <b>C. grando</b> means 'hail', a form of precipitation. <b>D. nimbus</b> refers to a 'rain cloud' or 'storm cloud'. All distractors are related atmospheric phenomena, making them strong but incorrect choices." }, { meta: "Circumlocution", stem: "Quae est <b>pars corporis</b> per quam cibus et potus trānsmittitur, vel angustus locī aditus?", options: ["faucēs", "ōs", "guttur", "venter"], i: 0, explanation: "The correct answer is <b>A. faucēs</b> (plural), meaning 'jaws, throat, gullet; also, a narrow pass, strait, or defile'. This word, common in poetic and elevated prose, uniquely captures both the anatomical sense ('part of the body through which food and drink are transmitted') and the geographical sense ('a narrow approach of a place'). <b>B. ōs</b> means 'mouth', a more general term that doesn't fully encompass the 'pass' or 'gullet' aspect. <b>C. guttur</b> means 'throat, gullet', which is very close anatomically but less commonly used for a narrow geographical pass. <b>D. venter</b> means 'belly' or 'stomach', which is a different part of the body." }, { meta: "Circumlocution", stem: "Quid est <b>circumīre locum</b>, vel rem sacrīs pūrgāre?", options: ["lūstrāre", "expiāre", "contemplārī", "circumeāre"], i: 0, explanation: "The correct answer is <b>A. lūstrāre</b>, meaning 'to purify by sacrifice, to review, survey, or traverse'. This verb, prominent in Vergil, encompasses both 'to go around a place' (e.g., in a procession or survey) and 'to purify a thing with sacred rites'. <b>B. expiāre</b> means 'to atone for, purify, or expiate', which is very close in the sense of purification but lacks the 'going around' aspect. <b>C. contemplārī</b> means 'to gaze at, observe, or contemplate', a different action entirely. <b>D. circumeāre</b> means 'to go around', capturing only one part of the definition without the crucial element of ritual purification." }, { meta: "Circumlocution", stem: "Quid est <b>ad terram dēscendere</b> aut in locō cōnsistere?", options: ["sīdere", "cōnsistere", "ērigere", "fluere"], i: 0, explanation: "The correct answer is <b>A. sīdere</b>, meaning 'to sit down, settle, or sink down'. This verb, often found in archaic and poetic Latin (especially in the perfect tense), accurately describes 'to descend to the ground or to settle in a place'. <b>B. cōnsistere</b> means 'to stand still, take a stand, or halt', which implies settling but not necessarily descending or sinking. <b>C. ērigere</b> means 'to raise or erect', an antonym. <b>D. fluere</b> means 'to flow', which is unrelated to sitting or settling." }, { meta: "Circumlocution", stem: "Quī rērum <b>nōn habet scientiam</b> aut nōn cōgnōvit?", options: ["īgnārus", "prūdēns", "callidus", "sciēns"], i: 0, explanation: "The correct answer is <b>A. īgnārus</b>, meaning 'ignorant, unaware, or unacquainted with'. This adjective, often found in poetic contexts, precisely describes someone 'who does not have knowledge of things or has not known'. <b>B. prūdēns</b> means 'prudent, wise, or sagacious', implying knowledge and good judgment. <b>C. callidus</b> means 'clever, cunning, or skillful', suggesting a different kind of mental acuity. <b>D. sciēns</b> means 'knowing, skilled, or conscious', which is a direct antonym to the definition provided." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>aequor, aequoris</b>?", options: ["fairness", "equality", "sea", "level ground"], i: 2, explanation: "The correct answer is <b>C. sea</b>. <i>Aequor, aequoris</i> (n.) primarily means 'a level surface, a plain,' and specifically 'the sea.' Distractors include <i>aequitās, aequitātis</i> (f.) meaning 'fairness' (A), <i>aequālitās, aequālitātis</i> (f.) meaning 'equality' (B), and <i>aequum, -ī</i> (n.) meaning 'a level place' or 'level ground' (D), all of which are visually or semantically related but distinct." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>cōnūbium, -ī</b>?", options: ["plan", "cloud", "consul", "marriage"], i: 3, explanation: "The correct answer is <b>D. marriage</b>. <i>Cōnūbium, -ī</i> (n.) means 'marriage' or 'the right of marriage.' Distractors include <i>cōnsilium, -ī</i> (n.) meaning 'plan' or 'counsel' (A), <i>nūbēs, nūbis</i> (f.) meaning 'cloud' (B), and <i>cōnsul, cōnsulis</i> (m.) meaning 'consul' (C), all of which bear some phonetic or visual resemblance." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>fūnus, fūneris</b>?", options: ["rope", "foundation", "funeral", "smoke"], i: 2, explanation: "The correct answer is <b>C. funeral</b>. <i>Fūnus, fūneris</i> (n.) means 'funeral,' 'death,' or 'corpse.' Distractors include <i>fūnis, fūnis</i> (m.) meaning 'rope' (A), <i>fundāmentum, -ī</i> (n.) meaning 'foundation' (B), and <i>fūmus, fūmī</i> (m.) meaning 'smoke' (D), all of which are phonetically or visually similar nouns." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>lūctus, lūctūs</b>?", options: ["light", "game", "grief", "struggle"], i: 2, explanation: "The correct answer is <b>C. grief</b>. <i>Lūctus, lūctūs</i> (m.) means 'grief,' 'mourning,' or 'sorrow.' Distractors include <i>lūx, lūcis</i> (f.) meaning 'light' (A), <i>lūdus, lūdī</i> (m.) meaning 'game' or 'school' (B), and <i>lūcta, lūctae</i> (f.) meaning 'struggle' or 'wrestling' (D), all of which are nouns that share initial letters or sounds." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin verb <b>obruō, obruere, obruī, obrutus</b>?", options: ["to overwhelm", "to rub against", "to arise", "to break off"], i: 0, explanation: "The correct answer is <b>A. to overwhelm</b>. <i>Obruō, obruere, obruī, obrutus</i> means 'to overwhelm,' 'bury,' or 'cover.' Distractors include <i>obterō, obterre, obtrīvī, obtrītus</i> meaning 'to rub against' (B), <i>oborior, oborīrī, obortus sum</i> meaning 'to arise' or 'spring up' (C), and <i>obrumpō, obrumpere, obprūpī, obruptus</i> meaning 'to break off' or 'interrupt' (D), all of which are verbs with similar prefixes or stems." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>sōlācium, -ī</b>?", options: ["comfort", "sun", "ground", "loneliness"], i: 0, explanation: "The correct answer is <b>A. comfort</b>. <i>Sōlācium, -ī</i> (n.) means 'comfort,' 'consolation,' or 'relief.' Distractors include <i>sōl, sōlis</i> (m.) meaning 'sun' (B), <i>sōlum, -ī</i> (n.) meaning 'ground' or 'soil' (C), and <i>sōlitūdō, sōlitūdinis</i> (f.) meaning 'loneliness' or 'solitude' (D), all of which are nouns sharing the initial 'sōl-' sound." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>vātēs, vātis</b>?", options: ["prophet", "vastness", "vessel", "life"], i: 0, explanation: "The correct answer is <b>A. prophet</b>. <i>Vātēs, vātis</i> (m./f.) means 'prophet,' 'seer,' or 'poet.' Distractors include <i>vastitās, vastitātis</i> (f.) meaning 'vastness' or 'desolation' (B), <i>vās, vāsis</i> (n.) meaning 'vessel' or 'dish' (C), and <i>vīta, vītae</i> (f.) meaning 'life' (D), all of which are nouns with similar initial sounds or spellings." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>prōra, prōrae</b>?", options: ["prow", "shore", "orator", "speech"], i: 0, explanation: "The correct answer is <b>A. prow</b>. <i>Prōra, prōrae</i> (f.) means 'the prow' or 'bow of a ship.' Distractors are related to the word <i>ōra</i> (shore) or <i>ōrātor</i> (orator) which can be confused with <i>prōra</i> due to phonetic similarity or visual resemblance (if the 'pr-' is misread). These include <i>ōra, ōrae</i> (f.) meaning 'shore' (B), <i>ōrātor, ōrātōris</i> (m.) meaning 'orator' (C), and <i>ōrātiō, ōrātiōnis</i> (f.) meaning 'speech' (D)." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>aether, aetheris</b>?", options: ["upper air", "summer", "heat", "eternity"], i: 0, explanation: "The correct answer is <b>A. upper air</b>. <i>Aether, aetheris</i> (m.) means 'the upper air,' 'sky,' or 'heaven.' Distractors include <i>aestās, aestātis</i> (f.) meaning 'summer' (B), <i>aestus, aestūs</i> (m.) meaning 'heat' or 'tide' (C), and <i>aeternitās, aeternitātis</i> (f.) meaning 'eternity' (D), all of which are nouns that are visually or phonetically similar." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>fīdēs, fideī</b>?", options: ["faith", "end", "rope", "club"], i: 0, explanation: "The correct answer is <b>A. faith</b>. <i>Fīdēs, fideī</i> (f.) means 'faith,' 'trust,' or 'loyalty.' In poetry, it can also mean 'lyre string.' Distractors include <i>fīnis, fīnis</i> (m.) meaning 'end' or 'boundary' (B), <i>fūnis, fūnis</i> (m.) meaning 'rope' (C), and <i>fūstis, fūstis</i> (m.) meaning 'club' (D), all of which are nouns that are visually or phonetically similar." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin verb <b>cōnsulō, cōnsulere, cōnsuluī, cōnsultus</b>?", options: ["to consult", "to console", "to plan", "to advise"], i: 0, explanation: "The correct answer is <b>A. to consult</b>. <i>Cōnsulō, cōnsulere, cōnsuluī, cōnsultus</i> means 'to consult,' 'deliberate,' or 'take counsel for.' Distractors include <i>cōnsoleor, cōnsolārī, cōnsolātus sum</i> meaning 'to console' or 'comfort' (B), <i>cōnsiliārī, cōnsiliātus sum</i> meaning 'to plan' (C), and 'to advise' (D), all of which are verbs with similar prefixes or stems, leading to common confusion." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin verb <b>dēficiō, dēficere, dēfēcī, dēfectus</b>?", options: ["to fail", "to flee from", "to fix down", "to make down"], i: 0, explanation: "The correct answer is <b>A. to fail</b>. <i>Dēficiō, dēficere, dēfēcī, dēfectus</i>, a compound of <i>dē</i> and <i>faciō</i>, means 'to fail,' 'desert,' 'be lacking,' or 'grow weak.' Distractors include <i>dēfugiō, dēfugere, dēfūgī, dēfugitus</i> meaning 'to flee from' (B), <i>dēfīgō, dēfīgere, dēfīxī, dēfīxus</i> meaning 'to fix down' or 'fasten' (C), and 'to make down' (D), which is a literal but incorrect interpretation of the compound `dē` + `faciō`." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin verb <b>exuō, exuere, exuī, exūtus</b>?", options: ["to take off", "to go out", "to burn up", "to arise"], i: 0, explanation: "The correct answer is <b>A. to take off</b>. <i>Exuō, exuere, exuī, exūtus</i> means 'to take off,' 'strip off,' or 'lay aside.' Distractors include <i>exeō, exīre, exiī/exīvī, exitus</i> meaning 'to go out' (B), <i>exūrō, exūrere, exussī, exustus</i> meaning 'to burn up' (C), and <i>exorior, exorīrī, exortus sum</i> meaning 'to arise' or 'spring up' (D), all of which are verbs with similar prefixes and initial sounds." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>līmen, līminis</b>?", options: ["threshold", "boundary", "mud", "linen"], i: 0, explanation: "The correct answer is <b>A. threshold</b>. <i>Līmen, līminis</i> (n.) means 'threshold,' 'doorway,' 'entrance,' or 'beginning/end.' Distractors include <i>līmes, līmitis</i> (m.) meaning 'boundary' or 'path' (B), <i>līmus, līmī</i> (m.) meaning 'mud' or 'slime' (C), and <i>līnum, līnī</i> (n.) meaning 'flax' or 'linen' (D), all of which are visually or phonetically similar nouns." }, { meta: "Latin to English", stem: "What is the best English translation for the Latin word <b>pignus, pignoris</b>?", options: ["pledge", "fist", "painting", "fatness"], i: 0, explanation: "The correct answer is <b>A. pledge</b>. <i>Pignus, pignoris</i> (n.) means 'pledge,' 'guarantee,' 'security,' or 'token.' Distractors include <i>pugnus, pugnī</i> (m.) meaning 'fist' (B), <i>pictūra, pictūrae</i> (f.) meaning 'painting' or 'picture' (C), and <i>pinguitūdō, pinguitūdinis</i> (f.) meaning 'fatness' or 'richness' (D), all of which are nouns that are visually or phonetically similar to the correct answer or its related verb <i>pingō</i>." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to shun / avoid'?", options: ["vītō, vītāre", "fugiō, fugere", "dēclīnō, dēclīnāre", "dēprecōr, dēprecārī"], i: 0, explanation: "The most general and direct translation for 'to shun' or 'to avoid' is <b>vītō</b>. <br><b>fugiō</b> means 'to flee' or 'to run away from,' implying active escape rather than mere avoidance. <br><b>dēclīnō</b> means 'to bend aside,' 'to turn away,' or 'to deflect,' often implying a physical turning away. <br><b>dēprecōr</b> means 'to avert by prayer' or 'to deprecate,' implying an entreaty to avoid something, which is too specific for a general 'shun' or 'avoid'." }, { meta: "English to Latin", stem: "Which Latin word best translates 'light' (as in illumination or a source of light)?", options: ["lūx, lūcis", "lūmen, lūminis", "ignis, ignis", "fulgor, fulgōris"], i: 1, explanation: "While <b>lūx</b> (A) means 'light' or 'daylight,' <b>lūmen</b> (B) more specifically refers to a 'light' as a source of illumination (e.g., a lamp, the eye, a star) or the light it emits, and often carries a poetic connotation, making it a nuanced choice for advanced texts. Both are 3rd declension nouns. <br><b>ignis</b> (C) means 'fire' and can refer to the light from fire, but is primarily 'fire.' <br><b>fulgor</b> (D) means 'brightness,' 'splendor,' or 'a flash,' referring to the quality of light rather than the light itself or its source. All options are 3rd declension nouns, adhering to the rigor constraint." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to mourn / grieve' (often publicly)?", options: ["lūgeō, lūgēre", "fleō, flēre", "queror, querī", "plōrō, plōrāre"], i: 0, explanation: "<b>lūgeō</b> is the most appropriate verb for 'to mourn' or 'to grieve,' often implying a sustained and sometimes public display of sorrow. <br><b>fleō</b> means 'to weep' or 'to shed tears,' focusing on the physical act of crying. <br><b>queror</b> means 'to complain' or 'to lament,' often with words or a mournful sound, but can be less intense than full mourning. <br><b>plōrō</b> means 'to wail' or 'to lament loudly,' implying a more vociferous and often tearful expression of grief." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to entreat / implore'?", options: ["ōrō, ōrāre", "obsecrō, obsecrāre", "supplicō, supplicāre", "rogō, rogāre"], i: 0, explanation: "<b>ōrō</b> is a general verb for 'to pray,' 'to beg,' or 'to entreat.' All options are 1st conjugation verbs. <br><b>obsecrō</b> means 'to beseech' or 'to implore by sacred things,' implying a more solemn and urgent plea. <br><b>supplicō</b> means 'to supplicate' or 'to pray humbly,' often implying a posture of humility (e.g., on one's knees). <br><b>rogō</b> means 'to ask' or 'to inquire,' which is a less intense and less emotional request than 'entreat' or 'implore'." }, { meta: "English to Latin", stem: "Which Latin word best translates 'old age'?", options: ["senectūs, senectūtis", "aetās, aetātis", "vetustās, vetustātis", "gravitās, gravitātis"], i: 0, explanation: "<b>senectūs</b> specifically means 'old age.' All options are 3rd declension feminine nouns. <br><b>aetās</b> means 'age' or 'period of life' in general, not necessarily old age. <br><b>vetustās</b> means 'oldness,' 'antiquity,' or 'long duration,' typically referring to things or time, not the biological state of a person. <br><b>gravitās</b> means 'heaviness,' 'seriousness,' or 'dignity,' which can be associated with old age but does not mean 'old age' itself." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to seize / snatch up' (often with force or haste)?", options: ["corripiō, corripere", "capiō, capere", "rapiō, rapere", "apprehendō, apprehendere"], i: 0, explanation: "<b>corripiō</b> means 'to seize,' 'to snatch up,' or 'to grasp quickly,' often implying suddenness or violence, making it a strong choice for the nuance. All options are 3rd conjugation verbs (including mixed conjugations). <br><b>capiō</b> is a more general verb meaning 'to take,' 'to seize,' or 'to capture.' <br><b>rapiō</b> means 'to snatch,' 'to carry off,' or 'to plunder,' often with greater violence or intent to carry away. <br><b>apprehendō</b> means 'to grasp,' 'to lay hold of,' or 'to apprehend,' implying a firm grip or understanding." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to perish / be utterly destroyed'?", options: ["pereō, perīre", "moriōr, morī", "occidō, occidere", "intereō, interīre"], i: 0, explanation: "<b>pereō</b> means 'to perish,' 'to die,' or 'to be destroyed,' often emphasizing complete destruction or ruin. <br><b>moriōr</b> is the general verb for 'to die.' <br><b>occidō</b> means 'to fall,' 'to set' (of the sun), or 'to perish,' often implying ruin or destruction by falling. <br><b>intereō</b> also means 'to perish' or 'to be lost,' and is very close to <b>pereō</b>, but <b>pereō</b> more strongly conveys the sense of utter destruction or going to ruin, especially in poetic or elevated contexts." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to scatter / strew'?", options: ["spargō, spargere", "fundō, fundere", "dispergō, dispergere", "diffundō, diffundere"], i: 0, explanation: "<b>spargō</b> is the most direct and general translation for 'to scatter' or 'to strew.' All options are 3rd conjugation verbs. <br><b>fundō</b> means 'to pour' or 'to pour out,' and can sometimes imply scattering, especially of liquids or granular substances. <br><b>dispergō</b> means 'to scatter widely' or 'to disperse,' implying a broader and more complete separation. <br><b>diffundō</b> means 'to pour out,' 'to spread abroad,' or 'to diffuse,' often referring to something spreading out from a central point." }, { meta: "English to Latin", stem: "Which Latin word best translates 'dread / terror' (often caused by an external threat)?", options: ["terror, terrōris", "pavor, pavōris", "timor, timōris", "formīdō, formīdinis"], i: 0, explanation: "<b>terror</b> refers to 'terror,' 'alarm,' or 'dread,' often implying a strong, overwhelming fear caused by an external threat. All options are 3rd declension nouns. <br><b>pavor</b> means 'dread,' 'panic,' or 'consternation,' often implying a sudden, irrational, or unreasoning fear. <br><b>timor</b> is a more general word for 'fear' or 'apprehension,' which can be rational or irrational. <br><b>formīdō</b> means 'dread,' 'terror,' or 'awe,' and can refer to the object causing fear or the feeling of awe/dread itself." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to delay / linger'?", options: ["moror, morārī", "cūnctor, cūnctārī", "retineō, retinēre", "tardō, tardāre"], i: 0, explanation: "<b>moror</b> means 'to delay,' 'to linger,' or 'to tarry,' and can be used both transitively and intransitively. <br><b>cūnctor</b> means 'to delay,' 'to hesitate,' or 'to linger,' often implying reluctance or indecision. <br><b>retineō</b> means 'to hold back,' 'to detain,' or 'to restrain,' usually implying an external force preventing movement. <br><b>tardō</b> means 'to delay,' 'to hinder,' or 'to slow down,' often used transitively to describe slowing something else." }, { meta: "English to Latin", stem: "Which Latin word best translates 'shame / disgrace' (a stain on one's reputation)?", options: ["dedecus, dedecoris", "pudor, pudōris", "turpitūdō, turpitūdinis", "scelus, sceleris"], i: 0, explanation: "<b>dedecus</b> specifically means 'disgrace,' 'dishonor,' or 'shame,' often referring to a stain on one's reputation. All options are 3rd declension nouns. <br><b>pudor</b> means 'shame,' 'modesty,' or 'a sense of honor,' often referring to an internal feeling that can be positive (modesty) or negative (shame). <br><b>turpitūdō</b> means 'ugliness,' 'baseness,' or 'moral depravity,' referring to the inherent vileness of an act or character. <br><b>scelus</b> means 'crime' or 'wickedness,' referring to a specific evil deed, which might *lead* to disgrace but is not disgrace itself." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to stir up / rouse' (often with a poetic or archaic nuance)?", options: ["cieō, ciēre", "incitō, incitāre", "excitō, excitāre", "commoveō, commovēre"], i: 0, explanation: "<b>cieō</b> (or its variant <i>ciō</i>) is a poetic and archaic verb meaning 'to stir up,' 'to rouse,' or 'to excite,' often used for emotions, armies, or sounds. <br><b>incitō</b> is a common verb meaning 'to urge on,' 'to incite,' or 'to rouse.' <br><b>excitō</b> is a common verb meaning 'to rouse,' 'to awaken,' or 'to stimulate.' <br><b>commoveō</b> is a common verb meaning 'to move,' 'to stir up,' or 'to agitate.' While all are synonyms, <b>cieō</b> carries the specific poetic/archaic flavor often found in advanced texts." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to prophesy / foretell' (especially with divine inspiration)?", options: ["vāticinor, vāticinārī", "praedīcō, praedīcere", "fānor, fārī", "auguror, augurārī"], i: 0, explanation: "<b>vāticinor</b> specifically means 'to prophesy' or 'to foretell,' often implying divine inspiration or the utterance of prophecies. <br><b>praedīcō</b> means 'to foretell,' 'to predict,' or 'to proclaim,' a more general term for prediction. <br><b>fānor</b> (from <i>for</i>) means 'to speak' or 'to say,' often used in poetic contexts for divine utterance, but not specifically 'to prophesy.' <br><b>auguror</b> means 'to augur' or 'to predict from omens,' referring to a specific method of divination rather than general prophecy." }, { meta: "English to Latin", stem: "Which Latin word best translates 'to lament / complain' (often with words or mournful sounds)?", options: ["queror, querī", "lūgeō, lūgēre", "fleō, flēre", "ingemō, ingemere"], i: 0, explanation: "<b>queror</b> means 'to complain,' 'to lament,' or 'to express grief,' often with words or a mournful sound. <br><b>lūgeō</b> means 'to mourn' or 'to grieve,' implying a deeper, more sustained sorrow, often publicly. <br><b>fleō</b> means 'to weep' or 'to shed tears,' focusing on the physical act of crying. <br><b>ingemō</b> means 'to groan,' 'to sigh,' or 'to lament,' specifically referring to the utterance of groans or sighs as an expression of pain or grief." }, { meta: "English to Latin", stem: "Which Latin word best translates 'leader / guide' (in a general sense)?", options: ["dux, ducis", "prīnceps, prīncipis", "imperātor, imperātōris", "rēx, rēgis"], i: 0, explanation: "<b>dux</b> is the most general term for a 'leader' or 'guide.' All options are 3rd declension masculine nouns. <br><b>prīnceps</b> means 'chief,' 'leader,' or 'first citizen' (as in the Roman emperor), implying preeminence or authority. <br><b>imperātor</b> means 'commander,' 'general,' or 'emperor,' specifically referring to a military leader or supreme ruler. <br><b>rēx</b> means 'king' or 'ruler,' implying a monarchical head of state. While all denote leadership, <b>dux</b> is the broadest and most fundamental term for one who leads or guides." }, { meta: "Synonyms", stem: "Quod verbum est simillimum fās?", options: ["iūs", "lēx", "mōs", "aequitās"], i: 0, explanation: "The word <b>fās</b> refers to divine law or right, that which is sanctioned by the gods. <b>iūs</b>, while often contrasted as human law, is the closest general synonym for 'right' or 'law' in a broader sense. <b>lēx</b> specifically denotes a statute or written law, often enacted by humans. <b>mōs</b> refers to custom or tradition, and <b>aequitās</b> means equity or fairness, which are related concepts but not direct synonyms for divine right." }, { meta: "Synonyms", stem: "Quod verbum est simillimum vituperō?", options: ["accūsō", "laudō", "cōnfirmō", "dēmonstrō"], i: 0, explanation: "The verb <b>vituperō</b> means 'to blame, censure, or find fault with.' <b>accūsō</b>, meaning 'to accuse' or 'to blame,' is its closest synonym. <b>laudō</b> means 'to praise,' making it an antonym. <b>cōnfirmō</b> means 'to strengthen' or 'to confirm,' and <b>dēmonstrō</b> means 'to show' or 'to point out,' neither of which are semantically related to blaming." }, { meta: "Synonyms", stem: "Quod verbum est simillimum maeror?", options: ["dolor", "aegritūdō", "sollicitūdō", "perturbātiō"], i: 0, explanation: "<b>Maeror</b> signifies deep sadness, grief, or sorrow. <b>Dolor</b>, meaning 'pain' or 'grief,' is the most direct synonym, often referring to emotional suffering. <b>Aegritūdō</b> denotes sickness, distress, or mental anguish, often with a physical component. <b>Sollicitūdō</b> refers to anxiety or worry, a state of unease rather than profound grief. <b>Perturbātiō</b> means disturbance or confusion, a state of agitation." }, { meta: "Synonyms", stem: "Quod verbum est simillimum vātēs?", options: ["augur", "haruspex", "sacerdōs", "ōrātor"], i: 0, explanation: "A <b>vātēs</b> is a prophet, seer, or poet, often inspired by divine influence. An <b>augur</b> is a Roman religious official who interpreted omens, particularly from the flight of birds, and thus also acted as a prophet or diviner. A <b>haruspex</b> was a diviner who inspected entrails of sacrificed animals, a more specific type of soothsayer. A <b>sacerdōs</b> is a priest, performing religious rites. An <b>ōrātor</b> is a speaker or orator, not necessarily connected with prophecy." }, { meta: "Synonyms", stem: "Quod verbum est simillimum aether?", options: ["caelum", "mundus", "polus", "solum"], i: 0, explanation: "<b>Aether</b> refers to the upper air, the pure air of the heavens, or heaven itself. <b>Caelum</b>, meaning 'sky' or 'heaven,' is its closest general synonym, encompassing both the physical sky and the celestial realm. <b>Mundus</b> refers to the 'world' or 'universe.' <b>Polus</b> means 'pole' or 'sky,' often referring to the celestial pole or vault, but less general than <i>caelum</i>. <b>Solum</b> means 'soil' or 'ground,' an antonym in terms of elevation." }, { meta: "Synonyms", stem: "Quod verbum est simillimum cōnūbium?", options: ["mātrimōnium", "coniugium", "vinculum", "pactum"], i: 0, explanation: "<b>Cōnūbium</b> denotes marriage, or specifically the legal right to marry. <b>Mātrimōnium</b> is the most direct and common synonym for 'marriage' or 'wedlock.' <b>Coniugium</b> also means 'marriage' or 'union,' but can be more general, referring to any joining. <b>Vinculum</b> means 'chain' or 'bond,' and while marriage creates a bond, it's not a direct synonym. <b>Pactum</b> means 'agreement' or 'pact,' which is a prerequisite for marriage but not the institution itself." }, { meta: "Synonyms", stem: "Quod verbum est simillimum lūctus?", options: ["plōrātus", "gemītus", "fletus", "ululātus"], i: 0, explanation: "<b>Lūctus</b> signifies grief, sorrow, or mourning, often accompanied by outward expressions. <b>Plōrātus</b> means 'weeping' or 'lamentation,' a very direct and intense expression of grief. <b>Gemītus</b> refers to a 'groan' or 'sigh,' a sound of distress. <b>Fletus</b> means 'weeping' or 'tears,' similar to <i>plōrātus</i> but perhaps less active. <b>Ululātus</b> means 'wailing' or 'howling,' a loud and often ritualistic cry of grief." }, { meta: "Synonyms", stem: "Quod verbum est simillimum vetustus?", options: ["antīquus", "prīscus", "dēfessus", "novus"], i: 0, explanation: "The adjective <b>vetustus</b> means 'old,' 'ancient,' or 'of long standing,' often implying something worn by age. <b>Antīquus</b> is a close synonym, meaning 'ancient,' 'old,' or 'of former times,' often with a sense of reverence. <b>Prīscus</b> also means 'ancient' or 'old-fashioned,' sometimes implying a venerable but perhaps rustic antiquity. <b>Dēfessus</b> means 'tired' or 'worn out,' referring to a state of exhaustion. <b>Novus</b> means 'new,' serving as a clear antonym." }, { meta: "Synonyms", stem: "Quod verbum est simillimum pōscō?", options: ["petō", "quaerō", "exigō", "mittō"], i: 0, explanation: "The verb <b>pōscō</b> means 'to demand,' 'request urgently,' or 'ask for.' <b>Petō</b>, meaning 'to seek,' 'ask,' or 'request,' is its closest general synonym, though <i>pōscō</i> often implies more insistence. <b>Quaerō</b> means 'to seek' or 'to ask a question,' focusing on inquiry. <b>Exigō</b> means 'to drive out,' 'demand,' or 'exact,' often with a stronger sense of compulsion. <b>Mittō</b> means 'to send' or 'to dismiss,' unrelated semantically." }, { meta: "Synonyms", stem: "Quod verbum est simillimum sōlācium?", options: ["remedium", "auxilium", "subsidium", "cōnsilium"], i: 0, explanation: "<b>Sōlācium</b> denotes comfort, consolation, or relief from distress. <b>Remedium</b>, meaning 'remedy,' 'cure,' or 'relief,' is a very close synonym as it provides alleviation from suffering. <b>Auxilium</b> means 'aid' or 'help,' a broader term for assistance. <b>Subsidium</b> refers to 'reserve' or 'support,' often military or financial. <b>Cōnsilium</b> means 'plan' or 'advice,' which might lead to comfort but is not comfort itself." }, { meta: "Synonyms", stem: "Quod verbum est simillimum faveō?", options: ["indulgeō", "studeō", "placeō", "dēbeō"], i: 0, explanation: "The verb <b>faveō</b> (with dative) means 'to favor,' 'be well-disposed towards,' or 'support.' <b>Indulgeō</b> (with dative), meaning 'to indulge,' 'grant,' or 'show favor to,' is a strong synonym, implying a yielding or giving in to someone's wishes. <b>Studeō</b> (with dative) means 'to be eager,' 'study,' or 'be zealous for,' which can imply favoring but is less direct. <b>Placeō</b> (with dative) means 'to please,' indicating a reciprocal feeling. <b>Dēbeō</b> means 'to owe' or 'ought,' which is unrelated." }, { meta: "Synonyms", stem: "Quod verbum est simillimum ingēns?", options: ["grandis", "gravis", "fortis", "brevis"], i: 0, explanation: "The adjective <b>ingēns</b> means 'huge,' 'vast,' or 'enormous.' <b>Grandis</b> means 'great,' 'large,' or 'grand,' making it a close synonym for size and magnitude. <b>Gravis</b> means 'heavy' or 'serious,' referring to weight or importance. <b>Fortis</b> means 'brave' or 'strong,' referring to courage or strength. <b>Brevis</b> means 'short,' serving as an antonym." }, { meta: "Synonyms", stem: "Quod verbum est simillimum gaudium?", options: ["dēlectāmentum", "oblectāmentum", "studium", "ōtium"], i: 0, explanation: "<b>Gaudium</b> signifies joy, delight, or gladness. <b>Dēlectāmentum</b>, meaning 'delight' or 'amusement,' is a very close synonym, referring to that which causes pleasure. <b>Oblectāmentum</b> also means 'delight,' 'amusement,' or 'diversion,' similar to <i>dēlectāmentum</i>. <b>Studium</b> refers to 'eagerness,' 'zeal,' or 'pursuit,' which can be associated with pleasure but is not the pleasure itself. <b>Ōtium</b> means 'leisure,' 'peace,' or 'quiet,' a state often conducive to joy but not synonymous with it." }, { meta: "Synonyms", stem: "Quod verbum est simillimum cōnfiteor?", options: ["fateor", "polliceor", "tueor", "mereor"], i: 0, explanation: "The deponent verb <b>cōnfiteor</b> means 'to confess,' 'admit,' or 'acknowledge.' <b>Fateor</b>, also a deponent verb, is its most direct synonym, meaning 'to confess,' 'admit,' or 'declare.' <b>Polliceor</b> means 'to promise.' <b>Tueor</b> means 'to watch,' 'protect,' or 'look at.' <b>Mereor</b> means 'to deserve' or 'to earn.' These distractors are all 2nd conjugation deponent verbs, but semantically distinct." }, { meta: "Synonyms", stem: "Quod verbum est simillimum mīrābilis?", options: ["admirābilis", "horribilis", "terribilis", "crūdēlis"], i: 0, explanation: "The adjective <b>mīrābilis</b> means 'wonderful,' 'marvelous,' or 'astonishing.' <b>Admirābilis</b>, meaning 'admirable' or 'wonderful,' is its closest synonym, often used to describe something worthy of admiration or wonder. <b>Horribilis</b> means 'horrible' or 'dreadful.' <b>Terribilis</b> means 'terrible' or 'frightening.' <b>Crūdēlis</b> means 'cruel' or 'harsh.' These distractors are all 3rd declension adjectives but convey negative or unrelated connotations." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum ōtium?", options: ["negōtium", "gaudium", "silentium", "studium"], i: 0, explanation: "The word <b>ōtium</b> refers to leisure, peace, or freedom from business. Its direct antonym, both semantically and often morphologically (via the negative prefix <i>neg-</i>), is <b>negōtium</b>, meaning business, trouble, or lack of leisure. Options B (<b>gaudium</b>, joy), C (<b>silentium</b>, silence), and D (<b>studium</b>, eagerness, study) are related to states of mind or activity but do not represent the direct opposite of leisure or freedom from obligation." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum profundus?", options: ["altus", "summus", "cavus", "lātus"], i: 1, explanation: "<b>Profundus</b> means 'deep' or 'profound.' The most direct antonym for 'deep' in terms of spatial dimension is 'highest' or 'topmost,' which is conveyed by <b>summus</b>. Option A, <b>altus</b>, is ambiguous as it can mean both 'high' and 'deep,' making it a poor antonym. Option C, <b>cavus</b>, means 'hollow,' and option D, <b>lātus</b>, means 'wide,' neither of which is a direct opposite of 'deep.'" }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum mītis?", options: ["placidus", "lēnis", "saevus", "benignus"], i: 2, explanation: "The adjective <b>mītis</b> means 'mild, gentle, soft.' Its closest antonym is <b>saevus</b>, meaning 'fierce, cruel, savage.' Options A (<b>placidus</b>, calm), B (<b>lēnis</b>, gentle), and D (<b>benignus</b>, kind) are all synonyms or closely related positive attributes, making them distractors." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum cōnfiteor?", options: ["fateor", "negō", "probō", "affirmō"], i: 1, explanation: "The deponent verb <b>cōnfiteor</b> means 'to confess, admit, acknowledge.' Its direct antonym is <b>negō</b>, 'to deny, refuse.' Option A, <b>fateor</b>, is a synonym of <b>cōnfiteor</b>. Options C (<b>probō</b>, to approve) and D (<b>affirmō</b>, to affirm) are related to stating something positively but are not direct antonyms of 'confess' in the sense of admitting fault or truth." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum probitās?", options: ["virtūs", "improbitās", "fīdēs", "aequitās"], i: 1, explanation: "<b>Probitās</b> means 'honesty, integrity, uprightness.' Its clearest and most direct antonym, formed with the negative prefix <i>im-</i>, is <b>improbitās</b>, meaning 'dishonesty, wickedness, depravity.' Options A (<b>virtūs</b>, virtue), C (<b>fīdēs</b>, faith, trust), and D (<b>aequitās</b>, fairness) are all positive qualities but are not the direct semantic opposite of 'honesty' or 'integrity' in the same way <b>improbitās</b> is." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum sērō?", options: ["mātūrē", "tandem", "post", "umquam"], i: 0, explanation: "The adverb <b>sērō</b> means 'late, at a late hour.' Its most direct antonym is <b>mātūrē</b>, meaning 'early, quickly, at the right time.' Option B (<b>tandem</b>, finally) describes the culmination of a process, not the opposite of 'late.' Option C (<b>post</b>, after) is a preposition or adverb of sequence. Option D (<b>umquam</b>, ever) relates to indefinite time, not the opposite of 'late.'" }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum exstinguō?", options: ["dēleō", "occīdō", "accendō", "tollō"], i: 2, explanation: "The verb <b>exstinguō</b> means 'to extinguish, put out (a fire or light),' or 'to destroy, abolish.' In the primary sense of extinguishing a flame, its direct antonym is <b>accendō</b>, 'to light, kindle, set on fire.' Option A (<b>dēleō</b>, to destroy) is a synonym for the 'destroy' sense of <b>exstinguō</b>. Option B (<b>occīdō</b>, to kill) refers to ending life. Option D (<b>tollō</b>, to lift, raise, remove) has a broader meaning." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum prīstinus?", options: ["antīquus", "vetus", "novus", "aeternus"], i: 2, explanation: "The adjective <b>prīstinus</b> means 'former, original, ancient.' Its most direct antonym is <b>novus</b>, meaning 'new, fresh, recent.' Options A (<b>antīquus</b>, ancient) and B (<b>vetus</b>, old) are synonyms or closely related terms to <b>prīstinus</b>. Option D (<b>aeternus</b>, eternal) refers to perpetual existence, not the opposite of a former state." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum sōlācium?", options: ["laetitia", "gaudium", "dolor", "voluptās"], i: 2, explanation: "<b>Sōlācium</b> means 'comfort, consolation, relief.' The most direct emotional antonym for comfort or consolation is <b>dolor</b>, meaning 'pain, grief, sorrow.' While options A (<b>laetitia</b>, joy), B (<b>gaudium</b>, joy), and D (<b>voluptās</b>, pleasure) represent positive emotional states, they are not direct opposites of 'consolation' in the same way that 'grief' is." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum arduus?", options: ["difficilis", "gravis", "facilis", "lēvis"], i: 2, explanation: "The adjective <b>arduus</b> means 'steep, high,' and metaphorically 'difficult, arduous.' In the sense of 'difficult,' its direct antonym is <b>facilis</b>, meaning 'easy.' Option A (<b>difficilis</b>, difficult) is a synonym. Option B (<b>gravis</b>, heavy, serious) can imply difficulty but is not a direct opposite. Option D (<b>lēvis</b>, light, smooth) is the opposite of 'heavy' or 'rough,' not necessarily 'steep' or 'difficult.'" }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum īnflāmmō?", options: ["urō", "calefaciō", "incendō", "refrigerō"], i: 3, explanation: "The verb <b>īnflāmmō</b> means 'to set on fire, inflame, excite.' Its most direct antonym, especially in the sense of temperature, is <b>refrigerō</b>, 'to cool, make cold.' Options A (<b>urō</b>, to burn), B (<b>calefaciō</b>, to heat), and C (<b>incendō</b>, to set on fire) are all synonyms or actions related to heating or burning, making them strong distractors." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum cōnfertus?", options: ["plēnus", "dēnsus", "dīspersus", "frequēns"], i: 2, explanation: "The adjective <b>cōnfertus</b> means 'crowded, dense, packed together.' Its most direct antonym is <b>dīspersus</b> (from <i>dispergō</i>), meaning 'scattered, dispersed.' Option A (<b>plēnus</b>, full) is related but not the opposite of 'dense.' Options B (<b>dēnsus</b>, dense) and D (<b>frequēns</b>, frequent, crowded) are synonyms or closely related terms to <b>cōnfertus</b>." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum adūlor?", options: ["laudō", "obsequor", "vituperō", "blandior"], i: 2, explanation: "The deponent verb <b>adūlor</b> means 'to flatter, fawn upon, pay court to.' Its direct antonym is <b>vituperō</b>, 'to blame, censure, find fault with.' Option A (<b>laudō</b>, to praise) can be sincere, unlike flattery, but is not a direct opposite of the insincere nature of <b>adūlor</b>. Option B (<b>obsequor</b>, to comply, indulge) and D (<b>blandior</b>, to flatter) are synonyms or closely associated actions with flattery." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum pervicāx?", options: ["pertināx", "dūrus", "obsequēns", "tenāx"], i: 2, explanation: "The adjective <b>pervicāx</b> means 'stubborn, obstinate, headstrong.' Its closest antonym is <b>obsequēns</b>, meaning 'compliant, yielding, obedient.' Option A (<b>pertināx</b>, persistent, stubborn) and D (<b>tenāx</b>, tenacious, clinging) are synonyms or nearly synonymous. Option B (<b>dūrus</b>, hard) can metaphorically imply stubbornness but is not a direct antonym for the character trait." }, { meta: "Antonyms", stem: "Quod verbum est antonymum verbum oblivīscor?", options: ["meminī", "recordor", "cōgitō", "sciō"], i: 0, explanation: "The deponent verb <b>oblivīscor</b> means 'to forget.' Its direct antonym is the defective verb <b>meminī</b>, 'to remember, recall.' Option B (<b>recordor</b>, to recall, remember) is a synonym of <b>meminī</b>, but <b>meminī</b> is often considered the more fundamental opposite of <b>oblivīscor</b>. Options C (<b>cōgitō</b>, to think) and D (<b>sciō</b>, to know) are related mental activities but not direct antonyms of 'forgetting.'" }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["lūcus", "pāgus", "pecus", "focus"], i: 2, explanation: "The correct answer is &lt;b&gt;C&lt;/b&gt;. &lt;i&gt;Lūcus&lt;/i&gt; (grove), &lt;i&gt;pāgus&lt;/i&gt; (district, village), and &lt;i&gt;focus&lt;/i&gt; (hearth) are all second declension masculine nouns. &lt;i&gt;Pecus, pecoris&lt;/i&gt; (flock, herd) is a third declension neuter noun. This is an 'invisible trap' based on declension and gender for words sharing the same nominative singular ending." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["sequor", "vertō", "currō", "tendō"], i: 0, explanation: "The correct answer is &lt;b&gt;A&lt;/b&gt;. &lt;i&gt;Sequor, sequī, secūtus sum&lt;/i&gt; (to follow) is a deponent verb. &lt;i&gt;Vertō, vertere, vertī, versum&lt;/i&gt; (to turn), &lt;i&gt;currō, currere, cucurrī, cursum&lt;/i&gt; (to run), and &lt;i&gt;tendō, tendere, tetendī, tentum&lt;/i&gt; (to stretch, aim) are all active verbs. All verbs appear active in their first principal part, creating a subtle distinction." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["fātum", "fortūna", "cāsus", "līmen"], i: 3, explanation: "The correct answer is &lt;b&gt;D&lt;/b&gt;. &lt;i&gt;Fātum&lt;/i&gt; (fate, destiny), &lt;i&gt;fortūna&lt;/i&gt; (fortune, luck), and &lt;i&gt;cāsus&lt;/i&gt; (chance, misfortune, event) are all abstract nouns related to destiny, luck, or chance. &lt;i&gt;Līmen, līminis&lt;/i&gt; (threshold, entrance) is a concrete noun referring to a physical object." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["trucīdō", "caedō", "mactō", "interficiō"], i: 2, explanation: "The correct answer is &lt;b&gt;C&lt;/b&gt;. While all four verbs can mean 'to kill' or 'slaughter', &lt;i&gt;mactō, mactāre&lt;/i&gt; (to sacrifice, slay in honor of the gods, glorify) carries a specific connotation of ritualistic killing or honoring through sacrifice, often in a religious context. &lt;i&gt;Trucīdō&lt;/i&gt; (to slaughter, butcher), &lt;i&gt;caedō&lt;/i&gt; (to cut down, kill), and &lt;i&gt;interficiō&lt;/i&gt; (to kill, destroy) refer to more general acts of killing or destruction." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["caelum", "polus", "aethēr", "sīdus"], i: 3, explanation: "The correct answer is &lt;b&gt;D&lt;/b&gt;. &lt;i&gt;Caelum&lt;/i&gt; (sky, heaven), &lt;i&gt;polus&lt;/i&gt; (pole, sky, heaven), and &lt;i&gt;aethēr&lt;/i&gt; (upper air, heaven) are all terms referring to the sky or heavens. &lt;i&gt;Sīdus, sīderis&lt;/i&gt; (star, constellation) refers to a celestial body within the sky, rather than the sky itself." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["nauta", "silva", "aqua", "terra"], i: 0, explanation: "The correct answer is &lt;b&gt;A&lt;/b&gt;. All four words are first declension nouns ending in -a. However, &lt;i&gt;nauta, nautae&lt;/i&gt; (sailor) is a masculine noun. &lt;i&gt;Silva, silvae&lt;/i&gt; (forest), &lt;i&gt;aqua, aquae&lt;/i&gt; (water), and &lt;i&gt;terra, terrae&lt;/i&gt; (land) are all feminine nouns. This is a classic 'invisible trap' based on gender within the first declension." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["stō", "sedeō", "iaceō", "ponō"], i: 3, explanation: "The correct answer is &lt;b&gt;D&lt;/b&gt;. &lt;i&gt;Stō, stāre&lt;/i&gt; (to stand), &lt;i&gt;sedeō, sedēre&lt;/i&gt; (to sit), and &lt;i&gt;iaceō, iacēre&lt;/i&gt; (to lie down) are all intransitive verbs describing a state or position. &lt;i&gt;Ponō, pōnere&lt;/i&gt; (to put, place) is a transitive verb, requiring an object to be placed." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["capillus", "frōns", "vultus", "corōna"], i: 3, explanation: "The correct answer is &lt;b&gt;D&lt;/b&gt;. &lt;i&gt;Capillus&lt;/i&gt; (hair), &lt;i&gt;frōns&lt;/i&gt; (forehead), and &lt;i&gt;vultus&lt;/i&gt; (face, expression) are all parts of the head or face. &lt;i&gt;Corōna, corōnae&lt;/i&gt; (crown, garland) is an adornment worn on the head." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["virtūs", "honōs", "fīdēs", "dolor"], i: 3, explanation: "The correct answer is &lt;b&gt;D&lt;/b&gt;. &lt;i&gt;Virtūs&lt;/i&gt; (virtue, courage), &lt;i&gt;honōs&lt;/i&gt; (honor, esteem), and &lt;i&gt;fīdēs&lt;/i&gt; (faith, loyalty) are all abstract nouns representing positive qualities or virtues. &lt;i&gt;Dolor, dolōris&lt;/i&gt; (pain, grief, sorrow) is an abstract noun representing a negative emotional or physical state." }, { meta: "Odd One Out", stem: "Which word does not belong?", options: ["ignis", "flamma", "lūmen", "incendium"], i: 2, explanation: "The correct answer is &lt;b&gt;C&lt;/b&gt;. &lt;i&gt;Ignis&lt;/i&gt; (fire), &lt;i&gt;flamma&lt;/i&gt; (flame), and &lt;i&gt;incendium&lt;/i&gt; (conflagration, fire) are all terms directly related to fire or burning. &lt;i&gt;Lūmen, lūminis&lt;/i&gt; (light, lamp, eye) refers to light itself or a source of light, which may come from fire but is not fire in its essence." }, { meta: "Analogies", stem: "<b>pēs</b> : <b>corpus</b> :: <b>rōbur</b> : X", options: ["virtūs", "dolor", "ōrātiō", "tempestās"], i: 0, explanation: "The relationship is 'specific part/quality to encompassing whole/quality'. A <b>pēs</b> (foot) is a part of the <b>corpus</b> (body). Similarly, <b>rōbur</b> (strength, vigor) is a key component or aspect of <b>virtūs</b> (virtue, excellence, manliness). All options are 3rd declension feminine nouns in the nominative singular. <b>Dolor</b> (pain), <b>ōrātiō</b> (speech), and <b>tempestās</b> (storm) do not share this abstract part-to-whole relationship with <b>rōbur</b>." }, { meta: "Analogies", stem: "<b>īre</b> : <b>iēns</b> :: <b>velle</b> : X", options: ["volēns", "sciēns", "potēns", "dīcēns"], i: 0, explanation: "The relationship is 'present active infinitive to its present active participle (nominative singular)'. <b>īre</b> (to go) forms the participle <b>iēns</b> (going). The irregular verb <b>velle</b> (to wish, to want) forms the participle <b>volēns</b> (wishing, wanting, willing). All options are present active participles in the nominative singular, matching the grammatical form of the correct answer. <b>Sciēns</b> (knowing), <b>potēns</b> (powerful), and <b>dīcēns</b> (saying) are participles of other verbs." }, { meta: "Analogies", stem: "<b>iter</b> : <b>via</b> :: <b>laus</b> : X", options: ["glōria", "cōpia", "īnsula", "familia"], i: 0, explanation: "The relationship is 'synonym across different declensions'. <b>iter</b> (journey, 3rd declension neuter) is synonymous with <b>via</b> (road, way, 1st declension feminine). Similarly, <b>laus</b> (praise, 3rd declension feminine) is synonymous with <b>glōria</b> (glory, fame, 1st declension feminine). All options are 1st declension feminine nouns in the nominative singular. <b>Cōpia</b> (abundance), <b>īnsula</b> (island), and <b>familia</b> (family) are not synonyms for <b>laus</b>." }, { meta: "Analogies", stem: "<b>bonus</b> : <b>malus</b> :: <b>sapiēns</b> : X", options: ["stultus", "laetus", "dūrus", "līber"], i: 0, explanation: "The relationship is 'antonym'. <b>bonus</b> (good) is the antonym of <b>malus</b> (bad). Similarly, <b>sapiēns</b> (wise) is the antonym of <b>stultus</b> (foolish). All options are adjectives in the nominative singular masculine (or applicable to masculine, like 3rd declension adjectives). <b>Laetus</b> (happy), <b>dūrus</b> (hard), and <b>līber</b> (free) are not antonyms of <b>sapiēns</b>." }, { meta: "Analogies", stem: "<b>amor</b> : <b>cor</b> :: <b>fortūna</b> : X", options: ["rota", "aqua", "terra", "silva"], i: 0, explanation: "The relationship is 'abstract concept to its concrete symbolic representation'. <b>amor</b> (love) is often symbolized by the <b>cor</b> (heart). Similarly, <b>fortūna</b> (fortune, luck) is famously symbolized by the <b>rota</b> (wheel), as in the 'wheel of fortune'. All options are 1st declension feminine nouns in the nominative singular. <b>Aqua</b> (water), <b>terra</b> (earth), and <b>silva</b> (forest) are not traditional symbols for <b>fortūna</b>." }, { meta: "Analogies", stem: "<b>scrīptor</b> : <b>scrīptūra</b> :: <b>ōrātor</b> : X", options: ["ōrātiō", "ratiō", "lēgātiō", "condiciō"], i: 0, explanation: "The relationship is 'agent noun to the action or product of the action'. A <b>scrīptor</b> (writer) produces <b>scrīptūra</b> (writing, a writing). Similarly, an <b>ōrātor</b> (speaker, orator) delivers an <b>ōrātiō</b> (speech, oration). All options are 3rd declension feminine nouns in the nominative singular. <b>Ratiō</b> (reason), <b>lēgātiō</b> (embassy), and <b>condiciō</b> (condition) are not the direct product of an <b>ōrātor</b>'s activity." }, { meta: "Analogies", stem: "<b>gladius</b> : <b>pugna</b> :: <b>lībra</b> : X", options: ["aequitās", "cīvitās", "voluptās", "potestās"], i: 0, explanation: "The relationship is 'instrument to its primary abstract purpose or outcome'. A <b>gladius</b> (sword) is used for <b>pugna</b> (fighting, battle). Similarly, a <b>lībra</b> (balance, scales) is primarily used to ensure <b>aequitās</b> (equity, fairness, balance). All options are 3rd declension feminine nouns in the nominative singular. <b>Cīvitās</b> (state), <b>voluptās</b> (pleasure), and <b>potestās</b> (power) are not the direct abstract purpose of scales." }, { meta: "Analogies", stem: "<b>tempus</b> : <b>aevum</b> :: <b>sōlācium</b> : X", options: ["levāmen", "nōmen", "carmen", "flūmen"], i: 0, explanation: "The relationship is 'common word to its poetic/less common synonym'. <b>tempus</b> (time) is the common word for which <b>aevum</b> (age, time) is a more poetic or archaic synonym. Similarly, <b>sōlācium</b> (comfort, solace) has <b>levāmen</b> (alleviation, relief, comfort) as a poetic or less common synonym. All options are 3rd declension neuter nouns in the nominative singular. <b>Nōmen</b> (name), <b>carmen</b> (song), and <b>flūmen</b> (river) are unrelated." }, { meta: "Analogies", stem: "<b>puppis</b> : <b>nāvis</b> :: <b>mūrī</b> : X", options: ["urbs", "pars", "vōx", "nūbēs"], i: 0, explanation: "The relationship is 'prominent part to the whole (synecdoche)'. The <b>puppis</b> (stern) is a defining part of a <b>nāvis</b> (ship). Similarly, the <b>mūrī</b> (walls, often used in plural for city walls) are a defining part of an <b>urbs</b> (city). All options are 3rd declension feminine nouns in the nominative singular (matching the grammatical category of the correct answer, despite <b>mūrī</b> being plural). <b>Pars</b> (part), <b>vōx</b> (voice), and <b>nūbēs</b> (cloud) do not complete this specific part-to-whole relationship." }, { meta: "Analogies", stem: "<b>morior</b> : <b>mors</b> :: <b>nāscor</b> : X", options: ["ōrīgō", "ratiō", "condiciō", "imāgō"], i: 0, explanation: "The relationship is 'verb to its related abstract noun of action/state'. The verb <b>morior</b> (to die) is related to the noun <b>mors</b> (death). Similarly, the verb <b>nāscor</b> (to be born) is related to the noun <b>ōrīgō</b> (origin, birth, source). All options are 3rd declension feminine nouns in the nominative singular. <b>Ratiō</b> (reason), <b>condiciō</b> (condition), and <b>imāgō</b> (image) are not directly related to the act of being born." }, { meta: "Fill-in-the-Blank", stem: "Dracō ingēns, cuius corpus āreā squāmīs __________ fulgēbat, fēminam terruit.", options: ["obtectum", "adornātum", "indūtum", "mūnītum"], i: 0, explanation: "The sentence describes a huge dragon whose body gleamed with bronze scales. The verb <i>obtegō</i> means 'to cover, conceal'. Thus, <b>obtectum</b> (covered) perfectly fits the context of a body covered with scales. Options B, C, and D are all perfect passive participles, neuter singular, grammatically correct but semantically less precise: <b>adornātum</b> (adorned) suggests decoration rather than natural covering; <b>indūtum</b> (clothed, put on) is typically used for garments; and <b>mūnītum</b> (fortified, protected) implies defense, which is not the primary description here." }, { meta: "Fill-in-the-Blank", stem: "Cum _________ nūlla dē futūrīs darentur, cīvēs anxīī ad templum Apollinis contendērunt.", options: ["ōmina", "prōdigia", "fāta", "orācula"], i: 3, explanation: "The sentence states that the citizens anxiously hastened to the temple of Apollo because 'no ______ were given concerning the future'. Apollo is famously associated with prophecy. <b>Orācula</b> (oracles, prophecies) from <i>orāculum, -ī</i> n. is the most precise term for divine pronouncements about the future. While <b>ōmina</b> (omens) and <b>prōdigia</b> (portents, prodigies) are related to signs of the future, they are less direct pronouncements 'given'. <b>Fāta</b> (fates, destinies) are abstract concepts, not typically 'given' in this manner." }, { meta: "Fill-in-the-Blank", stem: "Cicerō, summā _________ praeditus, senātum saepe ad suam sententiam dūcēbat.", options: ["ēloquentiā", "sapientiā", "doctrīnā", "industriā"], i: 0, explanation: "The sentence describes Cicero's ability to lead the senate to his opinion. Cicero was renowned for his rhetorical skill. <b>Ēloquentiā</b> (eloquence) from <i>ēloquentia, -ae</i> f. is the most fitting quality for persuading an assembly. While <b>sapientiā</b> (wisdom), <b>doctrīnā</b> (learning), and <b>industriā</b> (diligence) are all positive attributes, they do not directly describe the power of persuasion in speech as eloquently as <i>ēloquentia</i>." }, { meta: "Fill-in-the-Blank", stem: "Nāvēs, post longum labōrem per undās _________, tandem ad lītus appulsae sunt.", options: ["tumidās", "rapidās", "altās", "caeruleās"], i: 0, explanation: "The sentence describes ships enduring 'long toil' through waves. This implies difficult conditions. <b>Tumidās</b> (swelling, turbulent) from <i>tumidus, -a, -um</i> is a poetic and apt description of rough, high seas that would cause 'long toil'. While <b>rapidās</b> (swift), <b>altās</b> (deep/high), and <b>caeruleās</b> (dark blue, sea-colored) can describe waves, they do not convey the sense of difficulty and turbulence as strongly as <i>tumidās</i>." }, { meta: "Fill-in-the-Blank", stem: "Per silvās dēnsās, ventus folia leviter _________, quasi trīstia verba susurrāns.", options: ["crepitābat", "agitābat", "vibrābat", "flāgitābat"], i: 0, explanation: "The sentence describes the wind's action on leaves, comparing it to whispering sad words. <b>Crepitābat</b> (was rustling, rattling) from <i>crepitō, crepitāre</i> is the most precise verb for the sound of leaves in a gentle wind. <b>Agitābat</b> (was shaking, stirring) and <b>vibrābat</b> (was quivering, shaking) describe the motion but not specifically the sound. <b>Flāgitābat</b> (was demanding) is semantically incorrect." }, { meta: "Fill-in-the-Blank", stem: "Pāstor, ovibus ā grege _________, per montēs et vallēs diū quaerēbat.", options: ["aberrantibus", "errantibus", "dēviantibus", "vagantibus"], i: 0, explanation: "The sentence describes a shepherd searching for sheep that are 'from the flock'. The prefix <i>ab-</i> in <b>aberrantibus</b> (straying away, wandering off) from <i>aberrō, aberrāre</i> specifically denotes movement *away from* a point, making it the most accurate term for sheep straying *from the flock*. While <b>errantibus</b> (wandering), <b>dēviantibus</b> (straying, deviating), and <b>vagantibus</b> (roaming) describe wandering, <i>aberrantibus</i> most clearly implies separation from the group." }, { meta: "Fill-in-the-Blank", stem: "Aenēās, quamquam fātō pressus, tamen spem nōn _________ sed fortūnam suam virtūte superāvit.", options: ["dēposuit", "āmisit", "relīquit", "dēseruit"], i: 0, explanation: "The sentence states that Aeneas, though pressed by fate, did not ______ hope, but overcame his fortune by virtue. The idiom 'spem dēpōnere' (to lay aside hope, abandon hope) is common in Latin. Thus, <b>dēposuit</b> (laid aside, abandoned) from <i>dēpōnō, dēpōnere</i> is the most idiomatic and fitting choice. While <b>āmisit</b> (lost), <b>relīquit</b> (left), and <b>dēseruit</b> (deserted) could imply a loss of hope, <i>dēposuit</i> is the precise and elevated expression for giving up hope." }, { meta: "Fill-in-the-Blank", stem: "Mars ipse, oculīs ārdentibus, animōs mīlitum _________ et ad pugnam vehementius incitāvit.", options: ["incendit", "ērexit", "dūxit", "vertit"], i: 0, explanation: "The sentence describes Mars, with burning eyes, acting upon the soldiers' spirits to incite them to battle. <b>Incendit</b> (inflamed, set on fire) from <i>incendō, incendere</i> is a powerful and frequently used verb in epic poetry to describe the rousing of passions or spirits, making it the most evocative choice for Mars's influence. <b>Ērexit</b> (roused, raised) is also plausible but less intense. <b>Dūxit</b> (led) and <b>vertit</b> (turned) do not convey the fiery emotional stirring implied by 'oculīs ārdentibus' and 'incitāvit'." }, { meta: "Fill-in-the-Blank", stem: "Populus Rōmānus, nōn semper _________, aliquandō vōcibus clāmōribusque senātum terruit.", options: ["placida", "tranquilla", "quiēta", "turbulenta"], i: 3, explanation: "The sentence states that the Roman people were 'not always ______' and sometimes 'terrified the senate with shouts and cries'. This implies that the missing word should describe the opposite of their unruly behavior. Therefore, if they were 'not always <b>turbulenta</b>' (turbulent, restless), it means they were sometimes peaceful, which contrasts with their capacity to terrify the senate. Options A, B, and C (<b>placida</b>, <b>tranquilla</b>, <b>quiēta</b> – all meaning calm or peaceful) would create a contradictory statement if negated, as 'not always peaceful' would imply they were sometimes turbulent, which is the behavior described. The correct choice is the word whose negation aligns with the context." }, { meta: "Fill-in-the-Blank", stem: "Subitō ingēns _________ caelum complēvit, dum fulmina ā Iove mittēbantur.", options: ["fragor", "clāmor", "terror", "dolor"], i: 0, explanation: "The sentence describes a huge sound filling the sky as lightning bolts were sent by Jupiter. <b>Fragor</b> (crash, roar, din) from <i>fragor, fragōris</i> m. is the most appropriate term for the loud, violent sound associated with thunder and lightning. While <b>clāmor</b> (shout, cry) is a loud noise, it typically refers to human or animal cries. <b>Terror</b> (terror) is an emotion, not a sound. <b>Dolor</b> (pain, grief) is also an emotion. All options are 3rd declension masculine nominative singular nouns, but only <i>fragor</i> fits the semantic context." }, { meta: "Circumlocution", stem: "Quī nōn longē ā nōbīs habitat aut quī familiā nōbīs coniūnctus est.", options: ["propinquus", "vicīnus", "amīcus", "socius"], i: 0, explanation: "The Latin word <b>propinquus</b> (m. 2nd declension) means 'kinsman', 'relative', or 'neighbor'. The definition, \"He who lives not far from us or who is connected to us by family,\" encompasses both meanings, making <b>propinquus</b> the best fit. <i>Vicīnus</i> (m. 2nd) specifically means 'neighbor', <i>amīcus</i> (m. 2nd) means 'friend', and <i>socius</i> (m. 2nd) means 'ally' or 'companion'. All options are masculine nouns of the second declension." }, { meta: "Circumlocution", stem: "Arma vel rēs aliī hostī dētractae post victōriam.", options: ["spolia", "arma", "praemia", "impedīmenta"], i: 0, explanation: "The term <b>spolia</b> (n. pl. 2nd declension) refers specifically to the 'spoils of war', items stripped from a defeated enemy after victory, as described by the definition. <i>Arma</i> (n. pl. 2nd) means 'arms' or 'weapons' generally. <i>Praemia</i> (n. pl. 2nd) are 'rewards' or 'prizes', which are not necessarily taken from an enemy. <i>Impedīmenta</i> (n. pl. 2nd) refers to 'baggage' or 'hindrances'. All options are neuter plural nouns of the second declension." }, { meta: "Circumlocution", stem: "Locus quō terra vel rēgnum dēsinit, aut terminus alicuius reī.", options: ["fīnis", "līmes", "orbis", "collis"], i: 0, explanation: "<b>Fīnis</b> (m. 3rd declension) means 'end', 'boundary', or 'territory'. The definition, \"A place where land or a kingdom ends, or the limit of something,\" perfectly describes <b>fīnis</b>. <i>Līmes</i> (m. 3rd) means 'boundary' or 'frontier path', a very close distractor. <i>Orbis</i> (m. 3rd) means 'circle' or 'world'. <i>Collis</i> (m. 3rd) means 'hill'. All options are masculine nouns of the third declension." }, { meta: "Circumlocution", stem: "Suāvis pressiō labrōrum in alterius labra vel faciem, amōris signum.", options: ["ōsculum", "bāsium", "labrum", "dōnum"], i: 0, explanation: "<b>Ōsculum</b> (n. 2nd declension) is a 'kiss', often a tender or poetic one, and a 'sign of love', which aligns with the definition. <i>Bāsium</i> (n. 2nd) is also a 'kiss', sometimes implying a more passionate one, making it an excellent distractor. <i>Labrum</i> (n. 2nd) means 'lip', and <i>dōnum</i> (n. 2nd) means 'gift'. All options are neuter nouns of the second declension." }, { meta: "Circumlocution", stem: "Ignis caelestis quī subitō ē nūbibus cadit cum magnō sonitū.", options: ["fulmen", "nūmen", "flūmen", "lūmen"], i: 0, explanation: "<b>Fulmen</b> (n. 3rd declension) is a 'lightning bolt', which is accurately described as \"celestial fire that suddenly falls from the clouds with a great sound.\" <i>Nūmen</i> (n. 3rd) means 'divine will' or 'divine power'. <i>Flūmen</i> (n. 3rd) means 'river'. <i>Lūmen</i> (n. 3rd) means 'light'. All options are neuter nouns of the third declension." }, { meta: "Circumlocution", stem: "Quī rem aliquam scit et particeps est cōnsiliī occultī.", options: ["cōnscius", "socius", "amīcus", "nūntius"], i: 0, explanation: "As a noun, <b>cōnscius</b> (m. 2nd declension) means 'accomplice' or 'confidant', someone who is 'privy to' or 'aware of' a secret plan, as stated in the definition. <i>Socius</i> (m. 2nd) is an 'ally' or 'companion'. <i>Amīcus</i> (m. 2nd) is a 'friend'. <i>Nūntius</i> (m. 2nd) is a 'messenger'. All options are masculine nouns of the second declension." }, { meta: "Circumlocution", stem: "Vasta et plāna spatium aquae vel terrae.", options: ["aequor", "mare", "flūmen", "lītus"], i: 0, explanation: "<b>Aequor</b> (n. 3rd declension) means a 'level surface', 'plain', or poetically, the 'sea'. The definition, \"A vast and level space of water or land,\" fits <b>aequor</b> best because it encompasses both water and land. <i>Mare</i> (n. 3rd) means 'sea'. <i>Flūmen</i> (n. 3rd) means 'river'. <i>Lītus</i> (n. 3rd) means 'shore'. All options are neuter nouns of the third declension." }, { meta: "Circumlocution", stem: "Locus cavus et obscūrus in terrā vel monte, ubi ferae saepe habitant.", options: ["specus", "lacus", "portus", "domus"], i: 0, explanation: "<b>Specus</b> (m./f. 4th declension) means 'cave' or 'grotto'. The definition, \"A hollow and dark place in the earth or a mountain, where wild beasts often live,\" perfectly describes a cave. <i>Lacus</i> (m. 4th) means 'lake'. <i>Portus</i> (m. 4th) means 'harbor'. <i>Domus</i> (f. 4th/2nd) means 'house' or 'home'. All options are nouns of the fourth declension (<i>domus</i> having forms from both 2nd and 4th but primarily considered 4th)." }, { meta: "Circumlocution", stem: "Potestās dīvīna vel voluntās deī, quae rēs omnēs regit.", options: ["nūmen", "carmen", "flāmen", "lūmen"], i: 0, explanation: "<b>Nūmen</b> (n. 3rd declension) refers to 'divine will', 'divine power', or a 'deity' itself, which governs all things, as the definition states. <i>Carmen</i> (n. 3rd) is a 'song', 'poem', or 'prophecy'. <i>Flāmen</i> (n. 3rd) is a 'priest'. <i>Lūmen</i> (n. 3rd) is 'light'. All options are neuter nouns of the third declension." }, { meta: "Circumlocution", stem: "Id quod animō trīstī lēnitātem affert et dolōrem minuit.", options: ["sōlācium", "auxilium", "remedium", "gaudium"], i: 0, explanation: "<b>Sōlācium</b> (n. 2nd declension) means 'comfort' or 'consolation', specifically that which brings gentleness to a sad mind and lessens pain. <i>Auxilium</i> (n. 2nd) means 'help' or 'aid'. <i>Remedium</i> (n. 2nd) means 'cure' or 'remedy'. <i>Gaudium</i> (n. 2nd) means 'joy'. While related, <b>sōlācium</b> most precisely describes the emotional relief from sadness and pain. All options are neuter nouns of the second declension." }, { meta: "Latin to English", stem: "What is the best translation of <i>aetās</i>?", options: ["age", "summer", "sky", "sea"], i: 0, explanation: "The correct answer is <b>A. age</b>. The Latin word <i>aetās, aetātis</i> (f.) means 'age' or 'time of life'. Distractor B, 'summer', is the translation of <i>aestās, aestātis</i>, which is visually and phonetically similar. Distractor C, 'sky' or 'upper air', is the translation of <i>aether, aetheris</i>. Distractor D, 'sea' or 'level surface', is the translation of <i>aequor, aequoris</i>. All are third declension nouns." }, { meta: "Latin to English", stem: "What is the best translation of <i>cōnūbium</i>?", options: ["marriage", "plan", "contact", "boundary"], i: 0, explanation: "The correct answer is <b>A. marriage</b>. The Latin word <i>cōnūbium, cōnūbiī</i> (n.) refers to 'marriage' or 'the right of intermarriage'. Distractor B, 'plan' or 'counsel', is the translation of <i>cōnsilium, cōnsiliī</i>. Distractor C, 'contact' or 'contagion', is the translation of <i>contāgium, contāgiī</i>. Distractor D, 'common boundary' or 'neighborhood', is the translation of <i>cōnfīnium, cōnfīniī</i>. All are second declension neuter nouns, making them visually and morphologically similar." }, { meta: "Latin to English", stem: "What is the best translation of <i>dēfīxus</i>?", options: ["spellbound", "failed", "defended", "exhausted"], i: 0, explanation: "The correct answer is <b>A. spellbound</b>. <i>Dēfīxus, -a, -um</i> is the perfect passive participle of <i>dēfīgō</i>, meaning 'fixed', 'rooted', or metaphorically 'spellbound'. Distractor B, 'failed' or 'deficient', is the translation of <i>dēfectus, -a, -um</i> (from <i>dēficiō</i>). Distractor C, 'defended', is the translation of <i>dēfēnsus, -a, -um</i> (from <i>dēfendō</i>). Distractor D, 'exhausted' or 'weary', is the translation of the adjective <i>dēfessus, -a, -um</i>. All are similar in form to participles." }, { meta: "Latin to English", stem: "What is the best translation of <i>fīdus</i>?", options: ["faithful", "festive", "split", "wild"], i: 0, explanation: "The correct answer is <b>A. faithful</b>. The Latin word <i>fīdus, -a, -um</i> is an adjective meaning 'faithful' or 'trustworthy'. Distractor B, 'festive' or 'holiday', is the translation of <i>fēstus, -a, -um</i>. Distractor C, 'split' or 'cloven', is the translation of <i>fissus, -a, -um</i> (the participle of <i>findō</i>). Distractor D, 'wild' or 'savage', is the translation of <i>fērus, -a, -um</i>. All options are adjectives or participles with similar endings." }, { meta: "Latin to English", stem: "What is the best translation of <i>līmen</i>?", options: ["threshold", "light", "river", "name"], i: 0, explanation: "The correct answer is <b>A. threshold</b>. The Latin word <i>līmen, līminis</i> (n.) means 'threshold' or 'doorway'. Distractor B, 'light' or 'lamp', is the translation of <i>lūmen, lūminis</i>. Distractor C, 'river', is the translation of <i>flūmen, flūminis</i>. Distractor D, 'name', is the translation of <i>nōmen, nōminis</i>. All are third declension neuter nouns with similar endings, making them easily confused." }, { meta: "Latin to English", stem: "What is the best translation of <i>mīror</i>?", options: ["to wonder at", "to delay", "to change", "to threaten"], i: 0, explanation: "The correct answer is <b>A. to wonder at</b>. The Latin verb <i>mīror, mīrārī, mīrātus sum</i> is a first conjugation deponent verb meaning 'to wonder at' or 'to admire'. Distractor B, 'to delay', is the translation of <i>moror, morārī, morātus sum</i>, another first conjugation deponent verb. Distractor C, 'to change', is the translation of <i>mūtō, mūtāre, mūtāvī, mūtātum</i>. Distractor D, 'to threaten', is the translation of <i>minor, minārī, minātus sum</i>, also a first conjugation deponent verb. These verbs are all visually and phonetically similar." }, { meta: "Latin to English", stem: "What is the best translation of <i>nūmen</i>?", options: ["divine will", "light", "omen", "name"], i: 0, explanation: "The correct answer is <b>A. divine will</b>. The Latin word <i>nūmen, nūminis</i> (n.) means 'divine will', 'divine power', or 'divinity'. Distractor B, 'light', is the translation of <i>lūmen, lūminis</i>. Distractor C, 'omen' or 'sign', is the translation of <i>ōmen, ōminis</i>. Distractor D, 'name', is the translation of <i>nōmen, nōminis</i>. All are third declension neuter nouns that are very similar in form, making them frequently confused." }, { meta: "Latin to English", stem: "What is the best translation of <i>ōra</i>?", options: ["shore", "breeze", "altar", "work"], i: 0, explanation: "The correct answer is <b>A. shore</b>. The Latin word <i>ōra, ōrae</i> (f.) means 'shore', 'coast', or 'border'. Distractor B, 'breeze' or 'air', is the translation of <i>aura, aurae</i>. Distractor C, 'altar', is the translation of <i>āra, ārae</i>. Distractor D, 'work' or 'effort', is the translation of <i>opera, operae</i>. All are first declension feminine nouns that are visually and phonetically similar." }, { meta: "Latin to English", stem: "What is the best translation of <i>palla</i>?", options: ["cloak", "palm", "ball", "girl"], i: 0, explanation: "The correct answer is <b>A. cloak</b>. The Latin word <i>palla, pallae</i> (f.) refers to a 'cloak' or 'mantle', especially one worn by women. Distractor B, 'palm' (of the hand or a tree), is the translation of <i>palma, palmae</i>. Distractor C, 'ball', is the translation of <i>pīla, pīlae</i>. Distractor D, 'girl' or 'doll', is the translation of <i>pūpa, pūpae</i>. All are first declension feminine nouns, making them visually similar." }, { meta: "Latin to English", stem: "What is the best translation of <i>queror</i>?", options: ["to complain", "to seek", "to follow", "to speak"], i: 0, explanation: "The correct answer is <b>A. to complain</b>. The Latin verb <i>queror, querī, questus sum</i> is a third conjugation deponent verb meaning 'to complain' or 'to lament'. Distractor B, 'to seek' or 'to ask', is the translation of <i>quaerō, quaerere, quaesīvī, quaesītum</i>, an active third conjugation verb. Distractor C, 'to follow', is the translation of <i>sequor, sequī, secūtus sum</i>, a third conjugation deponent verb. Distractor D, 'to speak', is the translation of <i>loquor, loquī, locūtus sum</i>, also a third conjugation deponent verb. These verbs are often confused due to their similar forms and meanings." }, { meta: "Latin to English", stem: "What is the best translation of <i>sōlācium</i>?", options: ["comfort", "silence", "space", "sacrifice"], i: 0, explanation: "The correct answer is <b>A. comfort</b>. The Latin word <i>sōlācium, sōlāciī</i> (n.) means 'comfort' or 'solace'. Distractor B, 'silence', is the translation of <i>silentium, silentiī</i>. Distractor C, 'space' or 'interval', is the translation of <i>spatium, spatiī</i>. Distractor D, 'sacrifice', is the translation of <i>sacrificium, sacrificiī</i>. All are second declension neuter nouns, making them visually and morphologically similar." }, { meta: "Latin to English", stem: "What is the best translation of <i>stīpes</i>?", options: ["tree trunk", "root", "hedge", "staff"], i: 0, explanation: "The correct answer is <b>A. tree trunk</b>. The Latin word <i>stīpes, stīpitis</i> (m.) means 'tree trunk', 'post', or 'stake'. Distractor B, 'root', 'stock', or 'lineage', is the translation of <i>stirps, stirpis</i> (f.). Distractor C, 'hedge' or 'fence', is the translation of <i>sēpes, sēpis</i> (f.). Distractor D, 'staff' or 'scepter', is the translation of <i>scīpiō, scīpiōnis</i> (m.). All are third declension nouns that are visually similar and can be confused." }, { meta: "Latin to English", stem: "What is the best translation of <i>tegmen</i>?", options: ["covering", "seed", "song", "column"], i: 0, explanation: "The correct answer is <b>A. covering</b>. The Latin word <i>tegmen, tegminis</i> (n.) means 'covering', 'shield', or 'clothing'. Distractor B, 'seed', is the translation of <i>sēmen, sēminis</i>. Distractor C, 'song' or 'poem', is the translation of <i>carmen, carminis</i>. Distractor D, 'column' or 'army on the march', is the translation of <i>agmen, agminis</i>. All are third declension neuter nouns with similar '-men' endings." }, { meta: "Latin to English", stem: "What is the best translation of <i>vātēs</i>?", options: ["prophet", "vine", "light-armed soldiers", "strength"], i: 0, explanation: "The correct answer is <b>A. prophet</b>. The Latin word <i>vātēs, vātis</i> (m./f.) means 'prophet', 'seer', 'poet', or 'bard'. Distractor B, 'vine', is the translation of <i>vītis, vītis</i> (f.). Distractor C, 'light-armed soldiers', is the translation of <i>vēlēs, vēlitum</i> (m. pl.). Distractor D, 'strength' or 'forces', is the translation of <i>vīrēs, vīrium</i> (f. pl., from <i>vīs</i>). All are third declension nouns, often confused due to similar stems or endings." }, { meta: "Latin to English", stem: "What is the best translation of <i>voluptās</i>?", options: ["pleasure", "book", "will", "bird"], i: 0, explanation: "The correct answer is <b>A. pleasure</b>. The Latin word <i>voluptās, voluptātis</i> (f.) means 'pleasure' or 'delight'. Distractor B, 'roll' or 'book', is the translation of <i>volūmen, volūminis</i> (n.). Distractor C, 'will' or 'desire', is the translation of <i>voluntās, voluntātis</i> (f.). Distractor D, 'bird', is the translation of <i>volūcris, volūcris</i> (f.). All are third declension nouns, and their similar initial syllables and endings can cause confusion." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to shun, avoid", options: ["vītāre", "fugere", "dēclīnāre", "ēvādere"], i: 0, explanation: "The most precise translation for 'to shun' or 'to avoid' in the sense of keeping away from something or someone is <b>vītāre</b>. <b>Fugere</b> means 'to flee' or 'to run away from,' implying active escape. <b>Dēclīnāre</b> means 'to turn aside' or 'to deflect,' often in a physical or grammatical sense. <b>Ēvādere</b> means 'to escape' or 'to get away from,' focusing on successful evasion." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to mourn, lament", options: ["lūgēre", "flēre", "gemere", "plōrāre"], i: 0, explanation: "<b>Lūgēre</b> specifically means 'to mourn' or 'to express grief,' often implying a prolonged period of sorrow or public mourning. <b>Flēre</b> means 'to weep' or 'to cry.' <b>Gemere</b> means 'to groan' or 'to sigh,' often indicating pain or distress. <b>Plōrāre</b> means 'to wail' or 'to lament loudly,' suggesting a more vocal and intense expression of grief." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: darkness, gloom", options: ["calīgō, calīginis (f.)", "nox, noctis (f.)", "lūmen, lūminis (n.)", "tempestās, tempestātis (f.)"], i: 0, explanation: "<b>Calīgō</b> refers to a thick mist, fog, or gloom, often obscuring vision or creating a sense of dread. <b>Nox</b> means 'night,' which is a period of darkness but not necessarily gloom or mist. <b>Lūmen</b> means 'light' or 'lamp,' an antonym. <b>Tempestās</b> means 'storm' or 'season,' unrelated to darkness." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: star, constellation", options: ["sīdus, sīderis (n.)", "aether, aetheris (m.)", "lūmen, lūminis (n.)", "ignis, ignis (m.)"], i: 0, explanation: "<b>Sīdus</b> refers to a star, a constellation, or a celestial body, often with a poetic connotation. <b>Aether</b> means 'upper air,' 'sky,' or 'heaven,' often used poetically for the abode of stars. <b>Lūmen</b> means 'light' or 'lamp,' and while stars emit light, it's not their primary designation. <b>Ignis</b> means 'fire,' and while stars are fiery, it's not the direct translation for 'star.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: fierce, savage", options: ["saevus, -a, -um", "ferus, -a, -um", "atrōx, atrōcis", "crūdēlis, crūdēle"], i: 0, explanation: "<b>Saevus</b> means 'fierce,' 'savage,' 'cruel,' often implying an uncontrolled or destructive force, rage, or wildness. <b>Ferus</b> means 'wild,' 'untamed,' or 'savage' like a wild beast. <b>Atrōx</b> means 'fierce,' 'cruel,' 'terrible,' or 'dreadful,' often describing actions or character. <b>Crūdēlis</b> means 'cruel' or 'harsh,' focusing on the infliction of suffering." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to happen, occur", options: ["accidere", "contingere", "ēvenīre", "fīerī"], i: 0, explanation: "<b>Accidere</b> is a general term for 'to happen' or 'to occur,' often implying something unexpected or by chance, and can be used for both good and bad events. <b>Contingere</b> also means 'to happen' or 'to befall,' but often implies good fortune or a specific outcome. <b>Ēvenīre</b> means 'to come out,' 'to result,' or 'to happen,' with a focus on the outcome or conclusion. <b>Fīerī</b> means 'to become,' 'to happen,' or 'to be made,' often as the passive of <i>facere</i>." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to entreat, implore", options: ["obsecrāre", "ōrāre", "precārī", "supplicāre"], i: 0, explanation: "<b>Obsecrāre</b> means 'to entreat' or 'to implore,' often by appealing to something sacred or by adjuration. <b>Ōrāre</b> is a more general term meaning 'to pray,' 'to plead,' or 'to beg.' <b>Precārī</b> is a deponent verb meaning 'to pray,' 'to beg,' or 'to implore.' <b>Supplicāre</b> means 'to supplicate,' 'to pray humbly,' or 'to implore,' often with a sense of prostration or humility." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to scatter, strew", options: ["spargere", "fundere", "sternere", "diffundere"], i: 0, explanation: "<b>Spargere</b> means 'to scatter,' 'to strew,' or 'to sprinkle,' often of discrete particles or objects. <b>Fundere</b> means 'to pour,' 'to shed,' or 'to scatter,' often of liquids or loose, flowing materials. <b>Sternere</b> means 'to spread,' 'to strew,' or 'to lay low.' <b>Diffundere</b> means 'to spread out,' 'to diffuse,' or 'to pour forth.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to flow, stream", options: ["fluere", "labī", "manāre", "currere"], i: 0, explanation: "<b>Fluere</b> is the most direct and general translation for 'to flow' or 'to stream,' referring to the movement of liquids. <b>Labī</b> means 'to glide,' 'to slip,' or 'to flow,' often with a sense of gentle or imperceptible movement. <b>Manāre</b> means 'to flow,' 'to trickle,' or 'to spread,' often used for exudations or emanations. <b>Currere</b> means 'to run,' which can apply to water but is more general for rapid movement." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to seize, snatch", options: ["rapere", "corripere", "prehendere", "capere"], i: 0, explanation: "<b>Rapere</b> means 'to seize,' 'to snatch,' or 'to carry off by force,' often implying violence or haste. <b>Corripere</b> means 'to snatch up,' 'to seize,' or 'to carry off,' similar to <i>rapere</i> but can also mean 'to rebuke.' <b>Prehendere</b> means 'to grasp,' 'to seize,' or 'to take hold of,' focusing on the act of taking. <b>Capere</b> is a more general verb meaning 'to take,' 'to seize,' or 'to capture.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: old age", options: ["senectūs, senectūtis (f.)", "aetās, aetātis (f.)", "vetustās, vetustātis (f.)", "senex, senis (m./f.)"], i: 0, explanation: "<b>Senectūs</b> specifically refers to 'old age' as a period of life or the state of being old. <b>Aetās</b> means 'age' or 'time of life' in general, not exclusively old age. <b>Vetustās</b> refers to 'antiquity' or 'oldness' of things, rather than the age of a person. <b>Senex</b> is a noun meaning 'old man' or 'old woman,' or an adjective meaning 'old,' but not the abstract concept of 'old age.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to yield, give way", options: ["cēdere", "concēdere", "succumbere", "dēsilīre"], i: 0, explanation: "<b>Cēdere</b> is the most direct translation for 'to yield,' 'to give way,' or 'to withdraw,' implying a reluctant giving up of ground or position. <b>Concēdere</b> means 'to yield,' 'to grant,' or 'to concede,' often with a sense of permission or agreement. <b>Succumbere</b> means 'to fall under,' 'to succumb,' or 'to yield' under pressure. <b>Dēsilīre</b> means 'to leap down' or 'to dismount,' unrelated to yielding." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to pierce, transfix", options: ["trānsfīgere", "pungere", "perforāre", "fixere"], i: 0, explanation: "<b>Trānsfīgere</b> specifically means 'to pierce through' or 'to transfix,' implying that an object passes entirely through another. <b>Pungere</b> means 'to prick' or 'to sting,' suggesting a superficial piercing. <b>Perforāre</b> means 'to bore through' or 'to pierce,' often with a tool to make a hole. <b>Fixere</b> means 'to fix,' 'to fasten,' or 'to attach,' not to pierce." }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to weave", options: ["texere", "nectere", "implicāre", "serere"], i: 0, explanation: "<b>Texere</b> is the primary verb for 'to weave' or 'to plait,' referring to the creation of fabric or intricate patterns. <b>Nectere</b> means 'to bind,' 'to tie,' or 'to interweave,' focusing on connecting elements. <b>Implicāre</b> means 'to entangle,' 'to enfold,' or 'to involve.' <b>Serere</b> means 'to sow' or 'to plant,' though it can also mean 'to join' or 'to intertwine' in some contexts, it's less common for 'to weave.'" }, { meta: "English to Latin", stem: "Choose the best Latin translation for the English word: to warn, advise", options: ["monēre", "suādēre", "praecipere", "hortārī"], i: 0, explanation: "<b>Monēre</b> means 'to warn,' 'to advise,' or 'to remind,' often with a sense of caution or instruction. <b>Suādēre</b> means 'to advise,' 'to recommend,' or 'to persuade,' focusing on influencing an opinion or action. <b>Praecipere</b> means 'to instruct,' 'to order,' or 'to anticipate.' <b>Hortārī</b> is a deponent verb meaning 'to urge' or 'to encourage,' often with exhortation." }, { meta: "Synonyms", stem: "hortor", options: ["incitō", "moneō", "suādeō", "iubeō"], i: 0, explanation: "The verb <b>hortor, hortārī, hortātus sum</b> means 'to urge, encourage'. The closest synonym among the options is <b>incitō, incitāre, incitāvī, incitātum</b>, meaning 'to rouse, incite, urge on'. While <b>moneō</b> means 'to warn, advise', <b>suādeō</b> means 'to persuade, advise', and <b>iubeō</b> means 'to order, command', these verbs imply different degrees or types of influence, making <b>incitō</b> the most direct and vigorous synonym for 'urging'." }, { meta: "Synonyms", stem: "cōnor", options: ["temptō", "studeō", "labōrō", "peragō"], i: 0, explanation: "The verb <b>cōnor, cōnārī, cōnātus sum</b> means 'to try, attempt'. Its closest synonym is <b>temptō, temptāre, temptāvī, temptātum</b>, which also means 'to try, attempt, test'. <b>Studeō</b> means 'to be eager, strive for', implying a strong desire rather than the act of trying. <b>Labōrō</b> means 'to toil, work', focusing on effort rather than an attempt. <b>Peragō</b> means 'to complete, carry through', which is the outcome of an attempt, not the attempt itself." }, { meta: "Synonyms", stem: "ignis", options: ["flamma", "cinis", "fūmus", "ardor"], i: 0, explanation: "The noun <b>ignis, ignis</b> m. means 'fire'. The most direct synonym is <b>flamma, flammae</b> f., meaning 'flame, fire'. <b>Cinis, cineris</b> m./f. means 'ashes', which are the residue of fire. <b>Fūmus, fūmī</b> m. means 'smoke', a product of fire. <b>Ardor, ardōris</b> m. means 'burning, heat, passion', an effect or quality of fire, but not 'fire' itself." }, { meta: "Synonyms", stem: "celer", options: ["vēlōx", "alacer", "praeceps", "levis"], i: 0, explanation: "The adjective <b>celer, celeris, celere</b> means 'swift, quick'. The closest synonym is <b>vēlōx, vēlōcis</b>, which means 'swift, rapid'. <b>Alacer, alacris, alacre</b> means 'eager, lively, quick-moving', but emphasizes eagerness more than sheer speed. <b>Praeceps, praecipitis</b> means 'headlong, rash, precipitate', implying speed but also a lack of control or caution. <b>Levis, leve</b> means 'light, slight, fickle', which can sometimes imply quickness due to lack of weight, but is not a direct synonym for 'swift'." }, { meta: "Synonyms", stem: "mīror", options: ["stupeō", "veneror", "adōrō", "contemplor"], i: 0, explanation: "The verb <b>mīror, mīrārī, mīrātus sum</b> means 'to wonder at, admire'. The closest synonym is <b>stupeō, stupēre, stupuī</b>, meaning 'to be amazed, stunned, bewildered'. While <b>veneror</b> ('to revere, worship') and <b>adōrō</b> ('to worship, adore') involve a high degree of admiration, they imply religious or profound respect beyond mere wonder. <b>Contemplor</b> ('to gaze at, observe') describes the act of looking intently, but does not necessarily include the element of wonder or amazement." }, { meta: "Synonyms", stem: "loquor", options: ["dicō", "fāror", "ōrō", "narrō"], i: 0, explanation: "The verb <b>loquor, loquī, locūtus sum</b> means 'to speak, talk'. The most common and direct synonym is <b>dicō, dīcere, dīxī, dictum</b>, meaning 'to say, tell, speak'. <b>Fāror, fārī, fātus sum</b> also means 'to speak, say', but is generally more poetic or archaic. <b>Ōrō</b> means 'to plead, pray, beg', a specific type of speaking. <b>Narrō</b> means 'to tell, relate, recount', which implies a longer, more detailed form of speaking." }, { meta: "Synonyms", stem: "pulcher", options: ["formōsus", "decorus", "splendidus", "honestus"], i: 0, explanation: "The adjective <b>pulcher, pulchra, pulchrum</b> means 'beautiful, handsome'. Its closest synonym is <b>formōsus, formōsa, formōsum</b>, which also means 'beautiful, handsome, shapely'. <b>Decorus, decora, decorum</b> means 'fitting, proper, graceful', implying an aesthetic quality but not necessarily beauty itself. <b>Splendidus, splendida, splendidum</b> means 'splendid, brilliant, magnificent', suggesting grandeur rather than intrinsic beauty. <b>Honestus, honesta, honestum</b> means 'honorable, respectable', referring to moral rather than physical beauty." }, { meta: "Synonyms", stem: "nox", options: ["tenebrae", "umbra", "calīgō", "obscūritās"], i: 0, explanation: "The noun <b>nox, noctis</b> f. means 'night'. While all options relate to darkness, <b>tenebrae, tenebrārum</b> f. pl. is the most direct synonym for 'darkness' or 'the darkness of night'. <b>Umbra, umbrae</b> f. means 'shade, shadow', a localized absence of light. <b>Calīgō, calīginis</b> f. means 'mist, fog, gloom, darkness', implying a thick, obscuring darkness. <b>Obscūritās, obscūritātis</b> f. means 'darkness, obscurity', but can also refer to lack of clarity or fame, making <b>tenebrae</b> a more specific and common poetic synonym for the darkness of night." }, { meta: "Synonyms", stem: "timor", options: ["pavor", "formīdō", "horror", "maeror"], i: 0, explanation: "The noun <b>timor, timōris</b> m. means 'fear'. The closest synonym is <b>pavor, pavōris</b> m., meaning 'panic, terror, dread', which is an intense form of fear. <b>Formīdō, formīdinis</b> f. also means 'fear, terror, dread', but often with an emphasis on the object causing fear. <b>Horror, horrōris</b> m. means 'shuddering, dread, horror', often implying a physical reaction to fear or revulsion. <b>Maeror, maerōris</b> m. means 'sadness, grief', which is a distinct emotion from fear." }, { meta: "Synonyms", stem: "mors", options: ["lētum", "fūnus", "exitium", "interitus"], i: 0, explanation: "The noun <b>mors, mortis</b> f. means 'death'. The most direct synonym, especially in poetic contexts, is <b>lētum, lētī</b> n., meaning 'death, destruction'. <b>Fūnus, fūneris</b> n. refers to a 'funeral' or 'death' as an event, rather than the state itself. <b>Exitium, exitiī</b> n. and <b>interitus, interitūs</b> m. both mean 'destruction, ruin', which can be a consequence of death but are not direct synonyms for 'death' as a state of being." }, { meta: "Synonyms", stem: "arma", options: ["tēla", "ferrum", "gladius", "scūtum"], i: 0, explanation: "The plural noun <b>arma, armōrum</b> n. means 'arms, weapons' (especially defensive armor and offensive weapons collectively). The closest synonym for 'weapons' in general, often with an emphasis on missiles, is <b>tēla, tēlōrum</b> n. pl., meaning 'weapons, missiles'. <b>Ferrum, ferrī</b> n. means 'iron' but is often used metonymically for 'sword' or 'weapon'. <b>Gladius, gladiī</b> m. is a specific type of weapon, a 'sword'. <b>Scūtum, scūtī</b> n. is a 'shield', a piece of defensive equipment, not an offensive weapon." }, { meta: "Synonyms", stem: "vīvus", options: ["vīvēns", "aeternus", "immortālis", "sānus"], i: 0, explanation: "The adjective <b>vīvus, vīva, vīvum</b> means 'alive, living'. The present participle <b>vīvēns, vīventis</b> also means 'living, alive', and functions as a direct synonym. <b>Aeternus, aeterna, aeternum</b> means 'eternal, everlasting', referring to duration rather than the state of being alive. <b>Immortālis, immortāle</b> means 'immortal', referring to not being subject to death. <b>Sānus, sāna, sānum</b> means 'healthy, sound', referring to a state of well-being, not necessarily life itself." }, { meta: "Synonyms", stem: "fātum", options: ["sors", "fortūna", "cāsus", "arbitrium"], i: 0, explanation: "The noun <b>fātum, fātī</b> n. means 'fate, destiny'. The closest synonym is <b>sors, sortis</b> f., which means 'lot, fate, destiny', often with the nuance of an allotted portion or outcome. <b>Fortūna, fortūnae</b> f. means 'fortune, luck, chance', which can include fate but also implies randomness or good/bad luck. <b>Cāsus, cāsūs</b> m. means 'fall, chance, accident', emphasizing randomness or an unforeseen event. <b>Arbitrium, arbitriī</b> n. means 'judgment, decision, will', which stands in contrast to the concept of predetermined fate." }, { meta: "Synonyms", stem: "caedō", options: ["occīdō", "necō", "trucīdō", "feriō"], i: 0, explanation: "The verb <b>caedō, caedere, cecīdī, caesum</b> means 'to cut, kill, strike down'. The most direct synonym for 'to kill' is <b>occīdō, occīdere, occīdī, occīsum</b>, meaning 'to kill, cut down'. While <b>necō, necāre, necāvī, necātum</b> also means 'to kill, murder', and <b>trucīdō, trucīdāre, trucīdāvī, trucīdātum</b> means 'to slaughter, butcher', <b>occīdō</b> is often a more general term for killing, closely matching the 'strike down' sense of <b>caedō</b>. <b>Feriō, ferīre, ferīvī/feriī, ferītum</b> means 'to strike, hit', which can lead to killing but is not synonymous with 'to kill' itself." }, { meta: "Synonyms", stem: "vōx", options: ["sonus", "clāmor", "strepitus", "murmur"], i: 0, explanation: "The noun <b>vōx, vōcis</b> f. means 'voice, sound'. The most general and direct synonym for 'sound' is <b>sonus, sonī</b> m. <b>Clāmor, clāmōris</b> m. means 'shout, cry', a specific type of loud sound. <b>Strepitus, strepitūs</b> m. means 'noise, din, rattling', often implying a confused or unpleasant sound. <b>Murmur, murmuris</b> n. means 'murmur, roar, rumble', a low or continuous sound. Thus, <b>sonus</b> is the broadest and most fitting synonym for 'sound' in general." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>oblivīscor</b>?", options: ["meminī", "patior", "sequor", "loquor"], i: 0, explanation: "The verb <b>oblivīscor</b> means 'to forget'. Its direct antonym is <b>meminī</b>, 'to remember'.<br>Option B, <b>patior</b>, means 'to suffer' or 'to allow'.<br>Option C, <b>sequor</b>, means 'to follow'.<br>Option D, <b>loquor</b>, means 'to speak'. All options are deponent verbs, matching the grammatical category of <b>oblivīscor</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>cōnfiteor</b>?", options: ["negō", "abnuō", "recūsō", "dissimulō"], i: 0, explanation: "The verb <b>cōnfiteor</b> means 'to confess' or 'to admit'. Its closest antonym is <b>negō</b>, 'to deny'.<br>Option B, <b>abnuō</b>, means 'to refuse' or 'to deny by a sign', which is a related but less direct antonym.<br>Option C, <b>recūsō</b>, means 'to refuse' or 'to object'.<br>Option D, <b>dissimulō</b>, means 'to disguise' or 'to conceal'. While related to not admitting, it's not a direct opposite of 'confess'." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>sōbrius</b>?", options: ["ēbrius", "lassus", "aeger", "stupidus"], i: 0, explanation: "The adjective <b>sōbrius</b> means 'sober' or 'temperate'. Its direct antonym is <b>ēbrius</b>, 'drunk' or 'intoxicated'.<br>Option B, <b>lassus</b>, means 'tired' or 'weary'.<br>Option C, <b>aeger</b>, means 'sick' or 'ill'.<br>Option D, <b>stupidus</b>, means 'stupid' or 'amazed'. All options are 1st/2nd declension adjectives, matching the grammatical category of <b>sōbrius</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>odiōsus</b>?", options: ["cārus", "grātus", "laetus", "pulcher"], i: 0, explanation: "The adjective <b>odiōsus</b> means 'hateful' or 'odious'. Its closest antonym is <b>cārus</b>, meaning 'dear' or 'beloved'.<br>Option B, <b>grātus</b>, means 'pleasing' or 'agreeable', which is a related but less direct antonym.<br>Option C, <b>laetus</b>, means 'happy' or 'joyful'.<br>Option D, <b>pulcher</b>, means 'beautiful'. All options are 1st/2nd declension adjectives, matching the grammatical category of <b>odiōsus</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>paupertās</b>?", options: ["opēs", "fāmēs", "labor", "voluptās"], i: 0, explanation: "The noun <b>paupertās</b> means 'poverty'. Its closest antonym is <b>opēs, opum</b> (plural), meaning 'resources' or 'wealth'.<br>Option B, <b>fāmēs</b>, means 'hunger'.<br>Option C, <b>labor</b>, means 'toil' or 'labor'.<br>Option D, <b>voluptās</b>, means 'pleasure'. All options are 3rd declension nouns, matching the grammatical category of <b>paupertās</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>cōnsūmō</b>?", options: ["struō", "gignō", "faciō", "solvō"], i: 0, explanation: "The verb <b>cōnsūmō</b> means 'to consume', 'to use up', or 'to destroy'. Its closest antonym is <b>struō</b>, 'to build' or 'to arrange'.<br>Option B, <b>gignō</b>, means 'to beget' or 'to produce', which is related but less about physical construction.<br>Option C, <b>faciō</b>, means 'to make' or 'to do', which is more general.<br>Option D, <b>solvō</b>, means 'to loosen', 'to release', or 'to pay'. All options are 3rd conjugation verbs (or 3rd -io), matching the grammatical category of <b>cōnsūmō</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>hostis</b>?", options: ["cīvis", "comes", "dux", "fīnis"], i: 0, explanation: "The noun <b>hostis</b> means 'enemy', particularly a public or national enemy. Its closest antonym, in a civic or political sense, is <b>cīvis</b>, 'citizen'.<br>Option B, <b>comes</b>, means 'companion' or 'comrade'.<br>Option C, <b>dux</b>, means 'leader'.<br>Option D, <b>fīnis</b>, means 'boundary' or 'end'. All options are 3rd declension nouns, matching the grammatical category of <b>hostis</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>ignārus</b>?", options: ["perītus", "doctus", "callidus", "cautus"], i: 0, explanation: "The adjective <b>ignārus</b> means 'ignorant' or 'unaware'. Its closest antonym is <b>perītus</b>, 'skilled' or 'experienced'.<br>Option B, <b>doctus</b>, means 'learned' or 'taught', which is related but emphasizes acquired knowledge rather than practical skill or experience.<br>Option C, <b>callidus</b>, means 'clever' or 'shrewd'.<br>Option D, <b>cautus</b>, means 'cautious'. All options are 1st/2nd declension adjectives, matching the grammatical category of <b>ignārus</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>trīstis</b>?", options: ["fēlīx", "hilaris", "gravis", "mītis"], i: 0, explanation: "The adjective <b>trīstis</b> means 'sad' or 'gloomy'. Its closest antonym is <b>fēlīx</b>, 'lucky', 'happy', or 'fortunate'.<br>Option B, <b>hilaris</b>, means 'cheerful' or 'lively', which is a close synonym but <b>fēlīx</b> implies a deeper state of well-being.<br>Option C, <b>gravis</b>, means 'heavy' or 'serious'.<br>Option D, <b>mītis</b>, means 'mild' or 'gentle'. All options are 3rd declension adjectives, matching the grammatical category of <b>trīstis</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>vetus</b>?", options: ["recēns", "iuvenis", "viridis", "brevis"], i: 0, explanation: "The adjective <b>vetus</b> means 'old' or 'ancient'. Its closest antonym is <b>recēns</b>, 'recent' or 'fresh'.<br>Option B, <b>iuvenis</b>, means 'young', typically referring to a person.<br>Option C, <b>viridis</b>, means 'green' or 'fresh', often used for plants or a vibrant state.<br>Option D, <b>brevis</b>, means 'short'. All options are 3rd declension adjectives, matching the grammatical category of <b>vetus</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>incipiō</b>?", options: ["dēsinō", "perficiō", "claudō", "intermittō"], i: 0, explanation: "The verb <b>incipiō</b> means 'to begin'. Its direct antonym is <b>dēsinō</b>, 'to cease' or 'to stop'.<br>Option B, <b>perficiō</b>, means 'to complete' or 'to finish', which implies bringing something to a successful end, rather than simply stopping.<br>Option C, <b>claudō</b>, means 'to close' or 'to shut'.<br>Option D, <b>intermittō</b>, means 'to interrupt' or 'to cease temporarily'. All options are 3rd conjugation verbs (or 3rd -io), matching the grammatical category of <b>incipiō</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>pudīcitia</b>?", options: ["luxuria", "lascīvia", "impudentia", "superbia"], i: 0, explanation: "The noun <b>pudīcitia</b> means 'chastity' or 'modesty', implying moral restraint and purity. Its closest antonym is <b>luxuria</b>, which can mean 'luxury' or 'extravagance', but also 'debauchery' or 'licentiousness', directly opposing the virtue of <b>pudīcitia</b>.<br>Option B, <b>lascīvia</b>, means 'wantonness' or 'playfulness', which is related but often less severe.<br>Option C, <b>impudentia</b>, means 'shamelessness'.<br>Option D, <b>superbia</b>, means 'pride' or 'arrogance'. All options are 1st declension nouns, matching the grammatical category of <b>pudīcitia</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>fīdus</b>?", options: ["perfidus", "dubius", "varius", "incertus"], i: 0, explanation: "The adjective <b>fīdus</b> means 'faithful' or 'trustworthy'. Its direct antonym is <b>perfidus</b>, 'treacherous' or 'perfidious'.<br>Option B, <b>dubius</b>, means 'doubtful' or 'uncertain', which relates to trust but not directly to active betrayal.<br>Option C, <b>varius</b>, means 'various' or 'changeable', implying unreliability but not necessarily treachery.<br>Option D, <b>incertus</b>, means 'uncertain'. All options are 1st/2nd declension adjectives, matching the grammatical category of <b>fīdus</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>celeritās</b>?", options: ["lentitūdō", "gravitās", "magnitūdō", "altitūdō"], i: 0, explanation: "The noun <b>celeritās</b> means 'swiftness' or 'speed'. Its direct antonym is <b>lentitūdō</b>, 'slowness'.<br>Option B, <b>gravitās</b>, means 'heaviness' or 'seriousness'.<br>Option C, <b>magnitūdō</b>, means 'greatness' or 'size'.<br>Option D, <b>altitūdō</b>, means 'height' or 'depth'. All options are 3rd declension nouns, matching the grammatical category of <b>celeritās</b>." }, { meta: "Antonyms", stem: "Which of the following is the closest antonym to <b>sānus</b>?", options: ["lymphāticus", "aeger", "lassus", "stupidus"], i: 0, explanation: "The adjective <b>sānus</b> means 'sound', 'healthy', or 'sane'. In the sense of 'sane', its closest antonym is <b>lymphāticus</b>, meaning 'frantic' or 'mad'.<br>Option B, <b>aeger</b>, means 'sick' or 'ill', referring more to physical ailment.<br>Option C, <b>lassus</b>, means 'tired' or 'weary'.<br>Option D, <b>stupidus</b>, means 'stupid', which is a mental state but not necessarily 'insane'. All options are 1st/2nd declension adjectives, matching the grammatical category of <b>sānus</b>." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["rūmor", "honor", "labor", "arbor"], i: 3, explanation: "All four words are 3rd declension nouns ending in <i>-or</i>. However, <i>rūmor</i> (rumor), <i>honor</i> (honor), and <i>labor</i> (toil/work) are all masculine nouns. <i>Arbor</i> (tree) is a feminine noun, making it the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["manus", "domus", "cornū", "portus"], i: 2, explanation: "All four words are 4th declension nouns. <i>Manus</i> (hand), <i>domus</i> (house), and <i>portus</i> (harbor) are all feminine or masculine nouns (<i>domus</i> can be both). <i>Cornū</i> (horn) is a neuter noun, which is less common in the 4th declension and makes it the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["audeō", "gaudeō", "soleō", "valeō"], i: 3, explanation: "All four verbs are 2nd conjugation. <i>Audeō</i> (to dare), <i>gaudeō</i> (to rejoice), and <i>soleō</i> (to be accustomed) are all semi-deponent verbs, meaning they have active forms in the present system but passive forms in the perfect system. <i>Valeō</i> (to be strong/well) is a regular active verb, making it the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["odiōsus", "invidus", "inimīcus", "amīcus"], i: 3, explanation: "<i>Odiōsus</i> means 'hateful' or 'odious'. <i>Invidus</i> means 'envious' or 'hostile'. <i>Inimīcus</i> means 'unfriendly' or 'hostile'. All three convey a negative or hostile sentiment. <i>Amīcus</i> means 'friendly' or 'a friend', which is positive and thus the semantic outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["vulgus", "pelagus", "virus", "lūcus"], i: 3, explanation: "All four words end in <i>-us</i>. <i>Vulgus</i> (the common people), <i>pelagus</i> (the sea), and <i>virus</i> (poison) are all 2nd declension neuter nouns, despite their <i>-us</i> ending (which typically indicates masculine in the 2nd declension). <i>Lūcus</i> (grove) is a regular 2nd declension masculine noun, making it the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["sīdus", "astrum", "stella", "fulmen"], i: 3, explanation: "<i>Sīdus</i>, <i>astrum</i>, and <i>stella</i> all refer to stars or constellations. <i>Sīdus</i> often implies a constellation or heavenly body with astrological significance, <i>astrum</i> is a Greek loanword for star, and <i>stella</i> is the common Latin word for star. <i>Fulmen</i> means 'lightning bolt', which is an atmospheric phenomenon, not a celestial body, making it the semantic outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["ferō", "eō", "volō", "mīror"], i: 3, explanation: "<i>Ferō</i> (to bear/carry), <i>eō</i> (to go), and <i>volō</i> (to wish/be willing) are all highly irregular active verbs. <i>Mīror</i> (to wonder at/admire) is a deponent verb, meaning it has passive forms but an active meaning. This difference in verb type makes <i>mīror</i> the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["fāma", "glōria", "laus", "spolia"], i: 3, explanation: "<i>Fāma</i> (fame/reputation), <i>glōria</i> (glory), and <i>laus</i> (praise) are all abstract concepts related to renown, reputation, or honor. <i>Spolia</i> (spoils of war) refers to concrete objects taken from a defeated enemy, making it the semantic outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["vetus", "pauper", "dīves", "integer"], i: 3, explanation: "<i>Vetus</i> (old), <i>pauper</i> (poor), and <i>dīves</i> (rich) are all 3rd declension adjectives. <i>Integer</i> (whole/untouched/sound) is a 1st/2nd declension adjective, making it the morphological outlier." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["aequor", "pontus", "altum", "flūmen"], i: 3, explanation: "<i>Aequor</i> (the level surface of the sea), <i>pontus</i> (the sea, especially the open sea), and <i>altum</i> (the deep/the sea) are all poetic or elevated terms for the sea. <i>Flūmen</i> (river) refers to a freshwater body, making it the semantic outlier among these terms for the ocean." }, { meta: "Analogies", stem: "<b>vātēs</b> : <b>fātur</b> :: <b>augur</b> : X", options: ["ōminātur", "augurātur", "cōnsōlātur", "morātur"], i: 1, explanation: "The relationship is between an agent noun and its characteristic action expressed as a 3rd person singular present indicative deponent verb. A <i>vātēs</i> (prophet, poet) <i>fātur</i> (prophesies, speaks). Similarly, an <i>augur</i> (augur, diviner) <i>augurātur</i> (acts as an augur, divines). All options are 3rd person singular present indicative deponent verbs, ensuring grammatical consistency. <b>ōminātur</b> means 'takes an omen,' <b>cōnsōlātur</b> means 'comforts,' and <b>morātur</b> means 'delays.' While related to divination, 'ōminātur' is a distinct action, not the primary, overarching action of an augur." }, { meta: "Analogies", stem: "<b>sapientia</b> : <b>philosophus</b> :: <b>tyrannis</b> : X", options: ["dominus", "patrōnus", "tyrannus", "minister"], i: 2, explanation: "The relationship is between an abstract quality (noun) and the person who embodies or is characterized by that quality (noun). <i>Sapientia</i> (wisdom) is embodied by a <i>philosophus</i> (philosopher). Likewise, <i>tyrannis</i> (tyranny) is embodied by a <i>tyrannus</i> (tyrant). All options are 2nd declension masculine nouns in the nominative singular, matching the grammatical category of the correct answer and the given examples. <b>dominus</b> means 'master,' <b>patrōnus</b> means 'patron,' and <b>minister</b> means 'attendant' or 'minister,' none of which directly embody the abstract concept of tyranny in the same way a 'tyrant' does." }, { meta: "Analogies", stem: "<b>ferēns</b> : <b>lātus</b> :: <b>gerēns</b> : X", options: ["missus", "victus", "ductus", "gestus"], i: 3, explanation: "The relationship is between the present active participle (PAP) and the perfect passive participle (PPP) of a verb. <b>ferēns</b> (carrying) is the PAP of <i>ferō</i>, and <b>lātus</b> (carried) is its PPP. Similarly, <b>gerēns</b> (carrying, waging) is the PAP of <i>gerō</i>, and its PPP is <b>gestus</b> (carried, waged). All options are perfect passive participles in the nominative singular masculine, ensuring grammatical consistency. <b>missus</b> means 'sent' (from <i>mittō</i>), <b>victus</b> means 'conquered' (from <i>vincō</i>), and <b>ductus</b> means 'led' (from <i>dūcō</i>)." }, { meta: "Analogies", stem: "<b>gladius</b> : <b>ensis</b> :: <b>caelum</b> : X", options: ["sīdus", "nūbēs", "aether", "tempestās"], i: 2, explanation: "The relationship is between a common Latin noun and its poetic or elevated synonym. <b>gladius</b> (sword) is a common term, while <b>ensis</b> is its poetic equivalent. In the same way, <b>caelum</b> (sky, heaven) has a poetic synonym in <b>aether</b> (the upper air, heaven, sky). All options are 3rd declension nouns in the nominative singular, maintaining grammatical consistency. <b>sīdus</b> means 'star,' <b>nūbēs</b> means 'cloud,' and <b>tempestās</b> means 'storm,' none of which are direct poetic synonyms for 'sky' in the same manner as 'aether'." }, { meta: "Analogies", stem: "<b>celerō</b> : <b>celeriter</b> :: <b>aequō</b> : X", options: ["vērē", "certē", "aequē", "frūstrā"], i: 2, explanation: "The relationship is between a verb and its corresponding adverbial derivative. <b>celerō</b> (to hasten) forms the adverb <b>celeriter</b> (quickly). Similarly, <b>aequō</b> (to make equal, level) forms the adverb <b>aequē</b> (equally, justly). All options are adverbs, ensuring grammatical consistency. <b>vērē</b> means 'truly,' <b>certē</b> means 'certainly,' and <b>frūstrā</b> means 'in vain,' none of which are derived from <i>aequō</i>." }, { meta: "Analogies", stem: "<b>digitī</b> : <b>manus</b> :: <b>rōstrum</b> : X", options: ["puppis", "gubernātor", "nāvis", "ratis"], i: 2, explanation: "The relationship is between a plural part and the singular whole of which it is a component. <b>digitī</b> (fingers) are parts of a <b>manus</b> (hand). Likewise, a <b>rōstrum</b> (prow) is a part of a <b>nāvis</b> (ship). All options are 3rd declension nouns in the nominative singular, maintaining grammatical consistency. <b>puppis</b> means 'stern' (another part of a ship), <b>gubernātor</b> means 'helmsman' (a person associated with a ship), and <b>ratis</b> means 'raft' or 'boat' (a type of vessel, but 'nāvis' is the more general 'ship' of which a prow is a distinct part)." }, { meta: "Analogies", stem: "<b>aedificō</b> : <b>aedificium</b> :: <b>cōnstituō</b> : X", options: ["lēx", "ōrdō", "cōnstitūtiō", "condiciō"], i: 2, explanation: "The relationship is between a verb and a noun derived from it, often representing the action or its result. <b>aedificō</b> (to build) yields <b>aedificium</b> (a building). Similarly, <b>cōnstituō</b> (to establish, decide, arrange) yields <b>cōnstitūtiō</b> (an arrangement, constitution, ordinance). All options are 3rd declension nouns in the nominative singular, ensuring grammatical consistency. <b>lēx</b> means 'law,' <b>ōrdō</b> means 'order' or 'rank,' and <b>condiciō</b> means 'condition' or 'agreement.' While related to governance or order, they are not direct noun derivatives of <i>cōnstituō</i> in the same manner as <i>cōnstitūtiō</i>." }, { meta: "Analogies", stem: "<b>videō</b> : <b>vīsus</b> :: <b>sentiō</b> : X", options: ["audītus", "cognitus", "sēnsus", "dictus"], i: 2, explanation: "The relationship is between a verb in the present active indicative and its perfect passive participle. <b>videō</b> (to see) has the perfect passive participle <b>vīsus</b> (seen). Likewise, <b>sentiō</b> (to feel, perceive) has the perfect passive participle <b>sēnsus</b> (felt, perceived). All options are perfect passive participles in the nominative singular masculine, ensuring grammatical consistency. <b>audītus</b> means 'heard' (from <i>audiō</i>), <b>cognitus</b> means 'known' (from <i>cognōscō</i>), and <b>dictus</b> means 'said' (from <i>dīcō</i>)." }, { meta: "Analogies", stem: "<b>vōs</b> : <b>vōbīs</b> :: <b>quī</b> : X", options: ["eīs", "hīs", "quīs", "illīs"], i: 2, explanation: "The relationship is between a nominative plural pronoun and its dative/ablative plural form. <b>vōs</b> (you all, nom. pl.) corresponds to <b>vōbīs</b> (to/for/by/with you all, dat./abl. pl.). Similarly, <b>quī</b> (who, which, nom. pl.) has an archaic dative/ablative plural form <b>quīs</b>. All options are dative/ablative plural pronouns, ensuring grammatical consistency. <b>eīs</b> means 'to/for/by/with them' (from <i>is, ea, id</i>), <b>hīs</b> means 'to/for/by/with these' (from <i>hic, haec, hoc</i>), and <b>illīs</b> means 'to/for/by/with those' (from <i>ille, illa, illud</i>)." }, { meta: "Analogies", stem: "<b>poēta</b> : <b>carmen</b> :: <b>ōrātor</b> : X", options: ["dictiō", "persuāsiō", "ōrātiō", "laus"], i: 2, explanation: "The relationship is between a person performing a specific role and the characteristic product or outcome of their action. A <b>poēta</b> (poet) creates a <b>carmen</b> (song, poem). Likewise, an <b>ōrātor</b> (orator) delivers an <b>ōrātiō</b> (speech, oration). All options are 3rd declension feminine nouns in the nominative singular, ensuring grammatical consistency. <b>dictiō</b> means 'speaking' or 'word choice,' <b>persuāsiō</b> means 'persuasion,' and <b>laus</b> means 'praise.' While related to rhetoric, <i>ōrātiō</i> is the most direct and comprehensive term for the product of an orator's activity." }, { meta: "Fill-in-the-Blank", stem: "Post clādem apud Cannās, Rōmānī, quamquam spem nōn omnīnō āmisērunt, animīs tamen erant _____.", options: ["īnfrāctī", "ēlātī", "praedītī", "vigilantēs"], i: 0, explanation: "The sentence describes the state of the Romans' spirits after the devastating defeat at Cannae. Although they did not entirely lose hope, the context implies a sense of discouragement or being broken in spirit. <b>īnfrāctī</b> (from īnfrangō, īnfrangere, īnfrēgī, īnfrāctus) means 'broken, disheartened, crushed,' which perfectly fits the context of a severe military defeat impacting morale. <b>ēlātī</b> (elated, puffed up) is the semantic opposite and thus absurd. <b>praedītī</b> (endowed with) and <b>vigilantēs</b> (watchful, vigilant) do not fit the emotional state described by the sentence." }, { meta: "Fill-in-the-Blank", stem: "Cum dīra fāta imminentia vīdissent, sacerdōtēs hostiās immolāre coepērunt, ut deōrum īram _____.", options: ["dēprecārentur", "augērent", "celebrārent", "ignorārent"], i: 0, explanation: "The sentence describes priests sacrificing victims because they saw 'dire impending fates.' The purpose of such a ritual would be to appease the gods and avert their wrath. <b>dēprecārentur</b> (from dēprecārī, to avert by prayer, to beg off, to deprecate) is the only verb that makes sense in this context. <b>augērent</b> (increase) is absurd, as priests would not sacrifice to increase divine wrath. <b>celebrārent</b> (celebrate) is illogical. <b>ignorārent</b> (ignore) is also absurd, as the priests are clearly taking action because they are aware of the fates." }, { meta: "Fill-in-the-Blank", stem: "Quamquam multōs annōs exsul vīverat, tamen numquam patriae dulcīs ____ potuit.", options: ["oblīvīscī", "meminisse", "carēre", "fruī"], i: 0, explanation: "The sentence states that despite living as an exile for many years, he was never able to do something regarding his 'sweet homeland.' The context of exile and the emotional attachment implied by 'dulcīs patriae' suggests that he could never forget it. <b>oblīvīscī</b> (to forget) takes the genitive case (patriae dulcīs) and fits perfectly. <b>meminisse</b> (to remember) also takes the genitive, but 'never able to remember' is semantically contradictory to the idea of a cherished homeland for an exile. <b>carēre</b> (to lack, be without) and <b>fruī</b> (to enjoy) both take the ablative case, not the genitive, making them grammatically incorrect for this sentence structure." }, { meta: "Fill-in-the-Blank", stem: "Flēns puer, postquam māter eum complexa est, nōn parvum ____ invēnit.", options: ["sōlācium", "perīculum", "ōdium", "impedīmentum"], i: 0, explanation: "The sentence describes a weeping boy being embraced by his mother. The natural outcome of a mother's embrace for a crying child is comfort. <b>sōlācium</b> (comfort, solace) is the appropriate word. <b>perīculum</b> (danger), <b>ōdium</b> (hatred), and <b>impedīmentum</b> (hindrance) are all absurd in the context of a comforting maternal embrace." }, { meta: "Fill-in-the-Blank", stem: "Hostēs, cum moenibus urbis iam _____, cīvēs ad arma vocāvērunt.", options: ["īnstārent", "cessārent", "dēfenderent", "recederent"], i: 0, explanation: "The sentence describes enemies in relation to the city walls, causing citizens to be called to arms. This implies an active threat or attack. <b>īnstārent</b> (from īnstāre, to press on, urge, threaten, be at hand) perfectly conveys the idea of the enemy threatening or pressing upon the walls, which would necessitate a call to arms. <b>cessārent</b> (were delaying/ceasing), <b>dēfenderent</b> (were defending), and <b>recederent</b> (were retreating) are all contrary to the action of calling citizens to arms, making them absurd in context." }, { meta: "Fill-in-the-Blank", stem: "Propter eius fidem et _____, senātus eī summōs honōrēs tribuit.", options: ["obsequium", "fastīdium", "scelus", "tumultum"], i: 0, explanation: "The sentence states that the senate bestowed the highest honors because of someone's loyalty ('fidem') and another quality. This implies a positive attribute. <b>obsequium</b> (compliance, deference, obedience) is a positive quality that aligns with loyalty and would be rewarded with honors. <b>fastīdium</b> (disdain, arrogance), <b>scelus</b> (crime), and <b>tumultum</b> (uproar, disorder) are all negative qualities that would not lead to the bestowal of high honors, making them absurd." }, { meta: "Fill-in-the-Blank", stem: "Poēta nōbilis, Vergiliī fāmam ____ volēns, novum carmen epicum scrībere cōnstituit.", options: ["aemulārī", "dēspicere", "neglegere", "laudāre"], i: 0, explanation: "A noble poet, wanting to do something with Vergil's fame, decided to write a new epic poem. This suggests a desire to compete with or match Vergil's literary achievement. <b>aemulārī</b> (to rival, emulate, be jealous of) perfectly captures this ambition. <b>dēspicere</b> (to despise) and <b>neglegere</b> (to neglect) are contrary to the act of writing a new epic inspired by Vergil. While one might <b>laudāre</b> (praise) Vergil, the act of writing a *new* epic poem implies a more active form of emulation or rivalry rather than mere praise." }, { meta: "Fill-in-the-Blank", stem: "Flūmen, postquam rīpās trānsiluit, agrōs vīcīnōs aquā et līmō _____.", options: ["obrūxit", "siccāvit", "ēlēgit", "dīvīsit"], i: 0, explanation: "The sentence describes a river overflowing its banks ('rīpās trānsiluit') and its effect on neighboring fields with 'water and mud.' This strongly implies the fields were covered or overwhelmed. <b>obrūxit</b> (from obruō, obruere, obrūī, obrūtus, to overwhelm, bury, cover) is the most fitting verb. <b>siccāvit</b> (dried up) is the opposite of what an overflowing river does. <b>ēlēgit</b> (chose) is semantically irrelevant. <b>dīvīsit</b> (divided) does not capture the impact of an overflow with water and mud as effectively as 'covered' or 'overwhelmed.'" }, { meta: "Fill-in-the-Blank", stem: "Quamquam tempestās vehementer saeviēbat, nautae spērābant eam brevi tempore _____.", options: ["dēsitūram esse", "incēnsūram esse", "perpetuāturam esse", "accelerātūram esse"], i: 0, explanation: "The sentence states that a storm was raging violently ('vehementer saeviēbat'), but the sailors hoped that it would do something 'in a short time.' Given the severity of the storm and the sailors' hope, they would naturally hope for it to end. <b>dēsitūram esse</b> (from dēsinō, dēsinere, dēsiī, dēsitūrus, to cease, stop) is the correct choice. <b>incēnsūram esse</b> (to inflame/burn) is irrelevant. <b>perpetuāturam esse</b> (to continue/perpetuate) is the opposite of what sailors would hope for in a violent storm. <b>accelerātūram esse</b> (to accelerate) would also be an undesirable outcome for sailors in a storm." }, { meta: "Fill-in-the-Blank", stem: "Mīles, cum hostium cōnsiliī prōfundī ____ esset, in īnsidiās imprōvīsō incidit.", options: ["īnscius", "cōnscius", "perītus", "cupidus"], i: 0, explanation: "The soldier fell unexpectedly into an ambush ('in īnsidiās imprōvīsō incidit') because he was something regarding the enemy's deep plan ('hostium cōnsiliī prōfundī'). This strongly suggests a lack of knowledge or awareness. <b>īnscius</b> (ignorant, unaware) takes the genitive case and perfectly fits the context of falling into an ambush due to ignorance of a plan. <b>cōnscius</b> (aware, conscious) is the semantic opposite; if he were aware of the plan, he would not have fallen into the ambush. <b>perītus</b> (skilled, experienced) and <b>cupidus</b> (desirous) do not fit the narrative of falling into an unexpected trap." }, { meta: "Circumlocution", stem: "Spatium temporis longissimum vel omnī temporī continuum; saeculum vel vīta hominis.", options: ["saeculum", "aevum", "spatium", "initium"], i: 1, explanation: "The Latin definition describes 'A very long span of time or continuous for all time; an age or a human life.' This precisely matches <b>aevum, -ī</b> n., which refers to an age, time, or eternity, often used poetically. While <b>saeculum</b> means an age or generation, and <b>spatium</b> is a general term for space or an interval, <b>aevum</b> captures the broader, often more abstract or eternal sense of time. <b>Initium</b> means a beginning." }, { meta: "Circumlocution", stem: "Dīcere vērō id quod nōn celāre velimus, praesertim dē culpā vel rē nōn grātā.", options: ["loquor", "fateor", "sequor", "proficīscor"], i: 1, explanation: "The definition 'To say truly that which we do not wish to hide, especially concerning a fault or an unpleasant matter' accurately describes <b>fateor, fatērī, fassus sum</b>, meaning 'to confess, admit, acknowledge.' While <b>loquor</b> means 'to speak,' it lacks the specific nuance of admitting or revealing something that might otherwise be hidden. <b>Sequor</b> means 'to follow,' and <b>proficīscor</b> means 'to set out.'" }, { meta: "Circumlocution", stem: "Magna et gravis rēs, praesertim structūra ingēns vel onus difficile.", options: ["nūbēs", "clādēs", "mōlēs", "fāmēs"], i: 2, explanation: "The definition 'A great and heavy thing, especially a huge structure or a difficult burden' perfectly describes <b>mōlēs, mōlis</b> f., which refers to a great mass, bulk, a huge structure (like a siege engine or a pier), or a heavy burden/effort. <b>Nūbēs</b> is a cloud. <b>Clādēs</b> is a disaster or defeat. <b>Fāmēs</b> is hunger. All options are 3rd declension feminine nouns, but only <b>mōlēs</b> fits the semantic description." }, { meta: "Circumlocution", stem: "Ad superiōrem caelum pertinēns vel dīvīnus; levissimus et pūrissimus.", options: ["aeternus", "clārus", "aetherius", "supernus"], i: 2, explanation: "The definition 'Pertaining to the upper sky or divine; very light and pure' points to something of the upper air, ethereal, or divine, which is the core meaning of <b>aetherius, -a, -um</b>. While <b>aeternus</b> means eternal, <b>clārus</b> means clear/bright, and <b>supernus</b> means upper/celestial, <b>aetherius</b> specifically conveys the sense of the pure, rarefied upper air or its divine qualities, often used poetically." }, { meta: "Circumlocution", stem: "Rem novam facere vel iterum facere; reparāre vel rursus incipere.", options: ["reparō", "iterō", "īnstaurō", "renovō"], i: 2, explanation: "The definition 'To make a thing new or do it again; to repair or begin again' precisely captures the dual sense of <b>īnstaurō, īnstaurāre, īnstaurāvī, īnstaurātus</b>: to renew or restore something, and also to repeat or begin something again, often with a sense of solemnity or re-establishment (e.g., renewing a sacrifice, repeating a battle). While <b>reparō</b> and <b>renovō</b> focus on restoring, and <b>iterō</b> focuses on repeating, <b>īnstaurō</b> encompasses both aspects, making it the best fit." }, { meta: "Circumlocution", stem: "Pars īnfima portae vel aditus; initium vel fīnis alicuius reī.", options: ["flūmen", "līmen", "agmen", "ōmen"], i: 1, explanation: "The definition 'The lowest part of a gate or entrance; the beginning or end of something' describes both the literal threshold of a doorway and its metaphorical meaning as a beginning or end, which is the primary sense of <b>līmen, līminis</b> n. <b>Flūmen</b> is a river. <b>Agmen</b> is a line of march or an army. <b>Ōmen</b> is a sign or portent. All options are 3rd declension neuter nouns, but only <b>līmen</b> fits the description." }, { meta: "Circumlocution", stem: "Quī inimīcus est vel perīculum affert; locus nōn tūtus.", options: ["īnfirmus", "inimīcus", "īnfestus", "īnsānus"], i: 2, explanation: "The definition 'Who is hostile or brings danger; an unsafe place' perfectly describes <b>īnfestus, -a, -um</b>, which means hostile, dangerous, or unsafe. While <b>inimīcus</b> means hostile, <b>īnfestus</b> often carries a stronger connotation of active threat or danger, especially when describing places as unsafe. <b>Īnfirmus</b> means weak, and <b>īnsānus</b> means mad or insane. All options are 1st/2nd declension adjectives." }, { meta: "Circumlocution", stem: "Subitō exorīrī vel apparēre, praesertim dē lacrimīs vel affectibus.", options: ["orior", "morior", "oborior", "patior"], i: 2, explanation: "The definition 'To suddenly arise or appear, especially concerning tears or emotions' specifically describes the sudden arising or appearance of something, particularly tears or emotions, which is the precise meaning of <b>oborior, oborīrī, obortus sum</b>. While <b>orior</b> means 'to rise' or 'arise' generally, <b>oborior</b> emphasizes the suddenness and often the inward or emotional aspect. <b>Morior</b> means 'to die,' and <b>patior</b> means 'to suffer.' All options are deponent verbs." }, { meta: "Circumlocution", stem: "Partēs internōrum corporum animālium; etiam sēdēs affectuum vel intimum animī.", options: ["pectus", "vīscus", "cor", "corpus"], i: 1, explanation: "The definition 'The inner parts of animal bodies; also the seat of emotions or the innermost part of the soul' accurately describes <b>vīscus, vīsceris</b> n. (usually plural <b>vīscera</b>), referring to the inner organs or entrails, and metaphorically to the innermost feelings or heart. While <b>pectus</b> (chest, breast) and <b>cor</b> (heart) also refer to the seat of emotions, <b>vīscus</b> specifically includes the literal 'entrails' aspect, which is a key part of its meaning and often used in poetic contexts. <b>Corpus</b> is the general term for body. All options are 3rd declension neuter nouns." }, { meta: "Circumlocution", stem: "Ōlim vel aliquandō in praeteritō; nōnnumquam vel futūrō tempore.", options: ["olim", "aliquandō", "quondam", "tum"], i: 2, explanation: "The definition 'Once or at some time in the past; sometimes or at a future time' captures the full range of <b>quondam</b>, which means 'once,' 'formerly,' 'at some time,' but can also mean 'sometimes' or even 'hereafter' in certain contexts (though less common for the latter). While <b>olim</b> also means 'once' or 'formerly,' and <b>aliquandō</b> means 'sometimes' or 'at some time,' <b>quondam</b> uniquely encompasses both the past 'once' and the 'sometimes' aspect, and the rare future sense. <b>Tum</b> simply means 'then.' All options are adverbs of time." }, { meta: "Latin to English", stem: "What is the best translation of aestus, -ūs?", options: ["heat, tide", "age, time", "summer", "bronze"], i: 0, explanation: "The Latin noun <b>aestus, -ūs</b> (m.) means 'heat' or 'tide'. Option B, 'age, time', is the translation of <b>aetās, aetātis</b> (f.). Option C, 'summer', is the translation of <b>aestās, aestātis</b> (f.). Option D, 'bronze', is the translation of <b>aes, aeris</b> (n.)." }, { meta: "Latin to English", stem: "What is the best translation of arx, arcis?", options: ["citadel, stronghold", "arch, bow", "art, skill", "altar"], i: 0, explanation: "The Latin noun <b>arx, arcis</b> (f.) means 'citadel' or 'stronghold'. Option B, 'arch, bow', is the translation of <b>arcus, -ūs</b> (m.). Option C, 'art, skill', is the translation of <b>ars, artis</b> (f.). Option D, 'altar', is the translation of <b>āra, -ae</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of carmen, carminis?", options: ["song, poem", "flesh", "crime, charge", "heat"], i: 0, explanation: "The Latin noun <b>carmen, carminis</b> (n.) means 'song' or 'poem'. Option B, 'flesh', is the translation of <b>carō, carnis</b> (f.). Option C, 'crime, charge', is the translation of <b>crīmen, crīminis</b> (n.). Option D, 'heat', is the translation of <b>calor, calōris</b> (m.)." }, { meta: "Latin to English", stem: "What is the best translation of condō, condere?", options: ["to found, establish, hide", "to season", "to condemn", "to consult"], i: 0, explanation: "The Latin verb <b>condō, condere, condidī, conditus</b> means 'to found, establish, or hide'. Option B, 'to season', is the translation of <b>condiō, condīre, condīvī, condītus</b>. Option C, 'to condemn', is the translation of <b>condemnō, condemnāre, condemnāvī, condemnātus</b>. Option D, 'to consult', is the translation of <b>cōnsulō, cōnsulere, cōnsuluī, cōnsultus</b>." }, { meta: "Latin to English", stem: "What is the best translation of crīmen, crīminis?", options: ["crime, charge", "hair", "cross", "sieve"], i: 0, explanation: "The Latin noun <b>crīmen, crīminis</b> (n.) means 'crime' or 'charge'. Option B, 'hair', is the translation of <b>crīnis, crīnis</b> (m.). Option C, 'cross', is the translation of <b>crux, crucis</b> (f.). Option D, 'sieve', is the translation of <b>crībrum, -ī</b> (n.)." }, { meta: "Latin to English", stem: "What is the best translation of cruor, cruōris?", options: ["gore, blood", "cross", "color", "heart"], i: 0, explanation: "The Latin noun <b>cruor, cruōris</b> (m.) means 'gore' or 'blood'. Option B, 'cross', is the translation of <b>crux, crucis</b> (f.). Option C, 'color', is the translation of <b>color, colōris</b> (m.). Option D, 'heart', is the translation of <b>cor, cordis</b> (n.)." }, { meta: "Latin to English", stem: "What is the best translation of dolus, -ī?", options: ["trick, deceit", "pain, grief", "gift", "house"], i: 0, explanation: "The Latin noun <b>dolus, -ī</b> (m.) means 'trick' or 'deceit'. Option B, 'pain, grief', is the translation of <b>dolor, dolōris</b> (m.). Option C, 'gift', is the translation of <b>dōnum, -ī</b> (n.). Option D, 'house', is the translation of <b>domus, -ūs</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of ēnsis, ēnsis?", options: ["sword", "fire", "island", "anger"], i: 0, explanation: "The Latin noun <b>ēnsis, ēnsis</b> (m.) means 'sword'. Option B, 'fire', is the translation of <b>īgnis, īgnis</b> (m.). Option C, 'island', is the translation of <b>īnsula, -ae</b> (f.). Option D, 'anger', is the translation of <b>īra, -ae</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of the masculine noun flāmen, flāminis?", options: ["priest", "blast, breeze", "river", "flame"], i: 0, explanation: "The Latin noun <b>flāmen, flāminis</b> (m.) means 'priest'. The homograph <b>flāmen, flāminis</b> (n.) means 'blast' or 'breeze', which is Option B. Option C, 'river', is the translation of <b>flūmen, flūminis</b> (n.). Option D, 'flame', is the translation of <b>flamma, -ae</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of foedus, foederis?", options: ["treaty, league", "foul, horrible", "fraud", "faith"], i: 0, explanation: "The Latin noun <b>foedus, foederis</b> (n.) means 'treaty' or 'league'. Option B, 'foul, horrible', is the translation of the adjective <b>foedus, -a, -um</b>. Option C, 'fraud', is the translation of <b>fraus, fraudis</b> (f.). Option D, 'faith', is the translation of <b>fīdēs, fideī</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of lābor, lābōris?", options: ["toil, labor", "tear", "lake", "death"], i: 0, explanation: "The Latin noun <b>lābor, lābōris</b> (m.) means 'toil' or 'labor'. The verb <b>lābor, lābī, lāpsus sum</b> means 'to slip, glide'. Option B, 'tear', is the translation of <b>lacrima, -ae</b> (f.). Option C, 'lake', is the translation of <b>lacus, -ūs</b> (m.). Option D, 'death', is the translation of <b>lētum, -ī</b> (n.)." }, { meta: "Latin to English", stem: "What is the best translation of mōlēs, mōlis?", options: ["mass, burden, structure", "custom", "death", "wall"], i: 0, explanation: "The Latin noun <b>mōlēs, mōlis</b> (f.) means 'mass, burden, or structure'. Option B, 'custom', is the translation of <b>mōs, mōris</b> (m.). Option C, 'death', is the translation of <b>mors, mortis</b> (f.). Option D, 'wall', is the translation of <b>mūrus, -ī</b> (m.). The adjective <b>mollis, molle</b> ('soft, gentle') is a common visual distractor." }, { meta: "Latin to English", stem: "What is the best translation of ōra, -ae?", options: ["shore, coast", "mouth, face", "bone", "breeze"], i: 0, explanation: "The Latin noun <b>ōra, -ae</b> (f.) means 'shore' or 'coast'. Option B, 'mouth, face', is the translation of <b>ōs, ōris</b> (n.). Option C, 'bone', is the translation of <b>os, ossis</b> (n.). Option D, 'breeze', is the translation of <b>aura, -ae</b> (f.)." }, { meta: "Latin to English", stem: "What is the best translation of pecus, pecoris?", options: ["cattle, flock", "chest, breast", "money", "foot"], i: 0, explanation: "The Latin noun <b>pecus, pecoris</b> (n.) means 'cattle' or 'flock'. Option B, 'chest, breast', is the translation of <b>pectus, pectoris</b> (n.). Option C, 'money', is the translation of <b>pecūnia, -ae</b> (f.). Option D, 'foot', is the translation of <b>pēs, pedis</b> (m.)." }, { meta: "Latin to English", stem: "What is the best translation of puppis, puppis?", options: ["stern, ship", "pupil of eye", "dust", "gate"], i: 0, explanation: "The Latin noun <b>puppis, puppis</b> (f.) means 'stern' or 'ship'. Option B, 'pupil of eye', is the translation of <b>pūpula, -ae</b> (f.). Option C, 'dust', is the translation of <b>pulvis, pulveris</b> (m.). Option D, 'gate', is the translation of <b>porta, -ae</b> (f.)." }, { meta: "English to Latin", stem: "Which Latin word means 'to lament'?", options: ["quaerō", "queror", "fleō", "doleō"], i: 1, explanation: "The correct answer is <b>queror, querī, questus sum</b>, which means 'to lament' or 'to complain'.<br>Option A, <b>quaerō, quaerere, quaesīvī, quaesītus</b>, means 'to seek' or 'to ask'.<br>Option C, <b>fleō, flēre, flēvī, flētus</b>, means 'to weep' or 'to cry'. While related to sadness, it specifically refers to the act of shedding tears, whereas 'to lament' is a broader expression of grief.<br>Option D, <b>doleō, dolēre, doluī, dolitūrus</b>, means 'to grieve' or 'to suffer pain'. This describes an internal state of sorrow, distinct from the outward expression of lamentation." }, { meta: "English to Latin", stem: "Which Latin word means 'omen'?", options: ["ōmen", "nūmen", "lūmen", "carmen"], i: 0, explanation: "The correct answer is <b>ōmen, ōminis</b> (n.), which means 'omen' or 'sign'.<br>Option B, <b>nūmen, nūminis</b> (n.), means 'divine will', 'divinity', or 'divine power'. While related to supernatural phenomena, it refers to the divine force itself, not a specific predictive sign.<br>Option C, <b>lūmen, lūminis</b> (n.), means 'light' or 'an eye'. It is a morphological false friend.<br>Option D, <b>carmen, carminis</b> (n.), means 'song', 'poem', or 'prophecy'. While it can mean prophecy, an omen is typically a non-verbal sign, distinct from a spoken or written prophecy." }, { meta: "English to Latin", stem: "Which Latin word means 'to scatter'?", options: ["spargō", "stringō", "sternō", "serō"], i: 0, explanation: "The correct answer is <b>spargō, spargere, sparsī, sparsus</b>, which means 'to scatter', 'to strew', or 'to sprinkle'.<br>Option B, <b>stringō, stringere, strīnxī, strictus</b>, means 'to draw tight', 'to bind', or 'to graze'.<br>Option C, <b>sternō, sternere, strāvī, strātus</b>, means 'to lay low', 'to spread out', or 'to strew' (especially in the sense of laying something flat). While related to spreading, it lacks the dispersive quality of 'to scatter'.<br>Option D, <b>serō, serere, sēvī, satus</b>, means 'to sow' or 'to plant'. While it involves spreading seeds, its primary meaning is planting, not general scattering." }, { meta: "English to Latin", stem: "Which Latin word means 'threshold'?", options: ["līmen", "lūmen", "flūmen", "culmen"], i: 0, explanation: "The correct answer is <b>līmen, līminis</b> (n.), which means 'threshold' or 'doorway'.<br>Option B, <b>lūmen, lūminis</b> (n.), means 'light' or 'an eye'. It is a morphological false friend.<br>Option C, <b>flūmen, flūminis</b> (n.), means 'river' or 'stream'. It is also a morphological false friend.<br>Option D, <b>culmen, culminis</b> (n.), means 'summit', 'peak', or 'roof'. While an architectural term, it refers to the highest point, not the entrance." }, { meta: "English to Latin", stem: "Which Latin word means 'to weave'?", options: ["texō", "tegō", "torqueō", "nectō"], i: 0, explanation: "The correct answer is <b>texō, texere, texuī, textus</b>, which means 'to weave' or 'to plait'.<br>Option B, <b>tegō, tegere, tēxī, tēctus</b>, means 'to cover' or 'to conceal'. It is a morphological false friend with similar principal parts.<br>Option C, <b>torqueō, torquēre, torsī, tortus</b>, means 'to twist', 'to turn', or 'to torment'. While weaving involves twisting, this verb specifically means twisting, not the entire process of weaving.<br>Option D, <b>nectō, nectere, nexuī/nexī, nexus</b>, means 'to bind', 'to tie', or 'to connect'. While related to joining, it is distinct from the specific act of weaving threads together." }, { meta: "English to Latin", stem: "Which Latin word means 'a shore, coast'?", options: ["lītus", "rīpa", "saxum", "fluctus"], i: 0, explanation: "The correct answer is <b>lītus, lītoris</b> (n.), which means 'shore' or 'coast' (especially of the sea).<br>Option B, <b>rīpa, rīpae</b> (f.), means 'bank' (specifically of a river). This is distinct from a sea-coast.<br>Option C, <b>saxum, saxī</b> (n.), means 'rock' or 'stone'. Rocks are often found on shores but are not the shore itself.<br>Option D, <b>fluctus, fluctūs</b> (m.), means 'wave'. Waves are part of the sea, distinct from the land bordering it." }, { meta: "English to Latin", stem: "Which Latin word means 'darkness, gloom'?", options: ["tenebrae", "umbra", "nox", "lūx"], i: 0, explanation: "The correct answer is <b>tenebrae, tenebrārum</b> (f. pl.), which means 'darkness' or 'gloom'.<br>Option B, <b>umbra, umbrae</b> (f.), means 'shade' or 'shadow'. While related to lack of light, it refers to an area partially obscured from light, not total darkness.<br>Option C, <b>nox, noctis</b> (f.), means 'night'. This refers to a period of time, not the state of darkness itself.<br>Option D, <b>lūx, lūcis</b> (f.), means 'light'. This is the antonym of darkness." }, { meta: "English to Latin", stem: "Which Latin word means 'a crowd, throng'?", options: ["turba", "grex", "cohors", "agmen"], i: 0, explanation: "The correct answer is <b>turba, turbae</b> (f.), which means 'a crowd', 'throng', or 'mob', often implying disorder or disturbance.<br>Option B, <b>grex, gregis</b> (m.), means 'flock', 'herd' (often of animals), or 'company' (of people, but often with a specific connotation, e.g., a theatrical company).<br>Option C, <b>cohors, cohortis</b> (f.), means 'cohort' or 'company of soldiers'. This refers to a specific military unit.<br>Option D, <b>agmen, agminis</b> (n.), means 'column' or 'army on the march'. This refers to a specific organized procession, not a general crowd." }, { meta: "English to Latin", stem: "Which Latin word means 'to delay, linger'?", options: ["moror", "mīror", "memorō", "maneō"], i: 0, explanation: "The correct answer is <b>moror, morārī, morātus sum</b>, which means 'to delay', 'to linger', or 'to tarry'.<br>Option B, <b>mīror, mīrārī, mīrātus sum</b>, means 'to wonder' or 'to admire'. It is a morphological false friend.<br>Option C, <b>memorō, memorāre, memorāvī, memorātus</b>, means 'to recall' or 'to relate'. It is morphologically similar.<br>Option D, <b>maneō, manēre, mānsī, mānsus</b>, means 'to remain' or 'to stay'. While lingering implies staying, 'to remain' does not carry the connotation of slowness or reluctance to depart that 'to delay' or 'to linger' does." }, { meta: "English to Latin", stem: "Which Latin word means 'to fall'?", options: ["cadō", "caedō", "cēdō", "currō"], i: 0, explanation: "The correct answer is <b>cadō, cadere, cecidī, cāsūrus</b>, which means 'to fall'.<br>Option B, <b>caedō, caedere, cecīdī, caesus</b>, means 'to cut', 'to strike', or 'to kill'. This is an excellent morphological false friend, with very similar principal parts but a completely different meaning.<br>Option C, <b>cēdō, cēdere, cessī, cessus</b>, means 'to yield', 'to withdraw', or 'to go'. It is morphologically similar.<br>Option D, <b>currō, currere, cucurrī, cursus</b>, means 'to run'. This is a distinct action." }, { meta: "English to Latin", stem: "Which Latin word means 'a prophecy'?", options: ["vāticinium", "fātum", "augurium", "nūmen"], i: 0, explanation: "The correct answer is <b>vāticinium, vāticiniī</b> (n.), which means 'a prophecy' or 'soothsaying'.<br>Option B, <b>fātum, fātī</b> (n.), means 'fate' or 'destiny'. This refers to the predetermined outcome, not the act or content of foretelling it.<br>Option C, <b>augurium, auguriī</b> (n.), means 'augury' or 'divination'. This refers to the act or sign used for divination, distinct from the prophecy itself.<br>Option D, <b>nūmen, nūminis</b> (n.), means 'divine will' or 'divinity'. This refers to the divine power, not a specific prophecy." }, { meta: "English to Latin", stem: "Which Latin word means 'to fear'?", options: ["vereor", "videor", "reor", "horreō"], i: 0, explanation: "The correct answer is <b>vereor, verērī, veritus sum</b>, which means 'to fear' or 'to revere'.<br>Option B, <b>videor, vidērī, vīsus sum</b>, means 'to seem' or 'to be seen'. It is a morphological false friend.<br>Option C, <b>reor, rērī, ratus sum</b>, means 'to think' or 'to believe'. It is also a morphological false friend.<br>Option D, <b>horreō, horrēre, horruī</b>, means 'to shudder' or 'to dread'. While dread is a strong form of fear, 'to shudder' is a physical reaction, making it distinct from general 'to fear'." }, { meta: "English to Latin", stem: "Which Latin word means 'a ghost, shade' (as in departed spirit)?", options: ["umbra", "anima", "corpus", "lūx"], i: 0, explanation: "The correct answer is <b>umbra, umbrae</b> (f.), which can mean 'shade', 'shadow', or 'a ghost'/'departed spirit'.<br>Option B, <b>anima, animae</b> (f.), means 'soul', 'breath', or 'life'. While related to the spiritual, it refers to the animating principle of life, not specifically a departed spirit.<br>Option C, <b>corpus, corporis</b> (n.), means 'body'. This is the physical form, distinct from a spirit.<br>Option D, <b>lūx, lūcis</b> (f.), means 'light'. This is the antonym of shade and conceptually opposite to a shadowy ghost." }, { meta: "English to Latin", stem: "Which Latin word means 'to hasten'?", options: ["properō", "praepōnō", "prōferō", "ruō"], i: 0, explanation: "The correct answer is <b>properō, properāre, properāvī, properātus</b>, which means 'to hasten' or 'to hurry'.<br>Option B, <b>praepōnō, praepōnere, praeposuī, praepositus</b>, means 'to place before' or 'to prefer'. It is a morphological false friend.<br>Option C, <b>prōferō, prōferre, prōtulī, prōlātus</b>, means 'to bring forward', 'to produce', or 'to postpone'. It is morphologically similar.<br>Option D, <b>ruō, ruere, ruī, rutus/ruitus</b>, means 'to rush', 'to fall', or 'to collapse'. While 'to rush' implies speed, it often carries a connotation of impetuosity or uncontrolled movement, distinct from the more general 'to hasten'." }, { meta: "English to Latin", stem: "Which Latin word means 'a wall (of a city)'?", options: ["moenia", "pariēs", "agger", "fornix"], i: 0, explanation: "The correct answer is <b>moenia, moenium</b> (n. pl.), which specifically refers to the 'city walls' or 'fortifications' of a city.<br>Option B, <b>pariēs, parietis</b> (m.), means 'wall' (specifically of a house or room, an interior wall). This is distinct from a city wall.<br>Option C, <b>agger, aggeris</b> (m.), means 'mound', 'rampart', or 'dike'. While related to fortifications, it refers to an earthen embankment, not a stone wall.<br>Option D, <b>fornix, fornicis</b> (m.), means 'arch' or 'vault'. This is a specific architectural feature, distinct from a wall." }, { meta: "Synonyms", stem: "dolor", options: ["maeror", "fūrōr", "timor", "labōr"], i: 0, explanation: "The word <b>dolor</b> (m., 3rd declension) means 'grief, pain, sorrow'. Its closest synonym among the options is <b>maeror</b> (m., 3rd declension), which also means 'sadness, mourning, grief'. <b>Fūrōr</b> (m., 3rd declension) means 'rage, madness'. <b>Timor</b> (m., 3rd declension) means 'fear'. <b>Labōr</b> (m., 3rd declension) means 'toil, effort, suffering', which can be related to pain but is not a direct synonym for grief." }, { meta: "Synonyms", stem: "cēlō", options: ["occultō", "vītō", "negō", "dissimulō"], i: 0, explanation: "The verb <b>cēlō</b> (1st conjugation) means 'to hide, conceal'. Its closest synonym is <b>occultō</b> (1st conjugation), which means 'to hide, conceal, keep secret'. <b>Vītō</b> (1st conjugation) means 'to avoid'. <b>Negō</b> (1st conjugation) means 'to deny, refuse'. <b>Dissimulō</b> (1st conjugation) means 'to disguise, conceal (one's feelings), dissemble', which is related to concealing but specifically implies feigning ignorance or indifference, rather than simply hiding something." }, { meta: "Synonyms", stem: "onus", options: ["pondus", "scelus", "lūmen", "fūnus"], i: 0, explanation: "The word <b>onus</b> (n., 3rd declension) means 'burden, load, weight'. Its closest synonym is <b>pondus</b> (n., 3rd declension), meaning 'weight, burden, load'. <b>Scelus</b> (n., 3rd declension) means 'crime, wickedness'. <b>Lūmen</b> (n., 3rd declension) means 'light'. <b>Fūnus</b> (n., 3rd declension) means 'funeral, death'." }, { meta: "Synonyms", stem: "petō", options: ["quaerō", "currō", "mittō", "tendō"], i: 0, explanation: "The verb <b>petō</b> (3rd conjugation) has a broad range of meanings including 'to seek, aim at, ask for, attack'. Its closest synonym among the options, particularly in the sense of 'to seek' or 'to ask for', is <b>quaerō</b> (3rd conjugation), meaning 'to seek, search for, ask'. <b>Currō</b> (3rd conjugation) means 'to run'. <b>Mittō</b> (3rd conjugation) means 'to send'. <b>Tendō</b> (3rd conjugation) means 'to stretch, strive, aim', which shares the 'aim at' sense with <b>petō</b> but is not as broad a synonym for 'seek' or 'ask for'." }, { meta: "Synonyms", stem: "atrōx", options: ["ferōx", "audāx", "fallāx", "ingēns"], i: 0, explanation: "The adjective <b>atrōx</b> (3rd declension, one termination) means 'fierce, cruel, terrible, savage'. Its closest synonym is <b>ferōx</b> (3rd declension, one termination), meaning 'fierce, wild, bold, spirited'. While <b>audāx</b> (3rd declension, one termination) means 'bold, daring' and <b>fallāx</b> (3rd declension, one termination) means 'deceitful', and <b>ingēns</b> (3rd declension, one termination) means 'huge, vast', none capture the 'fierce' or 'savage' quality as directly as <b>ferōx</b>." }, { meta: "Synonyms", stem: "sentiō", options: ["comperiō", "scīō", "veniō", "dormiō"], i: 0, explanation: "The verb <b>sentiō</b> (4th conjugation) means 'to feel, perceive, realize, understand'. Its closest synonym in the sense of 'to realize' or 'to find out' is <b>comperiō</b> (4th conjugation), which means 'to find out, discover, ascertain'. While <b>scīō</b> (4th conjugation) means 'to know', <b>comperiō</b> implies the process of coming to know or discovering, which aligns well with <b>sentiō</b>'s nuance of perception and realization. <b>Veniō</b> (4th conjugation) means 'to come'. <b>Dormiō</b> (4th conjugation) means 'to sleep'." }, { meta: "Synonyms", stem: "moveō", options: ["cieō", "teneō", "habeō", "augeō"], i: 0, explanation: "The verb <b>moveō</b> (2nd conjugation) means 'to move, stir, rouse, affect'. Its closest synonym, especially in the sense of 'to stir up' or 'to rouse', is <b>cieō</b> (2nd conjugation), which means 'to stir up, rouse, excite'. <b>Teneō</b> (2nd conjugation) means 'to hold, keep'. <b>Habeō</b> (2nd conjugation) means 'to have, hold'. <b>Augeō</b> (2nd conjugation) means 'to increase, enlarge'." }, { meta: "Synonyms", stem: "cōnsilium", options: ["propositum", "imperium", "beneficium", "perīculum"], i: 0, explanation: "The word <b>cōnsilium</b> (n., 2nd declension) means 'plan, counsel, advice, purpose'. Its closest synonym is <b>propositum</b> (n., 2nd declension), meaning 'plan, purpose, intention'. <b>Imperium</b> (n., 2nd declension) means 'command, power, empire'. <b>Beneficium</b> (n., 2nd declension) means 'kindness, favor'. <b>Perīculum</b> (n., 2nd declension) means 'danger'." }, { meta: "Synonyms", stem: "dīvitiae", options: ["copiae", "īnsidiae", "nūptiae", "tenebrāe"], i: 0, explanation: "The plural noun <b>dīvitiae</b> (f. pl., 1st declension) means 'riches, wealth'. Its closest synonym among the options, in the sense of 'resources' or 'abundance', is <b>copiae</b> (f. pl., 1st declension). While <b>copiae</b> can also mean 'forces' or 'troops', it frequently refers to 'resources' or 'abundance', which aligns with wealth. <b>Īnsidiae</b> (f. pl., 1st declension) means 'ambush, plot'. <b>Nūptiae</b> (f. pl., 1st declension) means 'wedding'. <b>Tenebrāe</b> (f. pl., 1st declension) means 'darkness'." }, { meta: "Synonyms", stem: "vīrēs", options: ["rōbora", "artēs", "fīnēs", "cīvēs"], i: 0, explanation: "The plural noun <b>vīrēs</b> (f. pl., 3rd declension, from <b>vīs</b>) means 'strength, power, force'. Its closest synonym, particularly in poetic and elevated contexts, is <b>rōbora</b> (n. pl., 3rd declension, from <b>rōbur</b>), which means 'strength, vigor, power'. <b>Artēs</b> (f. pl., 3rd declension) means 'skills, arts'. <b>Fīnēs</b> (m. pl., 3rd declension) means 'boundaries, territory'. <b>Cīvēs</b> (m. pl., 3rd declension) means 'citizens'." }, { meta: "Synonyms", stem: "cupiō", options: ["appetō", "cadō", "legō", "vertō"], i: 0, explanation: "The verb <b>cupiō</b> (3rd conjugation i-stem) means 'to desire, wish, long for'. Its closest synonym is <b>appetō</b> (3rd conjugation), which means 'to seek, strive for, desire'. <b>Cadō</b> (3rd conjugation) means 'to fall'. <b>Legō</b> (3rd conjugation) means 'to read, gather'. <b>Vertō</b> (3rd conjugation) means 'to turn'." }, { meta: "Synonyms", stem: "cōnfiteor", options: ["fateor", "vereor", "tueor", "mīror"], i: 0, explanation: "The deponent verb <b>cōnfiteor</b> (2nd conjugation) means 'to confess, acknowledge, admit'. Its direct synonym is <b>fateor</b> (2nd conjugation deponent), which also means 'to confess, admit, acknowledge'. <b>Vereor</b> (2nd conjugation deponent) means 'to fear, revere'. <b>Tueor</b> (2nd conjugation deponent) means 'to watch, protect'. <b>Mīror</b> (2nd conjugation deponent) means 'to wonder at, admire'." }, { meta: "Synonyms", stem: "aequor", options: ["pontus", "fluvius", "locus", "ventus"], i: 0, explanation: "The word <b>aequor</b> (n., 3rd declension) means 'a flat surface', especially 'the surface of the sea, the sea'. Its closest synonym among the options, specifically referring to the sea, is <b>pontus</b> (m., 2nd declension), which means 'the sea, the deep sea' (often poetic). <b>Fluvius</b> (m., 2nd declension) means 'river'. <b>Locus</b> (m., 2nd declension) means 'place'. <b>Ventus</b> (m., 2nd declension) means 'wind'." }, { meta: "Synonyms", stem: "vātēs", options: ["augur", "cōnsul", "prīnceps", "custōs"], i: 0, explanation: "The word <b>vātēs</b> (m./f., 3rd declension) means 'prophet, seer, poet'. Its closest synonym in the sense of a diviner or seer is <b>augur</b> (m., 3rd declension), an official diviner who interpreted omens. <b>Cōnsul</b> (m., 3rd declension) means 'consul'. <b>Prīnceps</b> (m., 3rd declension) means 'chief, leader, prince'. <b>Custōs</b> (m., 3rd declension) means 'guard, guardian'." }, { meta: "Synonyms", stem: "laudō", options: ["praedicō", "aestīmō", "celebrō", "honorō"], i: 0, explanation: "The verb <b>laudō</b> (1st conjugation) means 'to praise, commend'. Its closest synonym is <b>praedicō</b> (1st conjugation), which means 'to proclaim, declare, praise'. While <b>celebrō</b> (1st conjugation) means 'to celebrate, honor' and <b>honorō</b> (1st conjugation) means 'to honor', <b>praedicō</b> more directly conveys the act of speaking highly of someone or something. <b>Aestīmō</b> (1st conjugation) means 'to estimate, value'." }, { meta: "Antonyms", stem: "oblivīscor", options: ["meminī", "retineō", "discō", "ignōrō"], i: 0, explanation: "The verb <b>oblivīscor</b> means 'to forget'. Its direct antonym is <b>meminī</b>, meaning 'to remember'. Option B, <b>retineō</b>, means 'to retain' or 'hold back', which is related but not the primary antonym for the act of forgetting. Option C, <b>discō</b>, means 'to learn', which is about acquiring knowledge, not remembering what was previously known. Option D, <b>ignōrō</b>, means 'to be ignorant of' or 'not know', which implies a lack of prior knowledge, whereas forgetting implies previous knowledge that has been lost." }, { meta: "Antonyms", stem: "pudīcitia", options: ["libīdō", "impudīcitia", "luxuria", "stuprum"], i: 1, explanation: "The noun <b>pudīcitia</b> means 'chastity' or 'modesty'. Its direct morphological and semantic antonym is <b>impudīcitia</b>, meaning 'unchastity' or 'immodesty'. Option A, <b>libīdō</b>, means 'lust' or 'desire', which is a vice related to a lack of chastity but not the state itself. Option C, <b>luxuria</b>, can mean 'extravagance' or 'wantonness', which might imply moral looseness but is not a direct opposite of chastity. Option D, <b>stuprum</b>, refers to 'dishonor' or 'illicit sexual intercourse', describing an act rather than the virtue or lack thereof." }, { meta: "Antonyms", stem: "ōtium", options: ["bellum", "labōr", "cūra", "negotium"], i: 3, explanation: "The noun <b>ōtium</b> means 'leisure', 'peace', or 'quiet'. Its direct antonym, often used in contrast, is <b>negotium</b>, meaning 'business', 'activity', or 'trouble' (literally 'not-leisure'). Option A, <b>bellum</b>, means 'war', which is an opposite of peace but narrower than the full scope of <b>ōtium</b>. Option B, <b>labōr</b>, means 'toil' or 'labor', which is a component of <b>negotium</b> but not the comprehensive opposite. Option C, <b>cūra</b>, means 'care' or 'anxiety', which can be a consequence of business but not the state of activity itself." }, { meta: "Antonyms", stem: "sēnsus", options: ["stultitia", "ignōrantia", "āmentia", "caecitās"], i: 2, explanation: "The noun <b>sēnsus</b> can mean 'sense', 'understanding', or 'reason'. Its closest antonym, particularly in the sense of 'good sense' or 'reason', is <b>āmentia</b>, meaning 'senselessness', 'madness', or 'folly'. Option A, <b>stultitia</b>, means 'folly' or 'stupidity', which is related but less severe or comprehensive than <b>āmentia</b>. Option B, <b>ignōrantia</b>, means 'ignorance', referring to a lack of knowledge, not necessarily a lack of mental faculty or reason. Option D, <b>caecitās</b>, means 'blindness', referring to a physical lack of sight, not mental sense." }, { meta: "Antonyms", stem: "salūs", options: ["mortēs", "malum", "perniciēs", "exitium"], i: 2, explanation: "The noun <b>salūs</b> means 'safety', 'welfare', or 'health'. Its direct antonym, signifying destruction or ruin, is <b>perniciēs</b>. Option A, <b>mortēs</b> (plural of <i>mors</i>), means 'death', which is a consequence of lacking safety but not the broader concept of ruin. Option B, <b>malum</b>, means 'evil' or 'misfortune', which is too general. Option D, <b>exitium</b>, also means 'destruction' or 'ruin', and is very close. However, <b>perniciēs</b> often carries a stronger connotation of fatal harm or ruinous influence, making it a slightly more precise opposite to <b>salūs</b> (preservation, well-being)." }, { meta: "Antonyms", stem: "fidēs", options: ["mendācium", "fraus", "perfidia", "īnfidēlitās"], i: 2, explanation: "The noun <b>fidēs</b> means 'faith', 'trust', or 'loyalty'. Its direct morphological and semantic antonym, emphasizing treachery, is <b>perfidia</b>, meaning 'faithlessness' or 'treachery'. Option A, <b>mendācium</b>, means 'lie' or 'falsehood', which is contrary to truth but not the direct opposite of trust or loyalty. Option B, <b>fraus</b>, means 'deceit' or 'fraud', which is a form of betrayal but not the core opposite of the state of faithfulness. Option D, <b>īnfidēlitās</b>, also means 'disloyalty' and is a strong antonym, but <b>perfidia</b> often carries a more intense connotation of active betrayal and treachery, making it a very robust opposite for <b>fidēs</b>." }, { meta: "Antonyms", stem: "paupertās", options: ["opēs", "abundantia", "dīvitiae", "fortūna"], i: 2, explanation: "The noun <b>paupertās</b> means 'poverty'. Its direct and most common antonym is <b>dīvitiae</b> (plural), meaning 'riches' or 'wealth'. Option A, <b>opēs</b>, means 'resources', 'wealth', or 'power', but <b>dīvitiae</b> is more specifically 'wealth'. Option B, <b>abundantia</b>, means 'abundance', which is too general. Option D, <b>fortūna</b>, can mean 'fortune' or 'wealth', but it also encompasses 'luck' and 'destiny', making <b>dīvitiae</b> a more precise antonym for 'poverty'." }, { meta: "Antonyms", stem: "probitās", options: ["scelus", "vitium", "improbitās", "malignitās"], i: 2, explanation: "The noun <b>probitās</b> means 'honesty' or 'integrity'. Its direct morphological and semantic antonym is <b>improbitās</b>, meaning 'dishonesty' or 'wickedness'. Option A, <b>scelus</b>, means 'crime' or 'wickedness', referring to an act rather than the character trait. Option B, <b>vitium</b>, means 'fault' or 'vice', which is too general. Option D, <b>malignitās</b>, means 'malice' or 'ill-will', which is a specific type of wickedness, not general dishonesty." }, { meta: "Antonyms", stem: "cōnfirmō", options: ["dēbilītō", "īnvalidō", "dissolvō", "frangō"], i: 1, explanation: "The verb <b>cōnfirmō</b> means 'to strengthen', 'confirm', or 'establish'. Its closest antonym, especially in the sense of making something firm or valid, is <b>īnvalidō</b>, meaning 'to weaken' or 'to invalidate'. Option A, <b>dēbilītō</b>, means 'to weaken' or 'cripple', which is very close, but <b>īnvalidō</b> also covers the aspect of 'confirming' vs. 'invalidating'. Option C, <b>dissolvō</b>, means 'to loosen' or 'dissolve', implying breaking apart rather than simply weakening. Option D, <b>frangō</b>, means 'to break', which is a more extreme action than merely weakening or invalidating." }, { meta: "Antonyms", stem: "sapientia", options: ["ignōrantia", "stultitia", "āmentia", "dēmentia"], i: 1, explanation: "The noun <b>sapientia</b> means 'wisdom'. Its direct and most appropriate antonym is <b>stultitia</b>, meaning 'folly' or 'stupidity'. Option A, <b>ignōrantia</b>, means 'ignorance', which is a lack of knowledge, not necessarily a lack of wisdom. Option C, <b>āmentia</b>, means 'madness' or 'senselessness', which is a more severe condition than mere folly. Option D, <b>dēmentia</b>, also means 'madness' or 'insanity', similarly indicating a profound mental derangement rather than simply a lack of wisdom." }, { meta: "Antonyms", stem: "laudō", options: ["accūsō", "damnō", "vituperō", "reprehendō"], i: 2, explanation: "The verb <b>laudō</b> means 'to praise' or 'to commend'. Its direct antonym, meaning 'to blame' or 'censure', is <b>vituperō</b>. Option A, <b>accūsō</b>, means 'to accuse', which is more formal and legalistic. Option B, <b>damnō</b>, means 'to condemn', implying a stronger judgment or punishment. Option D, <b>reprehendō</b>, means 'to rebuke' or 'criticize', which is very close, but <b>vituperō</b> specifically implies finding fault and speaking ill of, making it a precise opposite to praise." }, { meta: "Antonyms", stem: "ōsculum", options: ["repulsa", "contumēlia", "sputum", "verbera"], i: 2, explanation: "The noun <b>ōsculum</b> means 'kiss', a physical act of affection. The most direct physical antonym, representing an act of extreme disgust or rejection, is <b>sputum</b>, meaning 'spit'. Option A, <b>repulsa</b>, means 'rejection' or 'refusal', which is an abstract concept, not a physical act. Option B, <b>contumēlia</b>, means 'insult' or 'abuse', which is often verbal or emotional. Option D, <b>verbera</b>, means 'blows' or 'lashes', which are acts of physical violence, but <b>sputum</b> is more specifically an act of visceral contempt, directly opposing the tenderness of a kiss." }, { meta: "Antonyms", stem: "pāx", options: ["tumultus", "discordia", "bellum", "sēditiō"], i: 2, explanation: "The noun <b>pāx</b> means 'peace'. Its direct and unequivocal antonym is <b>bellum</b>, meaning 'war'. Option A, <b>tumultus</b>, means 'uproar' or 'commotion', which is a disturbance but not full-scale war. Option B, <b>discordia</b>, means 'discord' or 'disagreement', which can be a cause of war but is not war itself. Option D, <b>sēditiō</b>, means 'rebellion' or 'sedition', referring to internal conflict, not necessarily international war." }, { meta: "Antonyms", stem: "fortūna", options: ["cāsus", "calamitās", "adversitās", "misēria"], i: 2, explanation: "The noun <b>fortūna</b> can mean 'fortune' or 'luck', often implying good fortune. Its closest antonym, meaning 'adversity' or 'misfortune', is <b>adversitās</b>. Option A, <b>cāsus</b>, can mean 'chance', 'event', or 'misfortune', but it is less consistently negative than <b>adversitās</b>. Option B, <b>calamitās</b>, means 'disaster' or 'calamity', which is generally more extreme than typical misfortune. Option D, <b>misēria</b>, means 'wretchedness' or 'distress', referring to a state of suffering rather than the external force of misfortune itself." }, { meta: "Antonyms", stem: "vīvus", options: ["exstīnctus", "dēfūnctus", "mortuus", "occīsus"], i: 2, explanation: "The adjective <b>vīvus</b> means 'alive' or 'living'. Its direct and most fundamental antonym is <b>mortuus</b>, meaning 'dead'. Option A, <b>exstīnctus</b>, means 'extinguished' or 'dead', but it often implies being put out or destroyed. Option B, <b>dēfūnctus</b>, means 'dead' or 'deceased', which is very close but often used in a more formal context. Option D, <b>occīsus</b>, is the perfect passive participle of <i>occīdō</i>, meaning 'slain' or 'killed', which describes an action rather than the state of being dead." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MORPHOLOGY?", options: ["<i>hortus</i>", "<i>locus</i>", "<i>corpus</i>", "<i>numerus</i>"], i: 2, explanation: "The correct answer is <b>C) <i>corpus</i></b>. While all four words end in <i>-us</i> in the nominative singular, <i>hortus</i>, <i>locus</i>, and <i>numerus</i> are all second declension masculine nouns. <i>Corpus</i>, however, is a third declension neuter noun (<i>corpus, corporis</i>). This distinction in declension and gender makes it morphologically different from the others." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MEANING?", options: ["<i>fulgor</i>", "<i>nitor</i>", "<i>clāmor</i>", "<i>splendor</i>"], i: 2, explanation: "The correct answer is <b>C) <i>clāmor</i></b>. <i>Fulgor</i> (brightness, gleam), <i>nitor</i> (brightness, splendor, sheen), and <i>splendor</i> (brilliance, splendor) all relate to light, shining, or radiance. <i>Clāmor</i>, on the other hand, means 'a shout, a cry, a noise,' belonging to the semantic field of sound." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MORPHOLOGY?", options: ["<i>columba</i>", "<i>nauta</i>", "<i>silva</i>", "<i>terra</i>"], i: 1, explanation: "The correct answer is <b>B) <i>nauta</i></b>. All four words are first declension nouns ending in <i>-a</i>. However, <i>columba</i> (dove), <i>silva</i> (forest), and <i>terra</i> (earth) are all feminine nouns. <i>Nauta</i> (sailor) is a masculine noun, despite its first declension ending, making it morphologically distinct in terms of gender." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MEANING?", options: ["<i>currō</i>", "<i>stō</i>", "<i>volō</i>", "<i>gradior</i>"], i: 1, explanation: "The correct answer is <b>B) <i>stō</i></b>. <i>Currō</i> (to run), <i>volō</i> (to fly), and <i>gradior</i> (to walk, to step) are all verbs of motion. <i>Stō</i> (to stand), however, signifies a state of rest or being stationary, making it semantically distinct from the others." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MORPHOLOGY?", options: ["<i>gaudeō</i>", "<i>teneō</i>", "<i>videō</i>", "<i>moveō</i>"], i: 0, explanation: "The correct answer is <b>A) <i>gaudeō</i></b>. While all four verbs appear to be second conjugation and active in form, <i>gaudeō</i> (to rejoice) is a semi-deponent verb (<i>gaudeō, gaudēre, gavīsus sum</i>). This means it has active forms in the present system but deponent forms in the perfect system. <i>Teneō</i> (to hold), <i>videō</i> (to see), and <i>moveō</i> (to move) are all regular active verbs of the second conjugation." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MEANING?", options: ["<i>virtūs</i>", "<i>probītās</i>", "<i>scelus</i>", "<i>aequitās</i>"], i: 2, explanation: "The correct answer is <b>C) <i>scelus</i></b>. <i>Virtūs</i> (virtue, courage), <i>probītās</i> (uprightness, honesty), and <i>aequitās</i> (fairness, equity) are all abstract nouns denoting positive moral qualities or virtues. <i>Scelus</i>, however, means 'a crime, wickedness, impiety,' representing a negative moral concept, making it semantically distinct." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MORPHOLOGY?", options: ["<i>ingēns</i>", "<i>celer</i>", "<i>trīstis</i>", "<i>pulcher</i>"], i: 3, explanation: "The correct answer is <b>D) <i>pulcher</i></b>. <i>Ingēns</i> (huge), <i>celer</i> (swift), and <i>trīstis</i> (sad) are all adjectives of the third declension. <i>Ingēns</i> is a one-ending adjective, while <i>celer</i> and <i>trīstis</i> are two-ending adjectives of the third declension. <i>Pulcher</i> (beautiful), however, is a first/second declension adjective (<i>pulcher, pulchra, pulchrum</i>), making it morphologically different from the others." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MEANING?", options: ["<i>aequor</i>", "<i>pontus</i>", "<i>tellūs</i>", "<i>pelagus</i>"], i: 2, explanation: "The correct answer is <b>C) <i>tellūs</i></b>. <i>Aequor</i> (the surface of the sea, the sea), <i>pontus</i> (the sea), and <i>pelagus</i> (the open sea, the sea) are all poetic or elevated terms for the sea or ocean. <i>Tellūs</i>, on the other hand, means 'the earth, land, ground,' belonging to a different semantic category." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MORPHOLOGY?", options: ["<i>cīvis</i>", "<i>hostis</i>", "<i>mare</i>", "<i>pēs</i>"], i: 3, explanation: "The correct answer is <b>D) <i>pēs</i></b>. All four words are third declension nouns. However, <i>cīvis</i> (citizen), <i>hostis</i> (enemy), and <i>mare</i> (sea) are all i-stem nouns (<i>cīvis, cīvis</i>; <i>hostis, hostis</i>; <i>mare, maris</i>). <i>Pēs</i> (foot), with its genitive <i>pedis</i>, is a consonant-stem noun, making it morphologically distinct from the i-stems." }, { meta: "Odd One Out", stem: "Which of the following words does not belong by MEANING?", options: ["<i>timor</i>", "<i>pavor</i>", "<i>mīrāculum</i>", "<i>metus</i>"], i: 2, explanation: "The correct answer is <b>C) <i>mīrāculum</i></b>. <i>Timor</i> (fear, dread), <i>pavor</i> (panic, terror), and <i>metus</i> (fear, apprehension) are all nouns related to the emotion of fear. <i>Mīrāculum</i>, however, means 'a wonder, a marvel, a miracle,' referring to something astonishing or extraordinary, rather than an emotion of fear." }, { meta: "Analogies", stem: "digitus : manus :: pēs : X", options: ["caput", "pectus", "corpus", "ōs"], i: 2, explanation: "The relationship is 'part to whole'. A <i>digitus</i> (finger) is a part of a <i>manus</i> (hand). Similarly, a <i>pēs</i> (foot) is a part of the <i>corpus</i> (body). All options are 3rd declension neuter nouns in the nominative singular." }, { meta: "Analogies", stem: "ferō : lātus :: eō : X", options: ["factus", "missus", "itus", "dictus"], i: 2, explanation: "The relationship is 'present active indicative first person singular to perfect participle nominative singular masculine'. <i>Ferō</i> (I carry) has the perfect passive participle <i>lātus</i> (having been carried). <i>Eō</i> (I go) has the perfect active participle <i>itus</i> (having gone). All options are perfect participles in the nominative singular masculine." }, { meta: "Analogies", stem: "timor : metus :: bellum : X", options: ["victōria", "pugna", "paenitentia", "fortūna"], i: 1, explanation: "The relationship is 'synonym'. <i>Timor</i> and <i>metus</i> both mean 'fear'. <i>Bellum</i> means 'war'. A common synonym for 'war' or 'battle' is <i>pugna</i>. All options are 1st declension feminine nouns in the nominative singular." }, { meta: "Analogies", stem: "ignis : cinis :: senectūs : X", options: ["dolor", "languor", "honor", "amor"], i: 1, explanation: "The relationship is 'cause and effect'. <i>Ignis</i> (fire) produces <i>cinis</i> (ash). Similarly, <i>senectūs</i> (old age) often brings about <i>languor</i> (languor, weakness, feebleness). All options are 3rd declension masculine nouns in the nominative singular." }, { meta: "Analogies", stem: "Cererēs : frūmentum :: Bacchus : X", options: ["bellum", "ferrum", "vīnum", "aurum"], i: 2, explanation: "The relationship is 'deity as metonymy for their domain/product'. <i>Cererēs</i> (Ceres, goddess of grain, often used poetically in the plural for grain itself) relates to <i>frūmentum</i> (grain). Similarly, <i>Bacchus</i> (god of wine) relates to <i>vīnum</i> (wine). All options are 2nd declension neuter nouns in the nominative singular." }, { meta: "Analogies", stem: "fortis : fortitūdō :: aequus : X", options: ["vēritās", "cīvitās", "aequitās", "dīgnitās"], i: 2, explanation: "The relationship is 'adjective to abstract noun'. <i>Fortis</i> (brave) corresponds to <i>fortitūdō</i> (bravery). Similarly, <i>aequus</i> (equal, fair) corresponds to <i>aequitās</i> (equality, fairness). All options are 3rd declension feminine nouns in the nominative singular." }, { meta: "Analogies", stem: "aethēr : caelum :: pontus : X", options: ["flūmen", "mare", "lūmen", "nōmen"], i: 1, explanation: "The relationship is 'poetic/elevated term to more common synonym'. <i>Aethēr</i> (upper air, ether) is a poetic synonym for <i>caelum</i> (sky, heaven). Similarly, <i>pontus</i> (sea) is a poetic synonym for <i>mare</i> (sea). All options are 3rd declension neuter nouns in the nominative singular." }, { meta: "Analogies", stem: "fātālis : fātum :: lētālis : X", options: ["tēlum", "bellum", "lētum", "ōtium"], i: 2, explanation: "The relationship is 'adjective to related noun'. <i>Fātālis</i> (fateful, deadly) is derived from or relates to <i>fātum</i> (fate, destiny, doom). Similarly, <i>lētālis</i> (deadly, lethal) is derived from or relates to <i>lētum</i> (death, destruction). All options are 2nd declension neuter nouns in the nominative singular." }, { meta: "Analogies", stem: "virtūs : bonum :: vitium : X", options: ["falsum", "verbum", "malum", "exemplum"], i: 2, explanation: "The relationship is 'concept to its inherent quality'. <i>Virtūs</i> (virtue) is inherently a <i>bonum</i> (good thing). Conversely, <i>vitium</i> (vice, fault) is inherently a <i>malum</i> (bad thing, evil). All options are 2nd declension neuter nouns in the nominative singular." }, { meta: "Analogies", stem: "volō : voluī :: nōlō : X", options: ["māluī", "potuī", "nōluī", "fuī"], i: 2, explanation: "The relationship is 'present active indicative first person singular to perfect active indicative first person singular for irregular verbs'. <i>Volō</i> (I wish, I want) has the perfect form <i>voluī</i> (I wished, I wanted). Similarly, <i>nōlō</i> (I am unwilling) has the perfect form <i>nōluī</i> (I was unwilling). All options are first person singular perfect active indicative forms of irregular verbs." }, { meta: "Fill-in-the-Blank", stem: "Nāvis, saevā tempestāte iactāta, per undās maris diū _____ antequam portum tandem attigit.", options: ["natābat", "fluctuābat", "dormiēbat", "stābat"], i: 1, explanation: "The sentence describes a ship 'tossed by a fierce storm' (<i>saevā tempestāte iactāta</i>) and moving 'through the waves of the sea' (<i>per undās maris</i>). The verb <b>fluctuābat</b>, meaning 'was being tossed by waves' or 'was fluctuating', perfectly fits this context. Options A (<i>natābat</i>, 'was swimming') and C (<i>dormiēbat</i>, 'was sleeping') are absurd for a ship. Option D (<i>stābat</i>, 'was standing') directly contradicts the idea of being tossed by a storm." }, { meta: "Fill-in-the-Blank", stem: "Poēta, antequam opus suum inciperet, Mūsam Calliopēn _____, ut carmina dīvīna dictāret.", options: ["salūtāvit", "invocāvit", "vulnerāvit", "neglexit"], i: 1, explanation: "The purpose clause 'ut carmina dīvīna dictāret' (so that she might dictate divine songs) indicates that the poet is seeking inspiration or assistance from the Muse. <b>Invocāvit</b>, meaning 'invoked' or 'called upon', is the appropriate action for a poet addressing a Muse for inspiration. Options A (<i>salūtāvit</i>, 'greeted') is too weak for the context of seeking divine inspiration. Options C (<i>vulnerāvit</i>, 'wounded') and D (<i>neglexit</i>, 'neglected') are semantically absurd or contradictory to the act of beginning a divine work." }, { meta: "Fill-in-the-Blank", stem: "Vīta hominum, ut Sapiēns dīxit, est _____, quod quam celerrimē praeterit et nūllō modō retinerī potest.", options: ["aeterna", "fugāx", "stabilis", "longa"], i: 1, explanation: "The clause 'quod quam celerrimē praeterit et nūllō modō retinerī potest' (because it passes by most swiftly and can be retained in no way) strongly implies that human life is transient or fleeting. The adjective <b>fugāx</b>, meaning 'fleeting' or 'transient', accurately captures this idea. Options A (<i>aeterna</i>, 'eternal'), C (<i>stabilis</i>, 'stable'), and D (<i>longa</i>, 'long') all contradict the notion of life passing swiftly and being impossible to retain." }, { meta: "Fill-in-the-Blank", stem: "Hostēs, spē praedae incēnsī, mūrōs urbis acriter _____ per multōs diēs, sed nūllum frāctum invēnērunt.", options: ["dēfendēbant", "oppugnābant", "aedificābant", "ornābant"], i: 1, explanation: "The phrase 'spē praedae incēnsī' (inflamed by hope of plunder) indicates that the 'hostēs' (enemies) are attacking. They are acting 'acriter' (fiercely) against 'mūrōs urbis' (the walls of the city) for 'multōs diēs' (many days), yet found 'nūllum frāctum' (no breach). This context points to a siege. <b>Oppugnābant</b>, meaning 'were besieging' or 'were attacking', is the correct verb. Option A (<i>dēfendēbant</i>, 'were defending') contradicts the idea of 'hostēs' seeking plunder. Options C (<i>aedificābant</i>, 'were building') and D (<i>ornābant</i>, 'were decorating') are absurd in a context of enemies and city walls." }, { meta: "Fill-in-the-Blank", stem: "Nēmō illī virō crēdēbat, propter eius nōtissimam _____, quī semper promissa fallēbat et amīcōs trādēbat.", options: ["fidem", "perfidiam", "virtūtem", "cōstantiam"], i: 1, explanation: "The phrase 'quī semper promissa fallēbat et amīcōs trādēbat' (who always deceived promises and betrayed friends) describes a person characterized by deceit and disloyalty. <b>Perfidiam</b>, meaning 'treachery' or 'perfidy', perfectly fits this description. Options A (<i>fidem</i>, 'faith' or 'loyalty'), C (<i>virtūtem</i>, 'virtue'), and D (<i>cōstantiam</i>, 'constancy' or 'steadfastness') are all antonyms or virtues that contradict the man's actions." }, { meta: "Fill-in-the-Blank", stem: "Nix alta viātōrēs in Alpibus _____, quō minus ad urbem tempestīvē pervenīrent.", options: ["adiūvit", "accelerāvit", "impedīvit", "praecēpit"], i: 2, explanation: "The clause 'quō minus ad urbem tempestīvē pervenīrent' (so that they might less arrive at the city in time) indicates that the deep snow had a negative effect on the travelers' progress. <b>Impedīvit</b>, meaning 'hindered' or 'impeded', is the correct verb. Options A (<i>adiūvit</i>, 'helped') and B (<i>accelerāvit</i>, 'accelerated') contradict the idea of being prevented from reaching the city on time. Option D (<i>praecēpit</i>, 'instructed' or 'anticipated') is semantically unrelated to the action of snow on travelers." }, { meta: "Fill-in-the-Blank", stem: "Rēx ille, cuius nōmen odiōsum erat, propter suam _____, populum suum tyrannicē regēbat.", options: ["clementiam", "saevitiam", "iūstitiam", "sapientiam"], i: 1, explanation: "The phrase 'populum suum tyrannicē regēbat' (ruled his people tyrannically) and 'cuius nōmen odiōsum erat' (whose name was hateful) clearly describe a cruel ruler. <b>Saevitiam</b>, meaning 'cruelty' or 'savagery', is the appropriate characteristic. Options A (<i>clementiam</i>, 'clemency'), C (<i>iūstitiam</i>, 'justice'), and D (<i>sapientiam</i>, 'wisdom') are all virtues that contradict the description of a tyrannical and hateful king." }, { meta: "Fill-in-the-Blank", stem: "Subitō magnus armōrum et virōrum _____ ex castrīs hostium audītus est, omnēs terrēns.", options: ["amor", "clāmor", "dolor", "honor"], i: 1, explanation: "The sentence describes 'magnus armōrum et virōrum' (a great [something] of arms and men) heard 'ex castrīs hostium' (from the enemy camp), which 'omnēs terrēns' (terrified everyone). This context strongly suggests a loud noise. <b>Clāmor</b>, meaning 'shout' or 'uproar', fits perfectly. Options A (<i>amor</i>, 'love'), C (<i>dolor</i>, 'pain'), and D (<i>honor</i>, 'honor') are abstract nouns that do not describe a sound emanating from a camp and terrifying people." }, { meta: "Fill-in-the-Blank", stem: "Antīquī crēdēbant _____ esse potentiam dīvīnam, quod nūllus mortālis mūtāre potest.", options: ["arbitrium", "fātum", "cōnsilium", "fortūnam"], i: 1, explanation: "The phrase 'quod nūllus mortālis mūtāre potest' (which no mortal can change) refers to an unalterable divine power. <b>Fātum</b>, meaning 'fate' or 'destiny', is precisely this concept in ancient belief. Options A (<i>arbitrium</i>, 'choice' or 'will') and C (<i>cōnsilium</i>, 'plan' or 'counsel') imply human agency, directly contradicting the unchangeable nature described. Option D (<i>fortūnam</i>, 'fortune' or 'luck') is generally considered more capricious and mutable than immutable fate, especially at an advanced level of Latin understanding." }, { meta: "Fill-in-the-Blank", stem: "Cicero, propter suam _____, quae tanta ēloquentia et rērum pondere pollebat, princeps ōrātōrum habēbātur.", options: ["silentium", "brevitatem", "ōrātiōnem", "ignōrantiam"], i: 2, explanation: "The sentence describes Cicero as 'princeps ōrātōrum' (foremost of orators) due to something 'quae tanta ēloquentia et rērum pondere pollebat' (which excelled with such eloquence and weight of subject matter). This refers to his speaking ability and style. <b>Ōrātiōnem</b>, meaning 'speech' or 'style of speaking', is the most fitting term. Options A (<i>silentium</i>, 'silence') and D (<i>ignōrantiam</i>, 'ignorance') directly contradict the idea of eloquence. Option B (<i>brevitatem</i>, 'brevity') is not the primary characteristic that would make one the 'foremost of orators' when 'weight of subject matter' is also highlighted; Cicero was known for his expansive and powerful rhetoric, not necessarily brevity as a defining trait." }, { meta: "Circumlocution", stem: "Spatium temporis longissimum, saepe infinitum, quod omnia complectitur.", options: ["aevum", "saeculum", "lūstrum", "fātum"], i: 0, explanation: "The correct answer is <b>aevum</b>, meaning 'age, time, eternity,' often used poetically to denote a vast or infinite span of time. The Latin definition describes 'a very long, often infinite space of time, which embraces all things.'<br>B. <b>saeculum</b> means 'age, generation, century,' referring to a definite, albeit long, period, not necessarily infinite.<br>C. <b>lūstrum</b> refers to a specific period of five years, a census period.<br>D. <b>fātum</b> means 'fate, destiny,' an abstract concept but not directly related to a span of time." }, { meta: "Circumlocution", stem: "Rēs quae animum trīstem levat aut dolōrem minuit.", options: ["sōlācium", "auxilium", "remedium", "dōnum"], i: 0, explanation: "The correct answer is <b>sōlācium</b>, meaning 'solace, comfort, consolation.' The definition 'a thing which lightens a sad spirit or lessens pain' perfectly describes solace.<br>B. <b>auxilium</b> means 'help, aid,' which can alleviate suffering but is a broader term for assistance.<br>C. <b>remedium</b> means 'cure, remedy,' implying a solution or treatment for a problem or illness.<br>D. <b>dōnum</b> means 'gift,' which might bring joy but is not primarily defined by its comforting effect." }, { meta: "Circumlocution", stem: "Ignis ingēns et dēvāstāns, quī multa simul cōnsūmit.", options: ["cōnflāgrātiō", "dēvāstātiō", "calamitās", "strāgēs"], i: 0, explanation: "The correct answer is <b>cōnflāgrātiō</b>, meaning 'conflagration, a great fire.' The definition 'a huge and devastating fire, which consumes many things at once' precisely describes this term.<br>B. <b>dēvāstātiō</b> means 'devastation, laying waste,' referring to the act or result of destruction, which can be caused by fire but is not the fire itself.<br>C. <b>calamitās</b> means 'disaster, misfortune,' a general term for a harmful event.<br>D. <b>strāgēs</b> means 'slaughter, massacre, ruin, overthrow,' referring to widespread destruction or killing, but not specifically fire." }, { meta: "Circumlocution", stem: "Mōrēs vel actiōnēs quibus aliī placēre aut eīs pāreō studēmus.", options: ["obsequium", "imperium", "beneficium", "servitium"], i: 0, explanation: "The correct answer is <b>obsequium</b>, meaning 'compliance, deference, obedience, complaisance.' The definition 'manners or actions by which we strive to please others or obey them' accurately captures the essence of willing submission or courteous compliance.<br>B. <b>imperium</b> means 'command, power, authority,' the opposite of obedience.<br>C. <b>beneficium</b> means 'kindness, favor, benefit,' a good deed done for someone.<br>D. <b>servitium</b> means 'slavery, servitude, service,' implying a state of being a slave or forced service, which is distinct from voluntary deference." }, { meta: "Circumlocution", stem: "Nātūra īnsita et ingenium quod ab initiō cuique adest.", options: ["indolēs", "virtūs", "ratiō", "fēlīcitās"], i: 0, explanation: "The correct answer is <b>indolēs</b>, meaning 'innate character, nature, disposition, inherent quality.' The definition 'inborn nature and talent which is present in each from the beginning' perfectly describes this concept.<br>B. <b>virtūs</b> means 'virtue, courage, excellence,' referring to moral goodness or strength, which is a part of character but not the entire innate disposition.<br>C. <b>ratiō</b> means 'reason, reckoning, method,' referring to the faculty of thought or a logical process.<br>D. <b>fēlīcitās</b> means 'happiness, good fortune,' referring to a state of being or an external condition, not an inherent quality." }, { meta: "Circumlocution", stem: "Actus supplicandī vel ōrandī ut malum āvertātur aut venia petātur.", options: ["dēprecātiō", "supplicātiō", "ōrātiō", "obsecrātiō"], i: 0, explanation: "The correct answer is <b>dēprecātiō</b>, meaning 'earnest prayer, entreaty, averting by prayer, deprecation.' The definition 'the act of supplicating or praying that evil may be averted or pardon sought' aligns precisely with <i>dēprecātiō</i>, which often involves praying to ward off something undesirable.<br>B. <b>supplicātiō</b> means 'public prayer, thanksgiving, supplication,' often a formal public religious observance.<br>C. <b>ōrātiō</b> means 'speech, prayer,' a general term for speaking, including formal addresses or prayers.<br>D. <b>obsecrātiō</b> means 'entreaty, supplication, earnest prayer,' very close to <i>dēprecātiō</i> but often implying a more general plea, whereas <i>dēprecātiō</i> specifically carries the nuance of averting evil or seeking pardon." }, { meta: "Circumlocution", stem: "Quod ad lūctum aut trīstitiam maximam pertinet.", options: ["lūgubris", "fūnebris", "trīstis", "mīserābilis"], i: 0, explanation: "The correct answer is <b>lūgubris</b>, an adjective meaning 'mournful, dismal, lamentable, funereal.' The definition 'which pertains to mourning or the greatest sadness' perfectly describes this word.<br>B. <b>fūnebris</b> means 'funereal, deadly, fatal,' pertaining specifically to funerals or death, which can be mournful but is a narrower scope.<br>C. <b>trīstis</b> means 'sad, gloomy, sorrowful,' a general term for sadness.<br>D. <b>mīserābilis</b> means 'lamentable, pitiable, wretched,' describing something that evokes pity or lament, rather than the state of mourning itself." }, { meta: "Circumlocution", stem: "Locī flexuōsī et difficilēs, vel dictiōnēs obscūrae et perplexae.", options: ["ambāgēs", "cōnfūsiōnēs", "difficultātēs", "perplexitātēs"], i: 0, explanation: "The correct answer is <b>ambāgēs</b> (plural only), meaning 'winding paths, circuitous ways, circumlocutions, ambiguities.' The definition 'winding and difficult places, or obscure and perplexing expressions' precisely captures both the literal and figurative meanings of <i>ambāgēs</i>.<br>B. <b>cōnfūsiōnēs</b> means 'confusions, disorders,' referring to a state of being confused or disordered.<br>C. <b>difficultātēs</b> means 'difficulties, troubles,' referring to obstacles or hard situations.<br>D. <b>perplexitātēs</b> means 'perplexities, entanglements,' referring to states of being intricate or confused, but <i>ambāgēs</i> specifically denotes the winding paths or obscure expressions themselves, not just the state of perplexity." }, { meta: "Circumlocution", stem: "Sonitum facere quī alterum sonitum impedit aut taciturnitātem rumpit.", options: ["obstrepere", "interloquī", "obmūtēscere", "rumpere"], i: 0, explanation: "The correct answer is <b>obstrepere</b>, meaning 'to make a noise against, interrupt, drown out, clamor.' The definition 'to make a sound which hinders another sound or breaks silence' accurately describes this verb.<br>B. <b>interloquī</b> means 'to interrupt (by speaking), interject,' which involves speaking against, but <i>obstrepere</i> is broader, referring to any noise.<br>C. <b>obmūtēscere</b> means 'to become dumb or silent,' which is the opposite of making a sound.<br>D. <b>rumpere</b> means 'to break, burst,' which can apply to breaking silence but is a more general verb for breaking something, not specifically making a noise against another." }, { meta: "Circumlocution", stem: "Rēs ā corpore vel hoste dētractae, ut pellis serpentis aut arma capta.", options: ["exuviae", "reliquiae", "praedae", "manubiae"], i: 0, explanation: "The correct answer is <b>exuviae</b> (plural only), meaning 'things stripped off, cast-off clothes, spoils of war, relics.' The definition 'things stripped from a body or an enemy, such as a serpent's skin or captured arms' perfectly encapsulates the dual meaning of <i>exuviae</i> as both cast-off biological material and military spoils.<br>B. <b>reliquiae</b> (plural only) means 'remains, relics, remnants,' referring to what is left behind, which can include things stripped off but is a broader term.<br>C. <b>praedae</b> (plural of <i>praeda</i>) means 'booty, plunder, prey,' referring to things taken by force, often from animals or enemies.<br>D. <b>manubiae</b> (plural only) means 'spoils of war, prize money,' specifically referring to the money obtained from the sale of spoils, or the spoils themselves, but <i>exuviae</i> has the added nuance of things 'stripped off' or 'cast off' from a body." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>arx</b>", options: ["art, skill", "citadel, stronghold", "axle, axis", "air"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Arx, arcis, f.</i> means 'citadel' or 'stronghold'. Option <b>A</b>, 'art, skill', is the translation of <i>ars, artis, f.</i> Option <b>C</b>, 'axle, axis', is the translation of <i>axis, axis, m.</i> Option <b>D</b>, 'air', is the translation of <i>āēr, āeris, m.</i> All are third declension nouns, but with distinct meanings." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>cāsus</b>", options: ["hut, cottage", "cheese", "fall, chance, misfortune", "hunting nets"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Cāsus, -ūs, m.</i> means 'fall, chance, accident, misfortune'. Option <b>A</b>, 'hut, cottage', is the translation of <i>casa, -ae, f.</i> Option <b>B</b>, 'cheese', is the translation of <i>cāseus, -ī, m.</i> Option <b>D</b>, 'hunting nets', is the translation of <i>cassēs, -ium, m. pl.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>crīmen</b>", options: ["hair", "sieve", "charge, accusation, crime", "gore, blood"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Crīmen, crīminis, n.</i> means 'charge, accusation, crime'. Option <b>A</b>, 'hair', is the translation of <i>crīnis, crīnis, m.</i> Option <b>B</b>, 'sieve', is the translation of <i>crībrum, -ī, n.</i> Option <b>D</b>, 'gore, blood', is the translation of <i>cruor, cruōris, m.</i> All are nouns with similar initial sounds." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>fīnis</b>", options: ["faith, trust", "fountain, spring", "end, boundary", "thread, fiber"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Fīnis, fīnis, m.</i> means 'end, boundary' (in plural, 'territory'). Option <b>A</b>, 'faith, trust', is the translation of <i>fīdēs, fīdeī, f.</i> Option <b>B</b>, 'fountain, spring', is the translation of <i>fōns, fontis, m.</i> Option <b>D</b>, 'thread, fiber', is the translation of <i>fīlum, -ī, n.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>frōns</b>", options: ["deceit, fraud", "forehead, brow", "fruit, crop", "rope, cable"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Frōns, frontis, f.</i> means 'forehead' or 'brow'. (Note: <i>frōns, frondis, f.</i> means 'leafy branch', but 'forehead' is a more common advanced usage). Option <b>A</b>, 'deceit, fraud', is the translation of <i>fraus, fraudis, f.</i> Option <b>C</b>, 'fruit, crop', is the translation of <i>frūx, frūgis, f.</i> Option <b>D</b>, 'rope, cable', is the translation of <i>fūnis, fūnis, m.</i> All are third declension nouns." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>fūnus</b>", options: ["rope, cable", "funeral, death", "smoke", "bottom, farm"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Fūnus, fūneris, n.</i> means 'funeral' or 'death'. Option <b>A</b>, 'rope, cable', is the translation of <i>fūnis, fūnis, m.</i> Option <b>C</b>, 'smoke', is the translation of <i>fūmus, -ī, m.</i> Option <b>D</b>, 'bottom, farm', is the translation of <i>fundus, -ī, m.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>hostis</b>", options: ["guest, host, stranger", "honor, esteem", "enemy, foe", "garden"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Hostis, hostis, m./f.</i> means 'enemy' or 'foe'. Option <b>A</b>, 'guest, host, stranger', is the translation of <i>hospes, hospitis, m./f.</i> Option <b>B</b>, 'honor, esteem', is the translation of <i>honor, honōris, m.</i> Option <b>D</b>, 'garden', is the translation of <i>hortus, -ī, m.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>lītus</b>", options: ["flax, linen", "shore, beach", "attendant, lictor", "light, lamp"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Lītus, lītoris, n.</i> means 'shore' or 'beach'. Option <b>A</b>, 'flax, linen', is the translation of <i>līnum, -ī, n.</i> Option <b>C</b>, 'attendant, lictor', is the translation of <i>līctor, līctōris, m.</i> Option <b>D</b>, 'light, lamp', is the translation of <i>lūmen, lūminis, n.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>mōs</b>", options: ["death", "wall", "custom, manner, habit", "duty, gift"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Mōs, mōris, m.</i> means 'custom, manner, habit' (in plural, 'character'). Option <b>A</b>, 'death', is the translation of <i>mors, mortis, f.</i> Option <b>B</b>, 'wall', is the translation of <i>mūrus, -ī, m.</i> Option <b>D</b>, 'duty, gift', is the translation of <i>mūnus, mūneris, n.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>nūmen</b>", options: ["number", "divine will, divinity", "nurse", "cloud"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Nūmen, nūminis, n.</i> means 'divine will, divine power, divinity'. Option <b>A</b>, 'number', is the translation of <i>nūmerus, -ī, m.</i> Option <b>C</b>, 'nurse', is the translation of <i>nūtrīx, nūtrīcis, f.</i> Option <b>D</b>, 'cloud', is the translation of <i>nūbēs, nūbis, f.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>ōra</b>", options: ["mouth, face", "bone", "shore, coast", "speaker, orator"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Ōra, -ae, f.</i> means 'shore' or 'coast'. Option <b>A</b>, 'mouth, face', is the translation of <i>ōs, ōris, n.</i> Option <b>B</b>, 'bone', is the translation of <i>os, ossis, n.</i> Option <b>D</b>, 'speaker, orator', is the translation of <i>ōrātor, ōrātōris, m.</i> These words are often confused due to similar spellings and pronunciations." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>pectus</b>", options: ["flock, herd", "money", "chest, breast, heart", "peace"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Pectus, pectoris, n.</i> means 'chest, breast, heart'. Option <b>A</b>, 'flock, herd', is the translation of <i>pecus, pecoris, n.</i> Option <b>B</b>, 'money', is the translation of <i>pecūnia, -ae, f.</i> Option <b>D</b>, 'peace', is the translation of <i>pāx, pācis, f.</i> The similarity between <i>pectus</i> and <i>pecus</i> is a common source of confusion." }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>pontus</b>", options: ["bridge", "sea, ocean", "fruit, apple", "weight, burden"], i: 1, explanation: "The correct answer is <b>B</b>. <i>Pontus, -ī, m.</i> means 'sea' or 'ocean' (especially in poetic contexts). Option <b>A</b>, 'bridge', is the translation of <i>pōns, pontis, m.</i> Option <b>C</b>, 'fruit, apple', is the translation of <i>pōmum, -ī, n.</i> Option <b>D</b>, 'weight, burden', is the translation of <i>pondus, ponderis, n.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>sīdus</b>", options: ["site, position", "dagger", "star, constellation", "sign, standard"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Sīdus, sīderis, n.</i> means 'star' or 'constellation'. Option <b>A</b>, 'site, position', is the translation of <i>situs, -ūs, m.</i> Option <b>B</b>, 'dagger', is the translation of <i>sīca, -ae, f.</i> Option <b>D</b>, 'sign, standard', is the translation of <i>sīgnum, -ī, n.</i>" }, { meta: "Latin to English", stem: "Choose the best English translation for: <b>tellūs</b>", options: ["weapon, spear", "web, warp", "earth, land, ground", "terror, dread"], i: 2, explanation: "The correct answer is <b>C</b>. <i>Tellūs, tellūris, f.</i> means 'earth, land, ground'. Option <b>A</b>, 'weapon, spear', is the translation of <i>tēlum, -ī, n.</i> Option <b>B</b>, 'web, warp', is the translation of <i>tēla, -ae, f.</i> Option <b>D</b>, 'terror, dread', is the translation of <i>terror, terrōris, m.</i>" }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to lament, bewail", options: ["pulsō", "pendeō", "plangō", "pōscō"], i: 2, explanation: "The correct Latin verb for 'to lament, bewail' is <b>plangō, plangere, planxī, planctus</b>. Option A, <b>pulsō</b>, means 'to beat, strike'. Option B, <b>pendeō</b>, means 'to hang, be suspended'. Option D, <b>pōscō</b>, means 'to demand, request'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a hinge, pivot", options: ["carō, carnis", "cardō, cardinis", "caedēs, caedis", "cacūmen, cacūminis"], i: 1, explanation: "The correct Latin noun for 'a hinge, pivot' is <b>cardō, cardinis</b> (m.). Option A, <b>carō, carnis</b> (f.), means 'flesh'. Option C, <b>caedēs, caedis</b> (f.), means 'slaughter, massacre'. Option D, <b>cacūmen, cacūminis</b> (n.), means 'summit, peak'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to propitiate, appease", options: ["placeō", "plicō", "plācō", "plangō"], i: 2, explanation: "The correct Latin verb for 'to propitiate, appease' is <b>plācō, plācāre, plācāvī, plācātus</b>. Option A, <b>placeō</b>, means 'to please'. Option B, <b>plicō</b>, means 'to fold'. Option D, <b>plangō</b>, means 'to strike, lament'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a ram, battering ram", options: ["āra, ārae", "ariēs, arietis", "auris, auris", "arātor, arātōris"], i: 1, explanation: "The correct Latin noun for 'a ram, battering ram' is <b>ariēs, arietis</b> (m.). Option A, <b>āra, ārae</b> (f.), means 'altar'. Option C, <b>auris, auris</b> (f.), means 'ear'. Option D, <b>arātor, arātōris</b> (m.), means 'plowman'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to wander, stray", options: ["eō", "errō", "orior", "ōrō"], i: 1, explanation: "The correct Latin verb for 'to wander, stray' is <b>errō, errāre, errāvī, errātus</b>. Option A, <b>eō</b>, means 'to go'. Option C, <b>orior</b>, means 'to rise, arise'. Option D, <b>ōrō</b>, means 'to beg, pray'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a threshold, doorstep", options: ["lūmen, lūminis", "līnum, līni", "līmen, līminis", "līs, lītis"], i: 2, explanation: "The correct Latin noun for 'a threshold, doorstep' is <b>līmen, līminis</b> (n.). Option A, <b>lūmen, lūminis</b> (n.), means 'light'. Option B, <b>līnum, līni</b> (n.), means 'flax, linen'. Option D, <b>līs, lītis</b> (f.), means 'strife, dispute'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to gleam, shine", options: ["fulciō", "fulgeō", "fundō", "fūriō"], i: 1, explanation: "The correct Latin verb for 'to gleam, shine' is <b>fulgeō, fulgēre, fulsī</b>. Option A, <b>fulciō</b>, means 'to prop up, support'. Option C, <b>fundō</b>, means 'to pour, establish'. Option D, <b>fūriō</b>, means 'to rage, madden'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a marsh, swamp", options: ["palla, pallae", "pālus, pāli", "palūs, palūdis", "pulvis, pulveris"], i: 2, explanation: "The correct Latin noun for 'a marsh, swamp' is <b>palūs, palūdis</b> (f.). Option A, <b>palla, pallae</b> (f.), means 'cloak, robe'. Option B, <b>pālus, pāli</b> (m.), means 'stake, pole'. Option D, <b>pulvis, pulveris</b> (m.), means 'dust'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to be ashamed", options: ["putō", "pūniō", "pudet", "pōscō"], i: 2, explanation: "The correct Latin impersonal verb for 'to be ashamed' is <b>pudet, pudēre, puduit</b> (it shames, one is ashamed). Option A, <b>putō</b>, means 'to think, consider'. Option B, <b>pūniō</b>, means 'to punish'. Option D, <b>pōscō</b>, means 'to demand, request'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a chasm, abyss", options: ["balneum, balneī", "barathrum, barathrī", "bracchium, bracchiī", "bellum, bellī"], i: 1, explanation: "The correct Latin noun for 'a chasm, abyss' is <b>barathrum, barathrī</b> (n.). Option A, <b>balneum, balneī</b> (n.), means 'bath'. Option C, <b>bracchium, bracchiī</b> (n.), means 'arm'. Option D, <b>bellum, bellī</b> (n.), means 'war'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to cling to, hold fast", options: ["habeō", "horreō", "haereō", "hūmō"], i: 2, explanation: "The correct Latin verb for 'to cling to, hold fast' is <b>haereō, haerēre, haesī, haesus</b>. Option A, <b>habeō</b>, means 'to have, hold'. Option B, <b>horreō</b>, means 'to shudder, dread'. Option D, <b>hūmō</b>, means 'to bury'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a shroud, covering", options: ["tēlum, tēlī", "temō, temōnis", "tegmen, tegminis", "tēgula, tēgulae"], i: 2, explanation: "The correct Latin noun for 'a shroud, covering' is <b>tegmen, tegminis</b> (n.). Option A, <b>tēlum, tēlī</b> (n.), means 'weapon, dart'. Option B, <b>temō, temōnis</b> (m.), means 'pole, tongue of a wagon'. Option D, <b>tēgula, tēgulae</b> (f.), means 'tile'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to mock, deride", options: ["allūdō", "illūdō", "ēdūcō", "lūdō"], i: 1, explanation: "The correct Latin verb for 'to mock, deride' is <b>illūdō, illūdere, illūsī, illūsus</b>. Option A, <b>allūdō</b>, means 'to play with, jest at'. Option C, <b>ēdūcō</b>, means 'to lead out, bring up, educate'. Option D, <b>lūdō</b>, means 'to play, sport'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: a portent, omen", options: ["prōvidentia, prōvidentiae", "prōlēs, prōlis", "prōdigium, prōdigiī", "prōra, prōrae"], i: 2, explanation: "The correct Latin noun for 'a portent, omen' is <b>prōdigium, prōdigiī</b> (n.). Option A, <b>prōvidentia, prōvidentiae</b> (f.), means 'foresight, providence'. Option B, <b>prōlēs, prōlis</b> (f.), means 'offspring, progeny'. Option D, <b>prōra, prōrae</b> (f.), means 'prow (of a ship)'." }, { meta: "English to Latin", stem: "Choose the best Latin translation for: to defile, pollute", options: ["pellō", "polleō", "polluō", "pōscō"], i: 2, explanation: "The correct Latin verb for 'to defile, pollute' is <b>polluō, polluere, polluī, pollūtus</b>. Option A, <b>pellō</b>, means 'to drive, push'. Option B, <b>polleō</b>, means 'to be strong, powerful'. Option D, <b>pōscō</b>, means 'to demand, request'." }, { meta: "Synonyms", stem: "<i>aequor</i>", options: ["<i>pontus</i>", "<i>fluctus</i>", "<i>lītus</i>", "<i>unda</i>"], i: 0, explanation: "<i>Aequor</i> is a poetic term for the 'sea' or 'level surface'. <i>Pontus</i> is also a poetic term for the 'sea'. <i>Fluctus</i> and <i>unda</i> both mean 'wave', while <i>lītus</i> means 'shore'." }, { meta: "Synonyms", stem: "<i>fās</i>", options: ["<i>lēx</i>", "<i>ius</i>", "<i>aequitās</i>", "<i>licentia</i>"], i: 1, explanation: "<i>Fās</i> refers to divine law, right, or what is religiously permissible. <i>Ius</i> can also refer to divine or natural law, and often overlaps with <i>fās</i> in meaning, particularly in philosophical and religious contexts. <i>Lēx</i> typically denotes human, enacted law. <i>Aequitās</i> means 'fairness' or 'equity', and <i>licentia</i> means 'freedom' or 'license'." }, { meta: "Synonyms", stem: "<i>volucer</i>", options: ["<i>ferus</i>", "<i>alēs</i>", "<i>piscis</i>", "<i>reptīle</i>"], i: 1, explanation: "When used as a noun, <i>volucer</i> means 'a bird' or 'winged creature'. <i>Alēs</i> is a direct synonym, also meaning 'bird' or 'winged creature', often with an augural connotation. <i>Ferus</i> means 'wild beast', <i>piscis</i> means 'fish', and <i>reptīle</i> means 'reptile'." }, { meta: "Synonyms", stem: "<i>conqueror</i>", options: ["<i>laudō</i>", "<i>gaudeō</i>", "<i>queror</i>", "<i>rīdeō</i>"], i: 2, explanation: "<i>Conqueror</i> is an intensive form of <i>queror</i>, both meaning 'to complain, lament, bewail'. The prefix <i>con-</i> in this context often intensifies the action. <i>Laudō</i> means 'to praise', <i>gaudeō</i> 'to rejoice', and <i>rīdeō</i> 'to laugh'." }, { meta: "Synonyms", stem: "<i>prōlēs</i>", options: ["<i>parentēs</i>", "<i>stirps</i>", "<i>familia</i>", "<i>genus</i>"], i: 1, explanation: "<i>Prōlēs</i> means 'offspring, progeny, race'. <i>Stirps</i> is a close synonym, referring to 'root, stock, lineage, offspring'. <i>Parentēs</i> are 'parents', <i>familia</i> is 'family', and <i>genus</i> refers to 'origin' or 'kind'." }, { meta: "Synonyms", stem: "<i>cōnātus</i>", options: ["<i>victōria</i>", "<i>dēfēnsiō</i>", "<i>temptāmen</i>", "<i>fuga</i>"], i: 2, explanation: "<i>Cōnātus</i> means 'an attempt, effort, undertaking'. <i>Temptāmen</i> is a direct synonym, meaning 'an attempt, trial, effort'. <i>Victōria</i> means 'victory', <i>dēfēnsiō</i> 'defense', and <i>fuga</i> 'flight'." }, { meta: "Synonyms", stem: "<i>fax</i>", options: ["<i>ignis</i>", "<i>flamma</i>", "<i>tēda</i>", "<i>lūmen</i>"], i: 2, explanation: "<i>Fax</i> means 'torch'. <i>Tēda</i> specifically refers to a 'pine torch', and by extension simply 'torch', making it a very close synonym, especially in poetic contexts. <i>Ignis</i> is 'fire', <i>flamma</i> is 'flame', and <i>lūmen</i> is 'light'; these are related but not direct synonyms for the object itself." }, { meta: "Synonyms", stem: "<i>ōmen</i>", options: ["<i>fātum</i>", "<i>prōdigium</i>", "<i>fortūna</i>", "<i>cāsus</i>"], i: 1, explanation: "<i>Ōmen</i> means 'omen, portent, sign'. <i>Prōdigium</i> is a direct synonym, also meaning 'omen, portent, sign', often implying something unnatural or monstrous. <i>Fātum</i> is 'fate', <i>fortūna</i> is 'fortune', and <i>cāsus</i> is 'chance' or 'accident'." }, { meta: "Synonyms", stem: "<i>opācus</i>", options: ["<i>lūcidus</i>", "<i>umbrōsus</i>", "<i>apertus</i>", "<i>clārus</i>"], i: 1, explanation: "<i>Opācus</i> means 'shady, dark, opaque'. <i>Umbrōsus</i> means 'shady, full of shade', making it a close synonym for the 'shady' aspect of <i>opācus</i>. <i>Lūcidus</i> means 'bright', <i>apertus</i> 'open', and <i>clārus</i> 'clear' or 'famous'." }, { meta: "Synonyms", stem: "<i>cōnsors</i>", options: ["<i>hostis</i>", "<i>socius</i>", "<i>servus</i>", "<i>dominus</i>"], i: 1, explanation: "<i>Cōnsors</i> means 'partner, sharer, associate'. <i>Socius</i> is a direct synonym, meaning 'companion, partner, ally'. <i>Hostis</i> means 'enemy', <i>servus</i> 'slave', and <i>dominus</i> 'master'." }, { meta: "Synonyms", stem: "<i>aevum</i>", options: ["<i>tempus</i>", "<i>diēs</i>", "<i>saeculum</i>", "<i>annus</i>"], i: 2, explanation: "<i>Aevum</i> means 'age, lifetime, eternity'. <i>Saeculum</i> means 'age, generation, century', often used synonymously with <i>aevum</i> for a long period of time or an era. <i>Tempus</i> is general 'time', <i>diēs</i> is 'day', and <i>annus</i> is 'year'." }, { meta: "Synonyms", stem: "<i>lētum</i>", options: ["<i>vīta</i>", "<i>mors</i>", "<i>nātūra</i>", "<i>salūs</i>"], i: 1, explanation: "<i>Lētum</i> is a poetic word for 'death, destruction'. <i>Mors</i> is the standard word for 'death'. <i>Vīta</i> means 'life', <i>nātūra</i> 'nature', and <i>salūs</i> 'safety' or 'health'." }, { meta: "Synonyms", stem: "<i>ēnsis</i>", options: ["<i>scūtum</i>", "<i>galea</i>", "<i>gladius</i>", "<i>pīlum</i>"], i: 2, explanation: "<i>Ēnsis</i> is a poetic word for 'sword'. <i>Gladius</i> is the standard word for 'sword'. <i>Scūtum</i> means 'shield', <i>galea</i> 'helmet', and <i>pīlum</i> 'javelin'." }, { meta: "Synonyms", stem: "<i>nūmen</i>", options: ["<i>dīvīnitās</i>", "<i>sacrum</i>", "<i>templum</i>", "<i>sacerdōs</i>"], i: 0, explanation: "<i>Nūmen</i> refers to 'divine power, divine will, a deity'. <i>Dīvīnitās</i> means 'divinity, divine nature, divine power', making it the closest synonym. <i>Sacrum</i> is a 'sacred thing', <i>templum</i> is a 'temple', and <i>sacerdōs</i> is a 'priest'; these are related to religious practice but not direct synonyms for divine power itself." }, { meta: "Synonyms", stem: "<i>vātēs</i>", options: ["<i>mīles</i>", "<i>poēta</i>", "<i>agricola</i>", "<i>mercātor</i>"], i: 1, explanation: "<i>Vātēs</i> means 'prophet, seer, bard, poet'. <i>Poēta</i> means 'poet', and in ancient contexts, poets were often seen as divinely inspired, blurring the lines with prophets. This makes <i>poēta</i> a very close synonym, especially in poetic contexts where <i>vātēs</i> is frequently used. <i>Mīles</i> means 'soldier', <i>agricola</i> 'farmer', and <i>mercātor</i> 'merchant'." }, { meta: "Antonyms", stem: "ōtium", options: ["negōtium", "studium", "silentium", "imperium"], i: 0, explanation: "The word <i>ōtium</i> means 'leisure, peace, quiet'. Its direct antonym, referring to a lack of leisure or a state of business/trouble, is <i>negōtium</i>. All options are second declension neuter nouns. <i>Studium</i> means 'eagerness, zeal'. <i>Silentium</i> means 'silence'. <i>Imperium</i> means 'command, empire'." }, { meta: "Antonyms", stem: "sōlācium", options: ["maeror", "timor", "fūror", "labōr"], i: 0, explanation: "The word <i>sōlācium</i> means 'comfort, consolation'. The closest antonym, expressing deep sorrow or grief, is <i>maeror</i>. All options are third declension masculine nouns. <i>Timor</i> means 'fear'. <i>Fūror</i> means 'rage, madness'. <i>Labōr</i> means 'toil, effort'." }, { meta: "Antonyms", stem: "arduus", options: ["facilis", "lēnis", "mollis", "humilis"], i: 0, explanation: "The word <i>arduus</i> means 'steep, difficult'. The most direct antonym, especially in the sense of 'difficult', is <i>facilis</i>, meaning 'easy'. All options are adjectives. <i>Lēnis</i> means 'gentle, mild'. <i>Mollis</i> means 'soft, yielding'. <i>Humilis</i> means 'lowly, humble'." }, { meta: "Antonyms", stem: "obscūrus", options: ["clārus", "apertus", "manifestus", "serēnus"], i: 0, explanation: "The word <i>obscūrus</i> means 'dark, obscure, unclear'. Its direct antonym, meaning 'bright, clear, famous', is <i>clārus</i>. All options are adjectives. <i>Apertus</i> means 'open, exposed'. <i>Manifestus</i> means 'evident, clear'. <i>Serēnus</i> means 'calm, clear (of weather)'." }, { meta: "Antonyms", stem: "celer", options: ["tardus", "iners", "lentus", "gravis"], i: 0, explanation: "The word <i>celer</i> means 'swift, quick'. The most direct antonym is <i>tardus</i>, meaning 'slow'. All options are adjectives. <i>Iners</i> means 'inactive, sluggish'. <i>Lentus</i> also means 'slow, sluggish', but <i>tardus</i> is a more common and direct opposite for 'swift'. <i>Gravis</i> means 'heavy, serious'." }, { meta: "Antonyms", stem: "incipiō", options: ["finiō", "dēsinō", "intermittō", "cōnsūmō"], i: 0, explanation: "The verb <i>incipiō</i> means 'to begin, undertake'. The most direct antonym is <i>finiō</i>, meaning 'to end, finish'. All options are verbs. <i>Dēsinō</i> means 'to cease, stop'. <i>Intermittō</i> means 'to interrupt, cease for a time'. <i>Cōnsūmō</i> means 'to consume, use up, finish'." }, { meta: "Antonyms", stem: "virtūs", options: ["vitium", "odium", "perīculum", "imperium"], i: 0, explanation: "The word <i>virtūs</i> means 'virtue, excellence, courage'. Its direct antonym, referring to a moral fault or defect, is <i>vitium</i>. All options are second declension neuter nouns. <i>Odium</i> means 'hatred'. <i>Perīculum</i> means 'danger'. <i>Imperium</i> means 'command, power'." }, { meta: "Antonyms", stem: "pauper", options: ["dīves", "opulentus", "locuplēs", "potēns"], i: 0, explanation: "The word <i>pauper</i> means 'poor, needy'. The most common and direct antonym is <i>dīves</i>, meaning 'rich, wealthy'. All options are adjectives. <i>Opulentus</i> means 'wealthy, rich'. <i>Locuplēs</i> means 'wealthy, substantial'. <i>Potēns</i> means 'powerful, able'." }, { meta: "Antonyms", stem: "amīcitia", options: ["inimīcitia", "discordia", "īra", "cūra"], i: 0, explanation: "The word <i>amīcitia</i> means 'friendship'. Its direct antonym, meaning 'enmity, hostility', is <i>inimīcitia</i>. All options are first declension feminine nouns. <i>Discordia</i> means 'discord, disagreement'. <i>Īra</i> means 'anger, wrath'. <i>Cūra</i> means 'care, anxiety'." }, { meta: "Antonyms", stem: "sapiēns", options: ["stultus", "īnsipiēns", "ignārus", "dēmens"], i: 0, explanation: "The word <i>sapiēns</i> means 'wise, sensible'. The most common and direct antonym is <i>stultus</i>, meaning 'foolish, stupid'. All options are adjectives. <i>Īnsipiēns</i> also means 'unwise, foolish' but is less common as a direct antonym. <i>Ignārus</i> means 'ignorant, unaware'. <i>Dēmens</i> means 'mad, insane'." }, { meta: "Antonyms", stem: "loquor", options: ["taceō", "sileō", "mūtiō", "obmūtēscō"], i: 0, explanation: "The verb <i>loquor</i> means 'to speak, talk'. The most direct antonym, meaning 'to be silent', is <i>taceō</i>. All options are verbs. <i>Sileō</i> also means 'to be silent', but <i>taceō</i> often implies a more active choice to refrain from speaking. <i>Mūtiō</i> means 'to mutter, mumble'. <i>Obmūtēscō</i> means 'to become silent, fall silent'." }, { meta: "Antonyms", stem: "vīvus", options: ["mortuus", "exstīnctus", "dēfūnctus", "frigidus"], i: 0, explanation: "The word <i>vīvus</i> means 'alive, living'. Its direct antonym is <i>mortuus</i>, meaning 'dead'. All options are adjectives (or participles used as adjectives). <i>Exstīnctus</i> means 'extinguished, dead'. <i>Dēfūnctus</i> means 'deceased, dead'. <i>Frigidus</i> means 'cold'." }, { meta: "Antonyms", stem: "aequus", options: ["inīquus", "dispar", "injustus", "prāvus"], i: 0, explanation: "The word <i>aequus</i> means 'equal, fair, level'. Its direct morphological and semantic antonym is <i>inīquus</i>, meaning 'unequal, unfair, uneven'. All options are adjectives. <i>Dispar</i> means 'unequal, unlike'. <i>Injustus</i> means 'unjust'. <i>Prāvus</i> means 'crooked, depraved, wrong'." }, { meta: "Antonyms", stem: "fidēlis", options: ["īnfidēlis", "perfidus", "fallāx", "levis"], i: 0, explanation: "The word <i>fidēlis</i> means 'faithful, loyal'. Its direct morphological antonym is <i>īnfidēlis</i>, meaning 'unfaithful, disloyal'. All options are adjectives. <i>Perfidus</i> means 'treacherous, perfidious'. <i>Fallāx</i> means 'deceitful, treacherous'. <i>Levis</i> means 'light, fickle, inconstant'." }, { meta: "Antonyms", stem: "ōrdō", options: ["cōnfūsiō", "perturbātiō", "dissēnsiō", "seditio"], i: 0, explanation: "The word <i>ōrdō</i> means 'order, rank, arrangement'. The closest antonym, referring to a state of disarray, is <i>cōnfūsiō</i>, meaning 'confusion, disorder'. All options are third declension feminine nouns. <i>Perturbātiō</i> means 'disorder, disturbance'. <i>Dissēnsiō</i> means 'disagreement, discord'. <i>Seditio</i> means 'rebellion, civil strife'." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["annus", "locus", "equus", "corpus"], i: 3, explanation: "The correct answer is <b>corpus</b>. While all four words end in <i>-us</i> in the nominative singular, <b>annus</b>, <b>locus</b>, and <b>equus</b> are all 2nd declension masculine nouns. <b>Corpus</b>, however, is a 3rd declension neuter noun (<i>corpus, corporis</i>)." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["nauta", "silva", "puella", "fēmina"], i: 0, explanation: "The correct answer is <b>nauta</b>. All four words are 1st declension nouns. However, <b>silva</b>, <b>puella</b>, and <b>fēmina</b> are feminine, while <b>nauta</b> (sailor) is one of the common 1st declension nouns that are masculine." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["amō", "regō", "audiō", "audeō"], i: 3, explanation: "The correct answer is <b>audeō</b>. While <b>amō</b> (1st conjugation), <b>regō</b> (3rd conjugation), and <b>audiō</b> (4th conjugation) are all regular active verbs, <b>audeō</b> is a semi-deponent verb (<i>audēre, ausus sum</i>), meaning it has active forms in the present system but deponent forms in the perfect system." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["timor", "metus", "audācia", "pavor"], i: 2, explanation: "The correct answer is <b>audācia</b>. <b>Timor</b>, <b>metus</b>, and <b>pavor</b> are all nouns meaning 'fear' or 'terror' (with slight nuances in intensity or suddenness). <b>Audācia</b>, however, means 'boldness' or 'daring', which is semantically opposite to fear." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["rēx", "dux", "cīvis", "lēx"], i: 2, explanation: "The correct answer is <b>cīvis</b>. All four words are 3rd declension nouns. However, <b>rēx</b> (<i>rēgis</i>), <b>dux</b> (<i>ducis</i>), and <b>lēx</b> (<i>lēgis</i>) are consonant-stem nouns. <b>Cīvis</b> (<i>cīvis</i>) is an i-stem noun, which affects its genitive plural (<i>cīvium</i>) and sometimes its accusative singular (<i>cīvem</i> or <i>cīvim</i>)." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["mare", "pontus", "aequor", "flūmen"], i: 3, explanation: "The correct answer is <b>flūmen</b>. <b>Mare</b>, <b>pontus</b> (often poetic), and <b>aequor</b> (often poetic) all refer to the 'sea' or 'ocean'. <b>Flūmen</b>, on the other hand, means 'river'." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["bonus", "pulcher", "fortis", "magnus"], i: 2, explanation: "The correct answer is <b>fortis</b>. <b>Bonus</b>, <b>pulcher</b>, and <b>magnus</b> are all 1st/2nd declension adjectives (e.g., <i>bonus, bona, bonum</i>; <i>pulcher, pulchra, pulchrum</i>). <b>Fortis</b>, however, is a 3rd declension adjective (e.g., <i>fortis, forte</i>)." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["lūx", "lūmen", "umbra", "candor"], i: 2, explanation: "The correct answer is <b>umbra</b>. <b>Lūx</b> ('light'), <b>lūmen</b> ('light, lamp, eye'), and <b>candor</b> ('brightness, whiteness, radiance') are all related to light or brightness. <b>Umbra</b>, by contrast, means 'shadow' or 'shade'." }, { meta: "Odd One Out", stem: "Which word does not belong by MORPHOLOGY?", options: ["dō", "ferō", "eō", "capiō"], i: 2, explanation: "The correct answer is <b>eō</b>. While <b>dō</b>, <b>ferō</b>, and <b>capiō</b> are all transitive verbs (taking a direct object), <b>eō</b> ('to go') is fundamentally an intransitive verb. Although it can take a direct object in some idiomatic expressions (e.g., <i>īre viam</i>), its core meaning and typical usage are intransitive, unlike the others." }, { meta: "Odd One Out", stem: "Which word does not belong by MEANING?", options: ["virtūs", "fīdēs", "honōs", "arma"], i: 3, explanation: "The correct answer is <b>arma</b>. <b>Virtūs</b> ('courage, virtue'), <b>fīdēs</b> ('faith, loyalty, trust'), and <b>honōs</b> ('honor, esteem') are all abstract nouns representing moral qualities or concepts. <b>Arma</b>, however, is a concrete noun meaning 'arms, weapons'." }, { meta: "Analogies", stem: "<b>digitus</b> : <b>manus</b> :: <b>pēs</b> : X", options: ["crūs", "corpus", "caput", "latus"], i: 0, explanation: "The relationship is 'part to whole'. A <i>digitus</i> (finger) is part of a <i>manus</i> (hand). Similarly, a <i>pēs</i> (foot) is part of a <b>crūs</b> (leg). All options are third declension neuter nouns in the nominative singular, maintaining grammatical consistency among distractors." }, { meta: "Analogies", stem: "<b>ferre</b> : <b>tulisse</b> :: <b>īre</b> : X", options: ["īsse", "fuisse", "potuisse", "voluisse"], i: 0, explanation: "This question tests the transformation from the present active infinitive to the perfect active infinitive of irregular verbs. <i>Ferre</i> (to bear) has the perfect active infinitive <i>tulisse</i> (to have borne). Following this pattern, <i>īre</i> (to go) has the perfect active infinitive <b>īsse</b> (to have gone). All options are perfect active infinitives of irregular verbs." }, { meta: "Analogies", stem: "<b>pulcher</b> : <b>fōrmōsus</b> :: <b>rēx</b> : X", options: ["prīnceps", "dux", "imperātor", "cōnsul"], i: 0, explanation: "The relationship is one of synonymy. <i>Pulcher</i> and <i>fōrmōsus</i> are synonyms for 'beautiful'. Similarly, <i>rēx</i> (king) finds its closest semantic equivalent among the options in <b>prīnceps</b>, which can mean 'chief, leader, emperor', often used to denote a sovereign ruler, especially in later Latin. All options are third declension masculine nouns in the nominative singular, representing various forms of leadership or authority." }, { meta: "Analogies", stem: "<b>gladius</b> : <b>caedēs</b> :: <b>venēnum</b> : X", options: ["mors", "dolor", "aegritūdō", "vulnus"], i: 0, explanation: "The relationship is 'instrument to effect'. A <i>gladius</i> (sword) is an instrument that causes <i>caedēs</i> (slaughter). Following this, <i>venēnum</i> (poison) is an instrument that causes <b>mors</b> (death). All options are third declension nouns in the nominative singular, representing negative outcomes or states." }, { meta: "Analogies", stem: "<b>amārī</b> : <b>amātus</b> :: <b>monērī</b> : X", options: ["monitus", "dūctus", "scrīptus", "captus"], i: 0, explanation: "This question tests the transformation from the present passive infinitive to the perfect passive participle. <i>Amārī</i> (to be loved) has the perfect passive participle <i>amātus</i> (loved, having been loved). Following this pattern, <i>monērī</i> (to be warned) has the perfect passive participle <b>monitus</b> (warned, having been warned). All options are perfect passive participles in the nominative singular masculine." }, { meta: "Analogies", stem: "<b>arātrum</b> : <b>ager</b> :: <b>tēla</b> : X", options: ["palla", "rōsa", "corōna", "fābula"], i: 0, explanation: "The relationship here is 'tool to the object/product of its use'. An <i>arātrum</i> (plow) is used on an <i>ager</i> (field). Similarly, a <i>tēla</i> (loom) is used to produce woven goods, such as a <b>palla</b> (cloak, robe). All options are first declension feminine nouns in the nominative singular." }, { meta: "Analogies", stem: "<b>celer</b> : <b>celeriter</b> :: <b>facilis</b> : X", options: ["facile", "fortiter", "graviter", "breviter"], i: 0, explanation: "This question tests the transformation from an adjective to its corresponding adverb. <i>Celer</i> (swift) becomes <i>celeriter</i> (swiftly). Following this pattern, <i>facilis</i> (easy) becomes <b>facile</b> (easily). All options are adverbs derived from adjectives." }, { meta: "Analogies", stem: "<b>auris</b> : <b>audīre</b> :: <b>oculus</b> : X", options: ["vidēre", "tangere", "olfacere", "gustāre"], i: 0, explanation: "The relationship is 'sense organ to its corresponding verb of sense'. The <i>auris</i> (ear) is used for <i>audīre</i> (to hear). Similarly, the <i>oculus</i> (eye) is used for <b>vidēre</b> (to see). All options are present active infinitives of verbs related to the senses." }, { meta: "Analogies", stem: "<b>somnus</b> : <b>quiēs</b> :: <b>famēs</b> : X", options: ["egestās", "sitis", "aegritūdō", "labor"], i: 0, explanation: "The relationship is one of closely related abstract concepts or states. <i>Somnus</i> (sleep) is a form of <i>quiēs</i> (rest). Similarly, <i>famēs</i> (hunger) is often associated with or leads to <b>egestās</b> (poverty, want, need). All options are third declension feminine nouns in the nominative singular, representing states of hardship or lack." }, { meta: "Analogies", stem: "<b>amāns</b> : <b>amandus</b> :: <b>regēns</b> : X", options: ["regendus", "capiendus", "audiendus", "monendus"], i: 0, explanation: "This question tests the transformation from the present active participle to the gerundive. <i>Amāns</i> (loving, present participle) corresponds to <i>amandus</i> (to be loved, deserving of love, gerundive). Following this pattern, <i>regēns</i> (ruling, present participle) corresponds to <b>regendus</b> (to be ruled, deserving of rule, gerundive). All options are gerundives in the nominative singular masculine." }, { meta: "Fill-in-the-Blank", stem: "Quamquam senex fīliō suō multōs annōs cōnsilium dabat, ille, propter īnsolentiam suam, patrī nūllō modō ___ voluit.", options: ["obsequī", "parēre", "fīdī", "resistī"], i: 0, explanation: "The sentence states that the old man gave his son advice for many years, but the son, due to his insolence, was unwilling to ___ his father. The context of 'cōnsilium dabat' (gave advice) and 'nūllō modō' (in no way) strongly suggests a refusal to comply or yield to that advice. <br><br><b>A. obsequī</b> (to comply with, yield to, gratify) perfectly fits this context. It often takes the dative (patrī) and implies yielding to influence or wishes.<br><b>B. parēre</b> (to obey) is very close, but *pāreō* typically implies obedience to a direct command or authority, whereas *obsequor* is better suited for yielding to advice or influence, especially when the subject is described as 'īnsolentiam suam' (his insolence).<br><b>C. fīdī</b> (to trust) also takes the dative, but while the son might not trust his father, the primary action related to refusing advice is compliance, not trust.<br><b>D. resistī</b> (to resist) also takes the dative. If the son was 'unwilling to resist' his father, it would mean he *was* willing to comply, which directly contradicts 'nūllō modō'." }, { meta: "Fill-in-the-Blank", stem: "Urbs obsidiōne pressa lēgātōs ad hostem mīsit, spē nūllā nisi in ___ posita.", options: ["dēprecātiōne", "dēditiōne", "dēfēnsiōne", "dīvīsiōne"], i: 0, explanation: "The sentence describes a city under siege sending envoys to the enemy, with no hope remaining except in a certain action. The act of sending envoys to an enemy during a siege, especially when hope is scarce, is typically to plead for mercy or terms.<br><br><b>A. dēprecātiōne</b> (a pleading, entreaty, prayer for averting evil) is the best fit. It describes the act of imploring the enemy for clemency or favorable terms, which is a common purpose for envoys in such a desperate situation.<br><b>B. dēditiōne</b> (surrender) is plausible, as surrender is often the outcome of a siege. However, 'spē nūllā nisi in dēditiōne posita' (no hope except in surrender) is a stark statement. Envoys usually seek *terms* or *mercy* through a plea, rather than simply stating 'surrender is our only hope.' *Dēprecātiō* is the act of seeking a better outcome from the inevitable.<br><b>C. dēfēnsiōne</b> (defense) contradicts the action of sending envoys. If their only hope was in defense, they would be fighting, not negotiating.<br><b>D. dīvīsiōne</b> (division) is semantically absurd in this context." }, { meta: "Fill-in-the-Blank", stem: "Cum duo poētae, alter alterī invidēns, certāmen carminum inīssent, uterque fāmam ___ suī superāre studēbat.", options: ["aemulī", "amīcī", "patrōnī", "sociī"], i: 0, explanation: "The sentence describes two poets who 'alter alterī invidēns' (envying each other) entered a 'certāmen carminum' (contest of songs). This clearly sets up a competitive relationship.<br><br><b>A. aemulī</b> (of his rival) is the perfect fit. An *aemulus* is a rival or competitor, which aligns precisely with the context of envy and a contest.<br><b>B. amīcī</b> (of his friend) contradicts 'invidēns' (envying). Friends do not typically envy each other in such a competitive, hostile way.<br><b>C. patrōnī</b> (of his patron) is plausible in the context of Roman poets, but the phrase 'alter alterī invidēns' points to direct competition between peers, not between a poet and their patron.<br><b>D. sociī</b> (of his ally/companion) also contradicts 'invidēns,' as allies or companions would not typically be envying each other in a contest." }, { meta: "Fill-in-the-Blank", stem: "Nocte atrōcī, cum nūlla lūx in caelō vidērētur, subitō fulmen per nūbēs ___.", options: ["effulsit", "ēmicuit", "ērupit", "exārsit"], i: 0, explanation: "The sentence describes a 'nocte atrōcī' (dreadful night) where 'nūlla lūx in caelō vidērētur' (no light was seen in the sky), followed by 'subitō fulmen per nūbēs' (suddenly lightning through the clouds). The key is the contrast between no light and the sudden appearance of lightning.<br><br><b>A. effulsit</b> (shone forth, gleamed) from *effulgeō* is the most precise choice. It specifically describes the act of shining or gleaming, emphasizing the visual aspect of light appearing in the darkness.<br><b>B. ēmicuit</b> (flashed forth, darted out) from *ēmicō* is very close, also implying a sudden burst of light. However, *effulgeō* often carries a sense of more intense or radiant shining, fitting the dramatic appearance of lightning.<br><b>C. ērupit</b> (burst forth) from *ērrumpō* describes the sudden emergence or breaking out, which lightning certainly does. But it focuses more on the action of breaking through rather than the visual phenomenon of light itself.<br><b>D. exārsit</b> (blazed up, flared up) from *exārdeō* implies a more fiery or intense burning, which, while related to light, is less directly descriptive of lightning's flash than *effulsit*." }, { meta: "Fill-in-the-Blank", stem: "Cum omnia dēspērāta essent, captīvus deōs hominēsque summā vōce ___ auxilium petēns.", options: ["obtestāns", "querēns", "cōnfītentēs", "mīrāns"], i: 0, explanation: "The sentence describes a captive in a desperate situation ('omnia dēspērāta essent') who, with a loud voice ('summā vōce'), addresses 'deōs hominēsque' (gods and men) while 'auxilium petēns' (seeking help).<br><br><b>A. obtestāns</b> (imploring, calling to witness) from *obtestor* perfectly captures the act of desperately appealing to gods and men for help. It is a present participle, matching the grammatical requirement.<br><b>B. querēns</b> (complaining) from *queror* is a plausible action for a captive, but 'seeking help' ('auxilium petēns') implies a more active and direct appeal than mere complaining.<br><b>C. cōnfītentēs</b> (confessing) from *cōnfiteor* is grammatically correct as a nominative singular present participle. However, 'confessing gods and men' makes no semantic sense in this context.<br><b>D. mīrāns</b> (wondering at) from *mīror* is semantically absurd; a captive in despair seeking help would not be wondering at gods and men." }, { meta: "Fill-in-the-Blank", stem: "Mīlitēs, hostem exspectantēs, in densīs silvīs ___ ut imprōvīsī impetum facerent.", options: ["dēlituērunt", "latuērunt", "cōnsēdērunt", "substitērunt"], i: 0, explanation: "The sentence describes soldiers 'hostem exspectantēs' (awaiting the enemy) who take action 'in densīs silvīs' (in dense woods) 'ut imprōvīsī impetum facerent' (so that they might make an attack unawares). This is a classic description of an ambush, which requires active concealment.<br><br><b>A. dēlituērunt</b> (hid themselves, lay concealed) from *dēlitēscō* is the best fit. *Dēlitēscō* is an inchoative verb meaning 'to go into hiding' or 'to hide oneself,' emphasizing the active process of concealment necessary for an ambush.<br><b>B. latuērunt</b> (lay hidden) from *lateō* describes the state of being hidden. While grammatically plausible, *dēlitēscō* emphasizes the *action* of hiding for a purpose, which is more appropriate for preparing an ambush.<br><b>C. cōnsēdērunt</b> (sat down, settled) from *cōnsīdō* describes taking a position, which is part of waiting, but it lacks the crucial element of *hiding* for an ambush.<br><b>D. substitērunt</b> (stopped, stood still) from *subsistō* also describes a static position, but again, it does not convey the active concealment implied by the phrase 'ut imprōvīsī impetum facerent'." }, { meta: "Fill-in-the-Blank", stem: "Dux, cum mīlitēs suōs terrōre perterritōs vīdisset, eōs verbīs vehementibus ___ ut spem reciperent.", options: ["cōnfīrmāvit", "incitāvit", "dēterrēvit", "ēdocuit"], i: 0, explanation: "The sentence describes a general who saw his soldiers 'terrōre perterritōs' (terrified by fear) and then used 'verbīs vehementibus' (vehement words) to cause them 'ut spem reciperent' (to regain hope). The action must be one of encouraging or strengthening morale.<br><br><b>A. cōnfīrmāvit</b> (strengthened, encouraged, confirmed) from *cōnfīrmō* is the most appropriate choice. It means to strengthen resolve or courage, which directly leads to regaining hope.<br><b>B. incitāvit</b> (incited, stirred up) from *incitō* implies rousing to action or stirring up emotions. While a general might incite troops, the specific goal 'ut spem reciperent' (that they might regain hope) is better served by strengthening their resolve (*cōnfīrmō*) rather than merely stirring them up.<br><b>C. dēterrēvit</b> (deterred) from *dēterreō* means to discourage or frighten away, which is the opposite of what is needed for terrified soldiers to regain hope.<br><b>D. ēdocuit</b> (taught, instructed) from *ēdoceō* means to teach or instruct thoroughly, which is semantically absurd in this context of inspiring terrified soldiers." }, { meta: "Fill-in-the-Blank", stem: "Postquam tempestās saevissima per trēs diēs et noctēs bacchāta est, tandem ad aurōram ___ furere.", options: ["dēsiit", "cessit", "subsedit", "intermīsit"], i: 0, explanation: "The sentence describes a 'tempestās saevissima' (fiercest storm) that 'per trēs diēs et noctēs bacchāta est' (had raged for three days and nights). The storm then 'tandem ad aurōram' (at last towards dawn) performed an action related to 'furere' (to rage). The most natural fit is that the storm ceased to rage.<br><br><b>A. dēsiit</b> (ceased, stopped) from *dēsinō* is the best choice, especially when followed by an infinitive like 'furere'. *Dēsinō* commonly means 'to cease' or 'to stop doing something.'<br><b>B. cessit</b> (yielded, withdrew) from *cēdō* could imply the storm 'withdrew,' but it does not naturally take an infinitive like 'furere' to mean 'ceased to rage.'<br><b>C. subsedit</b> (subsided, settled down) from *subsīdō* is a very strong distractor, as storms do subside. However, *subsīdō* does not typically take an infinitive complement like 'furere' in the same way *dēsinō* does.<br><b>D. intermīsit</b> (interrupted, left off) from *intermittō* could mean the storm 'interrupted' its raging, but 'tandem ad aurōram' suggests a definitive cessation, for which *dēsinō* is more appropriate than *intermittō* (which can imply a temporary pause)." }, { meta: "Fill-in-the-Blank", stem: "Duo rēgna, quibus erat ūna et eadem fīnis, saepe dē agrīs ___ inter sē contendēbant.", options: ["cōnfīnium", "hostium", "gentium", "cīvium"], i: 0, explanation: "The sentence describes 'duo rēgna' (two kingdoms) that 'quibus erat ūna et eadem fīnis' (which had one and the same border). They 'saepe ... inter sē contendēbant' (often contended among themselves) 'dē agrīs' (concerning the fields). The contention is naturally about the lands of their immediate neighbors or bordering regions.<br><br><b>A. cōnfīnium</b> (of their neighbors, of their bordering lands) is the best fit. *Cōnfīnis, -is* (m./f.) means a neighbor or borderer, and *cōnfīnium, -ī* (n.) means a border district or frontier. Both forms have a genitive plural *cōnfīnium*, perfectly matching the context of two kingdoms sharing a border and disputing land.<br><b>B. hostium</b> (of enemies) is plausible as kingdoms that contend are often enemies. However, *cōnfīnium* is more specific, identifying *who* these enemies are in this context: those sharing a border.<br><b>C. gentium</b> (of peoples/tribes) is too general. While kingdoms consist of peoples, the dispute is specifically about bordering lands.<br><b>D. cīvium</b> (of citizens) is semantically absurd; kingdoms contend over the lands of other kingdoms, not their own citizens." }, { meta: "Fill-in-the-Blank", stem: "Cum diūtius obsidiō sustinērī nōn posset, quod cibus et aqua paulatim ___ coeperant, cīvēs dē dēditiōne cōgitābant.", options: ["dēfēcisse", "dēperiisse", "ēvānuisse", "conticuisse"], i: 0, explanation: "The sentence describes a situation where 'obsidiō sustinērī nōn posset' (the siege could not be sustained any longer) because 'cibus et aqua paulatim ___ coeperant' (food and water had gradually begun to ___). This leads the citizens to 'dē dēditiōne cōgitābant' (think about surrender). The missing verb must describe supplies running out.<br><br><b>A. dēfēcisse</b> (to have run short, failed) from *dēficiō* is the most idiomatic and precise choice for supplies (food and water) gradually diminishing or failing. The adverb 'paulatim' (gradually) perfectly complements this meaning.<br><b>B. dēperiisse</b> (to have perished, been lost) from *dēpereō* is plausible, as supplies can be lost. However, *dēficiō* more commonly describes the process of running out or becoming insufficient, which is key in a siege.<br><b>C. ēvānuisse</b> (to have vanished) from *ēvānēscō* implies a sudden disappearance, which contradicts 'paulatim' (gradually).<br><b>D. conticuisse</b> (to have become silent) from *conticeō* is semantically absurd in the context of food and water." }, { meta: "Circumlocution", stem: "Potestās dīvīna quae mundum regit et hominibus fāta mōnstrat.", options: ["carmen", "flūmen", "lūmen", "nūmen"], i: 3, explanation: "The Latin definition describes <i>\"divine power that rules the world and shows fates to humans.\"</i> This accurately defines <b>nūmen, nūminis</b> (n.), meaning 'divine will, divine power, deity'.<br>Option A, <b>carmen, carminis</b> (n.), means 'song, poem, prophecy'.<br>Option B, <b>flūmen, flūminis</b> (n.), means 'river'.<br>Option C, <b>lūmen, lūminis</b> (n.), means 'light'.<br>All options are 3rd declension neuter nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Rēs quae ab hoste victō dētrahuntur, praesertim arma et vestēs, vel pellēs serpentis.", options: ["īnsidiae", "exuviae", "dīvitiae", "tenebrae"], i: 1, explanation: "The definition translates to <i>\"Things which are stripped from a conquered enemy, especially arms and clothing, or the skin of a snake.\"</i> This precisely describes <b>exuviae, -ārum</b> (f. pl.), which means 'spoils, relics, clothes stripped off, cast-off skin'.<br>Option A, <b>īnsidiae, -ārum</b> (f. pl.), means 'ambush, trap'.<br>Option C, <b>dīvitiae, -ārum</b> (f. pl.), means 'riches, wealth'.<br>Option D, <b>tenebrae, -ārum</b> (f. pl.), means 'darkness'.<br>All options are plural nouns, mostly 1st declension, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Ferrum longum et acūtum, ad pugnam et caedem factum.", options: ["fūstis", "lapis", "ēnsis", "sōl"], i: 2, explanation: "The Latin definition describes <i>\"A long and sharp iron (object), made for battle and slaughter.\"</i> This is a poetic description of a sword, which is <b>ēnsis, ēnsis</b> (m.).<br>Option A, <b>fūstis, fūstis</b> (m.), means 'club, stick'.<br>Option B, <b>lapis, lapidis</b> (m.), means 'stone'.<br>Option D, <b>sōl, sōlis</b> (m.), means 'sun'.<br>All options are 3rd declension masculine nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Fīnis vītae, mors, interitus.", options: ["bellum", "lētum", "odium", "vīnum"], i: 1, explanation: "The definition means <i>\"The end of life, death, destruction.\"</i> This is a poetic term for death, <b>lētum, -ī</b> (n.).<br>Option A, <b>bellum, -ī</b> (n.), means 'war'.<br>Option C, <b>odium, -ī</b> (n.), means 'hatred'.<br>Option D, <b>vīnum, -ī</b> (n.), means 'wine'.<br>All options are 2nd declension neuter nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Rēs quae fortuītō accidit, saepe mala et nōn exspectāta.", options: ["cursus", "cāsus", "gemitus", "senātus"], i: 1, explanation: "The definition translates to <i>\"A thing which happens by chance, often bad and unexpected.\"</i> This describes <b>cāsus, -ūs</b> (m.), meaning 'fall, accident, chance, misfortune'.<br>Option A, <b>cursus, -ūs</b> (m.), means 'course, running'.<br>Option C, <b>gemitus, -ūs</b> (m.), means 'groan, sigh'.<br>Option D, <b>senātus, -ūs</b> (m.), means 'senate'.<br>All options are 4th declension masculine nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Id quod contrā iūs dīvīnum est, scelus abominandum.", options: ["fās", "nēfās", "nihil", "īnstar"], i: 1, explanation: "The definition states <i>\"That which is against divine law, an abominable crime.\"</i> This perfectly defines <b>nēfās</b> (n. indecl.), meaning 'sacrilege, impiety, crime (against divine law)'.<br>Option A, <b>fās</b> (n. indecl.), is its opposite, meaning 'divine law, right, destiny'.<br>Option C, <b>nihil</b> (n. indecl.), means 'nothing'.<br>Option D, <b>īnstar</b> (n. indecl.), means 'likeness, image, equivalent'.<br>All options are indeclinable nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Sanguis effūsus ex vulnere, saepe dēnsus et atrox.", options: ["honor", "cruor", "dolor", "timor"], i: 1, explanation: "The definition describes <i>\"Blood poured out from a wound, often thick and terrible.\"</i> This specific type of blood is <b>cruor, cruōris</b> (m.), meaning 'gore, blood from a wound', distinct from <i>sanguis</i> (blood in general).<br>Option A, <b>honor, honōris</b> (m.), means 'honor'.<br>Option C, <b>dolor, dolōris</b> (m.), means 'pain, grief'.<br>Option D, <b>timor, timōris</b> (m.), means 'fear'.<br>All options are 3rd declension masculine nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Mūrī validī quibus urbs circumdātur ad dēfēnsiōnem.", options: ["moenia", "flūmina", "lūmina", "carmīna"], i: 0, explanation: "The definition translates to <i>\"Strong walls by which a city is surrounded for defense.\"</i> This describes <b>moenia, -ium</b> (n. pl.), meaning '(city) walls, fortifications'.<br>Option B, <b>flūmina, -um</b> (n. pl.), is the plural of <i>flūmen</i>, meaning 'rivers'.<br>Option C, <b>lūmina, -um</b> (n. pl.), is the plural of <i>lūmen</i>, meaning 'lights'.<br>Option D, <b>carmīna, -um</b> (n. pl.), is the plural of <i>carmen</i>, meaning 'songs, poems'.<br>All options are 3rd declension plural neuter nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Pars aedificiī secreta et sānctissima, ad quam paucī adīre possunt.", options: ["animāle", "penetrāle", "tribūnāle", "vectīgāle"], i: 1, explanation: "The definition means <i>\"A secret and most sacred part of a building, to which few can approach.\"</i> This describes <b>penetrāle, -is</b> (n.), meaning 'inner sanctuary, innermost part'.<br>Option A, <b>animāle, -is</b> (n.), means 'animal'.<br>Option C, <b>tribūnāle, -is</b> (n.), means 'tribunal, judgment seat'.<br>Option D, <b>vectīgāle, -is</b> (n.), means 'tax, revenue' (often plural).<br>All options are 3rd declension neuter nouns, maintaining grammatical rigor." }, { meta: "Circumlocution", stem: "Vēns vehementer rotāns, vel rēs quae celeriter circumagitur.", options: ["ōrdō", "turbō", "vertex", "pulvis"], i: 1, explanation: "The definition translates to <i>\"A violently rotating wind, or a thing which is quickly spun around.\"</i> This describes <b>turbō, turbinis</b> (m.), meaning 'whirlwind, storm, spinning top'.<br>Option A, <b>ōrdō, ōrdinis</b> (m.), means 'order, rank'.<br>Option C, <b>vertex, verticis</b> (m.), means 'whirlpool, summit, crown of the head', a good distractor due to its association with spinning or a high point.<br>Option D, <b>pulvis, pulveris</b> (m.), means 'dust', which can be associated with wind.<br>All options are 3rd declension masculine nouns, maintaining grammatical rigor." }, { meta: "Latin to English", stem: "quippe", options: ["alas", "surely", "that", "which"], i: 1, explanation: "<b>quippe</b> is a Latin adverb and conjunction that is most commonly translated as <i>of course</i>, <i>indeed</i>, <i>obviously</i>, or <i>surely</i>. It is often used to emphasize a statement or to introduce a self-evident reason. <i>alas</i> would be <b>heu</b> or <b>ēheu</b>. <i>that</i> (as a conjunction) would often be <b>ut</b> or <b>quod</b>. <i>which</i> would be a form of the relative pronoun <b>quī, quae, quod</b>." }];